INSERT INTO `question_options` (`id`, `translation_id`, `base_question_id`, `option_text`, `option_image_path`, `marks`, `original_order`, `status`, `created_at`) VALUES
	(1, 1, 1, 'Politely refuse the Test Ride and explain that a valid Driving License is mandatory as per dealership and legal policy', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(2, 1, 1, 'Ask the customer to return with a valid license holder and allow the Test Ride with that person riding while the customer sits as pillion', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(3, 1, 1, 'Offer the customer a supervised test ride as a pillion rider to safely experience the scooter', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(4, 1, 1, 'Guide the customer to register online for a Learner’s License and explain the quick process. Invite him back for a Test Ride once he receives it', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(5, 2, 1, 'नम्रता से टेस्ट राइड मना करें और बताएं कि डीलरशिप और क़ानूनी नियमों के अनुसार वैध ड्राइविंग लाइसेंस ज़रूरी है।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(6, 2, 1, 'कस्टमर से कहें कि वह किसी वैध लाइसेंस होल्डर के साथ आए और टेस्ट राइड में वही व्यक्ति स्कूटर चलाए, जबकि कस्टमर पिलियन पर बैठे।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(7, 2, 1, 'कस्टमर को सुरक्षित तरीके से स्कूटर का अनुभव देने के लिए सुपरवाइज़्ड पिलियन टेस्ट राइड ऑफर करें।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(8, 2, 1, 'कस्टमर को ऑनलाइन लर्नर लाइसेंस के लिए रजिस्टर करने की जानकारी दें, आसान और तेज़ प्रोसेस समझाएं और लाइसेंस मिलने के बाद टेस्ट राइड के लिए दोबारा बुलाएं।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(9, 3, 1, 'ਨਮ੍ਰਤਾ ਨਾਲ ਟੈਸਟ ਰਾਈਡ ਤੋਂ ਇਨਕਾਰ ਕਰੋ ਅਤੇ ਸਮਝਾਓ ਕਿ ਡੀਲਰਸ਼ਿਪ ਅਤੇ ਕਾਨੂੰਨੀ ਨੀਤੀਆਂ ਮੁਤਾਬਕ ਵੈਧ ਡਰਾਈਵਿੰਗ ਲਾਇਸੈਂਸ ਲਾਜ਼ਮੀ ਹੈ।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(10, 3, 1, 'ਕਸਟਮਰ ਨੂੰ ਕਹੋ ਕਿ ਉਹ ਕਿਸੇ ਵੈਧ ਲਾਇਸੈਂਸ ਹੋਲਡਰ ਨਾਲ ਵਾਪਸ ਆਵੇ ਅਤੇ ਟੈਸਟ ਰਾਈਡ ਦੌਰਾਨ ਉਹ ਵਿਅਕਤੀ ਸਕੂਟਰ ਚਲਾਏ, ਜਦਕਿ ਕਸਟਮਰ ਪਿਲਿਅਨ ਵਜੋਂ ਬੈਠੇ।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(11, 3, 1, 'ਕਸਟਮਰ ਨੂੰ ਸੁਰੱਖਿਅਤ ਤਰੀਕੇ ਨਾਲ ਅਨੁਭਵ ਦਿਵਾਉਣ ਲਈ ਨਿਗਰਾਨੀ ਹੇਠ ਪਿਲਿਅਨ ਟੈਸਟ ਰਾਈਡ ਦਿਓ।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(12, 3, 1, 'ਕਸਟਮਰ ਨੂੰ ਆਨਲਾਈਨ ਲਰਨਰ ਲਾਇਸੈਂਸ ਲਈ ਰਜਿਸਟਰ ਕਰਨ ਦੀ ਜਾਣਕਾਰੀ ਦਿਓ, ਆਸਾਨ ਪ੍ਰਕਿਰਿਆ ਸਮਝਾਓ ਅਤੇ ਲਾਇਸੈਂਸ ਮਿਲਣ ਤੋਂ ਬਾਅਦ ਟੈਸਟ ਰਾਈਡ ਲਈ ਮੁੜ ਸੱਦੋ।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(13, 4, 1, 'વિનમ્રતાથી ટેસ્ટ રાઇડ માટે ના પાડો અને સમજાવો કે ડીલરશિપ અને કાયદા મુજબ માન્ય ડ્રાઇવિંગ લાઇસન્સ ફરજિયાત છે।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(14, 4, 1, 'કસ્ટમરને માન્ય લાઇસન્સ ધરાવતા વ્યક્તિ સાથે આવવા કહો અને ટેસ્ટ રાઇડ દરમિયાન તે વ્યક્તિ સ્કૂટર ચલાવે, જ્યારે કસ્ટમર પિલિયન પર બેસે।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(15, 4, 1, 'કસ્ટમરને સલામત રીતે અનુભવ અપાવવા માટે સુપરવિઝ્ડ પિલિયન ટેસ્ટ રાઇડ ઓફર કરો।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(16, 4, 1, 'કસ્ટમરને ઓનલાઈન લર્નર લાઇસન્સ માટે રજિસ્ટર કરવાની માહિતી આપો, સરળ પ્રક્રિયા સમજાવો અને લાઇસન્સ મળ્યા બાદ ટેસ્ટ રાઇડ માટે ફરી આમંત્રણ આપો।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(17, 5, 1, 'नम्रपणे टेस्ट राइड नाकारा आणि डीलरशिप व कायद्याप्रमाणे वैध ड्रायव्हिंग लायसन्स आवश्यक आहे हे समजावून सांगा.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(18, 5, 1, 'कस्टमरला वैध लायसन्स असलेल्या व्यक्तीसोबत परत येण्यास सांगा आणि टेस्ट राइडमध्ये ती व्यक्ती स्कूटर चालवेल, तर कस्टमर पिलियनवर बसेल.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(19, 5, 1, 'कस्टमरला सुरक्षित अनुभव देण्यासाठी सुपरवाइज्ड पिलियन टेस्ट राइड ऑफर करा.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(20, 5, 1, 'कस्टमरला ऑनलाइन लर्नर लायसन्ससाठी नोंदणी कशी करायची ते समजावून सांगा आणि लायसन्स मिळाल्यावर टेस्ट राइडसाठी पुन्हा बोलवा.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(21, 6, 1, 'ভদ্রভাবে টেস্ট রাইড প্রত্যাখ্যান করুন এবং ব্যাখ্যা করুন যে ডিলারশিপ ও আইনি নিয়ম অনুযায়ী বৈধ ড্রাইভিং লাইসেন্স বাধ্যতামূলক।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(22, 6, 1, 'কাস্টমারকে বৈধ লাইসেন্সধারীর সঙ্গে ফিরে আসতে বলুন এবং টেস্ট রাইডের সময় সেই ব্যক্তি স্কুটার চালাবে, কাস্টমার পিলিয়নে বসবে।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(23, 6, 1, 'নিরাপদভাবে অভিজ্ঞতা দেওয়ার জন্য কাস্টমারকে সুপারভাইজড পিলিয়ন টেস্ট রাইড অফার করুন।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(24, 6, 1, 'কাস্টমারকে অনলাইনে লার্নার লাইসেন্স রেজিস্ট্রেশন করার পদ্ধতি বুঝিয়ে দিন এবং লাইসেন্স পাওয়ার পর টেস্ট রাইডের জন্য আবার আমন্ত্রণ জানান।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(25, 7, 1, 'নম্ৰভাৱে টেষ্ট ৰাইড নাকচ কৰক আৰু বুজাই দিয়ক যে ডীলাৰশ্বিপ আৰু আইন অনুসাৰে বৈধ ড্ৰাইভিং লাইচেঞ্চ বাধ্যতামূলক।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(26, 7, 1, 'কাষ্টমাৰক বৈধ লাইচেঞ্চ থকা লোকৰ সৈতে পুনৰ আহিবলৈ কওক আৰু টেষ্ট ৰাইডত সেই লোকেই স্কুটাৰ চলাব, কাষ্টমাৰ পিলিয়নত বহিব।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(27, 7, 1, 'নিৰাপদ অভিজ্ঞতা দিবলৈ কাষ্টমাৰক চুপাৰভাইজড পিলিয়ন টেষ্ট ৰাইড আগবঢ়াওক।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(28, 7, 1, 'কাষ্টমাৰক অনলাইন লাৰ্নাৰ লাইচেঞ্চ ৰেজিষ্ট্ৰেচনৰ বিষয়ে জনাওক, সহজ প্ৰক্ৰিয়া বুজাওক আৰু লাইচেঞ্চ পালে টেষ্ট ৰাইডৰ বাবে পুনৰ মাতক।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(29, 8, 1, 'மரியாதையாக டெஸ்ட் ரைட்டை மறுத்து, டீலர்ஷிப் மற்றும் சட்ட விதிகளின்படி செல்லுபடியாகும் டிரைவிங் லைசென்ஸ் கட்டாயம் என்று விளக்குங்கள்.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(30, 8, 1, 'செல்லுபடியாகும் லைசென்ஸ் உள்ள ஒருவருடன் மீண்டும் வரச் சொல்லி, அந்த நபர் ஸ்கூட்டரை ஓட்ட, கஸ்டமர் பில்லியனாக உட்கார்ந்து டெஸ்ட் ரைடு செய்ய அனுமதிக்கவும்.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(31, 8, 1, 'பாதுகாப்பாக அனுபவிக்க கஸ்டமருக்கு கண்காணிப்புடன் பில்லியன் டெஸ்ட் ரைடு ஆஃபர் செய்யவும்.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(32, 8, 1, 'லெர்னர்ஸ் லைசென்ஸுக்கு ஆன்லைனில் பதிவு செய்வது எப்படி என்று விளக்கி, லைசென்ஸ் வந்த பிறகு டெஸ்ட் ரைடுக்கு மீண்டும் அழைக்கவும்.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(33, 9, 1, 'మర్యాదగా టెస్ట్ రైడ్‌ను నిరాకరించి, డీలర్‌షిప్ మరియు చట్టం ప్రకారం చెల్లుబాటు అయ్యే డ్రైవింగ్ లైసెన్స్ తప్పనిసరి అని వివరించండి.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(34, 9, 1, 'చెల్లుబాటు అయ్యే లైసెన్స్ ఉన్న వ్యక్తితో తిరిగి రావాలని చెప్పి, టెస్ట్ రైడ్ సమయంలో ఆ వ్యక్తి స్కూటర్ నడపగా కస్టమర్ పిలియన్‌గా కూర్చునేలా చేయండి.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(35, 9, 1, 'భద్రంగా అనుభవించేందుకు కస్టమర్‌కు సూపర్వైజ్డ్ పిలియన్ టెస్ట్ రైడ్ ఆఫర్ చేయండి.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(36, 9, 1, 'లెర్నర్ లైసెన్స్ కోసం ఆన్‌లైన్‌లో రిజిస్టర్ అయ్యే ప్రక్రియను వివరించి, లైసెన్స్ వచ్చిన తర్వాత టెస్ట్ రైడ్‌కు తిరిగి రావాలని ఆహ్వానించండి.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(37, 10, 1, 'വിനീതമായി ടെസ്റ്റ് റൈഡ് നിരസിക്കുകയും ഡീലർഷിപ്പിന്റെയും നിയമത്തിന്റെയും പ്രകാരം സാധുവായ ഡ്രൈവിംഗ് ലൈസൻസ് നിർബന്ധമാണെന്ന് വിശദീകരിക്കുകയും ചെയ്യുക.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(38, 10, 1, 'സാധുവായ ലൈസൻസ് ഉള്ള ഒരാളോടൊപ്പം വീണ്ടും വരാൻ ആവശ്യപ്പെടുകയും ടെസ്റ്റ് റൈഡിൽ ആ വ്യക്തി സ്കൂട്ടർ ഓടിക്കുമ്പോൾ കസ്റ്റമർ പില്ലിയനായി ഇരിക്കാനും അനുവദിക്കുക.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(39, 10, 1, 'സുരക്ഷിതമായി അനുഭവിക്കാൻ കസ്റ്റമർക്കു സൂപ്പർവൈസ്ഡ് പില്ലിയൻ ടെസ്റ്റ് റൈഡ് ഓഫർ ചെയ്യുക.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(40, 10, 1, 'ലേണർ ലൈസൻസിനായി ഓൺലൈനായി രജിസ്റ്റർ ചെയ്യാനുള്ള പ്രക്രിയ വിശദീകരിച്ച്, ലൈസൻസ് ലഭിച്ച ശേഷം ടെസ്റ്റ് റൈഡിന് വീണ്ടും ക്ഷണിക്കുക.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(41, 11, 1, 'ವಿನಯದಿಂದ ಟೆಸ್ಟ್ ರೈಡ್ ನಿರಾಕರಿಸಿ ಮತ್ತು ಡೀಲರ್‌ಶಿಪ್ ಹಾಗೂ ಕಾನೂನು ನಿಯಮಗಳ ಪ್ರಕಾರ ಮಾನ್ಯ ಡ್ರೈವಿಂಗ್ ಲೈಸೆನ್ಸ್ ಕಡ್ಡಾಯವೆಂದು ವಿವರಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(42, 11, 1, 'ಮಾನ್ಯ ಲೈಸೆನ್ಸ್ ಹೊಂದಿರುವ ವ್ಯಕ್ತಿಯೊಂದಿಗೆ ಮರಳಿ ಬರಲು ಹೇಳಿ ಮತ್ತು ಟೆಸ್ಟ್ ರೈಡ್‌ನಲ್ಲಿ ಆ ವ್ಯಕ್ತಿ ಸ್ಕೂಟರ್ ಓಡಿಸಿ, ಕಸ್ಟಮರ್ ಪಿಲಿಯನ್ ಆಗಿ ಕುಳಿತುಕೊಳ್ಳಲು ಅವಕಾಶ ನೀಡಿ.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(43, 11, 1, 'ಸುರಕ್ಷಿತ ಅನುಭವಕ್ಕಾಗಿ ಕಸ್ಟಮರ್‌ಗೆ ಸೂಪರ್ವೈಜ್ಡ್ ಪಿಲಿಯನ್ ಟೆಸ್ಟ್ ರೈಡ್ ಆಫರ್ ಮಾಡಿ.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(44, 11, 1, 'ಲರ್ನರ್ ಲೈಸೆನ್ಸ್‌ಗಾಗಿ ಆನ್‌ಲೈನ್‌ನಲ್ಲಿ ನೋಂದಣಿ ಪ್ರಕ್ರಿಯೆಯನ್ನು ವಿವರಿಸಿ ಮತ್ತು ಲೈಸೆನ್ಸ್ ಬಂದ ನಂತರ ಟೆಸ್ಟ್ ರೈಡ್‌ಗೆ ಮರಳಿ ಆಹ್ವಾನಿಸಿ.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
