	(60, 15, 2, 'ਸਟਾਕ ਦੀ ਟਾਈਮਲਾਈਨ ਪਾਰਦਰਸ਼ੀ ਤਰੀਕੇ ਨਾਲ ਸਮਝਾਓ, 3 ਦਿਨ ਬਾਅਦ ਡਿਲਿਵਰੀ ਕਨਫਰਮ ਕਰੋ, ਹੋਮ ਡਿਲਿਵਰੀ ਦਾ ਪ੍ਰਬੰਧ ਕਰੋ ਅਤੇ ਇੱਕ ਛੋਟਾ ਗੁੱਡਵਿਲ ਜੈਸਚਰ ਦਿਓ।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(61, 16, 2, 'પરિસ્થિતિને સ્પષ્ટ રીતે સમજાવો અને પસંદ કરેલા રંગ સાથે 3 દિવસમાં ડિલિવરી કન્ફર્મ કરો।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
