	(78, 20, 2, 'தாமதத்திற்கு மன்னிப்பு கேட்டுக் கொண்டு, செயல்முறையை விரைவுபடுத்துவதாக உறுதி அளித்து, கஸ்டமருக்கு அடிக்கடி அப்டேட்ஸ் வழங்குங்கள்.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(79, 20, 2, 'அதே வேரியண்ட்டை வேறு நிறத்தில் ஆஃபர் செய்து, பிறந்தநாள் அனுபவத்தை மேம்படுத்த ஒரு இலவச வால்யூ-அடெட் சர்வீஸையும் சேர்க்கவும்.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(80, 20, 2, 'ஸ்டாக் டைம்லைனை வெளிப்படையாக விளக்கி, 3 நாட்கள் கழித்து டெலிவரி உறுதி செய்து, ஹோம் டெலிவரி ஏற்பாடு செய்து, ஒரு சிறிய குட்வில் ஜெஸ்ச்சர் வழங்குங்கள்.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(81, 21, 2, 'పరిస్థితిని స్పష్టంగా వివరించి, ఎంచుకున్న రంగుతో 3 రోజుల్లో డెలివరీని కన్ఫర్మ్ చేయండి.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
