	(86, 22, 2, 'വൈകിയതിന് ക്ഷമ ചോദിച്ച്, പ്രക്രിയ വേഗത്തിലാക്കുമെന്ന് ഉറപ്പ് നൽകി, കസ്റ്റമറെ സ്ഥിരമായി അപ്‌ഡേറ്റ് ചെയ്യുക.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(87, 22, 2, 'അതേ വേരിയന്റ് മറ്റൊരു നിറത്തിൽ ഓഫർ ചെയ്ത്, പിറന്നാൾ അനുഭവം മെച്ചപ്പെടുത്താൻ ഒരു സൗജന്യ വാല്യൂ-ആഡഡ് സർവീസ് ഉൾപ്പെടുത്തുക.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(88, 22, 2, 'സ്റ്റോക്ക് ടൈംലൈൻ സുതാര്യമായി വിശദീകരിച്ച്, 3 ദിവസം കഴിഞ്ഞ് ഡെലിവറി ഉറപ്പാക്കി, ഹോം ഡെലിവറി ക്രമീകരിച്ച്, ഒരു ചെറിയ ഗുഡ്‌വിൽ ജെസ്‌ചർ നൽകുക.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(89, 23, 2, 'ಪರಿಸ್ಥಿತಿಯನ್ನು ಸ್ಪಷ್ಟವಾಗಿ ವಿವರಿಸಿ, ಆಯ್ಕೆ ಮಾಡಿದ ಬಣ್ಣದೊಂದಿಗೆ 3 ದಿನಗಳಲ್ಲಿ ಡೆಲಿವರಿ ಖಚಿತಪಡಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(90, 23, 2, 'ತಡವಾದುದಕ್ಕಾಗಿ ಕ್ಷಮೆ ಕೇಳಿ, ಪ್ರಕ್ರಿಯೆಯನ್ನು ವೇಗಗೊಳಿಸುವುದಾಗಿ ಭರವಸೆ ನೀಡಿ ಮತ್ತು ಗ್ರಾಹಕರಿಗೆ ನಿಯಮಿತ ಅಪ್‌ಡೇಟ್ ನೀಡಿರಿ.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(91, 23, 2, 'ಅದೇ ವೇರಿಯಂಟ್ ಅನ್ನು ಮತ್ತೊಂದು ಬಣ್ಣದಲ್ಲಿ ಆಫರ್ ಮಾಡಿ, ಹುಟ್ಟುಹಬ್ಬದ ಅನುಭವವನ್ನು ಉತ್ತಮಗೊಳಿಸಲು ಉಚಿತ ವ್ಯಾಲ್ಯೂ-ಆಡ್ಡೆಡ್ ಸೇವೆಯನ್ನು ಸೇರಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(92, 23, 2, 'ಸ್ಟಾಕ್ ಟೈಮ್‌ಲೈನ್ ಅನ್ನು ಪಾರದರ್ಶಕವಾಗಿ ವಿವರಿಸಿ, 3 ದಿನಗಳ ನಂತರ ಡೆಲಿವರಿ ಖಚಿತಪಡಿಸಿ, ಹೋಮ್ ಡೆಲಿವರಿ ವ್ಯವಸ್ಥೆ ಮಾಡಿ ಮತ್ತು ಒಂದು ಸಣ್ಣ ಗುಡ್‌ವಿಲ್ ಜೆಸ್ಚರ್ ನೀಡಿ.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(93, 24, 2, 'ପରିସ୍ଥିତିକୁ ସ୍ପଷ୍ଟଭାବେ ବୁଝାନ୍ତୁ ଏବଂ ବାଛିଥିବା ରଙ୍ଗ ସହ 3 ଦିନ ମଧ୍ୟରେ ଡିଲିଭରି ନିଶ୍ଚିତ କରନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(94, 24, 2, 'ବିଳମ୍ବ ପାଇଁ କ୍ଷମା ଚାହାନ୍ତୁ, ପ୍ରକ୍ରିୟା ଶୀଘ୍ର କରିବାକୁ ପ୍ରତିଶ୍ରୁତି ଦିଅନ୍ତୁ ଏବଂ କଷ୍ଟମରଙ୍କୁ ନିୟମିତ ଅପଡେଟ୍ ଦିଅନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(95, 24, 2, 'ସେହି ଭେରିଆଣ୍ଟକୁ ଅନ୍ୟ ରଙ୍ଗରେ ଅଫର୍ କରନ୍ତୁ ଏବଂ ଜନ୍ମଦିନ ଅନୁଭବକୁ ଉନ୍ନତ କରିବା ପାଇଁ ଏକ ମାଗଣା ଭ୍ୟାଲୁ-ଏଡେଡ୍ ସେବା ଯୋଗ କରନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(96, 24, 2, 'ଷ୍ଟକ୍ ଟାଇମ୍ଲାଇନ୍‌କୁ ସ୍ପଷ୍ଟଭାବେ ବୁଝାନ୍ତୁ, 3 ଦିନ ପରେ ଡିଲିଭରି ନିଶ୍ଚିତ କରନ୍ତୁ, ହୋମ୍ ଡିଲିଭରି ବ୍ୟବସ୍ଥା କରନ୍ତୁ ଏବଂ ଏକ ଛୋଟ ଗୁଡ୍‌ୱିଲ୍ ଜେସ୍ଚର୍ ଦିଅନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(97, 25, 3, 'Explain that the quotation follows standard pricing and assure the customer there are no hidden charges', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(98, 25, 3, 'Provide a clear breakdown of the quotation and explain what is included in the on-road price', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(99, 25, 3, 'Acknowledge the concern and explain why the other dealership may be offering a lower price', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(100, 25, 3, 'Review the other quotation, explain the reason for discount, confirm standard pricing transparency, and offer a value-added benefit', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(101, 26, 3, 'समझाएँ कि कोटेशन स्टैंडर्ड प्राइसिंग के अनुसार है और कस्टमर को भरोसा दिलाएँ कि कोई छिपे हुए चार्ज नहीं हैं।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(102, 26, 3, 'कोटेशन का साफ़ और डिटेल में ब्रेकडाउन दें और बताएं कि ऑन-रोड प्राइस में क्या-क्या शामिल है।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(103, 26, 3, 'कस्टमर की चिंता को स्वीकार करें और समझाएँ कि दूसरी डीलरशिप कम कीमत क्यों दे रही हो सकती है।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(104, 26, 3, 'दूसरे कोटेशन को रिव्यू करें, डिस्काउंट का कारण समझाएँ, स्टैंडर्ड प्राइसिंग की पारदर्शिता कन्फर्म करें और एक वैल्यू-एडेड बेनिफिट ऑफर करें।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(105, 27, 3, 'ਸਮਝਾਓ ਕਿ ਕੋਟੇਸ਼ਨ ਸਟੈਂਡਰਡ ਪ੍ਰਾਈਸਿੰਗ ਅਨੁਸਾਰ ਹੈ ਅਤੇ ਭਰੋਸਾ ਦਿਓ ਕਿ ਕੋਈ ਲੁਕੇ ਹੋਏ ਚਾਰਜ ਨਹੀਂ ਹਨ।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(106, 27, 3, 'ਕੋਟੇਸ਼ਨ ਦਾ ਸਪਸ਼ਟ ਅਤੇ ਵਿਸਥਾਰ ਨਾਲ ਬ੍ਰੇਕਡਾਊਨ ਦਿਓ ਅਤੇ ਦੱਸੋ ਕਿ ਆਨ-ਰੋਡ ਪ੍ਰਾਈਸ ਵਿੱਚ ਕੀ-ਕੀ ਸ਼ਾਮਲ ਹੈ।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(107, 27, 3, 'ਕਸਟਮਰ ਦੀ ਚਿੰਤਾ ਨੂੰ ਮੰਨੋ ਅਤੇ ਸਮਝਾਓ ਕਿ ਦੂਜੀ ਡੀਲਰਸ਼ਿਪ ਘੱਟ ਕੀਮਤ ਕਿਉਂ ਦੇ ਰਹੀ ਹੋ ਸਕਦੀ ਹੈ।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(108, 27, 3, 'ਦੂਜੇ ਕੋਟੇਸ਼ਨ ਦੀ ਸਮੀਖਿਆ ਕਰੋ, ਡਿਸਕਾਊਂਟ ਦਾ ਕਾਰਣ ਸਮਝਾਓ, ਸਟੈਂਡਰਡ ਪ੍ਰਾਈਸਿੰਗ ਦੀ ਪਾਰਦਰਸ਼ਤਾ ਕਨਫਰਮ ਕਰੋ ਅਤੇ ਇੱਕ ਵੈਲਯੂ-ਐਡਡ ਫਾਇਦਾ ਆਫਰ ਕਰੋ।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(109, 28, 3, 'સમજાવો કે ક્વોટેશન સ્ટાન્ડર્ડ પ્રાઇસિંગ મુજબ છે અને ખાતરી આપો કે કોઈ છુપાયેલા ચાર્જ નથી.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(110, 28, 3, 'ક્વોટેશનનો સ્પષ્ટ અને વિગતવાર બ્રેકડાઉન આપો અને ઓન-રોડ કિંમતમાં શું સામેલ છે તે સમજાવો.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(111, 28, 3, 'કસ્ટમરની ચિંતા સ્વીકારો અને સમજાવો કે બીજી ડીલરશિપ ઓછી કિંમત કેમ આપી રહી હોઈ શકે.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(112, 28, 3, 'બીજા ક્વોટેશનની સમીક્ષા કરો, ડિસ્કાઉન્ટનું કારણ સમજાવો, સ્ટાન્ડર્ડ પ્રાઇસિંગની પારદર્શિતા કન્ફર્મ કરો અને વેલ્યુ-એડેડ લાભ ઓફર કરો.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(113, 29, 3, 'समजावून सांगा की कोटेशन स्टँडर्ड प्राइसिंगनुसार आहे आणि कोणतेही लपवलेले चार्ज नाहीत याची खात्री द्या.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(114, 29, 3, 'कोटेशनचा स्पष्ट आणि सविस्तर ब्रेकडाउन द्या आणि ऑन-रोड किंमतीत काय समाविष्ट आहे ते समजवा.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(115, 29, 3, 'कस्टमरची चिंता मान्य करा आणि दुसरी डीलरशिप कमी किंमत का देत असेल ते समजवा.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(116, 29, 3, 'दुसऱ्या कोटेशनचा आढावा घ्या, डिस्काउंटचे कारण समजवा, स्टँडर्ड प्राइसिंगची पारदर्शकता कन्फर्म करा आणि व्हॅल्यू-अॅडेड लाभ द्या.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(117, 30, 3, 'ব্যাখ্যা করুন যে কোটেশনটি স্ট্যান্ডার্ড প্রাইসিং অনুযায়ী এবং কোনো গোপন চার্জ নেই।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(118, 30, 3, 'কোটেশনের পরিষ্কার ও বিস্তারিত ব্রেকডাউন দিন এবং অন-রোড মূল্যে কী কী অন্তর্ভুক্ত আছে তা বুঝিয়ে দিন।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(119, 30, 3, 'কাস্টমারের উদ্বেগ স্বীকার করুন এবং কেন অন্য ডিলারশিপ কম দাম দিচ্ছে তা ব্যাখ্যা করুন।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(120, 30, 3, 'অন্য কোটেশনটি রিভিউ করুন, ডিসকাউন্টের কারণ ব্যাখ্যা করুন, স্ট্যান্ডার্ড প্রাইসিং স্বচ্ছতা নিশ্চিত করুন এবং একটি ভ্যালু-অ্যাডেড সুবিধা অফার করুন।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(121, 31, 3, 'বুজাই দিয়ক যে কোটেশ্যনটো ষ্টেণ্ডাৰ্ড প্ৰাইচিং অনুসাৰে আৰু কোনো লুকুৱা চাৰ্জ নাই।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(122, 31, 3, 'কোটেশ্যনৰ স্পষ্ট আৰু বিস্তৃত ব্ৰেকডাউন দিয়ক আৰু অন-ৰোড মূল্যত কি কি অন্তৰ্ভুক্ত আছে সেয়া বুজাওক।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(123, 31, 3, 'কাষ্টমাৰৰ চিন্তাটো স্বীকাৰ কৰক আৰু আন ডীলাৰশ্বিপে কম মূল্য কিয় আগবঢ়াইছে বুজাওক।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(124, 31, 3, 'আন কোটেশ্যনৰ পৰ্যালোচনা কৰক, ডিছকাউণ্টৰ কাৰণ বুজাওক, ষ্টেণ্ডাৰ্ড প্ৰাইচিংৰ স্বচ্ছতা নিশ্চিত কৰক আৰু এটা ভেল্যু-এডেড সুবিধা আগবঢ়াওক।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(125, 32, 3, 'கோட்டேஷன் ஸ்டாண்டர்டு விலைக்கேற்ப இருப்பதாகவும், மறைமுக கட்டணங்கள் எதுவும் இல்லை என்பதையும் விளக்குங்கள்.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(126, 32, 3, 'கோட்டேஷனின் தெளிவான மற்றும் விரிவான பிரேக்டவுன் கொடுத்து, ஆன்ரோடு விலையில் என்னெல்லாம் உள்ளதென விளக்குங்கள்.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(127, 32, 3, 'கஸ்டமரின் கவலை ஏற்று, மற்ற டீலர்ஷிப் ஏன் குறைந்த விலை வழங்கலாம் என்பதை விளக்குங்கள்.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(128, 32, 3, 'மற்ற கோட்டேஷனை ரிவ்யூ செய்து, தள்ளுபடியின் காரணத்தை விளக்கி, ஸ்டாண்டர்டு விலையின் வெளிப்படைத்தன்மையை உறுதி செய்து, ஒரு வால்யூ-அடெட் நன்மை வழங்குங்கள்.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(129, 33, 3, 'కోటేషన్ స్టాండర్డ్ ప్రైసింగ్ ప్రకారం ఉందని మరియు ఎలాంటి దాచిన ఛార్జీలు లేవని వివరించండి.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(130, 33, 3, 'కోటేషన్‌కు స్పష్టమైన మరియు వివరమైన బ్రేక్‌డౌన్ ఇచ్చి, ఆన్-రోడ్ ధరలో ఏమేమి ఉన్నాయి అనేది వివరించండి.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(131, 33, 3, 'కస్టమర్ ఆందోళనను అంగీకరించి, ఇతర డీలర్‌షిప్ తక్కువ ధర ఎందుకు ఇస్తుందో వివరించండి.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(132, 33, 3, 'ఇతర కోటేషన్‌ను సమీక్షించి, డిస్కౌంట్ కారణాన్ని వివరించి, స్టాండర్డ్ ప్రైసింగ్ పారదర్శకతను నిర్ధారించి, ఒక విలువ-జోడించిన ప్రయోజనం ఆఫర్ చేయండి.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(133, 34, 3, 'ക്വോട്ടേഷൻ സ്റ്റാൻഡേർഡ് പ്രൈസിംഗിനുസരിച്ചാണെന്നും മറഞ്ഞ ചാർജുകൾ ഇല്ലെന്നും വിശദീകരിക്കുക.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(134, 34, 3, 'ക്വോട്ടേഷന്റെ വ്യക്തമായും വിശദമായും ബ്രേക്ക്‌డൗൺ നൽകി ഓൺ-റോഡ് വിലയിൽ എന്തെല്ലാം ഉൾപ്പെടുന്നുവെന്ന് വിശദീകരിക്കുക.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(135, 34, 3, 'കസ്റ്റമറുടെ ആശങ്ക അംഗീകരിച്ച്, മറ്റൊരു ഡീലർഷിപ്പ് കുറഞ്ഞ വില നൽകുന്നതിന് കാരണമെന്താകാമെന്ന് വിശദീകരിക്കുക.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(136, 34, 3, 'മറ്റു ക്വോട്ടേഷൻ പരിശോധിച്ച്, ഡിസ്കൗണ്ടിന്റെ കാരണം വിശദീകരിച്ച്, സ്റ്റാൻഡേർഡ് പ്രൈസിംഗ് സുതാര്യത ഉറപ്പാക്കി, ഒരു വാല്യൂ-ആഡഡ് ഗുണം നൽകുക.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(137, 35, 3, 'ಕೋಟೇಶನ್ ಸ್ಟ್ಯಾಂಡರ್ಡ್ ಪ್ರೈಸಿಂಗ್ ಪ್ರಕಾರ ಇದೆ ಮತ್ತು ಯಾವುದೇ ಲುಕಾಯಿತ ಶುಲ್ಕಗಳಿಲ್ಲ ಎಂದು ವಿವರಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(138, 35, 3, 'ಕೋಟೇಶನ್‌ನ ಸ್ಪಷ್ಟ ಮತ್ತು ವಿವರವಾದ ಬ್ರೇಕ್‌ಡೌನ್ ನೀಡಿ, ಆನ್-ರೋಡ್ ಬೆಲೆಯಲ್ಲಿ ಏನು ಏನು ಸೇರಿದೆ ಎಂದು ವಿವರಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(139, 35, 3, 'ಗ್ರಾಹಕರ ಚಿಂತೆಯನ್ನು ಒಪ್ಪಿಕೊಂಡು, ಇನ್ನೊಂದು ಡೀಲರ್‌ಶಿಪ್ ಕಡಿಮೆ ಬೆಲೆ ಯಾಕೆ ನೀಡಬಹುದು ಎಂದು ವಿವರಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(140, 35, 3, 'ಇನ್ನೊಂದು ಕೋಟೇಶನ್ ಅನ್ನು ಪರಿಶೀಲಿಸಿ, ಡಿಸ್ಕೌಂಟ್ ಕಾರಣವನ್ನು ವಿವರಿಸಿ, ಸ್ಟ್ಯಾಂಡರ್ಡ್ ಪ್ರೈಸಿಂಗ್ ಪಾರದರ್ಶಕತೆಯನ್ನು ಖಚಿತಪಡಿಸಿ ಮತ್ತು ಒಂದು ವ್ಯಾಲ್ಯೂ-ಆಡ್ಡೆಡ್ ಲಾಭವನ್ನು ನೀಡಿ.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(141, 36, 3, 'କୋଟେସନ୍‌ ଷ୍ଟାଣ୍ଡାର୍ଡ ପ୍ରାଇସିଂ ଅନୁଯାୟୀ ଅଛି ଏବଂ କୌଣସି ଲୁଚିଥିବା ଚାର୍ଜ୍‌ ନାହିଁ ବୋଲି ବୁଝାନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(142, 36, 3, 'କୋଟେସନ୍‌ର ସ୍ପଷ୍ଟ ଓ ବିସ୍ତୃତ ବ୍ରେକଡାଉନ୍‌ ଦିଅନ୍ତୁ ଏବଂ ଅନ୍-ରୋଡ୍‌ ମୂଲ୍ୟରେ କଣ କଣ ଅନ୍ତର୍ଭୁକ୍ତ ଅଛି ସେଥି ଖୋଲାମେଲା କରନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(143, 36, 3, 'କଷ୍ଟମରଙ୍କ ଚିନ୍ତାକୁ ସ୍ୱୀକାର କରନ୍ତୁ ଏବଂ ଅନ୍ୟ ଡିଲର୍‌ଶିପ୍‌ କମ୍‌ ଦାମ୍‌ କାହିଁକି ଦେଉଛି ବୋଲି ବୁଝାନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(144, 36, 3, 'ଅନ୍ୟ କୋଟେସନ୍‌କୁ ଖତିଆନ କରନ୍ତୁ, ଡିସ୍କାଉଣ୍ଟର କାରଣ ବୁଝାନ୍ତୁ, ଷ୍ଟାଣ୍ଡାର୍ଡ ପ୍ରାଇସିଂର ପାରଦର୍ଶିତା ନିଶ୍ଚିତ କରନ୍ତୁ ଏବଂ ଏକ ଭ୍ୟାଲୁ-ଏଡେଡ୍ ଲାଭ ଅଫର୍ କରନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(145, 37, 4, 'Apologize to the customer and them that they are not eligible for the scheme', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(146, 37, 4, 'Apologize for the confusion and explain the eligibility criteria of the scheme', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(147, 37, 4, 'Apologize, explain the eligibility criteria, and suggest an alternative finance option', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(148, 37, 4, 'Apologize, explain the eligibility criteria, suggest a suitable finance option, and offer help with the application process', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(149, 38, 4, 'कस्टमर से माफ़ी माँगें और बताएं कि वे इस स्कीम के लिए पात्र नहीं हैं।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(150, 38, 4, 'कन्फ्यूजन के लिए माफ़ी माँगें और स्कीम की एलिजिबिलिटी क्राइटेरिया समझाएँ।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(151, 38, 4, 'माफ़ी माँगें, एलिजिबिलिटी क्राइटेरिया समझाएँ और कोई वैकल्पिक फाइनेंस ऑप्शन सुझाएँ।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(152, 38, 4, 'माफ़ी माँगें, एलिजिबिलिटी क्राइटेरिया समझाएँ, एक उपयुक्त फाइनेंस ऑप्शन सुझाएँ और आवेदन प्रक्रिया में मदद की पेशकश करें।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(153, 39, 4, 'ਕਸਟਮਰ ਤੋਂ ਮਾਫ਼ੀ ਮੰਗੋ ਅਤੇ ਦੱਸੋ ਕਿ ਉਹ ਇਸ ਸਕੀਮ ਲਈ ਯੋਗ ਨਹੀਂ ਹਨ।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(154, 39, 4, 'ਗਲਤਫਹਿਮੀ ਲਈ ਮਾਫ਼ੀ ਮੰਗੋ ਅਤੇ ਸਕੀਮ ਦੇ ਯੋਗਤਾ ਮਾਪਦੰਡ ਸਮਝਾਓ।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(155, 39, 4, 'ਮਾਫ਼ੀ ਮੰਗੋ, ਯੋਗਤਾ ਮਾਪਦੰਡ ਸਮਝਾਓ ਅਤੇ ਕੋਈ ਬਦਲ ਵਿੱਤੀ ਵਿਕਲਪ ਸੁਝਾਓ।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(156, 39, 4, 'ਮਾਫ਼ੀ ਮੰਗੋ, ਯੋਗਤਾ ਮਾਪਦੰਡ ਸਮਝਾਓ, ਇੱਕ ਉਚਿਤ ਵਿੱਤੀ ਵਿਕਲਪ ਸੁਝਾਓ ਅਤੇ ਅਰਜ਼ੀ ਪ੍ਰਕਿਰਿਆ ਵਿੱਚ ਮਦਦ ਦੀ ਪੇਸ਼ਕਸ਼ ਕਰੋ।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(157, 40, 4, 'કસ્ટમર પાસે માફી માગો અને જણાવો કે તેઓ આ યોજના માટે પાત્ર નથી.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(158, 40, 4, 'ગેરસમજ માટે માફી માગો અને યોજનાની પાત્રતા માપદંડ સમજાવો.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(159, 40, 4, 'માફી માગો, પાત્રતા માપદંડ સમજાવો અને કોઈ વિકલ્પિક ફાઇનાન્સ વિકલ્પ સૂચવો.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(160, 40, 4, 'માફી માગો, પાત્રતા માપદંડ સમજાવો, યોગ્ય ફાઇનાન્સ વિકલ્પ સૂચવો અને અરજી પ્રક્રિયામાં મદદની ઓફર કરો.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(161, 41, 4, 'कस्टमरची माफी मागा आणि ते या योजनेसाठी पात्र नाहीत हे सांगा.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(162, 41, 4, 'गोंधळाबद्दल माफी मागा आणि योजनेचे पात्रता निकष समजवा.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(163, 41, 4, 'माफी मागा, पात्रता निकष समजवा आणि पर्यायी फायनान्स पर्याय सुचवा.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(164, 41, 4, 'माफी मागा, पात्रता निकष समजवा, योग्य फायनान्स पर्याय सुचवा आणि अर्ज प्रक्रियेत मदत करण्याची ऑफर द्या.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(165, 42, 4, 'কাস্টমারের কাছে ক্ষমা চান এবং জানান যে তিনি এই স্কিমের জন্য যোগ্য নন।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(166, 42, 4, 'ভুল বোঝাবুঝির জন্য ক্ষমা চান এবং স্কিমের যোগ্যতার মানদণ্ড ব্যাখ্যা করুন।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(167, 42, 4, 'ক্ষমা চান, যোগ্যতার মানদণ্ড ব্যাখ্যা করুন এবং বিকল্প ফাইন্যান্স অপশন প্রস্তাব করুন।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(168, 42, 4, 'ক্ষমা চান, যোগ্যতার মানদণ্ড ব্যাখ্যা করুন, উপযুক্ত ফাইন্যান্স অপশন প্রস্তাব করুন এবং আবেদন প্রক্রিয়ায় সাহায্যের প্রস্তাব দিন।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(169, 43, 4, 'কাষ্টমাৰৰ ওচৰত ক্ষমা বিচাৰক আৰু জনাওক যে তেওঁ এই স্কীমৰ বাবে যোগ্য নহয়।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(170, 43, 4, 'গোলযোগৰ বাবে ক্ষমা বিচাৰক আৰু স্কীমৰ যোগ্যতাৰ মানদণ্ড বুজাওক।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(171, 43, 4, 'ক্ষমা বিচাৰক, যোগ্যতাৰ মানদণ্ড বুজাওক আৰু বিকল্প ফাইনেন্স অপশ্যন আগবঢ়াওক।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(172, 43, 4, 'ক্ষমা বিচাৰক, যোগ্যতাৰ মানদণ্ড বুজাওক, উপযুক্ত ফাইনেন্স অপশ্যন আগবঢ়াওক আৰু আবেদন প্ৰক্ৰিয়াত সহায়ৰ প্ৰস্তাৱ দিওক।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(173, 44, 4, 'கஸ்டமரிடம் மன்னிப்பு கேட்டு, அவர் இந்த திட்டத்திற்கு தகுதியற்றவர் என்பதை தெரிவிக்கவும்.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(174, 44, 4, 'குழப்பத்திற்கு மன்னிப்பு கேட்டு, திட்டத்தின் தகுதி விதிகளை விளக்கவும்.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(175, 44, 4, 'மன்னிப்பு கேட்டு, தகுதி விதிகளை விளக்கி, மாற்று நிதி விருப்பத்தை பரிந்துரைக்கவும்.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(176, 44, 4, 'மன்னிப்பு கேட்டு, தகுதி விதிகளை விளக்கி, பொருத்தமான நிதி விருப்பத்தை பரிந்துரைத்து, விண்ணப்ப செயல்முறையில் உதவி வழங்க முன்வரவும்.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(177, 45, 4, 'కస్టమర్‌కు క్షమాపణ చెప్పి, వారు ఈ పథకానికి అర్హులు కాదని తెలియజేయండి.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(178, 45, 4, 'గందరగోళానికి క్షమాపణ చెప్పి, పథక అర్హత ప్రమాణాలను వివరించండి.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(179, 45, 4, 'క్షమాపణ చెప్పి, అర్హత ప్రమాణాలను వివరించి, ప్రత్యామ్నాయ ఫైనాన్స్ ఎంపికను సూచించండి.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(180, 45, 4, 'క్షమాపణ చెప్పి, అర్హత ప్రమాణాలను వివరించి, సరైన ఫైనాన్స్ ఎంపికను సూచించి, అప్లికేషన్ ప్రక్రియలో సహాయం అందిస్తామని చెప్పండి.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(181, 46, 4, 'കസ്റ്റമറോട് ക്ഷമ ചോദിച്ച്, അവർ ഈ സ്കീമിന് അർഹരല്ലെന്ന് അറിയിക്കുക.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(182, 46, 4, 'കുഴപ്പത്തിന് ക്ഷമ ചോദിച്ച്, സ്കീമിന്റെ അർഹത മാനദണ്ഡങ്ങൾ വിശദീകരിക്കുക.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(183, 46, 4, 'ക്ഷമ ചോദിച്ച്, അർഹത മാനദണ്ഡങ്ങൾ വിശദീകരിച്ച്, ഒരു പകരം ഫൈനാൻസ് ഓപ്ഷൻ നിർദ്ദേശിക്കുക.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(184, 46, 4, 'ക്ഷമ ചോദിച്ച്, അർഹത മാനദണ്ഡങ്ങൾ വിശദീകരിച്ച്, അനുയോജ്യമായ ഫൈനാൻസ് ഓപ്ഷൻ നിർദ്ദേശിച്ച്, അപേക്ഷാ പ്രക്രിയയിൽ സഹായം വാഗ്ദാനം ചെയ്യുക.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(185, 47, 4, 'ಗ್ರಾಹಕರಿಗೆ ಕ್ಷಮೆ ಕೇಳಿ ಮತ್ತು ಅವರು ಈ ಯೋಜನೆಗೆ ಅರ್ಹರಲ್ಲ ಎಂದು ತಿಳಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(186, 47, 4, 'ಗೊಂದಲಕ್ಕಾಗಿ ಕ್ಷಮೆ ಕೇಳಿ ಮತ್ತು ಯೋಜನೆಯ ಅರ್ಹತಾ ಮಾನದಂಡಗಳನ್ನು ವಿವರಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(187, 47, 4, 'ಕ್ಷಮೆ ಕೇಳಿ, ಅರ್ಹತಾ ಮಾನದಂಡಗಳನ್ನು ವಿವರಿಸಿ ಮತ್ತು ಪರ್ಯಾಯ ಹಣಕಾಸು ಆಯ್ಕೆಯನ್ನು ಸೂಚಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(188, 47, 4, 'ಕ್ಷಮೆ ಕೇಳಿ, ಅರ್ಹತಾ ಮಾನದಂಡಗಳನ್ನು ವಿವರಿಸಿ, ಸೂಕ್ತ ಹಣಕಾಸು ಆಯ್ಕೆಯನ್ನು ಸೂಚಿಸಿ ಮತ್ತು ಅರ್ಜಿ ಪ್ರಕ್ರಿಯೆಯಲ್ಲಿ ಸಹಾಯ ಮಾಡುವುದಾಗಿ ತಿಳಿಸಿ.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
