	(218, 55, 5, 'পলমৰ বাবে ক্ষমা বিচাৰক আৰু কাষ্টমাৰক জনাওক যে আপুনি এই কেছটো প্ৰাধান্য দিব।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(219, 55, 5, 'ক্ষমা বিচাৰক, ষ্টেটাছ পৰীক্ষা কৰক আৰু আপডেট কৰা ডেলিভাৰী টাইমলাইন ভাগ-বতৰা কৰক।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(220, 55, 5, 'ক্ষমা বিচাৰক, সংশোধিত টাইমলাইন নিশ্চিত কৰক আৰু বুকিং ৰাখিবলৈ এটা গুডৱিল জেচাৰ আগবঢ়াওক।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(221, 56, 5, 'தாமதத்திற்கு மன்னிப்பு கேட்டு, நிலையை சரிபார்ப்பதாக வாக்குறுதி அளிக்கவும்.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(222, 56, 5, 'தாமதத்திற்கு மன்னிப்பு கேட்டு, இந்த கேஸை முன்னுரிமை அளித்து பார்க்கப்போகிறோம் என்று கஸ்டமருக்கு தெரிவிக்கவும்.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(223, 56, 5, 'மன்னிப்பு கேட்டு, நிலையை சரிபார்த்து, புதுப்பிக்கப்பட்ட டெலிவரி நேரத்தைக் கூறுங்கள்.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(224, 56, 5, 'மன்னிப்பு கேட்டு, திருத்தப்பட்ட நேரத்தைக் உறுதி செய்து, புக்கிங்கை தக்க வைத்துக்கொள்ள ஒரு குட்வில் ஜெஸ்சர் வழங்குங்கள்.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(225, 57, 5, 'ఆలస్యానికి క్షమాపణ చెప్పి, స్టేటస్ చెక్ చేస్తామని హామీ ఇవ్వండి.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(226, 57, 5, 'ఆలస్యానికి క్షమాపణ చెప్పి, ఈ కేసును ప్రాధాన్యంగా తీసుకుంటామని కస్టమర్‌కు తెలియజేయండి.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(227, 57, 5, 'క్షమాపణ చెప్పి, స్టేటస్ చెక్ చేసి, అప్‌డేట్ అయిన డెలివరీ టైమ్‌లైన్‌ను పంచుకోండి.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(228, 57, 5, 'క్షమాపణ చెప్పి, సవరించిన టైమ్‌లైన్‌ను నిర్ధారించి, బుకింగ్ నిలుపుకోవడానికి ఒక గుడ్‌విల్ జెస్చర్ ఇవ్వండి.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(229, 58, 5, 'വൈകിയതിന് ക്ഷമ ചോദിച്ച്, സ്റ്റാറ്റസ് പരിശോധിക്കാമെന്ന് വാഗ്ദാനം ചെയ്യുക.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(230, 58, 5, 'വൈകിയതിന് ക്ഷമ ചോദിച്ച്, ഈ കേസ് മുൻഗണന നൽകുമെന്ന് കസ്റ്റമറെ അറിയിക്കുക.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
