	(350, 88, 8, 'બંને વિકલ્પો બતાવો અને કસ્ટમરને બંનેનો જાતે અનુભવ લેવા કહો.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(351, 88, 8, 'કસ્ટમરની જરૂરિયાતો જાણો, સ્કૂટર અને મોટરસાયકલના ફાયદા સમજાવો અને કયો વધુ યોગ્ય છે તે સૂચવો.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(352, 88, 8, 'વિગતે જરૂરિયાતો ઓળખો, બંને વિકલ્પોના ફાયદા સાથે પિચ કરો અને કસ્ટમરને બંને અજમાવવા દેતા માર્ગદર્શન આપો.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(353, 89, 8, 'स्कूटर आणि मोटरसायकलचे वेगवेगळे फायदे ठळकपणे सांगा.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(354, 89, 8, 'दोन्ही पर्याय दाखवा आणि कस्टमरला दोन्ही प्रत्यक्ष अनुभवायला सांगा.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(355, 89, 8, 'कस्टमरच्या गरजा जाणून घ्या, स्कूटर आणि मोटरसायकलचे फायदे समजवा आणि कोणता पर्याय योग्य आहे ते सुचवा.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(356, 89, 8, 'सविस्तर गरजा ओळखा, दोन्ही पर्यायांचे फायदे सांगून पिच करा आणि कस्टमरला दोन्ही वापरू देत योग्य मार्गदर्शन द्या.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(357, 90, 8, 'স্কুটার ও মোটরসাইকেলের আলাদা আলাদা সুবিধাগুলো তুলে ধরুন।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(358, 90, 8, 'দুটো অপশনই দেখান এবং কাস্টমারকে দুটোই নিজে ব্যবহার করে দেখতে বলুন।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(359, 90, 8, 'কাস্টমারের প্রয়োজন বুঝে স্কুটার ও মোটরসাইকেলের সুবিধা ব্যাখ্যা করুন এবং কোনটা ভালো হবে তা প্রস্তাব করুন।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(360, 90, 8, 'বিস্তারিতভাবে প্রয়োজন বুঝে দুটো অপশনই সুবিধাসহ উপস্থাপন করুন এবং কাস্টমারকে দুটোই ট্রাই করতে দিয়ে গাইড করুন।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(361, 91, 8, 'স্কুটাৰ আৰু মোটৰচাইকেলৰ পৃথক পৃথক সুবিধাসমূহ উজাগৰ কৰক।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(362, 91, 8, 'দুয়োটা বিকল্প দেখুৱাওক আৰু কাষ্টমাৰক দুয়োটাই নিজে অনুভৱ কৰিবলৈ কওক।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(363, 91, 8, 'কাষ্টমাৰৰ প্ৰয়োজন বুজি স্কুটাৰ আৰু মোটৰচাইকেলৰ সুবিধা বুজাওক আৰু কোনটো বেছি উপযোগী হ’ব কওক।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(364, 91, 8, 'বিশদভাৱে প্ৰয়োজন চিনাক্ত কৰি দুয়োটা বিকল্প সুবিধাসহ উপস্থাপন কৰক আৰু কাষ্টমাৰক দুয়োটাই চেষ্টা কৰিবলৈ দিয়া অৱস্থাত দিশনির্দেশনা দিয়ক।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(365, 92, 8, 'ஸ்கூட்டர் மற்றும் மோட்டார் சைக்கிள்களின் தனிப்பட்ட நன்மைகளை விளக்குங்கள்.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(366, 92, 8, 'இரு தேர்வுகளையும் காட்டி, கஸ்டமரிடம் இரண்டையும் நேரில் அனுபவிக்க சொல்லுங்கள்.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(367, 92, 8, 'கஸ்டமரின் தேவைகளை அறிந்து, ஸ்கூட்டர் மற்றும் பைக்கின் நன்மைகளை விளக்கி, எது பொருத்தம் என பரிந்துரையுங்கள்.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(368, 92, 8, 'விவரமாக தேவைகளை கண்டறிந்து, இரு தேர்வுகளையும் நன்மைகளுடன் விளக்கி, கஸ்டமர் இரண்டையும் முயற்சி செய்ய வழிகாட்டுங்கள்.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(369, 93, 8, 'స్కూటర్ మరియు మోటార్‌సైకిల్‌ల ప్రత్యేక ప్రయోజనాలను హైలైట్ చేయండి.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(370, 93, 8, 'రెండు ఆప్షన్లను చూపించి, కస్టమర్‌కు రెండింటినీ ప్రత్యక్షంగా అనుభవించమని చెప్పండి.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(371, 93, 8, 'కస్టమర్ అవసరాలను తెలుసుకుని, స్కూటర్ మరియు బైక్ ప్రయోజనాలను వివరించి, ఏది సరిపోతుందో సూచించండి.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(372, 93, 8, 'వివరంగా అవసరాలను గుర్తించి, రెండు ఆప్షన్లను ప్రయోజనాలతో పిచ్ చేసి, కస్టమర్ రెండింటినీ ట్రై చేసేలా మార్గనిర్దేశం చేయండి.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(373, 94, 8, 'സ്കൂട്ടറിന്റെയും മോട്ടോർസൈക്കിളിന്റെയും വ്യത്യസ്ത ഗുണങ്ങൾ വ്യക്തമാക്കുക.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(374, 94, 8, 'രണ്ടു ഓപ്ഷനുകളും കാണിച്ച്, കസ്റ്റമറെ രണ്ടും നേരിട്ട് അനുഭവിക്കാൻ പറയുക.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(375, 94, 8, 'കസ്റ്റമറുടെ ആവശ്യങ്ങൾ മനസ്സിലാക്കി, സ്കൂട്ടറിന്റെയും ബൈക്കിന്റെയും ഗുണങ്ങൾ വിശദീകരിച്ച് ഏത് കൂടുതൽ അനുയോജ്യമാണെന്ന് നിർദ്ദേശിക്കുക.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
