	(377, 95, 8, 'ಸ್ಕೂಟರ್ ಮತ್ತು ಮೋಟಾರ್‌ಸೈಕಲ್‌ಗಳ ಪ್ರತ್ಯೇಕ ಲಾಭಗಳನ್ನು ಹೈಲೈಟ್ ಮಾಡಿ.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(378, 95, 8, 'ಎರಡೂ ಆಯ್ಕೆಗಳನ್ನು ತೋರಿಸಿ ಮತ್ತು ಗ್ರಾಹಕರಿಗೆ ಎರಡನ್ನೂ ನೇರವಾಗಿ ಅನುಭವಿಸಲು ಹೇಳಿ.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(379, 95, 8, 'ಗ್ರಾಹಕರ ಅಗತ್ಯಗಳನ್ನು ತಿಳಿದು, ಸ್ಕೂಟರ್ ಮತ್ತು ಬೈಕ್‌ನ ಲಾಭಗಳನ್ನು ವಿವರಿಸಿ, ಯಾವುದು ಸೂಕ್ತವೆಂದು ಸೂಚಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(380, 95, 8, 'ವಿವರವಾಗಿ ಅಗತ್ಯಗಳನ್ನು ಗುರುತಿಸಿ, ಎರಡೂ ಆಯ್ಕೆಗಳನ್ನು ಲಾಭಗಳೊಂದಿಗೆ ಪ್ರಸ್ತುತಪಡಿಸಿ ಮತ್ತು ಗ್ರಾಹಕರು ಎರಡನ್ನೂ ಪ್ರಯತ್ನಿಸುವಾಗ ಮಾರ್ಗದರ್ಶನ ನೀಡಿ.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
