	(452, 113, 10, 'Xoom 110 पिच करा, Xoom 125 ची अतिरिक्त व्हॅल्यू समजावून सांगा, ती कस्टमरच्या गरजांशी कशी जुळते ते दाखवा आणि दोन्हींची टेस्ट राईड ऑफर करा.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(453, 114, 10, 'Xoom 110 পিচ করুন এবং সংক্ষেপে বলুন যে কাস্টমারের প্রয়োজন অনুযায়ী Xoom 125-ও উপযুক্ত হতে পারে।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(454, 114, 10, 'Xoom 110 পিচ করুন এবং 110-এর তুলনায় Xoom 125-এর অতিরিক্ত সুবিধাগুলো ব্যাখ্যা করুন।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(455, 114, 10, 'Xoom 110 পিচ করুন, Xoom 125-এর সুবিধা দেখান এবং সামান্য বেশি দামে যে ভ্যালু পাওয়া যায় তা বোঝান।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(456, 114, 10, 'Xoom 110 পিচ করুন, Xoom 125-এর অতিরিক্ত ভ্যালু ব্যাখ্যা করুন, এটি কাস্টমারের প্রয়োজনের সাথে কীভাবে মেলে তা দেখান এবং দুটোরই টেস্ট রাইড অফার করুন।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(457, 115, 10, 'Xoom 110 পিচ কৰক আৰু সংক্ষিপ্তভাৱে কওক যে কাষ্টমাৰৰ প্ৰয়োজন অনুসাৰে Xoom 125 ও উপযোগী হ’ব পাৰে।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(458, 115, 10, 'Xoom 110 পিচ কৰক আৰু 110 ৰ তুলনাত Xoom 125 ৰ অতিৰিক্ত সুবিধাসমূহ বুজাওক।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(459, 115, 10, 'Xoom 110 পিচ কৰক, Xoom 125 ৰ সুবিধাসমূহ দেখুৱাওক আৰু অলপ বেছি মূল্যত পোৱা মূল্য বুজাওক।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(460, 115, 10, 'Xoom 110 পিচ কৰক, Xoom 125 ৰ অতিৰিক্ত মূল্য বুজাওক, ই কাষ্টমাৰৰ প্ৰয়োজনৰ সৈতে কেনেকৈ মিল খায় দেখুৱাওক আৰু দুয়োটাৰ টেষ্ট ৰাইড আগবঢ়াওক।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(461, 116, 10, 'Xoom 110-ஐ பரிந்துரைத்து, கஸ்டமரின் தேவையை பார்த்தால் Xoom 125-வும் பொருத்தமானது என்று சுருக்கமாக கூறுங்கள்.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(462, 116, 10, 'Xoom 110-ஐ பரிந்துரைத்து, 110-ஐ விட Xoom 125 வழங்கும் கூடுதல் நன்மைகளை விளக்குங்கள்.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(463, 116, 10, 'Xoom 110-ஐ பரிந்துரைத்து, Xoom 125-ன் நன்மைகளை காட்டி, சற்று அதிக விலையில் கிடைக்கும் மதிப்பை விளக்குங்கள்.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(464, 116, 10, 'Xoom 110-ஐ பரிந்துரைத்து, Xoom 125-ன் கூடுதல் மதிப்பை விளக்கி, அது கஸ்டமரின் தேவைக்கு எவ்வாறு பொருந்துகிறது என்பதை காட்டி, இரண்டிற்கும் டெஸ்ட் ரைடு வழங்குங்கள்.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(465, 117, 10, 'Xoom 110‌ను పిచ్ చేసి, కస్టమర్ అవసరాలను బట్టి Xoom 125 కూడా సరిపోతుందని సంక్షిప్తంగా చెప్పండి.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(466, 117, 10, 'Xoom 110‌ను పిచ్ చేసి, 110తో పోల్చితే Xoom 125 అదనపు ప్రయోజనాలను వివరించండి.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(467, 117, 10, 'Xoom 110‌ను పిచ్ చేసి, Xoom 125 ప్రయోజనాలను చూపించి, స్వల్పంగా ఎక్కువ ధరకు లభించే విలువను వివరించండి.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(468, 117, 10, 'Xoom 110‌ను పిచ్ చేసి, Xoom 125 అదనపు విలువను వివరించి, అది కస్టమర్ అవసరాలకు ఎలా సరిపోతుందో చూపించి, రెండింటికీ టెస్ట్ రైడ్ ఆఫర్ చేయండి.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(469, 118, 10, 'Xoom 110 ശുപാർശ ചെയ്ത്, കസ്റ്റമറുടെ ആവശ്യങ്ങൾ നോക്കുമ്പോൾ Xoom 125യും അനുയോജ്യമാണെന്ന് ചുരുക്കത്തിൽ പറയുക.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(470, 118, 10, 'Xoom 110 ശുപാർശ ചെയ്ത്, 110-നെക്കാൾ Xoom 125 നൽകുന്ന അധിക ഗുണങ്ങൾ വിശദീകരിക്കുക.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(471, 118, 10, 'Xoom 110 ശുപാർശ ചെയ്ത്, Xoom 125യുടെ ഗുണങ്ങൾ കാണിച്ച്, കുറച്ച് കൂടുതലുള്ള വിലയ്ക്ക് ലഭിക്കുന്ന മൂല്യം വിശദീകരിക്കുക.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(472, 118, 10, 'Xoom 110 ശുപാർശ ചെയ്ത്, Xoom 125യുടെ അധിക മൂല്യം വിശദീകരിച്ച്, അത് കസ്റ്റമറുടെ ആവശ്യങ്ങളുമായി എങ്ങനെ പൊരുത്തപ്പെടുന്നു എന്ന് കാണിച്ച്, രണ്ടിന്റെയും ടെസ്റ്റ് റൈഡ് നൽകുക.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(473, 119, 10, 'Xoom 110 ಅನ್ನು ಪಿಚ್ ಮಾಡಿ ಮತ್ತು ಗ್ರಾಹಕರ ಅಗತ್ಯಗಳನ್ನು ನೋಡಿದರೆ Xoom 125 ಕೂಡ ಸೂಕ್ತವೆಂದು ಸಂಕ್ಷಿಪ್ತವಾಗಿ ಹೇಳಿ.', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(474, 119, 10, 'Xoom 110 ಅನ್ನು ಪಿಚ್ ಮಾಡಿ ಮತ್ತು 110 ಗೆ ಹೋಲಿಸಿದರೆ Xoom 125 ನೀಡುವ ಹೆಚ್ಚುವರಿ ಲಾಭಗಳನ್ನು ವಿವರಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(475, 119, 10, 'Xoom 110 ಅನ್ನು ಪಿಚ್ ಮಾಡಿ, Xoom 125 ಲಾಭಗಳನ್ನು ತೋರಿಸಿ ಮತ್ತು ಸ್ವಲ್ಪ ಹೆಚ್ಚು ಬೆಲೆಯಲ್ಲಿ ಸಿಗುವ ಮೌಲ್ಯವನ್ನು ವಿವರಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(476, 119, 10, 'Xoom 110 ಅನ್ನು ಪಿಚ್ ಮಾಡಿ, Xoom 125 ನ ಹೆಚ್ಚುವರಿ ಮೌಲ್ಯವನ್ನು ವಿವರಿಸಿ, ಅದು ಗ್ರಾಹಕರ ಅಗತ್ಯಗಳಿಗೆ ಹೇಗೆ ಹೊಂದಿಕೊಳ್ಳುತ್ತದೆ ಎಂದು ತೋರಿಸಿ ಮತ್ತು ಎರಡಕ್ಕೂ ಟೆಸ್ಟ್ ರೈಡ್ ಆಫರ್ ಮಾಡಿ.', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(477, 120, 10, 'Xoom 110 କୁ ପିଚ୍ କରନ୍ତୁ ଏବଂ କଷ୍ଟମରଙ୍କ ଆବଶ୍ୟକତା ଦେଖି Xoom 125 ମଧ୍ୟ ଉପଯୁକ୍ତ ବୋଲି ସଂକ୍ଷେପରେ କୁହନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-25 17:54:17'),
	(478, 120, 10, 'Xoom 110 କୁ ପିଚ୍ କରନ୍ତୁ ଏବଂ 110 ତୁଳନାରେ Xoom 125 ର ଅତିରିକ୍ତ ଲାଭ ବୁଝାନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-25 17:54:17'),
	(479, 120, 10, 'Xoom 110 କୁ ପିଚ୍ କରନ୍ତୁ, Xoom 125 ର ଲାଭ ଦେଖାନ୍ତୁ ଏବଂ ଅଳ୍ପ ଅଧିକ ଦାମରେ ମିଳୁଥିବା ମୂଲ୍ୟ ବୁଝାନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-25 17:54:17'),
	(480, 120, 10, 'Xoom 110 କୁ ପିଚ୍ କରନ୍ତୁ, Xoom 125 ର ଅତିରିକ୍ତ ମୂଲ୍ୟ ବୁଝାନ୍ତୁ, ଏହା କଷ୍ଟମରଙ୍କ ଆବଶ୍ୟକତା ସହ କିପରି ମେଳ ଖାଉଛି ଦେଖାନ୍ତୁ ଏବଂ ଦୁହେଁର ଟେଷ୍ଟ ରାଇଡ୍ ଅଫର୍ କରନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-25 17:54:17'),
	(481, 121, 11, 'Politely refuse the Test Ride and explain that a valid Driving License is mandatory as per dealership and legal policy', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(482, 121, 11, 'Ask the customer to return with a valid license holder and allow the Test Ride with that person riding while the customer sits as pillion', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(483, 121, 11, 'Offer the customer a supervised test ride as a pillion rider to safely experience the scooter', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(484, 121, 11, 'Guide the customer to register online for a Learner’s License and explain the quick process. Invite him back for a Test Ride once he receives it', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(485, 122, 11, 'नम्रता से टेस्ट राइड मना करें और बताएं कि डीलरशिप और क़ानूनी नियमों के अनुसार वैध ड्राइविंग लाइसेंस ज़रूरी है।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(486, 122, 11, 'कस्टमर से कहें कि वह किसी वैध लाइसेंस होल्डर के साथ आए और टेस्ट राइड में वही व्यक्ति स्कूटर चलाए, जबकि कस्टमर पिलियन पर बैठे।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(487, 122, 11, 'कस्टमर को सुरक्षित तरीके से स्कूटर का अनुभव देने के लिए सुपरवाइज़्ड पिलियन टेस्ट राइड ऑफर करें।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(488, 122, 11, 'कस्टमर को ऑनलाइन लर्नर लाइसेंस के लिए रजिस्टर करने की जानकारी दें, आसान और तेज़ प्रोसेस समझाएं और लाइसेंस मिलने के बाद टेस्ट राइड के लिए दोबारा बुलाएं।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(489, 123, 11, 'ਨਮ੍ਰਤਾ ਨਾਲ ਟੈਸਟ ਰਾਈਡ ਤੋਂ ਇਨਕਾਰ ਕਰੋ ਅਤੇ ਸਮਝਾਓ ਕਿ ਡੀਲਰਸ਼ਿਪ ਅਤੇ ਕਾਨੂੰਨੀ ਨੀਤੀਆਂ ਮੁਤਾਬਕ ਵੈਧ ਡਰਾਈਵਿੰਗ ਲਾਇਸੈਂਸ ਲਾਜ਼ਮੀ ਹੈ।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(490, 123, 11, 'ਕਸਟਮਰ ਨੂੰ ਕਹੋ ਕਿ ਉਹ ਕਿਸੇ ਵੈਧ ਲਾਇਸੈਂਸ ਹੋਲਡਰ ਨਾਲ ਵਾਪਸ ਆਵੇ ਅਤੇ ਟੈਸਟ ਰਾਈਡ ਦੌਰਾਨ ਉਹ ਵਿਅਕਤੀ ਸਕੂਟਰ ਚਲਾਏ, ਜਦਕਿ ਕਸਟਮਰ ਪਿਲਿਅਨ ਵਜੋਂ ਬੈਠੇ।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(491, 123, 11, 'ਕਸਟਮਰ ਨੂੰ ਸੁਰੱਖਿਅਤ ਤਰੀਕੇ ਨਾਲ ਅਨੁਭਵ ਦਿਵਾਉਣ ਲਈ ਨਿਗਰਾਨੀ ਹੇਠ ਪਿਲਿਅਨ ਟੈਸਟ ਰਾਈਡ ਦਿਓ।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(492, 123, 11, 'ਕਸਟਮਰ ਨੂੰ ਆਨਲਾਈਨ ਲਰਨਰ ਲਾਇਸੈਂਸ ਲਈ ਰਜਿਸਟਰ ਕਰਨ ਦੀ ਜਾਣਕਾਰੀ ਦਿਓ, ਆਸਾਨ ਪ੍ਰਕਿਰਿਆ ਸਮਝਾਓ ਅਤੇ ਲਾਇਸੈਂਸ ਮਿਲਣ ਤੋਂ ਬਾਅਦ ਟੈਸਟ ਰਾਈਡ ਲਈ ਮੁੜ ਸੱਦੋ।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(493, 124, 11, 'વિનમ્રતાથી ટેસ્ટ રાઇડ માટે ના પાડો અને સમજાવો કે ડીલરશિપ અને કાયદા મુજબ માન્ય ડ્રાઇવિંગ લાઇસન્સ ફરજિયાત છે।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(494, 124, 11, 'કસ્ટમરને માન્ય લાઇસન્સ ધરાવતા વ્યક્તિ સાથે આવવા કહો અને ટેસ્ટ રાઇડ દરમિયાન તે વ્યક્તિ સ્કૂટર ચલાવે, જ્યારે કસ્ટમર પિલિયન પર બેસે।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(495, 124, 11, 'કસ્ટમરને સલામત રીતે અનુભવ અપાવવા માટે સુપરવિઝ્ડ પિલિયન ટેસ્ટ રાઇડ ઓફર કરો।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(496, 124, 11, 'કસ્ટમરને ઓનલાઈન લર્નર લાઇસન્સ માટે રજિસ્ટર કરવાની માહિતી આપો, સરળ પ્રક્રિયા સમજાવો અને લાઇસન્સ મળ્યા બાદ ટેસ્ટ રાઇડ માટે ફરી આમંત્રણ આપો।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(497, 125, 11, 'नम्रपणे टेस्ट राइड नाकारा आणि डीलरशिप व कायद्याप्रमाणे वैध ड्रायव्हिंग लायसन्स आवश्यक आहे हे समजावून सांगा.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
