	(536, 134, 12, 'स्टॉक की टाइमलाइन पारदर्शी तरीके से समझाएँ, 3 दिन बाद की डिलीवरी कन्फर्म करें, होम डिलीवरी अरेंज करें और एक छोटा सा गुडविल जेस्चर ऑफर करें।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(537, 135, 12, 'ਸਥਿਤੀ ਨੂੰ ਸਾਫ਼ ਤੌਰ ’ਤੇ ਸਮਝਾਓ ਅਤੇ ਚੁਣੇ ਹੋਏ ਰੰਗ ਨਾਲ 3 ਦਿਨਾਂ ਵਿੱਚ ਡਿਲਿਵਰੀ ਕਨਫਰਮ ਕਰੋ।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(538, 135, 12, 'ਦੇਰੀ ਲਈ ਮਾਫ਼ੀ ਮੰਗੋ, ਪ੍ਰਕਿਰਿਆ ਤੇਜ਼ ਕਰਨ ਦਾ ਵਾਅਦਾ ਕਰੋ ਅਤੇ ਕਸਟਮਰ ਨੂੰ ਨਿਯਮਿਤ ਅਪਡੇਟ ਦਿੰਦੇ ਰਹੋ।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(539, 135, 12, 'ਉਹੀ ਵੈਰੀਐਂਟ ਕਿਸੇ ਹੋਰ ਰੰਗ ਵਿੱਚ ਆਫਰ ਕਰੋ ਅਤੇ ਜਨਮਦਿਨ ਦੇ ਤਜਰਬੇ ਨੂੰ ਬਿਹਤਰ ਬਣਾਉਣ ਲਈ ਇੱਕ ਮੁਫ਼ਤ ਵੈਲਯੂ-ਐਡਡ ਸਰਵਿਸ ਸ਼ਾਮਲ ਕਰੋ।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(540, 135, 12, 'ਸਟਾਕ ਦੀ ਟਾਈਮਲਾਈਨ ਪਾਰਦਰਸ਼ੀ ਤਰੀਕੇ ਨਾਲ ਸਮਝਾਓ, 3 ਦਿਨ ਬਾਅਦ ਡਿਲਿਵਰੀ ਕਨਫਰਮ ਕਰੋ, ਹੋਮ ਡਿਲਿਵਰੀ ਦਾ ਪ੍ਰਬੰਧ ਕਰੋ ਅਤੇ ਇੱਕ ਛੋਟਾ ਗੁੱਡਵਿਲ ਜੈਸਚਰ ਦਿਓ।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(541, 136, 12, 'પરિસ્થિતિને સ્પષ્ટ રીતે સમજાવો અને પસંદ કરેલા રંગ સાથે 3 દિવસમાં ડિલિવરી કન્ફર્મ કરો।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(542, 136, 12, 'વિલંબ માટે માફી માંગો, પ્રક્રિયા ઝડપથી પૂરી કરવાની ખાતરી આપો અને કસ્ટમરને નિયમિત અપડેટ આપતા રહો।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(543, 136, 12, 'એ જ વેરિઅન્ટ બીજા રંગમાં ઓફર કરો અને જન્મદિવસનો અનુભવ વધુ સારો બનાવવા માટે એક મફત વેલ્યુ-એડેડ સર્વિસ ઉમેરો।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(544, 136, 12, 'સ્ટોકની સમયરેખા પારદર્શક રીતે સમજાવો, 3 દિવસ પછી ડિલિવરી કન્ફર્મ કરો, હોમ ડિલિવરી ગોઠવો અને એક નાનું ગુડવિલ જેશ્ચર આપો।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(545, 137, 12, 'परिस्थिती स्पष्टपणे समजावून सांगा आणि निवडलेल्या रंगासह 3 दिवसांत डिलिव्हरी कन्फर्म करा.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(546, 137, 12, 'उशीराबद्दल माफी मागा, प्रक्रिया जलद करण्याचे आश्वासन द्या आणि कस्टमरला नियमित अपडेट देत राहा.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(547, 137, 12, 'तोच व्हेरिएंट दुसऱ्या रंगात ऑफर करा आणि वाढदिवसाचा अनुभव अधिक चांगला करण्यासाठी मोफत व्हॅल्यू-अॅडेड सर्विस द्या.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(548, 137, 12, 'स्टॉकची टाइमलाइन पारदर्शकपणे समजावून सांगा, 3 दिवसांनी डिलिव्हरी कन्फर्म करा, होम डिलिव्हरीची व्यवस्था करा आणि एक छोटा गुडविल जेस्चर द्या.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(549, 138, 12, 'পরিস্থিতিটা পরিষ্কারভাবে বুঝিয়ে দিন এবং পছন্দের রঙে ৩ দিনের মধ্যে ডেলিভারি কনফার্ম করুন।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(550, 138, 12, 'দেরির জন্য ক্ষমা চান, প্রক্রিয়া দ্রুত করার প্রতিশ্রুতি দিন এবং কাস্টমারকে নিয়মিত আপডেট দিন।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(551, 138, 12, 'একই ভ্যারিয়েন্ট অন্য রঙে অফার করুন এবং জন্মদিনের অভিজ্ঞতা ভালো করতে একটি ফ্রি ভ্যালু-অ্যাডেড সার্ভিস যোগ করুন।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(552, 138, 12, 'স্টকের টাইমলাইন স্বচ্ছভাবে ব্যাখ্যা করুন, ৩ দিন পর ডেলিভারি কনফার্ম করুন, হোম ডেলিভারির ব্যবস্থা করুন এবং একটি ছোট গুডউইল জেসচার দিন।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(553, 139, 12, 'পৰিস্থিতিটো স্পষ্টভাৱে বুজাই দিয়ক আৰু বাছনি কৰা ৰঙৰ সৈতে ৩ দিনৰ ভিতৰত ডেলিভাৰী নিশ্চিত কৰক।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(554, 139, 12, 'পলমৰ বাবে ক্ষমা বিচাৰক, প্ৰক্ৰিয়া ত্বৰান্বিত কৰাৰ প্ৰতিশ্ৰুতি দিয়ক আৰু কাষ্টমাৰক নিয়মিত আপডেট দি থাকক।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(555, 139, 12, 'একেটা ভেৰিয়েণ্ট আন ৰঙত আগবঢ়াওক আৰু জন্মদিনৰ অভিজ্ঞতা উন্নত কৰিবলৈ এটা ফ্ৰী ভেল্যু-এডেড সেৱা যোগ কৰক।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(556, 139, 12, 'ষ্টকৰ টাইমলাইন স্বচ্ছভাৱে বুজাওক, ৩ দিন পিছত ডেলিভাৰী নিশ্চিত কৰক, হোম ডেলিভাৰীৰ ব্যৱস্থা কৰক আৰু এটা সৰু গুডউইল জেচাৰ আগবঢ়াওক।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(557, 140, 12, 'நிலையை தெளிவாக விளக்கி, தேர்ந்தெடுத்த நிறத்தில் 3 நாட்களில் டெலிவரி உறுதி செய்யுங்கள்.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(558, 140, 12, 'தாமதத்திற்கு மன்னிப்பு கேட்டுக் கொண்டு, செயல்முறையை விரைவுபடுத்துவதாக உறுதி அளித்து, கஸ்டமருக்கு அடிக்கடி அப்டேட்ஸ் வழங்குங்கள்.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(559, 140, 12, 'அதே வேரியண்ட்டை வேறு நிறத்தில் ஆஃபர் செய்து, பிறந்தநாள் அனுபவத்தை மேம்படுத்த ஒரு இலவச வால்யூ-அடெட் சர்வீஸையும் சேர்க்கவும்.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(560, 140, 12, 'ஸ்டாக் டைம்லைனை வெளிப்படையாக விளக்கி, 3 நாட்கள் கழித்து டெலிவரி உறுதி செய்து, ஹோம் டெலிவரி ஏற்பாடு செய்து, ஒரு சிறிய குட்வில் ஜெஸ்ச்சர் வழங்குங்கள்.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(561, 141, 12, 'పరిస్థితిని స్పష్టంగా వివరించి, ఎంచుకున్న రంగుతో 3 రోజుల్లో డెలివరీని కన్ఫర్మ్ చేయండి.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(562, 141, 12, 'ఆలస్యానికి క్షమాపణ చెప్పి, ప్రక్రియను వేగవంతం చేస్తామని హామీ ఇచ్చి, కస్టమర్‌కు తరచూ అప్డేట్లు ఇవ్వండి.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(563, 141, 12, 'అదే వేరియంట్‌ను మరో రంగులో ఆఫర్ చేసి, పుట్టినరోజు అనుభవాన్ని మెరుగుపరచడానికి ఉచిత విలువ-జోడించిన సేవను ఇవ్వండి.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(564, 141, 12, 'స్టాక్ టైమ్‌లైన్‌ను పారదర్శకంగా వివరించి, 3 రోజులు తర్వాత డెలివరీని కన్ఫర్మ్ చేసి, హోమ్ డెలివరీ ఏర్పాటు చేసి, ఒక చిన్న గుడ్‌విల్ జెస్చర్ ఇవ్వండి.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(565, 142, 12, 'സാഹചര്യം വ്യക്തമായി വിശദീകരിച്ച് തിരഞ്ഞെടുത്ത നിറത്തിൽ 3 ദിവസത്തിനുള്ളിൽ ഡെലിവറി ഉറപ്പാക്കുക.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(566, 142, 12, 'വൈകിയതിന് ക്ഷമ ചോദിച്ച്, പ്രക്രിയ വേഗത്തിലാക്കുമെന്ന് ഉറപ്പ് നൽകി, കസ്റ്റമറെ സ്ഥിരമായി അപ്‌ഡേറ്റ് ചെയ്യുക.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(567, 142, 12, 'അതേ വേരിയന്റ് മറ്റൊരു നിറത്തിൽ ഓഫർ ചെയ്ത്, പിറന്നാൾ അനുഭവം മെച്ചപ്പെടുത്താൻ ഒരു സൗജന്യ വാല്യൂ-ആഡഡ് സർവീസ് ഉൾപ്പെടുത്തുക.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(568, 142, 12, 'സ്റ്റോക്ക് ടൈംലൈൻ സുതാര്യമായി വിശദീകരിച്ച്, 3 ദിവസം കഴിഞ്ഞ് ഡെലിവറി ഉറപ്പാക്കി, ഹോം ഡെലിവറി ക്രമീകരിച്ച്, ഒരു ചെറിയ ഗുഡ്‌വിൽ ജെസ്‌ചർ നൽകുക.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(569, 143, 12, 'ಪರಿಸ್ಥಿತಿಯನ್ನು ಸ್ಪಷ್ಟವಾಗಿ ವಿವರಿಸಿ, ಆಯ್ಕೆ ಮಾಡಿದ ಬಣ್ಣದೊಂದಿಗೆ 3 ದಿನಗಳಲ್ಲಿ ಡೆಲಿವರಿ ಖಚಿತಪಡಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(570, 143, 12, 'ತಡವಾದುದಕ್ಕಾಗಿ ಕ್ಷಮೆ ಕೇಳಿ, ಪ್ರಕ್ರಿಯೆಯನ್ನು ವೇಗಗೊಳಿಸುವುದಾಗಿ ಭರವಸೆ ನೀಡಿ ಮತ್ತು ಗ್ರಾಹಕರಿಗೆ ನಿಯಮಿತ ಅಪ್‌ಡೇಟ್ ನೀಡಿರಿ.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(571, 143, 12, 'ಅದೇ ವೇರಿಯಂಟ್ ಅನ್ನು ಮತ್ತೊಂದು ಬಣ್ಣದಲ್ಲಿ ಆಫರ್ ಮಾಡಿ, ಹುಟ್ಟುಹಬ್ಬದ ಅನುಭವವನ್ನು ಉತ್ತಮಗೊಳಿಸಲು ಉಚಿತ ವ್ಯಾಲ್ಯೂ-ಆಡ್ಡೆಡ್ ಸೇವೆಯನ್ನು ಸೇರಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(572, 143, 12, 'ಸ್ಟಾಕ್ ಟೈಮ್‌ಲೈನ್ ಅನ್ನು ಪಾರದರ್ಶಕವಾಗಿ ವಿವರಿಸಿ, 3 ದಿನಗಳ ನಂತರ ಡೆಲಿವರಿ ಖಚಿತಪಡಿಸಿ, ಹೋಮ್ ಡೆಲಿವರಿ ವ್ಯವಸ್ಥೆ ಮಾಡಿ ಮತ್ತು ಒಂದು ಸಣ್ಣ ಗುಡ್‌ವಿಲ್ ಜೆಸ್ಚರ್ ನೀಡಿ.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(573, 144, 12, 'ପରିସ୍ଥିତିକୁ ସ୍ପଷ୍ଟଭାବେ ବୁଝାନ୍ତୁ ଏବଂ ବାଛିଥିବା ରଙ୍ଗ ସହ 3 ଦିନ ମଧ୍ୟରେ ଡିଲିଭରି ନିଶ୍ଚିତ କରନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(574, 144, 12, 'ବିଳମ୍ବ ପାଇଁ କ୍ଷମା ଚାହାନ୍ତୁ, ପ୍ରକ୍ରିୟା ଶୀଘ୍ର କରିବାକୁ ପ୍ରତିଶ୍ରୁତି ଦିଅନ୍ତୁ ଏବଂ କଷ୍ଟମରଙ୍କୁ ନିୟମିତ ଅପଡେଟ୍ ଦିଅନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(575, 144, 12, 'ସେହି ଭେରିଆଣ୍ଟକୁ ଅନ୍ୟ ରଙ୍ଗରେ ଅଫର୍ କରନ୍ତୁ ଏବଂ ଜନ୍ମଦିନ ଅନୁଭବକୁ ଉନ୍ନତ କରିବା ପାଇଁ ଏକ ମାଗଣା ଭ୍ୟାଲୁ-ଏଡେଡ୍ ସେବା ଯୋଗ କରନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(576, 144, 12, 'ଷ୍ଟକ୍ ଟାଇମ୍ଲାଇନ୍‌କୁ ସ୍ପଷ୍ଟଭାବେ ବୁଝାନ୍ତୁ, 3 ଦିନ ପରେ ଡିଲିଭରି ନିଶ୍ଚିତ କରନ୍ତୁ, ହୋମ୍ ଡିଲିଭରି ବ୍ୟବସ୍ଥା କରନ୍ତୁ ଏବଂ ଏକ ଛୋଟ ଗୁଡ୍‌ୱିଲ୍ ଜେସ୍ଚର୍ ଦିଅନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(577, 145, 13, 'Explain that the quotation follows standard pricing and assure the customer there are no hidden charges', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(578, 145, 13, 'Provide a clear breakdown of the quotation and explain what is included in the on-road price', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(579, 145, 13, 'Acknowledge the concern and explain why the other dealership may be offering a lower price', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(580, 145, 13, 'Review the other quotation, explain the reason for discount, confirm standard pricing transparency, and offer a value-added benefit', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(581, 146, 13, 'समझाएँ कि कोटेशन स्टैंडर्ड प्राइसिंग के अनुसार है और कस्टमर को भरोसा दिलाएँ कि कोई छिपे हुए चार्ज नहीं हैं।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(582, 146, 13, 'कोटेशन का साफ़ और डिटेल में ब्रेकडाउन दें और बताएं कि ऑन-रोड प्राइस में क्या-क्या शामिल है।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(583, 146, 13, 'कस्टमर की चिंता को स्वीकार करें और समझाएँ कि दूसरी डीलरशिप कम कीमत क्यों दे रही हो सकती है।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(584, 146, 13, 'दूसरे कोटेशन को रिव्यू करें, डिस्काउंट का कारण समझाएँ, स्टैंडर्ड प्राइसिंग की पारदर्शिता कन्फर्म करें और एक वैल्यू-एडेड बेनिफिट ऑफर करें।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(585, 147, 13, 'ਸਮਝਾਓ ਕਿ ਕੋਟੇਸ਼ਨ ਸਟੈਂਡਰਡ ਪ੍ਰਾਈਸਿੰਗ ਅਨੁਸਾਰ ਹੈ ਅਤੇ ਭਰੋਸਾ ਦਿਓ ਕਿ ਕੋਈ ਲੁਕੇ ਹੋਏ ਚਾਰਜ ਨਹੀਂ ਹਨ।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(586, 147, 13, 'ਕੋਟੇਸ਼ਨ ਦਾ ਸਪਸ਼ਟ ਅਤੇ ਵਿਸਥਾਰ ਨਾਲ ਬ੍ਰੇਕਡਾਊਨ ਦਿਓ ਅਤੇ ਦੱਸੋ ਕਿ ਆਨ-ਰੋਡ ਪ੍ਰਾਈਸ ਵਿੱਚ ਕੀ-ਕੀ ਸ਼ਾਮਲ ਹੈ।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(587, 147, 13, 'ਕਸਟਮਰ ਦੀ ਚਿੰਤਾ ਨੂੰ ਮੰਨੋ ਅਤੇ ਸਮਝਾਓ ਕਿ ਦੂਜੀ ਡੀਲਰਸ਼ਿਪ ਘੱਟ ਕੀਮਤ ਕਿਉਂ ਦੇ ਰਹੀ ਹੋ ਸਕਦੀ ਹੈ।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(588, 147, 13, 'ਦੂਜੇ ਕੋਟੇਸ਼ਨ ਦੀ ਸਮੀਖਿਆ ਕਰੋ, ਡਿਸਕਾਊਂਟ ਦਾ ਕਾਰਣ ਸਮਝਾਓ, ਸਟੈਂਡਰਡ ਪ੍ਰਾਈਸਿੰਗ ਦੀ ਪਾਰਦਰਸ਼ਤਾ ਕਨਫਰਮ ਕਰੋ ਅਤੇ ਇੱਕ ਵੈਲਯੂ-ਐਡਡ ਫਾਇਦਾ ਆਫਰ ਕਰੋ।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(589, 148, 13, 'સમજાવો કે ક્વોટેશન સ્ટાન્ડર્ડ પ્રાઇસિંગ મુજબ છે અને ખાતરી આપો કે કોઈ છુપાયેલા ચાર્જ નથી.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(590, 148, 13, 'ક્વોટેશનનો સ્પષ્ટ અને વિગતવાર બ્રેકડાઉન આપો અને ઓન-રોડ કિંમતમાં શું સામેલ છે તે સમજાવો.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(591, 148, 13, 'કસ્ટમરની ચિંતા સ્વીકારો અને સમજાવો કે બીજી ડીલરશિપ ઓછી કિંમત કેમ આપી રહી હોઈ શકે.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(592, 148, 13, 'બીજા ક્વોટેશનની સમીક્ષા કરો, ડિસ્કાઉન્ટનું કારણ સમજાવો, સ્ટાન્ડર્ડ પ્રાઇસિંગની પારદર્શિતા કન્ફર્મ કરો અને વેલ્યુ-એડેડ લાભ ઓફર કરો.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(593, 149, 13, 'समजावून सांगा की कोटेशन स्टँडर्ड प्राइसिंगनुसार आहे आणि कोणतेही लपवलेले चार्ज नाहीत याची खात्री द्या.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(594, 149, 13, 'कोटेशनचा स्पष्ट आणि सविस्तर ब्रेकडाउन द्या आणि ऑन-रोड किंमतीत काय समाविष्ट आहे ते समजवा.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(595, 149, 13, 'कस्टमरची चिंता मान्य करा आणि दुसरी डीलरशिप कमी किंमत का देत असेल ते समजवा.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(596, 149, 13, 'दुसऱ्या कोटेशनचा आढावा घ्या, डिस्काउंटचे कारण समजवा, स्टँडर्ड प्राइसिंगची पारदर्शकता कन्फर्म करा आणि व्हॅल्यू-अॅडेड लाभ द्या.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(597, 150, 13, 'ব্যাখ্যা করুন যে কোটেশনটি স্ট্যান্ডার্ড প্রাইসিং অনুযায়ী এবং কোনো গোপন চার্জ নেই।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(598, 150, 13, 'কোটেশনের পরিষ্কার ও বিস্তারিত ব্রেকডাউন দিন এবং অন-রোড মূল্যে কী কী অন্তর্ভুক্ত আছে তা বুঝিয়ে দিন।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(599, 150, 13, 'কাস্টমারের উদ্বেগ স্বীকার করুন এবং কেন অন্য ডিলারশিপ কম দাম দিচ্ছে তা ব্যাখ্যা করুন।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(600, 150, 13, 'অন্য কোটেশনটি রিভিউ করুন, ডিসকাউন্টের কারণ ব্যাখ্যা করুন, স্ট্যান্ডার্ড প্রাইসিং স্বচ্ছতা নিশ্চিত করুন এবং একটি ভ্যালু-অ্যাডেড সুবিধা অফার করুন।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(601, 151, 13, 'বুজাই দিয়ক যে কোটেশ্যনটো ষ্টেণ্ডাৰ্ড প্ৰাইচিং অনুসাৰে আৰু কোনো লুকুৱা চাৰ্জ নাই।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(602, 151, 13, 'কোটেশ্যনৰ স্পষ্ট আৰু বিস্তৃত ব্ৰেকডাউন দিয়ক আৰু অন-ৰোড মূল্যত কি কি অন্তৰ্ভুক্ত আছে সেয়া বুজাওক।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(603, 151, 13, 'কাষ্টমাৰৰ চিন্তাটো স্বীকাৰ কৰক আৰু আন ডীলাৰশ্বিপে কম মূল্য কিয় আগবঢ়াইছে বুজাওক।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(604, 151, 13, 'আন কোটেশ্যনৰ পৰ্যালোচনা কৰক, ডিছকাউণ্টৰ কাৰণ বুজাওক, ষ্টেণ্ডাৰ্ড প্ৰাইচিংৰ স্বচ্ছতা নিশ্চিত কৰক আৰু এটা ভেল্যু-এডেড সুবিধা আগবঢ়াওক।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(605, 152, 13, 'கோட்டேஷன் ஸ்டாண்டர்டு விலைக்கேற்ப இருப்பதாகவும், மறைமுக கட்டணங்கள் எதுவும் இல்லை என்பதையும் விளக்குங்கள்.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(606, 152, 13, 'கோட்டேஷனின் தெளிவான மற்றும் விரிவான பிரேக்டவுன் கொடுத்து, ஆன்ரோடு விலையில் என்னெல்லாம் உள்ளதென விளக்குங்கள்.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(607, 152, 13, 'கஸ்டமரின் கவலை ஏற்று, மற்ற டீலர்ஷிப் ஏன் குறைந்த விலை வழங்கலாம் என்பதை விளக்குங்கள்.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(608, 152, 13, 'மற்ற கோட்டேஷனை ரிவ்யூ செய்து, தள்ளுபடியின் காரணத்தை விளக்கி, ஸ்டாண்டர்டு விலையின் வெளிப்படைத்தன்மையை உறுதி செய்து, ஒரு வால்யூ-அடெட் நன்மை வழங்குங்கள்.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(609, 153, 13, 'కోటేషన్ స్టాండర్డ్ ప్రైసింగ్ ప్రకారం ఉందని మరియు ఎలాంటి దాచిన ఛార్జీలు లేవని వివరించండి.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(610, 153, 13, 'కోటేషన్‌కు స్పష్టమైన మరియు వివరమైన బ్రేక్‌డౌన్ ఇచ్చి, ఆన్-రోడ్ ధరలో ఏమేమి ఉన్నాయి అనేది వివరించండి.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(611, 153, 13, 'కస్టమర్ ఆందోళనను అంగీకరించి, ఇతర డీలర్‌షిప్ తక్కువ ధర ఎందుకు ఇస్తుందో వివరించండి.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(612, 153, 13, 'ఇతర కోటేషన్‌ను సమీక్షించి, డిస్కౌంట్ కారణాన్ని వివరించి, స్టాండర్డ్ ప్రైసింగ్ పారదర్శకతను నిర్ధారించి, ఒక విలువ-జోడించిన ప్రయోజనం ఆఫర్ చేయండి.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(613, 154, 13, 'ക്വോട്ടേഷൻ സ്റ്റാൻഡേർഡ് പ്രൈസിംഗിനുസരിച്ചാണെന്നും മറഞ്ഞ ചാർജുകൾ ഇല്ലെന്നും വിശദീകരിക്കുക.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(614, 154, 13, 'ക്വോട്ടേഷന്റെ വ്യക്തമായും വിശദമായും ബ്രേക്ക്‌డൗൺ നൽകി ഓൺ-റോഡ് വിലയിൽ എന്തെല്ലാം ഉൾപ്പെടുന്നുവെന്ന് വിശദീകരിക്കുക.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(615, 154, 13, 'കസ്റ്റമറുടെ ആശങ്ക അംഗീകരിച്ച്, മറ്റൊരു ഡീലർഷിപ്പ് കുറഞ്ഞ വില നൽകുന്നതിന് കാരണമെന്താകാമെന്ന് വിശദീകരിക്കുക.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(616, 154, 13, 'മറ്റു ക്വോട്ടേഷൻ പരിശോധിച്ച്, ഡിസ്കൗണ്ടിന്റെ കാരണം വിശദീകരിച്ച്, സ്റ്റാൻഡേർഡ് പ്രൈസിംഗ് സുതാര്യത ഉറപ്പാക്കി, ഒരു വാല്യൂ-ആഡഡ് ഗുണം നൽകുക.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(617, 155, 13, 'ಕೋಟೇಶನ್ ಸ್ಟ್ಯಾಂಡರ್ಡ್ ಪ್ರೈಸಿಂಗ್ ಪ್ರಕಾರ ಇದೆ ಮತ್ತು ಯಾವುದೇ ಲುಕಾಯಿತ ಶುಲ್ಕಗಳಿಲ್ಲ ಎಂದು ವಿವರಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(618, 155, 13, 'ಕೋಟೇಶನ್‌ನ ಸ್ಪಷ್ಟ ಮತ್ತು ವಿವರವಾದ ಬ್ರೇಕ್‌ಡೌನ್ ನೀಡಿ, ಆನ್-ರೋಡ್ ಬೆಲೆಯಲ್ಲಿ ಏನು ಏನು ಸೇರಿದೆ ಎಂದು ವಿವರಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(619, 155, 13, 'ಗ್ರಾಹಕರ ಚಿಂತೆಯನ್ನು ಒಪ್ಪಿಕೊಂಡು, ಇನ್ನೊಂದು ಡೀಲರ್‌ಶಿಪ್ ಕಡಿಮೆ ಬೆಲೆ ಯಾಕೆ ನೀಡಬಹುದು ಎಂದು ವಿವರಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(620, 155, 13, 'ಇನ್ನೊಂದು ಕೋಟೇಶನ್ ಅನ್ನು ಪರಿಶೀಲಿಸಿ, ಡಿಸ್ಕೌಂಟ್ ಕಾರಣವನ್ನು ವಿವರಿಸಿ, ಸ್ಟ್ಯಾಂಡರ್ಡ್ ಪ್ರೈಸಿಂಗ್ ಪಾರದರ್ಶಕತೆಯನ್ನು ಖಚಿತಪಡಿಸಿ ಮತ್ತು ಒಂದು ವ್ಯಾಲ್ಯೂ-ಆಡ್ಡೆಡ್ ಲಾಭವನ್ನು ನೀಡಿ.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(621, 156, 13, 'କୋଟେସନ୍‌ ଷ୍ଟାଣ୍ଡାର୍ଡ ପ୍ରାଇସିଂ ଅନୁଯାୟୀ ଅଛି ଏବଂ କୌଣସି ଲୁଚିଥିବା ଚାର୍ଜ୍‌ ନାହିଁ ବୋଲି ବୁଝାନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(622, 156, 13, 'କୋଟେସନ୍‌ର ସ୍ପଷ୍ଟ ଓ ବିସ୍ତୃତ ବ୍ରେକଡାଉନ୍‌ ଦିଅନ୍ତୁ ଏବଂ ଅନ୍-ରୋଡ୍‌ ମୂଲ୍ୟରେ କଣ କଣ ଅନ୍ତର୍ଭୁକ୍ତ ଅଛି ସେଥି ଖୋଲାମେଲା କରନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(623, 156, 13, 'କଷ୍ଟମରଙ୍କ ଚିନ୍ତାକୁ ସ୍ୱୀକାର କରନ୍ତୁ ଏବଂ ଅନ୍ୟ ଡିଲର୍‌ଶିପ୍‌ କମ୍‌ ଦାମ୍‌ କାହିଁକି ଦେଉଛି ବୋଲି ବୁଝାନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(624, 156, 13, 'ଅନ୍ୟ କୋଟେସନ୍‌କୁ ଖତିଆନ କରନ୍ତୁ, ଡିସ୍କାଉଣ୍ଟର କାରଣ ବୁଝାନ୍ତୁ, ଷ୍ଟାଣ୍ଡାର୍ଡ ପ୍ରାଇସିଂର ପାରଦର୍ଶିତା ନିଶ୍ଚିତ କରନ୍ତୁ ଏବଂ ଏକ ଭ୍ୟାଲୁ-ଏଡେଡ୍ ଲାଭ ଅଫର୍ କରନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(625, 157, 14, 'Apologize to the customer and them that they are not eligible for the scheme', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(626, 157, 14, 'Apologize for the confusion and explain the eligibility criteria of the scheme', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(627, 157, 14, 'Apologize, explain the eligibility criteria, and suggest an alternative finance option', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(628, 157, 14, 'Apologize, explain the eligibility criteria, suggest a suitable finance option, and offer help with the application process', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(629, 158, 14, 'कस्टमर से माफ़ी माँगें और बताएं कि वे इस स्कीम के लिए पात्र नहीं हैं।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(630, 158, 14, 'कन्फ्यूजन के लिए माफ़ी माँगें और स्कीम की एलिजिबिलिटी क्राइटेरिया समझाएँ।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(631, 158, 14, 'माफ़ी माँगें, एलिजिबिलिटी क्राइटेरिया समझाएँ और कोई वैकल्पिक फाइनेंस ऑप्शन सुझाएँ।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(632, 158, 14, 'माफ़ी माँगें, एलिजिबिलिटी क्राइटेरिया समझाएँ, एक उपयुक्त फाइनेंस ऑप्शन सुझाएँ और आवेदन प्रक्रिया में मदद की पेशकश करें।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(633, 159, 14, 'ਕਸਟਮਰ ਤੋਂ ਮਾਫ਼ੀ ਮੰਗੋ ਅਤੇ ਦੱਸੋ ਕਿ ਉਹ ਇਸ ਸਕੀਮ ਲਈ ਯੋਗ ਨਹੀਂ ਹਨ।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(634, 159, 14, 'ਗਲਤਫਹਿਮੀ ਲਈ ਮਾਫ਼ੀ ਮੰਗੋ ਅਤੇ ਸਕੀਮ ਦੇ ਯੋਗਤਾ ਮਾਪਦੰਡ ਸਮਝਾਓ।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(635, 159, 14, 'ਮਾਫ਼ੀ ਮੰਗੋ, ਯੋਗਤਾ ਮਾਪਦੰਡ ਸਮਝਾਓ ਅਤੇ ਕੋਈ ਬਦਲ ਵਿੱਤੀ ਵਿਕਲਪ ਸੁਝਾਓ।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(636, 159, 14, 'ਮਾਫ਼ੀ ਮੰਗੋ, ਯੋਗਤਾ ਮਾਪਦੰਡ ਸਮਝਾਓ, ਇੱਕ ਉਚਿਤ ਵਿੱਤੀ ਵਿਕਲਪ ਸੁਝਾਓ ਅਤੇ ਅਰਜ਼ੀ ਪ੍ਰਕਿਰਿਆ ਵਿੱਚ ਮਦਦ ਦੀ ਪੇਸ਼ਕਸ਼ ਕਰੋ।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(637, 160, 14, 'કસ્ટમર પાસે માફી માગો અને જણાવો કે તેઓ આ યોજના માટે પાત્ર નથી.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(638, 160, 14, 'ગેરસમજ માટે માફી માગો અને યોજનાની પાત્રતા માપદંડ સમજાવો.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(639, 160, 14, 'માફી માગો, પાત્રતા માપદંડ સમજાવો અને કોઈ વિકલ્પિક ફાઇનાન્સ વિકલ્પ સૂચવો.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(640, 160, 14, 'માફી માગો, પાત્રતા માપદંડ સમજાવો, યોગ્ય ફાઇનાન્સ વિકલ્પ સૂચવો અને અરજી પ્રક્રિયામાં મદદની ઓફર કરો.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(641, 161, 14, 'कस्टमरची माफी मागा आणि ते या योजनेसाठी पात्र नाहीत हे सांगा.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(642, 161, 14, 'गोंधळाबद्दल माफी मागा आणि योजनेचे पात्रता निकष समजवा.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(643, 161, 14, 'माफी मागा, पात्रता निकष समजवा आणि पर्यायी फायनान्स पर्याय सुचवा.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(644, 161, 14, 'माफी मागा, पात्रता निकष समजवा, योग्य फायनान्स पर्याय सुचवा आणि अर्ज प्रक्रियेत मदत करण्याची ऑफर द्या.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(645, 162, 14, 'কাস্টমারের কাছে ক্ষমা চান এবং জানান যে তিনি এই স্কিমের জন্য যোগ্য নন।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(646, 162, 14, 'ভুল বোঝাবুঝির জন্য ক্ষমা চান এবং স্কিমের যোগ্যতার মানদণ্ড ব্যাখ্যা করুন।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(647, 162, 14, 'ক্ষমা চান, যোগ্যতার মানদণ্ড ব্যাখ্যা করুন এবং বিকল্প ফাইন্যান্স অপশন প্রস্তাব করুন।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(648, 162, 14, 'ক্ষমা চান, যোগ্যতার মানদণ্ড ব্যাখ্যা করুন, উপযুক্ত ফাইন্যান্স অপশন প্রস্তাব করুন এবং আবেদন প্রক্রিয়ায় সাহায্যের প্রস্তাব দিন।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(649, 163, 14, 'কাষ্টমাৰৰ ওচৰত ক্ষমা বিচাৰক আৰু জনাওক যে তেওঁ এই স্কীমৰ বাবে যোগ্য নহয়।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(650, 163, 14, 'গোলযোগৰ বাবে ক্ষমা বিচাৰক আৰু স্কীমৰ যোগ্যতাৰ মানদণ্ড বুজাওক।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(651, 163, 14, 'ক্ষমা বিচাৰক, যোগ্যতাৰ মানদণ্ড বুজাওক আৰু বিকল্প ফাইনেন্স অপশ্যন আগবঢ়াওক।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(652, 163, 14, 'ক্ষমা বিচাৰক, যোগ্যতাৰ মানদণ্ড বুজাওক, উপযুক্ত ফাইনেন্স অপশ্যন আগবঢ়াওক আৰু আবেদন প্ৰক্ৰিয়াত সহায়ৰ প্ৰস্তাৱ দিওক।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(653, 164, 14, 'கஸ்டமரிடம் மன்னிப்பு கேட்டு, அவர் இந்த திட்டத்திற்கு தகுதியற்றவர் என்பதை தெரிவிக்கவும்.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(654, 164, 14, 'குழப்பத்திற்கு மன்னிப்பு கேட்டு, திட்டத்தின் தகுதி விதிகளை விளக்கவும்.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(655, 164, 14, 'மன்னிப்பு கேட்டு, தகுதி விதிகளை விளக்கி, மாற்று நிதி விருப்பத்தை பரிந்துரைக்கவும்.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(656, 164, 14, 'மன்னிப்பு கேட்டு, தகுதி விதிகளை விளக்கி, பொருத்தமான நிதி விருப்பத்தை பரிந்துரைத்து, விண்ணப்ப செயல்முறையில் உதவி வழங்க முன்வரவும்.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(657, 165, 14, 'కస్టమర్‌కు క్షమాపణ చెప్పి, వారు ఈ పథకానికి అర్హులు కాదని తెలియజేయండి.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(658, 165, 14, 'గందరగోళానికి క్షమాపణ చెప్పి, పథక అర్హత ప్రమాణాలను వివరించండి.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(659, 165, 14, 'క్షమాపణ చెప్పి, అర్హత ప్రమాణాలను వివరించి, ప్రత్యామ్నాయ ఫైనాన్స్ ఎంపికను సూచించండి.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(660, 165, 14, 'క్షమాపణ చెప్పి, అర్హత ప్రమాణాలను వివరించి, సరైన ఫైనాన్స్ ఎంపికను సూచించి, అప్లికేషన్ ప్రక్రియలో సహాయం అందిస్తామని చెప్పండి.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(661, 166, 14, 'കസ്റ്റമറോട് ക്ഷമ ചോദിച്ച്, അവർ ഈ സ്കീമിന് അർഹരല്ലെന്ന് അറിയിക്കുക.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(662, 166, 14, 'കുഴപ്പത്തിന് ക്ഷമ ചോദിച്ച്, സ്കീമിന്റെ അർഹത മാനദണ്ഡങ്ങൾ വിശദീകരിക്കുക.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(663, 166, 14, 'ക്ഷമ ചോദിച്ച്, അർഹത മാനദണ്ഡങ്ങൾ വിശദീകരിച്ച്, ഒരു പകരം ഫൈനാൻസ് ഓപ്ഷൻ നിർദ്ദേശിക്കുക.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(664, 166, 14, 'ക്ഷമ ചോദിച്ച്, അർഹത മാനദണ്ഡങ്ങൾ വിശദീകരിച്ച്, അനുയോജ്യമായ ഫൈനാൻസ് ഓപ്ഷൻ നിർദ്ദേശിച്ച്, അപേക്ഷാ പ്രക്രിയയിൽ സഹായം വാഗ്ദാനം ചെയ്യുക.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(665, 167, 14, 'ಗ್ರಾಹಕರಿಗೆ ಕ್ಷಮೆ ಕೇಳಿ ಮತ್ತು ಅವರು ಈ ಯೋಜನೆಗೆ ಅರ್ಹರಲ್ಲ ಎಂದು ತಿಳಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(666, 167, 14, 'ಗೊಂದಲಕ್ಕಾಗಿ ಕ್ಷಮೆ ಕೇಳಿ ಮತ್ತು ಯೋಜನೆಯ ಅರ್ಹತಾ ಮಾನದಂಡಗಳನ್ನು ವಿವರಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(667, 167, 14, 'ಕ್ಷಮೆ ಕೇಳಿ, ಅರ್ಹತಾ ಮಾನದಂಡಗಳನ್ನು ವಿವರಿಸಿ ಮತ್ತು ಪರ್ಯಾಯ ಹಣಕಾಸು ಆಯ್ಕೆಯನ್ನು ಸೂಚಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(668, 167, 14, 'ಕ್ಷಮೆ ಕೇಳಿ, ಅರ್ಹತಾ ಮಾನದಂಡಗಳನ್ನು ವಿವರಿಸಿ, ಸೂಕ್ತ ಹಣಕಾಸು ಆಯ್ಕೆಯನ್ನು ಸೂಚಿಸಿ ಮತ್ತು ಅರ್ಜಿ ಪ್ರಕ್ರಿಯೆಯಲ್ಲಿ ಸಹಾಯ ಮಾಡುವುದಾಗಿ ತಿಳಿಸಿ.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
