	(780, 195, 17, 'ਟੈਕਨੋਲੋਜੀ ਅਤੇ ਇਸਦੇ ਫਾਇਦੇ ਸਮਝਾਓ, Hero ਦੇ ਭਰੋਸੇਯੋਗ ਫਾਇਦੇ ਦੱਸੋ ਅਤੇ ਟੈਸਟ ਰਾਈਡ ਆਫਰ ਕਰੋ।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(781, 196, 17, 'કસ્ટમરને ખાતરી આપો કે Glamour Xમાં ઉપયોગમાં લેવાયેલ Ride-By-Wire એક વિશ્વસનીય ટેકનોલોજી છે.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(782, 196, 17, 'Ride-By-Wire ફીચર સમજાવો અને તેના બધા ફાયદા હાઇલાઇટ કરો.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(783, 196, 17, 'આ ફીચર સેગમેન્ટમાં પ્રથમ વખત આપવામાં આવ્યું છે એવું જણાવો અને તેના ફાયદા સમજાવવા ટેસ્ટ રાઈડ ઓફર કરો.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(784, 196, 17, 'ટેકનોલોજી અને તેના ફાયદા સમજાવો, Heroના વિશ્વસનીય ફાયદા બતાવો અને ટેસ્ટ રાઈડ ઓફર કરો.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(785, 197, 17, 'कस्टमरला खात्री द्या की Glamour X मध्ये दिलेले Ride-By-Wire हे विश्वासार्ह तंत्रज्ञान आहे.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(786, 197, 17, 'Ride-By-Wire फीचर समजावून सांगा आणि त्याचे सर्व फायदे हायलाइट करा.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(787, 197, 17, 'हे फीचर सेगमेंटमध्ये पहिल्यांदाच दिले आहे हे सांगा आणि फायदे समजण्यासाठी टेस्ट राईड ऑफर करा.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(788, 197, 17, 'तंत्रज्ञान आणि त्याचे फायदे समजावून सांगा, Hero चे विश्वासार्ह फायदे सांगा आणि टेस्ट राईड ऑफर करा.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(789, 198, 17, 'কাস্টমারকে আশ্বস্ত করুন যে Glamour X-এ ব্যবহৃত Ride-By-Wire একটি নির্ভরযোগ্য প্রযুক্তি।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(790, 198, 17, 'Ride-By-Wire ফিচারটি ব্যাখ্যা করুন এবং এর সব সুবিধা তুলে ধরুন।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(791, 198, 17, 'বলুন যে এটি সেগমেন্টে প্রথমবার দেওয়া হয়েছে এবং সুবিধা বোঝাতে একটি টেস্ট রাইড অফার করুন।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(792, 198, 17, 'প্রযুক্তি ও এর সুবিধাগুলি ব্যাখ্যা করুন, Hero-এর নির্ভরযোগ্য সুবিধাগুলি তুলে ধরুন এবং টেস্ট রাইড অফার করুন।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(793, 199, 17, 'কাষ্টমাৰক আশ্বাস দিয়ক যে Glamour X-ত ব্যৱহৃত Ride-By-Wire এটা বিশ্বাসযোগ্য প্ৰযুক্তি।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(794, 199, 17, 'Ride-By-Wire ফিচাৰটো বুজাওক আৰু ইয়াৰ সকলো সুবিধা উজাগৰ কৰক।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(795, 199, 17, 'এই ফিচাৰটো এই শ্ৰেণীত প্ৰথমবাৰৰ বাবে দিয়া হৈছে বুলি কওক আৰু সুবিধা বুজাবলৈ টেষ্ট ৰাইড আগবঢ়াওক।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(796, 199, 17, 'প্ৰযুক্তি আৰু ইয়াৰ সুবিধাসমূহ বুজাওক, Hero-ৰ বিশ্বাসযোগ্য সুবিধা বৰ্ণনা কৰক আৰু টেষ্ট ৰাইড আগবঢ়াওক।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(797, 200, 17, 'Glamour X-ல் பயன்படுத்தப்படும் Ride-By-Wire ஒரு நம்பகமான தொழில்நுட்பம் என்பதை கஸ்டமருக்கு உறுதி அளிக்கவும்.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(798, 200, 17, 'Ride-By-Wire அம்சத்தை விளக்கி, அது வழங்கும் அனைத்து நன்மைகளையும் எடுத்துக்காட்டுங்கள்.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(799, 200, 17, 'இந்த அம்சம் இந்த வகையில் முதல் முறையாக வழங்கப்படுகிறது என்பதை கூறி, அதன் பயன்களை புரிந்து கொள்ள டெஸ்ட் ரைடு வழங்குங்கள்.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(800, 200, 17, 'தொழில்நுட்பம் மற்றும் அதன் நன்மைகளை விளக்கி, Hero-வின் நம்பகமான பலன்களை கூறி, டெஸ்ட் ரைடு வழங்குங்கள்.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(801, 201, 17, 'Glamour X‌లో ఉపయోగించిన Ride-By-Wire ఒక నమ్మకమైన టెక్నాలజీ అని కస్టమర్‌కు భరోసా ఇవ్వండి.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(802, 201, 17, 'Ride-By-Wire ఫీచర్‌ను వివరించి, అది అందించే అన్ని ప్రయోజనాలను హైలైట్ చేయండి.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(803, 201, 17, 'ఈ ఫీచర్ ఈ సెగ్మెంట్‌లో మొదటిసారిగా అందించబడిందని చెప్పి, దాని ప్రయోజనాలు అర్థం చేసుకునేందుకు టెస్ట్ రైడ్ ఆఫర్ చేయండి.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(804, 201, 17, 'టెక్నాలజీ మరియు దాని ప్రయోజనాలను వివరించి, Hero నమ్మకమైన లాభాలను తెలియజేసి, టెస్ట్ రైడ్ ఆఫర్ చేయండి.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(805, 202, 17, 'Glamour X-ൽ ഉപയോഗിക്കുന്ന Ride-By-Wire വിശ്വസനീയമായ ഒരു സാങ്കേതികവിദ്യയാണെന്ന് കസ്റ്റമറോട് ഉറപ്പുനൽകുക.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(806, 202, 17, 'Ride-By-Wire ഫീച്ചർ വിശദീകരിച്ച് അതിന്റെ എല്ലാ ഗുണങ്ങളും ഹൈലൈറ്റ് ചെയ്യുക.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(807, 202, 17, 'ഈ ഫീച്ചർ ഈ വിഭാഗത്തിൽ ആദ്യമായാണ് നൽകിയിരിക്കുന്നത് എന്ന് വ്യക്തമാക്കുകയും ഗുണങ്ങൾ മനസിലാക്കാൻ ടെസ്റ്റ് റൈഡ് നൽകുകയും ചെയ്യുക.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(808, 202, 17, 'സാങ്കേതികവിദ്യയും അതിന്റെ ഗുണങ്ങളും വിശദീകരിച്ച്, Heroയുടെ വിശ്വസനീയത വ്യക്തമാക്കുകയും ടെസ്റ്റ് റൈഡ് നൽകുകയും ചെയ്യുക.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(809, 203, 17, 'Glamour X ನಲ್ಲಿ ಬಳಸಿರುವ Ride-By-Wire ಒಂದು ವಿಶ್ವಾಸಾರ್ಹ ತಂತ್ರಜ್ಞಾನ ಎಂದು ಗ್ರಾಹಕರಿಗೆ ಭರವಸೆ ನೀಡಿ.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(810, 203, 17, 'Ride-By-Wire ವೈಶಿಷ್ಟ್ಯವನ್ನು ವಿವರಿಸಿ ಮತ್ತು ಅದು ನೀಡುವ ಎಲ್ಲಾ ಲಾಭಗಳನ್ನು ಹೈಲೈಟ್ ಮಾಡಿ.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(811, 203, 17, 'ಈ ವೈಶಿಷ್ಟ್ಯವು ಈ ಸೆಗ್ಮೆಂಟ್‌ನಲ್ಲಿ ಮೊದಲ ಬಾರಿಗೆ ನೀಡಲಾಗಿದೆ ಎಂದು ಹೇಳಿ, ಲಾಭಗಳನ್ನು ಅರ್ಥಮಾಡಿಕೊಳ್ಳಲು ಟೆಸ್ಟ್ ರೈಡ್ ಆಫರ್ ಮಾಡಿ.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(812, 203, 17, 'ತಂತ್ರಜ್ಞಾನ ಮತ್ತು ಅದರ ಲಾಭಗಳನ್ನು ವಿವರಿಸಿ, Hero ನ ನಂಬಿಕೆಗೂರ್ಹ ಲಾಭಗಳನ್ನು ತಿಳಿಸಿ ಮತ್ತು ಟೆಸ್ಟ್ ರೈಡ್ ಆಫರ್ ಮಾಡಿ.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(813, 204, 17, 'Glamour X ରେ ବ୍ୟବହୃତ Ride-By-Wire ଏକ ବିଶ୍ୱସନୀୟ ପ୍ରଯୁକ୍ତି ବୋଲି କଷ୍ଟମରଙ୍କୁ ଆଶ୍ୱାସନ ଦିଅନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(814, 204, 17, 'Ride-By-Wire ବୈଶିଷ୍ଟ୍ୟକୁ ବୁଝାନ୍ତୁ ଏବଂ ଏହା ଦେଉଥିବା ସମସ୍ତ ଲାଭ ଉଲ୍ଲେଖ କରନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(815, 204, 17, 'ଏହି ବୈଶିଷ୍ଟ୍ୟ ଏହି ସେଗ୍ମେଣ୍ଟରେ ପ୍ରଥମ ବୋଲି କହି, ଲାଭ ବୁଝିବା ପାଇଁ ଟେଷ୍ଟ ରାଇଡ୍ ଅଫର୍ କରନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(816, 204, 17, 'ପ୍ରଯୁକ୍ତି ଓ ଏହାର ଲାଭ ବୁଝାନ୍ତୁ, Hero ର ବିଶ୍ୱସନୀୟ ଲାଭ ଦେଖାନ୍ତୁ ଏବଂ ଟେଷ୍ଟ ରାଇଡ୍ ଅଫର୍ କରନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(817, 205, 18, 'Highlight the individual advantages of scooters vs motorcycles ', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(818, 205, 18, 'Showcase both options and ask the customer to experience both first-hand', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(819, 205, 18, 'Probe his requirements, explain benefits of both the motorcycle and scooter, and suggest which might suit him better', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(820, 205, 18, 'Probe for details, identify needs, pitch both options with benefits, and offer guidance while letting the customer try both', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(821, 206, 18, 'स्कूटर और मोटरसाइकिल के अलग-अलग फायदों को हाइलाइट करें।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(822, 206, 18, 'दोनों ऑप्शंस दिखाएँ और कस्टमर से कहें कि वे दोनों को खुद अनुभव करें।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(823, 206, 18, 'कस्टमर की ज़रूरतें समझें, स्कूटर और मोटरसाइकिल दोनों के फायदे समझाएँ और बताएं कि उनके लिए कौन सा बेहतर रहेगा।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(824, 206, 18, 'डिटेल में ज़रूरतें समझें, दोनों ऑप्शंस के फायदे बताकर पिच करें और कस्टमर को दोनों ट्राय करने देते हुए सही मार्गदर्शन दें।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(825, 207, 18, 'ਸਕੂਟਰ ਅਤੇ ਮੋਟਰਸਾਈਕਲ ਦੇ ਅਲੱਗ-ਅਲੱਗ ਫਾਇਦੇ ਉਜਾਗਰ ਕਰੋ।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(826, 207, 18, 'ਦੋਵੇਂ ਵਿਕਲਪ ਦਿਖਾਓ ਅਤੇ ਕਸਟਮਰ ਨੂੰ ਦੋਵੇਂ ਖੁਦ ਅਨੁਭਵ ਕਰਨ ਲਈ ਕਹੋ।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(827, 207, 18, 'ਕਸਟਮਰ ਦੀਆਂ ਲੋੜਾਂ ਸਮਝੋ, ਸਕੂਟਰ ਅਤੇ ਮੋਟਰਸਾਈਕਲ ਦੋਵੇਂ ਦੇ ਫਾਇਦੇ ਸਮਝਾਓ ਅਤੇ ਦੱਸੋ ਕਿ ਕਿਹੜਾ ਵਧੀਆ ਰਹੇਗਾ।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(828, 207, 18, 'ਵੇਰਵੇ ਨਾਲ ਲੋੜਾਂ ਪਤਾ ਕਰੋ, ਦੋਵੇਂ ਵਿਕਲਪਾਂ ਦੇ ਫਾਇਦੇ ਦੱਸੋ ਅਤੇ ਕਸਟਮਰ ਨੂੰ ਦੋਵੇਂ ਆਜ਼ਮਾਉਂਦੇ ਹੋਏ ਸਹੀ ਮਾਰਗਦਰਸ਼ਨ ਦਿਓ।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(829, 208, 18, 'સ્કૂટર અને મોટરસાયકલના અલગ-અલગ ફાયદાઓને હાઇલાઇટ કરો.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(830, 208, 18, 'બંને વિકલ્પો બતાવો અને કસ્ટમરને બંનેનો જાતે અનુભવ લેવા કહો.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(831, 208, 18, 'કસ્ટમરની જરૂરિયાતો જાણો, સ્કૂટર અને મોટરસાયકલના ફાયદા સમજાવો અને કયો વધુ યોગ્ય છે તે સૂચવો.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(832, 208, 18, 'વિગતે જરૂરિયાતો ઓળખો, બંને વિકલ્પોના ફાયદા સાથે પિચ કરો અને કસ્ટમરને બંને અજમાવવા દેતા માર્ગદર્શન આપો.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(833, 209, 18, 'स्कूटर आणि मोटरसायकलचे वेगवेगळे फायदे ठळकपणे सांगा.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
