	(847, 212, 18, 'கஸ்டமரின் தேவைகளை அறிந்து, ஸ்கூட்டர் மற்றும் பைக்கின் நன்மைகளை விளக்கி, எது பொருத்தம் என பரிந்துரையுங்கள்.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(848, 212, 18, 'விவரமாக தேவைகளை கண்டறிந்து, இரு தேர்வுகளையும் நன்மைகளுடன் விளக்கி, கஸ்டமர் இரண்டையும் முயற்சி செய்ய வழிகாட்டுங்கள்.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
