	(854, 214, 18, 'രണ്ടു ഓപ്ഷനുകളും കാണിച്ച്, കസ്റ്റമറെ രണ്ടും നേരിട്ട് അനുഭവിക്കാൻ പറയുക.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(855, 214, 18, 'കസ്റ്റമറുടെ ആവശ്യങ്ങൾ മനസ്സിലാക്കി, സ്കൂട്ടറിന്റെയും ബൈക്കിന്റെയും ഗുണങ്ങൾ വിശദീകരിച്ച് ഏത് കൂടുതൽ അനുയോജ്യമാണെന്ന് നിർദ്ദേശിക്കുക.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
