	(941, 236, 20, 'Xoom 110-ஐ பரிந்துரைத்து, கஸ்டமரின் தேவையை பார்த்தால் Xoom 125-வும் பொருத்தமானது என்று சுருக்கமாக கூறுங்கள்.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(942, 236, 20, 'Xoom 110-ஐ பரிந்துரைத்து, 110-ஐ விட Xoom 125 வழங்கும் கூடுதல் நன்மைகளை விளக்குங்கள்.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(943, 236, 20, 'Xoom 110-ஐ பரிந்துரைத்து, Xoom 125-ன் நன்மைகளை காட்டி, சற்று அதிக விலையில் கிடைக்கும் மதிப்பை விளக்குங்கள்.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(944, 236, 20, 'Xoom 110-ஐ பரிந்துரைத்து, Xoom 125-ன் கூடுதல் மதிப்பை விளக்கி, அது கஸ்டமரின் தேவைக்கு எவ்வாறு பொருந்துகிறது என்பதை காட்டி, இரண்டிற்கும் டெஸ்ட் ரைடு வழங்குங்கள்.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(945, 237, 20, 'Xoom 110‌ను పిచ్ చేసి, కస్టమర్ అవసరాలను బట్టి Xoom 125 కూడా సరిపోతుందని సంక్షిప్తంగా చెప్పండి.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(946, 237, 20, 'Xoom 110‌ను పిచ్ చేసి, 110తో పోల్చితే Xoom 125 అదనపు ప్రయోజనాలను వివరించండి.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(947, 237, 20, 'Xoom 110‌ను పిచ్ చేసి, Xoom 125 ప్రయోజనాలను చూపించి, స్వల్పంగా ఎక్కువ ధరకు లభించే విలువను వివరించండి.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(948, 237, 20, 'Xoom 110‌ను పిచ్ చేసి, Xoom 125 అదనపు విలువను వివరించి, అది కస్టమర్ అవసరాలకు ఎలా సరిపోతుందో చూపించి, రెండింటికీ టెస్ట్ రైడ్ ఆఫర్ చేయండి.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(949, 238, 20, 'Xoom 110 ശുപാർശ ചെയ്ത്, കസ്റ്റമറുടെ ആവശ്യങ്ങൾ നോക്കുമ്പോൾ Xoom 125യും അനുയോജ്യമാണെന്ന് ചുരുക്കത്തിൽ പറയുക.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(950, 238, 20, 'Xoom 110 ശുപാർശ ചെയ്ത്, 110-നെക്കാൾ Xoom 125 നൽകുന്ന അധിക ഗുണങ്ങൾ വിശദീകരിക്കുക.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(951, 238, 20, 'Xoom 110 ശുപാർശ ചെയ്ത്, Xoom 125യുടെ ഗുണങ്ങൾ കാണിച്ച്, കുറച്ച് കൂടുതലുള്ള വിലയ്ക്ക് ലഭിക്കുന്ന മൂല്യം വിശദീകരിക്കുക.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(952, 238, 20, 'Xoom 110 ശുപാർശ ചെയ്ത്, Xoom 125യുടെ അധിക മൂല്യം വിശദീകരിച്ച്, അത് കസ്റ്റമറുടെ ആവശ്യങ്ങളുമായി എങ്ങനെ പൊരുത്തപ്പെടുന്നു എന്ന് കാണിച്ച്, രണ്ടിന്റെയും ടെസ്റ്റ് റൈഡ് നൽകുക.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(953, 239, 20, 'Xoom 110 ಅನ್ನು ಪಿಚ್ ಮಾಡಿ ಮತ್ತು ಗ್ರಾಹಕರ ಅಗತ್ಯಗಳನ್ನು ನೋಡಿದರೆ Xoom 125 ಕೂಡ ಸೂಕ್ತವೆಂದು ಸಂಕ್ಷಿಪ್ತವಾಗಿ ಹೇಳಿ.', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(954, 239, 20, 'Xoom 110 ಅನ್ನು ಪಿಚ್ ಮಾಡಿ ಮತ್ತು 110 ಗೆ ಹೋಲಿಸಿದರೆ Xoom 125 ನೀಡುವ ಹೆಚ್ಚುವರಿ ಲಾಭಗಳನ್ನು ವಿವರಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(955, 239, 20, 'Xoom 110 ಅನ್ನು ಪಿಚ್ ಮಾಡಿ, Xoom 125 ಲಾಭಗಳನ್ನು ತೋರಿಸಿ ಮತ್ತು ಸ್ವಲ್ಪ ಹೆಚ್ಚು ಬೆಲೆಯಲ್ಲಿ ಸಿಗುವ ಮೌಲ್ಯವನ್ನು ವಿವರಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(956, 239, 20, 'Xoom 110 ಅನ್ನು ಪಿಚ್ ಮಾಡಿ, Xoom 125 ನ ಹೆಚ್ಚುವರಿ ಮೌಲ್ಯವನ್ನು ವಿವರಿಸಿ, ಅದು ಗ್ರಾಹಕರ ಅಗತ್ಯಗಳಿಗೆ ಹೇಗೆ ಹೊಂದಿಕೊಳ್ಳುತ್ತದೆ ಎಂದು ತೋರಿಸಿ ಮತ್ತು ಎರಡಕ್ಕೂ ಟೆಸ್ಟ್ ರೈಡ್ ಆಫರ್ ಮಾಡಿ.', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(957, 240, 20, 'Xoom 110 କୁ ପିଚ୍ କରନ୍ତୁ ଏବଂ କଷ୍ଟମରଙ୍କ ଆବଶ୍ୟକତା ଦେଖି Xoom 125 ମଧ୍ୟ ଉପଯୁକ୍ତ ବୋଲି ସଂକ୍ଷେପରେ କୁହନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-25 17:54:28'),
	(958, 240, 20, 'Xoom 110 କୁ ପିଚ୍ କରନ୍ତୁ ଏବଂ 110 ତୁଳନାରେ Xoom 125 ର ଅତିରିକ୍ତ ଲାଭ ବୁଝାନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-25 17:54:28'),
	(959, 240, 20, 'Xoom 110 କୁ ପିଚ୍ କରନ୍ତୁ, Xoom 125 ର ଲାଭ ଦେଖାନ୍ତୁ ଏବଂ ଅଳ୍ପ ଅଧିକ ଦାମରେ ମିଳୁଥିବା ମୂଲ୍ୟ ବୁଝାନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-25 17:54:28'),
	(960, 240, 20, 'Xoom 110 କୁ ପିଚ୍ କରନ୍ତୁ, Xoom 125 ର ଅତିରିକ୍ତ ମୂଲ୍ୟ ବୁଝାନ୍ତୁ, ଏହା କଷ୍ଟମରଙ୍କ ଆବଶ୍ୟକତା ସହ କିପରି ମେଳ ଖାଉଛି ଦେଖାନ୍ତୁ ଏବଂ ଦୁହେଁର ଟେଷ୍ଟ ରାଇଡ୍ ଅଫର୍ କରନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-25 17:54:28'),
	(961, 241, 21, 'Politely refuse the Test Ride and explain that a valid Driving License is mandatory as per dealership and legal policy', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(962, 241, 21, 'Ask the customer to return with a valid license holder and allow the Test Ride with that person riding while the customer sits as pillion', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(963, 241, 21, 'Offer the customer a supervised test ride as a pillion rider to safely experience the Motorcycle', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(964, 241, 21, 'Guide the customer to register online for a Learner’s License and explain the quick process. Invite him back for a Test Ride once he receives it', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(965, 242, 21, 'टेस्ट राइड के लिए विनम्रता से मना करें और समझाएँ कि डीलरशिप और कानूनी नियमों के अनुसार वैध ड्राइविंग लाइसेंस होना अनिवार्य है।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(966, 242, 21, 'ग्राहक से कहें कि वे किसी ऐसे व्यक्ति के साथ दोबारा आएँ जिनके पास वैध ड्राइविंग लाइसेंस हो।\r\n\r\nफिर उस लाइसेंस वाले व्यक्ति को बाइक चलाने दें और ग्राहक पीछे बैठकर (पिलियन के रूप में) टेस्ट राइड का अनुभव कर सकता है।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(967, 242, 21, 'कस्टमर को एक सुपरवाइज्ड टेस्ट राइड ऑफर करें, जिसमें वे पिलियन राइडर के रूप में बैठकर मोटरसाइकिल को सुरक्षित तरीके से अनुभव कर सकें।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(968, 242, 21, 'ग्राहक को बताएं कि वह ऑनलाइन लर्नर लाइसेंस के लिए रजिस्टर कर सकता है और उसे इसकी आसान और जल्दी पूरी होने वाली प्रक्रिया समझाएं।\r\n\r\nउसे कहें कि जैसे ही उसे लर्नर लाइसेंस मिल जाए, वह टेस्ट राइड के लिए दोबारा आ सकता है।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(969, 243, 21, 'ਨਿਮਰਤਾ ਨਾਲ ਟੈਸਟ ਰਾਈਡ ਤੋਂ ਇਨਕਾਰ ਕਰੋ ਅਤੇ ਸਮਝਾਓ ਕਿ ਡੀਲਰਸ਼ਿਪ ਅਤੇ ਕਾਨੂੰਨੀ ਨੀਤੀ ਅਨੁਸਾਰ ਵੈਧ ਡਰਾਈਵਿੰਗ ਲਾਇਸੈਂਸ ਲਾਜ਼ਮੀ ਹੈ।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(970, 243, 21, 'ਗਾਹਕ ਨੂੰ ਕਹੋ ਕਿ ਵੈਧ ਲਾਇਸੈਂਸ ਵਾਲੇ ਵਿਅਕਤੀ ਨਾਲ ਵਾਪਸ ਆਏ। ਉਸ ਵਿਅਕਤੀ ਨੂੰ ਚਲਾਉਣ ਦਿਓ ਅਤੇ ਗਾਹਕ ਪਿਲੀਅਨ ਵਜੋਂ ਬੈਠ ਸਕਦਾ ਹੈ।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(971, 243, 21, 'ਗਾਹਕ ਨੂੰ ਇੱਕ ਸੁਪਰਵਾਈਜ਼ਡ ਟੈਸਟ ਰਾਈਡ ਦੀ ਪੇਸ਼ਕਸ਼ ਕਰੋ, ਜਿਸ ਵਿੱਚ ਉਹ ਪਿਲੀਅਨ ਰਾਈਡਰ ਵਜੋਂ ਬੈਠ ਕੇ ਮੋਟਰਸਾਈਕਲ ਨੂੰ ਸੁਰੱਖਿਅਤ ਤਰੀਕੇ ਨਾਲ ਅਨੁਭਵ ਕਰ ਸਕਣ।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(972, 243, 21, 'ਗਾਹਕ ਨੂੰ ਲਰਨਰ ਲਾਇਸੈਂਸ ਲਈ ਆਨਲਾਈਨ ਰਜਿਸਟਰ ਕਰਨ ਲਈ ਮਾਰਗਦਰਸ਼ਨ ਦਿਓ ਅਤੇ ਲਾਇਸੈਂਸ ਮਿਲਣ ਉਪਰੰਤ ਟੈਸਟ ਰਾਈਡ ਲਈ ਆਮੰਤ੍ਰਿਤ ਕਰੋ।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(973, 244, 21, 'વિનમ્રતાથી ટેસ્ટ રાઇડ માટે ના પાડી સમજાવો કે ડીલરશિપ અને કાનૂની નીતિ મુજબ માન્ય ડ્રાઇવિંગ લાયસન્સ ફરજિયાત છે.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(974, 244, 21, 'ગ્રાહકને માન્ય લાયસન્સ ધરાવતા વ્યક્તિ સાથે ફરી આવવા કહો. તે વ્યક્તિ વાહન ચલાવે અને ગ્રાહક પિલિયન તરીકે બેસી શકે.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(975, 244, 21, 'ગ્રાહકને એક સુપરવાઈઝ્ડ ટેસ્ટ રાઈડ ઓફર કરો, જેમાં તેઓ પિલિયન રાઈડર તરીકે બેસીને મોટરસાયકલનો સુરક્ષિત રીતે અનુભવ કરી શકે.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(976, 244, 21, 'ગ્રાહકને લર્નર લાયસન્સ માટે ઓનલાઇન નોંધણી કરવા માર્ગદર્શન આપો અને લાયસન્સ મળ્યા પછી ટેસ્ટ રાઇડ માટે આમંત્રિત કરો.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(977, 245, 21, 'नम्रपणे टेस्ट राईड नाकारून सांगा की डीलरशिप आणि कायद्यानुसार वैध ड्रायव्हिंग लायसन्स आवश्यक आहे.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(978, 245, 21, 'ग्राहकाला वैध लायसन्स असलेल्या व्यक्तीसोबत पुन्हा येण्यास सांगा. ती व्यक्ती गाडी चालवेल आणि ग्राहक पिलियन म्हणून बसेल.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(979, 245, 21, 'ग्राहकाला सुपरवाइज्ड टेस्ट राईड ऑफर करा, ज्यामध्ये तो पिलियन रायडर म्हणून बसून मोटरसायकलचा सुरक्षितपणे अनुभव घेऊ शकतो.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(980, 245, 21, 'ग्राहकाला लर्नर लायसन्ससाठी ऑनलाइन नोंदणी करण्याचे मार्गदर्शन करा आणि लायसन्स मिळाल्यावर टेस्ट राईडसाठी आमंत्रित करा.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(981, 246, 21, 'ভদ্রভাবে টেস্ট রাইডের জন্য না বলুন এবং বুঝিয়ে দিন যে ডিলারশিপ ও আইন অনুযায়ী বৈধ ড্রাইভিং লাইসেন্স বাধ্যতামূলক।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(982, 246, 21, 'গ্রাহককে বৈধ লাইসেন্সধারী কাউকে নিয়ে আবার আসতে বলুন। সেই ব্যক্তি গাড়ি চালাবে এবং গ্রাহক পিলিয়ন হিসেবে বসবেন।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(983, 246, 21, 'গ্রাহককে একটি সুপারভাইজড টেস্ট রাইড অফার করুন, যাতে তিনি পিলিয়ন রাইডার হিসেবে বসে মোটরসাইকেলটি নিরাপদভাবে অনুভব করতে পারেন।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(984, 246, 21, 'গ্রাহককে লার্নার লাইসেন্সের জন্য অনলাইনে নিবন্ধন করতে সাহায্য করুন এবং লাইসেন্স পাওয়ার পর টেস্ট রাইডের জন্য আমন্ত্রণ জানান।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(985, 247, 21, 'নম্ৰভাৱে টেষ্ট ৰাইড নাকচ কৰি বুজাওক যে ডিলাৰশ্বীপ আৰু আইন অনুসাৰে বৈধ ড্ৰাইভিং লাইচেন্স বাধ্যতামূলক।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(986, 247, 21, 'গ্ৰাহকক বৈধ লাইচেন্সধাৰী লোকৰ সৈতে পুনৰ আহিবলৈ কওক। সেই লোকজনে চলাব আৰু গ্ৰাহক পিলিয়ন হিচাপে বহিব।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(987, 247, 21, 'গ্ৰাহকক এটা ছুপাৰভাইজড টেষ্ট ৰাইড অফাৰ কৰক, যাতে তেওঁ পিলিয়ন ৰাইডাৰ হিচাপে বহি মটৰচাইকেলটো নিৰাপদভাৱে অনুভৱ কৰিব পাৰে।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(988, 247, 21, 'গ্ৰাহকক লাৰ্নাৰ লাইচেন্সৰ বাবে অনলাইন পঞ্জীয়ন কৰিবলৈ পথ দেখুৱাওক আৰু লাইচেন্স পোৱাৰ পিছত টেষ্ট ৰাইডৰ বাবে আহিবলৈ আমন্ত্ৰণ জনাওক।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(989, 248, 21, 'மரியாதையாக டெஸ்ட் ரைடை மறுத்து, டீலர்ஷிப் மற்றும் சட்டப்படி செல்லுபடியாகும் ஓட்டுநர் உரிமம் அவசியம் என்பதை விளக்குங்கள்.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(990, 248, 21, 'வாடிக்கையாளரை செல்லுபடியாகும் உரிமம் கொண்ட ஒருவருடன் மீண்டும் வரச் சொல்லுங்கள். அந்த நபர் ஓட்டவும், வாடிக்கையாளர் பில்லியனாக அமரவும் அனுமதிக்கலாம்.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(991, 248, 21, 'வாடிக்கையாளருக்கு ஒரு சூப்பர்வைஸ்ட் டெஸ்ட் ரைடு வழங்குங்கள், அதில் அவர்கள் பில்லியன் ரைடர் ஆக அமர்ந்து மோட்டார் சைக்கிளை பாதுகாப்பாக அனுபவிக்க முடியும்.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(992, 248, 21, 'வாடிக்கையாளரை லெர்னர் லைசன்ஸிற்காக ஆன்லைனில் பதிவு செய்ய வழிகாட்டி, லைசன்ஸ் கிடைத்த பிறகு டெஸ்ட் ரைடுக்கு அழைக்கவும்.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(993, 249, 21, 'వినయంగా టెస్ట్ రైడ్‌ను నిరాకరించి, డీలర్‌షిప్ మరియు చట్ట ప్రకారం చెల్లుబాటు అయ్యే డ్రైవింగ్ లైసెన్స్ తప్పనిసరి అని వివరించండి.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(994, 249, 21, 'కస్టమర్‌ను చెల్లుబాటు అయ్యే లైసెన్స్ ఉన్న వ్యక్తితో తిరిగి రావాలని చెప్పండి. ఆ వ్యక్తి వాహనం నడపాలి, కస్టమర్ పిలియన్‌గా కూర్చోవచ్చు.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(995, 249, 21, 'కస్టమర్‌కు ఒక సూపర్వైజ్డ్ టెస్ట్ రైడ్ ఆఫర్ చేయండి, అందులో వారు పిల్లియన్ రైడర్ గా కూర్చొని మోటార్ సైకిల్‌ను సురక్షితంగా అనుభవించవచ్చు.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(996, 249, 21, 'కస్టమర్‌కు లెర్నర్ లైసెన్స్ కోసం ఆన్‌లైన్‌లో నమోదు చేయడం గురించి మార్గనిర్దేశం చేసి, లైసెన్స్ వచ్చిన తర్వాత టెస్ట్ రైడ్‌కు ఆహ్వానించండి.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(997, 250, 21, 'വിനയത്തോടെ ടെസ്റ്റ് റൈഡ് നിരസിച്ച്, ഡീലർഷിപ്പ് നിയമങ്ങളും നിയമപരമായ നിബന്ധനകളും പ്രകാരം സാധുവായ ഡ്രൈവിംഗ് ലൈസൻസ് നിർബന്ധമാണെന്ന് വിശദീകരിക്കുക.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(998, 250, 21, 'ഉപഭോക്താവിനെ സാധുവായ ലൈസൻസ് ഉള്ള ഒരാളുമായി വീണ്ടും വരാൻ പറയുക. ആ വ്യക്തി ഓടിക്കട്ടെ, ഉപഭോക്താവ് പില്ലിയനായി ഇരിക്കാം.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(999, 250, 21, 'കസ്റ്റമറിന് ഒരു സൂപ്പർവൈസ്ഡ് ടെസ്റ്റ് റൈഡ് ഓഫർ ചെയ്യുക, അതിൽ അവർ പില്ലിയൻ റൈഡർ ആയി ഇരുന്ന് മോട്ടോർസൈക്കിൾ സുരക്ഷിതമായി അനുഭവിക്കാം.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1000, 250, 21, 'ഉപഭോക്താവിനെ ലേണർ ലൈസൻസിനായി ഓൺലൈനിൽ രജിസ്റ്റർ ചെയ്യാൻ സഹായിച്ച്, ലൈസൻസ് ലഭിച്ച ശേഷം ടെസ്റ്റ് റൈഡിന് ക്ഷണിക്കുക.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1001, 251, 21, 'ವಿನಯದಿಂದ ಟೆಸ್ಟ್ ರೈಡ್ ನಿರಾಕರಿಸಿ, ಡೀಲರ್‌ಶಿಪ್ ಮತ್ತು ಕಾನೂನು ನಿಯಮಗಳ ಪ್ರಕಾರ ಮಾನ್ಯ ಚಾಲನಾ ಪರವಾನಗಿ ಅಗತ್ಯವೆಂದು ತಿಳಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1002, 251, 21, 'ಗ್ರಾಹಕರಿಗೆ ಮಾನ್ಯ ಲೈಸೆನ್ಸ್ ಹೊಂದಿರುವ ವ್ಯಕ್ತಿಯೊಂದಿಗೆ ಮತ್ತೆ ಬರಲು ಹೇಳಿ. ಆ ವ್ಯಕ್ತಿ ಚಾಲನೆ ಮಾಡಲಿ, ಗ್ರಾಹಕರು ಪಿಲಿಯನ್ ಆಗಿ ಕುಳಿತುಕೊಳ್ಳಬಹುದು.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1003, 251, 21, 'ಗ್ರಾಹಕರಿಗೆ ಒಂದು ಸೂಪರ್‌ವೈಸ್ಡ್ ಟೆಸ್ಟ್ ರೈಡ್ ಆಫರ್ ಮಾಡಿ, ಅದರಲ್ಲಿ ಅವರು ಪಿಲಿಯನ್ ರೈಡರ್ ಆಗಿ ಕುಳಿತು ಮೋಟಾರ್ ಸೈಕಲ್ ಅನ್ನು ಸುರಕ್ಷಿತವಾಗಿ ಅನುಭವಿಸಬಹುದು.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1004, 251, 21, 'ಗ್ರಾಹಕರಿಗೆ ಲರ್ನರ್ ಲೈಸೆನ್ಸ್‌ಗೆ ಆನ್‌ಲೈನ್‌ನಲ್ಲಿ ನೋಂದಣಿ ಮಾಡಲು ಮಾರ್ಗದರ್ಶನ ನೀಡಿ ಮತ್ತು ಲೈಸೆನ್ಸ್ ಪಡೆದ ನಂತರ ಟೆಸ್ಟ್ ರೈಡ್‌ಗೆ ಆಹ್ವಾನಿಸಿ.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1005, 252, 21, 'ନମ୍ରତାର ସହିତ ଟେଷ୍ଟ ରାଇଡ୍ ନାକଚ କରି କହନ୍ତୁ ଯେ ଡିଲରଶିପ୍ ଏବଂ କାନୁନ ଅନୁଯାୟୀ ବୈଧ ଡ୍ରାଇଭିଂ ଲାଇସେନ୍ସ ଆବଶ୍ୟକ।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1006, 252, 21, 'ଗ୍ରାହକଙ୍କୁ ବୈଧ ଲାଇସେନ୍ସ ଥିବା ବ୍ୟକ୍ତି ସହ ପୁଣି ଆସିବାକୁ କହନ୍ତୁ। ସେ ବ୍ୟକ୍ତି ଚଳାଇବେ ଏବଂ ଗ୍ରାହକ ପିଲିୟନ୍ ଭାବେ ବସିପାରିବେ।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1007, 252, 21, 'ଗ୍ରାହକଙ୍କୁ ଗୋଟିଏ ସୁପରଭାଇଜ୍ଡ ଟେଷ୍ଟ ରାଇଡ୍ ଅଫର କରନ୍ତୁ, ଯେଉଁଥିରେ ସେ ପିଲିଅନ୍ ରାଇଡର୍ ଭାବେ ବସି ମୋଟରସାଇକେଲକୁ ସୁରକ୍ଷିତ ଭାବରେ ଅନୁଭବ କରିପାରିବେ।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1008, 252, 21, 'ଗ୍ରାହକଙ୍କୁ ଲର୍ନର ଲାଇସେନ୍ସ ପାଇଁ ଅନଲାଇନ୍ ରେଜିଷ୍ଟର କରିବାରେ ମାର୍ଗଦର୍ଶନ କରନ୍ତୁ ଏବଂ ଲାଇସେନ୍ସ ମିଳିଲେ ଟେଷ୍ଟ ରାଇଡ୍ ପାଇଁ ଆମନ୍ତ୍ରଣ କରନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1009, 253, 22, 'Explain the situation clearly and confirm delivery in 3 days with the selected colour', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1010, 253, 22, 'Apologize for the delay, commit to expediting the process, and keep the customer regularly informed with updates', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1011, 253, 22, 'Offer same variant in another colour and include a complimentary value-added service to enhance the birthday experience', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1012, 253, 22, 'Explain the stock timeline transparently, confirm delivery 3 days later, arrange home delivery, and offer a small goodwill gesture', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1013, 254, 22, 'स्थिति को साफ-साफ समझाएँ और यह पक्का करें कि चुने हुए रंग में डिलीवरी 3 दिन में कर दी जाएगी।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1014, 254, 22, 'देरी के लिए माफी मांगें, प्रक्रिया को जल्दी पूरा करने का भरोसा दें, और ग्राहक को समय-समय पर नियमित अपडेट देते रहें।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1015, 254, 22, 'उसी मॉडल को किसी दूसरे रंग में देने का विकल्प दें और जन्मदिन के अनुभव को खास बनाने के लिए एक कॉम्प्लिमेंट्री वैल्यू-ऐडेड सर्विस भी ऑफर करें।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1016, 254, 22, 'स्टॉक आने की टाइमलाइन साफ-साफ बताएं, 3 दिन बाद डिलीवरी कन्फर्म करें, घर पर डिलीवरी की व्यवस्था करें और सद्भावना के तौर पर एक छोटा-सा गुडविल जेस्चर भी ऑफर करें।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1017, 255, 22, 'ਸਥਿਤੀ ਨੂੰ ਸਾਫ਼-ਸਾਫ਼ ਸਮਝਾਓ ਅਤੇ ਚੁਣੇ ਹੋਏ ਰੰਗ ਵਿੱਚ 3 ਦਿਨਾਂ ਵਿੱਚ ਡਿਲਿਵਰੀ ਦੀ ਪੁਸ਼ਟੀ ਕਰੋ।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1018, 255, 22, 'ਦੇਰੀ ਲਈ ਮਾਫ਼ੀ ਮੰਗੋ, ਪ੍ਰਕਿਰਿਆ ਨੂੰ ਤੇਜ਼ ਕਰਨ ਦਾ ਭਰੋਸਾ ਦਿਓ ਅਤੇ ਗਾਹਕ ਨੂੰ ਨਿਯਮਿਤ ਅਪਡੇਟ ਦਿੰਦੇ ਰਹੋ।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1019, 255, 22, 'ਉਹੀ ਵੈਰੀਐਂਟ ਕਿਸੇ ਹੋਰ ਰੰਗ ਵਿੱਚ ਆਫਰ ਕਰੋ ਅਤੇ ਜਨਮਦਿਨ ਦੇ ਤਜਰਬੇ ਨੂੰ ਖਾਸ ਬਣਾਉਣ ਲਈ ਇੱਕ ਮੁਫ਼ਤ ਵੈਲਯੂ-ਐਡਿਡ ਸਰਵਿਸ ਸ਼ਾਮਲ ਕਰੋ।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1020, 255, 22, 'ਸਟਾਕ ਦੀ ਟਾਈਮਲਾਈਨ ਖੁੱਲ੍ਹੇ ਤੌਰ ‘ਤੇ ਸਮਝਾਓ, 3 ਦਿਨ ਬਾਅਦ ਡਿਲਿਵਰੀ ਦੀ ਪੁਸ਼ਟੀ ਕਰੋ, ਹੋਮ ਡਿਲਿਵਰੀ ਦੀ ਵਿਵਸਥਾ ਕਰੋ ਅਤੇ ਇੱਕ ਛੋਟਾ ਜਿਹਾ ਗੁਡਵਿੱਲ ਜੈਸਚਰ ਆਫਰ ਕਰੋ।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1021, 256, 22, 'પરિસ્થિતિ સ્પષ્ટ રીતે સમજાવો અને પસંદ કરેલા રંગમાં 3 દિવસમાં ડિલિવરીની પુષ્ટિ કરો.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1022, 256, 22, 'વિલંબ માટે માફી માગો, પ્રક્રિયા ઝડપી કરવાની ખાતરી આપો અને ગ્રાહકને નિયમિત અપડેટ આપતા રહો.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1023, 256, 22, 'એ જ વેરિઅન્ટ અન્ય રંગમાં ઓફર કરો અને જન્મદિવસનો અનુભવ ખાસ બનાવવા માટે એક મફત વેલ્યુ-એડેડ સર્વિસ ઉમેરો.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1024, 256, 22, 'સ્ટોક ટાઇમલાઇન પારદર્શક રીતે સમજાવો, 3 દિવસ પછી ડિલિવરી કન્ફર્મ કરો, હોમ ડિલિવરી ગોઠવો અને નાનું ગુડવિલ જેશ્ચર ઓફર કરો.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1025, 257, 22, 'परिस्थिती स्पष्टपणे समजावून सांगा आणि निवडलेल्या रंगात 3 दिवसांत डिलिव्हरीची खात्री द्या.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
