	(1029, 258, 22, 'পরিস্থিতি পরিষ্কারভাবে ব্যাখ্যা করুন এবং নির্বাচিত রঙে ৩ দিনের মধ্যে ডেলিভারি নিশ্চিত করুন।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
