	(1031, 258, 22, 'একই ভেরিয়েন্ট অন্য রঙে অফার করুন এবং জন্মদিনের অভিজ্ঞতা আরও ভালো করতে একটি ফ্রি ভ্যালু-অ্যাডেড সার্ভিস দিন।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1032, 258, 22, 'স্টকের টাইমলাইন স্বচ্ছভাবে ব্যাখ্যা করুন, ৩ দিন পরে ডেলিভারি নিশ্চিত করুন, হোম ডেলিভারির ব্যবস্থা করুন এবং একটি ছোট গুডউইল জেসচার দিন।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1033, 259, 22, 'পৰিস্থিতি স্পষ্টকৈ বুজাওক আৰু নিৰ্বাচিত ৰঙত ৩ দিনৰ ভিতৰত ডেলিভাৰী নিশ্চিত কৰক।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
