	(1037, 260, 22, 'நிலையை தெளிவாக விளக்கி, தேர்ந்தெடுத்த நிறத்தில் 3 நாட்களில் டெலிவரி உறுதிசெய்யுங்கள்.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1038, 260, 22, 'தாமதத்திற்கு மன்னிப்பு கேட்டு, செயல்முறையை விரைவுபடுத்த உறுதி அளித்து, வாடிக்கையாளருக்கு নিয়মিত அப்டேட் வழங்குங்கள்.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1039, 260, 22, 'அதே வேரியண்டை வேறு நிறத்தில் வழங்கி, பிறந்தநாள் அனுபவத்தை சிறப்பாக்க ஒரு இலவச value-added சேவையை சேர்க்குங்கள்.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1040, 260, 22, 'ஸ்டாக் டைம்லைனை வெளிப்படையாக விளக்கி, 3 நாட்கள் கழித்து டெலிவரி உறுதிசெய்து, ஹோம் டெலிவரி ஏற்பாடு செய்து, ஒரு சிறிய goodwill gesture வழங்குங்கள்.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1041, 261, 22, 'పరిస్థితిని స్పష్టంగా వివరించి, ఎంపిక చేసిన రంగులో 3 రోజుల్లో డెలివరీని నిర్ధారించండి.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1042, 261, 22, 'ఆలస్యానికి క్షమాపణ చెప్పి, ప్రక్రియను వేగవంతం చేస్తామని హామీ ఇవ్వండి మరియు కస్టమర్‌కు నియమిత అప్డేట్లు ఇవ్వండి.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1043, 261, 22, 'అదే వేరియంట్‌ను మరో రంగులో ఆఫర్ చేసి, పుట్టినరోజు అనుభవాన్ని మెరుగుపరచడానికి ఉచిత value-added సేవను ఇవ్వండి.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1044, 261, 22, 'స్టాక్ టైమ్‌లైన్‌ను పారదర్శకంగా వివరించి, 3 రోజుల తర్వాత డెలివరీని నిర్ధారించి, హోమ్ డెలివరీ ఏర్పాటు చేసి, చిన్న గుడ్‌విల్ జెస్టర్ ఇవ్వండి.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1045, 262, 22, 'സ്ഥിതി വ്യക്തമായി വിശദീകരിച്ച് തിരഞ്ഞെടുത്ത നിറത്തിൽ 3 ദിവസത്തിനകം ഡെലിവറി സ്ഥിരീകരിക്കുക.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1046, 262, 22, 'വിലംബത്തിനായി ക്ഷമ ചോദിച്ച്, പ്രക്രിയ വേഗത്തിലാക്കാമെന്ന് ഉറപ്പ് നൽകി, ഉപഭോക്താവിനെ സ്ഥിരമായി അപ്‌ഡേറ്റ് ചെയ്യുക.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1047, 262, 22, 'അതേ വേരിയന്റ് മറ്റൊരു നിറത്തിൽ നൽകുകയും ജന്മദിന അനുഭവം മെച്ചപ്പെടുത്താൻ ഒരു ഫ്രീ value-added സേവനം ഉൾപ്പെടുത്തുകയും ചെയ്യുക.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1048, 262, 22, 'സ്റ്റോക്ക് ടൈംലൈൻ സുതാര്യമായി വിശദീകരിച്ച്, 3 ദിവസം കഴിഞ്ഞ് ഡെലിവറി സ്ഥിരീകരിച്ച്, ഹോം ഡെലിവറി ഒരുക്കി, ഒരു ചെറിയ ഗുഡ്‌വിൽ ജെസ്റ്റർ നൽകുക.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1049, 263, 22, 'ಪರಿಸ್ಥಿತಿಯನ್ನು ಸ್ಪಷ್ಟವಾಗಿ ವಿವರಿಸಿ ಮತ್ತು ಆಯ್ದ ಬಣ್ಣದಲ್ಲಿ 3 ದಿನಗಳಲ್ಲಿ ಡೆಲಿವರಿ ದೃಢಪಡಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1050, 263, 22, 'ವಿಳಂಬಕ್ಕೆ ಕ್ಷಮೆ ಕೇಳಿ, ಪ್ರಕ್ರಿಯೆಯನ್ನು ವೇಗಗೊಳಿಸುವ ಭರವಸೆ ನೀಡಿ ಮತ್ತು ಗ್ರಾಹಕರಿಗೆ ನಿಯಮಿತ ಅಪ್ಡೇಟ್ ನೀಡಿ.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1051, 263, 22, 'ಅದೇ ವೇರಿಯಂಟ್ ಅನ್ನು ಬೇರೆ ಬಣ್ಣದಲ್ಲಿ ಆಫರ್ ಮಾಡಿ ಮತ್ತು ಹುಟ್ಟುಹಬ್ಬದ ಅನುಭವವನ್ನು ಉತ್ತಮಗೊಳಿಸಲು ಉಚಿತ value-added ಸೇವೆಯನ್ನು ಸೇರಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1052, 263, 22, 'ಸ್ಟಾಕ್ ಟೈಮ್‌ಲೈನ್ ಅನ್ನು ಪಾರದರ್ಶಕವಾಗಿ ವಿವರಿಸಿ, 3 ದಿನಗಳ ನಂತರ ಡೆಲಿವರಿ ದೃಢಪಡಿಸಿ, ಹೋಮ್ ಡೆಲಿವರಿ ವ್ಯವಸ್ಥೆ ಮಾಡಿ ಮತ್ತು ಸಣ್ಣ ಗೂಡ್‌ವಿಲ್ ಜೆಸ್ಟರ್ ನೀಡಿ.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1053, 264, 22, 'ପରିସ୍ଥିତିକୁ ସ୍ପଷ୍ଟ ଭାବେ ବୁଝାନ୍ତୁ ଏବଂ ଚୟନିତ ରଙ୍ଗରେ 3 ଦିନ ମଧ୍ୟରେ ଡେଲିଭେରୀ ସୁନିଶ୍ଚିତ କରନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1054, 264, 22, 'ବିଳମ୍ବ ପାଇଁ କ୍ଷମା ମାଗନ୍ତୁ, ପ୍ରକ୍ରିୟା ଶୀଘ୍ର କରିବାର ଭରସା ଦିଅନ୍ତୁ ଏବଂ ଗ୍ରାହକଙ୍କୁ ନିୟମିତ ଅପଡେଟ୍ ଦିଅନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1055, 264, 22, 'ସେହି ଭେରିଆଣ୍ଟକୁ ଅନ୍ୟ ରଙ୍ଗରେ ଅଫର କରନ୍ତୁ ଏବଂ ଜନ୍ମଦିନ ଅନୁଭବକୁ ଭଲ କରିବା ପାଇଁ ଏକ ମାଗଣା value-added ସେବା ଯୋଗ କରନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1056, 264, 22, 'ଷ୍ଟକ୍ ଟାଇମଲାଇନ୍ ପାରଦର୍ଶୀ ଭାବେ ବୁଝାନ୍ତୁ, 3 ଦିନ ପରେ ଡେଲିଭେରୀ ସୁନିଶ୍ଚିତ କରନ୍ତୁ, ହୋମ ଡେଲିଭେରୀ ବ୍ୟବସ୍ଥା କରନ୍ତୁ ଏବଂ ଏକ ଛୋଟ ଗୁଡ଼ୱିଲ୍ ଜେସ୍ଚର ଦିଅନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1057, 265, 23, 'Explain that the quotation follows standard pricing and assure the customer there are no hidden charges', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1058, 265, 23, 'Provide a clear breakdown of the quotation and explain what is included in the on-road price', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1059, 265, 23, 'Acknowledge the concern and explain why the other dealership may be offering a lower price', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
