	(1061, 266, 23, 'उन्हें समझाएँ कि यह कोटेशन कंपनी की तय की हुई स्टैंडर्ड कीमत के अनुसार है और इसमें कोई भी छुपे हुए चार्ज नहीं हैं।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1062, 266, 23, 'कोटेशन का साफ-साफ पूरा ब्रेकअप बताएं और समझाएँ कि ऑन-रोड कीमत में कौन-कौन सी चीजें शामिल हैं।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1063, 266, 23, 'उनकी चिंता को समझें और स्वीकार करें, फिर शांति से समझाएँ कि दूसरी डीलरशिप कम कीमत क्यों ऑफर कर रही हो सकती है।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1064, 266, 23, 'दूसरी डीलरशिप के कोटेशन को ध्यान से देखें, छूट देने की वजह समझाएँ, अपनी स्टैंडर्ड और पारदर्शी कीमत की पुष्टि करें, और साथ में एक वैल्यू-ऐडेड बेनिफिट भी ऑफर करें।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1065, 267, 23, 'ਸਮਝਾਓ ਕਿ ਕੋਟੇਸ਼ਨ ਸਟੈਂਡਰਡ ਕੀਮਤਾਂ ਅਨੁਸਾਰ ਹੈ ਅਤੇ ਗਾਹਕ ਨੂੰ ਯਕੀਨ ਦਿਵਾਓ ਕਿ ਕੋਈ ਲੁਕੇ ਹੋਏ ਚਾਰਜ ਨਹੀਂ ਹਨ।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1066, 267, 23, 'ਕੋਟੇਸ਼ਨ ਦੀ ਸਪਸ਼ਟ ਜਾਣਕਾਰੀ ਦਿਓ ਅਤੇ ਦੱਸੋ ਕਿ ਆਨ-ਰੋਡ ਕੀਮਤ ਵਿੱਚ ਕੀ-ਕੀ ਸ਼ਾਮਲ ਹੈ।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1067, 267, 23, 'ਗਾਹਕ ਦੀ ਚਿੰਤਾ ਨੂੰ ਮੰਨੋ ਅਤੇ ਸਮਝਾਓ ਕਿ ਦੂਜੀ ਡੀਲਰਸ਼ਿਪ ਘੱਟ ਕੀਮਤ ਕਿਉਂ ਦੇ ਰਹੀ ਹੋ ਸਕਦੀ ਹੈ।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1068, 267, 23, 'ਦੂਜੀ ਕੋਟੇਸ਼ਨ ਦੀ ਸਮੀਖਿਆ ਕਰੋ, ਡਿਸਕਾਊਂਟ ਦਾ ਕਾਰਨ ਸਮਝਾਓ, ਸਟੈਂਡਰਡ ਕੀਮਤ ਦੀ ਪਾਰਦਰਸ਼ਤਾ ਦੀ ਪੁਸ਼ਟੀ ਕਰੋ ਅਤੇ ਇੱਕ ਵੈਲਯੂ-ਐਡਿਡ ਫਾਇਦਾ ਦਿਓ।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1069, 268, 23, 'સમજાવો કે ક્વોટેશન સ્ટાન્ડર્ડ કિંમતો અનુસાર છે અને ગ્રાહકને ખાતરી આપો કે કોઈ છુપાયેલા ચાર્જ નથી.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1070, 268, 23, 'ક્વોટેશનનો સ્પષ્ટ બ્રેકડાઉન આપો અને ઓન-રોડ કિંમતે શું શામેલ છે તે સમજાવો.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1071, 268, 23, 'ગ્રાહકની ચિંતા સ્વીકારો અને સમજાવો કે બીજી ડીલરશિપ ઓછી કિંમત કેમ આપી રહી હોઈ શકે.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1072, 268, 23, 'બીજી ક્વોટેશનની સમીક્ષા કરો, ડિસ્કાઉન્ટનું કારણ સમજાવો, સ્ટાન્ડર્ડ પ્રાઇસિંગ પારદર્શિતા કન્ફર્મ કરો અને એક વેલ્યુ-એડેડ લાભ આપો.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1073, 269, 23, 'समजावून सांगा की कोटेशन स्टँडर्ड किंमतीनुसार आहे आणि कोणतेही लपलेले चार्ज नाहीत याची खात्री द्या.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1074, 269, 23, 'कोटेशनचा स्पष्ट तपशील द्या आणि ऑन-रोड किमतीत काय समाविष्ट आहे ते समजवा.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1075, 269, 23, 'ग्राहकाची चिंता मान्य करा आणि दुसरी डीलरशिप कमी किंमत का देत असेल ते समजवा.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1076, 269, 23, 'दुसऱ्या कोटेशनची पाहणी करा, सवलतीचे कारण समजवा, स्टँडर्ड प्राइसिंग पारदर्शकतेची खात्री द्या आणि एक व्हॅल्यू-अॅडेड फायदा द्या.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1077, 270, 23, 'বোঝান যে কোটেশন স্ট্যান্ডার্ড মূল্যের অনুযায়ী এবং গ্রাহককে আশ্বস্ত করুন যে কোনও লুকানো চার্জ নেই।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1078, 270, 23, 'কোটেশনের পরিষ্কার ব্রেকডাউন দিন এবং অন-রোড মূল্যের মধ্যে কী কী অন্তর্ভুক্ত আছে তা ব্যাখ্যা করুন।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1079, 270, 23, 'গ্রাহকের উদ্বেগ স্বীকার করুন এবং ব্যাখ্যা করুন কেন অন্য ডিলারশিপ কম দাম দিতে পারে।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1080, 270, 23, 'অন্য কোটেশনটি পর্যালোচনা করুন, ছাড়ের কারণ ব্যাখ্যা করুন, স্ট্যান্ডার্ড প্রাইসিং স্বচ্ছতা নিশ্চিত করুন এবং একটি ভ্যালু-অ্যাডেড সুবিধা দিন।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1081, 271, 23, 'বুজাওক যে কোটেচন স্টেণ্ডাৰ্ড মূল্য অনুসাৰে আছে আৰু কোনো লুকাই থকা চাৰ্জ নাই বুলি গ্ৰাহকক আশ্বস্ত কৰক।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1082, 271, 23, 'কোটেচনৰ স্পষ্ট বিৱৰণ দিয়ক আৰু অন-ৰোড মূল্যত কি কি অন্তৰ্ভুক্ত আছে সেয়া বুজাওক।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1083, 271, 23, 'গ্ৰাহকৰ চিন্তা স্বীকাৰ কৰক আৰু কিয় আন ডিলাৰশ্বীপে কম মূল্য আগবঢ়াব পাৰে সেয়া বুজাওক।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1084, 271, 23, 'আন কোটেচনটো পৰ্যালোচনা কৰক, ৰেহাতৰ কাৰণ বুজাওক, ষ্টেণ্ডাৰ্ড প্ৰাইচিং স্বচ্ছতা নিশ্চিত কৰক আৰু এটা ভেলিউ-এডেড সুবিধা দিয়ক।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1085, 272, 23, 'கோட்டேஷன் ஸ்டாண்டர்ட் விலையில் உள்ளது மற்றும் மறைமுக கட்டணங்கள் இல்லை என்பதை வாடிக்கையாளருக்கு உறுதி செய்யுங்கள்.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1086, 272, 23, 'கோட்டேஷனின் தெளிவான விவரத்தை வழங்கி, ஆன்ரோட் விலையில் என்னென்ன சேர்க்கப்பட்டுள்ளது என்பதை விளக்குங்கள்.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1087, 272, 23, 'வாடிக்கையாளரின் கவலை ஏற்றுக்கொண்டு, மற்ற டீலர்ஷிப் குறைந்த விலை வழங்குவதற்கான காரணத்தை விளக்குங்கள்.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1088, 272, 23, 'மற்ற கோட்டேஷனை பரிசீலித்து, தள்ளுபடியின் காரணத்தை விளக்கி, ஸ்டாண்டர்ட் விலை வெளிப்படைத்தன்மையை உறுதி செய்து, ஒரு value-added நன்மையை வழங்குங்கள்.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1089, 273, 23, 'కోటేషన్ స్టాండర్డ్ ధరల ప్రకారం ఉందని మరియు ఎలాంటి దాచిన చార్జీలు లేవని కస్టమర్‌కు హామీ ఇవ్వండి.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1090, 273, 23, 'కోటేషన్‌కు స్పష్టమైన వివరాలు ఇవ్వండి మరియు ఆన్-రోడ్ ధరలో ఏమేమి చేర్చబడ్డాయో వివరించండి.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1091, 273, 23, 'కస్టమర్ ఆందోళనను అంగీకరించి, మరో డీలర్‌షిప్ తక్కువ ధర ఎందుకు ఇస్తుందో వివరించండి.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1092, 273, 23, 'మరో కోటేషన్‌ను సమీక్షించి, డిస్కౌంట్ కారణాన్ని వివరించి, స్టాండర్డ్ ప్రైసింగ్ పారదర్శకతను నిర్ధారించి, ఒక value-added లాభాన్ని ఇవ్వండి.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1093, 274, 23, 'കോട്ടേഷൻ സ്റ്റാൻഡേർഡ് വിലപ്രകാരമാണെന്നും മറഞ്ഞിരിക്കുന്ന ചാർജുകൾ ഇല്ലെന്നും ഉപഭോക്താവിനെ ഉറപ്പാക്കുക.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1094, 274, 23, 'കോട്ടേഷന്റെ വ്യക്തമായ വിശദീകരണം നൽകുകയും ഓൺ-റോഡ് വിലയിൽ എന്തൊക്കെ ഉൾപ്പെടുന്നു എന്ന് വ്യക്തമാക്കുകയും ചെയ്യുക.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1095, 274, 23, 'ഉപഭോക്താവിന്റെ ആശങ്ക അംഗീകരിച്ച്, മറ്റൊരു ഡീലർഷിപ്പ് കുറഞ്ഞ വില നൽകാനുള്ള കാരണമെന്തെന്ന് വിശദീകരിക്കുക.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1096, 274, 23, 'മറ്റുള്ള കോട്ടേഷൻ പരിശോധിച്ച്, ഡിസ്‌കൗണ്ടിന്റെ കാരണം വ്യക്തമാക്കുകയും സ്റ്റാൻഡേർഡ് വിലയുടെ സുതാര്യത ഉറപ്പാക്കി ഒരു value-added പ്രയോജനം നൽകുകയും ചെയ്യുക.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1097, 275, 23, 'ಕೋಟೇಶನ್ ಸ್ಟ್ಯಾಂಡರ್ಡ್ ಬೆಲೆ ಪ್ರಕಾರವೇ ಇದೆ ಮತ್ತು ಯಾವುದೇ ಮರೆಮಾಚಿದ ಶುಲ್ಕಗಳಿಲ್ಲ ಎಂದು ಗ್ರಾಹಕರಿಗೆ ಭರವಸೆ ನೀಡಿ.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1098, 275, 23, 'ಕೋಟೇಶನ್‌ನ ಸ್ಪಷ್ಟ ವಿವರ ನೀಡಿ ಮತ್ತು ಆನ್-ರೋಡ್ ಬೆಲೆಯಲ್ಲಿ ಏನು ಸೇರಿದೆ ಎಂಬುದನ್ನು ವಿವರಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1099, 275, 23, 'ಗ್ರಾಹಕರ ಚಿಂತೆ ಒಪ್ಪಿಕೊಂಡು, ಇನ್ನೊಂದು ಡೀಲರ್‌ಶಿಪ್ ಕಡಿಮೆ ಬೆಲೆ ನೀಡುವ ಕಾರಣವನ್ನು ವಿವರಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1100, 275, 23, 'ಇನ್ನೊಂದು ಕೋಟೇಶನ್ ಪರಿಶೀಲಿಸಿ, ಡಿಸ್ಕೌಂಟ್ ಕಾರಣವನ್ನು ವಿವರಿಸಿ, ಸ್ಟ್ಯಾಂಡರ್ಡ್ ಪ್ರೈಸಿಂಗ್ ಪಾರದರ್ಶಕತೆಯನ್ನು ದೃಢಪಡಿಸಿ ಮತ್ತು ಒಂದು value-added ಲಾಭ ನೀಡಿ.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1101, 276, 23, 'କୋଟେସନ୍ ସ୍ଟାଣ୍ଡାର୍ଡ ମୂଲ୍ୟ ଅନୁଯାୟୀ ଅଛି ଏବଂ କୌଣସି ଲୁଚା ଚାର୍ଜ୍ ନାହିଁ ବୋଲି ଗ୍ରାହକଙ୍କୁ ନିଶ୍ଚିତ କରନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1102, 276, 23, 'କୋଟେସନ୍‌ର ସ୍ପଷ୍ଟ ବିବରଣୀ ଦିଅନ୍ତୁ ଏବଂ ଅନ-ରୋଡ୍ ମୂଲ୍ୟରେ କ’ଣ କ’ଣ ଶାମିଲ ଅଛି ବୁଝାନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1103, 276, 23, 'ଗ୍ରାହକଙ୍କ ଚିନ୍ତାକୁ ମାନନ୍ତୁ ଏବଂ ଅନ୍ୟ ଡିଲରଶିପ୍ କାହିଁକି କମ ମୂଲ୍ୟ ଦେଉଥାଇପାରେ ସେଥି ପ୍ରସ୍ତୁତ କରନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1104, 276, 23, 'ଅନ୍ୟ କୋଟେସନ୍‌ର ସମୀକ୍ଷା କରନ୍ତୁ, ଡିସ୍କାଉଣ୍ଟର କାରଣ ବୁଝାନ୍ତୁ, ସ୍ଟାଣ୍ଡାର୍ଡ ମୂଲ୍ୟର ପାରଦର୍ଶିତା ନିଶ୍ଚିତ କରନ୍ତୁ ଏବଂ ଗୋଟିଏ value-added ଲାଭ ଦିଅନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
