	(1109, 278, 24, 'ग्राहक से गलतफहमी के लिए माफी मांगें।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1110, 278, 24, 'माफी मांगें, समझाएँ कि अभी टेस्ट राइड क्यों उपलब्ध नहीं है, और कोई दूसरी तारीख या दूसरी गाड़ी का विकल्प ऑफर करें।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1111, 278, 24, 'ग्राहक से माफी मांगें, डीलरशिप तक आने के लिए उन्होंने जो मेहनत की है उसे स्वीकार करें, और साथ ही कोई दूसरा विकल्प चेक करें।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1112, 278, 24, 'जिम्मेदारी लें, माफी मांगें, ग्राहक की मेहनत को समझें और सराहें, और जल्दी से या उनकी सुविधाजनक तारीख पर टेस्ट राइड की व्यवस्था करें।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1113, 279, 24, 'ਗਲਤਫ਼ਹਮੀ ਲਈ ਗਾਹਕ ਤੋਂ ਮਾਫ਼ੀ ਮੰਗੋ।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1114, 279, 24, 'ਮਾਫ਼ੀ ਮੰਗੋ, ਸਮਝਾਓ ਕਿ ਟੈਸਟ ਰਾਈਡ ਕਿਉਂ ਉਪਲਬਧ ਨਹੀਂ ਹੈ ਅਤੇ ਕੋਈ ਹੋਰ ਤਾਰੀਖ ਜਾਂ ਵਾਹਨ ਆਫਰ ਕਰੋ।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1115, 279, 24, 'ਗਾਹਕ ਤੋਂ ਮਾਫ਼ੀ ਮੰਗੋ, ਡੀਲਰਸ਼ਿਪ ਤੇ ਆਉਣ ਲਈ ਕੀਤੇ ਉਪਰਾਲਿਆਂ ਨੂੰ ਮੰਨੋ ਅਤੇ ਹੋਰ ਵਿਕਲਪ ਵੇਖੋ।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1116, 279, 24, 'ਜ਼ਿੰਮੇਵਾਰੀ ਲਓ, ਮਾਫ਼ੀ ਮੰਗੋ, ਗਾਹਕ ਦੀ ਕੋਸ਼ਿਸ਼ ਨੂੰ ਮੰਨੋ ਅਤੇ ਜਲਦੀ ਜਾਂ ਸੁਵਿਧਾਜਨਕ ਤਾਰੀਖ ਤੇ ਟੈਸਟ ਰਾਈਡ ਦੀ ਵਿਵਸਥਾ ਕਰੋ।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1117, 280, 24, 'ગેરસમજ માટે ગ્રાહક પાસે માફી માગો.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1118, 280, 24, 'માફી માગો, ટેસ્ટ રાઇડ કેમ ઉપલબ્ધ નથી તે સમજાવો અને વિકલ્પ તરીકે બીજી તારીખ અથવા વાહન ઓફર કરો.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1119, 280, 24, 'ગ્રાહક પાસે માફી માગી, ડીલરશિપ પર આવવા માટે કરેલા પ્રયત્નોને માન્યતા આપો અને વિકલ્પો તપાસો.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1120, 280, 24, 'જવાબદારી લો, માફી માગો, ગ્રાહકના પ્રયત્નોને સ્વીકારો અને જલ્દી અથવા અનુકૂળ તારીખે ટેસ્ટ રાઇડ ગોઠવો.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1121, 281, 24, 'गैरसमजासाठी ग्राहकाची माफी मागा.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
