	(1123, 281, 24, 'ग्राहकाची माफी मागा, डीलरशिपला भेट देण्यासाठी केलेल्या प्रयत्नांची दखल घ्या आणि पर्याय तपासा.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1124, 281, 24, 'जबाबदारी घ्या, माफी मागा, ग्राहकाच्या प्रयत्नांची दखल घ्या आणि लवकर किंवा सोयीस्कर तारखेला टेस्ट राईडची व्यवस्था करा.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
