	(1126, 282, 24, 'ক্ষমা চেয়ে ব্যাখ্যা করুন কেন টেস্ট রাইড উপলব্ধ নয় এবং বিকল্প তারিখ বা গাড়ি প্রস্তাব করুন।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1127, 282, 24, 'গ্রাহকের কাছে ক্ষমা চেয়ে, ডিলারশিপে আসার জন্য তার প্রচেষ্টার স্বীকৃতি দিন এবং বিকল্পগুলি দেখুন।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1128, 282, 24, 'দায়িত্ব নিন, ক্ষমা চান, গ্রাহকের প্রচেষ্টা স্বীকার করুন এবং দ্রুত বা সুবিধাজনক তারিখে টেস্ট রাইডের ব্যবস্থা করুন।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1129, 283, 24, 'ভুল বুজাবুজিৰ বাবে গ্ৰাহকৰ পৰা ক্ষমা বিচাৰক।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1130, 283, 24, 'ক্ষমা বিচাৰি টেষ্ট ৰাইড কিয় উপলব্ধ নহয় সেয়া বুজাওক আৰু বিকল্প তাৰিখ বা বাহন অফাৰ কৰক।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1131, 283, 24, 'গ্ৰাহকৰ পৰা ক্ষমা বিচাৰি, ডিলাৰশ্বীপলৈ অহাৰ বাবে কৰা প্ৰচেষ্টাৰ স্বীকৃতি দিয়ক আৰু বিকল্পসমূহ চাওক।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1132, 283, 24, 'দায়িত্ব লওক, ক্ষমা বিচাৰক, গ্ৰাহকৰ প্ৰচেষ্টাৰ স্বীকৃতি দিয়ক আৰু সোনকালে বা সুবিধাজনক তাৰিখত টেষ্ট ৰাইডৰ ব্যৱস্থা কৰক।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1133, 284, 24, 'தவறான தகவலுக்கு வாடிக்கையாளரிடம் மன்னிப்பு கேளுங்கள்.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1134, 284, 24, 'மன்னிப்பு கேட்டு, டெஸ்ட் ரைடு ஏன் கிடைக்கவில்லை என்பதை விளக்கி, மாற்று தேதி அல்லது வாகனத்தை வழங்குங்கள்.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1135, 284, 24, 'வாடிக்கையாளரிடம் மன்னிப்பு கேட்டு, டீலர்ஷிப்பிற்கு வந்த முயற்சியை பாராட்டி, மாற்று விருப்பங்களை பாருங்கள்.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1136, 284, 24, 'பொறுப்பேற்று மன்னிப்பு கேட்டு, வாடிக்கையாளரின் முயற்சியை மதித்து, விரைவில் அல்லது வசதியான தேதியில் டெஸ்ட் ரைடு ஏற்பாடு செய்யுங்கள்.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1137, 285, 24, 'తప్పు సమాచారానికి కస్టమర్‌కు క్షమాపణ చెప్పండి.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1138, 285, 24, 'క్షమాపణ చెప్పి, టెస్ట్ రైడ్ ఎందుకు అందుబాటులో లేదో వివరించి, ప్రత్యామ్నాయ తేదీ లేదా వాహనం ఆఫర్ చేయండి.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1139, 285, 24, 'కస్టమర్‌కు క్షమాపణ చెప్పి, డీలర్‌షిప్‌కు రావడానికి చేసిన ప్రయత్నాన్ని గుర్తించి, ప్రత్యామ్నాయాలను పరిశీలించండి.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1140, 285, 24, 'బాధ్యత తీసుకుని క్షమాపణ చెప్పి, కస్టమర్ ప్రయత్నాన్ని గుర్తించి, త్వరగా లేదా అనుకూల తేదీలో టెస్ట్ రైడ్ ఏర్పాటు చేయండి.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1141, 286, 24, 'തെറ്റായ ആശയവിനിമയത്തിന് ഉപഭോക്താവിനോട് ക്ഷമ ചോദിക്കുക.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1142, 286, 24, 'ക്ഷമ ചോദിച്ച് ടെസ്റ്റ് റൈഡ് ലഭ്യമല്ലാത്തതിന്റെ കാരണം വിശദീകരിച്ച്, മറ്റൊരു തീയതി അല്ലെങ്കിൽ വാഹനം ഓഫർ ചെയ്യുക.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1143, 286, 24, 'ഉപഭോക്താവിനോട് ക്ഷമ ചോദിച്ച്, ഡീലർഷിപ്പിൽ എത്താൻ നടത്തിയ ശ്രമം അംഗീകരിച്ച്, മറ്റു વિકല്പങ്ങൾ പരിശോധിക്കുക.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1144, 286, 24, 'ഉത്തരവാദിത്തം ഏറ്റെടുത്തു ക്ഷമ ചോദിച്ച്, ഉപഭോക്താവിന്റെ ശ്രമം അംഗീകരിച്ച്, വേഗത്തിൽ അല്ലെങ്കിൽ സൗകര്യപ്രദമായ തീയതിയിൽ ടെസ്റ്റ് റൈഡ് ഒരുക്കുക.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1145, 287, 24, 'ತಪ್ಪು ಸಂವಹನಕ್ಕಾಗಿ ಗ್ರಾಹಕರಿಗೆ ಕ್ಷಮೆ ಕೇಳಿ.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1146, 287, 24, 'ಕ್ಷಮೆ ಕೇಳಿ, ಟೆಸ್ಟ್ ರೈಡ್ ಏಕೆ ಲಭ್ಯವಿಲ್ಲ ಎಂಬುದನ್ನು ವಿವರಿಸಿ ಮತ್ತು ಪರ್ಯಾಯ ದಿನಾಂಕ ಅಥವಾ ವಾಹನವನ್ನು ಆಫರ್ ಮಾಡಿ.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1147, 287, 24, 'ಗ್ರಾಹಕರಿಗೆ ಕ್ಷಮೆ ಕೇಳಿ, ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಬರಲು ಮಾಡಿದ ಪ್ರಯತ್ನವನ್ನು ಗುರುತಿಸಿ ಮತ್ತು ಪರ್ಯಾಯ ಆಯ್ಕೆಗಳನ್ನು ಪರಿಶೀಲಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1148, 287, 24, 'ಜವಾಬ್ದಾರಿ ತೆಗೆದುಕೊಂಡು ಕ್ಷಮೆ ಕೇಳಿ, ಗ್ರಾಹಕರ ಪ್ರಯತ್ನವನ್ನು ಗುರುತಿಸಿ ಮತ್ತು ಶೀಘ್ರದಲ್ಲೇ ಅಥವಾ ಅನುಕೂಲಕರ ದಿನಾಂಕದಲ್ಲಿ ಟೆಸ್ಟ್ ರೈಡ್ ವ್ಯವಸ್ಥೆ ಮಾಡಿ.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1149, 288, 24, 'ଭୁଲ ସଂଯୋଗ ପାଇଁ ଗ୍ରାହକଙ୍କୁ କ୍ଷମା ମାଗନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
