	(1208, 302, 26, 'उनकी रिसर्च की सराहना करें, उनसे पूछें कि क्या वह टेस्ट राइड लेना चाहेंगे, और उन्हें बताएं कि उन्हें जो भी जरूरत हो, आप मदद के लिए उपलब्ध हैं।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1209, 303, 26, 'ਉਸਦੀ ਰਿਸਰਚ ਦੀ ਕਦਰ ਕਰੋ ਅਤੇ ਸੰਖੇਪ ਵਿੱਚ ਉਹ ਫੀਚਰ ਜਾਂ ਸਪੈਸਿਫਿਕੇਸ਼ਨ ਦੱਸੋ ਜੋ ਸ਼ਾਇਦ ਉਸ ਤੋਂ ਰਹਿ ਗਏ ਹੋਣ।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1210, 303, 26, 'ਉਸਦੀ ਰਿਸਰਚ ਨੂੰ ਮੰਨੋ, ਉਸਦੀ ਤਰਜੀਹਾਂ ਬਾਰੇ ਪੁੱਛੋ ਅਤੇ ਕੋਈ ਸੰਦੇਹ ਹੋਣ ਤੇ ਸਪਸ਼ਟ ਕਰੋ।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1211, 303, 26, 'ਉਸਦੀ ਰਿਸਰਚ ਦੀ ਕਦਰ ਕਰੋ ਅਤੇ ਬਾਈਕ ਦੇਖਣ ਤੋਂ ਬਾਅਦ ਟੈਸਟ ਰਾਈਡ ਲਈ ਸੱਦਾ ਦਿਓ।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1212, 303, 26, 'ਰਿਸਰਚ ਨੂੰ ਮੰਨੋ, ਪੁੱਛੋ ਕਿ ਕੀ ਉਹ ਟੈਸਟ ਰਾਈਡ ਕਰਨਾ ਚਾਹੇਗਾ ਅਤੇ ਦੱਸੋ ਕਿ ਤੁਸੀਂ ਕਿਸੇ ਵੀ ਮਦਦ ਲਈ ਉਪਲਬਧ ਹੋ।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1213, 304, 26, 'તેની રિસર્ચની કદર કરો અને સંક્ષિપ્તમાં એવા ફીચર્સ અથવા સ્પેસિફિકેશન્સ બતાવો જે કદાચ રહી ગયા હોય.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1214, 304, 26, 'તેની રિસર્ચને સ્વીકારી તેની પ્રાથમિકતાઓ જાણો અને કોઈ શંકા હોય તો દૂર કરો.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1215, 304, 26, 'તેની રિસર્ચની કદર કરો અને બાઈક નિરીક્ષણ કર્યા પછી ટેસ્ટ રાઇડ માટે આમંત્રણ આપો.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1216, 304, 26, 'રિસર્ચને માન્યતા આપો, પૂછો કે શું તે ટેસ્ટ રાઇડ ઇચ્છે છે અને જણાવો કે તમે કોઈ પણ મદદ માટે ઉપલબ્ધ છો.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1217, 305, 26, 'त्याच्या रिसर्चची दखल घ्या आणि थोडक्यात कदाचित राहिलेले फीचर्स किंवा स्पेसिफिकेशन्स सांगा.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1218, 305, 26, 'त्याच्या रिसर्चची दखल घेऊन त्याच्या प्राधान्यांबद्दल विचारा आणि काही शंका असल्यास स्पष्ट करा.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1219, 305, 26, 'त्याच्या रिसर्चची दखल घ्या आणि बाईक पाहून झाल्यावर टेस्ट राईडसाठी आमंत्रित करा.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1220, 305, 26, 'रिसर्च मान्य करा, त्याला टेस्ट राईड हवी आहे का विचारा आणि कोणत्याही मदतीसाठी आपण उपलब्ध आहात हे सांगा.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1221, 306, 26, 'তার গবেষণার প্রশংসা করুন এবং সংক্ষেপে এমন ফিচার বা স্পেসিফিকেশন উল্লেখ করুন যা হয়তো তার চোখ এড়িয়ে গেছে।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1222, 306, 26, 'তার গবেষণাকে স্বীকার করুন, তার অগ্রাধিকারগুলো জানুন এবং কোনও সন্দেহ থাকলে পরিষ্কার করুন।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1223, 306, 26, 'তার গবেষণার প্রশংসা করুন এবং বাইক দেখার পর টেস্ট রাইডের আমন্ত্রণ জানান।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1224, 306, 26, 'গবেষণাকে স্বীকার করে জিজ্ঞাসা করুন সে টেস্ট রাইড করতে চায় কি না এবং জানান যে যে কোনও প্রয়োজনে আপনি উপলব্ধ আছেন।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1225, 307, 26, 'তেওঁৰ ৰিচাৰ্চৰ স্বীকৃতি দিয়ক আৰু সংক্ষেপে হয়তো বাদ পৰি যোৱা ফিচাৰ বা স্পেচিফিকেশ্যন উল্লেখ কৰক।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1226, 307, 26, 'তেওঁৰ ৰিচাৰ্চ মানি লৈ তেওঁৰ প্ৰাধান্যবোৰ সুধক আৰু কোনো সন্দেহ থাকিলে স্পষ্ট কৰক।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1227, 307, 26, 'তেওঁৰ ৰিচাৰ্চৰ স্বীকৃতি দিয়ক আৰু বাইক চোৱাৰ পিছত টেষ্ট ৰাইডলৈ আমন্ত্ৰণ জনাওক।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1228, 307, 26, 'ৰিচাৰ্চ স্বীকাৰ কৰি সুধক যে তেওঁ টেষ্ট ৰাইড কৰিব বিচাৰে নে নাই আৰু কিবা প্ৰয়োজন হ’লে আপুনি উপলব্ধ আছেন বুলি কওক।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1229, 308, 26, 'அவரின் ஆய்வை பாராட்டி, அவர் கவனிக்காமல் போயிருக்கக் கூடிய அம்சங்கள் அல்லது விவரங்களை சுருக்கமாக கூறுங்கள்.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1230, 308, 26, 'அவரின் ஆய்வை ஏற்று, அவரது முன்னுரிமைகளை கேட்டு, சந்தேகம் இருந்தால் தெளிவுபடுத்துங்கள்.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1231, 308, 26, 'அவரின் ஆய்வை பாராட்டி, பைக் பார்த்து முடித்த பிறகு டெஸ்ட் ரைடுக்கு அழைக்கவும்.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1232, 308, 26, 'ஆய்வை ஏற்று, டெஸ்ட் ரைடு விருப்பமா என்று கேட்டு, எந்த உதவிக்கும் நீங்கள் தயாராக இருப்பதை தெரிவிக்கவும்.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1233, 309, 26, 'అతని పరిశోధనను అభినందించి, అతను గమనించకపోయి ఉండవచ్చు అనే ఫీచర్లు లేదా స్పెసిఫికేషన్లు సంక్షిప్తంగా చెప్పండి.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1234, 309, 26, 'అతని పరిశోధనను గుర్తించి, అతని ప్రాధాన్యతలు తెలుసుకుని, ఏమైనా సందేహాలు ఉంటే క్లియర్ చేయండి.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1235, 309, 26, 'అతని పరిశోధనను అభినందించి, బైక్ పరిశీలన పూర్తయ్యాక టెస్ట్ రైడ్‌కు ఆహ్వానించండి.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1236, 309, 26, 'పరిశోధనను గుర్తించి, టెస్ట్ రైడ్ చేయాలనుకుంటున్నాడా అని అడిగి, ఏ అవసరం ఉన్నా మీరు అందుబాటులో ఉన్నారని చెప్పండి.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1237, 310, 26, 'അവന്റെ ഗവേഷണം അംഗീകരിച്ച്, ശ്രദ്ധിക്കാതെ പോയിരിക്കാവുന്ന ഫീച്ചറുകളോ സ്പെസിഫിക്കേഷനുകളോ സംക്ഷിപ്തമായി വ്യക്തമാക്കുക.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1238, 310, 26, 'ഗവേഷണം അംഗീകരിച്ച്, അവന്റെ മുൻഗണനകൾ ചോദിച്ച്, സംശയങ്ങൾ ഉണ്ടെങ്കിൽ വ്യക്തമാക്കുക.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1239, 310, 26, 'ഗവേഷണം അംഗീകരിച്ച്, ബൈക്ക് പരിശോധിച്ച ശേഷം ടെസ്റ്റ് റൈഡിന് ക്ഷണിക്കുക.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1240, 310, 26, 'ഗവേഷണം അംഗീകരിച്ച്, ടെസ്റ്റ് റൈഡ് വേണമോ എന്ന് ചോദിച്ച്, എന്ത് സഹായത്തിനും നിങ്ങൾ ലഭ്യരാണെന്ന് അറിയിക്കുക.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1241, 311, 26, 'ಅವರ ಸಂಶೋಧನೆಯನ್ನು ಮೆಚ್ಚಿ, ಗಮನಿಸದೆ ಹೋಗಿರಬಹುದಾದ ವೈಶಿಷ್ಟ್ಯಗಳು ಅಥವಾ ಸ್ಪೆಸಿಫಿಕೇಶನ್‌ಗಳನ್ನು ಸಂಕ್ಷಿಪ್ತವಾಗಿ ತಿಳಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1242, 311, 26, 'ಅವರ ಸಂಶೋಧನೆಯನ್ನು ಗುರುತಿಸಿ, ಅವರ ಪ್ರಾಧಾನ್ಯತೆಗಳನ್ನು ಕೇಳಿ ಮತ್ತು ಯಾವುದೇ ಅನುಮಾನಗಳಿದ್ದರೆ ಸ್ಪಷ್ಟಪಡಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1243, 311, 26, 'ಅವರ ಸಂಶೋಧನೆಯನ್ನು ಮೆಚ್ಚಿ, ಬೈಕ್ ಪರಿಶೀಲನೆ ಮುಗಿದ ನಂತರ ಟೆಸ್ಟ್ ರೈಡ್‌ಗೆ ಆಹ್ವಾನಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1244, 311, 26, 'ಸಂಶೋಧನೆಯನ್ನು ಗುರುತಿಸಿ, ಟೆಸ್ಟ್ ರೈಡ್ ಬೇಕೇ ಎಂದು ಕೇಳಿ ಮತ್ತು ಯಾವ ಸಹಾಯಕ್ಕೂ ನೀವು ಲಭ್ಯವಿರುವುದಾಗಿ ತಿಳಿಸಿ.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1245, 312, 26, 'ତାଙ୍କ ଗବେଷଣାକୁ ସ୍ୱୀକାର କରି, ହୋଇପାରେ ଛାଡ଼ି ଯାଇଥିବା ଫିଚର୍ କିମ୍ବା ସ୍ପେସିଫିକେଶନ୍‌ଗୁଡ଼ିକୁ ସଂକ୍ଷେପରେ କହନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1246, 312, 26, 'ତାଙ୍କ ଗବେଷଣାକୁ ମାନି ତାଙ୍କ ପ୍ରାଥମିକତା ସମ୍ପର୍କରେ ପଚାରନ୍ତୁ ଏବଂ କୌଣସି ସନ୍ଦେହ ଥିଲେ ସ୍ପଷ୍ଟ କରନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1247, 312, 26, 'ତାଙ୍କ ଗବେଷଣାକୁ ସ୍ୱୀକାର କରି ବାଇକ୍ ଦେଖିସାରିଲେ ଟେଷ୍ଟ ରାଇଡ୍ ପାଇଁ ଆମନ୍ତ୍ରଣ କରନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1248, 312, 26, 'ଗବେଷଣାକୁ ସ୍ୱୀକାର କରି, ସେ ଟେଷ୍ଟ ରାଇଡ୍ ଚାହୁଁଛନ୍ତି କି ନାହିଁ ପଚାରନ୍ତୁ ଏବଂ ଯେକୌଣସି ସହଯୋଗ ପାଇଁ ଆପଣ ଉପଲବ୍ଧ ବୋଲି କହନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1249, 313, 27, 'Assure the customer that Ride-By-Wire is a reliable technology used in the Xtreme 160R 4V', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1250, 313, 27, 'Explain the Ride-By-Wire feature, and highlight all the benefits it offers ', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1251, 313, 27, 'Highlight that the advantage of the feature and offer a test ride to understand feature benefits', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1252, 313, 27, 'Explain the technology and benefits, reassure with Hero advantages, and offer a test ride', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1253, 314, 27, 'ग्राहक को भरोसा दिलाएँ कि Ride-By-Wire एक भरोसेमंद तकनीक है, जिसका इस्तेमाल Xtreme 160R 4V में किया गया है।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1254, 314, 27, 'Ride-By-Wire फीचर को आसान शब्दों में समझाएँ और यह भी बताएं कि इससे क्या-क्या फायदे मिलते हैं।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1255, 314, 27, 'इस फीचर के फायदे बताएं और उसे समझने के लिए ग्राहक को टेस्ट राइड का ऑफर करें।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
