	(1422, 356, 30, 'Xpulse 200-ஐ அறிமுகப்படுத்தி, Xpulse 210-ன் 200-ஐ விட கூடுதல் நன்மைகளை விளக்குங்கள்.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1423, 356, 30, 'Xpulse 200-ஐ அறிமுகப்படுத்தி, Xpulse 210-ன் நன்மைகளை காட்டி, சிறிது அதிக விலையில் கிடைக்கும் மதிப்பை விளக்குங்கள்.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1424, 356, 30, 'Xpulse 200-ஐ அறிமுகப்படுத்தி, Xpulse 210-ன் கூடுதல் மதிப்பை விளக்கி, வாடிக்கையாளர் தேவைகளுடன் இணைத்து, இரண்டிற்கும் டெஸ்ட் ரைடு வழங்குங்கள்.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1425, 357, 30, 'Xpulse 200 ను పరిచయం చేసి, కస్టమర్ అవసరాలకు అనుగుణంగా Xpulse 210 కూడా సరిపోతుందని సంక్షిప్తంగా చెప్పండి.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1426, 357, 30, 'Xpulse 200 ను పరిచయం చేసి, Xpulse 210 యొక్క అదనపు ప్రయోజనాలను వివరించండి.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1427, 357, 30, 'Xpulse 200 ను పరిచయం చేసి, Xpulse 210 ప్రయోజనాలను చూపించి, కొంచెం ఎక్కువ ధరకు లభించే విలువను వివరించండి.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1428, 357, 30, 'Xpulse 200 ను పరిచయం చేసి, Xpulse 210 యొక్క అదనపు విలువను వివరించి, కస్టమర్ అవసరాలకు అనుసంధానం చేసి, రెండింటికీ టెస్ట్ రైడ్ ఆఫర్ చేయండి.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1429, 358, 30, 'Xpulse 200 അവതരിപ്പിച്ച്, ഉപഭോക്താവിന്റെ ആവശ്യങ്ങൾക്കനുസരിച്ച് Xpulse 210യും അനുയോജ്യമാണെന്ന് സംക്ഷിപ്തമായി പറയുക.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1430, 358, 30, 'Xpulse 200 അവതരിപ്പിച്ച്, Xpulse 210-ന്റെ അധിക ഗുണങ്ങൾ വിശദീകരിക്കുക.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1431, 358, 30, 'Xpulse 200 അവതരിപ്പിച്ച്, Xpulse 210-ന്റെ ഗുണങ്ങൾ കാണിച്ച്, കുറച്ച് കൂടുതലായ വിലയ്ക്ക് ലഭിക്കുന്ന മൂല്യം വിശദീകരിക്കുക.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1432, 358, 30, 'Xpulse 200 അവതരിപ്പിച്ച്, Xpulse 210-ന്റെ അധിക മൂല്യം വിശദീകരിച്ച്, ഉപഭോക്താവിന്റെ ആവശ്യങ്ങളുമായി ബന്ധപ്പെടുത്തി, രണ്ടിനും ടെസ്റ്റ് റൈഡ് നൽകുക.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1433, 359, 30, 'Xpulse 200 ಅನ್ನು ಪರಿಚಯಿಸಿ ಮತ್ತು ಗ್ರಾಹಕರ ಅಗತ್ಯಗಳಿಗೆ ಅನುಗುಣವಾಗಿ Xpulse 210 ಕೂಡ ಸೂಕ್ತವೆಂದು ಸಂಕ್ಷಿಪ್ತವಾಗಿ ಹೇಳಿ.', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1434, 359, 30, 'Xpulse 200 ಅನ್ನು ಪರಿಚಯಿಸಿ, Xpulse 210 ರ ಹೆಚ್ಚುವರಿ ಲಾಭಗಳನ್ನು ವಿವರಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1435, 359, 30, 'Xpulse 200 ಅನ್ನು ಪರಿಚಯಿಸಿ, Xpulse 210 ರ ಲಾಭಗಳನ್ನು ತೋರಿಸಿ ಮತ್ತು ಸ್ವಲ್ಪ ಹೆಚ್ಚಿನ ಬೆಲೆಗೆ ದೊರೆಯುವ ಮೌಲ್ಯವನ್ನು ವಿವರಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1436, 359, 30, 'Xpulse 200 ಅನ್ನು ಪರಿಚಯಿಸಿ, Xpulse 210 ರ ಹೆಚ್ಚುವರಿ ಮೌಲ್ಯವನ್ನು ವಿವರಿಸಿ, ಗ್ರಾಹಕರ ಅಗತ್ಯಗಳಿಗೆ ಹೊಂದಿಸಿ ಮತ್ತು ಎರಡಕ್ಕೂ ಟೆಸ್ಟ್ ರೈಡ್ ಆಫರ್ ಮಾಡಿ.', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
	(1437, 360, 30, 'Xpulse 200 ପ୍ରସ୍ତୁତ କରନ୍ତୁ ଏବଂ ଗ୍ରାହକଙ୍କ ଆବଶ୍ୟକତା ଅନୁସାରେ Xpulse 210 ମଧ୍ୟ ଉପଯୁକ୍ତ ବୋଲି ସଂକ୍ଷେପରେ କହନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-26 07:03:07'),
	(1438, 360, 30, 'Xpulse 200 ପ୍ରସ୍ତୁତ କରନ୍ତୁ ଏବଂ Xpulse 210 ର ଅତିରିକ୍ତ ଲାଭ ବୁଝାନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-26 07:03:07'),
	(1439, 360, 30, 'Xpulse 200 ପ୍ରସ୍ତୁତ କରନ୍ତୁ, Xpulse 210 ର ଲାଭ ଦେଖାନ୍ତୁ ଏବଂ ଅଳ୍ପ ଅଧିକ ମୂଲ୍ୟରେ ମିଳୁଥିବା ଭାଲୁ ବୁଝାନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-26 07:03:07'),
	(1440, 360, 30, 'Xpulse 200 ପ୍ରସ୍ତୁତ କରନ୍ତୁ, Xpulse 210 ର ଅତିରିକ୍ତ ଭାଲୁ ବୁଝାନ୍ତୁ, ଗ୍ରାହକଙ୍କ ଆବଶ୍ୟକତା ସହିତ ମେଳ କରନ୍ତୁ ଏବଂ ଦୁହିଁଟିର ଟେଷ୍ଟ ରାଇଡ୍ ଅଫର କରନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-26 07:03:07'),
