	(1447, 362, 31, 'माफी मांगें और बताएं कि आवेदन में गलत आय दर्ज होने के कारण लोन रिजेक्ट हुआ।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1448, 362, 31, 'माफी मांगें, रिजेक्शन का कारण समझाएं और सुधार के कदम बताकर दोबारा आवेदन में मदद करें।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1449, 363, 31, 'ਅਸੁਵਿਧਾ ਲਈ ਮਾਫ਼ੀ ਮੰਗੋ ਅਤੇ ਲੋਨ ਰੱਦ ਹੋਣ ਕਾਰਨ ਗਾਹਕ ਦੀ ਨਿਰਾਸ਼ਾ ਨੂੰ ਮੰਨੋ।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1450, 363, 31, 'ਮਾਫ਼ੀ ਮੰਗੋ ਅਤੇ ਸਮਝਾਓ ਕਿ ਲੋਨ ਦੀ ਮਨਜ਼ੂਰੀ ਪੂਰੀ ਤਰ੍ਹਾਂ ਫਾਇਨੈਂਸਰ ਦੇ ਫੈਸਲੇ ‘ਤੇ ਨਿਰਭਰ ਕਰਦੀ ਹੈ।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1451, 363, 31, 'ਮਾਫ਼ੀ ਮੰਗੋ ਅਤੇ ਦੱਸੋ ਕਿ ਅਰਜ਼ੀ ਵਿੱਚ ਗਲਤ ਆਮਦਨ ਦਰਜ ਹੋਣ ਕਰਕੇ ਲੋਨ ਰੱਦ ਹੋਇਆ।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1452, 363, 31, 'ਮਾਫ਼ੀ ਮੰਗੋ, ਰੱਦ ਹੋਣ ਦਾ ਕਾਰਨ ਸਮਝਾਓ ਅਤੇ ਸੁਧਾਰਕ ਕਦਮ ਦੱਸ ਕੇ ਦੁਬਾਰਾ ਅਰਜ਼ੀ ਵਿੱਚ ਮਦਦ ਕਰੋ।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1453, 364, 31, 'અસુવિધા માટે માફી માંગો અને લોન નકારાતા ગ્રાહકની નિરાશાને સ્વીકારો।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1454, 364, 31, 'માફી માંગો અને સમજાવો કે લોન મંજૂરી સંપૂર્ણપણે ફાઇનાન્સરના નિર્ણય પર આધારિત છે।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1455, 364, 31, 'માફી માંગો અને જણાવો કે અરજીમાં ખોટી આવક દર્શાવવાના કારણે લોન નકારાયો।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1456, 364, 31, 'માફી માંગો, નકારવાનો કારણ સ્પષ્ટ સમજાવો અને સુધારણા પગલાં સાથે ફરી અરજી માટે માર્ગદર્શન આપો।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1457, 365, 31, 'असुविधेबद्दल माफी मागा आणि कर्ज नाकारल्यामुळे झालेली ग्राहकाची नाराजी मान्य करा।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
