	(1459, 365, 31, 'माफी मागून सांगा की अर्जात चुकीचे उत्पन्न नमूद केल्यामुळे कर्ज नाकारले गेले।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1460, 365, 31, 'माफी मागा, नकाराचे कारण स्पष्ट करा आणि सुधारात्मक पावले सांगून पुन्हा अर्ज करण्यास मदत करा।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1461, 366, 31, 'অসুবিধার জন্য ক্ষমা চান এবং ঋণ বাতিল হওয়ায় গ্রাহকের হতাশা স্বীকার করুন।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1462, 366, 31, 'ক্ষমা চেয়ে ব্যাখ্যা করুন যে ঋণ অনুমোদন সম্পূর্ণভাবে ফাইন্যান্সারের সিদ্ধান্তের উপর নির্ভর করে।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
