	(1464, 366, 31, 'ক্ষমা চেয়ে বাতিলের কারণ স্পষ্ট করে ব্যাখ্যা করুন এবং সংশোধনের ধাপ ও পুনরায় আবেদন করতে সহায়তা করুন।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1465, 367, 31, 'অসুবিধাৰ বাবে ক্ষমা বিচাৰক আৰু ঋণ নাকচ হোৱাৰ বাবে গ্ৰাহকৰ হতাশা স্বীকাৰ কৰক।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1466, 367, 31, 'ক্ষমা বিচাৰি বুজাওক যে ঋণ অনুমোদন সম্পূৰ্ণকৈ ফাইনান্সাৰৰ সিদ্ধান্তৰ ওপৰত নিৰ্ভৰ কৰে।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1467, 367, 31, 'ক্ষমা বিচাৰি জনাওক যে আবেদনত ভুল আয় উল্লেখ কৰাৰ বাবে ঋণ নাকচ কৰা হৈছিল।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1468, 367, 31, 'ক্ষমা বিচাৰি নাকচ কৰাৰ কাৰণ স্পষ্টকৈ বুজাওক আৰু সংশোধনৰ পদক্ষেপসমূহ দেখুৱাই পুনৰ আবেদনত সহায় কৰক।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1469, 368, 31, 'ஏற்பட்ட சிரமத்திற்கு மன்னிப்பு கேட்டு, கடன் நிராகரிப்பால் ஏற்பட்ட வாடிக்கையாளர் ஏமாற்றத்தை ஏற்றுக்கொள்ளுங்கள்.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1470, 368, 31, 'மன்னிப்பு கேட்டு, கடன் ஒப்புதல் முழுமையாக நிதியாளரின் முடிவில் இருப்பதை விளக்குங்கள்.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1471, 368, 31, 'மன்னிப்பு கேட்டு, விண்ணப்பத்தில் தவறான வருமானம் குறிப்பிடப்பட்டதால் கடன் நிராகரிக்கப்பட்டது என்பதை தெரிவிக்கவும்.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1472, 368, 31, 'மன்னிப்பு கேட்டு, நிராகரிப்பு காரணத்தை தெளிவாக விளக்கி, திருத்த நடவடிக்கைகள் மற்றும் மீண்டும் விண்ணப்பிக்க உதவுங்கள்.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1473, 369, 31, 'అసౌకర్యానికి క్షమాపణ చెప్పి, లోన్ తిరస్కరణ వల్ల కస్టమర్ నిరాశను గుర్తించండి.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1474, 369, 31, 'క్షమాపణ చెప్పి, లోన్ ఆమోదం పూర్తిగా ఫైనాన్సర్ నిర్ణయంపై ఆధారపడుతుందని వివరించండి.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1475, 369, 31, 'క్షమాపణ చెప్పి, దరఖాస్తులో తప్పు ఆదాయం పేర్కొనడం వల్ల లోన్ తిరస్కరించబడిందని తెలియజేయండి.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1476, 369, 31, 'క్షమాపణ చెప్పి, తిరస్కరణ కారణాన్ని స్పష్టంగా వివరించి, సరిదిద్దే చర్యలు మరియు మళ్లీ దరఖాస్తు చేయడంలో సహాయం చేయండి.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1477, 370, 31, 'അസൗകര്യത്തിന് ക്ഷമ ചോദിച്ച്, വായ്പ നിരസിച്ചതിനാൽ ഉണ്ടായ ഉപഭോക്താവിന്റെ നിരാശ അംഗീകരിക്കുക.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1478, 370, 31, 'ക്ഷമ ചോദിച്ച് വായ്പ അംഗീകാരം പൂർണ്ണമായും ഫിനാൻസറുടെ തീരുമാനത്തിനാണ് വിധേയമെന്ന് വിശദീകരിക്കുക.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1479, 370, 31, 'ക്ഷമ ചോദിച്ച് അപേക്ഷയിൽ തെറ്റായ വരുമാനം നൽകിയതിനാൽ വായ്പ നിരസിച്ചതായി അറിയിക്കുക.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1480, 370, 31, 'ക്ഷമ ചോദിച്ച് നിരസിച്ച കാരണവും വിശദീകരിച്ച് തിരുത്തൽ നടപടികളും വീണ്ടും അപേക്ഷിക്കാനും സഹായിക്കുക.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1481, 371, 31, 'ಅಸೌಕರ್ಯಕ್ಕಾಗಿ ಕ್ಷಮೆ ಕೇಳಿ ಮತ್ತು ಸಾಲು ತಿರಸ್ಕೃತವಾದ ಕಾರಣ ಗ್ರಾಹಕರ ನಿರಾಶೆಯನ್ನು ಒಪ್ಪಿಕೊಳ್ಳಿ.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1482, 371, 31, 'ಕ್ಷಮೆ ಕೇಳಿ, ಸಾಲು ಅನುಮೋದನೆ ಸಂಪೂರ್ಣವಾಗಿ ಫೈನಾನ್ಸರ್‌ನ ನಿರ್ಧಾರಕ್ಕೆ ಒಳಪಟ್ಟಿದೆ ಎಂದು ವಿವರಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1483, 371, 31, 'ಕ್ಷಮೆ ಕೇಳಿ, ಅರ್ಜಿಯಲ್ಲಿ ತಪ್ಪು ಆದಾಯವನ್ನು ಉಲ್ಲೇಖಿಸಿದ್ದರಿಂದ ಸಾಲು ತಿರಸ್ಕರಿಸಲಾಗಿದೆ ಎಂದು ತಿಳಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1484, 371, 31, 'ಕ್ಷಮೆ ಕೇಳಿ, ತಿರಸ್ಕಾರದ ಕಾರಣವನ್ನು ಸ್ಪಷ್ಟವಾಗಿ ವಿವರಿಸಿ ಮತ್ತು ತಿದ್ದುಪಡಿ ಕ್ರಮಗಳು ಹಾಗೂ ಮರುಅರ್ಜಿಗೆ ಸಹಾಯ ಮಾಡಿ.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1485, 372, 31, 'ଅସୁବିଧା ପାଇଁ କ୍ଷମା ମାଗନ୍ତୁ ଏବଂ ଋଣ ରଦ୍ଦ ହେବାରୁ ଗ୍ରାହକଙ୍କ ନିରାଶାକୁ ସ୍ୱୀକାର କରନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1486, 372, 31, 'କ୍ଷମା ମାଗି ବୁଝାନ୍ତୁ ଯେ ଋଣ ମଞ୍ଜୁରି ପୂର୍ଣ୍ଣରୂପେ ଫାଇନାନ୍ସରଙ୍କ ନିଷ୍ପତ୍ତି ଉପରେ ନିର୍ଭର କରେ।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1487, 372, 31, 'କ୍ଷମା ମାଗି ଜଣାନ୍ତୁ ଯେ ଆବେଦନରେ ଭୁଲ ଆୟ ଦେବାରୁ ଋଣ ରଦ୍ଦ ହୋଇଥିଲା।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1488, 372, 31, 'କ୍ଷମା ମାଗି ରଦ୍ଦ ହେବାର କାରଣ ସ୍ପଷ୍ଟ କରନ୍ତୁ ଏବଂ ସୁଧାର ପଦକ୍ଷେପ ସହ ପୁନଃଆବେଦନରେ ସହଯୋଗ କରନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1489, 373, 32, 'Apologize for the inconvenience and acknowledge the customer’s disappointment ', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1490, 373, 32, 'Apologize for the inconvenience and assure the customer you will follow up ', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1491, 373, 32, 'Apologize, explain the reason for delay and tell the customer you will do your best to ensure approval at the earliest', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1492, 373, 32, 'Apologize, clearly explain that the delay reason, prioritize the case and provide a specific timeline for approval, and ensure regular updates ', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1493, 374, 32, 'असुविधा के लिए माफी मांगें और ग्राहक की निराशा को समझें।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1494, 374, 32, 'असुविधा के लिए माफी मांगें और ग्राहक को भरोसा दें कि आप फॉलो‑अप करेंगे।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1495, 374, 32, 'माफी मांगें, देरी का कारण समझाएं और बताएं कि आप जल्द से जल्द मंजूरी दिलाने की पूरी कोशिश करेंगे।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1496, 374, 32, 'माफी मांगें, देरी का कारण स्पष्ट बताएं, केस को प्राथमिकता दें, मंजूरी की तय समयसीमा दें और नियमित अपडेट देते रहें।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1497, 375, 32, 'ਅਸੁਵਿਧਾ ਲਈ ਮਾਫ਼ੀ ਮੰਗੋ ਅਤੇ ਗਾਹਕ ਦੀ ਨਿਰਾਸ਼ਾ ਨੂੰ ਮੰਨੋ।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1498, 375, 32, 'ਅਸੁਵਿਧਾ ਲਈ ਮਾਫ਼ੀ ਮੰਗੋ ਅਤੇ ਗਾਹਕ ਨੂੰ ਯਕੀਨ ਦਿਵਾਓ ਕਿ ਤੁਸੀਂ ਫਾਲੋ‑ਅੱਪ ਕਰੋਗੇ।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1499, 375, 32, 'ਮਾਫ਼ੀ ਮੰਗੋ, ਦੇਰੀ ਦਾ ਕਾਰਨ ਸਮਝਾਓ ਅਤੇ ਦੱਸੋ ਕਿ ਤੁਸੀਂ ਜਲਦੀ ਮਨਜ਼ੂਰੀ ਲਈ ਪੂਰੀ ਕੋਸ਼ਿਸ਼ ਕਰੋਗੇ।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1500, 375, 32, 'ਮਾਫ਼ੀ ਮੰਗੋ, ਦੇਰੀ ਦਾ ਕਾਰਨ ਸਾਫ਼ ਦੱਸੋ, ਕੇਸ ਨੂੰ ਤਰਜੀਹ ਦਿਓ, ਮਨਜ਼ੂਰੀ ਦੀ ਸਮੇਂ ਸੀਮਾ ਦਿਓ ਅਤੇ ਨਿਯਮਿਤ ਅੱਪਡੇਟ ਦਿਓ।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1501, 376, 32, 'અસુવિધા માટે માફી માંગો અને ગ્રાહકની નિરાશાને સ્વીકારો।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1502, 376, 32, 'અસુવિધા માટે માફી માંગો અને ગ્રાહકને ખાતરી આપો કે તમે ફોલો‑અપ કરશો।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1503, 376, 32, 'માફી માંગો, વિલંબનું કારણ સમજાવો અને જલદી મંજૂરી માટે શ્રેષ્ઠ પ્રયત્ન કરશો તે કહો।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1504, 376, 32, 'માફી માંગો, વિલંબનું કારણ સ્પષ્ટ કહો, કેસને પ્રાથમિકતા આપો, નિશ્ચિત સમયરેખા આપો અને નિયમિત અપડેટ આપતા રહો।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1505, 377, 32, 'असुविधेबद्दल माफी मागा आणि ग्राहकाची नाराजी मान्य करा।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1506, 377, 32, 'असुविधेबद्दल माफी मागून ग्राहकाला खात्री द्या की तुम्ही फॉलो‑अप कराल।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1507, 377, 32, 'माफी मागा, उशीराचे कारण समजवा आणि लवकर मंजुरीसाठी पूर्ण प्रयत्न कराल असे सांगा।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1508, 377, 32, 'माफी मागा, उशीराचे कारण स्पष्ट करा, केसला प्राधान्य द्या, मंजुरीची वेळ ठरवा आणि नियमित अपडेट द्या।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1509, 378, 32, 'অসুবিধার জন্য ক্ষমা চান এবং গ্রাহকের হতাশা স্বীকার করুন।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1510, 378, 32, 'অসুবিধার জন্য ক্ষমা চেয়ে গ্রাহককে আশ্বাস দিন যে আপনি ফলো‑আপ করবেন।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1511, 378, 32, 'ক্ষমা চেয়ে দেরির কারণ ব্যাখ্যা করুন এবং দ্রুত অনুমোদনের জন্য সর্বোচ্চ চেষ্টা করবেন বলুন।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1512, 378, 32, 'ক্ষমা চেয়ে দেরির কারণ স্পষ্ট করুন, কেসকে অগ্রাধিকার দিন, নির্দিষ্ট সময়সীমা দিন এবং নিয়মিত আপডেট নিশ্চিত করুন।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1513, 379, 32, 'অসুবিধাৰ বাবে ক্ষমা বিচাৰক আৰু গ্ৰাহকৰ হতাশা স্বীকাৰ কৰক।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1514, 379, 32, 'অসুবিধাৰ বাবে ক্ষমা বিচাৰি গ্ৰাহকক আশ্বাস দিয়ক যে আপুনি ফলো‑আপ কৰিব।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1515, 379, 32, 'ক্ষমা বিচাৰি বিলম্বৰ কাৰণ বুজাওক আৰু সোনকালে অনুমোদনৰ বাবে সম্পূৰ্ণ চেষ্টা কৰাৰ কথা কওক।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1516, 379, 32, 'ক্ষমা বিচাৰি বিলম্বৰ কাৰণ স্পষ্ট কৰক, কেছটোত অগ্ৰাধিকাৰ দিয়ক, নিৰ্দিষ্ট সময়সীমা দিয়ক আৰু নিয়মিত আপডেট নিশ্চিত কৰক।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1517, 380, 32, 'ஏற்பட்ட சிரமத்திற்கு மன்னிப்பு கேட்டு, வாடிக்கையாளர் ஏமாற்றத்தை ஏற்றுக்கொள்ளுங்கள்.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1518, 380, 32, 'சிரமத்திற்கு மன்னிப்பு கேட்டு, நீங்கள் தொடர்ந்து கவனிப்பீர்கள் என்று வாடிக்கையாளருக்கு உறுதி அளிக்கவும்.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1519, 380, 32, 'மன்னிப்பு கேட்டு, தாமதத்தின் காரணத்தை விளக்கி, விரைவில் ஒப்புதல் பெற முயற்சி செய்வீர்கள் என்று கூறுங்கள்.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1520, 380, 32, 'மன்னிப்பு கேட்டு, தாமத காரணத்தை தெளிவாக விளக்கி, வழக்கை முன்னுரிமை அளித்து, குறிப்பிட்ட காலக்கெடு கூறி, வழக்கமான புதுப்பிப்புகளை வழங்குங்கள்.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1521, 381, 32, 'అసౌకర్యానికి క్షమాపణ చెప్పి, కస్టమర్ నిరాశను గుర్తించండి.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1522, 381, 32, 'అసౌకర్యానికి క్షమాపణ చెప్పి, మీరు ఫాలో‑అప్ చేస్తారని కస్టమర్‌కు భరోసా ఇవ్వండి.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1523, 381, 32, 'క్షమాపణ చెప్పి, ఆలస్యానికి కారణం వివరించి, త్వరగా ఆమోదం కోసం ప్రయత్నిస్తామని చెప్పండి.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
