	(1574, 394, 33, 'കുഴപ്പത്തിന് ക്ഷമ ചോദിച്ച് 0 ഡൗൺ പേയ്മെന്റ് ഓഫറിന്റെ അർഹത മാനദണ്ഡങ്ങൾ വിശദീകരിക്കുക.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1575, 394, 33, 'ക്ഷമ ചോദിച്ച് അർഹത വ്യക്തമാക്കുകയും അനുയോജ്യമായ മറ്റു ഫിനാൻസ് ഓപ്ഷൻ നിർദ്ദേശിക്കുകയും ചെയ്യുക.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1576, 394, 33, 'ക്ഷമ ചോദിച്ച് അർഹത വിശദീകരിച്ച്, മറ്റ് പരിഹാരം നിർദ്ദേശിച്ച്, മുഴുവൻ പ്രക്രിയയിലും സഹായിക്കുക.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1577, 395, 33, 'ಕ್ಷಮೆ ಕೇಳಿ, ಗ್ರಾಹಕರು 0 ಡೌನ್ ಪೇಮೆಂಟ್ ಆಫರ್‌ಗೆ ಅರ್ಹರಲ್ಲ ಎಂದು ತಿಳಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1578, 395, 33, 'ಗೊಂದಲಕ್ಕೆ ಕ್ಷಮೆ ಕೇಳಿ, 0 ಡೌನ್ ಪೇಮೆಂಟ್ ಆಫರ್ ಅರ್ಹತಾ ನಿಯಮಗಳನ್ನು ವಿವರಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1579, 395, 33, 'ಕ್ಷಮೆ ಕೇಳಿ, ಅರ್ಹತೆ ಸ್ಪಷ್ಟಪಡಿಸಿ ಮತ್ತು ಸೂಕ್ತ ಪರ್ಯಾಯ ಫೈನಾನ್ಸ್ ಆಯ್ಕೆ ಸೂಚಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1580, 395, 33, 'ಕ್ಷಮೆ ಕೇಳಿ, ಅರ್ಹತೆ ವಿವರಿಸಿ, ಪರ್ಯಾಯ ಪರಿಹಾರ ಸೂಚಿಸಿ ಮತ್ತು ಸಂಪೂರ್ಣ ಪ್ರಕ್ರಿಯೆಯಲ್ಲಿ ಸಹಾಯ ಮಾಡಿ.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1581, 396, 33, 'କ୍ଷମା ମାଗି ଗ୍ରାହକଙ୍କୁ କହନ୍ତୁ ଯେ ସେ 0 ଡାଉନ ପେମେଣ୍ଟ ଅଫର ପାଇଁ ଯୋଗ୍ୟ ନୁହନ୍ତି।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1582, 396, 33, 'ଭୁଲ ବୁଝାବୁଝି ପାଇଁ କ୍ଷମା ମାଗି 0 ଡାଉନ ପେମେଣ୍ଟ ଅଫରର ଯୋଗ୍ୟତା ନିୟମ ବୁଝାନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1583, 396, 33, 'କ୍ଷମା ମାଗି ଯୋଗ୍ୟତା ସ୍ପଷ୍ଟ କରନ୍ତୁ ଏବଂ ଉପଯୁକ୍ତ ବିକଳ୍ପ ଫାଇନାନ୍ସ ପ୍ରସ୍ତାବ ଦିଅନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1584, 396, 33, 'କ୍ଷମା ମାଗି ଯୋଗ୍ୟତା ବୁଝାନ୍ତୁ, ବିକଳ୍ପ ସମାଧାନ ପ୍ରସ୍ତାବ କରନ୍ତୁ ଏବଂ ପୂରା ପ୍ରକ୍ରିୟାରେ ସହଯୋଗ କରନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1585, 397, 34, 'Apologize but explain that such charges are standard finance charges and are decided by the financer', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1586, 397, 34, 'Apologize and explain that the processing fee and stamp duty are mandatory charges, assuring the quotation is accurate', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1587, 397, 34, 'Apologize for missing the explanation earlier and clearly describe the purpose of each charge', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1588, 397, 34, 'Apologize and acknowledge the concern, clearly break down every charge and reconfirm acceptance after ensuring full transparency and comfort', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1589, 398, 34, 'माफी मांगें लेकिन समझाएं कि ये सभी स्टैंडर्ड फाइनेंस चार्ज हैं और फाइनेंसर द्वारा तय किए जाते हैं।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1590, 398, 34, 'माफी मांगें और बताएं कि प्रोसेसिंग फीस और स्टाम्प ड्यूटी अनिवार्य शुल्क हैं तथा कोटेशन सही है।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1591, 398, 34, 'पहले स्पष्ट न करने के लिए माफी मांगें और हर चार्ज का उद्देश्य साफ-साफ समझाएं।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1592, 398, 34, 'माफी मांगें, ग्राहक की चिंता समझें, हर चार्ज का पूरा विवरण दें और पूरी पारदर्शिता के बाद दोबारा सहमति लें।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1593, 399, 34, 'ਮਾਫ਼ੀ ਮੰਗੋ ਪਰ ਸਮਝਾਓ ਕਿ ਇਹ ਸਾਰੇ ਸਟੈਂਡਰਡ ਫਾਇਨੈਂਸ ਚਾਰਜ ਹਨ ਜੋ ਫਾਇਨੈਂਸਰ ਤੈਅ ਕਰਦਾ ਹੈ।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1594, 399, 34, 'ਮਾਫ਼ੀ ਮੰਗੋ ਅਤੇ ਦੱਸੋ ਕਿ ਪ੍ਰੋਸੈਸਿੰਗ ਫੀਸ ਅਤੇ ਸਟੈਂਪ ਡਿਊਟੀ ਲਾਜ਼ਮੀ ਚਾਰਜ ਹਨ ਅਤੇ ਕੋਟੇਸ਼ਨ ਸਹੀ ਹੈ।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1595, 399, 34, 'ਪਹਿਲਾਂ ਨਾ ਸਮਝਾਉਣ ਲਈ ਮਾਫ਼ੀ ਮੰਗੋ ਅਤੇ ਹਰ ਚਾਰਜ ਦਾ ਮਕਸਦ ਸਪਸ਼ਟ ਕਰੋ।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1596, 399, 34, 'ਮਾਫ਼ੀ ਮੰਗੋ, ਗਾਹਕ ਦੀ ਚਿੰਤਾ ਨੂੰ ਮੰਨੋ, ਹਰ ਚਾਰਜ ਦਾ ਵੇਰਵਾ ਦਿਓ ਅਤੇ ਪੂਰੀ ਪਾਰਦਰਸ਼ਤਾ ਤੋਂ ਬਾਅਦ ਸਹਿਮਤੀ ਲਵੋ।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1597, 400, 34, 'માફી માંગો પરંતુ સમજાવો કે આ બધા સ્ટાન્ડર્ડ ફાઇનાન્સ ચાર્જ છે અને ફાઇનાન્સર દ્વારા નક્કી થાય છે।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1598, 400, 34, 'માફી માંગો અને કહો કે પ્રોસેસિંગ ફી અને સ્ટેમ્પ ડ્યુટી ફરજિયાત ચાર્જ છે અને કોટેશન સાચું છે।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1599, 400, 34, 'પહેલાં સ્પષ્ટ ન કરવા બદલ માફી માંગો અને દરેક ચાર્જનો હેતુ સ્પષ્ટ રીતે સમજાવો।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1600, 400, 34, 'માફી માંગો, ગ્રાહકની ચિંતા સ્વીકારો, દરેક ચાર્જનો વિગતવાર ખુલાસો કરો અને સંપૂર્ણ પારદર્શિતા બાદ સ્વીકૃતિ ફરીથી લો।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1601, 401, 34, 'माफी मागा पण समजवा की हे सर्व स्टँडर्ड फायनान्स चार्ज आहेत आणि फायनान्सर ठरवतो।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1602, 401, 34, 'माफी मागा आणि सांगा की प्रोसेसिंग फी आणि स्टॅम्प ड्युटी हे अनिवार्य शुल्क आहेत आणि कोटेशन बरोबर आहे।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1603, 401, 34, 'आधी स्पष्ट न केल्याबद्दल माफी मागा आणि प्रत्येक शुल्काचा उद्देश स्पष्ट करा।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1604, 401, 34, 'माफी मागा, ग्राहकाची चिंता मान्य करा, प्रत्येक शुल्काचे सविस्तर स्पष्टीकरण द्या आणि पूर्ण पारदर्शकतेनंतर पुन्हा संमती घ्या।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1605, 402, 34, 'ক্ষমা চেয়ে বলুন যে এগুলো স্ট্যান্ডার্ড ফাইন্যান্স চার্জ এবং ফাইন্যান্সার দ্বারা নির্ধারিত।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1606, 402, 34, 'ক্ষমা চেয়ে জানান যে প্রসেসিং ফি এবং স্ট্যাম্প ডিউটি বাধ্যতামূলক চার্জ এবং কোটেশন সঠিক।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1607, 402, 34, 'আগে ব্যাখ্যা না করার জন্য ক্ষমা চেয়ে প্রতিটি চার্জের উদ্দেশ্য পরিষ্কারভাবে ব্যাখ্যা করুন।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1608, 402, 34, 'ক্ষমা চেয়ে গ্রাহকের উদ্বেগ স্বীকার করুন, প্রতিটি চার্জ ভেঙে বুঝিয়ে দিন এবং পূর্ণ স্বচ্ছতার পর পুনরায় সম্মতি নিন।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1609, 403, 34, 'ক্ষমা বিচাৰি কওক যে এইবোৰ সাধাৰণ ফাইনান্স চাৰ্জ আৰু ফাইনান্সাৰে নিৰ্ধাৰণ কৰে।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1610, 403, 34, 'ক্ষমা বিচাৰি জনাওক যে প্ৰচেছিং ফী আৰু ষ্টাম্প ডিউটি বাধ্যতামূলক চাৰ্জ আৰু কোটেশ্যন সঠিক।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1611, 403, 34, 'আগতে ব্যাখ্যা নকৰাৰ বাবে ক্ষমা বিচাৰি প্ৰতিটো চাৰ্জৰ উদ্দেশ্য স্পষ্টকৈ বুজাওক।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1612, 403, 34, 'ক্ষমা বিচাৰি গ্ৰাহকৰ চিন্তা স্বীকাৰ কৰক, প্ৰতিটো চাৰ্জ বিৱৰণীসহ বুজাওক আৰু সম্পূৰ্ণ স্বচ্ছতাৰ পিছত পুনৰ সম্মতি লওক।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1613, 404, 34, 'மன்னிப்பு கேட்டு, இவை ஸ்டாண்டர்ட் நிதி கட்டணங்கள் மற்றும் நிதியாளரால் நிர்ணயிக்கப்படுகின்றன என்று விளக்குங்கள்.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1614, 404, 34, 'மன்னிப்பு கேட்டு, செயலாக்க கட்டணம் மற்றும் ஸ்டாம்ப் டியூட்டி கட்டாய கட்டணங்கள் என்றும் கோட்டேஷன் சரியானது என்றும் தெரிவிக்கவும்.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1615, 404, 34, 'முன்னதாக விளக்காமல் விட்டதற்கு மன்னிப்பு கேட்டு, ஒவ்வொரு கட்டணத்தின் நோக்கத்தை தெளிவாக விளக்கவும்.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1616, 404, 34, 'மன்னிப்பு கேட்டு, வாடிக்கையாளர் கவலை ஏற்றுக்கொண்டு, ஒவ்வொரு கட்டணத்தையும் தெளிவாக பிரித்து விளக்கி, முழு வெளிப்படைத்தன்மைக்கு பிறகு மீண்டும் ஒப்புதல் பெறவும்.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1617, 405, 34, 'క్షమాపణ చెప్పి, ఇవి సాధారణ ఫైనాన్స్ ఛార్జీలు మరియు ఫైనాన్సర్ నిర్ణయించినవని వివరించండి.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1618, 405, 34, 'క్షమాపణ చెప్పి, ప్రాసెసింగ్ ఫీ మరియు స్టాంప్ డ్యూటీ తప్పనిసరి ఛార్జీలు అని మరియు కోటేషన్ సరైందని చెప్పండి.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1619, 405, 34, 'ముందుగా వివరించకపోవడానికి క్షమాపణ చెప్పి, ప్రతి ఛార్జ్ ఉద్దేశ్యాన్ని స్పష్టంగా వివరించండి.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1620, 405, 34, 'క్షమాపణ చెప్పి, కస్టమర్ ఆందోళనను గుర్తించి, ప్రతి ఛార్జ్ వివరంగా చెప్పి, పూర్తి పారదర్శకత తర్వాత మళ్లీ అంగీకారం తీసుకోండి.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1621, 406, 34, 'ക്ഷമ ചോദിച്ച്, ഇവ സ്റ്റാൻഡേർഡ് ഫിനാൻസ് ചാർജുകളാണെന്നും ഫിനാൻസർ തീരുമാനിക്കുന്നതാണെന്നും വ്യക്തമാക്കുക.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1622, 406, 34, 'ക്ഷമ ചോദിച്ച്, പ്രോസസ്സിംഗ് ഫീയും സ്റ്റാംപ് ഡ്യൂട്ടിയും നിർബന്ധിത ചാർജുകളാണെന്നും ക്വോട്ടേഷൻ ശരിയാണെന്നും അറിയിക്കുക.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1623, 406, 34, 'മുന്‍പ് വിശദീകരിക്കാത്തതിന് ക്ഷമ ചോദിച്ച് ഓരോ ചാർജിന്റെയും ഉദ്ദേശ്യം വ്യക്തമാക്കുക.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1624, 406, 34, 'ക്ഷമ ചോദിച്ച് ഉപഭോക്താവിന്റെ ആശങ്ക അംഗീകരിച്ച്, ഓരോ ചാർജും വിശദമായി പറഞ്ഞ് പൂർണ്ണമായ സുതാര്യതയ്ക്കുശേഷം വീണ്ടും സമ്മതം നേടുക.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1625, 407, 34, 'ಕ್ಷಮೆ ಕೇಳಿ, ಇವು ಸಾಮಾನ್ಯ ಫೈನಾನ್ಸ್ ಶುಲ್ಕಗಳು ಮತ್ತು ಫೈನಾನ್ಸರ್ ನಿರ್ಧರಿಸುತ್ತಾರೆ ಎಂದು ವಿವರಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1626, 407, 34, 'ಕ್ಷಮೆ ಕೇಳಿ, ಪ್ರಾಸೆಸಿಂಗ್ ಫೀ ಮತ್ತು ಸ್ಟಾಂಪ್ ಡ್ಯೂಟಿ ಕಡ್ಡಾಯ ಶುಲ್ಕಗಳು ಎಂದು ತಿಳಿಸಿ ಮತ್ತು ಕೋಟ್ೇಶನ್ ಸರಿಯಾಗಿದೆ ಎಂದು ಭರವಸೆ ನೀಡಿ.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1627, 407, 34, 'ಮೊದಲು ವಿವರಿಸದಿದ್ದಕ್ಕಾಗಿ ಕ್ಷಮೆ ಕೇಳಿ ಮತ್ತು ಪ್ರತಿಯೊಂದು ಶುಲ್ಕದ ಉದ್ದೇಶವನ್ನು ಸ್ಪಷ್ಟಪಡಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1628, 407, 34, 'ಕ್ಷಮೆ ಕೇಳಿ, ಗ್ರಾಹಕರ ಚಿಂತೆಯನ್ನು ಒಪ್ಪಿಕೊಂಡು, ಪ್ರತಿಯೊಂದು ಶುಲ್ಕವನ್ನು ವಿವರಿಸಿ ಮತ್ತು ಪೂರ್ಣ ಪಾರದರ್ಶಕತೆಯ ನಂತರ ಮತ್ತೆ ಒಪ್ಪಿಗೆ ಪಡೆಯಿರಿ.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1629, 408, 34, 'କ୍ଷମା ମାଗି କହନ୍ତୁ ଯେ ଏହି ସମସ୍ତ ଷ୍ଟାଣ୍ଡାର୍ଡ ଫାଇନାନ୍ସ ଚାର୍ଜ ଓ ଫାଇନାନ୍ସର ନିର୍ଦ୍ଧାରଣ କରନ୍ତି।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1630, 408, 34, 'କ୍ଷମା ମାଗି ଜଣାନ୍ତୁ ଯେ ପ୍ରୋସେସିଂ ଫି ଓ ଷ୍ଟାମ୍ପ ଡ୍ୟୁଟି ଅନିବାର୍ୟ ଚାର୍ଜ ଏବଂ କୋଟେସନ୍ ସଠିକ୍।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1631, 408, 34, 'ପୂର୍ବରୁ ବୁଝାଇ ନଥିବା ପାଇଁ କ୍ଷମା ମାଗି ପ୍ରତ୍ୟେକ ଚାର୍ଜର ଉଦ୍ଦେଶ୍ୟ ସ୍ପଷ୍ଟ କରନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1632, 408, 34, 'କ୍ଷମା ମାଗି ଗ୍ରାହକଙ୍କ ଚିନ୍ତା ସ୍ୱୀକାର କରନ୍ତୁ, ପ୍ରତ୍ୟେକ ଚାର୍ଜର ବିବରଣୀ ଦିଅନ୍ତୁ ଏବଂ ପୂର୍ଣ୍ଣ ପାରଦର୍ଶିତା ପରେ ପୁନଃ ସମ୍ମତି ନିଅନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1633, 409, 35, 'Apologize and inform that foreclosure charges are financer policy', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1634, 409, 35, 'Apologize and explain how foreclosure charges work in the loan', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1635, 409, 35, 'Apologize and explain from the financer’s perspective why foreclosure charges are applicable', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1636, 409, 35, 'Apologize, explain the charges, reassure it’s small versus remaining interest, and clarify the bank applies it to cover lost interest', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1637, 410, 35, 'माफी मांगें और बताएं कि फोरक्लोज़र चार्ज फाइनेंसर की नीति के अनुसार लगते हैं।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1638, 410, 35, 'माफी मांगें और समझाएं कि लोन में फोरक्लोज़र चार्ज कैसे लागू होते हैं।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1639, 410, 35, 'माफी मांगें और फाइनेंसर के नजरिए से समझाएं कि फोरक्लोज़र चार्ज क्यों लगाए जाते हैं।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1640, 410, 35, 'माफी मांगें, चार्ज समझाएं, भरोसा दें कि यह बाकी ब्याज से कम है और बताएं कि बैंक इसे खोए हुए ब्याज की भरपाई के लिए लगाता है।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1641, 411, 35, 'ਮਾਫ਼ੀ ਮੰਗੋ ਅਤੇ ਦੱਸੋ ਕਿ ਫੋਰਕਲੋਜ਼ਰ ਚਾਰਜ ਫਾਇਨੈਂਸਰ ਦੀ ਨੀਤੀ ਅਨੁਸਾਰ ਹੁੰਦੇ ਹਨ।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1642, 411, 35, 'ਮਾਫ਼ੀ ਮੰਗੋ ਅਤੇ ਸਮਝਾਓ ਕਿ ਲੋਨ ਵਿੱਚ ਫੋਰਕਲੋਜ਼ਰ ਚਾਰਜ ਕਿਵੇਂ ਲੱਗਦੇ ਹਨ।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1643, 411, 35, 'ਮਾਫ਼ੀ ਮੰਗੋ ਅਤੇ ਫਾਇਨੈਂਸਰ ਦੇ ਨਜ਼ਰੀਏ ਤੋਂ ਦੱਸੋ ਕਿ ਫੋਰਕਲੋਜ਼ਰ ਚਾਰਜ ਕਿਉਂ ਲਾਗੂ ਹੁੰਦੇ ਹਨ।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1644, 411, 35, 'ਮਾਫ਼ੀ ਮੰਗੋ, ਚਾਰਜ ਸਮਝਾਓ, ਯਕੀਨ ਦਿਵਾਓ ਕਿ ਇਹ ਬਾਕੀ ਬਿਆਜ ਨਾਲੋਂ ਘੱਟ ਹੈ ਅਤੇ ਦੱਸੋ ਕਿ ਬੈਂਕ ਇਹ ਖੋਏ ਬਿਆਜ ਨੂੰ ਕਵਰ ਕਰਨ ਲਈ ਲਗਾਉਂਦਾ ਹੈ।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1645, 412, 35, 'માફી માંગો અને જણાવો કે ફોરક્લોઝર ચાર્જ ફાઇનાન્સરની પોલિસી મુજબ છે।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1646, 412, 35, 'માફી માંગો અને સમજાવો કે લોનમાં ફોરક્લોઝર ચાર્જ કેવી રીતે લાગુ પડે છે।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1647, 412, 35, 'માફી માંગો અને ફાઇનાન્સરના દૃષ્ટિકોણથી સમજાવો કે ફોરક્લોઝર ચાર્જ કેમ લાગુ થાય છે।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1648, 412, 35, 'માફી માંગો, ચાર્જ સમજાવો, ખાતરી આપો કે તે બાકી વ્યાજ કરતા ઓછું છે અને બેંક ગુમ થયેલા વ્યાજ માટે આ ચાર્જ લે છે તે સ્પષ્ટ કરો।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1649, 413, 35, 'माफी मागा आणि सांगा की फोरक्लोजर चार्ज हे फायनान्सरच्या धोरणानुसार असतात।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1650, 413, 35, 'माफी मागा आणि समजवा की कर्जामध्ये फोरक्लोजर चार्ज कसे लागू होतात।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1651, 413, 35, 'माफी मागा आणि फायनान्सरच्या दृष्टीकोनातून समजवा की फोरक्लोजर चार्ज का घेतले जातात।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1652, 413, 35, 'माफी मागा, शुल्क समजवा, ते उरलेल्या व्याजापेक्षा कमी आहे हे आश्वस्त करा आणि बँक हरवलेल्या व्याजासाठी ते आकारते हे स्पष्ट करा।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1653, 414, 35, 'ক্ষমা চেয়ে জানান যে ফোরক্লোজার চার্জ ফাইন্যান্সারের নীতিমালা অনুযায়ী।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1654, 414, 35, 'ক্ষমা চেয়ে ব্যাখ্যা করুন ঋণে ফোরক্লোজার চার্জ কীভাবে প্রযোজ্য হয়।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1655, 414, 35, 'ক্ষমা চেয়ে ফাইন্যান্সারের দৃষ্টিকোণ থেকে ব্যাখ্যা করুন কেন ফোরক্লোজার চার্জ নেওয়া হয়।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1656, 414, 35, 'ক্ষমা চেয়ে চার্জ ব্যাখ্যা করুন, আশ্বস্ত করুন যে এটি বাকি সুদের তুলনায় কম এবং ব্যাংক হারানো সুদ পূরণে এটি নেয়।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1657, 415, 35, 'ক্ষমা বিচাৰি জনাওক যে ফোৰক্লোজাৰ চাৰ্জ ফাইনান্সাৰৰ নীতি অনুসাৰে হয়।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1658, 415, 35, 'ক্ষমা বিচাৰি বুজাওক যে ঋণত ফোৰক্লোজাৰ চাৰ্জ কেনেকৈ প্ৰযোজ্য হয়।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1659, 415, 35, 'ক্ষমা বিচাৰি ফাইনান্সাৰৰ দৃষ্টিভংগীৰ পৰা বুজাওক যে ফোৰক্লোজাৰ চাৰ্জ কিয় লোৱা হয়।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1660, 415, 35, 'ক্ষমা বিচাৰি চাৰ্জ বুজাওক, আশ্বাস দিয়ক যে ই অবশিষ্ট সুদতকৈ কম আৰু বেংকে হেৰোৱা সুদ পূৰণ কৰিবলৈ লয়।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1661, 416, 35, 'மன்னிப்பு கேட்டு, முன்கூட்டியே அடைப்புக் கட்டணம் நிதியாளரின் கொள்கைப்படி இருப்பதை தெரிவிக்கவும்.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1662, 416, 35, 'மன்னிப்பு கேட்டு, கடனில் முன்கூட்டியே அடைப்புக் கட்டணம் எப்படி செயல்படுகிறது என்பதை விளக்கவும்.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1663, 416, 35, 'மன்னிப்பு கேட்டு, நிதியாளரின் பார்வையில் ஏன் முன்கூட்டியே அடைப்புக் கட்டணம் விதிக்கப்படுகிறது என்பதை விளக்கவும்.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1664, 416, 35, 'மன்னிப்பு கேட்டு, கட்டணத்தை விளக்கி, அது மீதமுள்ள வட்டியை விட குறைவானது என்று உறுதி அளித்து, இழந்த வட்டியை ஈடு செய்ய வங்கி இதை வசூலிக்கிறது என்பதை தெரிவிக்கவும்.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1665, 417, 35, 'క్షమాపణ చెప్పి, ఫోర్‌క్లోజర్ ఛార్జీలు ఫైనాన్సర్ పాలసీ ప్రకారం ఉంటాయని చెప్పండి.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1666, 417, 35, 'క్షమాపణ చెప్పి, లోన్‌లో ఫోర్‌క్లోజర్ ఛార్జీలు ఎలా పనిచేస్తాయో వివరించండి.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1667, 417, 35, 'క్షమాపణ చెప్పి, ఫైనాన్సర్ దృష్టిలో ఫోర్‌క్లోజర్ ఛార్జీలు ఎందుకు వర్తిస్తాయో వివరించండి.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1668, 417, 35, 'క్షమాపణ చెప్పి, ఛార్జీలు వివరించి, మిగిలిన వడ్డీతో పోలిస్తే ఇవి తక్కువని భరోసా ఇచ్చి, కోల్పోయిన వడ్డీని కవర్ చేయడానికి బ్యాంక్ వసూలు చేస్తుందని చెప్పండి.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1669, 418, 35, 'ക്ഷമ ചോദിച്ച് ഫോറ്ക്ലോഷർ ചാർജുകൾ ഫിനാൻസറിന്റെ നയപ്രകാരം ആണെന്ന് അറിയിക്കുക.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1670, 418, 35, 'ക്ഷമ ചോദിച്ച് വായ്പയിൽ ഫോറ്ക്ലോഷർ ചാർജുകൾ എങ്ങനെ പ്രവർത്തിക്കുന്നു എന്ന് വിശദീകരിക്കുക.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1671, 418, 35, 'ക്ഷമ ചോദിച്ച് ഫിനാൻസറിന്റെ കാഴ്ചപ്പാടിൽ ഫോറ്ക്ലോഷർ ചാർജുകൾ എന്തുകൊണ്ട് ബാധകമാണെന്ന് വിശദീകരിക്കുക.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1672, 418, 35, 'ക്ഷമ ചോദിച്ച് ചാർജുകൾ വിശദീകരിച്ച്, അത് ശേഷിക്കുന്ന പലിശയേക്കാൾ കുറവാണെന്ന് ഉറപ്പുനൽകി, നഷ്ടപ്പെട്ട പലിശ നികത്താൻ ബാങ്ക് ഇത് ഈടാക്കുന്നതാണെന്ന് വ്യക്തമാക്കുക.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1673, 419, 35, 'ಕ್ಷಮೆ ಕೇಳಿ, ಫೋರ್‌ಕ್ಲೋಸರ್ ಶುಲ್ಕಗಳು ಫೈನಾನ್ಸರ್ ನೀತಿಯ ಪ್ರಕಾರವೆಂದು ತಿಳಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1674, 419, 35, 'ಕ್ಷಮೆ ಕೇಳಿ, ಸಾಲಿನಲ್ಲಿ ಫೋರ್‌ಕ್ಲೋಸರ್ ಶುಲ್ಕಗಳು ಹೇಗೆ ಕಾರ್ಯನಿರ್ವಹಿಸುತ್ತವೆ ಎಂಬುದನ್ನು ವಿವರಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1675, 419, 35, 'ಕ್ಷಮೆ ಕೇಳಿ, ಫೈನಾನ್ಸರ್ ದೃಷ್ಟಿಯಿಂದ ಫೋರ್‌ಕ್ಲೋಸರ್ ಶುಲ್ಕಗಳು ಏಕೆ ಅನ್ವಯಿಸುತ್ತವೆ ಎಂದು ವಿವರಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1676, 419, 35, 'ಕ್ಷಮೆ ಕೇಳಿ, ಶುಲ್ಕಗಳನ್ನು ವಿವರಿಸಿ, ಅದು ಉಳಿದ ಬಡ್ಡಿಗಿಂತ ಕಡಿಮೆ ಎಂದು ಭರವಸೆ ನೀಡಿ ಮತ್ತು ಕಳೆದುಹೋದ ಬಡ್ಡಿಯನ್ನು ಭರಿಸಲು ಬ್ಯಾಂಕ್ ಇದು ವಿಧಿಸುತ್ತದೆ ಎಂದು ತಿಳಿಸಿ.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1677, 420, 35, 'କ୍ଷମା ମାଗି କହନ୍ତୁ ଯେ ଫୋରକ୍ଲୋଜର ଚାର୍ଜ ଫାଇନାନ୍ସରଙ୍କ ନୀତି ଅନୁସାରେ ହୁଏ।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1678, 420, 35, 'କ୍ଷମା ମାଗି ବୁଝାନ୍ତୁ ଯେ ଋଣରେ ଫୋରକ୍ଲୋଜର ଚାର୍ଜ କିପରି ଲାଗୁ ହୁଏ।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1679, 420, 35, 'କ୍ଷମା ମାଗି ଫାଇନାନ୍ସରଙ୍କ ଦୃଷ୍ଟିକୋଣରୁ ବୁଝାନ୍ତୁ ଯେ ଫୋରକ୍ଲୋଜର ଚାର୍ଜ କାହିଁକି ଲାଗୁ ହୁଏ।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1680, 420, 35, 'କ୍ଷମା ମାଗି ଚାର୍ଜ ବୁଝାନ୍ତୁ, ଏହା ଅବଶିଷ୍ଟ ସୁଦଠାରୁ କମ୍ ବୋଲି ଭରସା ଦିଅନ୍ତୁ ଏବଂ ହାରାଇଥିବା ସୁଦ ପୂରଣ ପାଇଁ ବ୍ୟାଙ୍କ ଏହା ନେଇଥାଏ ବୋଲି ସ୍ପଷ୍ଟ କରନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1681, 421, 36, 'Inform the customer NOC timelines depend on the financer and request him to wait for a while', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1682, 421, 36, 'Apologize for the inconvenience and guide the customer on how he can contact the financer', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1683, 421, 36, 'Apologize, check the status with the financer from your end and update the customer once you receive confirmation', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1684, 421, 36, 'Apologize, coordinate with the financer, proactively update the customer and assist until the NOC is received', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1685, 422, 36, 'ग्राहक को बताएं कि NOC की समयसीमा फाइनेंसर पर निर्भर करती है और उनसे थोड़ा इंतजार करने का अनुरोध करें।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1686, 422, 36, 'असुविधा के लिए माफी मांगें और ग्राहक को बताएं कि वह फाइनेंसर से कैसे संपर्क कर सकता है।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1687, 422, 36, 'माफी मांगें, अपनी तरफ से फाइनेंसर से स्टेटस चेक करें और पुष्टि मिलते ही ग्राहक को अपडेट दें।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1688, 422, 36, 'माफी मांगें, फाइनेंसर से समन्वय करें, ग्राहक को नियमित अपडेट दें और NOC मिलने तक पूरी मदद करें।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1689, 423, 36, 'ਗਾਹਕ ਨੂੰ ਦੱਸੋ ਕਿ NOC ਦੀ ਸਮੇਂ-ਸੀਮਾ ਫਾਇਨੈਂਸਰ ‘ਤੇ ਨਿਰਭਰ ਕਰਦੀ ਹੈ ਅਤੇ ਕੁਝ ਸਮਾਂ ਉਡੀਕ ਕਰਨ ਲਈ ਕਹੋ।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1690, 423, 36, 'ਅਸੁਵਿਧਾ ਲਈ ਮਾਫ਼ੀ ਮੰਗੋ ਅਤੇ ਗਾਹਕ ਨੂੰ ਦੱਸੋ ਕਿ ਉਹ ਫਾਇਨੈਂਸਰ ਨਾਲ ਕਿਵੇਂ ਸੰਪਰਕ ਕਰ ਸਕਦਾ ਹੈ।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1691, 423, 36, 'ਮਾਫ਼ੀ ਮੰਗੋ, ਆਪਣੀ ਪਾਸੋਂ ਫਾਇਨੈਂਸਰ ਨਾਲ ਸਟੇਟਸ ਚੈਕ ਕਰੋ ਅਤੇ ਪੁਸ਼ਟੀ ਮਿਲਦੇ ਹੀ ਗਾਹਕ ਨੂੰ ਦੱਸੋ।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1692, 423, 36, 'ਮਾਫ਼ੀ ਮੰਗੋ, ਫਾਇਨੈਂਸਰ ਨਾਲ ਕੋਆਰਡੀਨੇਟ ਕਰੋ, ਗਾਹਕ ਨੂੰ ਨਿਯਮਿਤ ਅਪਡੇਟ ਦਿਓ ਅਤੇ NOC ਮਿਲਣ ਤੱਕ ਮਦਦ ਕਰੋ।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1693, 424, 36, 'ગ્રાહકને કહો કે NOCની સમયરેખા ફાઇનાન્સર પર આધારિત છે અને થોડું રાહ જોવા વિનંતી કરો।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1694, 424, 36, 'અસુવિધા માટે માફી માંગો અને ગ્રાહકને ફાઇનાન્સરનો સંપર્ક કેવી રીતે કરવો તે સમજાવો।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1695, 424, 36, 'માફી માંગો, તમારી તરફથી ફાઇનાન્સર સાથે સ્ટેટસ તપાસો અને પુષ્ટિ મળતાં જ ગ્રાહકને અપડેટ આપો।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1696, 424, 36, 'માફી માંગો, ફાઇનાન્સર સાથે સમન્વય કરો, નિયમિત અપડેટ આપો અને NOC મળ્યા સુધી સંપૂર્ણ સહાય કરો।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1697, 425, 36, 'ग्राहकाला सांगा की NOC ची वेळ फायनान्सरवर अवलंबून असते आणि थोडा वेळ थांबण्याची विनंती करा।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1698, 425, 36, 'असुविधेबद्दल माफी मागा आणि ग्राहकाला फायनान्सरशी कसा संपर्क करावा हे सांगा।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1699, 425, 36, 'माफी मागा, आपल्या बाजूने फायनान्सरकडून स्टेटस तपासा आणि खात्री झाल्यावर ग्राहकाला कळवा।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1700, 425, 36, 'माफी मागा, फायनान्सरशी समन्वय साधा, नियमित अपडेट द्या आणि NOC मिळेपर्यंत मदत करा।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1701, 426, 36, 'গ্রাহককে জানান যে NOC এর সময়সীমা ফাইন্যান্সারের উপর নির্ভর করে এবং কিছু সময় অপেক্ষা করতে বলুন।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1702, 426, 36, 'অসুবিধার জন্য ক্ষমা চেয়ে গ্রাহককে জানান কিভাবে তিনি ফাইন্যান্সারের সাথে যোগাযোগ করতে পারেন।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1703, 426, 36, 'ক্ষমা চেয়ে আপনার পক্ষ থেকে ফাইন্যান্সারের সাথে স্ট্যাটাস যাচাই করুন এবং নিশ্চিত হলে গ্রাহককে জানান।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1704, 426, 36, 'ক্ষমা চেয়ে ফাইন্যান্সারের সাথে সমন্বয় করুন, নিয়মিত আপডেট দিন এবং NOC পাওয়া পর্যন্ত সহায়তা করুন।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1705, 427, 36, 'গ্ৰাহকক জনাওক যে NOC ৰ সময়সীমা ফাইনান্সাৰৰ ওপৰত নিৰ্ভৰ কৰে আৰু কিছু সময় অপেক্ষা কৰিবলৈ কওক।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1706, 427, 36, 'অসুবিধাৰ বাবে ক্ষমা বিচাৰি গ্ৰাহকক বুজাওক কেনেকৈ ফাইনান্সাৰৰ সৈতে যোগাযোগ কৰিব পাৰে।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1707, 427, 36, 'ক্ষমা বিচাৰি আপোনাৰ ফালে ফাইনান্সাৰৰ সৈতে স্টেটাছ চাওক আৰু নিশ্চিত হ\'লে গ্ৰাহকক জনাওক।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1708, 427, 36, 'ক্ষমা বিচাৰি ফাইনান্সাৰৰ সৈতে সমন্বয় কৰক, নিয়মিত আপডেট দিয়ক আৰু NOC পোৱা পৰ্যন্ত সহায় কৰক।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1709, 428, 36, 'NOC காலவரை நிதியாளரின் மீது அமையும் என்பதை வாடிக்கையாளருக்கு தெரிவித்து, சிறிது நேரம் காத்திருக்க சொல்லுங்கள்.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1710, 428, 36, 'சிரமத்திற்கு மன்னிப்பு கேட்டு, நிதியாளரை எப்படி தொடர்பு கொள்வது என்பதை வழிகாட்டுங்கள்.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1711, 428, 36, 'மன்னிப்பு கேட்டு, உங்கள் பக்கம் இருந்து நிதியாளருடன் நிலையை சரிபார்த்து, உறுதி கிடைத்ததும் புதுப்பிக்கவும்.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1712, 428, 36, 'மன்னிப்பு கேட்டு, நிதியாளருடன் ஒத்துழைத்து, নিয়মையான புதுப்பிப்புகளை வழங்கி, NOC கிடைக்கும் வரை உதவுங்கள்.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1713, 429, 36, 'NOC సమయం ఫైనాన్సర్‌పై ఆధారపడి ఉంటుందని కస్టమర్‌కు చెప్పి, కొంత సమయం వేచి ఉండమని అడగండి.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1714, 429, 36, 'అసౌకర్యానికి క్షమాపణ చెప్పి, ఫైనాన్సర్‌ను ఎలా సంప్రదించాలో సూచించండి.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1715, 429, 36, 'క్షమాపణ చెప్పి, మీవైపు నుండి ఫైనాన్సర్‌తో స్టేటస్ చెక్ చేసి, నిర్ధారణ వచ్చిన వెంటనే తెలియజేయండి.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1716, 429, 36, 'క్షమాపణ చెప్పి, ఫైనాన్సర్‌తో సమన్వయం చేసి, రెగ్యులర్ అప్డేట్లు ఇస్తూ, NOC వచ్చే వరకు సహాయం చేయండి.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1717, 430, 36, 'NOC സമയപരിധി ഫിനാൻസറിനെ ആശ്രയിച്ചാണെന്ന് ഉപഭോക്താവിനെ അറിയിച്ച് കുറച്ച് സമയം കാത്തിരിക്കണമെന്ന് പറയുക.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1718, 430, 36, 'അസൗകര്യത്തിന് ക്ഷമ ചോദിച്ച് ഫിനാൻസറെ എങ്ങനെ ബന്ധപ്പെടാമെന്ന് മാർഗനിർദേശം നൽകുക.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1719, 430, 36, 'ക്ഷമ ചോദിച്ച് നിങ്ങളുടെ ഭാഗത്ത് നിന്ന് ഫിനാൻസറുമായി സ്റ്റാറ്റസ് പരിശോധിച്ച് സ്ഥിരീകരണത്തിന് ശേഷം അറിയിക്കുക.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1720, 430, 36, 'ക്ഷമ ചോദിച്ച് ഫിനാൻസറുമായി സഹകരിച്ച് സ്ഥിരമായ അപ്‌ഡേറ്റുകൾ നൽകി NOC ലഭിക്കുന്നതുവരെ സഹായിക്കുക.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1721, 431, 36, 'NOC ಸಮಯ ಫೈನಾನ್ಸರ್ ಮೇಲೆ ಅವಲಂಬಿತವಾಗಿದೆ ಎಂದು ಗ್ರಾಹಕರಿಗೆ ತಿಳಿಸಿ ಮತ್ತು ಸ್ವಲ್ಪ ಸಮಯ ಕಾಯಲು ಕೇಳಿ.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1722, 431, 36, 'ಅಸೌಕರ್ಯಕ್ಕಾಗಿ ಕ್ಷಮೆ ಕೇಳಿ ಮತ್ತು ಫೈನಾನ್ಸರ್ ಅನ್ನು ಹೇಗೆ ಸಂಪರ್ಕಿಸಬೇಕು ಎಂದು ಮಾರ್ಗದರ್ಶನ ನೀಡಿ.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1723, 431, 36, 'ಕ್ಷಮೆ ಕೇಳಿ, ನಿಮ್ಮ ಕಡೆದಿಂದ ಫೈನಾನ್ಸರ್ ಜೊತೆ ಸ್ಥಿತಿ ಪರಿಶೀಲಿಸಿ ಮತ್ತು ದೃಢೀಕರಣ ಬಂದ ಬಳಿಕ ತಿಳಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1724, 431, 36, 'ಕ್ಷಮೆ ಕೇಳಿ, ಫೈನಾನ್ಸರ್ ಜೊತೆ ಸಂಯೋಜನೆ ಮಾಡಿ, ನಿಯಮಿತ ಅಪ್ಡೇಟ್ ನೀಡಿ ಮತ್ತು NOC ಸಿಗುವವರೆಗೆ ಸಹಾಯ ಮಾಡಿ.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1725, 432, 36, 'ଗ୍ରାହକଙ୍କୁ କହନ୍ତୁ ଯେ NOC ସମୟସୀମା ଫାଇନାନ୍ସର ଉପରେ ନିର୍ଭର କରେ ଏବଂ କିଛି ସମୟ ଅପେକ୍ଷା କରିବାକୁ ଅନୁରୋଧ କରନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1726, 432, 36, 'ଅସୁବିଧା ପାଇଁ କ୍ଷମା ମାଗି ଫାଇନାନ୍ସର ସହ କିପରି ଯୋଗାଯୋଗ କରିବେ ବୁଝାନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1727, 432, 36, 'କ୍ଷମା ମାଗି ଆପଣଙ୍କ ପକ୍ଷରୁ ଫାଇନାନ୍ସର ସହ ଷ୍ଟେଟସ୍ ଯାଞ୍ଚ କରନ୍ତୁ ଏବଂ ନିଶ୍ଚିତ ହେଲେ ଅପଡେଟ୍ ଦିଅନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1728, 432, 36, 'କ୍ଷମା ମାଗି ଫାଇନାନ୍ସର ସହ ସମନ୍ୱୟ କରନ୍ତୁ, ନିୟମିତ ଅପଡେଟ୍ ଦିଅନ୍ତୁ ଏବଂ NOC ମିଳିବା ପର୍ଯ୍ୟନ୍ତ ସହଯୋଗ କରନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1729, 433, 37, 'Explain that the final loan approval can differ from the estimate after financer assessment and verification', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1730, 433, 37, 'Apologize and clarify why the sanctioned amount has changed after verification by the financer', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1731, 433, 37, 'Apologize and explain the exact difference between the estimated and sanctioned EMI and loan amount', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1732, 433, 37, 'Apologize, compare the estimated and sanctioned figures, explain the impact on EMI, and guide the customer to proceed confidently', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1733, 434, 37, 'समझाएं कि फाइनेंसर की जांच और सत्यापन के बाद अंतिम लोन अप्रूवल अनुमान से अलग हो सकता है।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1734, 434, 37, 'माफी मांगें और स्पष्ट करें कि फाइनेंसर द्वारा वेरिफिकेशन के बाद स्वीकृत राशि क्यों बदली है।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1735, 434, 37, 'माफी मांगें और अनुमानित व स्वीकृत EMI और लोन राशि के बीच का सही अंतर समझाएं।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1736, 434, 37, 'माफी मांगें, अनुमानित और स्वीकृत आंकड़ों की तुलना करें, EMI पर असर समझाएं और ग्राहक को आत्मविश्वास के साथ आगे बढ़ने के लिए मार्गदर्शन दें।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1737, 435, 37, 'ਸਮਝਾਓ ਕਿ ਫਾਇਨੈਂਸਰ ਦੀ ਜਾਂਚ ਤੋਂ ਬਾਅਦ ਆਖਰੀ ਲੋਨ ਮਨਜ਼ੂਰੀ ਅੰਦਾਜ਼ੇ ਤੋਂ ਵੱਖ ਹੋ ਸਕਦੀ ਹੈ।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1738, 435, 37, 'ਮਾਫ਼ੀ ਮੰਗੋ ਅਤੇ ਦੱਸੋ ਕਿ ਵੈਰੀਫਿਕੇਸ਼ਨ ਤੋਂ ਬਾਅਦ ਮਨਜ਼ੂਰ ਰਕਮ ਕਿਉਂ ਬਦਲੀ ਹੈ।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1739, 435, 37, 'ਮਾਫ਼ੀ ਮੰਗੋ ਅਤੇ ਅੰਦਾਜ਼ੇ ਅਤੇ ਮਨਜ਼ੂਰ ਕੀਤੀ EMI ਅਤੇ ਲੋਨ ਰਕਮ ਵਿਚਕਾਰ ਸਹੀ ਫਰਕ ਸਮਝਾਓ।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1740, 435, 37, 'ਮਾਫ਼ੀ ਮੰਗੋ, ਅੰਦਾਜ਼ੇ ਅਤੇ ਮਨਜ਼ੂਰ ਅੰਕੜਿਆਂ ਦੀ ਤੁਲਨਾ ਕਰੋ, EMI ਤੇ ਅਸਰ ਦੱਸੋ ਅਤੇ ਗਾਹਕ ਨੂੰ ਵਿਸ਼ਵਾਸ ਨਾਲ ਅੱਗੇ ਵਧਣ ਲਈ ਮਾਰਗਦਰਸ਼ਨ ਦਿਓ।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1741, 436, 37, 'સમજાવો કે ફાઇનાન્સરની તપાસ પછી અંતિમ લોન મંજૂરી અંદાજથી અલગ હોઈ શકે છે।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1742, 436, 37, 'માફી માંગો અને સમજાવો કે ચકાસણી પછી મંજૂર રકમ કેમ બદલાઈ છે।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1743, 436, 37, 'માફી માંગો અને અંદાજિત અને મંજૂર EMI તથા લોન રકમ વચ્ચેનો તફાવત સમજાવો।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1744, 436, 37, 'માફી માંગો, બંને આંકડાની તુલના કરો, EMI પર અસર સમજાવો અને વિશ્વાસપૂર્વક આગળ વધવા માર્ગદર્શન આપો।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1745, 437, 37, 'समजवा की फायनान्सरच्या पडताळणीनंतर अंतिम कर्ज मंजुरी अंदाजापेक्षा वेगळी असू शकते।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1746, 437, 37, 'माफी मागा आणि पडताळणीनंतर मंजूर रक्कम का बदलली हे स्पष्ट करा।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1747, 437, 37, 'माफी मागा आणि अंदाजित व मंजूर EMI व कर्ज रकमेतील नेमका फरक समजवा।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1748, 437, 37, 'माफी मागा, दोन्ही आकड्यांची तुलना करा, EMI वर परिणाम समजवा आणि ग्राहकाला आत्मविश्वासाने पुढे जाण्यास मार्गदर्शन करा।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1749, 438, 37, 'ব্যাখ্যা করুন যে ফাইন্যান্সারের যাচাইয়ের পর চূড়ান্ত ঋণ অনুমোদন অনুমানের থেকে আলাদা হতে পারে।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1750, 438, 37, 'ক্ষমা চেয়ে জানান কেন যাচাইয়ের পর অনুমোদিত পরিমাণ পরিবর্তিত হয়েছে।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1751, 438, 37, 'ক্ষমা চেয়ে আনুমানিক ও অনুমোদিত EMI এবং ঋণের পরিমাণের সঠিক পার্থক্য ব্যাখ্যা করুন।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1752, 438, 37, 'ক্ষমা চেয়ে দুই পরিমাণ তুলনা করুন, EMI-তে প্রভাব ব্যাখ্যা করুন এবং গ্রাহককে আত্মবিশ্বাসের সাথে এগোতে সাহায্য করুন।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1753, 439, 37, 'বুজাওক যে ফাইনান্সাৰৰ যাচাইৰ পিছত চূড়ান্ত ঋণ অনুমোদন আন্দাজতকৈ ভিন্ন হব পাৰে।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1754, 439, 37, 'ক্ষমা বিচাৰি জনাওক কিয় যাচাইৰ পিছত অনুমোদিত পৰিমাণ সলনি হৈছে।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1755, 439, 37, 'ক্ষমা বিচাৰি আন্দাজিত আৰু অনুমোদিত EMI আৰু ঋণ পৰিমাণৰ মাজৰ সঠিক পাৰ্থক্য বুজাওক।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1756, 439, 37, 'ক্ষমা বিচাৰি দুয়োটা পৰিমাণ তুলনা কৰক, EMI ৰ প্ৰভাৱ বুজাওক আৰু গ্ৰাহকক আত্মবিশ্বাসে আগবাঢ়িবলৈ সহায় কৰক।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1757, 440, 37, 'நிதியாளரின் சரிபார்ப்புக்குப் பிறகு இறுதி கடன் ஒப்புதல் மதிப்பீட்டிலிருந்து மாறக்கூடும் என்பதை விளக்குங்கள்.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1758, 440, 37, 'மன்னிப்பு கேட்டு, சரிபார்ப்புக்குப் பிறகு ஒப்புதல் தொகை ஏன் மாறியுள்ளது என்பதை விளக்குங்கள்.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1759, 440, 37, 'மன்னிப்பு கேட்டு, மதிப்பீட்டும் ஒப்புதல் பெற்ற EMI மற்றும் கடன் தொகையின் சரியான வித்தியாசத்தை விளக்குங்கள்.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1760, 440, 37, 'மன்னிப்பு கேட்டு, இரு தொகைகளையும் ஒப்பிட்டு, EMI மீது தாக்கத்தை விளக்கி, நம்பிக்கையுடன் முன்னேற வழிகாட்டுங்கள்.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1761, 441, 37, 'ఫైనాన్సర్ పరిశీలన తర్వాత తుది లోన్ ఆమోదం అంచనాతో భిన్నంగా ఉండవచ్చని వివరించండి.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1762, 441, 37, 'క్షమాపణ చెప్పి, పరిశీలన తర్వాత ఆమోదించిన మొత్తం ఎందుకు మారిందో వివరించండి.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1763, 441, 37, 'క్షమాపణ చెప్పి, అంచనా మరియు ఆమోదించిన EMI మరియు లోన్ మొత్తాల మధ్య ఖచ్చితమైన తేడాను వివరించండి.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1764, 441, 37, 'క్షమాపణ చెప్పి, రెండు మొత్తాలను పోల్చి, EMIపై ప్రభావాన్ని వివరించి, కస్టమర్‌ను నమ్మకంగా ముందుకు సాగేందుకు మార్గనిర్దేశం చేయండి.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1765, 442, 37, 'ഫിനാൻസറിന്റെ പരിശോധനയ്ക്ക് ശേഷം അന്തിമ വായ്പാ അംഗീകാരം കണക്കിനേക്കാൾ വ്യത്യാസപ്പെട്ടേക്കാമെന്ന് വ്യക്തമാക്കുക.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1766, 442, 37, 'ക്ഷമ ചോദിച്ച് പരിശോധനയ്ക്ക് ശേഷം അംഗീകൃത തുക എന്തുകൊണ്ട് മാറിയെന്ന് വിശദീകരിക്കുക.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1767, 442, 37, 'ക്ഷമ ചോദിച്ച് കണക്കാക്കിയതും അംഗീകൃതവുമായ EMIയും വായ്പാ തുകയും തമ്മിലുള്ള വ്യത്യാസം വിശദീകരിക്കുക.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1768, 442, 37, 'ക്ഷമ ചോദിച്ച് ഇരുവിഭാഗം തുകകളും താരതമ്യം ചെയ്ത് EMI യിൽ ഉണ്ടാകുന്ന സ്വാധീനം വിശദീകരിച്ച് ആത്മവിശ്വാസത്തോടെ മുന്നോട്ട് പോകാൻ മാർഗനിർദേശം നൽകുക.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1769, 443, 37, 'ಫೈನಾನ್ಸರ್ ಪರಿಶೀಲನೆಯ ನಂತರ ಅಂತಿಮ ಸಾಲ ಮಂಜೂರು ಅಂದಾಜಿನಿಂದ ಭಿನ್ನವಾಗಬಹುದು ಎಂದು ವಿವರಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1770, 443, 37, 'ಕ್ಷಮೆ ಕೇಳಿ, ಪರಿಶೀಲನೆಯ ನಂತರ ಮಂಜೂರಾದ ಮೊತ್ತ ಏಕೆ ಬದಲಾಗಿದೆ ಎಂದು ವಿವರಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1771, 443, 37, 'ಕ್ಷಮೆ ಕೇಳಿ, ಅಂದಾಜು ಮತ್ತು ಮಂಜೂರಾದ EMI ಹಾಗೂ ಸಾಲ ಮೊತ್ತದ ನಿಖರ ವ್ಯತ್ಯಾಸವನ್ನು ವಿವರಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1772, 443, 37, 'ಕ್ಷಮೆ ಕೇಳಿ, ಎರಡೂ ಮೊತ್ತಗಳನ್ನು ಹೋಲಿಸಿ, EMI ಮೇಲೆ ಪರಿಣಾಮವನ್ನು ವಿವರಿಸಿ ಮತ್ತು ಗ್ರಾಹಕರಿಗೆ ವಿಶ್ವಾಸದಿಂದ ಮುಂದುವರಿಯಲು ಮಾರ್ಗದರ್ಶನ ನೀಡಿ.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1773, 444, 37, 'ଫାଇନାନ୍ସର ଯାଞ୍ଚ ପରେ ଅନ୍ତିମ ଋଣ ଅନୁମୋଦନ ଅନୁମାନଠାରୁ ଭିନ୍ନ ହୋଇପାରେ ବୋଲି ବୁଝାନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1774, 444, 37, 'କ୍ଷମା ମାଗି ଯାଞ୍ଚ ପରେ ଅନୁମୋଦିତ ରାଶି କାହିଁକି ବଦଳିଛି ବୋଲି ସ୍ପଷ୍ଟ କରନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1775, 444, 37, 'କ୍ଷମା ମାଗି ଅନୁମାନିତ ଏବଂ ଅନୁମୋଦିତ EMI ଓ ଋଣ ରାଶିର ତଫାତ ବୁଝାନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1776, 444, 37, 'କ୍ଷମା ମାଗି ଦୁଇଟି ରାଶିର ତୁଳନା କରନ୍ତୁ, EMI ଉପରେ ପ୍ରଭାବ ବୁଝାନ୍ତୁ ଏବଂ ଗ୍ରାହକଙ୍କୁ ଆତ୍ମବିଶ୍ୱାସ ସହ ଆଗକୁ ବଢ଼ିବାକୁ ସହଯୋଗ କରନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1777, 445, 38, 'Acknowledge the customer’s concern regarding the difference in cost', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1778, 445, 38, 'Acknowledge the concern and explain the marginal cost difference', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1779, 445, 38, 'Acknowledge the concern and highlight the advantages that the customer will receive through dealer finance ', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1780, 445, 38, 'Explain the marginal cost difference but highlight dealership advantages, and assure support at every step', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1781, 446, 38, 'लागत में अंतर को लेकर ग्राहक की चिंता को स्वीकार करें।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1782, 446, 38, 'चिंता स्वीकार करें और मामूली लागत अंतर को समझाएं।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1783, 446, 38, 'चिंता स्वीकार करें और बताएं कि डीलर फाइनेंस के माध्यम से ग्राहक को क्या फायदे मिलेंगे।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1784, 446, 38, 'मामूली लागत अंतर समझाएं, डीलरशिप के फायदे बताएं और हर कदम पर सहयोग का भरोसा दें।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1785, 447, 38, 'ਖਰਚੇ ਦੇ ਫਰਕ ਬਾਰੇ ਗਾਹਕ ਦੀ ਚਿੰਤਾ ਨੂੰ ਮੰਨੋ।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1786, 447, 38, 'ਚਿੰਤਾ ਮੰਨੋ ਅਤੇ ਥੋੜ੍ਹੇ ਖਰਚੇ ਦੇ ਫਰਕ ਨੂੰ ਸਮਝਾਓ।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1787, 447, 38, 'ਚਿੰਤਾ ਮੰਨੋ ਅਤੇ ਦੱਸੋ ਕਿ ਡੀਲਰ ਫਾਇਨੈਂਸ ਰਾਹੀਂ ਗਾਹਕ ਨੂੰ ਕਿਹੜੇ ਫਾਇਦੇ ਮਿਲਣਗੇ।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1788, 447, 38, 'ਥੋੜ੍ਹੇ ਖਰਚੇ ਦਾ ਫਰਕ ਸਮਝਾਓ, ਡੀਲਰਸ਼ਿਪ ਦੇ ਫਾਇਦੇ ਦੱਸੋ ਅਤੇ ਹਰ ਕਦਮ ਤੇ ਸਹਾਇਤਾ ਦਾ ਭਰੋਸਾ ਦਿਓ।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1789, 448, 38, 'ખર્ચના તફાવત અંગે ગ્રાહકની ચિંતા સ્વીકારો।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1790, 448, 38, 'ચિંતા સ્વીકારી અને નાનો ખર્ચ તફાવત સમજાવો।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1791, 448, 38, 'ચિંતા સ્વીકારી અને ડીલર ફાઇનાન્સ દ્વારા મળતા ફાયદા જણાવો।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1792, 448, 38, 'નાનો ખર્ચ તફાવત સમજાવી, ડીલરશિપના ફાયદા બતાવો અને દરેક પગલે સહાયનું આશ્વાસન આપો।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1793, 449, 38, 'खर्चातील फरकाबद्दल ग्राहकाची चिंता मान्य करा।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1794, 449, 38, 'चिंता मान्य करा आणि थोडासा खर्चातील फरक समजवा।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1795, 449, 38, 'चिंता मान्य करा आणि डीलर फायनान्समुळे मिळणारे फायदे सांगा।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1796, 449, 38, 'थोडासा खर्चातील फरक समजवा, डीलरशिपचे फायदे अधोरेखित करा आणि प्रत्येक टप्प्यावर मदतीचे आश्वासन द्या।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1797, 450, 38, 'খরচের পার্থক্য নিয়ে গ্রাহকের উদ্বেগ স্বীকার করুন।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1798, 450, 38, 'উদ্বেগ স্বীকার করে সামান্য খরচের পার্থক্য ব্যাখ্যা করুন।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1799, 450, 38, 'উদ্বেগ স্বীকার করে ডিলার ফাইন্যান্সের মাধ্যমে যে সুবিধা পাবেন তা তুলে ধরুন।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1800, 450, 38, 'সামান্য খরচের পার্থক্য ব্যাখ্যা করে ডিলারশিপের সুবিধা তুলে ধরুন এবং প্রতিটি ধাপে সহায়তার আশ্বাস দিন।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1801, 451, 38, 'খৰচৰ পাৰ্থক্য সম্পৰ্কে গ্ৰাহকৰ চিন্তা স্বীকাৰ কৰক।', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1802, 451, 38, 'চিন্তা স্বীকাৰ কৰি সামান্য খৰচৰ পাৰ্থক্য বুজাওক।', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1803, 451, 38, 'চিন্তা স্বীকাৰ কৰি ডীলাৰ ফাইনান্সৰ জৰিয়তে লাভবোৰ বুজাওক।', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1804, 451, 38, 'সামান্য খৰচৰ পাৰ্থক্য বুজাই ডীলাৰশিপৰ সুবিধাবোৰ উল্লেখ কৰক আৰু প্ৰতিটো ধাপত সহায়ৰ আশ্বাস দিয়ক।', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1805, 452, 38, 'செலவில் உள்ள வேறுபாடு குறித்து வாடிக்கையாளர் கவலைையை ஏற்றுக்கொள்ளுங்கள்.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1806, 452, 38, 'கவலை ஏற்று, சிறிய செலவு வேறுபாட்டை விளக்குங்கள்.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1807, 452, 38, 'கவலை ஏற்று, டீலர் நிதி மூலம் கிடைக்கும் நன்மைகளை விளக்குங்கள்.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1808, 452, 38, 'சிறிய செலவு வேறுபாட்டை விளக்கி, டீலர்ஷிப் நன்மைகளை கூறி, ஒவ்வொரு கட்டத்திலும் ஆதரவு வழங்குவோம் என உறுதி அளிக்கவும்.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1809, 453, 38, 'ఖర్చు తేడాపై కస్టమర్ ఆందోళనను గుర్తించండి.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1810, 453, 38, 'ఆందోళనను గుర్తించి, చిన్న ఖర్చు తేడాను వివరించండి.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1811, 453, 38, 'ఆందోళనను గుర్తించి, డీలర్ ఫైనాన్స్ ద్వారా లభించే ప్రయోజనాలను వివరించండి.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1812, 453, 38, 'చిన్న ఖర్చు తేడాను వివరించి, డీలర్‌షిప్ ప్రయోజనాలను హైలైట్ చేసి, ప్రతి దశలో మద్దతు ఇస్తామని భరోసా ఇవ్వండి.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1813, 454, 38, 'ചെലവിലെ വ്യത്യാസത്തെക്കുറിച്ചുള്ള ഉപഭോക്താവിന്റെ ആശങ്ക അംഗീകരിക്കുക.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1814, 454, 38, 'ആശങ്ക അംഗീകരിച്ച് ചെറിയ ചെലവ് വ്യത്യാസം വിശദീകരിക്കുക.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1815, 454, 38, 'ആശങ്ക അംഗീകരിച്ച് ഡീലർ ഫിനാൻസിലൂടെ ലഭിക്കുന്ന ഗുണങ്ങൾ വിശദീകരിക്കുക.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1816, 454, 38, 'ചെറിയ ചെലവ് വ്യത്യാസം വിശദീകരിച്ച് ഡീലർഷിപ്പ് ഗുണങ്ങൾ വ്യക്തമാക്കുകയും ഓരോ ഘട്ടത്തിലും പിന്തുണ നൽകുമെന്ന് ഉറപ്പ് നൽകുകയും ചെയ്യുക.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
	(1817, 455, 38, 'ಖರ್ಚಿನ ವ್ಯತ್ಯಾಸದ ಬಗ್ಗೆ ಗ್ರಾಹಕರ ಚಿಂತೆಯನ್ನು ಒಪ್ಪಿಕೊಳ್ಳಿ.', NULL, 3, 1, 'Active', '2026-02-27 05:40:40'),
	(1818, 455, 38, 'ಚಿಂತೆಯನ್ನು ಒಪ್ಪಿಕೊಂಡು ಸ್ವಲ್ಪ ಖರ್ಚಿನ ವ್ಯತ್ಯಾಸವನ್ನು ವಿವರಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-27 05:40:40'),
	(1819, 455, 38, 'ಚಿಂತೆಯನ್ನು ಒಪ್ಪಿಕೊಂಡು ಡೀಲರ್ ಫೈನಾನ್ಸ್ ಮೂಲಕ ಸಿಗುವ ಲಾಭಗಳನ್ನು ವಿವರಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-27 05:40:40'),
	(1820, 455, 38, 'ಸ್ವಲ್ಪ ಖರ್ಚಿನ ವ್ಯತ್ಯಾಸವನ್ನು ವಿವರಿಸಿ, ಡೀಲರ್‌ಶಿಪ್ ಲಾಭಗಳನ್ನು ತಿಳಿಸಿ ಮತ್ತು ಪ್ರತಿಯೊಂದು ಹಂತದಲ್ಲೂ ಬೆಂಬಲ ನೀಡುವುದಾಗಿ ಭರವಸೆ ನೀಡಿ.', NULL, 10, 4, 'Active', '2026-02-27 05:40:40'),
