	(2043, 511, 43, 'কওক যে বিজ্ঞাপিত মূল্য ক্ৰেতাৰ চাহিদা আৰু বজাৰৰ অৱস্থাৰ বাবে প্ৰকৃত মূল্যৰ পৰা বেলেগ হ\'ব পাৰে।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2044, 511, 43, 'স্পষ্ট কৰক যে বিজ্ঞাপিত আৰু প্ৰকৃত মূল্য বেলেগ হ\'ব পাৰে, ক্ৰেতাৰ চাহিদাৰ প্ৰভাৱ ব্যাখ্যা কৰক আৰু স্বচ্ছ বিডিং প্ৰক্ৰিয়াক জোৰ দিয়ক।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2045, 512, 43, 'ஆன்லைன் பட்டியலில் கேட்கப்படும் விலை மட்டுமே காட்டப்படுகிறது, அது உண்மையான மறுவிற்பனை விலையிலிருந்து வேறுபடலாம் என்பதை விளக்கவும்.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2046, 512, 43, 'ஆன்லைன் பட்டியலில் கேட்கப்பட்ட விலை இருக்கும், ஆனால் டெண்டரில் சரிபார்க்கப்பட்ட வாங்குபவர்களின் பங்கேற்பின் அடிப்படையில் விலை நிர்ணயிக்கப்படும் என்பதை விளக்கவும்.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2047, 512, 43, 'விளம்பர விலைகள் வாங்குபவர் தேவையும் சந்தை நிலையும் காரணமாக உண்மையான விலையிலிருந்து மாறுபடலாம் என்பதை சொல்லவும்.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2048, 512, 43, 'விளம்பர மற்றும் உண்மையான விலை வேறுபடும் என்பதை தெளிவுபடுத்தி, வாங்குபவர் தேவையின் தாக்கத்தை விளக்கி, வெளிப்படையான டெண்டர் முறையை வலியுறுத்தவும்.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2049, 513, 43, 'ఆన్‌లైన్ లిస్టింగ్‌లో చూపించే ధర కేవలం అడిగే ధర మాత్రమే, ఇది నిజమైన రీసేల్ ధరతో భిన్నంగా ఉండవచ్చు అని వివరించండి.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2050, 513, 43, 'ఆన్‌లైన్ లిస్టింగ్ అడిగే ధరను చూపుతుంది, కానీ టెండర్ ధృవీకరించిన కొనుగోలుదారుల పాల్గొనికపై ఆధారపడి ఉంటుంది అని వివరించండి.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2051, 513, 43, 'ప్రకటనలో చూపిన ధర కొనుగోలుదారుల డిమాండ్ మరియు మార్కెట్ పరిస్థితుల కారణంగా వాస్తవ ధరతో భిన్నంగా ఉండవచ్చు అని చెప్పండి.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2052, 513, 43, 'ప్రకటన ధర మరియు వాస్తవ ధర వేరుగా ఉండవచ్చని స్పష్టంగా చెప్పి, కొనుగోలుదారుల డిమాండ్ ప్రభావాన్ని వివరించి, పారదర్శక టెండర్ ప్రక్రియను బలపరచండి.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2053, 514, 43, 'ഓൺലൈൻ ലിസ്റ്റിംഗിൽ കാണിക്കുന്നത് ആവശ്യപ്പെട്ട വില മാത്രമാണ്, അത് യഥാർത്ഥ റീസേൽ വിലയിൽ നിന്ന് വ്യത്യാസപ്പെടാം എന്ന് വിശദീകരിക്കുക.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2054, 514, 43, 'ഓൺലൈൻ ലിസ്റ്റിംഗ് ആവശ്യപ്പെട്ട വില കാണിക്കും, എന്നാൽ ടെൻഡർ ശരിവെച്ച വാങ്ങുന്നവരുടെ പങ്കാളിത്തത്തെ അടിസ്ഥാനമാക്കിയാണ് എന്ന് വിശദീകരിക്കുക.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2055, 514, 43, 'വിജ്ഞാപന വില വാങ്ങുന്നവരുടെ ആവശ്യവും വിപണി സാഹചര്യവും കാരണം യഥാർത്ഥ വിലയിൽ നിന്ന് വ്യത്യാസപ്പെടാം എന്ന് പറയുക.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2056, 514, 43, 'വിജ്ഞാപന വിലയും യഥാർത്ഥ വിലയും വ്യത്യാസപ്പെടാം എന്ന് വ്യക്തമാക്കി, വാങ്ങുന്നവരുടെ ആവശ്യത്തിന്റെ സ്വാധീനം വിശദീകരിച്ച്, സുതാര്യമായ ടെൻഡർ പ്രക്രിയയെ ശക്തിപ്പെടുത്തുക.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2057, 515, 43, 'ಆನ್‌ಲೈನ್ ಲಿಸ್ಟಿಂಗ್‌ನಲ್ಲಿ ಕೇಳಿದ ಬೆಲೆ ಮಾತ್ರ ತೋರಿಸಲಾಗುತ್ತದೆ, ಅದು ನಿಜವಾದ ರೀಸೇಲ್ ಬೆಲೆಯಿಂದ ಭಿನ್ನವಾಗಿರಬಹುದು ಎಂದು ವಿವರಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2058, 515, 43, 'ಆನ್‌ಲೈನ್ ಲಿಸ್ಟಿಂಗ್ ಕೇಳಿದ ಬೆಲೆಯನ್ನು ತೋರಿಸುತ್ತದೆ, ಆದರೆ ಟೆಂಡರ್ ಪರಿಶೀಲಿತ ಖರೀದಿದಾರರ ಭಾಗವಹಿಸುವಿಕೆಗೆ ಆಧಾರಿತವಾಗಿದೆ ಎಂದು ವಿವರಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2059, 515, 43, 'ಜಾಹೀರಾತು ಬೆಲೆ ಖರೀದಿದಾರರ ಬೇಡಿಕೆ ಮತ್ತು ಮಾರುಕಟ್ಟೆ ಸ್ಥಿತಿಗಳಿಂದ ನಿಜವಾದ ಬೆಲೆಯಿಂದ ಭಿನ್ನವಾಗಿರಬಹುದು ಎಂದು ತಿಳಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2060, 515, 43, 'ಜಾಹೀರಾತು ಬೆಲೆ ಮತ್ತು ನಿಜವಾದ ಬೆಲೆ ವಿಭಿನ್ನವಾಗಬಹುದು ಎಂದು ಸ್ಪಷ್ಟಪಡಿಸಿ, ಖರೀದಿದಾರರ ಬೇಡಿಕೆಯ ಪ್ರಭಾವವನ್ನು ವಿವರಿಸಿ ಮತ್ತು ಪಾರದರ್ಶಕ ಟೆಂಡರ್ ಪ್ರಕ್ರಿಯೆಯನ್ನು ಬಲಪಡಿಸಿ.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2061, 516, 43, 'ଅନଲାଇନ ଲିଷ୍ଟିଂରେ ଦେଖାଯାଉଥିବା ମୂଲ୍ୟ କେବଳ ଚାହିଁଥିବା ମୂଲ୍ୟ, ଯାହା ପ୍ରକୃତ ରିସେଲ ମୂଲ୍ୟରୁ ଭିନ୍ନ ହୋଇପାରେ ବୋଲି ବ୍ୟାଖ୍ୟା କରନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2062, 516, 43, 'ଅନଲାଇନ ଲିଷ୍ଟିଂରେ ଚାହିଁଥିବା ମୂଲ୍ୟ ଦେଖାଯାଏ, କିନ୍ତୁ ଟେଣ୍ଡର ସତ୍ୟାପିତ କ୍ରେତାଙ୍କ ଅଂଶଗ୍ରହଣ ଉପରେ ଆଧାରିତ ଥାଏ ବୋଲି ବ୍ୟାଖ୍ୟା କରନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2063, 516, 43, 'ବିଜ୍ଞାପିତ ମୂଲ୍ୟ କ୍ରେତା ଚାହିଦା ଓ ବଜାର ପରିସ୍ଥିତି କାରଣରୁ ପ୍ରକୃତ ମୂଲ୍ୟରୁ ଭିନ୍ନ ହୋଇପାରେ ବୋଲି କହନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2064, 516, 43, 'ବିଜ୍ଞାପିତ ଓ ପ୍ରକୃତ ମୂଲ୍ୟ ଭିନ୍ନ ହୋଇପାରେ ବୋଲି ସ୍ପଷ୍ଟ କରି, କ୍ରେତା ଚାହିଦାର ପ୍ରଭାବ ବ୍ୟାଖ୍ୟା କରନ୍ତୁ ଏବଂ ପାରଦର୍ଶୀ ଟେଣ୍ଡର ପ୍ରକ୍ରିୟାକୁ ଜୋର ଦିଅନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2065, 517, 44, 'Explain that older vehicles require fitness renewal ', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2066, 517, 44, 'Explain that riding an older vehicle which hasn’t been re-registered can attract fines ', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2067, 517, 44, 'Explain that fitness and  maintenance increase total ownership expenses', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2068, 517, 44, 'Explain that continuing to maintain the old bike will cost close to the EMI of a new vehicle, making upgrading more economical', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2069, 518, 44, 'समझाएँ कि पुरानी गाड़ियों के लिए फिटनेस नवीनीकरण आवश्यक होता है।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2070, 518, 44, 'समझाएँ कि बिना दोबारा रजिस्ट्रेशन कराई गई पुरानी गाड़ी चलाने पर जुर्माना लग सकता है।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2071, 518, 44, 'बताएँ कि फिटनेस और मेंटेनेंस से कुल मालिकाना खर्च बढ़ जाता है।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2072, 518, 44, 'समझाएँ कि पुरानी बाइक को लगातार मेंटेन करने का खर्च नई गाड़ी की EMI के करीब पहुंच सकता है, इसलिए अपग्रेड करना ज्यादा फायदेमंद है।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2073, 519, 44, 'ਸਮਝਾਓ ਕਿ ਪੁਰਾਣੀਆਂ ਗੱਡੀਆਂ ਲਈ ਫਿਟਨੈੱਸ ਨਵੀਨੀਕਰਨ ਲਾਜ਼ਮੀ ਹੁੰਦਾ ਹੈ।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2074, 519, 44, 'ਸਮਝਾਓ ਕਿ ਜੇ ਪੁਰਾਣੀ ਗੱਡੀ ਦਾ ਦੁਬਾਰਾ ਰਜਿਸਟ੍ਰੇਸ਼ਨ ਨਾ ਹੋਵੇ ਤਾਂ ਚਲਾਉਣ \'ਤੇ ਜੁਰਮਾਨਾ ਹੋ ਸਕਦਾ ਹੈ।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2075, 519, 44, 'ਦੱਸੋ ਕਿ ਫਿਟਨੈੱਸ ਅਤੇ ਮੇਨਟੇਨੈਂਸ ਨਾਲ ਕੁੱਲ ਮਾਲਕੀ ਖਰਚ ਵੱਧ ਜਾਂਦਾ ਹੈ।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2076, 519, 44, 'ਸਮਝਾਓ ਕਿ ਪੁਰਾਣੀ ਬਾਈਕ ਦੀ ਦੇਖਭਾਲ ਦਾ ਖਰਚ ਨਵੀਂ ਗੱਡੀ ਦੀ EMI ਦੇ ਨੇੜੇ ਹੋ ਸਕਦਾ ਹੈ, ਇਸ ਲਈ ਅੱਪਗ੍ਰੇਡ ਕਰਨਾ ਜ਼ਿਆਦਾ ਫਾਇਦੇਮੰਦ ਹੈ।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2077, 520, 44, 'સમજાવો કે જૂના વાહનો માટે ફિટનેસ રિન્યુઅલ જરૂરી હોય છે.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2078, 520, 44, 'સમજાવો કે રી-રજીસ્ટ્રેશન વગરનું જૂનું વાહન ચલાવવાથી દંડ લાગી શકે છે.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2079, 520, 44, 'સમજાવો કે ફિટનેસ અને મેન્ટેનન્સ કુલ માલિકીના ખર્ચમાં વધારો કરે છે.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2080, 520, 44, 'સમજાવો કે જૂની બાઈક જાળવવાનો ખર્ચ નવી ગાડીની EMI જેટલો થઈ શકે છે, તેથી અપગ્રેડ કરવું વધુ લાભદાયી છે.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2081, 521, 44, 'समजवा की जुन्या वाहनांसाठी फिटनेस नूतनीकरण आवश्यक असते.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2082, 521, 44, 'समजवा की पुन्हा नोंदणी न केलेले जुने वाहन चालवल्यास दंड होऊ शकतो.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2083, 521, 44, 'सांगा की फिटनेस आणि मेंटेनन्समुळे एकूण मालकी खर्च वाढतो.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2084, 521, 44, 'समजवा की जुन्या बाईकची देखभाल करण्याचा खर्च नवीन वाहनाच्या EMI इतका होऊ शकतो, त्यामुळे अपग्रेड करणे अधिक फायदेशीर आहे.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2085, 522, 44, 'ব্যাখ্যা করুন যে পুরোনো গাড়ির জন্য ফিটনেস নবায়ন প্রয়োজন।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
