	(2137, 535, 45, 'ব্যাখ্যা কৰক যে পৰিদৰ্শনৰ সময়ত যানখনৰ বৰ্তমান দেখা অৱস্থাৰ ভিত্তিত মূল্যায়ন কৰা হৈছে।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2138, 535, 45, 'স্পষ্ট কৰক যে পৰিদৰ্শন মানক CertX নিৰ্দেশিকা অনুসৰি একে ধৰণৰ মূল্যায়নৰ বাবে কৰা হয়।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2139, 535, 45, 'নম্ৰভাৱে লিপিবদ্ধ পৰ্যবেক্ষণ আৰু তাৰ বিডিং মূল্যত সম্ভাৱ্য প্ৰভাৱ ব্যাখ্যা কৰক।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2140, 535, 45, 'পৰিদৰ্শন নিৰ্দেশিকা স্পষ্ট কৰক, লিপিবদ্ধ পৰ্যবেক্ষণ ব্যাখ্যা কৰক আৰু স্বচ্ছ বিডিং প্ৰক্ৰিয়াৰ আশ্বাস দিয়ক।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2141, 536, 45, 'மதிப்பீட்டின் போது வாகனத்தின் தற்போதைய தெரியும் நிலையை அடிப்படையாக கொண்டு ஆய்வு செய்யப்பட்டதாக விளக்கவும்.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2142, 536, 45, 'ஆய்வு நிலையான CertX வழிகாட்டுதல்களின் படி ஒரே மாதிரி மதிப்பீட்டிற்காக செய்யப்படுகிறது என்பதை தெளிவுபடுத்தவும்.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2143, 536, 45, 'பதிவு செய்யப்பட்ட குறிப்புகள் மற்றும் அவை ஏல மதிப்பில் ஏற்படுத்தும் தாக்கத்தை மரியாதையுடன் விளக்கவும்.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2144, 536, 45, 'ஆய்வு வழிகாட்டுதல்களை தெளிவுபடுத்தி, பதிவு செய்யப்பட்ட குறிப்புகளை விளக்கி, வெளிப்படையான ஏல செயல்முறைக்கு நம்பிக்கை அளிக்கவும்.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2145, 537, 45, 'పరిశీలన సమయంలో వాహనం ప్రస్తుతం కనిపిస్తున్న స్థితిని ఆధారంగా తీసుకుని మూల్యాంకనం చేయబడిందని వివరించండి.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2146, 537, 45, 'పరిశీలన ప్రామాణిక CertX మార్గదర్శకాల ప్రకారం సమానమైన మూల్యాంకన కోసం జరుగుతుందని స్పష్టం చేయండి.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2147, 537, 45, 'నమ్రంగా నమోదు చేసిన పరిశీలనలు మరియు అవి బిడ్డింగ్ విలువపై చూపే ప్రభావాన్ని వివరించండి.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2148, 537, 45, 'పరిశీలన మార్గదర్శకాలను స్పష్టం చేసి, నమోదు చేసిన అంశాలను వివరించి, పారదర్శక బిడ్డింగ్ ప్రక్రియకు భరోసా ఇవ్వండి.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2149, 538, 45, 'പരിശോധന സമയത്ത് വാഹനത്തിന്റെ നിലവിലെ കാണുന്ന അവസ്ഥയുടെ അടിസ്ഥാനത്തിലാണ് മൂല്യനിർണ്ണയം നടത്തിയതെന്ന് വിശദീകരിക്കുക.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2150, 538, 45, 'പരിശോധന സ്റ്റാൻഡേർഡ് CertX മാർഗ്ഗനിർദ്ദേശങ്ങൾ പ്രകാരം ഏകീകൃത മൂല്യനിർണ്ണയത്തിനായി നടത്തുന്നതാണെന്ന് വ്യക്തമാക്കുക.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2151, 538, 45, 'രേഖപ്പെടുത്തിയ നിരീക്ഷണങ്ങളും അവ ബിഡ്ഡിംഗ് മൂല്യത്തിൽ ഉണ്ടാക്കുന്ന സാധ്യതാപരമായ സ്വാധീനവും വിനീതമായി വിശദീകരിക്കുക.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2152, 538, 45, 'പരിശോധന മാർഗ്ഗനിർദ്ദേശങ്ങൾ വ്യക്തമാക്കുക, രേഖപ്പെടുത്തിയ നിരീക്ഷണങ്ങൾ വിശദീകരിക്കുക, പരസ്യമായ ബിഡ്ഡിംഗ് പ്രക്രിയയ്ക്ക് ഉറപ്പ് നൽകുക.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2153, 539, 45, 'ಮೌಲ್ಯಮಾಪನದ ವೇಳೆ ವಾಹನದ ಪ್ರಸ್ತುತ ಕಾಣುವ ಸ್ಥಿತಿಯನ್ನು ಆಧರಿಸಿ ಪರಿಶೀಲನೆ ಮಾಡಲಾಗಿದೆ ಎಂದು ವಿವರಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2154, 539, 45, 'ಪರಿಶೀಲನೆ ಮಾನದಂಡ CertX ಮಾರ್ಗಸೂಚಿಗಳ ಪ್ರಕಾರ ಸಮಾನ ಮೌಲ್ಯಮಾಪನಕ್ಕಾಗಿ ನಡೆಯುತ್ತದೆ ಎಂದು ಸ್ಪಷ್ಟಪಡಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2155, 539, 45, 'ದಾಖಲಾದ ಅವಲೋಕನಗಳು ಮತ್ತು ಅವುಗಳ ಬಿಡಿಂಗ್ ಮೌಲ್ಯದ ಮೇಲೆ ಸಾಧ್ಯವಾದ ಪರಿಣಾಮವನ್ನು ವಿನಯದಿಂದ ವಿವರಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2156, 539, 45, 'ಪರಿಶೀಲನಾ ಮಾರ್ಗಸೂಚಿಗಳನ್ನು ಸ್ಪಷ್ಟಪಡಿಸಿ, ದಾಖಲಾದ ಅವಲೋಕನಗಳನ್ನು ವಿವರಿಸಿ ಮತ್ತು ಪಾರದರ್ಶಕ ಬಿಡಿಂಗ್ ಪ್ರಕ್ರಿಯೆಗೆ ಭರವಸೆ ನೀಡಿ.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2157, 540, 45, 'ମୂଲ୍ୟାଙ୍କନ ସମୟରେ ଯାନର ବର୍ତ୍ତମାନ ଦେଖାଯାଉଥିବା ଅବସ୍ଥା ଆଧାରରେ ପରୀକ୍ଷା କରାଯାଇଛି ବୋଲି ବ୍ୟାଖ୍ୟା କରନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2158, 540, 45, 'ପରୀକ୍ଷା ମାନକ CertX ନିର୍ଦ୍ଦେଶିକା ଅନୁଯାୟୀ ସମାନ ମୂଲ୍ୟାଙ୍କନ ପାଇଁ କରାଯାଏ ବୋଲି ସ୍ପଷ୍ଟ କରନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2159, 540, 45, 'ନମ୍ରତାର ସହିତ ରେକର୍ଡ କରାଯାଇଥିବା ଅବଲୋକନ ଓ ତାହାର ବିଡିଂ ମୂଲ୍ୟ ଉପରେ ପ୍ରଭାବ ବ୍ୟାଖ୍ୟା କରନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2160, 540, 45, 'ପରୀକ୍ଷା ନିର୍ଦ୍ଦେଶିକା ସ୍ପଷ୍ଟ କରନ୍ତୁ, ରେକର୍ଡ ଅବଲୋକନ ବ୍ୟାଖ୍ୟା କରନ୍ତୁ ଏବଂ ପାରଦର୍ଶୀ ବିଡିଂ ପ୍ରକ୍ରିୟାର ଆଶ୍ୱାସନ ଦିଅନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2161, 541, 46, 'Inform the customer that once the highest bid is accepted and documentation completed, the vehicle stands transferred under the exchange process', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2162, 541, 46, 'Explain that after bid acceptance and documentation completion, ownership and associated responsibility shift as per exchange guidelines', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2163, 541, 46, 'Clarify that once documentation is completed, legal ownership transfers and retaining the vehicle may create financial and insurance exposure', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2164, 541, 46, 'Clarify that post-documentation transfer is binding, and temporary retention may breach compliance norms and create legal and financial exposure', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2165, 542, 46, 'ग्राहक को बताएं कि जैसे ही सबसे ऊँची बोली स्वीकार हो जाती है और दस्तावेज़ पूरे हो जाते हैं, वाहन एक्सचेंज प्रक्रिया के तहत ट्रांसफर हो जाता है।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2166, 542, 46, 'समझाएँ कि बोली स्वीकार होने और दस्तावेज़ पूरे होने के बाद, एक्सचेंज नियमों के अनुसार स्वामित्व और जिम्मेदारी ट्रांसफर हो जाती है।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2167, 542, 46, 'स्पष्ट करें कि दस्तावेज़ पूरे होने के बाद कानूनी स्वामित्व ट्रांसफर हो जाता है और वाहन अपने पास रखने से वित्तीय और बीमा संबंधी जोखिम हो सकता है।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2168, 542, 46, 'स्पष्ट करें कि दस्तावेज़ के बाद ट्रांसफर बाध्यकारी होता है और अस्थायी रूप से वाहन रखना नियमों का उल्लंघन कर सकता है तथा कानूनी और वित्तीय जोखिम पैदा कर सकता है।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2169, 543, 46, 'ਗਾਹਕ ਨੂੰ ਦੱਸੋ ਕਿ ਜਦੋਂ ਸਭ ਤੋਂ ਉੱਚੀ ਬੋਲੀ ਮਨਜ਼ੂਰ ਹੋ ਜਾਂਦੀ ਹੈ ਅਤੇ ਦਸਤਾਵੇਜ਼ ਪੂਰੇ ਹੋ ਜਾਂਦੇ ਹਨ, ਤਾਂ ਵਾਹਨ ਐਕਸਚੇਂਜ ਪ੍ਰਕਿਰਿਆ ਅਧੀਨ ਟ੍ਰਾਂਸਫਰ ਹੋ ਜਾਂਦਾ ਹੈ।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2170, 543, 46, 'ਸਮਝਾਓ ਕਿ ਬੋਲੀ ਮਨਜ਼ੂਰ ਹੋਣ ਅਤੇ ਦਸਤਾਵੇਜ਼ ਪੂਰੇ ਹੋਣ ਤੋਂ ਬਾਅਦ, ਐਕਸਚੇਂਜ ਨਿਯਮਾਂ ਅਨੁਸਾਰ ਮਾਲਕੀ ਅਤੇ ਜ਼ਿੰਮੇਵਾਰੀ ਟ੍ਰਾਂਸਫਰ ਹੋ ਜਾਂਦੀ ਹੈ।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2171, 543, 46, 'ਸਪਸ਼ਟ ਕਰੋ ਕਿ ਦਸਤਾਵੇਜ਼ ਪੂਰੇ ਹੋਣ ਤੋਂ ਬਾਅਦ ਕਾਨੂੰਨੀ ਮਾਲਕੀ ਟ੍ਰਾਂਸਫਰ ਹੋ ਜਾਂਦੀ ਹੈ ਅਤੇ ਵਾਹਨ ਆਪਣੇ ਕੋਲ ਰੱਖਣ ਨਾਲ ਵਿੱਤੀ ਅਤੇ ਬੀਮਾ ਜੋਖਮ ਹੋ ਸਕਦਾ ਹੈ।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2172, 543, 46, 'ਸਪਸ਼ਟ ਕਰੋ ਕਿ ਦਸਤਾਵੇਜ਼ ਤੋਂ ਬਾਅਦ ਟ੍ਰਾਂਸਫਰ ਬਾਈਂਡਿੰਗ ਹੁੰਦਾ ਹੈ ਅਤੇ ਅਸਥਾਈ ਰੱਖਣ ਨਾਲ ਨਿਯਮਾਂ ਦੀ ਉਲੰਘਣਾ ਅਤੇ ਕਾਨੂੰਨੀ ਤੇ ਵਿੱਤੀ ਜੋਖਮ ਪੈਦਾ ਹੋ ਸਕਦਾ ਹੈ।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2173, 544, 46, 'ગ્રાહકને જણાવો કે એકવાર સૌથી ઊંચી બોલી સ્વીકારાઈ જાય અને દસ્તાવેજીકરણ પૂર્ણ થાય, વાહન એક્સચેન્જ પ્રક્રિયા હેઠળ ટ્રાન્સફર થઈ જાય છે.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2174, 544, 46, 'સમજાવો કે બોલી સ્વીકાર્યા બાદ અને દસ્તાવેજીકરણ પૂર્ણ થયા પછી, એક્સચેન્જ માર્ગદર્શિકા મુજબ માલિકી અને જવાબદારી ટ્રાન્સફર થાય છે.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2175, 544, 46, 'સ્પષ્ટ કરો કે દસ્તાવેજીકરણ પૂર્ણ થયા પછી કાનૂની માલિકી ટ્રાન્સફર થાય છે અને વાહન રાખવાથી નાણાકીય અને વીમા જોખમ ઊભું થઈ શકે છે.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2176, 544, 46, 'સ્પષ્ટ કરો કે દસ્તાવેજીકરણ પછીનો ટ્રાન્સફર બાઈન્ડિંગ છે અને તાત્કાલિક વાહન રાખવું નિયમોના ભંગ અને કાનૂની-નાણાકીય જોખમ ઊભું કરી શકે છે.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2177, 545, 46, 'ग्राहकाला सांगा की एकदा सर्वाधिक बोली स्वीकारली आणि कागदपत्रे पूर्ण झाली की वाहन एक्सचेंज प्रक्रियेनुसार ट्रान्सफर होते.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2178, 545, 46, 'समजवा की बोली स्वीकारल्यानंतर आणि कागदपत्रे पूर्ण झाल्यावर एक्सचेंज नियमांनुसार मालकी आणि जबाबदारी हस्तांतरित होते.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2179, 545, 46, 'स्पष्ट करा की कागदपत्रे पूर्ण झाल्यानंतर कायदेशीर मालकी हस्तांतरित होते आणि वाहन ठेवणे आर्थिक व विमा जोखीम निर्माण करू शकते.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2180, 545, 46, 'स्पष्ट करा की कागदपत्रांनंतरचा हस्तांतरण बंधनकारक असतो आणि तात्पुरते वाहन ठेवणे नियमांचे उल्लंघन करून कायदेशीर व आर्थिक जोखीम निर्माण करू शकते.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2181, 546, 46, 'গ্রাহককে জানান যে সর্বোচ্চ বিড গ্রহণ এবং ডকুমেন্টেশন সম্পন্ন হলে গাড়িটি এক্সচেঞ্জ প্রক্রিয়ার অধীনে স্থানান্তরিত হয়।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2182, 546, 46, 'ব্যাখ্যা করুন যে বিড গ্রহণ এবং ডকুমেন্টেশন সম্পন্ন হওয়ার পর এক্সচেঞ্জ নির্দেশিকা অনুযায়ী মালিকানা ও দায়িত্ব স্থানান্তরিত হয়।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2183, 546, 46, 'স্পষ্ট করুন যে ডকুমেন্টেশন সম্পন্ন হলে আইনি মালিকানা স্থানান্তরিত হয় এবং গাড়ি রেখে দিলে আর্থিক ও বীমা ঝুঁকি তৈরি হতে পারে।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2184, 546, 46, 'স্পষ্ট করুন যে ডকুমেন্টেশনের পর স্থানান্তর বাধ্যতামূলক এবং অস্থায়ীভাবে গাড়ি রাখা নিয়ম ভঙ্গ করে আইনি ও আর্থিক ঝুঁকি সৃষ্টি করতে পারে।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2185, 547, 46, 'গ্ৰাহকক জনাওক যে সৰ্বোচ্চ বিড গ্ৰহণ আৰু নথিপত্ৰ সম্পূৰ্ণ হ’লে গাড়ী এক্সচেঞ্জ প্ৰক্ৰিয়াত স্থানান্তৰিত হয়।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2186, 547, 46, 'ব্যাখ্যা কৰক যে বিড গ্ৰহণ আৰু নথিপত্ৰ সম্পূৰ্ণ হোৱাৰ পিছত এক্সচেঞ্জ নিৰ্দেশিকা অনুসৰি মালিকানা আৰু দায়িত্ব স্থানান্তৰ হয়।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2187, 547, 46, 'স্পষ্ট কৰক যে নথিপত্ৰ সম্পূৰ্ণ হোৱাৰ পিছত আইনগত মালিকানা স্থানান্তৰ হয় আৰু গাড়ী ৰাখিলে আৰ্থিক আৰু বীমা ঝুঁকি থাকিব পাৰে।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2188, 547, 46, 'স্পষ্ট কৰক যে নথিপত্ৰৰ পিছৰ স্থানান্তৰ বাধ্যতামূলক আৰু অস্থায়ীভাৱে গাড়ী ৰাখিলে আইনগত আৰু আৰ্থিক ঝুঁকি সৃষ্টি হ’ব পাৰে।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2189, 548, 46, 'வாடிக்கையாளருக்கு தெரிவிக்கவும், அதிகபட்ச ஏலம் ஏற்கப்பட்டு ஆவணங்கள் முடிந்ததும், வாகனம் எக்சேஞ்ச் செயல்முறையின் கீழ் மாற்றம் செய்யப்படும்.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2190, 548, 46, 'ஏலம் ஏற்கப்பட்டதும் மற்றும் ஆவணங்கள் முடிந்ததும், எக்சேஞ்ச் விதிமுறைகளின் படி உரிமையும் பொறுப்பும் மாற்றம் செய்யப்படும் என்பதை விளக்கவும்.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2191, 548, 46, 'ஆவணங்கள் முடிந்ததும் சட்டபூர்வ உரிமை மாற்றம் செய்யப்படும் மற்றும் வாகனத்தை வைத்திருப்பது நிதி மற்றும் காப்பீட்டு அபாயத்தை உருவாக்கலாம் என்பதை தெளிவுபடுத்தவும்.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2192, 548, 46, 'ஆவணங்களுக்குப் பின் மாற்றம் கட்டாயமானது மற்றும் தற்காலிகமாக வாகனத்தை வைத்திருப்பது விதிமுறைகளை மீறி சட்ட மற்றும் நிதி அபாயத்தை உருவாக்கலாம் என்பதை தெளிவுபடுத்தவும்.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2193, 549, 46, 'గ్రాహకుడికి తెలియజేయండి, అత్యధిక బిడ్ ఆమోదించబడిన తర్వాత మరియు డాక్యుమెంటేషన్ పూర్తైన తర్వాత వాహనం ఎక్స్చేంజ్ ప్రక్రియలో బదిలీ అవుతుంది.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2194, 549, 46, 'బిడ్ ఆమోదం మరియు డాక్యుమెంటేషన్ పూర్తైన తర్వాత ఎక్స్చేంజ్ మార్గదర్శకాల ప్రకారం యాజమాన్యం మరియు బాధ్యత మారుతాయని వివరించండి.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2195, 549, 46, 'డాక్యుమెంటేషన్ పూర్తైన తర్వాత చట్టపరమైన యాజమాన్యం మారుతుంది మరియు వాహనాన్ని ఉంచుకోవడం వలన ఆర్థిక మరియు బీమా ప్రమాదం ఉండవచ్చని స్పష్టం చేయండి.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2196, 549, 46, 'డాక్యుమెంటేషన్ అనంతర బదిలీ బైండింగ్ అని, తాత్కాలికంగా వాహనాన్ని ఉంచుకోవడం నిబంధనలను ఉల్లంఘించి చట్టపరమైన మరియు ఆర్థిక ప్రమాదం కలిగించవచ్చని స్పష్టం చేయండి.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2197, 550, 46, 'ഉപഭോക്താവിനെ അറിയിക്കുക, ഏറ്റവും ഉയർന്ന ബിഡ് അംഗീകരിച്ച് രേഖകൾ പൂർത്തിയായാൽ വാഹനം എക്സ്ചേഞ്ച് പ്രക്രിയ പ്രകാരം മാറ്റം സംഭവിക്കും.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2198, 550, 46, 'ബിഡ് അംഗീകരിച്ചതും രേഖകൾ പൂർത്തിയായതും കഴിഞ്ഞാൽ എക്സ്ചേഞ്ച് മാർഗ്ഗനിർദ്ദേശങ്ങൾ പ്രകാരം ഉടമസ്ഥതയും ഉത്തരവാദിത്വവും മാറും എന്ന് വിശദീകരിക്കുക.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2199, 550, 46, 'രേഖകൾ പൂർത്തിയായ ശേഷം നിയമപരമായ ഉടമസ്ഥത മാറും, വാഹനം കൈവശം വയ്ക്കുന്നത് സാമ്പത്തികവും ഇൻഷുറൻസ് അപകടവും സൃഷ്ടിക്കാം എന്ന് വ്യക്തമാക്കുക.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2200, 550, 46, 'രേഖകൾക്കுப் ശേഷമുള്ള മാറ്റം ബാധകമാണെന്നും താത്കാലികമായി വാഹനം കൈവശം വയ്ക്കുന്നത് നിയമപരവും സാമ്പത്തികവുമായ അപകടം സൃഷ്ടിക്കാമെന്നും വ്യക്തമാക്കുക.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2201, 551, 46, 'ಗ್ರಾಹಕರಿಗೆ ತಿಳಿಸಿ, ಅತ್ಯಧಿಕ ಬಿಡ್ ಅಂಗೀಕರಿಸಿ ದಾಖಲೆಗಳು ಪೂರ್ಣಗೊಂಡ ನಂತರ ವಾಹನ ಎಕ್ಸ್ಚೇಂಜ್ ಪ್ರಕ್ರಿಯೆಯಲ್ಲಿ ವರ್ಗಾಯಿಸಲಾಗುತ್ತದೆ.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2202, 551, 46, 'ಬಿಡ್ ಅಂಗೀಕಾರ ಮತ್ತು ದಾಖಲೆ ಪೂರ್ಣಗೊಂಡ ನಂತರ ಎಕ್ಸ್ಚೇಂಜ್ ಮಾರ್ಗಸೂಚಿಗಳ ಪ್ರಕಾರ ಮಾಲೀಕತ್ವ ಮತ್ತು ಜವಾಬ್ದಾರಿ ವರ್ಗಾಯುತ್ತದೆ ಎಂದು ವಿವರಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2203, 551, 46, 'ದಾಖಲೆಗಳು ಪೂರ್ಣಗೊಂಡ ನಂತರ ಕಾನೂನುಬದ್ಧ ಮಾಲೀಕತ್ವ ವರ್ಗಾಯುತ್ತದೆ ಮತ್ತು ವಾಹನವನ್ನು ಇಟ್ಟುಕೊಳ್ಳುವುದು ಆರ್ಥಿಕ ಮತ್ತು ವಿಮಾ ಅಪಾಯ ಉಂಟುಮಾಡಬಹುದು ಎಂದು ಸ್ಪಷ್ಟಪಡಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2204, 551, 46, 'ದಾಖಲೆಗಳ ನಂತರದ ವರ್ಗಾವಣೆ ಬಾಧ್ಯತೆಯಾಗಿದೆ ಮತ್ತು ತಾತ್ಕಾಲಿಕವಾಗಿ ವಾಹನ ಇಟ್ಟುಕೊಳ್ಳುವುದು ನಿಯಮ ಉಲ್ಲಂಘನೆ ಹಾಗೂ ಕಾನೂನು ಮತ್ತು ಆರ್ಥಿಕ ಅಪಾಯ ಉಂಟುಮಾಡಬಹುದು ಎಂದು ಸ್ಪಷ್ಟಪಡಿಸಿ.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2205, 552, 46, 'ଗ୍ରାହକଙ୍କୁ କୁହନ୍ତୁ ଯେ ସର୍ବୋଚ୍ଚ ବିଡ୍ ଗ୍ରହଣ ଓ ଡକ୍ୟୁମେଣ୍ଟ ସମ୍ପୂର୍ଣ୍ଣ ହେଲେ ଯାନ ଏକ୍ସଚେଞ୍ଜ ପ୍ରକ୍ରିୟାରେ ସ୍ଥାନାନ୍ତର ହୋଇଯାଏ।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2206, 552, 46, 'ବିଡ୍ ଗ୍ରହଣ ଓ ଡକ୍ୟୁମେଣ୍ଟ ସମ୍ପୂର୍ଣ୍ଣ ହେବା ପରେ ଏକ୍ସଚେଞ୍ଜ ନିୟମାବଳୀ ଅନୁଯାୟୀ ମାଲିକାନା ଓ ଦାୟିତ୍ୱ ସ୍ଥାନାନ୍ତର ହୋଇଥାଏ ବୋଲି ବ୍ୟାଖ୍ୟା କରନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2207, 552, 46, 'ଡକ୍ୟୁମେଣ୍ଟ ସମ୍ପୂର୍ଣ୍ଣ ପରେ ଆଇନଗତ ମାଲିକାନା ସ୍ଥାନାନ୍ତର ହୋଇଥାଏ ଏବଂ ଯାନକୁ ରଖିବାରୁ ଆର୍ଥିକ ଓ ବୀମା ଜୋଖିମ ହୋଇପାରେ ବୋଲି ସ୍ପଷ୍ଟ କରନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2208, 552, 46, 'ଡକ୍ୟୁମେଣ୍ଟ ପରବର୍ତ୍ତୀ ସ୍ଥାନାନ୍ତର ବାଧ୍ୟତାମୂଳକ ଓ ତାତ୍କାଳିକ ରଖିବା ନିୟମ ଉଲ୍ଲଂଘନ ସହ ଆଇନଗତ ଓ ଆର୍ଥିକ ଜୋଖିମ ସୃଷ୍ଟି କରିପାରେ ବୋଲି ସ୍ପଷ୍ଟ କରନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
