	(2213, 554, 47, 'उनकी चिंता को स्वीकार करें और समझाएँ कि कीमत बोली के बाद प्राप्त अंतिम टेंडर परिणाम को दर्शाती है।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2214, 554, 47, 'उनकी चिंता को स्वीकार करें और स्पष्ट करें कि कीमत प्रतिस्पर्धी बाज़ार भागीदारी के आधार पर तय हुई है।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2215, 554, 47, 'उनकी चिंता को स्वीकार करें, प्रतिस्पर्धी बोली प्रक्रिया की तर्क समझाएँ और बाज़ार आधारित मूल्य निर्धारण स्पष्ट करें।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2216, 554, 47, 'उनकी चिंता को स्वीकार करें, प्रतिस्पर्धी बोली प्रक्रिया समझाएँ, बाज़ार आधारित मूल्य स्पष्ट करें और कीमत में पारदर्शिता का भरोसा दें।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2217, 555, 47, 'ਉਸਦੀ ਚਿੰਤਾ ਨੂੰ ਮੰਨੋ ਅਤੇ ਸਮਝਾਓ ਕਿ ਕੀਮਤ ਬੋਲੀ ਤੋਂ ਬਾਅਦ ਮਿਲੇ ਅੰਤਿਮ ਟੈਂਡਰ ਨਤੀਜੇ ਨੂੰ ਦਰਸਾਉਂਦੀ ਹੈ।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2218, 555, 47, 'ਉਸਦੀ ਚਿੰਤਾ ਨੂੰ ਮੰਨੋ ਅਤੇ ਸਪਸ਼ਟ ਕਰੋ ਕਿ ਕੀਮਤ ਮੁਕਾਬਲੇ ਵਾਲੀ ਮਾਰਕੀਟ ਭਾਗੀਦਾਰੀ ਦੇ ਆਧਾਰ \'ਤੇ ਹੈ।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2219, 555, 47, 'ਉਸਦੀ ਚਿੰਤਾ ਨੂੰ ਮੰਨੋ, ਮੁਕਾਬਲੇ ਵਾਲੀ ਬੋਲੀ ਦੀ ਪ੍ਰਕਿਰਿਆ ਸਮਝਾਓ ਅਤੇ ਮਾਰਕੀਟ ਅਧਾਰਿਤ ਕੀਮਤ ਨਿਰਧਾਰਨ ਦੱਸੋ।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2220, 555, 47, 'ਉਸਦੀ ਚਿੰਤਾ ਨੂੰ ਮੰਨੋ, ਮੁਕਾਬਲੇ ਵਾਲੀ ਬੋਲੀ ਪ੍ਰਕਿਰਿਆ ਅਤੇ ਮਾਰਕੀਟ ਮੁੱਲ ਸਮਝਾਓ ਅਤੇ ਕੀਮਤ ਵਿੱਚ ਪਾਰਦਰਸ਼ਤਾ ਦਾ ਭਰੋਸਾ ਦਿਓ।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2221, 556, 47, 'તેમની ચિંતા સ્વીકારો અને સમજાવો કે કિંમત બોલી પછી મળેલા અંતિમ ટેન્ડર પરિણામને દર્શાવે છે.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2222, 556, 47, 'તેમની ચિંતા સ્વીકારો અને સ્પષ્ટ કરો કે કિંમત સ્પર્ધાત્મક બજાર ભાગીદારીના આધારે નક્કી થાય છે.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2223, 556, 47, 'તેમની ચિંતા સ્વીકારો, સ્પર્ધાત્મક બોલી પ્રક્રિયા સમજાવો અને બજાર આધારિત કિંમત નક્કી થવાનું સ્પષ્ટ કરો.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2224, 556, 47, 'તેમની ચિંતા સ્વીકારો, સ્પર્ધાત્મક બોલી સમજાવો, બજાર આધારિત મૂલ્ય સ્પષ્ટ કરો અને કિંમતોમાં પારદર્શિતાનો વિશ્વાસ આપો.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2225, 557, 47, 'त्यांची चिंता मान्य करा आणि समजवा की किंमत बोलीनंतर मिळालेल्या अंतिम टेंडर निकालावर आधारित आहे.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
