	(2227, 557, 47, 'त्यांची चिंता मान्य करा, स्पर्धात्मक बोली प्रक्रिया समजवा आणि बाजार आधारित किंमत निर्धारण स्पष्ट करा.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2228, 557, 47, 'त्यांची चिंता मान्य करा, स्पर्धात्मक बोली आणि बाजार मूल्य समजवा आणि किंमतीत पारदर्शकतेचा विश्वास द्या.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2229, 558, 47, 'তার উদ্বেগ স্বীকার করুন এবং ব্যাখ্যা করুন যে মূল্য বিডিংয়ের পর প্রাপ্ত চূড়ান্ত টেন্ডার ফলাফল অনুযায়ী নির্ধারিত হয়েছে।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2230, 558, 47, 'তার উদ্বেগ স্বীকার করুন এবং স্পষ্ট করুন যে মূল্য প্রতিযোগিতামূলক বাজার অংশগ্রহণের ভিত্তিতে নির্ধারিত হয়েছে।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
