	(2232, 558, 47, 'তার উদ্বেগ স্বীকার করুন, প্রতিযোগিতামূলক বিডিং ও বাজারভিত্তিক মূল্য ব্যাখ্যা করুন এবং মূল্যে স্বচ্ছতার আশ্বাস দিন।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2233, 559, 47, 'তেওঁৰ চিন্তা স্বীকাৰ কৰক আৰু ব্যাখ্যা কৰক যে মূল্য বিডিংৰ পিছত পোৱা চূড়ান্ত টেণ্ডাৰ ফলাফল অনুসৰি নির্ধাৰিত।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2234, 559, 47, 'তেওঁৰ চিন্তা স্বীকাৰ কৰক আৰু স্পষ্ট কৰক যে মূল্য প্ৰতিযোগিতামূলক বজাৰ অংশগ্ৰহণৰ ভিত্তিত নিৰ্ধাৰিত।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
