	(2298, 575, 48, 'ಗ್ರಾಹಕರಿಗೆ ಎಕ್ಸ್ಚೇಂಜ್ ಮತ್ತು ಫೈನಾನ್ಸ್ ಆಯ್ಕೆಗಳು ವಿವರಿಸಿ ಮತ್ತು WOT CertX ಮೂಲಕ ವಾಹನವನ್ನು ಮೌಲ್ಯಮಾಪನ ಮಾಡಿ.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2299, 575, 48, 'ಎಕ್ಸ್ಚೇಂಜ್ ಮತ್ತು ಫೈನಾನ್ಸ್ ಆಯ್ಕೆಗಳು ವಿವರಿಸಿ, WOT CertX ಮೂಲಕ ಮೌಲ್ಯಮಾಪನ ಮಾಡಿ ಮತ್ತು ಅನ್ವಯಿಸುವ ಎಕ್ಸ್ಚೇಂಜ್ ಲಾಭಗಳನ್ನು રજૂ ಮಾಡಿ.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2300, 575, 48, 'ಎಕ್ಸ್ಚೇಂಜ್ ಮತ್ತು ಫೈನಾನ್ಸ್ ಆಯ್ಕೆಗಳು ವಿವರಿಸಿ, WOT CertX ಮೂಲಕ ಮೌಲ್ಯಮಾಪನ ಮಾಡಿ, ಎಕ್ಸ್ಚೇಂಜ್ ಲಾಭಗಳನ್ನು ತೋರಿಸಿ, ಟೆಸ್ಟ್ ರೈಡ್‌ಗೆ ಪ್ರೋತ್ಸಾಹಿಸಿ ಮತ್ತು ಅಪ್‌ಗ್ರೇಡ್ ವೈಶಿಷ್ಟ್ಯಗಳನ್ನು ಹೈಲೈಟ್ ಮಾಡಿ.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2301, 576, 48, 'ଗ୍ରାହକଙ୍କୁ ଶୋରୁମ୍‌ରେ ଉପଲବ୍ଧ ଏକ୍ସଚେଞ୍ଜ ଓ ଫାଇନାନ୍ସ ବିକଳ୍ପ ବିଷୟରେ ଜଣାନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2302, 576, 48, 'ଗ୍ରାହକଙ୍କୁ ଏକ୍ସଚେଞ୍ଜ ଓ ଫାଇନାନ୍ସ ବିକଳ୍ପ ବ୍ୟାଖ୍ୟା କରନ୍ତୁ ଏବଂ WOT CertX ମାଧ୍ୟମରେ ଯାନର ମୂଲ୍ୟାଙ୍କନ କରନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2303, 576, 48, 'ଏକ୍ସଚେଞ୍ଜ ଓ ଫାଇନାନ୍ସ ବିକଳ୍ପ ବ୍ୟାଖ୍ୟା କରନ୍ତୁ, WOT CertX ଦ୍ୱାରା ମୂଲ୍ୟାଙ୍କନ କରନ୍ତୁ ଏବଂ ଲାଗୁ ଏକ୍ସଚେଞ୍ଜ ଲାଭ ପ୍ରଦର୍ଶନ କରନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2304, 576, 48, 'ଏକ୍ସଚେଞ୍ଜ ଓ ଫାଇନାନ୍ସ ବିକଳ୍ପ ବ୍ୟାଖ୍ୟା କରନ୍ତୁ, WOT CertX ଦ୍ୱାରା ମୂଲ୍ୟାଙ୍କନ କରନ୍ତୁ, ଏକ୍ସଚେଞ୍ଜ ଲାଭ ଦେଖାନ୍ତୁ, ଟେଷ୍ଟ ରାଇଡ୍ ପାଇଁ ପ୍ରୋତ୍ସାହିତ କରନ୍ତୁ ଏବଂ ଅପଗ୍ରେଡ୍ ଫିଚର ହାଇଲାଇଟ କରନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2305, 577, 49, 'Explain that exchange value depends on vehicle condition and evaluation standards, and may vary between dealerships', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2306, 577, 49, 'Explain that exchange pricing depends on condition, documents, demand, and refurbishment cost, and may differ across dealerships', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2307, 577, 49, 'Explain that valuation is based on condition and market factors, justify how the price was derived, and reinforce fair evaluation practices', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2308, 577, 49, 'Offer a transparent re-evaluation, explain the price breakdown clearly, and reinforce that structured pricing ensures fairness and compliance', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2309, 578, 49, 'समझाएँ कि एक्सचेंज वैल्यू वाहन की स्थिति और मूल्यांकन मानकों पर निर्भर करती है और अलग-अलग डीलरशिप पर अलग हो सकती है।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2310, 578, 49, 'समझाएँ कि एक्सचेंज कीमत वाहन की हालत, दस्तावेज़, मांग और रीफर्बिशमेंट लागत पर निर्भर करती है और अलग डीलरशिप में अलग हो सकती है।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2311, 578, 49, 'समझाएँ कि मूल्यांकन वाहन की स्थिति और बाज़ार कारकों पर आधारित है, कीमत कैसे तय हुई यह स्पष्ट करें और निष्पक्ष मूल्यांकन प्रक्रिया का भरोसा दें।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2312, 578, 49, 'पारदर्शी री-इवैल्युएशन का प्रस्ताव दें, कीमत का स्पष्ट ब्रेकअप समझाएँ और बताएं कि संरचित प्राइसिंग निष्पक्षता और नियमों का पालन सुनिश्चित करती है।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2313, 579, 49, 'ਸਮਝਾਓ ਕਿ ਐਕਸਚੇਂਜ ਵੈਲਿਊ ਵਾਹਨ ਦੀ ਹਾਲਤ ਅਤੇ ਮੁਲਾਂਕਣ ਮਿਆਰਾਂ \'ਤੇ ਨਿਰਭਰ ਕਰਦੀ ਹੈ ਅਤੇ ਵੱਖ-ਵੱਖ ਡੀਲਰਸ਼ਿਪਾਂ ਵਿੱਚ ਵੱਖ ਹੋ ਸਕਦੀ ਹੈ।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2314, 579, 49, 'ਸਮਝਾਓ ਕਿ ਐਕਸਚੇਂਜ ਕੀਮਤ ਵਾਹਨ ਦੀ ਹਾਲਤ, ਦਸਤਾਵੇਜ਼, ਮੰਗ ਅਤੇ ਰੀਫਰਬਿਸਮੈਂਟ ਖਰਚ \'ਤੇ ਨਿਰਭਰ ਕਰਦੀ ਹੈ ਅਤੇ ਡੀਲਰਸ਼ਿਪ ਅਨੁਸਾਰ ਵੱਖ ਹੋ ਸਕਦੀ ਹੈ।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2315, 579, 49, 'ਸਮਝਾਓ ਕਿ ਮੁਲਾਂਕਣ ਹਾਲਤ ਅਤੇ ਮਾਰਕੀਟ ਕਾਰਕਾਂ \'ਤੇ ਆਧਾਰਿਤ ਹੈ, ਕੀਮਤ ਕਿਵੇਂ ਨਿਕਲੀ ਇਹ ਦੱਸੋ ਅਤੇ ਨਿਰਪੱਖ ਮੁਲਾਂਕਣ ਦਾ ਭਰੋਸਾ ਦਿਓ।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2316, 579, 49, 'ਪਾਰਦਰਸ਼ੀ ਮੁੜ-ਮੁਲਾਂਕਣ ਦੀ ਪੇਸ਼ਕਸ਼ ਕਰੋ, ਕੀਮਤ ਦਾ ਸਪਸ਼ਟ ਵੇਰਵਾ ਦਿਓ ਅਤੇ ਦੱਸੋ ਕਿ ਸਟਰੱਕਚਰਡ ਪ੍ਰਾਈਸਿੰਗ ਨਿਆਂ ਅਤੇ ਨਿਯਮਾਂ ਦੀ ਪਾਲਣਾ ਯਕੀਨੀ ਬਣਾਉਂਦੀ ਹੈ।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2317, 580, 49, 'સમજાવો કે એક્સચેન્જ વેલ્યુ વાહનની સ્થિતિ અને મૂલ્યાંકન ધોરણો પર આધારિત હોય છે અને અલગ-અલગ ડીલરશિપમાં ફેરફાર થઈ શકે છે.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2318, 580, 49, 'સમજાવો કે એક્સચેન્જ કિંમત વાહનની હાલત, દસ્તાવેજો, માંગ અને રીફર્બિશમેન્ટ ખર્ચ પર આધારિત હોય છે અને અલગ ડીલરશિપમાં અલગ હોઈ શકે છે.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2319, 580, 49, 'સમજાવો કે મૂલ્યાંકન વાહનની સ્થિતિ અને બજાર પરિબળો પર આધારિત છે, કિંમત કેવી રીતે નક્કી થઈ તે સ્પષ્ટ કરો અને ન્યાયસંગત મૂલ્યાંકનનો વિશ્વાસ આપો.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2320, 580, 49, 'પારદર્શક ફરી મૂલ્યાંકન ઓફર કરો, કિંમતનું સ્પષ્ટ બ્રેકઅપ સમજાવો અને જણાવો કે સ્ટ્રક્ચર્ડ પ્રાઇસિંગ ન્યાય અને પાલન સુનિશ્ચિત કરે છે.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2321, 581, 49, 'समजवा की एक्सचेंज मूल्य वाहनाच्या स्थिती आणि मूल्यांकन निकषांवर अवलंबून असते आणि वेगवेगळ्या डीलरशिपमध्ये बदलू शकते.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2322, 581, 49, 'समजवा की एक्सचेंज किंमत वाहनाची स्थिती, कागदपत्रे, मागणी आणि दुरुस्ती खर्चावर अवलंबून असते आणि डीलरशिपनुसार वेगळी असू शकते.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2323, 581, 49, 'समजवा की मूल्यांकन स्थिती आणि बाजार घटकांवर आधारित आहे, किंमत कशी ठरली ते स्पष्ट करा आणि निष्पक्ष मूल्यांकनाचा विश्वास द्या.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2324, 581, 49, 'पारदर्शक पुनर्मूल्यांकनाची ऑफर द्या, किंमतीचे स्पष्ट विभाजन समजवा आणि सांगा की संरचित किंमत प्रणाली न्याय आणि नियमांचे पालन सुनिश्चित करते.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2325, 582, 49, 'ব্যাখ্যা করুন যে এক্সচেঞ্জ মূল্য গাড়ির অবস্থা ও মূল্যায়ন মানদণ্ডের উপর নির্ভর করে এবং ডিলারশিপভেদে পরিবর্তিত হতে পারে।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2326, 582, 49, 'ব্যাখ্যা করুন যে এক্সচেঞ্জ মূল্য গাড়ির অবস্থা, কাগজপত্র, চাহিদা ও সংস্কার খরচের উপর নির্ভর করে এবং বিভিন্ন ডিলারশিপে ভিন্ন হতে পারে।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2327, 582, 49, 'ব্যাখ্যা করুন যে মূল্যায়ন গাড়ির অবস্থা ও বাজার পরিস্থিতির উপর ভিত্তি করে নির্ধারিত হয়েছে, কীভাবে মূল্য নির্ধারণ হয়েছে তা স্পষ্ট করুন এবং ন্যায্য মূল্যায়নের আশ্বাস দিন।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2328, 582, 49, 'স্বচ্ছ পুনর্মূল্যায়নের প্রস্তাব দিন, মূল্যের স্পষ্ট ব্রেকআপ ব্যাখ্যা করুন এবং জানান যে কাঠামোবদ্ধ মূল্য নির্ধারণ ন্যায্যতা ও নিয়ম মেনে চলা নিশ্চিত করে।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2329, 583, 49, 'ব্যাখ্যা কৰক যে এক্সচেঞ্জ মূল্য যানখনৰ অৱস্থা আৰু মূল্যায়ন মানদণ্ডৰ ওপৰত নিৰ্ভৰ কৰে আৰু ডিলাৰশ্বীপভেদে সলনি হ’ব পাৰে।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2330, 583, 49, 'ব্যাখ্যা কৰক যে এক্সচেঞ্জ মূল্য যানখনৰ অৱস্থা, নথিপত্ৰ, চাহিদা আৰু মেরামতি খৰচৰ ওপৰত নিৰ্ভৰ কৰে আৰু ডিলাৰশ্বীপ অনুসৰি ভিন্ন হ’ব পাৰে।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2331, 583, 49, 'ব্যাখ্যা কৰক যে মূল্যায়ন অৱস্থা আৰু বজাৰ কাৰকৰ ওপৰত ভিত্তি কৰি নিৰ্ধাৰিত, মূল্য কেনেকৈ স্থিৰ হ’ল স্পষ্ট কৰক আৰু ন্যায়সংগত মূল্যায়নৰ আশ্বাস দিয়ক।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2332, 583, 49, 'পাৰদৰ্শী পুনৰ-মূল্যায়নৰ প্ৰস্তাৱ আগবঢ়াওক, মূল্যৰ স্পষ্ট বিৱৰণ দিয়ক আৰু কওক যে গঠনমূলক মূল্য নিৰ্ধাৰণ ন্যায় আৰু নিয়ম পালন নিশ্চিত কৰে।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2333, 584, 49, 'வாகனத்தின் நிலை மற்றும் மதிப்பீட்டு தரநிலைகளின் அடிப்படையில் எக்சேஞ்ச் மதிப்பு நிர்ணயிக்கப்படுகிறது மற்றும் டீலர்ஷிப் ஒன்றுக்கு ஒன்று மாறுபடலாம் என்பதை விளக்கவும்.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2334, 584, 49, 'எக்சேஞ்ச் விலை வாகன நிலை, ஆவணங்கள், சந்தை தேவை மற்றும் பழுது செலவு ஆகியவற்றின் அடிப்படையில் மாறுபடலாம் என்பதை விளக்கவும்.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2335, 584, 49, 'மதிப்பீடு வாகன நிலை மற்றும் சந்தை காரணிகளை அடிப்படையாகக் கொண்டது என்பதை விளக்கி, விலை எவ்வாறு நிர்ணயிக்கப்பட்டது என்பதை தெளிவுபடுத்தி, நியாயமான மதிப்பீட்டின் உறுதியை அளிக்கவும்.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2336, 584, 49, 'தெளிவான மறுமதிப்பீட்டை வழங்கி, விலையின் விவரமான பிரிவை விளக்கி, கட்டுப்படுத்தப்பட்ட விலை அமைப்பு நியாயத்தையும் விதிமுறைகளையும் உறுதி செய்கிறது என்பதை வலியுறுத்தவும்.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2337, 585, 49, 'ఎక్స్చేంజ్ విలువ వాహనం స్థితి మరియు మూల్యాంకన ప్రమాణాలపై ఆధారపడి ఉంటుందని, డీలర్‌షిప్‌ల మధ్య మారవచ్చని వివరించండి.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2338, 585, 49, 'ఎక్స్చేంజ్ ధర వాహనం స్థితి, పత్రాలు, డిమాండ్ మరియు మరమ్మత్తు ఖర్చులపై ఆధారపడి ఉంటుందని, డీలర్‌షిప్‌లలో తేడా ఉండవచ్చని వివరించండి.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2339, 585, 49, 'మూల్యాంకనం వాహనం స్థితి మరియు మార్కెట్ కారకాలపై ఆధారపడి ఉందని వివరించి, ధర ఎలా నిర్ణయించబడిందో స్పష్టం చేసి, న్యాయమైన మూల్యాంకనంపై భరోసా ఇవ్వండి.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2340, 585, 49, 'పారదర్శక రీ-ఎవాల్యుయేషన్ ఆఫర్ చేసి, ధర విభజనను స్పష్టంగా వివరించి, నిర్మిత ధర విధానం న్యాయం మరియు అనుసరణను నిర్ధారిస్తుందని చెప్పండి.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2341, 586, 49, 'എക്സ്ചേഞ്ച് മൂല്യം വാഹനത്തിന്റെ അവസ്ഥയും മൂല്യനിർണ്ണയ മാനദണ്ഡങ്ങളും ആശ്രയിച്ചാണ് നിശ്ചയിക്കുന്നത്, ഡീലർഷിപ്പുകൾക്കിടയിൽ വ്യത്യാസപ്പെടാം എന്ന് വിശദീകരിക്കുക.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2342, 586, 49, 'എക്സ്ചേഞ്ച് വില വാഹനത്തിന്റെ അവസ്ഥ, രേഖകൾ, ആവശ്യകത, പുതുക്കൽ ചെലവ് എന്നിവയെ ആശ്രയിച്ചാണ് നിശ്ചയിക്കുന്നത്, ഡീലർഷിപ്പുകൾക്കിടയിൽ വ്യത്യാസപ്പെടാം എന്ന് വിശദീകരിക്കുക.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2343, 586, 49, 'മൂല്യനിർണ്ണയം വാഹന അവസ്ഥയും വിപണി ഘടകങ്ങളും അടിസ്ഥാനമാക്കിയാണെന്ന് വ്യക്തമാക്കുക, വില എങ്ങനെ നിശ്ചയിച്ചതെന്ന് വിശദീകരിക്കുക, ന്യായമായ മൂല്യനിർണ്ണയത്തിന്റെ ഉറപ്പ് നൽകുക.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2344, 586, 49, 'തെളിവുള്ള പുനർമൂല്യനിർണ്ണയം നൽകുക, വിലയുടെ വിശദമായ വിഭജനം വിശദീകരിക്കുക, ഘടനാപരമായ വില നിശ്ചയം ന്യായവും അനുസരണവും ഉറപ്പാക്കുന്നു എന്ന് ഊന്നിപ്പറയുക.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2345, 587, 49, 'ಎಕ್ಸ್ಚೇಂಜ್ ಮೌಲ್ಯವು ವಾಹನದ ಸ್ಥಿತಿ ಮತ್ತು ಮೌಲ್ಯಮಾಪನ ಮಾನದಂಡಗಳ ಮೇಲೆ ಅವಲಂಬಿತವಾಗಿರುತ್ತದೆ ಮತ್ತು ಡೀಲರ್‌ಶಿಪ್‌ಗಳಿಗೆ ಅನುಗುಣವಾಗಿ ಬದಲಾಗಬಹುದು ಎಂದು ವಿವರಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2346, 587, 49, 'ಎಕ್ಸ್ಚೇಂಜ್ ಬೆಲೆ ವಾಹನದ ಸ್ಥಿತಿ, ದಾಖಲೆಗಳು, ಬೇಡಿಕೆ ಮತ್ತು ಮರುಪೂರೈಕೆ ವೆಚ್ಚಗಳ ಮೇಲೆ ಅವಲಂಬಿತವಾಗಿರುತ್ತದೆ ಮತ್ತು ಡೀಲರ್‌ಶಿಪ್‌ಗಳಲ್ಲಿ ಬದಲಾಯಿಸಬಹುದು ಎಂದು ವಿವರಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2347, 587, 49, 'ಮೌಲ್ಯಮಾಪನವು ವಾಹನದ ಸ್ಥಿತಿ ಮತ್ತು ಮಾರುಕಟ್ಟೆ ಅಂಶಗಳ ಆಧಾರದ ಮೇಲೆ ನಿರ್ಧಾರವಾಗಿದ್ದು, ಬೆಲೆ ಹೇಗೆ ನಿರ್ಧರಿಸಲಾಯಿತು ಎಂಬುದನ್ನು ಸ್ಪಷ್ಟಪಡಿಸಿ ಮತ್ತು ನ್ಯಾಯಸಮ್ಮತ ಮೌಲ್ಯಮಾಪನದ ಭರವಸೆ ನೀಡಿ.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2348, 587, 49, 'ಪಾರದರ್ಶಕ ಮರು-ಮೌಲ್ಯಮಾಪನವನ್ನು ಒದಗಿಸಿ, ಬೆಲೆಯ ಸ್ಪಷ್ಟ ವಿಭಜನೆ ವಿವರಿಸಿ ಮತ್ತು ಸಂರಚಿತ ಬೆಲೆ ವ್ಯವಸ್ಥೆ ನ್ಯಾಯ ಮತ್ತು ಅನುಸರಣೆ ಖಚಿತಪಡಿಸುತ್ತದೆ ಎಂದು ತಿಳಿಸಿ.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2349, 588, 49, 'ଏକ୍ସଚେଞ୍ଜ ମୂଲ୍ୟ ଯାନର ଅବସ୍ଥା ଓ ମୂଲ୍ୟାଙ୍କନ ମାନଦଣ୍ଡ ଉପରେ ନିର୍ଭର କରେ ଏବଂ ଡିଲରଶିପ ମଧ୍ୟରେ ଭିନ୍ନ ହୋଇପାରେ ବୋଲି ବ୍ୟାଖ୍ୟା କରନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2350, 588, 49, 'ଏକ୍ସଚେଞ୍ଜ ମୂଲ୍ୟ ଯାନର ଅବସ୍ଥା, ଡକ୍ୟୁମେଣ୍ଟ, ଚାହିଦା ଓ ପୁନର୍ନିର୍ମାଣ ଖର୍ଚ୍ଚ ଉପରେ ନିର୍ଭର କରେ ଏବଂ ଡିଲରଶିପ ଅନୁଯାୟୀ ଭିନ୍ନ ହୋଇପାରେ ବୋଲି ବ୍ୟାଖ୍ୟା କରନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2351, 588, 49, 'ମୂଲ୍ୟାଙ୍କନ ଯାନର ଅବସ୍ଥା ଓ ବଜାର କାରକ ଉପରେ ଆଧାରିତ ବୋଲି ସ୍ପଷ୍ଟ କରନ୍ତୁ, ମୂଲ୍ୟ କିପରି ନିର୍ଦ୍ଧାରିତ ହେଲା ବୁଝାନ୍ତୁ ଏବଂ ନ୍ୟାୟସଂଗତ ମୂଲ୍ୟାଙ୍କନର ଆଶ୍ୱାସନ ଦିଅନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2352, 588, 49, 'ପାରଦର୍ଶୀ ପୁନଃମୂଲ୍ୟାଙ୍କନ ଦିଅନ୍ତୁ, ମୂଲ୍ୟର ସ୍ପଷ୍ଟ ବିଭାଜନ ବୁଝାନ୍ତୁ ଏବଂ ଗଠିତ ମୂଲ୍ୟ ପ୍ରଣାଳୀ ନ୍ୟାୟ ଓ ନିୟମ ପାଳନ ସୁନିଶ୍ଚିତ କରେ ବୋଲି କହନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2353, 589, 50, 'Inform the customer that the newly identified damage affects the vehicle’s valuation based on inspection', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2354, 589, 50, 'Acknowledge the concern and explain that final valuation depends on complete and accurate inspection findings', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2355, 589, 50, 'Explain that valuation reflects vehicle condition at final inspection and demonstrate how the damage affects market value', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2356, 589, 50, 'Demonstrate the identified damage, clarify its impact on resale and refurbishment cost, and objectively justify the revised valuation', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2357, 590, 50, 'कस्टमर को बताएं कि नई पहचानी गई डैमेज के कारण इंस्पेक्शन के आधार पर गाड़ी की वैल्यू पर असर पड़ेगा।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2358, 590, 50, 'कस्टमर की चिंता समझें और बताएं कि फाइनल वैल्यूएशन पूरी और सही इंस्पेक्शन रिपोर्ट पर निर्भर करता है।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2359, 590, 50, 'समझाएँ कि वैल्यूएशन फाइनल इंस्पेक्शन के समय गाड़ी की कंडीशन पर आधारित होता है और बताएं कि यह डैमेज मार्केट वैल्यू को कैसे प्रभावित करता है।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2360, 590, 50, 'पहचानी गई डैमेज दिखाएँ, बताएं कि इसका रीसेल और रिफर्बिशमेंट कॉस्ट पर क्या असर पड़ेगा और निष्पक्ष रूप से संशोधित वैल्यूएशन को सही ठहराएँ।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2361, 591, 50, 'ਕਸਟਮਰ ਨੂੰ ਦੱਸੋ ਕਿ ਨਵੀਂ ਪਛਾਣੀ ਗਈ ਡੈਮੇਜ ਇੰਸਪੈਕਸ਼ਨ ਦੇ ਆਧਾਰ ’ਤੇ ਵਾਹਨ ਦੀ ਕੀਮਤ ’ਤੇ ਅਸਰ ਪਾਂਦੀ ਹੈ।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2362, 591, 50, 'ਕਸਟਮਰ ਦੀ ਚਿੰਤਾ ਸਵੀਕਾਰ ਕਰੋ ਅਤੇ ਦੱਸੋ ਕਿ ਅੰਤਿਮ ਕੀਮਤ ਪੂਰੀ ਅਤੇ ਸਹੀ ਇੰਸਪੈਕਸ਼ਨ ਰਿਪੋਰਟ ’ਤੇ ਨਿਰਭਰ ਕਰਦੀ ਹੈ।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2363, 591, 50, 'ਸਮਝਾਓ ਕਿ ਅੰਤਿਮ ਇੰਸਪੈਕਸ਼ਨ ਵੇਲੇ ਵਾਹਨ ਦੀ ਹਾਲਤ ਅਨੁਸਾਰ ਕੀਮਤ ਤੈਅ ਹੁੰਦੀ ਹੈ ਅਤੇ ਇਹ ਡੈਮੇਜ ਮਾਰਕੀਟ ਵੈਲਯੂ ਨੂੰ ਕਿਵੇਂ ਪ੍ਰਭਾਵਿਤ ਕਰਦੀ ਹੈ।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2364, 591, 50, 'ਪਛਾਣੀ ਗਈ ਡੈਮੇਜ ਦਿਖਾਓ, ਰੀਸੇਲ ਅਤੇ ਰੀਫਰਬਿਸਮੈਂਟ ਖਰਚ ’ਤੇ ਇਸਦਾ ਅਸਰ ਸਮਝਾਓ ਅਤੇ ਸੰਸ਼ੋਧਿਤ ਕੀਮਤ ਨੂੰ ਨਿਰਪੱਖ ਤਰੀਕੇ ਨਾਲ ਜਾਇਜ਼ ਠਹਿਰਾਓ।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2365, 592, 50, 'કસ્ટમરને જણાવો કે નવી ઓળખાયેલી ડેમેજને કારણે ઇન્સ્પેક્શન આધારિત વાહનની વેલ્યુ પર અસર પડે છે.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2366, 592, 50, 'કસ્ટમરની ચિંતા સ્વીકારો અને સમજાવો કે ફાઈનલ વેલ્યુએશન સંપૂર્ણ અને ચોક્કસ ઇન્સ્પેક્શન પર આધારિત હોય છે.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2367, 592, 50, 'સમજાવો કે વેલ્યુએશન ફાઈનલ ઇન્સ્પેક્શન સમયે વાહનની સ્થિતિ દર્શાવે છે અને આ ડેમેજ માર્કેટ વેલ્યુને કેવી રીતે અસર કરે છે.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2368, 592, 50, 'ઓળખાયેલી ડેમેજ બતાવો, રિસેલ અને રિફર્બિશમેન્ટ ખર્ચ પર તેની અસર સમજાવો અને સુધારેલી વેલ્યુએશનને નિષ્પક્ષ રીતે ન્યાય આપો.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2369, 593, 50, 'कस्टमरला सांगा की नव्याने आढळलेल्या डॅमेजमुळे तपासणीनुसार वाहनाच्या किमतीवर परिणाम होतो.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2370, 593, 50, 'कस्टमरची चिंता मान्य करा आणि अंतिम किंमत संपूर्ण व अचूक तपासणीवर अवलंबून असते हे समजवा.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2371, 593, 50, 'अंतिम तपासणीवेळी वाहनाची स्थिती किमतीत प्रतिबिंबित होते आणि या डॅमेजमुळे बाजारमूल्यावर कसा परिणाम होतो ते समजवा.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2372, 593, 50, 'ओळखलेले डॅमेज दाखवा, रीसेल आणि रिफर्बिशमेंट खर्चावर त्याचा परिणाम स्पष्ट करा आणि सुधारित किंमत वस्तुनिष्ठपणे योग्य ठरवा.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2373, 594, 50, 'কাস্টমারকে জানান যে নতুন চিহ্নিত ক্ষতির কারণে পরিদর্শনের ভিত্তিতে গাড়ির মূল্য প্রভাবিত হবে।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2374, 594, 50, 'কাস্টমারের উদ্বেগ স্বীকার করুন এবং ব্যাখ্যা করুন যে চূড়ান্ত মূল্য সম্পূর্ণ ও সঠিক পরিদর্শনের উপর নির্ভর করে।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2375, 594, 50, 'ব্যাখ্যা করুন যে চূড়ান্ত পরিদর্শনের সময় গাড়ির অবস্থা অনুযায়ী মূল্য নির্ধারিত হয় এবং এই ক্ষতি বাজারমূল্যে কীভাবে প্রভাব ফেলে।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2376, 594, 50, 'চিহ্নিত ক্ষতি দেখান, রিসেল ও রিফারবিশমেন্ট খরচে এর প্রভাব বোঝান এবং সংশোধিত মূল্য নিরপেক্ষভাবে যুক্তিযুক্ত করুন।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2377, 595, 50, 'কাষ্টমাৰক জনাওক যে নতুনকৈ চিনাক্ত কৰা ক্ষতিয়ে পৰিদৰ্শনৰ ভিত্তিত বাহনৰ মূল্যত প্ৰভাৱ পেলায়।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2378, 595, 50, 'কাষ্টমাৰৰ চিন্তা স্বীকাৰ কৰক আৰু বুজাওক যে চূড়ান্ত মূল্য সম্পূৰ্ণ আৰু সঠিক পৰিদৰ্শনৰ ওপৰত নিৰ্ভৰ কৰে।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2379, 595, 50, 'বুজাওক যে চূড়ান্ত পৰিদৰ্শনৰ সময়ত বাহনৰ অৱস্থা মূল্যত প্ৰতিফলিত হয় আৰু এই ক্ষতিয়ে বজাৰমূল্যত কেনেকৈ প্ৰভাৱ পেলায়।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2380, 595, 50, 'চিনাক্ত কৰা ক্ষতি দেখুৱাওক, ৰিছেল আৰু ৰিফাৰবিশমেন্ট খৰচত ইয়াৰ প্ৰভাৱ বুজাওক আৰু সংশোধিত মূল্য ন্যায়সঙ্গতভাৱে সঠিক প্ৰমাণ কৰক।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2381, 596, 50, 'புதியதாக கண்டறியப்பட்ட சேதம் ஆய்வின் அடிப்படையில் வாகனத்தின் மதிப்பை பாதிக்கும் என்பதை கஸ்டமருக்கு தெரிவிக்கவும்.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2382, 596, 50, 'கஸ்டமரின் கவலை ஏற்றுக்கொண்டு, இறுதி மதிப்பீடு முழுமையான மற்றும் துல்லியமான ஆய்வின் அடிப்படையில் அமையும் என்பதை விளக்கவும்.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2383, 596, 50, 'இறுதி ஆய்வின் போது வாகனத்தின் நிலை மதிப்பில் பிரதிபலிக்கும் என்றும், இந்த சேதம் சந்தை மதிப்பை எவ்வாறு பாதிக்கிறது என்றும் விளக்கவும்.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2384, 596, 50, 'கண்டறியப்பட்ட சேதத்தை காட்டி, மறுவிற்பனை மற்றும் ரிபர்பிஷ்மென்ட் செலவில் அதன் தாக்கத்தை தெளிவுபடுத்தி, திருத்தப்பட்ட மதிப்பீட்டை நியாயப்படுத்தவும்.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2385, 597, 50, 'కొత్తగా గుర్తించిన నష్టం ఇన్‌స్పెక్షన్ ఆధారంగా వాహన విలువపై ప్రభావం చూపుతుందని కస్టమర్‌కు తెలియజేయండి.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2386, 597, 50, 'కస్టమర్ ఆందోళనను అంగీకరించి, తుది విలువ పూర్తిస్థాయి మరియు ఖచ్చితమైన ఇన్‌స్పెక్షన్‌పై ఆధారపడి ఉంటుందని వివరించండి.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2387, 597, 50, 'తుది ఇన్‌స్పెక్షన్ సమయంలో వాహన స్థితి విలువలో ప్రతిబింబిస్తుందని, ఈ నష్టం మార్కెట్ విలువను ఎలా ప్రభావితం చేస్తుందో వివరించండి.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2388, 597, 50, 'గుర్తించిన నష్టాన్ని చూపించి, రీసేల్ మరియు రిఫర్బిష్ ఖర్చులపై ప్రభావాన్ని వివరించి, సవరించిన విలువను నిష్పక్షపాతంగా సమర్థించండి.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2389, 598, 50, 'പുതുതായി കണ്ടെത്തിയ നാശനഷ്ടം പരിശോധനയുടെ അടിസ്ഥാനത്തിൽ വാഹനത്തിന്റെ മൂല്യത്തെ ബാധിക്കുന്നതായി കസ്റ്റമറോട് അറിയിക്കുക.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2390, 598, 50, 'കസ്റ്റമറുടെ ആശങ്ക അംഗീകരിച്ച്, അന്തിമ മൂല്യനിർണ്ണയം പൂർണ്ണവും കൃത്യവുമായ പരിശോധനയിൽ ആശ്രയിച്ചിരിക്കുന്നു എന്ന് വിശദീകരിക്കുക.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2391, 598, 50, 'അന്തിമ പരിശോധന സമയത്തെ വാഹനത്തിന്റെ നില മൂല്യത്തിൽ പ്രതിഫലിക്കുന്നു എന്നും, ഈ നാശനഷ്ടം വിപണി മൂല്യത്തെ എങ്ങനെ ബാധിക്കുന്നു എന്നും വ്യക്തമാക്കുക.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2392, 598, 50, 'കണ്ടെത്തിയ നാശനഷ്ടം കാണിച്ച്, റീസേൽ/റിഫർബിഷ് ചെലവിൽ അതിന്റെ സ്വാധീനം വ്യക്തമാക്കുകയും തിരുത്തിയ മൂല്യനിർണ്ണയം നിഷ്പക്ഷമായി ന്യായീകരിക്കുകയും ചെയ്യുക.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2393, 599, 50, 'ಹೊಸಾಗಿ ಗುರುತಿಸಿದ ಹಾನಿ ಪರಿಶೀಲನೆಯ ಆಧಾರದ ಮೇಲೆ ವಾಹನದ ಮೌಲ್ಯಕ್ಕೆ ಪರಿಣಾಮ ಬೀರುತ್ತದೆ ಎಂದು ಗ್ರಾಹಕರಿಗೆ ತಿಳಿಸಿ.', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2394, 599, 50, 'ಗ್ರಾಹಕರ ಚಿಂತೆಯನ್ನು ಅಂಗೀಕರಿಸಿ, ಅಂತಿಮ ಮೌಲ್ಯ ಸಂಪೂರ್ಣ ಮತ್ತು ನಿಖರ ಪರಿಶೀಲನೆಗೆ ಅವಲಂಬಿತವಾಗಿದೆ ಎಂದು ವಿವರಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2395, 599, 50, 'ಅಂತಿಮ ಪರಿಶೀಲನೆಯ ಸಮಯದ ವಾಹನದ ಸ್ಥಿತಿ ಮೌಲ್ಯದಲ್ಲಿ ಪ್ರತಿಬಿಂಬಿಸುತ್ತದೆ ಮತ್ತು ಈ ಹಾನಿ ಮಾರುಕಟ್ಟೆ ಮೌಲ್ಯವನ್ನು ಹೇಗೆ ಪ್ರಭಾವಿಸುತ್ತದೆ ಎಂದು ವಿವರಿಸಿ.', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2396, 599, 50, 'ಗುರುತಿಸಿದ ಹಾನಿಯನ್ನು ತೋರಿಸಿ, ಮರುಮಾರಾಟ ಮತ್ತು ಮರುಸಂಸ್ಕರಣ ವೆಚ್ಚದ ಮೇಲೆ ಅದರ ಪರಿಣಾಮವನ್ನು ಸ್ಪಷ್ಟಪಡಿಸಿ ಮತ್ತು ಪರಿಷ್ಕೃತ ಮೌಲ್ಯವನ್ನು ವಸ್ತುನಿಷ್ಠವಾಗಿ ಸಮರ್ಥಿಸಿ.', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2397, 600, 50, 'ନୂତନ ଚିହ୍ନଟ ହୋଇଥିବା କ୍ଷତି ପରୀକ୍ଷଣ ଆଧାରରେ ଗାଡ଼ିର ମୂଲ୍ୟକୁ ପ୍ରଭାବିତ କରେ ବୋଲି କଷ୍ଟମରଙ୍କୁ କୁହନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-27 06:03:51'),
	(2398, 600, 50, 'କଷ୍ଟମରଙ୍କ ଚିନ୍ତା ସ୍ୱୀକାର କରନ୍ତୁ ଏବଂ ଶେଷ ମୂଲ୍ୟ ସମ୍ପୂର୍ଣ୍ଣ ଓ ସଠିକ୍ ପରୀକ୍ଷଣ ଉପରେ ନିର୍ଭର କରେ ବୋଲି ବୁଝାନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-27 06:03:51'),
	(2399, 600, 50, 'ଶେଷ ପରୀକ୍ଷଣ ସମୟରେ ଗାଡ଼ିର ଅବସ୍ଥା ମୂଲ୍ୟରେ ପ୍ରତିଫଳିତ ହୁଏ ଏବଂ ଏହି କ୍ଷତି ବଜାର ମୂଲ୍ୟକୁ କିପରି ପ୍ରଭାବିତ କରେ ବୁଝାନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-27 06:03:51'),
	(2400, 600, 50, 'ଚିହ୍ନଟ ହୋଇଥିବା କ୍ଷତି ଦେଖାନ୍ତୁ, ପୁନଃବିକ୍ରୟ ଓ ରିଫର୍ବିଶମେଣ୍ଟ ଖର୍ଚ୍ଚ ଉପରେ ପ୍ରଭାବ ବୁଝାନ୍ତୁ ଏବଂ ସଂଶୋଧିତ ମୂଲ୍ୟକୁ ନିଷ୍ପକ୍ଷ ଭାବେ ଯୁକ୍ତିସଙ୍ଗତ କରନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-27 06:03:51'),
	(2401, 601, 51, 'Advise the customer to wait while the issue is checked and promise to revert if required', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2402, 601, 51, 'Explain that RC processing may take time and assure the customer that the team is handling it', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2403, 601, 51, 'Take the customer’s details and forward the concern to the concerned department and assure resolution', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2404, 601, 51, 'Show empathy, note the customer’s details, escalate the concern as a priority, and provide a clear response timeline', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2405, 602, 51, 'ग्राहक को कहें कि वह इंतज़ार करे जब तक हम मामले की जांच करते हैं, और ज़रूरत पड़ने पर वापस संपर्क करने का आश्वासन दें।', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2406, 602, 51, 'समझाएँ कि RC प्रोसेस में समय लग सकता है और ग्राहक को आश्वस्त करें कि हमारी टीम इस पर काम कर रही है।', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2407, 602, 51, 'ग्राहक की पूरी जानकारी लें, समस्या को संबंधित विभाग तक पहुँचाएँ और समाधान का आश्वासन दें।', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2408, 602, 51, 'ग्राहक के साथ सहानुभूति दिखाएँ, उसकी जानकारी नोट करें, मामले को प्राथमिकता के साथ आगे बढ़ाएँ और स्पष्ट समयसीमा बताएं कि कब तक समाधान मिलेगा।', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2409, 603, 51, 'ਗਾਹਕ ਨੂੰ ਕਹੋ ਕਿ ਜਾਂਚ ਦੌਰਾਨ ਉਡੀਕ ਕਰੇ ਅਤੇ ਲੋੜ ਪੈਣ ‘ਤੇ ਵਾਪਸ ਸੰਪਰਕ ਕਰਨ ਦਾ ਭਰੋਸਾ ਦਿਓ।', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2410, 603, 51, 'ਸਮਝਾਓ ਕਿ RC ਪ੍ਰੋਸੈਸ ਵਿੱਚ ਸਮਾਂ ਲੱਗ ਸਕਦਾ ਹੈ ਅਤੇ ਗਾਹਕ ਨੂੰ ਭਰੋਸਾ ਦਿਓ ਕਿ ਟੀਮ ਇਸਨੂੰ ਸੰਭਾਲ ਰਹੀ ਹੈ।', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2411, 603, 51, 'ਗਾਹਕ ਦੇ ਵੇਰਵੇ ਲਵੋ, ਮਾਮਲੇ ਨੂੰ ਸੰਬੰਧਿਤ ਵਿਭਾਗ ਨੂੰ ਭੇਜੋ ਅਤੇ ਹੱਲ ਦਾ ਭਰੋਸਾ ਦਿਓ।', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2412, 603, 51, 'ਸਹਾਨੁਭੂਤੀ ਦਿਖਾਓ, ਗਾਹਕ ਦੇ ਵੇਰਵੇ ਨੋਟ ਕਰੋ, ਮਾਮਲੇ ਨੂੰ ਪ੍ਰਾਥਮਿਕਤਾ ਦੇ ਨਾਲ ਅੱਗੇ ਵਧਾਓ ਅਤੇ ਸਪਸ਼ਟ ਜਵਾਬ ਦੀ ਸਮਾਂ-ਸੀਮਾ ਦਿਓ।', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2413, 604, 51, 'ગ્રાહકને કહો કે તપાસ દરમ્યાન રાહ જુએ અને જરૂર પડે તો પાછો સંપર્ક કરવાનો વચન આપો.', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2414, 604, 51, 'સમજાવો કે RC પ્રક્રિયામાં સમય લાગી શકે છે અને ગ્રાહકને વિશ્વાસ આપો કે ટીમ આ મુદ્દે કામ કરી રહી છે.', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2415, 604, 51, 'ગ્રાહકની વિગતો લો, મુદ્દાને સંબંધિત વિભાગને મોકલો અને ઉકેલનો વિશ્વાસ આપો.', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2416, 604, 51, 'સહાનુભૂતિ દર્શાવો, ગ્રાહકની વિગતો નોંધો, મુદ્દાને પ્રાથમિકતા સાથે આગળ વધારો અને સ્પષ્ટ જવાબ માટે સમયરેખા આપો.', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2417, 605, 51, 'ग्राहकाला सांगा की तपासणीदरम्यान थांबावे आणि गरज पडल्यास परत संपर्क करू असे आश्वासन द्या.', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2418, 605, 51, 'समजावून सांगा की RC प्रक्रियेला वेळ लागू शकतो आणि ग्राहकाला आश्वासन द्या की टीम हे हाताळत आहे.', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2419, 605, 51, 'ग्राहकाची माहिती घ्या, संबंधित विभागाकडे तक्रार पाठवा आणि निराकरणाचे आश्वासन द्या.', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2420, 605, 51, 'सहानुभूती दाखवा, ग्राहकाचे तपशील नोंदवा, प्रकरण प्राधान्याने पुढे पाठवा आणि स्पष्ट प्रतिसादाची वेळमर्यादा द्या.', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2421, 606, 51, 'গ্রাহককে বলুন বিষয়টি যাচাই হওয়া পর্যন্ত অপেক্ষা করতে এবং প্রয়োজন হলে পরে যোগাযোগ করবেন।', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2422, 606, 51, 'ব্যাখ্যা করুন যে RC প্রক্রিয়ায় সময় লাগতে পারে এবং গ্রাহককে আশ্বস্ত করুন যে টিম বিষয়টি দেখছে।', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2423, 606, 51, 'গ্রাহকের তথ্য নিন, বিষয়টি সংশ্লিষ্ট বিভাগে পাঠান এবং সমাধানের আশ্বাস দিন।', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2424, 606, 51, 'সহানুভূতি দেখান, গ্রাহকের তথ্য নোট করুন, বিষয়টি অগ্রাধিকার দিয়ে এগিয়ে নিন এবং স্পষ্ট উত্তর দেওয়ার সময়সীমা জানান।', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2425, 607, 51, 'গ্ৰাহকক কওক যে বিষয়টো চাওঁতে অলপ অপেক্ষা কৰক আৰু প্ৰয়োজন হ\'লে পুনৰ যোগাযোগ কৰা হ\'ব বুলি আশ্বাস দিয়ক।', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2426, 607, 51, 'বুজাওক যে RC প্ৰক্ৰিয়াত সময় লাগিব পাৰে আৰু গ্ৰাহকক আশ্বাস দিয়ক যে টীমে বিষয়টো সামাল দিছে।', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2427, 607, 51, 'গ্ৰাহকৰ বিৱৰণ লওক, বিষয়টো সংশ্লিষ্ট বিভাগলৈ পঠিয়াওক আৰু সমাধানৰ আশ্বাস দিয়ক।', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2428, 607, 51, 'সহানুভূতি দেখুৱাওক, গ্ৰাহকৰ বিৱৰণ লিখি ৰাখক, বিষয়টো প্ৰাধান্যভাৱে আগবঢ়াওক আৰু স্পষ্ট উত্তৰৰ সময়সীমা জনাওক।', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2429, 608, 51, 'விஷயம் சரிபார்க்கும் வரை காத்திருக்கச் சொல்லி, தேவையானால் மீண்டும் தொடர்பு கொள்வதாக உறுதி அளிக்கவும்.', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2430, 608, 51, 'RC செயல்முறைக்கு நேரம் ஆகலாம் என்று விளக்கி, குழு இதை கவனித்து வருகிறது என்று வாடிக்கையாளரை உறுதிப்படுத்துங்கள்.', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2431, 608, 51, 'வாடிக்கையாளரின் விவரங்களை பதிவு செய்து, தொடர்புடைய துறைக்கு அனுப்பி தீர்வு அளிப்பதாக உறுதி அளிக்கவும்.', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2432, 608, 51, 'அனுதாபம் காட்டி, வாடிக்கையாளர் விவரங்களை பதிவு செய்து, விஷயத்தை முன்னுரிமையுடன் உயர்த்தி, தெளிவான பதில் அளிக்கும் காலக்கெடுவை வழங்கவும்.', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2433, 609, 51, 'సమస్యను పరిశీలించే వరకు వేచి ఉండమని చెప్పి, అవసరమైతే తిరిగి సంప్రదిస్తామని హామీ ఇవ్వండి.', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2434, 609, 51, 'RC ప్రక్రియకు సమయం పట్టవచ్చని వివరించి, టీమ్ దీనిని నిర్వహిస్తున్నదని కస్టమర్‌కు భరోసా ఇవ్వండి.', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2435, 609, 51, 'కస్టమర్ వివరాలు తీసుకుని, సమస్యను సంబంధిత విభాగానికి పంపించి పరిష్కారం అందిస్తామని హామీ ఇవ్వండి.', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2436, 609, 51, 'సహానుభూతి చూపించి, కస్టమర్ వివరాలు నమోదు చేసి, సమస్యను ప్రాధాన్యతతో ముందుకు తీసుకెళ్లి, స్పష్టమైన స్పందన టైమ్‌లైన్ ఇవ్వండి.', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2437, 610, 51, 'വിഷയം പരിശോധിക്കുന്നതിനിടെ കാത്തിരിക്കണമെന്ന് പറയുകയും ആവശ്യമായാൽ തിരികെ ബന്ധപ്പെടാമെന്ന് ഉറപ്പ് നൽകുകയും ചെയ്യുക.', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2438, 610, 51, 'RC പ്രോസസിന് സമയം എടുക്കാമെന്ന് വിശദീകരിച്ച് ടീം ഇത് കൈകാര്യം ചെയ്യുകയാണെന്ന് ഉപഭോക്താവിനെ ഉറപ്പാക്കുക.', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2439, 610, 51, 'ഉപഭോക്താവിന്റെ വിവരങ്ങൾ എടുത്ത് ബന്ധപ്പെട്ട വിഭാഗത്തിലേക്ക് അയച്ച് പരിഹാരം നൽകുമെന്ന് ഉറപ്പ് നൽകുക.', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2440, 610, 51, 'സഹാനുഭൂതി പ്രകടിപ്പിച്ച്, ഉപഭോക്താവിന്റെ വിവരങ്ങൾ രേഖപ്പെടുത്തി, വിഷയം മുൻഗണനയായി ഉയർത്തി, വ്യക്തമായ മറുപടി സമയപരിധി നൽകുക.', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2441, 611, 51, 'ವಿಷಯವನ್ನು ಪರಿಶೀಲಿಸುವವರೆಗೆ ಕಾಯಲು ಹೇಳಿ ಮತ್ತು ಅಗತ್ಯವಿದ್ದರೆ ಮರಳಿ ಸಂಪರ್ಕಿಸುವುದಾಗಿ ಭರವಸೆ ನೀಡಿ.', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2442, 611, 51, 'RC ಪ್ರಕ್ರಿಯೆಗೆ ಸಮಯ ಬೇಕಾಗಬಹುದು ಎಂದು ವಿವರಿಸಿ, ತಂಡ ಇದನ್ನು ನೋಡಿಕೊಳ್ಳುತ್ತಿದೆ ಎಂದು ಗ್ರಾಹಕರಿಗೆ ಭರವಸೆ ನೀಡಿ.', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2443, 611, 51, 'ಗ್ರಾಹಕರ ವಿವರಗಳನ್ನು ಪಡೆದು ಸಂಬಂಧಿತ ವಿಭಾಗಕ್ಕೆ ಕಳುಹಿಸಿ ಪರಿಹಾರ ನೀಡುವುದಾಗಿ ಭರವಸೆ ನೀಡಿ.', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2444, 611, 51, 'ಸಹಾನುಭೂತಿ ತೋರಿಸಿ, ಗ್ರಾಹಕರ ವಿವರಗಳನ್ನು ದಾಖಲಿಸಿ, ವಿಷಯವನ್ನು ಪ್ರಾಥಮಿಕತೆಯಿಂದ ಮುಂದೂಡಿ ಮತ್ತು ಸ್ಪಷ್ಟ ಪ್ರತಿಕ್ರಿಯೆ ಸಮಯರೇಖೆ ನೀಡಿ.', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2445, 612, 51, 'ବିଷୟଟି ଯାଞ୍ଚ ହେଉଅ ପର୍ଯ୍ୟନ୍ତ ଅପେକ୍ଷା କରିବାକୁ କୁହନ୍ତୁ ଏବଂ ଆବଶ୍ୟକ ହେଲେ ପୁନଃ ସମ୍ପର୍କ କରିବେ ବୋଲି ଆଶ୍ୱାସନ ଦିଅନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2446, 612, 51, 'RC ପ୍ରକ୍ରିୟାରେ ସମୟ ଲାଗିପାରେ ବୋଲି ବୁଝାନ୍ତୁ ଏବଂ ଟିମ୍ ଏହାକୁ ସମ୍ଭାଳୁଛି ବୋଲି ଗ୍ରାହକଙ୍କୁ ଆଶ୍ୱାସନ ଦିଅନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2447, 612, 51, 'ଗ୍ରାହକଙ୍କ ବିବରଣୀ ନେଇ ସମ୍ପର୍କିତ ବିଭାଗକୁ ପଠାନ୍ତୁ ଏବଂ ସମାଧାନର ଆଶ୍ୱାସନ ଦିଅନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2448, 612, 51, 'ସହାନୁଭୂତି ଦେଖାନ୍ତୁ, ଗ୍ରାହକଙ୍କ ବିବରଣୀ ଲେଖନ୍ତୁ, ବିଷୟଟିକୁ ପ୍ରାଥମିକତାରେ ଉଠାନ୍ତୁ ଏବଂ ସ୍ପଷ୍ଟ ପ୍ରତିକ୍ରିୟା ସମୟସୀମା ଦିଅନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2449, 613, 52, 'Inform the customer that delivery timelines may vary and updates will be shared at the earliest ', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2450, 613, 52, 'Record the concern and escalate it to the concerned department for further action', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2451, 613, 52, 'Record the concern and assure the customer that delivery updates will be shared soon', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2452, 613, 52, 'Show empathy, note the booking details, coordinate with the concerned team, and share a clear timeline for delivery confirmation', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2453, 614, 52, 'ग्राहक को बताएं कि डिलीवरी की समय-सीमा बदल सकती है और अपडेट जल्द से जल्द साझा किए जाएंगे।', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
