	(2468, 617, 52, 'सहानुभूती दाखवा, बुकिंगचे तपशील नोंदवा, संबंधित टीमशी समन्वय साधा आणि डिलिव्हरी पुष्टीसाठी स्पष्ट वेळमर्यादा सांगा.', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2469, 618, 52, 'গ্রাহককে জানান যে ডেলিভারির সময়সীমা পরিবর্তিত হতে পারে এবং যত দ্রুত সম্ভব আপডেট জানানো হবে।', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
