	(2471, 618, 52, 'গ্রাহকের উদ্বেগ নথিভুক্ত করুন এবং তাকে আশ্বস্ত করুন যে ডেলিভারি সংক্রান্ত আপডেট শীঘ্রই জানানো হবে।', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2472, 618, 52, 'সহানুভূতি দেখান, বুকিংয়ের তথ্য নোট করুন, সংশ্লিষ্ট টিমের সাথে সমন্বয় করুন এবং ডেলিভারি নিশ্চিতকরণের জন্য স্পষ্ট সময়সীমা জানান।', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2473, 619, 52, 'গ্ৰাহকক জনাওক যে ডেলিভাৰীৰ সময়সীমা সলনি হ\'ব পাৰে আৰু যত সোনকালে সম্ভৱ আপডেট জনোৱা হ\'ব।', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2474, 619, 52, 'গ্ৰাহকৰ উদ্বেগ নথিভুক্ত কৰক আৰু পৰৱৰ্তী ব্যৱস্থাৰ বাবে সংশ্লিষ্ট বিভাগলৈ পঠিয়াওক।', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
