	(2477, 620, 52, 'டெலிவரி காலஅளவு மாறக்கூடும் என்பதை வாடிக்கையாளருக்கு தெரிவித்து, விரைவில் அப்டேட் பகிரப்படும் என்று சொல்லவும்.', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2478, 620, 52, 'வாடிக்கையாளர் கவலைையை பதிவு செய்து, மேலான நடவடிக்கைக்காக தொடர்புடைய துறைக்கு அனுப்பவும்.', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2479, 620, 52, 'வாடிக்கையாளர் கவலைையை பதிவு செய்து, டெலிவரி அப்டேட் விரைவில் பகிரப்படும் என்று உறுதி அளிக்கவும்.', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2480, 620, 52, 'அனுதாபம் காட்டி, முன்பதிவு விவரங்களை பதிவு செய்து, தொடர்புடைய அணியுடன் ஒருங்கிணைத்து, டெலிவரி உறுதிப்படுத்தலுக்கான தெளிவான காலக்கெடுவை பகிரவும்.', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2481, 621, 52, 'డెలివరీ సమయాలు మారవచ్చని కస్టమర్‌కు తెలియజేసి, వీలైనంత త్వరగా అప్డేట్ అందిస్తామని చెప్పండి.', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2482, 621, 52, 'కస్టమర్ సమస్యను నమోదు చేసి, తదుపరి చర్య కోసం సంబంధిత విభాగానికి పంపించండి.', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2483, 621, 52, 'కస్టమర్ సమస్యను నమోదు చేసి, డెలివరీ అప్డేట్లు త్వరలోనే అందిస్తామని భరోసా ఇవ్వండి.', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2484, 621, 52, 'సహానుభూతి చూపించి, బుకింగ్ వివరాలు నమోదు చేసి, సంబంధిత టీమ్‌తో సమన్వయం చేసి, డెలివరీ నిర్ధారణకు స్పష్టమైన టైమ్‌లైన్ ఇవ్వండి.', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
