	(2502, 626, 53, 'ग्राहक की चिंता को स्वीकार करें और समझाएँ कि दिया गया कोटेशन Hero की स्टैंडर्ड प्राइसिंग के अनुसार है।', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2503, 626, 53, 'ग्राहक की चिंता को स्वीकार करें और समझाएँ कि दूसरी डीलरशिप कम कीमत क्यों दे रही हो सकती है।', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
