	(2530, 633, 53, 'కస్టమర్ ఆందోళనను గుర్తించి, ఈ కోటేషన్ స్టాండర్డ్ హీరో ధరల ప్రకారం ఉందని వివరించండి.', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
