	(2540, 635, 53, 'ಸಂಪೂರ್ಣ ಬ್ರೇಕ್‌ಡೌನ್ ನೀಡಿ, ಸ್ಟ್ಯಾಂಡರ್ಡ್ ಬೆಲೆ ವಿವರಿಸಿ, ಇನ್ನೊಂದು ಡೀಲರ್‌ಶಿಪ್ ಕಡಿಮೆ ಬೆಲೆ ನೀಡುವ ಕಾರಣವನ್ನು ಸ್ಪಷ್ಟಪಡಿಸಿ ಮತ್ತು ಪಾರದರ್ಶಕತೆಯಿಂದ ಗ್ರಾಹಕರಿಗೆ ಭರವಸೆ ನೀಡಿ.', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2541, 636, 53, 'ଦାମର ତଫାତ ବିଷୟରେ ଗ୍ରାହକଙ୍କ ଚିନ୍ତାକୁ ସ୍ୱୀକାର କରନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2542, 636, 53, 'ଗ୍ରାହକଙ୍କ ଚିନ୍ତାକୁ ସ୍ୱୀକାର କରନ୍ତୁ ଏବଂ ଏହି କୋଟେସନ୍ ସ୍ଟାଣ୍ଡାର୍ଡ ହିରୋ ଦାମ ଅନୁସାରେ ଅଛି ବୋଲି ବୁଝାନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2543, 636, 53, 'ଗ୍ରାହକଙ୍କ ଚିନ୍ତାକୁ ସ୍ୱୀକାର କରନ୍ତୁ ଏବଂ ଅନ୍ୟ ଡିଲରଶିପ୍ କାହିଁକି କମ ଦାମ ଦେଉଥାଇପାରେ ବୋଲି ବୁଝାନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2544, 636, 53, 'ସମ୍ପୂର୍ଣ୍ଣ ବ୍ରେକଅପ୍ ଦିଅନ୍ତୁ, ସ୍ଟାଣ୍ଡାର୍ଡ ଦାମ ବୁଝାନ୍ତୁ, ଅନ୍ୟ ଡିଲରଶିପ୍ କମ ଦାମ ଦେବାର କାରଣ ସ୍ପଷ୍ଟ କରନ୍ତୁ ଏବଂ ପାରଦର୍ଶିତା ସହିତ ଗ୍ରାହକଙ୍କୁ ଆଶ୍ୱାସନ ଦିଅନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2545, 637, 54, 'Acknowledge the customer’s concern and empathize with the delay', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2546, 637, 54, 'Inform the customer that you will check with the concerned department and provide updates if any', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2547, 637, 54, 'Apologize, promise to prioritize the case and check with the concerned department', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2548, 637, 54, 'Apologize with empathy, escalate the concern as a priority, and promise to revert with a clear timeline', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2549, 638, 54, 'ग्राहक की चिंता को स्वीकार करें और देरी के लिए सहानुभूति जताएँ।', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2550, 638, 54, 'ग्राहक को बताएं कि आप संबंधित विभाग से जांच करेंगे और कोई अपडेट होगा तो साझा करेंगे।', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2551, 638, 54, 'माफी मांगें, मामले को प्राथमिकता देने का आश्वासन दें और संबंधित विभाग से जांच करने का वादा करें।', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2552, 638, 54, 'सहानुभूति के साथ माफी मांगें, मामले को प्राथमिकता के रूप में आगे बढ़ाएं और स्पष्ट समय-सीमा के साथ वापस संपर्क करने का आश्वासन दें।', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2553, 639, 54, 'ਗਾਹਕ ਦੀ ਚਿੰਤਾ ਨੂੰ ਸਵੀਕਾਰ ਕਰੋ ਅਤੇ ਦੇਰੀ ਲਈ ਸਹਾਨੁਭੂਤੀ ਜਤਾਓ。', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2554, 639, 54, 'ਗਾਹਕ ਨੂੰ ਦੱਸੋ ਕਿ ਤੁਸੀਂ ਸੰਬੰਧਿਤ ਵਿਭਾਗ ਨਾਲ ਜਾਂਚ ਕਰੋਗੇ ਅਤੇ ਕੋਈ ਅਪਡੇਟ ਹੋਵੇ ਤਾਂ ਸਾਂਝੀ ਕਰੋਗੇ。', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2555, 639, 54, 'ਮਾਫ਼ੀ ਮੰਗੋ, ਕੇਸ ਨੂੰ ਪ੍ਰਾਥਮਿਕਤਾ ਦੇਣ ਦਾ ਭਰੋਸਾ ਦਿਓ ਅਤੇ ਸੰਬੰਧਿਤ ਵਿਭਾਗ ਨਾਲ ਜਾਂਚ ਕਰੋ。', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2556, 639, 54, 'ਸਹਾਨੁਭੂਤੀ ਨਾਲ ਮਾਫ਼ੀ ਮੰਗੋ, ਮਾਮਲੇ ਨੂੰ ਪ੍ਰਾਥਮਿਕਤਾ ਵਜੋਂ ਅੱਗੇ ਵਧਾਓ ਅਤੇ ਸਪਸ਼ਟ ਸਮਾਂ-ਸੀਮਾ ਨਾਲ ਵਾਪਸ ਸੰਪਰਕ ਕਰਨ ਦਾ ਵਾਅਦਾ ਕਰੋ。', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2557, 640, 54, 'ગ્રાહકની ચિંતા સ્વીકારો અને વિલંબ માટે સહાનુભૂતિ દર્શાવો。', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2558, 640, 54, 'ગ્રાહકને જાણ કરો કે તમે સંબંધિત વિભાગ સાથે તપાસ કરશો અને અપડેટ હોય તો આપશો。', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2559, 640, 54, 'માફી માંગો, કેસને પ્રાથમિકતા આપવાનું વચન આપો અને સંબંધિત વિભાગ સાથે તપાસ કરો。', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2560, 640, 54, 'સહાનુભૂતિ સાથે માફી માંગો, મુદ્દાને પ્રાથમિકતા આપો અને સ્પષ્ટ સમયરેખા સાથે પાછો સંપર્ક કરવાનો વચન આપો。', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2561, 641, 54, 'ग्राहकाची चिंता मान्य करा आणि विलंबाबद्दल सहानुभूती दाखवा。', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2562, 641, 54, 'ग्राहकाला सांगा की तुम्ही संबंधित विभागाशी तपासणी कराल आणि काही अपडेट असल्यास कळवाल。', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2563, 641, 54, 'माफी मागा, प्रकरणाला प्राधान्य देण्याचे आश्वासन द्या आणि संबंधित विभागाशी तपासणी करा。', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2564, 641, 54, 'सहानुभूतीने माफी मागा, प्रकरण प्राधान्याने पुढे पाठवा आणि स्पष्ट वेळमर्यादेसह परत संपर्क करण्याचे वचन द्या。', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2565, 642, 54, 'গ্রাহকের উদ্বেগ স্বীকার করুন এবং বিলম্বের জন্য সহানুভূতি প্রকাশ করুন।', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2566, 642, 54, 'গ্রাহককে জানান যে আপনি সংশ্লিষ্ট বিভাগের সাথে কথা বলবেন এবং কোনো আপডেট থাকলে জানাবেন।', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2567, 642, 54, 'ক্ষমা চান, বিষয়টিকে অগ্রাধিকার দেওয়ার প্রতিশ্রুতি দিন এবং সংশ্লিষ্ট বিভাগের সাথে যাচাই করুন।', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2568, 642, 54, 'সহানুভূতির সাথে ক্ষমা চান, বিষয়টিকে অগ্রাধিকার দিন এবং স্পষ্ট সময়সীমা দিয়ে পুনরায় যোগাযোগের প্রতিশ্রুতি দিন।', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2569, 643, 54, 'গ্ৰাহকৰ উদ্বেগ স্বীকাৰ কৰক আৰু বিলম্বৰ বাবে সহানুভূতি দেখুৱাওক।', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2570, 643, 54, 'গ্ৰাহকক জনাওক যে আপুনি সংশ্লিষ্ট বিভাগৰ সৈতে পৰীক্ষা কৰিব আৰু কোনো আপডেট থাকিলে জনাব।', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2571, 643, 54, 'ক্ষমা বিচাৰক, বিষয়টো প্ৰাধান্য দিয়াৰ আশ্বাস দিয়ক আৰু সংশ্লিষ্ট বিভাগৰ সৈতে পৰীক্ষা কৰক।', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2572, 643, 54, 'সহানুভূতিৰে ক্ষমা বিচাৰি, বিষয়টো প্ৰাধান্যভাৱে আগবঢ়াওক আৰু স্পষ্ট সময়সীমাৰে পুনৰ যোগাযোগ কৰাৰ প্ৰতিশ্ৰুতি দিয়ক।', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2573, 644, 54, 'வாடிக்கையாளரின் கவலையை ஏற்றுக்கொண்டு தாமதத்திற்கு அனுதாபம் தெரிவிக்கவும்。', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2574, 644, 54, 'தொடர்புடைய துறையுடன் சரிபார்த்து, ஏதேனும் அப்டேட் இருந்தால் தெரிவிப்பதாக வாடிக்கையாளருக்கு சொல்லவும்。', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2575, 644, 54, 'மன்னிப்பு கேட்டு, வழக்கை முன்னுரிமையாக எடுத்துக்கொள்வதாக உறுதி அளித்து, தொடர்புடைய துறையுடன் சரிபார்க்கவும்。', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2576, 644, 54, 'அனுதாபத்துடன் மன்னிப்பு கேட்டு, பிரச்சினையை முன்னுரிமையாக உயர்த்தி, தெளிவான காலக்கெடுவுடன் மீண்டும் தொடர்பு கொள்வதாக உறுதி அளிக்கவும்。', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2577, 645, 54, 'కస్టమర్ ఆందోళనను గుర్తించి, ఆలస్యంపై సహానుభూతి వ్యక్తం చేయండి。', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2578, 645, 54, 'సంబంధిత విభాగంతో చెక్ చేసి, ఏదైనా అప్డేట్ ఉంటే తెలియజేస్తామని కస్టమర్‌కు చెప్పండి。', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2579, 645, 54, 'క్షమాపణ చెప్పి, కేసును ప్రాధాన్యతగా తీసుకుంటామని హామీ ఇచ్చి, సంబంధిత విభాగంతో పరిశీలించండి。', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2580, 645, 54, 'సహానుభూతితో క్షమాపణ చెప్పి, సమస్యను ప్రాధాన్యతగా ఎస్కలేట్ చేసి, స్పష్టమైన టైమ్‌లైన్‌తో తిరిగి సంప్రదిస్తామని హామీ ఇవ్వండి。', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2581, 646, 54, 'ഉപഭോക്താവിന്റെ ആശങ്ക അംഗീകരിച്ച് വൈകിയതിനാൽ സഹാനുഭൂതി പ്രകടിപ്പിക്കുക。', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2582, 646, 54, 'ബന്ധപ്പെട്ട വിഭാഗവുമായി പരിശോധിച്ച്, അപ്ഡേറ്റ് ഉണ്ടെങ്കിൽ അറിയിക്കാമെന്ന് ഉപഭോക്താവിനെ അറിയിക്കുക。', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2583, 646, 54, 'ക്ഷമ ചോദിച്ച്, കേസിനെ മുൻഗണന നൽകാമെന്ന് ഉറപ്പ് നൽകി ബന്ധപ്പെട്ട വിഭാഗവുമായി പരിശോധിക്കുക。', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2584, 646, 54, 'സഹാനുഭൂതിയോടെ ക്ഷമ ചോദിച്ച്, വിഷയത്തെ മുൻഗണനയായി ഉയർത്തി, വ്യക്തമായ സമയപരിധിയോടെ തിരികെ ബന്ധപ്പെടാമെന്ന് ഉറപ്പ് നൽകുക。', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2585, 647, 54, 'ಗ್ರಾಹಕರ ಚಿಂತೆಯನ್ನು ಅಂಗೀಕರಿಸಿ ಮತ್ತು ವಿಳಂಬಕ್ಕೆ ಸಹಾನುಭೂತಿ ತೋರಿಸಿ。', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2586, 647, 54, 'ಸಂಬಂಧಿತ ವಿಭಾಗದೊಂದಿಗೆ ಪರಿಶೀಲಿಸಿ, ಯಾವುದೇ ಅಪ್ಡೇಟ್ ಇದ್ದರೆ ತಿಳಿಸುವುದಾಗಿ ಗ್ರಾಹಕರಿಗೆ ಹೇಳಿ。', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2587, 647, 54, 'ಕ್ಷಮೆಯಾಚಿಸಿ, ಪ್ರಕರಣವನ್ನು ಪ್ರಾಥಮಿಕತೆಯಿಂದ ತೆಗೆದುಕೊಳ್ಳುವುದಾಗಿ ಭರವಸೆ ನೀಡಿ ಮತ್ತು ಸಂಬಂಧಿತ ವಿಭಾಗದೊಂದಿಗೆ ಪರಿಶೀಲಿಸಿ。', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
