	(2645, 662, 56, 'हुई असुविधा के लिए माफी मांगें और ग्राहक की नाराज़गी को स्वीकार करें।', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2646, 662, 56, 'माफी मांगें, उसकी नाराज़गी को स्वीकार करें और फॉलो-अप कॉल का कारण संक्षेप में समझाएँ।', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2647, 662, 56, 'माफी मांगें, उसकी नाराज़गी को स्वीकार करें और उसकी संपर्क से जुड़ी पसंद (preference) को नोट करें।', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2648, 662, 56, 'माफी मांगें, उसकी नाराज़गी को स्वीकार करें, कॉल का कारण स्पष्ट रूप से समझाएँ और आश्वासन दें कि आगे से अनावश्यक कॉल नहीं किए जाएंगे।', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
