	(2664, 666, 56, 'ক্ষমা চান, স্বীকার করুন, কলের কারণ ব্যাখ্যা করুন এবং অপ্রয়োজনীয় কল করা হবে না বলে আশ্বাস দিন।', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
