	(2693, 674, 57, 'ग्राहक को उसकी खरीदारी के लिए बधाई दें और बातचीत को विनम्रता से समाप्त करें।', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2694, 674, 57, 'ग्राहक को खरीदारी के लिए बधाई दें और बताएं कि अगर भविष्य में किसी भी मदद की जरूरत हो तो वह आपकी डीलरशिप से संपर्क कर सकता है।', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2695, 674, 57, 'ग्राहक को बधाई दें, पूछें कि उन्होंने दूसरी डीलरशिप क्यों चुनी, और फीडबैक के लिए धन्यवाद दें।', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
