	(2843, 711, 60, 'ਉਨ੍ਹਾਂ ਦੀ ਚਿੰਤਾ ਨੂੰ ਸਵੀਕਾਰ ਕਰੋ ਅਤੇ ਪੁੱਛੋ ਕਿ ਕੀ ਉਹ ਚਾਹੁੰਦੇ ਹਨ ਕਿ DFM ਕਾਲ ਕਰਕੇ ਫਾਇਨੈਂਸ ਵਿਕਲਪ ਸਮਝਾਏ।', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2844, 711, 60, 'ਸਹਾਨੁਭੂਤੀ ਦਿਖਾਓ, ਡੀਲਰ ਫਾਇਨੈਂਸ ਬਾਰੇ ਸੰਖੇਪ ਵਿੱਚ ਜਾਣਕਾਰੀ ਦਿਓ ਅਤੇ ਪੁੱਛੋ ਕਿ ਕੀ ਉਹ ਹੋਰ ਵੇਰਵਿਆਂ ਲਈ DFM ਨਾਲ ਕਾਲ ਗਠਿਤ ਕਰਵਾਉਣਾ ਚਾਹੁੰਦੇ ਹਨ।', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2845, 712, 60, 'તેમની પરિસ્થિતિ સ્વીકારો અને જ્યારે ખરીદી કરવાની યોજના બનાવે ત્યારે ડીલરશિપનો સંપર્ક કરવા કહો.', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2846, 712, 60, 'તેમની ચિંતા સ્વીકારો અને ઉપલબ્ધ ફાઇનાન્સ વિકલ્પો વિશે ટૂંકમાં જાણ કરો.', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2847, 712, 60, 'તેમની ચિંતા સ્વીકારો અને પૂછો કે શું તેઓ DFM દ્વારા કોલ કરીને ફાઇનાન્સ વિકલ્પો સમજાવવા ઇચ્છે છે.', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2848, 712, 60, 'સહાનુભૂતિ દર્શાવો, ડીલર ફાઇનાન્સ વિશે ટૂંકમાં સમજાવો અને વધુ વિગતો માટે DFM સાથે કોલ ગોઠવવા ઇચ્છે છે કે નહીં તે પૂછો.', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2849, 713, 60, 'त्यांची परिस्थिती मान्य करा आणि खरेदीची योजना झाल्यावर डीलरशिपशी संपर्क साधण्यास सांगा.', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2850, 713, 60, 'त्यांची चिंता मान्य करा आणि उपलब्ध फायनान्स पर्यायांविषयी थोडक्यात माहिती द्या.', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2851, 713, 60, 'त्यांची चिंता मान्य करा आणि DFM कडून कॉल करून फायनान्स पर्याय समजावून सांगावा का हे विचारा.', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2852, 713, 60, 'सहानुभूती दाखवा, डीलर फायनान्सची थोडक्यात माहिती द्या आणि अधिक तपशीलांसाठी DFM कडून कॉलची व्यवस्था हवी आहे का ते विचारा.', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2853, 714, 60, 'তাদের পরিস্থিতি স্বীকার করুন এবং কেনার পরিকল্পনা করলে ডিলারশিপে যোগাযোগ করতে বলুন।', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2854, 714, 60, 'তাদের উদ্বেগ স্বীকার করুন এবং উপলভ্য ফাইন্যান্স বিকল্প সম্পর্কে সংক্ষেপে জানান।', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2855, 714, 60, 'তাদের উদ্বেগ স্বীকার করুন এবং জিজ্ঞাসা করুন তারা কি DFM-এর কল চান ফাইন্যান্স বিকল্প ব্যাখ্যার জন্য।', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2856, 714, 60, 'সহানুভূতি দেখান, ডিলার ফাইন্যান্স সম্পর্কে সংক্ষেপে বলুন এবং বিস্তারিত জানার জন্য DFM-এর সাথে কলের ব্যবস্থা চান কিনা জিজ্ঞাসা করুন।', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2857, 715, 60, 'তেওঁলোকৰ পৰিস্থিতি স্বীকাৰ কৰক আৰু ক্ৰয়ৰ পরিকল্পনা কৰিলে ডিলাৰশ্বিপৰ সৈতে যোগাযোগ কৰিবলৈ কওক।', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2858, 715, 60, 'তেওঁলোকৰ উদ্বেগ স্বীকাৰ কৰি উপলব্ধ ফাইনেন্স বিকল্পসমূহ সংক্ষেপে জনাওক।', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2859, 715, 60, 'তেওঁলোকৰ উদ্বেগ স্বীকাৰ কৰি DFM ৰ পৰা কল কৰি ফাইনেন্স বিকল্প বুজাব লাগিব নেকি সুধক।', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2860, 715, 60, 'সহানুভূতি দেখুৱাওক, ডিলাৰ ফাইনেন্সৰ বিষয়ে সংক্ষেপে কওক আৰু অধিক বিৱৰণৰ বাবে DFM ৰ সৈতে কল ব্যৱস্থা কৰিব নেকি সুধক।', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2861, 716, 60, 'அவர்களின் நிலையை ஏற்றுக்கொண்டு, வாங்க திட்டமிட்டால் டீலர்ஷிப்பை தொடர்பு கொள்ள சொல்லவும்.', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2862, 716, 60, 'அவர்களின் கவலைையை ஏற்றுக்கொண்டு, கிடைக்கும் நிதி விருப்பங்களை சுருக்கமாக தெரிவிக்கவும்.', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2863, 716, 60, 'அவர்களின் கவலைையை ஏற்றுக்கொண்டு, DFM மூலம் அழைத்து நிதி விருப்பங்களை விளக்க வேண்டுமா என்று கேளுங்கள்.', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2864, 716, 60, 'அனுதாபம் காட்டி, டீலர் நிதி பற்றிச் சுருக்கமாக விளக்கி, மேலும் விவரங்களுக்கு DFM மூலம் அழைப்பு ஏற்பாடு செய்ய விரும்புகிறார்களா என்று கேளுங்கள்.', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2865, 717, 60, 'వారి పరిస్థితిని గుర్తించి, కొనుగోలు చేయాలనుకున్నప్పుడు డీలర్‌షిప్‌ను సంప్రదించమని చెప్పండి.', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2866, 717, 60, 'వారి ఆందోళనను గుర్తించి, అందుబాటులో ఉన్న ఫైనాన్స్ ఎంపికలను సంక్షిప్తంగా తెలియజేయండి.', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2867, 717, 60, 'వారి ఆందోళనను గుర్తించి, DFM కాల్ చేసి ఫైనాన్స్ ఎంపికలు వివరించాలా అని అడగండి.', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2868, 717, 60, 'సహానుభూతి చూపించి, డీలర్ ఫైనాన్స్ గురించి సంక్షిప్తంగా వివరించి, మరిన్ని వివరాల కోసం DFM కాల్ ఏర్పాటు చేయాలా అని అడగండి.', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2869, 718, 60, 'അവരുടെ സാഹചര്യം അംഗീകരിച്ച്, വാങ്ങാൻ പദ്ധതിയിടുമ്പോൾ ഡീലർഷിപ്പുമായി ബന്ധപ്പെടാൻ പറയുക.', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2870, 718, 60, 'അവരുടെ ആശങ്ക അംഗീകരിച്ച് ലഭ്യമായ ഫിനാൻസ് ഓപ്ഷനുകൾ ചുരുക്കത്തിൽ അറിയിക്കുക.', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2871, 718, 60, 'അവരുടെ ആശങ്ക അംഗീകരിച്ച് DFM വഴി വിളിച്ച് ഫിനാൻസ് ഓപ്ഷനുകൾ വിശദീകരിക്കണമോ എന്ന് ചോദിക്കുക.', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2872, 718, 60, 'സഹാനുഭൂതി പ്രകടിപ്പിച്ച് ഡീലർ ഫിനാൻസ് ചുരുക്കത്തിൽ വിശദീകരിച്ച് കൂടുതൽ വിവരങ്ങൾക്ക് DFM വഴി കോളിന്റെ ക്രമീകരണം വേണമോ എന്ന് ചോദിക്കുക.', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2873, 719, 60, 'ಅವರ ಪರಿಸ್ಥಿತಿಯನ್ನು ಅಂಗೀಕರಿಸಿ ಮತ್ತು ಖರೀದಿ ಯೋಜಿಸಿದಾಗ ಡೀಲರ್‌ಶಿಪ್ ಸಂಪರ್ಕಿಸಲು ಹೇಳಿ.', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2874, 719, 60, 'ಅವರ ಚಿಂತೆಯನ್ನು ಅಂಗೀಕರಿಸಿ ಲಭ್ಯವಿರುವ ಹಣಕಾಸು ಆಯ್ಕೆಗಳನ್ನು ಸಂಕ್ಷಿಪ್ತವಾಗಿ ತಿಳಿಸಿ.', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2875, 719, 60, 'ಅವರ ಚಿಂತೆಯನ್ನು ಅಂಗೀಕರಿಸಿ DFM ಕರೆ ಮಾಡಿ ಹಣಕಾಸು ಆಯ್ಕೆಗಳನ್ನು ವಿವರಿಸಬೇಕೇ ಎಂದು ಕೇಳಿ.', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2876, 719, 60, 'ಸಹಾನುಭೂತಿ ತೋರಿಸಿ ಡೀಲರ್ ಫೈನಾನ್ಸ್ ಬಗ್ಗೆ ಸಂಕ್ಷಿಪ್ತವಾಗಿ ವಿವರಿಸಿ ಮತ್ತು ಹೆಚ್ಚಿನ ವಿವರಗಳಿಗೆ DFM ಕರೆ ವ್ಯವಸ್ಥೆ ಬೇಕೇ ಎಂದು ಕೇಳಿ.', NULL, 10, 4, 'Active', '2026-02-27 06:06:08'),
	(2877, 720, 60, 'ସେମାନଙ୍କ ସ୍ଥିତିକୁ ସ୍ୱୀକାର କରନ୍ତୁ ଏବଂ କ୍ରୟ ଯୋଜନା କରିଲେ ଡିଲରଶିପ୍ ସହ ସମ୍ପର୍କ କରିବାକୁ କହନ୍ତୁ।', NULL, 3, 1, 'Active', '2026-02-27 06:06:08'),
	(2878, 720, 60, 'ସେମାନଙ୍କ ଚିନ୍ତାକୁ ସ୍ୱୀକାର କରି ଉପଲବ୍ଧ ଅର୍ଥାୟନ ବିକଳ୍ପ ସମ୍ପର୍କରେ ସଂକ୍ଷେପରେ ଜଣାନ୍ତୁ।', NULL, 5, 2, 'Active', '2026-02-27 06:06:08'),
	(2879, 720, 60, 'ସେମାନଙ୍କ ଚିନ୍ତାକୁ ସ୍ୱୀକାର କରି DFM କଲ୍ କରି ଅର୍ଥାୟନ ବିକଳ୍ପ ବୁଝାଇବେ କି ନାହିଁ ପଚାରନ୍ତୁ।', NULL, 7, 3, 'Active', '2026-02-27 06:06:08'),
	(2880, 720, 60, 'ସହାନୁଭୂତି ଦେଖାଇ ଡିଲର ଫାଇନାନ୍ସ ବିଷୟରେ ସଂକ୍ଷେପରେ ବୁଝାନ୍ତୁ ଏବଂ ଅଧିକ ବିବରଣୀ ପାଇଁ DFM ସହ କଲ୍ ବ୍ୟବସ୍ଥା ଚାହୁଁଛନ୍ତି କି ନାହିଁ ପଚାରନ୍ତୁ।', NULL, 10, 4, 'Active', '2026-02-27 06:06:08');
INSERT INTO `question_translations` (`id`, `base_question_id`, `language_id`, `question`, `question_media_path`, `short_content`, `long_content_text`, `long_content_file_path`, `long_content_audio_path`, `question_answer_audio_path`, `created_at`, `status`) VALUES
	(1, 1, 1, 'A college student visits the dealership interested in the Xoom 125 and asks for an immediate test ride.\r\n\r\nDuring verification, you notice he does not have a valid driving license but insists he regularly rides inside campus. He seems very serious about purchasing the scooter.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(2, 1, 2, 'एक कॉलेज स्टूडेंट Xoom 125 में इंटरेस्ट लेकर शोरूम आता है और तुरंत टेस्ट राइड मांगता है।\r\nवेरिफिकेशन के दौरान आपको पता चलता है कि उसके पास वैध ड्राइविंग लाइसेंस नहीं है, लेकिन वह कहता है कि वह कैंपस के अंदर रेगुलर स्कूटर चलाता है। वह खरीदने को लेकर काफ़ी सीरियस लगता है।\r\nऐसी सिचुएशन में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(3, 1, 3, 'ਇੱਕ ਕਾਲਜ ਸਟੂਡੈਂਟ Xoom 125 ਵਿੱਚ ਦਿਲਚਸਪੀ ਲੈ ਕੇ ਸ਼ੋਰੂਮ ਆਉਂਦਾ ਹੈ ਅਤੇ ਤੁਰੰਤ ਟੈਸਟ ਰਾਈਡ ਮੰਗਦਾ ਹੈ।\r\nਚੈਕ ਕਰਨ ਤੇ ਪਤਾ ਲੱਗਦਾ ਹੈ ਕਿ ਉਸ ਕੋਲ ਵੈਧ ਡਰਾਈਵਿੰਗ ਲਾਇਸੈਂਸ ਨਹੀਂ ਹੈ, ਪਰ ਉਹ ਕਹਿੰਦਾ ਹੈ ਕਿ ਉਹ ਕੈਂਪਸ ਦੇ ਅੰਦਰ ਰੈਗੂਲਰ ਸਕੂਟਰ ਚਲਾਉਂਦਾ ਹੈ। ਉਹ ਖਰੀਦਣ ਲਈ ਕਾਫ਼ੀ ਸੀਰੀਅਸ ਹੈ।\r\nਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(4, 1, 4, 'એક કોલેજ સ્ટુડન્ટ Xoom 125માં રસ લઈને શોરૂમમાં આવે છે અને તરત જ ટેસ્ટ રાઇડ માંગે છે।\r\nવેરિફિકેશન દરમિયાન ખબર પડે છે કે તેની પાસે માન્ય ડ્રાઇવિંગ લાઇસન્સ નથી, છતાં તે કહે છે કે તે કેમ્પસની અંદર નિયમિત ચલાવે છે. તે ખરીદી માટે ખૂબ જ સિરિયસ છે।\r\nઆ પરિસ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(5, 1, 5, 'एक कॉलेज स्टुडंट Xoom 125 मध्ये इंटरेस्ट घेऊन शोरूममध्ये येतो आणि लगेच टेस्ट राइड मागतो.\r\nवेरिफिकेशनमध्ये दिसतं की त्याच्याकडे वैध ड्रायव्हिंग लायसन्स नाही, पण तो म्हणतो की तो कॅम्पसमध्ये रेग्युलर गाडी चालवतो. तो खरेदीबाबत खूप सिरीयस आहे.\r\nअशा परिस्थितीत तुम्ही हे कसं हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(6, 1, 6, 'একজন কলেজ স্টুডেন্ট Xoom 125 নিয়ে আগ্রহ দেখিয়ে শোরুমে আসে এবং সঙ্গে সঙ্গে টেস্ট রাইড চায়।\r\nভেরিফিকেশনের সময় দেখা যায় তার কাছে বৈধ ড্রাইভিং লাইসেন্স নেই, কিন্তু সে বলে যে সে ক্যাম্পাসের ভিতরে নিয়মিত চালায়। সে কিনতে খুবই সিরিয়াস।\r\nএই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(7, 1, 7, 'এজন কলেজৰ ছাত্ৰ Xoom 125-ত আগ্ৰহ লৈ শোৰূমলৈ আহে আৰু তৎক্ষণাৎ টেষ্ট ৰাইড বিচাৰে।\r\nভেৰিফিকেশ্যনত দেখা যায় যে তাৰ ওচৰত বৈধ ড্ৰাইভিং লাইচেঞ্চ নাই, কিন্তু সি কয় যে কেম্পাছৰ ভিতৰত নিয়মিত চলাই থাকে। সি কিনাৰ ক্ষেত্ৰত বহুত চিৰিয়াছ।\r\nএই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(8, 1, 8, 'ஒரு கல்லூரி மாணவர் Xoom 125-ல் ஆர்வம் கொண்டு ஷோரூமுக்கு வந்து உடனே டெஸ்ட் ரைடு கேட்கிறார்.\r\nசரிபார்ப்பில் அவரிடம் செல்லுபடியாகும் டிரைவிங் லைசென்ஸ் இல்லை என்பது தெரிய வருகிறது, ஆனாலும் கேம்பஸுக்குள் அடிக்கடி ஓட்டுவதாக சொல்கிறார். அவர் வாங்குவதில் ரொம்ப சீரியஸாக இருக்கிறார்.\r\nஇந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(9, 1, 9, 'ஒரு கல்லூரி மாணவர் Xoom 125-ல் ஆர்வம் கொண்டு ஷோரூமுக்கு வந்து உடனே டெஸ்ட் ரைடு கேட்கிறார்.\r\nசரிபார்ப்பில் அவரிடம் செல்லுபடியாகும் டிரைவிங் லைசென்ஸ் இல்லை என்பது தெரிய வருகிறது, ஆனாலும் கேம்பஸுக்குள் அடிக்கடி ஓட்டுவதாக சொல்கிறார். அவர் வாங்குவதில் ரொம்ப சீரியஸாக இருக்கிறார்.\r\nஇந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(10, 1, 10, 'ഒരു കോളേജ് വിദ്യാർത്ഥി Xoom 125-ൽ താൽപര്യം കാണിച്ച് ഷോറൂമിലേക്ക് വന്ന് ഉടൻ തന്നെ ടെസ്റ്റ് റൈഡ് ചോദിക്കുന്നു.\r\nപരിശോധനയിൽ അദ്ദേഹത്തിന് സാധുവായ ഡ്രൈവിംഗ് ലൈസൻസ് ഇല്ലെന്ന് മനസ്സിലാകുന്നു, എന്നാൽ ക്യാമ്പസിനുള്ളിൽ സ്ഥിരമായി ഓടിക്കുന്നുണ്ടെന്ന് പറയുന്നു. വാങ്ങുന്നതിൽ അദ്ദേഹം വളരെ സീരിയസാണ്.\r\nഈ സാഹചര്യത്തെ നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(11, 1, 11, 'ಒಬ್ಬ ಕಾಲೇಜು ಸ್ಟೂಡೆಂಟ್ Xoom 125 ಬಗ್ಗೆ ಆಸಕ್ತಿಯಿಂದ ಶೋರೂಮ್‌ಗೆ ಬಂದು ತಕ್ಷಣ ಟೆಸ್ಟ್ ರೈಡ್ ಕೇಳ್ತಾನೆ.\r\nವೆರಿಫಿಕೇಶನ್‌ನಲ್ಲಿ ಅವನ ಬಳಿ ಮಾನ್ಯವಾದ ಡ್ರೈವಿಂಗ್ ಲೈಸೆನ್ಸ್ ಇಲ್ಲ ಅನ್ನೋದು ಗೊತ್ತಾಗುತ್ತೆ, ಆದ್ರೆ ಕ್ಯಾಂಪಸ್ ಒಳಗೆ ರೆಗ್ಯುಲರ್ ಆಗಿ ಓಡಿಸ್ತೀನಿ ಅಂತ ಹೇಳ್ತಾನೆ. ಖರೀದಿಗೆ ತುಂಬಾ ಸೀರಿಯಸ್ ಆಗಿದ್ದಾನೆ.\r\nಈ ಸಿಚ್ಯುಯೇಷನ್‌ನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(12, 1, 12, 'ଜଣେ କଲେଜ୍ ଛାତ୍ର Xoom 125 ରେ ଆଗ୍ରହ ନେଇ ଶୋରୁମକୁ ଆସି ତୁରନ୍ତ ଟେଷ୍ଟ ରାଇଡ୍ ଚାହୁଁଛନ୍ତି।\r\nଭେରିଫିକେସନ୍‌ ସମୟରେ ଦେଖାଯାଏ ଯେ ତାଙ୍କ ପାଖରେ ବ valid ଧ ଡ୍ରାଇଭିଂ ଲାଇସେନ୍ସ ନାହିଁ, କିନ୍ତୁ ସେ କହୁଛନ୍ତି ଯେ କ୍ୟାମ୍ପସ୍‌ ଭିତରେ ସେ ନିୟମିତ ଚଳାନ୍ତି। ସେ କିଣିବା ପାଇଁ ବହୁତ ସିରିଅସ୍‌।\r\nଏମିତି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(13, 2, 1, 'A customer booked an Xtreme 125R Dual Channel ABS for his son’s birthday delivery.\r\n\r\nThe chosen colour will arrive three days late, but the same variant is available in other colours today.\r\n\r\nThe customer is upset and insists on delivery on the promised date.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(14, 2, 2, 'एक कस्टमर ने अपने बेटे के बर्थडे डिलीवरी के लिए Xtreme 125R ड्यूल चैनल ABS बुक किया है। चुना हुआ कलर तीन दिन लेट आएगा, लेकिन वही वैरिएंट दूसरे कलर्स में आज उपलब्ध है। कस्टमर नाराज़ है और तय तारीख पर ही डिलीवरी चाहता है। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(15, 2, 3, 'ਇੱਕ ਕਸਟਮਰ ਨੇ ਆਪਣੇ ਪੁੱਤਰ ਦੇ ਜਨਮਦਿਨ ਲਈ Xtreme 125R ਡਿਊਅਲ ਚੈਨਲ ABS ਬੁੱਕ ਕੀਤਾ ਹੈ। ਚੁਣਿਆ ਹੋਇਆ ਰੰਗ ਤਿੰਨ ਦਿਨ ਦੇਰ ਨਾਲ ਆਵੇਗਾ, ਪਰ ਉਹੀ ਵੈਰੀਐਂਟ ਹੋਰ ਰੰਗਾਂ ਵਿੱਚ ਅੱਜ ਉਪਲਬਧ ਹੈ। ਕਸਟਮਰ ਨਾਰਾਜ਼ ਹੈ ਅਤੇ ਵਾਅਦੇ ਵਾਲੀ ਤਾਰੀਖ਼ ਤੇ ਹੀ ਡਿਲਿਵਰੀ ਚਾਹੁੰਦਾ ਹੈ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(16, 2, 4, 'એક કસ્ટમરે તેના દીકરાના જન્મદિવસ માટે Xtreme 125R ડ્યુઅલ ચેનલ ABS બુક કરી છે. પસંદ કરેલો રંગ ત્રણ દિવસ મોડો આવશે, પરંતુ એ જ વેરિઅન્ટ બીજા રંગોમાં આજે ઉપલબ્ધ છે. કસ્ટમર નારાજ છે અને વચન આપેલી તારીખે જ ડિલિવરી માંગે છે. આવી પરિસ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(17, 2, 5, 'एका कस्टमरने आपल्या मुलाच्या वाढदिवसासाठी Xtreme 125R ड्युअल चॅनल ABS बुक केली आहे. निवडलेला रंग तीन दिवस उशिरा येणार आहे, पण तोच व्हेरिएंट इतर रंगांमध्ये आज उपलब्ध आहे. कस्टमर नाराज आहे आणि दिलेल्या तारखेलाच डिलिव्हरी हवी आहे. अशा परिस्थितीत तुम्ही कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(18, 2, 6, 'একজন কাস্টমার তার ছেলের জন্মদিনের জন্য Xtreme 125R ডুয়াল চ্যানেল ABS বুক করেছেন। পছন্দের রংটি তিন দিন দেরিতে আসবে, কিন্তু একই ভ্যারিয়েন্ট অন্য রঙে আজই পাওয়া যাচ্ছে। কাস্টমার বিরক্ত এবং প্রতিশ্রুত তারিখেই ডেলিভারি চান। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(19, 2, 7, 'এজন কাষ্টমাৰে তেওঁৰ পুত্ৰৰ জন্মদিনৰ বাবে Xtreme 125R ডুৱেল চেনেল ABS বুক কৰিছে। বাছনি কৰা ৰংটো তিনিদিন পলমকৈ আহিব, কিন্তু একে ভেৰিয়েণ্ট আন ৰঙত আজি উপলব্ধ। কাষ্টমাৰ খং উঠিছে আৰু প্ৰতিশ্ৰুতি দিয়া তাৰিখতেই ডেলিভাৰী বিচাৰে। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(20, 2, 8, 'ஒரு கஸ்டமர் தன் மகனின் பிறந்தநாள் டெலிவரிக்காக Xtreme 125R Dual Channel ABS-ஐ புக் செய்துள்ளார். அவர் தேர்ந்தெடுத்த நிறம் மூன்று நாட்கள் தாமதமாக வரும், ஆனால் அதே வேரியண்ட் மற்ற நிறங்களில் இன்று கிடைக்கிறது. கஸ்டமர் கோபமாக இருந்து, வாக்குறுதி கொடுத்த தேதியிலேயே டெலிவரி வேண்டும் என்று கேட்கிறார். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(21, 2, 9, 'ఒక కస్టమర్ తన కుమారుడి పుట్టినరోజు డెలివరీ కోసం Xtreme 125R డ్యూయల్ ఛానల్ ABS బుక్ చేశారు. ఎంపిక చేసిన రంగు మూడు రోజులు ఆలస్యంగా వస్తుంది, కానీ అదే వేరియంట్ ఇతర రంగుల్లో ఈరోజే అందుబాటులో ఉంది. కస్టమర్ అసహనంగా ఉండి, హామీ ఇచ్చిన తేదీననే డెలివరీ కావాలని అంటున్నారు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(22, 2, 10, 'ഒരു കസ്റ്റമർ തന്റെ മകന്റെ പിറന്നാൾ ഡെലിവറിക്കായി Xtreme 125R ഡ്യുവൽ ചാനൽ ABS ബുക്ക് ചെയ്തിട്ടുണ്ട്. തിരഞ്ഞെടുത്ത നിറം മൂന്ന് ദിവസം വൈകിയാണ് എത്തുക, എന്നാൽ അതേ വേരിയന്റ് മറ്റ് നിറങ്ങളിൽ ഇന്ന് തന്നെ ലഭ്യമാണ്. കസ്റ്റമർ അസ്വസ്ഥനായി, വാഗ്ദാനം ചെയ്ത തീയതിയിൽ തന്നെ ഡെലിവറി വേണമെന്ന് ആവശ്യപ്പെടുന്നു. ഈ സാഹചര്യത്തെ നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(23, 2, 11, 'ಒಬ್ಬ ಕಸ್ಟಮರ್ ತನ್ನ ಮಗನ ಹುಟ್ಟುಹಬ್ಬದ ಡೆಲಿವರಿಗಾಗಿ Xtreme 125R ಡ್ಯುಯಲ್ ಚಾನೆಲ್ ABS ಬುಕ್ ಮಾಡಿದ್ದಾರೆ. ಆಯ್ಕೆ ಮಾಡಿದ ಬಣ್ಣ ಮೂರು ದಿನ ತಡವಾಗಿ ಬರಲಿದೆ, ಆದರೆ ಅದೇ ವೇರಿಯಂಟ್ ಇತರ ಬಣ್ಣಗಳಲ್ಲಿ ಇಂದು ಲಭ್ಯವಿದೆ. ಕಸ್ಟಮರ್ ಅಸಮಾಧಾನಗೊಂಡು, ಭರವಸೆ ನೀಡಿದ ದಿನವೇ ಡೆಲಿವರಿ ಬೇಕೆಂದು ಒತ್ತಾಯಿಸುತ್ತಿದ್ದಾರೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(24, 2, 12, 'ଜଣେ କଷ୍ଟମର ତାଙ୍କ ପୁଅଙ୍କ ଜନ୍ମଦିନ ଡିଲିଭରି ପାଇଁ Xtreme 125R Dual Channel ABS ବୁକ୍ କରିଛନ୍ତି। ବାଛିଥିବା ରଙ୍ଗ ତିନି ଦିନ ଦେରିରେ ଆସିବ, କିନ୍ତୁ ସେହି ଭେରିଆଣ୍ଟ ଅନ୍ୟ ରଙ୍ଗରେ ଆଜି ଉପଲବ୍ଧ ଅଛି। କଷ୍ଟମର ଅସନ୍ତୁଷ୍ଟ ଓ ପ୍ରତିଶ୍ରୁତ ତାରିଖରେ ଡିଲିଭରି ଚାହୁଁଛନ୍ତି। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(25, 3, 1, 'A customer compares your quotation with another dealership offering a lower on-road price for the same motorcycle.\r\n\r\nHe questions why your dealership price is higher and asks you to match it immediately.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(26, 3, 2, 'एक कस्टमर आपके कोटेशन की तुलना दूसरे डीलरशिप से करता है, जो उसी बाइक के लिए कम ऑन-रोड प्राइस दे रहा है। वह पूछता है कि आपकी डीलरशिप का प्राइस ज़्यादा क्यों है और तुरंत मैच करने को कहता है। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(27, 3, 3, 'ਇੱਕ ਕਸਟਮਰ ਤੁਹਾਡੇ ਕੋਟੇਸ਼ਨ ਦੀ ਤੁਲਨਾ ਇੱਕ ਹੋਰ ਡੀਲਰਸ਼ਿਪ ਨਾਲ ਕਰਦਾ ਹੈ ਜੋ ਉਸੇ ਮੋਟਰਸਾਈਕਲ ਲਈ ਘੱਟ ਆਨ-ਰੋਡ ਪ੍ਰਾਈਸ ਦੇ ਰਹੀ ਹੈ। ਉਹ ਪੁੱਛਦਾ ਹੈ ਕਿ ਤੁਹਾਡੀ ਡੀਲਰਸ਼ਿਪ ਦਾ ਭਾਅ ਵੱਧ ਕਿਉਂ ਹੈ ਅਤੇ ਤੁਰੰਤ ਮੈਚ ਕਰਨ ਲਈ ਕਹਿੰਦਾ ਹੈ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(28, 3, 4, 'એક કસ્ટમર તમારા ક્વોટેશનની તુલના બીજી ડીલરશિપ સાથે કરે છે, જ્યાં એ જ બાઇક માટે ઓન-રોડ કિંમત ઓછી આપવામાં આવી છે. તે પૂછે છે કે તમારી ડીલરશિપની કિંમત વધારે કેમ છે અને તરત જ મેચ કરવા કહે છે. આવી પરિસ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(29, 3, 5, 'एक कस्टमर तुमच्या कोटेशनची तुलना दुसऱ्या डीलरशिपशी करतो, जिथे त्याच मोटरसायकलसाठी कमी ऑन-रोड किंमत दिली जाते. तो विचारतो की तुमच्या डीलरशिपची किंमत जास्त का आहे आणि लगेच मॅच करण्यास सांगतो. अशा परिस्थितीत तुम्ही कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(30, 3, 6, 'একজন কাস্টমার আপনার কোটেশনের সঙ্গে অন্য একটি ডিলারশিপের কোটেশনের তুলনা করেন, যেখানে একই মোটরসাইকেলের অন-রোড দাম কম দেওয়া হচ্ছে। তিনি জানতে চান কেন আপনার ডিলারশিপের দাম বেশি এবং সঙ্গে সঙ্গে মিলিয়ে দিতে বলেন। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(31, 3, 7, 'এজন কাষ্টমাৰে আপোনাৰ কোটেশ্যনটো অন্য এখন ডীলাৰশ্বিপৰ সৈতে তুলনা কৰে, যিয়ে একে মটৰচাইকেলৰ বাবে কম অন-ৰোড মূল্য দিছে। সি সুধে যে আপোনাৰ ডীলাৰশ্বিপৰ মূল্য বেছি কিয় আৰু লগে লগে মিলাবলৈ কয়। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(32, 3, 8, 'ஒரு கஸ்டமர் உங்கள் கோட்டேஷனை அதே பைக்கிற்கு குறைந்த ஆன்ரோடு விலை தரும் மற்றொரு டீலர்ஷிப்புடன் ஒப்பிடுகிறார். உங்கள் டீலர்ஷிப்பில் விலை அதிகமாக இருக்கிறதேன் என்று கேட்டு, உடனே அதையே மேட்ச் செய்ய சொல்லுகிறார். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(33, 3, 9, 'ఒక కస్టమర్ మీ కోటేషన్‌ను అదే బైక్‌కు తక్కువ ఆన్-రోడ్ ధర ఇచ్చే మరో డీలర్‌షిప్‌తో పోల్చుతున్నాడు. మీ డీలర్‌షిప్ ధర ఎందుకు ఎక్కువగా ఉందని ప్రశ్నించి, వెంటనే మ్యాచ్ చేయమని అడుగుతున్నాడు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(34, 3, 10, 'ഒരു കസ്റ്റമർ നിങ്ങളുടെ ക്വട്ടേഷൻ അതേ മോട്ടോർസൈക്കിളിന് കുറഞ്ഞ ഓൺ-റോഡ് വില നൽകുന്ന മറ്റൊരു ഡീലർഷിപ്പുമായി താരതമ്യം ചെയ്യുന്നു. നിങ്ങളുടെ ഡീലർഷിപ്പിലെ വില കൂടുതലായതെന്തെന്ന് ചോദിക്കുകയും ഉടൻ തന്നെ മാച്ച് ചെയ്യാൻ ആവശ്യപ്പെടുകയും ചെയ്യുന്നു. ഈ സാഹചര്യത്തെ നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(35, 3, 11, 'ಒಬ್ಬ ಕಸ್ಟಮರ್ ನಿಮ್ಮ ಕೋಟೇಶನ್ ಅನ್ನು ಅದೇ ಬೈಕ್‌ಗೆ ಕಡಿಮೆ ಆನ್-ರೋಡ್ ಬೆಲೆ ನೀಡುತ್ತಿರುವ ಇನ್ನೊಂದು ಡೀಲರ್‌ಶಿಪ್ ಜೊತೆಗೆ ಹೋಲಿಸುತ್ತಾನೆ. ನಿಮ್ಮ ಡೀಲರ್‌ಶಿಪ್ ಬೆಲೆ ಏಕೆ ಜಾಸ್ತಿ ಅಂತ ಕೇಳಿ, ತಕ್ಷಣ ಮ್ಯಾಚ್ ಮಾಡಬೇಕು ಅಂತ ಒತ್ತಾಯಿಸುತ್ತಾನೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(36, 3, 12, 'ଜଣେ କଷ୍ଟମର ଆପଣଙ୍କ କୋଟେସନ୍‌କୁ ସେଇ ମୋଟରସାଇକେଲ୍‌ ପାଇଁ କମ୍‌ ଅନ୍-ରୋଡ୍ ମୂଲ୍ୟ ଦେଉଥିବା ଅନ୍ୟ ଡିଲର୍‌ଶିପ୍‌ ସହ ତୁଳନା କରୁଛନ୍ତି। ସେ ପଚାରୁଛନ୍ତି କାହିଁକି ଆପଣଙ୍କ ଡିଲର୍‌ଶିପ୍‌ ମୂଲ୍ୟ ଅଧିକ ଅଛି ଏବଂ ସହସ୍ରେ ମ୍ୟାଚ୍ କରିବାକୁ କହୁଛନ୍ତି। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(37, 4, 1, 'A farmer with no income proof enquires about purchasing an HF Deluxe under a low down payment scheme.\r\n\r\nWhile checking eligibility, you realize he does not meet the required documentation criteria and he appears hopeful about the purchase.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(38, 4, 2, 'एक किसान बिना इनकम प्रूफ के HF Deluxe को लो डाउन पेमेंट स्कीम में खरीदने के बारे में पूछताछ करता है। एलिजिबिलिटी चेक करते समय पता चलता है कि वह ज़रूरी डॉक्यूमेंट्स की शर्तें पूरी नहीं करता, लेकिन फिर भी वह खरीद को लेकर उम्मीद लगाए बैठा है। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(39, 4, 3, 'ਇੱਕ ਕਿਸਾਨ ਬਿਨਾਂ ਆਮਦਨ ਪ੍ਰੂਫ ਦੇ HF Deluxe ਨੂੰ ਘੱਟ ਡਾਊਨ ਪੇਮੈਂਟ ਸਕੀਮ ਵਿੱਚ ਖਰੀਦਣ ਬਾਰੇ ਪੁੱਛਦਾ ਹੈ। ਯੋਗਤਾ ਚੈੱਕ ਕਰਦੇ ਸਮੇਂ ਪਤਾ ਲੱਗਦਾ ਹੈ ਕਿ ਉਹ ਲੋੜੀਂਦੇ ਦਸਤਾਵੇਜ਼ਾਂ ਦੀਆਂ ਸ਼ਰਤਾਂ ਪੂਰੀਆਂ ਨਹੀਂ ਕਰਦਾ, ਪਰ ਫਿਰ ਵੀ ਉਹ ਖਰੀਦ ਲਈ ਉਮੀਦਵਾਰ ਹੈ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(40, 4, 4, 'એક ખેડૂત કોઈ ઇનકમ પ્રૂફ વગર HF Deluxe ને લો ડાઉન પેમેન્ટ સ્કીમમાં ખરીદવા માટે પૂછે છે. એલિજિબિલિટી ચેક કરતી વખતે ખબર પડે છે કે તે જરૂરી દસ્તાવેજોની શરતો પૂરી કરતો નથી, છતાં તે ખરીદી વિશે આશાવાન છે. આવી પરિસ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(41, 4, 5, 'एक शेतकरी इनकम प्रूफ नसताना HF Deluxe कमी डाउन पेमेंट स्कीममध्ये खरेदी करण्याबद्दल चौकशी करतो. पात्रता तपासताना लक्षात येते की तो आवश्यक कागदपत्रांची अट पूर्ण करत नाही, तरीही तो खरेदीबाबत आशावादी आहे. अशा परिस्थितीत तुम्ही हे कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(42, 4, 6, 'একজন কৃষক কোনও ইনকাম প্রুফ ছাড়াই HF Deluxe কম ডাউন পেমেন্ট স্কিমে কেনার বিষয়ে জিজ্ঞাসা করেন। যোগ্যতা যাচাই করার সময় দেখা যায় তিনি প্রয়োজনীয় নথিপত্রের শর্ত পূরণ করেন না, কিন্তু তবুও তিনি কেনার ব্যাপারে আশাবাদী। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(43, 4, 7, 'এজন কৃষকে কোনো আয় প্ৰমাণ নথকা অৱস্থাত HF Deluxe কম ডাউন পেমেণ্ট স্কীমত ক্ৰয় কৰাৰ বিষয়ে সুধে। যোগ্যতা পৰীক্ষা কৰোঁতে দেখা যায় যে তেওঁ প্ৰয়োজনীয় নথিপত্ৰৰ চৰ্ত পূৰণ নকৰে, তথাপিও তেওঁ ক্ৰয়ক লৈ আশাবাদী। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(44, 4, 8, 'ஒரு விவசாயி எந்த வருமான ஆதாரமும் இல்லாமல் HF Deluxe-ஐ குறைந்த டவுன் பேமெண்ட் திட்டத்தில் வாங்குவது பற்றி கேட்கிறார். தகுதியை சரிபார்க்கும் போது தேவையான ஆவணங்கள் பொருந்தவில்லை என்பது தெரிய வருகிறது, ஆனாலும் அவர் வாங்கலாம் என்ற நம்பிக்கையில் இருக்கிறார். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(45, 4, 9, 'ఒక రైతు ఎలాంటి ఆదాయ రుజువు లేకుండా HF Deluxe ను తక్కువ డౌన్ పేమెంట్ స్కీమ్‌లో కొనుగోలు చేయడం గురించి అడుగుతున్నాడు. అర్హతను చెక్ చేసే సమయంలో అవసరమైన డాక్యుమెంట్లు సరిపోవట్లేదని తెలుస్తుంది, అయినా కూడా అతను కొనుగోలు విషయంలో ఆశతో ఉన్నాడు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(46, 4, 10, 'ഒരു കർഷകൻ വരുമാന തെളിവൊന്നുമില്ലാതെ HF Deluxe കുറഞ്ഞ ഡൗൺ പേയ്മെന്റ് സ്കീമിൽ വാങ്ങുന്നതിനെക്കുറിച്ച് ചോദിക്കുന്നു. അർഹത പരിശോധിക്കുമ്പോൾ ആവശ്യമായ രേഖകൾ അദ്ദേഹത്തിനില്ലെന്ന് മനസ്സിലാകുന്നു, എങ്കിലും അദ്ദേഹം വാങ്ങുമെന്ന പ്രതീക്ഷയിലാണ്. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(47, 4, 11, 'ಒಬ್ಬ ರೈತ ಆದಾಯ ಪ್ರಮಾಣಪತ್ರವಿಲ್ಲದೆ HF Deluxe ಅನ್ನು ಕಡಿಮೆ ಡೌನ್ ಪೇಮೆಂಟ್ ಯೋಜನೆಯಲ್ಲಿ ಖರೀದಿಸುವ ಬಗ್ಗೆ ವಿಚಾರಿಸುತ್ತಾನೆ. ಅರ್ಹತೆ ಪರಿಶೀಲನೆ ವೇಳೆ ಅವನು ಅಗತ್ಯ ದಾಖಲೆಗಳನ್ನು ಪೂರೈಸಿಲ್ಲ ಎಂಬುದು ಗೊತ್ತಾಗುತ್ತದೆ, ಆದರೂ ಅವನು ಖರೀದಿಯ ಬಗ್ಗೆ ಭರವಸೆ ಇಟ್ಟುಕೊಂಡಿದ್ದಾನೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(48, 4, 12, 'ଜଣେ ଚାଷୀ କୌଣସି ଆୟ ପ୍ରମାଣ ନଥାଇ HF Deluxe କୁ କମ୍ ଡାଉନ୍ ପେମେଣ୍ଟ ଯୋଜନାରେ କିଣିବା ବିଷୟରେ ପଚାରୁଛନ୍ତି। ଯୋଗ୍ୟତା ଯାଞ୍ଚ କରିବାବେଳେ ଦେଖାଯାଏ ଯେ ସେ ଆବଶ୍ୟକ ଡକ୍ୟୁମେଣ୍ଟ ପୂରଣ କରୁନାହାନ୍ତି, ତଥାପି ସେ କିଣିବାକୁ ଆଶାବାଦୀ। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(49, 5, 1, 'A customer booked a motorcycle and was informed of a two-week waiting period.\r\n\r\nAfter two weeks, he has received no update and visits the dealership upset, threatening to cancel the booking.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(50, 5, 2, 'एक कस्टमर ने बाइक बुक की थी और उसे दो हफ्ते की वेटिंग बताई गई थी। दो हफ्ते बाद भी उसे कोई अपडेट नहीं मिला, इसलिए वह नाराज़ होकर शोरूम आता है और बुकिंग कैंसल करने की धमकी देता है। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(51, 5, 3, 'ਇੱਕ ਕਸਟਮਰ ਨੇ ਮੋਟਰਸਾਈਕਲ ਬੁੱਕ ਕੀਤੀ ਸੀ ਅਤੇ ਉਸਨੂੰ ਦੋ ਹਫ਼ਤਿਆਂ ਦੀ ਵੈਟਿੰਗ ਦੱਸੀ ਗਈ ਸੀ। ਦੋ ਹਫ਼ਤਿਆਂ ਬਾਅਦ ਵੀ ਕੋਈ ਅਪਡੇਟ ਨਹੀਂ ਮਿਲਿਆ, ਇਸ ਲਈ ਉਹ ਨਾਰਾਜ਼ ਹੋ ਕੇ ਸ਼ੋਰੂਮ ਆਉਂਦਾ ਹੈ ਅਤੇ ਬੁਕਿੰਗ ਰੱਦ ਕਰਨ ਦੀ ਧਮਕੀ ਦਿੰਦਾ ਹੈ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(52, 5, 4, 'એક કસ્ટમરે બાઈક બુક કરી હતી અને તેને બે અઠવાડિયાની વેટિંગ જણાવવામાં આવી હતી. બે અઠવાડિયા પછી પણ કોઈ અપડેટ ન મળતા તે નારાજ થઈને ડીલરશિપ પર આવે છે અને બુકિંગ રદ કરવાની ધમકી આપે છે. આવી સ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(53, 5, 5, 'एका कस्टमरने मोटरसायकल बुक केली होती आणि त्याला दोन आठवड्यांची वेटिंग सांगण्यात आली होती. दोन आठवड्यांनंतरही कोणताही अपडेट मिळाला नाही, त्यामुळे तो नाराज होऊन शोरूममध्ये येतो आणि बुकिंग कॅन्सल करण्याची धमकी देतो. अशा परिस्थितीत तुम्ही कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(54, 5, 6, 'একজন কাস্টমার একটি মোটরসাইকেল বুক করেছিলেন এবং তাকে দুই সপ্তাহের ওয়েটিং পিরিয়ড জানানো হয়েছিল। দুই সপ্তাহ পরেও কোনো আপডেট না পেয়ে তিনি বিরক্ত হয়ে শোরুমে আসেন এবং বুকিং বাতিল করার হুমকি দেন। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(55, 5, 7, 'এজন কাষ্টমাৰে এখন মটৰচাইকেল বুক কৰিছিল আৰু তেওঁক দুই সপ্তাহৰ ৱেইটিং পিৰিয়ড কোৱা হৈছিল। দুই সপ্তাহ পিছতেও কোনো আপডেট নাপাই তেওঁ খং উঠি শোৰূমলৈ আহে আৰু বুকিং বাতিল কৰাৰ ভাবুকি দিয়ে। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(56, 5, 8, 'ஒரு கஸ்டமர் ஒரு பைக்கை புக் செய்து, இரண்டு வாரங்கள் காத்திருக்க வேண்டும் என்று தெரிவிக்கப்பட்டது. இரண்டு வாரங்கள் கடந்தும் எந்த அப்டேட்டும் கிடைக்காததால், அவர் கோபமாக ஷோரூமுக்கு வந்து புக்கிங்கை கேன்சல் செய்வதாக மிரட்டுகிறார். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(57, 5, 9, 'ఒక కస్టమర్ ఒక బైక్ బుక్ చేశాడు మరియు రెండు వారాల వెయిటింగ్ పీరియడ్ ఉందని చెప్పారు. రెండు వారాలు గడిచినా ఎలాంటి అప్‌డేట్ రాకపోవడంతో, అతను అసహనంగా షోరూమ్‌కి వచ్చి బుకింగ్ రద్దు చేస్తానని బెదిరిస్తున్నాడు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(58, 5, 10, 'ഒരു കസ്റ്റമർ ഒരു മോട്ടോർസൈക്കിൾ ബുക്ക് ചെയ്തു, രണ്ട് ആഴ്ച കാത്തിരിക്കണം എന്ന് അറിയിച്ചു. രണ്ട് ആഴ്ച കഴിഞ്ഞിട്ടും യാതൊരു അപ്ഡേറ്റും ലഭിക്കാത്തതിനെ തുടർന്ന്, അദ്ദേഹം അസ്വസ്ഥനായി ഷോറൂമിൽ എത്തി ബുക്കിംഗ് റദ്ദാക്കുമെന്ന് ഭീഷണിപ്പെടുത്തുന്നു. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(59, 5, 11, 'ಒಬ್ಬ ಕಸ್ಟಮರ್ ಒಂದು ಬೈಕ್ ಬುಕ್ ಮಾಡಿಕೊಂಡಿದ್ದಾನೆ ಮತ್ತು ಎರಡು ವಾರಗಳ ವೇಟಿಂಗ್ ಇದೆ ಎಂದು ತಿಳಿಸಲಾಗಿತ್ತು. ಎರಡು ವಾರಗಳು ಕಳೆದರೂ ಯಾವುದೇ ಅಪ್‌ಡೇಟ್ ಸಿಗದ ಕಾರಣ, ಅವನು ಅಸಮಾಧಾನಗೊಂಡು ಶೋರೂಮ್‌ಗೆ ಬಂದು ಬುಕ್ಕಿಂಗ್ ಕ್ಯಾನ್ಸಲ್ ಮಾಡ್ತೀನಿ ಅಂತ ಬೆದರಿಕೆ ಹಾಕ್ತಾನೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(60, 5, 12, 'ଜଣେ କଷ୍ଟମର ଏକ ମୋଟରସାଇକେଲ୍ ବୁକ୍ କରିଥିଲେ ଏବଂ ତାଙ୍କୁ ଦୁଇ ସପ୍ତାହର ୱେଟିଂ ପିରିଅଡ୍ କୁହାଯାଇଥିଲା। ଦୁଇ ସପ୍ତାହ ପରେ ମଧ୍ୟ କୌଣସି ଅପଡେଟ୍ ମିଳିନଥିବାରୁ ସେ ଅସନ୍ତୁଷ୍ଟ ହୋଇ ଶୋରୁମକୁ ଆସି ବୁକିଂ କ୍ୟାନସଲ୍ କରିବାକୁ ଧମକ ଦେଉଛନ୍ତି। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(61, 6, 1, 'A father and daughter visit the showroom for a scooter.\r\n\r\nThe daughter prefers a stylish and easy-to-ride scooter, while the father is concerned about safety and asks about tracking features.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(62, 6, 2, 'एक पिता और बेटी स्कूटर देखने के लिए शोरूम आते हैं। बेटी को स्टाइलिश और आसान चलाने वाला स्कूटर पसंद है, जबकि पिता सेफ्टी को लेकर चिंतित हैं और ट्रैकिंग फीचर्स के बारे में पूछते हैं। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(63, 6, 3, 'ਇੱਕ ਪਿਤਾ ਅਤੇ ਧੀ ਸਕੂਟਰ ਦੇਖਣ ਲਈ ਸ਼ੋਰੂਮ ਆਉਂਦੇ ਹਨ। ਧੀ ਨੂੰ ਸਟਾਈਲਿਸ਼ ਅਤੇ ਆਸਾਨ ਚਲਾਉਣ ਵਾਲਾ ਸਕੂਟਰ ਚਾਹੀਦਾ ਹੈ, ਜਦਕਿ ਪਿਤਾ ਸੇਫਟੀ ਬਾਰੇ ਚਿੰਤਤ ਹਨ ਅਤੇ ਟ੍ਰੈਕਿੰਗ ਫੀਚਰਾਂ ਬਾਰੇ ਪੁੱਛਦੇ ਹਨ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(64, 6, 4, 'એક પિતા અને દીકરી સ્કૂટર જોવા માટે શોરૂમમાં આવે છે. દીકરીને સ્ટાઇલિશ અને સરળ ચલાવવાનો સ્કૂટર પસંદ છે, જ્યારે પિતા સુરક્ષા અંગે ચિંતિત છે અને ટ્રેકિંગ ફીચર્સ વિશે પૂછે છે. આવી પરિસ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(65, 6, 5, 'एक वडील आणि मुलगी स्कूटर पाहण्यासाठी शोरूममध्ये येतात. मुलीला स्टायलिश आणि सहज चालवता येणारा स्कूटर हवा आहे, तर वडील सेफ्टीबद्दल चिंतित आहेत आणि ट्रॅकिंग फीचर्सबद्दल विचारतात. अशा परिस्थितीत तुम्ही कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(66, 6, 6, 'একজন বাবা ও মেয়ে স্কুটার দেখতে শোরুমে আসেন। মেয়েটি স্টাইলিশ ও সহজে চালানো যায় এমন স্কুটার পছন্দ করে, আর বাবা সেফটি নিয়ে চিন্তিত এবং ট্র্যাকিং ফিচার সম্পর্কে জানতে চান। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(67, 6, 7, 'এজন পিতৃ আৰু কন্যা স্কুটাৰ চাবলৈ শোৰূমলৈ আহে। কন্যাই ষ্টাইলিছ আৰু সহজে চলাব পৰা স্কুটাৰ পছন্দ কৰে, কিন্তু পিতৃয়ে সুৰক্ষাৰ বিষয়ে চিন্তিত আৰু ট্ৰেকিং ফিচাৰ সম্পৰ্কে সুধে। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(68, 6, 8, 'ஒரு தந்தையும் மகளும் ஸ்கூட்டர் பார்க்க ஷோரூமுக்கு வருகிறார்கள். மகளுக்கு ஸ்டைலிஷ் மற்றும் எளிதாக ஓட்டக்கூடிய ஸ்கூட்டர் வேண்டும், ஆனால் தந்தை பாதுகாப்பைப் பற்றி கவலைப்பட்டு ட்ராக்கிங் அம்சங்கள் குறித்து கேட்கிறார். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(69, 6, 9, 'ఒక తండ్రి మరియు కుమార్తె స్కూటర్ కోసం షోరూమ్‌కి వస్తారు. కుమార్తెకు స్టైలిష్ మరియు సులభంగా నడపగలిగే స్కూటర్ కావాలి, కానీ తండ్రి భద్రతపై ఆందోళన చెందుతూ ట్రాకింగ్ ఫీచర్ల గురించి అడుగుతున్నారు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(70, 6, 10, 'ഒരു അച്ഛനും മകളും സ്കൂട്ടർ കാണാൻ ഷോറൂമിൽ എത്തുന്നു. മകൾക്ക് സ്റ്റൈലിഷും എളുപ്പത്തിൽ ഓടിക്കാവുന്നതുമായ സ്കൂട്ടർ വേണം, എന്നാൽ അച്ഛൻ സുരക്ഷയെ കുറിച്ച് ആശങ്കപ്പെടുകയും ട്രാക്കിംഗ് ഫീച്ചറുകൾക്കുറിച്ച് ചോദിക്കുകയും ചെയ്യുന്നു. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(71, 6, 11, 'ಒಬ್ಬ ತಂದೆ ಮತ್ತು ಮಗಳು ಸ್ಕೂಟರ್ ನೋಡಲು ಶೋರೂಮ್‌ಗೆ ಬರುತ್ತಾರೆ. ಮಗಳಿಗೆ ಸ್ಟೈಲಿಶ್ ಮತ್ತು ಸುಲಭವಾಗಿ ಓಡಿಸಬಹುದಾದ ಸ್ಕೂಟರ್ ಬೇಕು, ಆದರೆ ತಂದೆ ಸೆಫ್ಟಿ ಬಗ್ಗೆ ಚಿಂತಿತರಾಗಿ ಟ್ರ್ಯಾಕಿಂಗ್ ಫೀಚರ್‌ಗಳ ಬಗ್ಗೆ ಕೇಳುತ್ತಾರೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(72, 6, 12, 'ଜଣେ ପିତା ଓ ଝିଅ ସ୍କୁଟର ଦେଖିବାକୁ ଶୋରୁମକୁ ଆସନ୍ତି। ଝିଅଙ୍କୁ ଷ୍ଟାଇଲିଶ୍ ଏବଂ ସହଜରେ ଚଳାଇ ପାରିବା ସ୍କୁଟର ଭଲ ଲାଗେ, କିନ୍ତୁ ପିତା ସୁରକ୍ଷା ନେଇ ଚିନ୍ତିତ ଓ ଟ୍ରାକିଂ ଫିଚର୍ସ ବିଷୟରେ ପଚାରନ୍ତି। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(73, 7, 1, 'A customer interested in the Glamour X is unsure about the Ride-By-Wire feature.\r\n\r\nHe says he prefers simple mechanical systems and is concerned about reliability since he hasn’t seen this in other commuter bikes.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(74, 7, 2, 'Glamour X में दिलचस्पी रखने वाला एक कस्टमर Ride-By-Wire फीचर को लेकर कन्फ्यूज है। वह कहता है कि उसे सिंपल मैकेनिकल सिस्टम ज़्यादा पसंद हैं और उसे भरोसे को लेकर चिंता है, क्योंकि उसने ये फीचर दूसरी कम्यूटर बाइक्स में नहीं देखा है। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(75, 7, 3, 'Glamour X ਵਿੱਚ ਦਿਲਚਸਪੀ ਰੱਖਣ ਵਾਲਾ ਇੱਕ ਕਸਟਮਰ Ride-By-Wire ਫੀਚਰ ਨੂੰ ਲੈ ਕੇ ਕਨਫਿਊਜ਼ ਹੈ। ਉਹ ਕਹਿੰਦਾ ਹੈ ਕਿ ਉਸਨੂੰ ਸਧਾਰਣ ਮਕੈਨੀਕਲ ਸਿਸਟਮ ਪਸੰਦ ਹਨ ਅਤੇ ਭਰੋਸੇਯੋਗਤਾ ਨੂੰ ਲੈ ਕੇ ਚਿੰਤਾ ਹੈ, ਕਿਉਂਕਿ ਉਸਨੇ ਇਹ ਫੀਚਰ ਹੋਰ ਕਮਿਊਟਰ ਬਾਈਕਾਂ ਵਿੱਚ ਨਹੀਂ ਵੇਖਿਆ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(76, 7, 4, 'Glamour Xમાં રસ ધરાવતો એક કસ્ટમર Ride-By-Wire ફીચર અંગે અસમંજસમાં છે. તે કહે છે કે તેને સરળ મિકેનિકલ સિસ્ટમ્સ વધારે પસંદ છે અને વિશ્વસનીયતા વિશે ચિંતા છે, કારણ કે તેણે આ ફીચર અન્ય કમ્યુટર બાઇકોમાં નથી જોયું. આવી સ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(77, 7, 5, 'Glamour X मध्ये रस असलेला एक कस्टमर Ride-By-Wire फीचरबद्दल संभ्रमात आहे. तो सांगतो की त्याला साधी मेकॅनिकल सिस्टीम आवडते आणि विश्वासार्हतेबद्दल चिंता वाटते, कारण त्याने हे फीचर इतर कम्युटर बाईक्समध्ये पाहिलेले नाही. अशा परिस्थितीत तुम्ही कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(78, 7, 6, 'Glamour X-এ আগ্রহী একজন কাস্টমার Ride-By-Wire ফিচার নিয়ে দ্বিধায় রয়েছেন। তিনি বলেন, তিনি সহজ মেকানিক্যাল সিস্টেম পছন্দ করেন এবং নির্ভরযোগ্যতা নিয়ে চিন্তিত, কারণ অন্য কমিউটার বাইকে তিনি এই ফিচার দেখেননি। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(79, 7, 7, 'Glamour X-ত আগ্ৰহী এজন কাষ্টমাৰ Ride-By-Wire ফিচাৰটো লৈ সন্দিহান। সি কয় যে সৰল মেকানিকেল ছিষ্টেম পছন্দ কৰে আৰু বিশ্বাসযোগ্যতাৰ বিষয়ে চিন্তিত, কিয়নো সি এই ফিচাৰটো আন কমিউটাৰ বাইকত দেখা নাই। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(80, 7, 8, 'Glamour X-ல் ஆர்வம் கொண்ட ஒரு கஸ்டமர் Ride-By-Wire அம்சம் குறித்து சந்தேகமாக இருக்கிறார். அவருக்கு சிம்பிள் மெக்கானிக்கல் சிஸ்டம் தான் பிடிக்கும் என்றும், மற்ற கம்யூட்டர் பைக்குகளில் இதைப் பார்த்ததில்லை என்பதால் நம்பகத்தன்மை குறித்து கவலைப்படுகிறார். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(81, 7, 9, 'Glamour X పై ఆసక్తి ఉన్న ఒక కస్టమర్ Ride-By-Wire ఫీచర్ గురించి సందేహంలో ఉన్నాడు. అతనికి సింపుల్ మెకానికల్ సిస్టమ్‌లు ఇష్టమని, ఇతర కమ్యూటర్ బైక్‌లలో ఈ ఫీచర్ చూడలేదని నమ్మకంపై ఆందోళన వ్యక్తం చేస్తున్నాడు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(82, 7, 10, 'Glamour X-ൽ താൽപര്യമുള്ള ഒരു കസ്റ്റമർ Ride-By-Wire ഫീച്ചറിനെക്കുറിച്ച് ആശങ്കയിലാണ്. ലളിതമായ മെക്കാനിക്കൽ സിസ്റ്റമാണ് ഇഷ്ടമെന്നും, മറ്റ് കമ്മ്യൂട്ടർ ബൈക്കുകളിൽ ഇത് കണ്ടിട്ടില്ലാത്തതിനാൽ വിശ്വാസ്യതയെ കുറിച്ച് ആശങ്കയുണ്ടെന്നും പറയുന്നു. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(83, 7, 11, 'Glamour X ನಲ್ಲಿ ಆಸಕ್ತಿ ಇರುವ ಒಬ್ಬ ಕಸ್ಟಮರ್ Ride-By-Wire ಫೀಚರ್ ಬಗ್ಗೆ ಸಂಶಯದಲ್ಲಿದ್ದಾನೆ. ಅವನಿಗೆ ಸರಳ ಮೆಕ್ಯಾನಿಕಲ್ ಸಿಸ್ಟಮ್‌ಗಳು ಇಷ್ಟ ಮತ್ತು ಇತರೆ ಕಮ್ಯೂಟರ್ ಬೈಕ್‌ಗಳಲ್ಲಿ ಈ ಫೀಚರ್ ನೋಡಿಲ್ಲವೆಂದು ನಂಬಿಕೆಗೆ ಸಂಬಂಧಿಸಿದ ಚಿಂತೆಯಿದೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(84, 7, 12, 'Glamour X ରେ ଆଗ୍ରହ ରଖୁଥିବା ଜଣେ କଷ୍ଟମର Ride-By-Wire ଫିଚର୍ ବିଷୟରେ ସନ୍ଦେହରେ ଅଛନ୍ତି। ସେ କହୁଛନ୍ତି ଯେ ସେ ସରଳ ମେକାନିକାଲ୍ ସିଷ୍ଟମ୍ ପସନ୍ଦ କରନ୍ତି ଏବଂ ଅନ୍ୟ କମ୍ୟୁଟର ବାଇକ୍‌ରେ ଏହି ଫିଚର୍ ଦେଖିନଥିବାରୁ ବିଶ୍ୱସନୀୟତା ନେଇ ଚିନ୍ତିତ। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(85, 8, 1, 'A recently married customer who has moved to the city already owns a small car and wants a two-wheeler for daily commuting.\r\n\r\nHe is confused between a commuter motorcycle (better mileage) and a scooter (more practical and usable by his wife). He is seeking guidance.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(86, 8, 2, 'हाल ही में शादीशुदा एक कस्टमर शहर में शिफ्ट हुआ है। उसके पास पहले से एक छोटी कार है और वह डेली कम्यूट के लिए टू-व्हीलर लेना चाहता है। वह कम्यूटर बाइक (ज्यादा माइलेज) और स्कूटर (ज्यादा प्रैक्टिकल, पत्नी भी चला सके) के बीच कन्फ्यूज है और गाइडेंस चाहता है। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(87, 8, 3, 'ਹਾਲ ਹੀ ਵਿੱਚ ਵਿਆਹਿਆ ਇੱਕ ਕਸਟਮਰ ਸ਼ਹਿਰ ਵਿੱਚ ਸ਼ਿਫਟ ਹੋਇਆ ਹੈ। ਉਸ ਕੋਲ ਪਹਿਲਾਂ ਤੋਂ ਇੱਕ ਛੋਟੀ ਕਾਰ ਹੈ ਅਤੇ ਉਹ ਰੋਜ਼ਾਨਾ ਆਵਾਜਾਈ ਲਈ ਟੂ-ਵ੍ਹੀਲਰ ਲੈਣਾ ਚਾਹੁੰਦਾ ਹੈ। ਉਹ ਕਮਿਊਟਰ ਬਾਈਕ (ਵਧੀਆ ਮਾਈਲੇਜ) ਅਤੇ ਸਕੂਟਰ (ਜ਼ਿਆਦਾ ਪ੍ਰੈਕਟਿਕਲ, ਪਤਨੀ ਵੀ ਚਲਾ ਸਕੇ) ਵਿਚਕਾਰ ਕਨਫਿਊਜ਼ ਹੈ ਅਤੇ ਗਾਈਡੈਂਸ ਮੰਗਦਾ ਹੈ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(88, 8, 4, 'હાલમાં જ લગ્ન થયેલા એક કસ્ટમર શહેરમાં શિફ્ટ થયો છે. તેની પાસે પહેલેથી જ એક નાની કાર છે અને તે રોજિંદા કમ્યુટ માટે ટૂ-વ્હીલર લેવા માંગે છે. તે કમ્યુટર બાઈક (વધુ માઈલેજ) અને સ્કૂટર (વધુ પ્રેક્ટિકલ, પત્ની પણ ચલાવી શકે) વચ્ચે ગુંચવાયો છે અને માર્ગદર્શન માંગે છે. આવી સ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(89, 8, 5, 'अलीकडेच लग्न झालेला एक कस्टमर शहरात शिफ्ट झाला आहे. त्याच्याकडे आधीच एक छोटी कार आहे आणि तो रोजच्या कम्युटसाठी टू-व्हीलर घ्यायचा विचार करत आहे. तो कम्युटर बाइक (जास्त मायलेज) आणि स्कूटर (जास्त प्रॅक्टिकल, पत्नीही वापरू शकेल) यामध्ये कन्फ्यूज आहे आणि मार्गदर्शन मागतो आहे. अशा परिस्थितीत तुम्ही कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(90, 8, 6, 'সাম্প্রতিকভাবে বিয়ে হওয়া একজন কাস্টমার শহরে শিফট হয়েছেন। তাঁর কাছে আগে থেকেই একটি ছোট গাড়ি আছে এবং তিনি দৈনন্দিন যাতায়াতের জন্য একটি টু-হুইলার নিতে চান। তিনি কমিউটার বাইক (ভালো মাইলেজ) আর স্কুটার (বেশি ব্যবহারযোগ্য, স্ত্রীও চালাতে পারবেন) এর মধ্যে কনফিউজ হয়ে গাইডেন্স চাইছেন। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(91, 8, 7, 'সাম্প্ৰতিকভাৱে বিবাহিত এজন কাষ্টমাৰ শহৰলৈ শিফ্ট হৈছে। তেওঁৰ আগতেই এখন সৰু গাড়ী আছে আৰু দৈনিক যাতায়াতৰ বাবে এটা টু-হুইলাৰ ল\'ব বিচাৰে। তেওঁ কমিউটাৰ বাইক (ভাল মাইলেজ) আৰু স্কুটাৰ (অধিক প্ৰেক্টিকেল, পত্নীয়েও চলাব পাৰে) মাজত বিভ্ৰান্ত হৈ গাইডেন্স বিচাৰে। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(92, 8, 8, 'சமீபத்தில் திருமணம் ஆன ஒரு கஸ்டமர் நகரத்துக்கு இடம்பெயர்ந்துள்ளார். அவரிடம் ஏற்கனவே ஒரு சிறிய கார் உள்ளது, தினசரி பயணத்திற்கு ஒரு டூ-வீலர் வாங்க நினைக்கிறார். கம்யூட்டர் பைக் (நல்ல மைலேஜ்) மற்றும் ஸ்கூட்டர் (அதிக பயன்பாடு, மனைவியும் ஓட்டலாம்) இரண்டிற்கும் இடையில் குழப்பத்தில் இருந்து வழிகாட்டல் கேட்கிறார். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(93, 8, 9, 'ఇటీవలే పెళ్లి అయిన ఒక కస్టమర్ నగరానికి మారాడు. అతనికి ఇప్పటికే ఒక చిన్న కారు ఉంది మరియు రోజువారీ ప్రయాణాల కోసం టూ-వీలర్ కొనాలని చూస్తున్నాడు. అతను కమ్యూటర్ బైక్ (మంచి మైలేజ్) మరియు స్కూటర్ (ఎక్కువ ఉపయోగకరం, భార్య కూడా నడపవచ్చు) మధ్య అయోమయంలో ఉండి మార్గదర్శనం కోరుతున్నాడు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(94, 8, 10, 'സമീപകാലത്ത് വിവാഹിതനായ ഒരു കസ്റ്റമർ നഗരത്തിലേക്ക് താമസം മാറിയിട്ടുണ്ട്. അദ്ദേഹത്തിന് ഇതിനകം ഒരു ചെറിയ കാർ ഉണ്ട്, ദിവസേനയുള്ള യാത്രയ്ക്കായി ഒരു ടു-വീലർ വാങ്ങാൻ ആഗ്രഹിക്കുന്നു. കമ്മ്യൂട്ടർ ബൈക്ക് (കൂടുതൽ മൈലേജ്)യും സ്കൂട്ടർ (കൂടുതൽ പ്രായോഗികം, ഭാര്യക്കും ഉപയോഗിക്കാം)യും തമ്മിൽ ആശയക്കുഴപ്പത്തിലാണ്, മാർഗനിർദ്ദേശം തേടുന്നു. ഈ സാഹചര്യത്തെ നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(95, 8, 11, 'ಇತ್ತೀಚೆಗೆ ಮದುವೆಯಾದ ಒಬ್ಬ ಕಸ್ಟಮರ್ ನಗರಕ್ಕೆ ಶಿಫ್ಟ್ ಆಗಿದ್ದಾನೆ. ಅವನಿಗೆ ಈಗಾಗಲೇ ಒಂದು ಸಣ್ಣ ಕಾರು ಇದೆ ಮತ್ತು ದಿನನಿತ್ಯದ ಪ್ರಯಾಣಕ್ಕೆ ಟೂ-ವೀಲರ್ ಖರೀದಿಸಲು ಬಯಸುತ್ತಾನೆ. ಅವನು ಕಮ್ಯೂಟರ್ ಬೈಕ್ (ಉತ್ತಮ ಮೈಲೇಜ್) ಮತ್ತು ಸ್ಕೂಟರ್ (ಹೆಚ್ಚು ಪ್ರಾಯೋಗಿಕ, ಹೆಂಡತিও ಬಳಸಬಹುದು) ನಡುವೆ ಗೊಂದಲದಲ್ಲಿದ್ದು ಮಾರ್ಗದರ್ಶನ ಕೇಳುತ್ತಿದ್ದಾನೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(96, 8, 12, 'ସମ୍ପ୍ରତି ବିବାହିତ ଜଣେ କଷ୍ଟମର ସହରକୁ ସ୍ଥାନାନ୍ତର ହୋଇଛନ୍ତି। ତାଙ୍କ ପାଖରେ ପୂର୍ବରୁ ଏକ ଛୋଟ କାର୍ ଅଛି ଏବଂ ଦୈନିକ ଯାତାୟାତ ପାଇଁ ଏକ ଟୁ-ହ୍ୱିଲର୍ କିଣିବାକୁ ଚାହୁଁଛନ୍ତି। ସେ କମ୍ୟୁଟର୍ ବାଇକ୍ (ଭଲ ମାଇଲେଜ୍) ଓ ସ୍କୁଟର୍ (ଅଧିକ ପ୍ରାୟୋଗିକ, ପତ୍ନୀ ମଧ୍ୟ ବ୍ୟବହାର କରିପାରିବେ) ମଧ୍ୟରେ ଦ୍ୱନ୍ଦ୍ୱରେ ଅଛନ୍ତି ଏବଂ ମାର୍ଗଦର୍ଶନ ଚାହୁଁଛନ୍ତି। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(97, 9, 1, 'A father and son visit the dealership to purchase a motorcycle. The father prefers the Glamour (familiar and simple), while the son wants the Glamour X for its newer design and features at a marginally higher price.\r\n\r\nThe father is not open to change and asks for your suggestion.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(98, 9, 2, 'एक पिता और बेटा बाइक खरीदने के लिए डीलरशिप पर आते हैं। पिता Glamour को पसंद करते हैं क्योंकि वह उन्हें जानी-पहचानी और सिंपल लगती है, जबकि बेटा थोड़ी ज़्यादा कीमत पर नए डिजाइन और फीचर्स वाली Glamour X चाहता है। पिता बदलाव के लिए तैयार नहीं हैं और आपसे सलाह मांगते हैं। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(99, 9, 3, 'ਇੱਕ ਪਿਤਾ ਅਤੇ ਪੁੱਤਰ ਮੋਟਰਸਾਈਕਲ ਖਰੀਦਣ ਲਈ ਡੀਲਰਸ਼ਿਪ ਆਉਂਦੇ ਹਨ। ਪਿਤਾ Glamour ਨੂੰ ਤਰਜੀਹ ਦਿੰਦੇ ਹਨ ਕਿਉਂਕਿ ਉਹ ਉਨ੍ਹਾਂ ਲਈ ਜਾਣੀ-ਪਹਚਾਣੀ ਅਤੇ ਸਧਾਰਣ ਹੈ, ਜਦਕਿ ਪੁੱਤਰ ਥੋੜ੍ਹੀ ਵੱਧ ਕੀਮਤ ’ਤੇ ਨਵੇਂ ਡਿਜ਼ਾਇਨ ਅਤੇ ਫੀਚਰਾਂ ਵਾਲੀ Glamour X ਚਾਹੁੰਦਾ ਹੈ। ਪਿਤਾ ਬਦਲਾਅ ਲਈ ਤਿਆਰ ਨਹੀਂ ਹਨ ਅਤੇ ਤੁਹਾਡੀ ਸਲਾਹ ਮੰਗਦੇ ਹਨ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(100, 9, 4, 'એક પિતા અને પુત્ર મોટરસાયકલ ખરીદવા માટે ડીલરશિપ પર આવે છે. પિતાને Glamour પસંદ છે કારણ કે તે તેમને ઓળખીતી અને સરળ લાગે છે, જ્યારે પુત્ર થોડા વધારે ભાવે નવા ડિઝાઇન અને ફીચર્સવાળી Glamour X ઇચ્છે છે. પિતા બદલાવ માટે તૈયાર નથી અને તમારી સલાહ માંગે છે. આવી સ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(101, 9, 5, 'एक वडील आणि मुलगा मोटरसायकल खरेदीसाठी डीलरशिपवर येतात. वडिलांना Glamour आवडते कारण ती ओळखीची आणि सोपी आहे, तर मुलाला थोड्या जास्त किमतीत नवीन डिझाइन आणि फीचर्स असलेली Glamour X हवी आहे. वडील बदलासाठी तयार नाहीत आणि तुमच्याकडून सल्ला मागतात. अशा परिस्थितीत तुम्ही कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(102, 9, 6, 'একজন বাবা ও ছেলে মোটরসাইকেল কিনতে ডিলারশিপে আসেন। বাবা Glamour পছন্দ করেন কারণ এটি পরিচিত ও সহজ, আর ছেলে সামান্য বেশি দামে নতুন ডিজাইন ও ফিচারসহ Glamour X চায়। বাবা পরিবর্তনে আগ্রহী নন এবং আপনার পরামর্শ চান। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(103, 9, 7, 'এজন পিতৃ আৰু পুত্ৰ মটৰচাইকেল কিনিবলৈ ডীলাৰশ্বিপলৈ আহে। পিতৃয়ে Glamour পছন্দ কৰে কিয়নো ই চিনাকী আৰু সহজ, কিন্তু পুত্ৰই অলপ বেছি মূল্যত নতুন ডিজাইন আৰু ফিচাৰ থকা Glamour X বিচাৰে। পিতৃয়ে পৰিবৰ্তন মানি ল’বলৈ আগ্ৰহী নহয় আৰু আপোনাৰ পৰামৰ্শ বিচাৰে। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(104, 9, 8, 'ஒரு தந்தையும் மகனும் மோட்டார் சைக்கிள் வாங்க டீலர்ஷிப்புக்கு வருகிறார்கள். தந்தைக்கு பரிச்சயமானதும் எளிமையானதுமான Glamour பிடிக்கிறது, ஆனால் மகன் சிறிது கூடுதல் விலையில் புதிய டிசைன் மற்றும் அம்சங்கள் கொண்ட Glamour X-ஐ விரும்புகிறான். தந்தை மாற்றத்திற்கு தயாராக இல்லை மற்றும் உங்கள் ஆலோசனையை கேட்கிறார். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(105, 9, 9, 'ఒక తండ్రి మరియు కుమారుడు మోటార్‌సైకిల్ కొనడానికి డీలర్‌షిప్‌కి వస్తారు. తండ్రికి Glamour పరిచయమైనదిగా, సింపుల్‌గా ఉండటంతో ఇష్టం, కానీ కుమారుడు కొంచెం ఎక్కువ ధరకు కొత్త డిజైన్ మరియు ఫీచర్లు ఉన్న Glamour X కోరుకుంటున్నాడు. తండ్రి మార్పుకు సిద్ధంగా లేక మీ సలహా అడుగుతున్నారు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(106, 9, 10, 'ഒരു അച്ഛനും മകനും മോട്ടോർസൈക്കിൾ വാങ്ങാൻ ഡീലർഷിപ്പിൽ എത്തുന്നു. അച്ഛന് പരിചിതവും ലളിതവുമായ Glamour ഇഷ്ടമാണ്, എന്നാൽ മകൻ കുറച്ച് അധിക വിലക്ക് പുതിയ ഡിസൈനും ഫീച്ചറുകളും ഉള്ള Glamour X ആഗ്രഹിക്കുന്നു. അച്ഛൻ മാറ്റത്തിന് തയ്യാറല്ലാതെ നിങ്ങളുടെ നിർദ്ദേശം ചോദിക്കുന്നു. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(107, 9, 11, 'ಒಬ್ಬ ತಂದೆ ಮತ್ತು ಮಗ ಮೋಟಾರ್‌ಸೈಕಲ್ ಖರೀದಿಸಲು ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಬರುತ್ತಾರೆ. ತಂದೆಗೆ ಪರಿಚಿತ ಮತ್ತು ಸರಳವಾದ Glamour ಇಷ್ಟವಾಗುತ್ತದೆ, ಆದರೆ ಮಗ ಸ್ವಲ್ಪ ಹೆಚ್ಚುವರಿ ಬೆಲೆಗೆ ಹೊಸ ಡಿಸೈನ್ ಮತ್ತು ಫೀಚರ್‌ಗಳಿರುವ Glamour X ಅನ್ನು ಬಯಸುತ್ತಾನೆ. ತಂದೆ ಬದಲಾವಣೆಗೆ ಸಿದ್ಧರಾಗಿಲ್ಲ ಮತ್ತು ನಿಮ್ಮ ಸಲಹೆ ಕೇಳುತ್ತಾರೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(108, 9, 12, 'ଜଣେ ପିତା ଓ ପୁଅ ମୋଟରସାଇକେଲ୍ କିଣିବା ପାଇଁ ଡିଲର୍‌ଶିପ୍‌କୁ ଆସନ୍ତି। ପିତା Glamour କୁ ପସନ୍ଦ କରନ୍ତି କାରଣ ସେଟା ପରିଚିତ ଏବଂ ସରଳ, ଯେତେବେଳେ ପୁଅ ସାନା ଅଧିକ ଦାମରେ ନୂଆ ଡିଜାଇନ୍ ଓ ଫିଚର୍‌ସ୍‌ ଥିବା Glamour X ଚାହୁଁଛନ୍ତି। ପିତା ପରିବର୍ତ୍ତନ ପାଇଁ ପ୍ରସ୍ତୁତ ନୁହେଁ ଏବଂ ଆପଣଙ୍କ ସୁପାରିଶ ଚାହୁଁଛନ୍ତି। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(109, 10, 1, 'A young customer visits the dealership looking for a sporty scooter and shows interest in the Xoom 110.\r\n\r\nBased on his preferences, you see an opportunity to recommend the Xoom 125.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(110, 10, 2, 'एक युवा कस्टमर स्पोर्टी स्कूटर ढूंढते हुए डीलरशिप पर आता है और Xoom 110 में इंटरेस्ट दिखाता है। उसकी पसंद को देखते हुए आपको Xoom 125 रिकमेंड करने का मौका दिखता है। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(111, 10, 3, 'ਇੱਕ ਨੌਜਵਾਨ ਕਸਟਮਰ ਸਪੋਰਟੀ ਸਕੂਟਰ ਦੀ ਖੋਜ ਵਿੱਚ ਡੀਲਰਸ਼ਿਪ ਆਉਂਦਾ ਹੈ ਅਤੇ Xoom 110 ਵਿੱਚ ਦਿਲਚਸਪੀ ਦਿਖਾਉਂਦਾ ਹੈ। ਉਸ ਦੀ ਪਸੰਦ ਦੇ ਆਧਾਰ ’ਤੇ ਤੁਹਾਨੂੰ Xoom 125 ਦੀ ਸਿਫ਼ਾਰਸ਼ ਕਰਨ ਦਾ ਮੌਕਾ ਨਜ਼ਰ ਆਉਂਦਾ ਹੈ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(112, 10, 4, 'એક યુવાન કસ્ટમર સ્પોર્ટી સ્કૂટર શોધતા ડીલરશિપ પર આવે છે અને Xoom 110 માં રસ બતાવે છે. તેની પસંદગીને ધ્યાનમાં લઈ તમને Xoom 125 રિકમેન્ડ કરવાની તક દેખાય છે. આવી સ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(113, 10, 5, 'एक तरुण कस्टमर स्पोर्टी स्कूटर शोधत डीलरशिपवर येतो आणि Xoom 110 मध्ये इंटरेस्ट दाखवतो. त्याच्या पसंतीनुसार तुम्हाला Xoom 125 सुचवण्याची संधी दिसते. अशा परिस्थितीत तुम्ही कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(114, 10, 6, 'একজন তরুণ কাস্টমার স্পোর্টি স্কুটার খুঁজতে ডিলারশিপে আসে এবং Xoom 110-এ আগ্রহ দেখায়। তার পছন্দ অনুযায়ী আপনি Xoom 125 রেকমেন্ড করার সুযোগ দেখতে পান। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(115, 10, 7, 'এজন যুৱ কাষ্টমাৰ স্পোৰ্টী স্কুটাৰ বিচাৰি ডীলাৰশ্বিপলৈ আহে আৰু Xoom 110-ত আগ্ৰহ দেখুৱায়। তাৰ পছন্দৰ ওপৰত ভিত্তি কৰি আপুনি Xoom 125 ৰ পৰামৰ্শ দিব পৰা সুযোগ দেখে। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(116, 10, 8, 'ஒரு இளம் கஸ்டமர் ஸ்போர்ட்டி ஸ்கூட்டர் தேடி டீலர்ஷிப்புக்கு வந்து Xoom 110-ல் ஆர்வம் காட்டுகிறார். அவருடைய விருப்பங்களை பார்த்து Xoom 125-ஐ ரெக்கமெண்ட் செய்ய வாய்ப்பு இருப்பதாக நீங்கள் நினைக்கிறீர்கள். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(117, 10, 9, 'ఒక యువ కస్టమర్ స్పోర్టీ స్కూటర్ కోసం డీలర్‌షిప్‌కు వచ్చి Xoom 110 పై ఆసక్తి చూపిస్తున్నాడు. అతని అభిరుచులను బట్టి మీరు Xoom 125 ని సిఫారసు చేసే అవకాశం ఉందని చూస్తున్నారు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(118, 10, 10, 'ഒരു യുവ കസ്റ്റമർ സ്പോർട്ടി സ്കൂട്ടർ അന്വേഷിച്ച് ഡീലർഷിപ്പിലെത്തി Xoom 110-ൽ താൽപര്യം കാണിക്കുന്നു. അദ്ദേഹത്തിന്റെ ഇഷ്ടങ്ങൾ പരിഗണിച്ച് Xoom 125 ശുപാർശ ചെയ്യാനുള്ള അവസരം നിങ്ങൾക്ക് കാണാം. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(119, 10, 11, 'ಒಬ್ಬ ಯುವ ಕಸ್ಟಮರ್ ಸ್ಪೋರ್ಟಿ ಸ್ಕೂಟರ್ ಹುಡುಕುತ್ತಾ ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಬಂದು Xoom 110 ಬಗ್ಗೆ ಆಸಕ್ತಿ ತೋರಿಸುತ್ತಾನೆ. ಅವನ ಇಷ್ಟಗಳನ್ನು ಗಮನಿಸಿದರೆ Xoom 125 ಅನ್ನು ಶಿಫಾರಸು ಮಾಡುವ ಅವಕಾಶ ನಿಮಗೆ ಕಾಣುತ್ತದೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(120, 10, 12, 'ଜଣେ ଯୁବ କଷ୍ଟମର ସ୍ପୋର୍ଟି ସ୍କୁଟର ଖୋଜି ଡିଲର୍‌ଶିପ୍‌କୁ ଆସି Xoom 110 ଉପରେ ଆଗ୍ରହ ଦେଖାଉଛନ୍ତି। ତାଙ୍କ ପସନ୍ଦ ଆଧାରରେ ଆପଣ Xoom 125 ସୁପାରିଶ କରିବାର ସୁଯୋଗ ଦେଖୁଛନ୍ତି। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:17', 'Active'),
	(121, 11, 1, 'A college student visits the dealership interested in the Xoom 125 and asks for an immediate test ride.\r\n\r\nDuring verification, you notice he does not have a valid driving license but insists he regularly rides inside campus. He seems very serious about purchasing the scooter.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(122, 11, 2, 'एक कॉलेज स्टूडेंट Xoom 125 में इंटरेस्ट लेकर शोरूम आता है और तुरंत टेस्ट राइड मांगता है।\r\nवेरिफिकेशन के दौरान आपको पता चलता है कि उसके पास वैध ड्राइविंग लाइसेंस नहीं है, लेकिन वह कहता है कि वह कैंपस के अंदर रेगुलर स्कूटर चलाता है। वह खरीदने को लेकर काफ़ी सीरियस लगता है।\r\nऐसी सिचुएशन में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(123, 11, 3, 'ਇੱਕ ਕਾਲਜ ਸਟੂਡੈਂਟ Xoom 125 ਵਿੱਚ ਦਿਲਚਸਪੀ ਲੈ ਕੇ ਸ਼ੋਰੂਮ ਆਉਂਦਾ ਹੈ ਅਤੇ ਤੁਰੰਤ ਟੈਸਟ ਰਾਈਡ ਮੰਗਦਾ ਹੈ।\r\nਚੈਕ ਕਰਨ ਤੇ ਪਤਾ ਲੱਗਦਾ ਹੈ ਕਿ ਉਸ ਕੋਲ ਵੈਧ ਡਰਾਈਵਿੰਗ ਲਾਇਸੈਂਸ ਨਹੀਂ ਹੈ, ਪਰ ਉਹ ਕਹਿੰਦਾ ਹੈ ਕਿ ਉਹ ਕੈਂਪਸ ਦੇ ਅੰਦਰ ਰੈਗੂਲਰ ਸਕੂਟਰ ਚਲਾਉਂਦਾ ਹੈ। ਉਹ ਖਰੀਦਣ ਲਈ ਕਾਫ਼ੀ ਸੀਰੀਅਸ ਹੈ।\r\nਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(124, 11, 4, 'એક કોલેજ સ્ટુડન્ટ Xoom 125માં રસ લઈને શોરૂમમાં આવે છે અને તરત જ ટેસ્ટ રાઇડ માંગે છે।\r\nવેરિફિકેશન દરમિયાન ખબર પડે છે કે તેની પાસે માન્ય ડ્રાઇવિંગ લાઇસન્સ નથી, છતાં તે કહે છે કે તે કેમ્પસની અંદર નિયમિત ચલાવે છે. તે ખરીદી માટે ખૂબ જ સિરિયસ છે।\r\nઆ પરિસ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(125, 11, 5, 'एक कॉलेज स्टुडंट Xoom 125 मध्ये इंटरेस्ट घेऊन शोरूममध्ये येतो आणि लगेच टेस्ट राइड मागतो.\r\nवेरिफिकेशनमध्ये दिसतं की त्याच्याकडे वैध ड्रायव्हिंग लायसन्स नाही, पण तो म्हणतो की तो कॅम्पसमध्ये रेग्युलर गाडी चालवतो. तो खरेदीबाबत खूप सिरीयस आहे.\r\nअशा परिस्थितीत तुम्ही हे कसं हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(126, 11, 6, 'একজন কলেজ স্টুডেন্ট Xoom 125 নিয়ে আগ্রহ দেখিয়ে শোরুমে আসে এবং সঙ্গে সঙ্গে টেস্ট রাইড চায়।\r\nভেরিফিকেশনের সময় দেখা যায় তার কাছে বৈধ ড্রাইভিং লাইসেন্স নেই, কিন্তু সে বলে যে সে ক্যাম্পাসের ভিতরে নিয়মিত চালায়। সে কিনতে খুবই সিরিয়াস।\r\nএই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(127, 11, 7, 'এজন কলেজৰ ছাত্ৰ Xoom 125-ত আগ্ৰহ লৈ শোৰূমলৈ আহে আৰু তৎক্ষণাৎ টেষ্ট ৰাইড বিচাৰে।\r\nভেৰিফিকেশ্যনত দেখা যায় যে তাৰ ওচৰত বৈধ ড্ৰাইভিং লাইচেঞ্চ নাই, কিন্তু সি কয় যে কেম্পাছৰ ভিতৰত নিয়মিত চলাই থাকে। সি কিনাৰ ক্ষেত্ৰত বহুত চিৰিয়াছ।\r\nএই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(128, 11, 8, 'ஒரு கல்லூரி மாணவர் Xoom 125-ல் ஆர்வம் கொண்டு ஷோரூமுக்கு வந்து உடனே டெஸ்ட் ரைடு கேட்கிறார்.\r\nசரிபார்ப்பில் அவரிடம் செல்லுபடியாகும் டிரைவிங் லைசென்ஸ் இல்லை என்பது தெரிய வருகிறது, ஆனாலும் கேம்பஸுக்குள் அடிக்கடி ஓட்டுவதாக சொல்கிறார். அவர் வாங்குவதில் ரொம்ப சீரியஸாக இருக்கிறார்.\r\nஇந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(129, 11, 9, 'ஒரு கல்லூரி மாணவர் Xoom 125-ல் ஆர்வம் கொண்டு ஷோரூமுக்கு வந்து உடனே டெஸ்ட் ரைடு கேட்கிறார்.\r\nசரிபார்ப்பில் அவரிடம் செல்லுபடியாகும் டிரைவிங் லைசென்ஸ் இல்லை என்பது தெரிய வருகிறது, ஆனாலும் கேம்பஸுக்குள் அடிக்கடி ஓட்டுவதாக சொல்கிறார். அவர் வாங்குவதில் ரொம்ப சீரியஸாக இருக்கிறார்.\r\nஇந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(130, 11, 10, 'ഒരു കോളേജ് വിദ്യാർത്ഥി Xoom 125-ൽ താൽപര്യം കാണിച്ച് ഷോറൂമിലേക്ക് വന്ന് ഉടൻ തന്നെ ടെസ്റ്റ് റൈഡ് ചോദിക്കുന്നു.\r\nപരിശോധനയിൽ അദ്ദേഹത്തിന് സാധുവായ ഡ്രൈവിംഗ് ലൈസൻസ് ഇല്ലെന്ന് മനസ്സിലാകുന്നു, എന്നാൽ ക്യാമ്പസിനുള്ളിൽ സ്ഥിരമായി ഓടിക്കുന്നുണ്ടെന്ന് പറയുന്നു. വാങ്ങുന്നതിൽ അദ്ദേഹം വളരെ സീരിയസാണ്.\r\nഈ സാഹചര്യത്തെ നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(131, 11, 11, 'ಒಬ್ಬ ಕಾಲೇಜು ಸ್ಟೂಡೆಂಟ್ Xoom 125 ಬಗ್ಗೆ ಆಸಕ್ತಿಯಿಂದ ಶೋರೂಮ್‌ಗೆ ಬಂದು ತಕ್ಷಣ ಟೆಸ್ಟ್ ರೈಡ್ ಕೇಳ್ತಾನೆ.\r\nವೆರಿಫಿಕೇಶನ್‌ನಲ್ಲಿ ಅವನ ಬಳಿ ಮಾನ್ಯವಾದ ಡ್ರೈವಿಂಗ್ ಲೈಸೆನ್ಸ್ ಇಲ್ಲ ಅನ್ನೋದು ಗೊತ್ತಾಗುತ್ತೆ, ಆದ್ರೆ ಕ್ಯಾಂಪಸ್ ಒಳಗೆ ರೆಗ್ಯುಲರ್ ಆಗಿ ಓಡಿಸ್ತೀನಿ ಅಂತ ಹೇಳ್ತಾನೆ. ಖರೀದಿಗೆ ತುಂಬಾ ಸೀರಿಯಸ್ ಆಗಿದ್ದಾನೆ.\r\nಈ ಸಿಚ್ಯುಯೇಷನ್‌ನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(132, 11, 12, 'ଜଣେ କଲେଜ୍ ଛାତ୍ର Xoom 125 ରେ ଆଗ୍ରହ ନେଇ ଶୋରୁମକୁ ଆସି ତୁରନ୍ତ ଟେଷ୍ଟ ରାଇଡ୍ ଚାହୁଁଛନ୍ତି।\r\nଭେରିଫିକେସନ୍‌ ସମୟରେ ଦେଖାଯାଏ ଯେ ତାଙ୍କ ପାଖରେ ବ valid ଧ ଡ୍ରାଇଭିଂ ଲାଇସେନ୍ସ ନାହିଁ, କିନ୍ତୁ ସେ କହୁଛନ୍ତି ଯେ କ୍ୟାମ୍ପସ୍‌ ଭିତରେ ସେ ନିୟମିତ ଚଳାନ୍ତି। ସେ କିଣିବା ପାଇଁ ବହୁତ ସିରିଅସ୍‌।\r\nଏମିତି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(133, 12, 1, 'A customer booked an Xtreme 125R Dual Channel ABS for his son’s birthday delivery.\r\n\r\nThe chosen colour will arrive three days late, but the same variant is available in other colours today.\r\n\r\nThe customer is upset and insists on delivery on the promised date.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(134, 12, 2, 'एक कस्टमर ने अपने बेटे के बर्थडे डिलीवरी के लिए Xtreme 125R ड्यूल चैनल ABS बुक किया है। चुना हुआ कलर तीन दिन लेट आएगा, लेकिन वही वैरिएंट दूसरे कलर्स में आज उपलब्ध है। कस्टमर नाराज़ है और तय तारीख पर ही डिलीवरी चाहता है। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(135, 12, 3, 'ਇੱਕ ਕਸਟਮਰ ਨੇ ਆਪਣੇ ਪੁੱਤਰ ਦੇ ਜਨਮਦਿਨ ਲਈ Xtreme 125R ਡਿਊਅਲ ਚੈਨਲ ABS ਬੁੱਕ ਕੀਤਾ ਹੈ। ਚੁਣਿਆ ਹੋਇਆ ਰੰਗ ਤਿੰਨ ਦਿਨ ਦੇਰ ਨਾਲ ਆਵੇਗਾ, ਪਰ ਉਹੀ ਵੈਰੀਐਂਟ ਹੋਰ ਰੰਗਾਂ ਵਿੱਚ ਅੱਜ ਉਪਲਬਧ ਹੈ। ਕਸਟਮਰ ਨਾਰਾਜ਼ ਹੈ ਅਤੇ ਵਾਅਦੇ ਵਾਲੀ ਤਾਰੀਖ਼ ਤੇ ਹੀ ਡਿਲਿਵਰੀ ਚਾਹੁੰਦਾ ਹੈ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(136, 12, 4, 'એક કસ્ટમરે તેના દીકરાના જન્મદિવસ માટે Xtreme 125R ડ્યુઅલ ચેનલ ABS બુક કરી છે. પસંદ કરેલો રંગ ત્રણ દિવસ મોડો આવશે, પરંતુ એ જ વેરિઅન્ટ બીજા રંગોમાં આજે ઉપલબ્ધ છે. કસ્ટમર નારાજ છે અને વચન આપેલી તારીખે જ ડિલિવરી માંગે છે. આવી પરિસ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(137, 12, 5, 'एका कस्टमरने आपल्या मुलाच्या वाढदिवसासाठी Xtreme 125R ड्युअल चॅनल ABS बुक केली आहे. निवडलेला रंग तीन दिवस उशिरा येणार आहे, पण तोच व्हेरिएंट इतर रंगांमध्ये आज उपलब्ध आहे. कस्टमर नाराज आहे आणि दिलेल्या तारखेलाच डिलिव्हरी हवी आहे. अशा परिस्थितीत तुम्ही कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(138, 12, 6, 'একজন কাস্টমার তার ছেলের জন্মদিনের জন্য Xtreme 125R ডুয়াল চ্যানেল ABS বুক করেছেন। পছন্দের রংটি তিন দিন দেরিতে আসবে, কিন্তু একই ভ্যারিয়েন্ট অন্য রঙে আজই পাওয়া যাচ্ছে। কাস্টমার বিরক্ত এবং প্রতিশ্রুত তারিখেই ডেলিভারি চান। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(139, 12, 7, 'এজন কাষ্টমাৰে তেওঁৰ পুত্ৰৰ জন্মদিনৰ বাবে Xtreme 125R ডুৱেল চেনেল ABS বুক কৰিছে। বাছনি কৰা ৰংটো তিনিদিন পলমকৈ আহিব, কিন্তু একে ভেৰিয়েণ্ট আন ৰঙত আজি উপলব্ধ। কাষ্টমাৰ খং উঠিছে আৰু প্ৰতিশ্ৰুতি দিয়া তাৰিখতেই ডেলিভাৰী বিচাৰে। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(140, 12, 8, 'ஒரு கஸ்டமர் தன் மகனின் பிறந்தநாள் டெலிவரிக்காக Xtreme 125R Dual Channel ABS-ஐ புக் செய்துள்ளார். அவர் தேர்ந்தெடுத்த நிறம் மூன்று நாட்கள் தாமதமாக வரும், ஆனால் அதே வேரியண்ட் மற்ற நிறங்களில் இன்று கிடைக்கிறது. கஸ்டமர் கோபமாக இருந்து, வாக்குறுதி கொடுத்த தேதியிலேயே டெலிவரி வேண்டும் என்று கேட்கிறார். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(141, 12, 9, 'ఒక కస్టమర్ తన కుమారుడి పుట్టినరోజు డెలివరీ కోసం Xtreme 125R డ్యూయల్ ఛానల్ ABS బుక్ చేశారు. ఎంపిక చేసిన రంగు మూడు రోజులు ఆలస్యంగా వస్తుంది, కానీ అదే వేరియంట్ ఇతర రంగుల్లో ఈరోజే అందుబాటులో ఉంది. కస్టమర్ అసహనంగా ఉండి, హామీ ఇచ్చిన తేదీననే డెలివరీ కావాలని అంటున్నారు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(142, 12, 10, 'ഒരു കസ്റ്റമർ തന്റെ മകന്റെ പിറന്നാൾ ഡെലിവറിക്കായി Xtreme 125R ഡ്യുവൽ ചാനൽ ABS ബുക്ക് ചെയ്തിട്ടുണ്ട്. തിരഞ്ഞെടുത്ത നിറം മൂന്ന് ദിവസം വൈകിയാണ് എത്തുക, എന്നാൽ അതേ വേരിയന്റ് മറ്റ് നിറങ്ങളിൽ ഇന്ന് തന്നെ ലഭ്യമാണ്. കസ്റ്റമർ അസ്വസ്ഥനായി, വാഗ്ദാനം ചെയ്ത തീയതിയിൽ തന്നെ ഡെലിവറി വേണമെന്ന് ആവശ്യപ്പെടുന്നു. ഈ സാഹചര്യത്തെ നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(143, 12, 11, 'ಒಬ್ಬ ಕಸ್ಟಮರ್ ತನ್ನ ಮಗನ ಹುಟ್ಟುಹಬ್ಬದ ಡೆಲಿವರಿಗಾಗಿ Xtreme 125R ಡ್ಯುಯಲ್ ಚಾನೆಲ್ ABS ಬುಕ್ ಮಾಡಿದ್ದಾರೆ. ಆಯ್ಕೆ ಮಾಡಿದ ಬಣ್ಣ ಮೂರು ದಿನ ತಡವಾಗಿ ಬರಲಿದೆ, ಆದರೆ ಅದೇ ವೇರಿಯಂಟ್ ಇತರ ಬಣ್ಣಗಳಲ್ಲಿ ಇಂದು ಲಭ್ಯವಿದೆ. ಕಸ್ಟಮರ್ ಅಸಮಾಧಾನಗೊಂಡು, ಭರವಸೆ ನೀಡಿದ ದಿನವೇ ಡೆಲಿವರಿ ಬೇಕೆಂದು ಒತ್ತಾಯಿಸುತ್ತಿದ್ದಾರೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(144, 12, 12, 'ଜଣେ କଷ୍ଟମର ତାଙ୍କ ପୁଅଙ୍କ ଜନ୍ମଦିନ ଡିଲିଭରି ପାଇଁ Xtreme 125R Dual Channel ABS ବୁକ୍ କରିଛନ୍ତି। ବାଛିଥିବା ରଙ୍ଗ ତିନି ଦିନ ଦେରିରେ ଆସିବ, କିନ୍ତୁ ସେହି ଭେରିଆଣ୍ଟ ଅନ୍ୟ ରଙ୍ଗରେ ଆଜି ଉପଲବ୍ଧ ଅଛି। କଷ୍ଟମର ଅସନ୍ତୁଷ୍ଟ ଓ ପ୍ରତିଶ୍ରୁତ ତାରିଖରେ ଡିଲିଭରି ଚାହୁଁଛନ୍ତି। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(145, 13, 1, 'A customer compares your quotation with another dealership offering a lower on-road price for the same motorcycle.\r\n\r\nHe questions why your dealership price is higher and asks you to match it immediately.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(146, 13, 2, 'एक कस्टमर आपके कोटेशन की तुलना दूसरे डीलरशिप से करता है, जो उसी बाइक के लिए कम ऑन-रोड प्राइस दे रहा है। वह पूछता है कि आपकी डीलरशिप का प्राइस ज़्यादा क्यों है और तुरंत मैच करने को कहता है। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(147, 13, 3, 'ਇੱਕ ਕਸਟਮਰ ਤੁਹਾਡੇ ਕੋਟੇਸ਼ਨ ਦੀ ਤੁਲਨਾ ਇੱਕ ਹੋਰ ਡੀਲਰਸ਼ਿਪ ਨਾਲ ਕਰਦਾ ਹੈ ਜੋ ਉਸੇ ਮੋਟਰਸਾਈਕਲ ਲਈ ਘੱਟ ਆਨ-ਰੋਡ ਪ੍ਰਾਈਸ ਦੇ ਰਹੀ ਹੈ। ਉਹ ਪੁੱਛਦਾ ਹੈ ਕਿ ਤੁਹਾਡੀ ਡੀਲਰਸ਼ਿਪ ਦਾ ਭਾਅ ਵੱਧ ਕਿਉਂ ਹੈ ਅਤੇ ਤੁਰੰਤ ਮੈਚ ਕਰਨ ਲਈ ਕਹਿੰਦਾ ਹੈ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(148, 13, 4, 'એક કસ્ટમર તમારા ક્વોટેશનની તુલના બીજી ડીલરશિપ સાથે કરે છે, જ્યાં એ જ બાઇક માટે ઓન-રોડ કિંમત ઓછી આપવામાં આવી છે. તે પૂછે છે કે તમારી ડીલરશિપની કિંમત વધારે કેમ છે અને તરત જ મેચ કરવા કહે છે. આવી પરિસ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(149, 13, 5, 'एक कस्टमर तुमच्या कोटेशनची तुलना दुसऱ्या डीलरशिपशी करतो, जिथे त्याच मोटरसायकलसाठी कमी ऑन-रोड किंमत दिली जाते. तो विचारतो की तुमच्या डीलरशिपची किंमत जास्त का आहे आणि लगेच मॅच करण्यास सांगतो. अशा परिस्थितीत तुम्ही कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(150, 13, 6, 'একজন কাস্টমার আপনার কোটেশনের সঙ্গে অন্য একটি ডিলারশিপের কোটেশনের তুলনা করেন, যেখানে একই মোটরসাইকেলের অন-রোড দাম কম দেওয়া হচ্ছে। তিনি জানতে চান কেন আপনার ডিলারশিপের দাম বেশি এবং সঙ্গে সঙ্গে মিলিয়ে দিতে বলেন। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(151, 13, 7, 'এজন কাষ্টমাৰে আপোনাৰ কোটেশ্যনটো অন্য এখন ডীলাৰশ্বিপৰ সৈতে তুলনা কৰে, যিয়ে একে মটৰচাইকেলৰ বাবে কম অন-ৰোড মূল্য দিছে। সি সুধে যে আপোনাৰ ডীলাৰশ্বিপৰ মূল্য বেছি কিয় আৰু লগে লগে মিলাবলৈ কয়। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(152, 13, 8, 'ஒரு கஸ்டமர் உங்கள் கோட்டேஷனை அதே பைக்கிற்கு குறைந்த ஆன்ரோடு விலை தரும் மற்றொரு டீலர்ஷிப்புடன் ஒப்பிடுகிறார். உங்கள் டீலர்ஷிப்பில் விலை அதிகமாக இருக்கிறதேன் என்று கேட்டு, உடனே அதையே மேட்ச் செய்ய சொல்லுகிறார். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(153, 13, 9, 'ఒక కస్టమర్ మీ కోటేషన్‌ను అదే బైక్‌కు తక్కువ ఆన్-రోడ్ ధర ఇచ్చే మరో డీలర్‌షిప్‌తో పోల్చుతున్నాడు. మీ డీలర్‌షిప్ ధర ఎందుకు ఎక్కువగా ఉందని ప్రశ్నించి, వెంటనే మ్యాచ్ చేయమని అడుగుతున్నాడు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(154, 13, 10, 'ഒരു കസ്റ്റമർ നിങ്ങളുടെ ക്വട്ടേഷൻ അതേ മോട്ടോർസൈക്കിളിന് കുറഞ്ഞ ഓൺ-റോഡ് വില നൽകുന്ന മറ്റൊരു ഡീലർഷിപ്പുമായി താരതമ്യം ചെയ്യുന്നു. നിങ്ങളുടെ ഡീലർഷിപ്പിലെ വില കൂടുതലായതെന്തെന്ന് ചോദിക്കുകയും ഉടൻ തന്നെ മാച്ച് ചെയ്യാൻ ആവശ്യപ്പെടുകയും ചെയ്യുന്നു. ഈ സാഹചര്യത്തെ നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(155, 13, 11, 'ಒಬ್ಬ ಕಸ್ಟಮರ್ ನಿಮ್ಮ ಕೋಟೇಶನ್ ಅನ್ನು ಅದೇ ಬೈಕ್‌ಗೆ ಕಡಿಮೆ ಆನ್-ರೋಡ್ ಬೆಲೆ ನೀಡುತ್ತಿರುವ ಇನ್ನೊಂದು ಡೀಲರ್‌ಶಿಪ್ ಜೊತೆಗೆ ಹೋಲಿಸುತ್ತಾನೆ. ನಿಮ್ಮ ಡೀಲರ್‌ಶಿಪ್ ಬೆಲೆ ಏಕೆ ಜಾಸ್ತಿ ಅಂತ ಕೇಳಿ, ತಕ್ಷಣ ಮ್ಯಾಚ್ ಮಾಡಬೇಕು ಅಂತ ಒತ್ತಾಯಿಸುತ್ತಾನೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(156, 13, 12, 'ଜଣେ କଷ୍ଟମର ଆପଣଙ୍କ କୋଟେସନ୍‌କୁ ସେଇ ମୋଟରସାଇକେଲ୍‌ ପାଇଁ କମ୍‌ ଅନ୍-ରୋଡ୍ ମୂଲ୍ୟ ଦେଉଥିବା ଅନ୍ୟ ଡିଲର୍‌ଶିପ୍‌ ସହ ତୁଳନା କରୁଛନ୍ତି। ସେ ପଚାରୁଛନ୍ତି କାହିଁକି ଆପଣଙ୍କ ଡିଲର୍‌ଶିପ୍‌ ମୂଲ୍ୟ ଅଧିକ ଅଛି ଏବଂ ସହସ୍ରେ ମ୍ୟାଚ୍ କରିବାକୁ କହୁଛନ୍ତି। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(157, 14, 1, 'A farmer with no income proof enquires about purchasing an HF Deluxe under a low down payment scheme.\r\n\r\nWhile checking eligibility, you realize he does not meet the required documentation criteria and he appears hopeful about the purchase.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(158, 14, 2, 'एक किसान बिना इनकम प्रूफ के HF Deluxe को लो डाउन पेमेंट स्कीम में खरीदने के बारे में पूछताछ करता है। एलिजिबिलिटी चेक करते समय पता चलता है कि वह ज़रूरी डॉक्यूमेंट्स की शर्तें पूरी नहीं करता, लेकिन फिर भी वह खरीद को लेकर उम्मीद लगाए बैठा है। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(159, 14, 3, 'ਇੱਕ ਕਿਸਾਨ ਬਿਨਾਂ ਆਮਦਨ ਪ੍ਰੂਫ ਦੇ HF Deluxe ਨੂੰ ਘੱਟ ਡਾਊਨ ਪੇਮੈਂਟ ਸਕੀਮ ਵਿੱਚ ਖਰੀਦਣ ਬਾਰੇ ਪੁੱਛਦਾ ਹੈ। ਯੋਗਤਾ ਚੈੱਕ ਕਰਦੇ ਸਮੇਂ ਪਤਾ ਲੱਗਦਾ ਹੈ ਕਿ ਉਹ ਲੋੜੀਂਦੇ ਦਸਤਾਵੇਜ਼ਾਂ ਦੀਆਂ ਸ਼ਰਤਾਂ ਪੂਰੀਆਂ ਨਹੀਂ ਕਰਦਾ, ਪਰ ਫਿਰ ਵੀ ਉਹ ਖਰੀਦ ਲਈ ਉਮੀਦਵਾਰ ਹੈ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(160, 14, 4, 'એક ખેડૂત કોઈ ઇનકમ પ્રૂફ વગર HF Deluxe ને લો ડાઉન પેમેન્ટ સ્કીમમાં ખરીદવા માટે પૂછે છે. એલિજિબિલિટી ચેક કરતી વખતે ખબર પડે છે કે તે જરૂરી દસ્તાવેજોની શરતો પૂરી કરતો નથી, છતાં તે ખરીદી વિશે આશાવાન છે. આવી પરિસ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(161, 14, 5, 'एक शेतकरी इनकम प्रूफ नसताना HF Deluxe कमी डाउन पेमेंट स्कीममध्ये खरेदी करण्याबद्दल चौकशी करतो. पात्रता तपासताना लक्षात येते की तो आवश्यक कागदपत्रांची अट पूर्ण करत नाही, तरीही तो खरेदीबाबत आशावादी आहे. अशा परिस्थितीत तुम्ही हे कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(162, 14, 6, 'একজন কৃষক কোনও ইনকাম প্রুফ ছাড়াই HF Deluxe কম ডাউন পেমেন্ট স্কিমে কেনার বিষয়ে জিজ্ঞাসা করেন। যোগ্যতা যাচাই করার সময় দেখা যায় তিনি প্রয়োজনীয় নথিপত্রের শর্ত পূরণ করেন না, কিন্তু তবুও তিনি কেনার ব্যাপারে আশাবাদী। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(163, 14, 7, 'এজন কৃষকে কোনো আয় প্ৰমাণ নথকা অৱস্থাত HF Deluxe কম ডাউন পেমেণ্ট স্কীমত ক্ৰয় কৰাৰ বিষয়ে সুধে। যোগ্যতা পৰীক্ষা কৰোঁতে দেখা যায় যে তেওঁ প্ৰয়োজনীয় নথিপত্ৰৰ চৰ্ত পূৰণ নকৰে, তথাপিও তেওঁ ক্ৰয়ক লৈ আশাবাদী। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(164, 14, 8, 'ஒரு விவசாயி எந்த வருமான ஆதாரமும் இல்லாமல் HF Deluxe-ஐ குறைந்த டவுன் பேமெண்ட் திட்டத்தில் வாங்குவது பற்றி கேட்கிறார். தகுதியை சரிபார்க்கும் போது தேவையான ஆவணங்கள் பொருந்தவில்லை என்பது தெரிய வருகிறது, ஆனாலும் அவர் வாங்கலாம் என்ற நம்பிக்கையில் இருக்கிறார். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(165, 14, 9, 'ఒక రైతు ఎలాంటి ఆదాయ రుజువు లేకుండా HF Deluxe ను తక్కువ డౌన్ పేమెంట్ స్కీమ్‌లో కొనుగోలు చేయడం గురించి అడుగుతున్నాడు. అర్హతను చెక్ చేసే సమయంలో అవసరమైన డాక్యుమెంట్లు సరిపోవట్లేదని తెలుస్తుంది, అయినా కూడా అతను కొనుగోలు విషయంలో ఆశతో ఉన్నాడు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(166, 14, 10, 'ഒരു കർഷകൻ വരുമാന തെളിവൊന്നുമില്ലാതെ HF Deluxe കുറഞ്ഞ ഡൗൺ പേയ്മെന്റ് സ്കീമിൽ വാങ്ങുന്നതിനെക്കുറിച്ച് ചോദിക്കുന്നു. അർഹത പരിശോധിക്കുമ്പോൾ ആവശ്യമായ രേഖകൾ അദ്ദേഹത്തിനില്ലെന്ന് മനസ്സിലാകുന്നു, എങ്കിലും അദ്ദേഹം വാങ്ങുമെന്ന പ്രതീക്ഷയിലാണ്. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(167, 14, 11, 'ಒಬ್ಬ ರೈತ ಆದಾಯ ಪ್ರಮಾಣಪತ್ರವಿಲ್ಲದೆ HF Deluxe ಅನ್ನು ಕಡಿಮೆ ಡೌನ್ ಪೇಮೆಂಟ್ ಯೋಜನೆಯಲ್ಲಿ ಖರೀದಿಸುವ ಬಗ್ಗೆ ವಿಚಾರಿಸುತ್ತಾನೆ. ಅರ್ಹತೆ ಪರಿಶೀಲನೆ ವೇಳೆ ಅವನು ಅಗತ್ಯ ದಾಖಲೆಗಳನ್ನು ಪೂರೈಸಿಲ್ಲ ಎಂಬುದು ಗೊತ್ತಾಗುತ್ತದೆ, ಆದರೂ ಅವನು ಖರೀದಿಯ ಬಗ್ಗೆ ಭರವಸೆ ಇಟ್ಟುಕೊಂಡಿದ್ದಾನೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(168, 14, 12, 'ଜଣେ ଚାଷୀ କୌଣସି ଆୟ ପ୍ରମାଣ ନଥାଇ HF Deluxe କୁ କମ୍ ଡାଉନ୍ ପେମେଣ୍ଟ ଯୋଜନାରେ କିଣିବା ବିଷୟରେ ପଚାରୁଛନ୍ତି। ଯୋଗ୍ୟତା ଯାଞ୍ଚ କରିବାବେଳେ ଦେଖାଯାଏ ଯେ ସେ ଆବଶ୍ୟକ ଡକ୍ୟୁମେଣ୍ଟ ପୂରଣ କରୁନାହାନ୍ତି, ତଥାପି ସେ କିଣିବାକୁ ଆଶାବାଦୀ। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(169, 15, 1, 'A customer booked a motorcycle and was informed of a two-week waiting period.\r\n\r\nAfter two weeks, he has received no update and visits the dealership upset, threatening to cancel the booking.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(170, 15, 2, 'एक कस्टमर ने बाइक बुक की थी और उसे दो हफ्ते की वेटिंग बताई गई थी। दो हफ्ते बाद भी उसे कोई अपडेट नहीं मिला, इसलिए वह नाराज़ होकर शोरूम आता है और बुकिंग कैंसल करने की धमकी देता है। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(171, 15, 3, 'ਇੱਕ ਕਸਟਮਰ ਨੇ ਮੋਟਰਸਾਈਕਲ ਬੁੱਕ ਕੀਤੀ ਸੀ ਅਤੇ ਉਸਨੂੰ ਦੋ ਹਫ਼ਤਿਆਂ ਦੀ ਵੈਟਿੰਗ ਦੱਸੀ ਗਈ ਸੀ। ਦੋ ਹਫ਼ਤਿਆਂ ਬਾਅਦ ਵੀ ਕੋਈ ਅਪਡੇਟ ਨਹੀਂ ਮਿਲਿਆ, ਇਸ ਲਈ ਉਹ ਨਾਰਾਜ਼ ਹੋ ਕੇ ਸ਼ੋਰੂਮ ਆਉਂਦਾ ਹੈ ਅਤੇ ਬੁਕਿੰਗ ਰੱਦ ਕਰਨ ਦੀ ਧਮਕੀ ਦਿੰਦਾ ਹੈ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(172, 15, 4, 'એક કસ્ટમરે બાઈક બુક કરી હતી અને તેને બે અઠવાડિયાની વેટિંગ જણાવવામાં આવી હતી. બે અઠવાડિયા પછી પણ કોઈ અપડેટ ન મળતા તે નારાજ થઈને ડીલરશિપ પર આવે છે અને બુકિંગ રદ કરવાની ધમકી આપે છે. આવી સ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(173, 15, 5, 'एका कस्टमरने मोटरसायकल बुक केली होती आणि त्याला दोन आठवड्यांची वेटिंग सांगण्यात आली होती. दोन आठवड्यांनंतरही कोणताही अपडेट मिळाला नाही, त्यामुळे तो नाराज होऊन शोरूममध्ये येतो आणि बुकिंग कॅन्सल करण्याची धमकी देतो. अशा परिस्थितीत तुम्ही कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(174, 15, 6, 'একজন কাস্টমার একটি মোটরসাইকেল বুক করেছিলেন এবং তাকে দুই সপ্তাহের ওয়েটিং পিরিয়ড জানানো হয়েছিল। দুই সপ্তাহ পরেও কোনো আপডেট না পেয়ে তিনি বিরক্ত হয়ে শোরুমে আসেন এবং বুকিং বাতিল করার হুমকি দেন। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(175, 15, 7, 'এজন কাষ্টমাৰে এখন মটৰচাইকেল বুক কৰিছিল আৰু তেওঁক দুই সপ্তাহৰ ৱেইটিং পিৰিয়ড কোৱা হৈছিল। দুই সপ্তাহ পিছতেও কোনো আপডেট নাপাই তেওঁ খং উঠি শোৰূমলৈ আহে আৰু বুকিং বাতিল কৰাৰ ভাবুকি দিয়ে। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(176, 15, 8, 'ஒரு கஸ்டமர் ஒரு பைக்கை புக் செய்து, இரண்டு வாரங்கள் காத்திருக்க வேண்டும் என்று தெரிவிக்கப்பட்டது. இரண்டு வாரங்கள் கடந்தும் எந்த அப்டேட்டும் கிடைக்காததால், அவர் கோபமாக ஷோரூமுக்கு வந்து புக்கிங்கை கேன்சல் செய்வதாக மிரட்டுகிறார். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(177, 15, 9, 'ఒక కస్టమర్ ఒక బైక్ బుక్ చేశాడు మరియు రెండు వారాల వెయిటింగ్ పీరియడ్ ఉందని చెప్పారు. రెండు వారాలు గడిచినా ఎలాంటి అప్‌డేట్ రాకపోవడంతో, అతను అసహనంగా షోరూమ్‌కి వచ్చి బుకింగ్ రద్దు చేస్తానని బెదిరిస్తున్నాడు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(178, 15, 10, 'ഒരു കസ്റ്റമർ ഒരു മോട്ടോർസൈക്കിൾ ബുക്ക് ചെയ്തു, രണ്ട് ആഴ്ച കാത്തിരിക്കണം എന്ന് അറിയിച്ചു. രണ്ട് ആഴ്ച കഴിഞ്ഞിട്ടും യാതൊരു അപ്ഡേറ്റും ലഭിക്കാത്തതിനെ തുടർന്ന്, അദ്ദേഹം അസ്വസ്ഥനായി ഷോറൂമിൽ എത്തി ബുക്കിംഗ് റദ്ദാക്കുമെന്ന് ഭീഷണിപ്പെടുത്തുന്നു. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(179, 15, 11, 'ಒಬ್ಬ ಕಸ್ಟಮರ್ ಒಂದು ಬೈಕ್ ಬುಕ್ ಮಾಡಿಕೊಂಡಿದ್ದಾನೆ ಮತ್ತು ಎರಡು ವಾರಗಳ ವೇಟಿಂಗ್ ಇದೆ ಎಂದು ತಿಳಿಸಲಾಗಿತ್ತು. ಎರಡು ವಾರಗಳು ಕಳೆದರೂ ಯಾವುದೇ ಅಪ್‌ಡೇಟ್ ಸಿಗದ ಕಾರಣ, ಅವನು ಅಸಮಾಧಾನಗೊಂಡು ಶೋರೂಮ್‌ಗೆ ಬಂದು ಬುಕ್ಕಿಂಗ್ ಕ್ಯಾನ್ಸಲ್ ಮಾಡ್ತೀನಿ ಅಂತ ಬೆದರಿಕೆ ಹಾಕ್ತಾನೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(180, 15, 12, 'ଜଣେ କଷ୍ଟମର ଏକ ମୋଟରସାଇକେଲ୍ ବୁକ୍ କରିଥିଲେ ଏବଂ ତାଙ୍କୁ ଦୁଇ ସପ୍ତାହର ୱେଟିଂ ପିରିଅଡ୍ କୁହାଯାଇଥିଲା। ଦୁଇ ସପ୍ତାହ ପରେ ମଧ୍ୟ କୌଣସି ଅପଡେଟ୍ ମିଳିନଥିବାରୁ ସେ ଅସନ୍ତୁଷ୍ଟ ହୋଇ ଶୋରୁମକୁ ଆସି ବୁକିଂ କ୍ୟାନସଲ୍ କରିବାକୁ ଧମକ ଦେଉଛନ୍ତି। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(181, 16, 1, 'A father and daughter visit the showroom for a scooter.\r\n\r\nThe daughter prefers a stylish and easy-to-ride scooter, while the father is concerned about safety and asks about tracking features.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(182, 16, 2, 'एक पिता और बेटी स्कूटर देखने के लिए शोरूम आते हैं। बेटी को स्टाइलिश और आसान चलाने वाला स्कूटर पसंद है, जबकि पिता सेफ्टी को लेकर चिंतित हैं और ट्रैकिंग फीचर्स के बारे में पूछते हैं। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(183, 16, 3, 'ਇੱਕ ਪਿਤਾ ਅਤੇ ਧੀ ਸਕੂਟਰ ਦੇਖਣ ਲਈ ਸ਼ੋਰੂਮ ਆਉਂਦੇ ਹਨ। ਧੀ ਨੂੰ ਸਟਾਈਲਿਸ਼ ਅਤੇ ਆਸਾਨ ਚਲਾਉਣ ਵਾਲਾ ਸਕੂਟਰ ਚਾਹੀਦਾ ਹੈ, ਜਦਕਿ ਪਿਤਾ ਸੇਫਟੀ ਬਾਰੇ ਚਿੰਤਤ ਹਨ ਅਤੇ ਟ੍ਰੈਕਿੰਗ ਫੀਚਰਾਂ ਬਾਰੇ ਪੁੱਛਦੇ ਹਨ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(184, 16, 4, 'એક પિતા અને દીકરી સ્કૂટર જોવા માટે શોરૂમમાં આવે છે. દીકરીને સ્ટાઇલિશ અને સરળ ચલાવવાનો સ્કૂટર પસંદ છે, જ્યારે પિતા સુરક્ષા અંગે ચિંતિત છે અને ટ્રેકિંગ ફીચર્સ વિશે પૂછે છે. આવી પરિસ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(185, 16, 5, 'एक वडील आणि मुलगी स्कूटर पाहण्यासाठी शोरूममध्ये येतात. मुलीला स्टायलिश आणि सहज चालवता येणारा स्कूटर हवा आहे, तर वडील सेफ्टीबद्दल चिंतित आहेत आणि ट्रॅकिंग फीचर्सबद्दल विचारतात. अशा परिस्थितीत तुम्ही कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(186, 16, 6, 'একজন বাবা ও মেয়ে স্কুটার দেখতে শোরুমে আসেন। মেয়েটি স্টাইলিশ ও সহজে চালানো যায় এমন স্কুটার পছন্দ করে, আর বাবা সেফটি নিয়ে চিন্তিত এবং ট্র্যাকিং ফিচার সম্পর্কে জানতে চান। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(187, 16, 7, 'এজন পিতৃ আৰু কন্যা স্কুটাৰ চাবলৈ শোৰূমলৈ আহে। কন্যাই ষ্টাইলিছ আৰু সহজে চলাব পৰা স্কুটাৰ পছন্দ কৰে, কিন্তু পিতৃয়ে সুৰক্ষাৰ বিষয়ে চিন্তিত আৰু ট্ৰেকিং ফিচাৰ সম্পৰ্কে সুধে। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(188, 16, 8, 'ஒரு தந்தையும் மகளும் ஸ்கூட்டர் பார்க்க ஷோரூமுக்கு வருகிறார்கள். மகளுக்கு ஸ்டைலிஷ் மற்றும் எளிதாக ஓட்டக்கூடிய ஸ்கூட்டர் வேண்டும், ஆனால் தந்தை பாதுகாப்பைப் பற்றி கவலைப்பட்டு ட்ராக்கிங் அம்சங்கள் குறித்து கேட்கிறார். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(189, 16, 9, 'ఒక తండ్రి మరియు కుమార్తె స్కూటర్ కోసం షోరూమ్‌కి వస్తారు. కుమార్తెకు స్టైలిష్ మరియు సులభంగా నడపగలిగే స్కూటర్ కావాలి, కానీ తండ్రి భద్రతపై ఆందోళన చెందుతూ ట్రాకింగ్ ఫీచర్ల గురించి అడుగుతున్నారు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(190, 16, 10, 'ഒരു അച്ഛനും മകളും സ്കൂട്ടർ കാണാൻ ഷോറൂമിൽ എത്തുന്നു. മകൾക്ക് സ്റ്റൈലിഷും എളുപ്പത്തിൽ ഓടിക്കാവുന്നതുമായ സ്കൂട്ടർ വേണം, എന്നാൽ അച്ഛൻ സുരക്ഷയെ കുറിച്ച് ആശങ്കപ്പെടുകയും ട്രാക്കിംഗ് ഫീച്ചറുകൾക്കുറിച്ച് ചോദിക്കുകയും ചെയ്യുന്നു. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(191, 16, 11, 'ಒಬ್ಬ ತಂದೆ ಮತ್ತು ಮಗಳು ಸ್ಕೂಟರ್ ನೋಡಲು ಶೋರೂಮ್‌ಗೆ ಬರುತ್ತಾರೆ. ಮಗಳಿಗೆ ಸ್ಟೈಲಿಶ್ ಮತ್ತು ಸುಲಭವಾಗಿ ಓಡಿಸಬಹುದಾದ ಸ್ಕೂಟರ್ ಬೇಕು, ಆದರೆ ತಂದೆ ಸೆಫ್ಟಿ ಬಗ್ಗೆ ಚಿಂತಿತರಾಗಿ ಟ್ರ್ಯಾಕಿಂಗ್ ಫೀಚರ್‌ಗಳ ಬಗ್ಗೆ ಕೇಳುತ್ತಾರೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(192, 16, 12, 'ଜଣେ ପିତା ଓ ଝିଅ ସ୍କୁଟର ଦେଖିବାକୁ ଶୋରୁମକୁ ଆସନ୍ତି। ଝିଅଙ୍କୁ ଷ୍ଟାଇଲିଶ୍ ଏବଂ ସହଜରେ ଚଳାଇ ପାରିବା ସ୍କୁଟର ଭଲ ଲାଗେ, କିନ୍ତୁ ପିତା ସୁରକ୍ଷା ନେଇ ଚିନ୍ତିତ ଓ ଟ୍ରାକିଂ ଫିଚର୍ସ ବିଷୟରେ ପଚାରନ୍ତି। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(193, 17, 1, 'A customer interested in the Glamour X is unsure about the Ride-By-Wire feature.\r\n\r\nHe says he prefers simple mechanical systems and is concerned about reliability since he hasn’t seen this in other commuter bikes.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(194, 17, 2, 'Glamour X में दिलचस्पी रखने वाला एक कस्टमर Ride-By-Wire फीचर को लेकर कन्फ्यूज है। वह कहता है कि उसे सिंपल मैकेनिकल सिस्टम ज़्यादा पसंद हैं और उसे भरोसे को लेकर चिंता है, क्योंकि उसने ये फीचर दूसरी कम्यूटर बाइक्स में नहीं देखा है। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(195, 17, 3, 'Glamour X ਵਿੱਚ ਦਿਲਚਸਪੀ ਰੱਖਣ ਵਾਲਾ ਇੱਕ ਕਸਟਮਰ Ride-By-Wire ਫੀਚਰ ਨੂੰ ਲੈ ਕੇ ਕਨਫਿਊਜ਼ ਹੈ। ਉਹ ਕਹਿੰਦਾ ਹੈ ਕਿ ਉਸਨੂੰ ਸਧਾਰਣ ਮਕੈਨੀਕਲ ਸਿਸਟਮ ਪਸੰਦ ਹਨ ਅਤੇ ਭਰੋਸੇਯੋਗਤਾ ਨੂੰ ਲੈ ਕੇ ਚਿੰਤਾ ਹੈ, ਕਿਉਂਕਿ ਉਸਨੇ ਇਹ ਫੀਚਰ ਹੋਰ ਕਮਿਊਟਰ ਬਾਈਕਾਂ ਵਿੱਚ ਨਹੀਂ ਵੇਖਿਆ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(196, 17, 4, 'Glamour Xમાં રસ ધરાવતો એક કસ્ટમર Ride-By-Wire ફીચર અંગે અસમંજસમાં છે. તે કહે છે કે તેને સરળ મિકેનિકલ સિસ્ટમ્સ વધારે પસંદ છે અને વિશ્વસનીયતા વિશે ચિંતા છે, કારણ કે તેણે આ ફીચર અન્ય કમ્યુટર બાઇકોમાં નથી જોયું. આવી સ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(197, 17, 5, 'Glamour X मध्ये रस असलेला एक कस्टमर Ride-By-Wire फीचरबद्दल संभ्रमात आहे. तो सांगतो की त्याला साधी मेकॅनिकल सिस्टीम आवडते आणि विश्वासार्हतेबद्दल चिंता वाटते, कारण त्याने हे फीचर इतर कम्युटर बाईक्समध्ये पाहिलेले नाही. अशा परिस्थितीत तुम्ही कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(198, 17, 6, 'Glamour X-এ আগ্রহী একজন কাস্টমার Ride-By-Wire ফিচার নিয়ে দ্বিধায় রয়েছেন। তিনি বলেন, তিনি সহজ মেকানিক্যাল সিস্টেম পছন্দ করেন এবং নির্ভরযোগ্যতা নিয়ে চিন্তিত, কারণ অন্য কমিউটার বাইকে তিনি এই ফিচার দেখেননি। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(199, 17, 7, 'Glamour X-ত আগ্ৰহী এজন কাষ্টমাৰ Ride-By-Wire ফিচাৰটো লৈ সন্দিহান। সি কয় যে সৰল মেকানিকেল ছিষ্টেম পছন্দ কৰে আৰু বিশ্বাসযোগ্যতাৰ বিষয়ে চিন্তিত, কিয়নো সি এই ফিচাৰটো আন কমিউটাৰ বাইকত দেখা নাই। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(200, 17, 8, 'Glamour X-ல் ஆர்வம் கொண்ட ஒரு கஸ்டமர் Ride-By-Wire அம்சம் குறித்து சந்தேகமாக இருக்கிறார். அவருக்கு சிம்பிள் மெக்கானிக்கல் சிஸ்டம் தான் பிடிக்கும் என்றும், மற்ற கம்யூட்டர் பைக்குகளில் இதைப் பார்த்ததில்லை என்பதால் நம்பகத்தன்மை குறித்து கவலைப்படுகிறார். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(201, 17, 9, 'Glamour X పై ఆసక్తి ఉన్న ఒక కస్టమర్ Ride-By-Wire ఫీచర్ గురించి సందేహంలో ఉన్నాడు. అతనికి సింపుల్ మెకానికల్ సిస్టమ్‌లు ఇష్టమని, ఇతర కమ్యూటర్ బైక్‌లలో ఈ ఫీచర్ చూడలేదని నమ్మకంపై ఆందోళన వ్యక్తం చేస్తున్నాడు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(202, 17, 10, 'Glamour X-ൽ താൽപര്യമുള്ള ഒരു കസ്റ്റമർ Ride-By-Wire ഫീച്ചറിനെക്കുറിച്ച് ആശങ്കയിലാണ്. ലളിതമായ മെക്കാനിക്കൽ സിസ്റ്റമാണ് ഇഷ്ടമെന്നും, മറ്റ് കമ്മ്യൂട്ടർ ബൈക്കുകളിൽ ഇത് കണ്ടിട്ടില്ലാത്തതിനാൽ വിശ്വാസ്യതയെ കുറിച്ച് ആശങ്കയുണ്ടെന്നും പറയുന്നു. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(203, 17, 11, 'Glamour X ನಲ್ಲಿ ಆಸಕ್ತಿ ಇರುವ ಒಬ್ಬ ಕಸ್ಟಮರ್ Ride-By-Wire ಫೀಚರ್ ಬಗ್ಗೆ ಸಂಶಯದಲ್ಲಿದ್ದಾನೆ. ಅವನಿಗೆ ಸರಳ ಮೆಕ್ಯಾನಿಕಲ್ ಸಿಸ್ಟಮ್‌ಗಳು ಇಷ್ಟ ಮತ್ತು ಇತರೆ ಕಮ್ಯೂಟರ್ ಬೈಕ್‌ಗಳಲ್ಲಿ ಈ ಫೀಚರ್ ನೋಡಿಲ್ಲವೆಂದು ನಂಬಿಕೆಗೆ ಸಂಬಂಧಿಸಿದ ಚಿಂತೆಯಿದೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(204, 17, 12, 'Glamour X ରେ ଆଗ୍ରହ ରଖୁଥିବା ଜଣେ କଷ୍ଟମର Ride-By-Wire ଫିଚର୍ ବିଷୟରେ ସନ୍ଦେହରେ ଅଛନ୍ତି। ସେ କହୁଛନ୍ତି ଯେ ସେ ସରଳ ମେକାନିକାଲ୍ ସିଷ୍ଟମ୍ ପସନ୍ଦ କରନ୍ତି ଏବଂ ଅନ୍ୟ କମ୍ୟୁଟର ବାଇକ୍‌ରେ ଏହି ଫିଚର୍ ଦେଖିନଥିବାରୁ ବିଶ୍ୱସନୀୟତା ନେଇ ଚିନ୍ତିତ। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(205, 18, 1, 'A recently married customer who has moved to the city already owns a small car and wants a two-wheeler for daily commuting.\r\n\r\nHe is confused between a commuter motorcycle (better mileage) and a scooter (more practical and usable by his wife). He is seeking guidance.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(206, 18, 2, 'हाल ही में शादीशुदा एक कस्टमर शहर में शिफ्ट हुआ है। उसके पास पहले से एक छोटी कार है और वह डेली कम्यूट के लिए टू-व्हीलर लेना चाहता है। वह कम्यूटर बाइक (ज्यादा माइलेज) और स्कूटर (ज्यादा प्रैक्टिकल, पत्नी भी चला सके) के बीच कन्फ्यूज है और गाइडेंस चाहता है। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(207, 18, 3, 'ਹਾਲ ਹੀ ਵਿੱਚ ਵਿਆਹਿਆ ਇੱਕ ਕਸਟਮਰ ਸ਼ਹਿਰ ਵਿੱਚ ਸ਼ਿਫਟ ਹੋਇਆ ਹੈ। ਉਸ ਕੋਲ ਪਹਿਲਾਂ ਤੋਂ ਇੱਕ ਛੋਟੀ ਕਾਰ ਹੈ ਅਤੇ ਉਹ ਰੋਜ਼ਾਨਾ ਆਵਾਜਾਈ ਲਈ ਟੂ-ਵ੍ਹੀਲਰ ਲੈਣਾ ਚਾਹੁੰਦਾ ਹੈ। ਉਹ ਕਮਿਊਟਰ ਬਾਈਕ (ਵਧੀਆ ਮਾਈਲੇਜ) ਅਤੇ ਸਕੂਟਰ (ਜ਼ਿਆਦਾ ਪ੍ਰੈਕਟਿਕਲ, ਪਤਨੀ ਵੀ ਚਲਾ ਸਕੇ) ਵਿਚਕਾਰ ਕਨਫਿਊਜ਼ ਹੈ ਅਤੇ ਗਾਈਡੈਂਸ ਮੰਗਦਾ ਹੈ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(208, 18, 4, 'હાલમાં જ લગ્ન થયેલા એક કસ્ટમર શહેરમાં શિફ્ટ થયો છે. તેની પાસે પહેલેથી જ એક નાની કાર છે અને તે રોજિંદા કમ્યુટ માટે ટૂ-વ્હીલર લેવા માંગે છે. તે કમ્યુટર બાઈક (વધુ માઈલેજ) અને સ્કૂટર (વધુ પ્રેક્ટિકલ, પત્ની પણ ચલાવી શકે) વચ્ચે ગુંચવાયો છે અને માર્ગદર્શન માંગે છે. આવી સ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(209, 18, 5, 'अलीकडेच लग्न झालेला एक कस्टमर शहरात शिफ्ट झाला आहे. त्याच्याकडे आधीच एक छोटी कार आहे आणि तो रोजच्या कम्युटसाठी टू-व्हीलर घ्यायचा विचार करत आहे. तो कम्युटर बाइक (जास्त मायलेज) आणि स्कूटर (जास्त प्रॅक्टिकल, पत्नीही वापरू शकेल) यामध्ये कन्फ्यूज आहे आणि मार्गदर्शन मागतो आहे. अशा परिस्थितीत तुम्ही कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(210, 18, 6, 'সাম্প্রতিকভাবে বিয়ে হওয়া একজন কাস্টমার শহরে শিফট হয়েছেন। তাঁর কাছে আগে থেকেই একটি ছোট গাড়ি আছে এবং তিনি দৈনন্দিন যাতায়াতের জন্য একটি টু-হুইলার নিতে চান। তিনি কমিউটার বাইক (ভালো মাইলেজ) আর স্কুটার (বেশি ব্যবহারযোগ্য, স্ত্রীও চালাতে পারবেন) এর মধ্যে কনফিউজ হয়ে গাইডেন্স চাইছেন। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(211, 18, 7, 'সাম্প্ৰতিকভাৱে বিবাহিত এজন কাষ্টমাৰ শহৰলৈ শিফ্ট হৈছে। তেওঁৰ আগতেই এখন সৰু গাড়ী আছে আৰু দৈনিক যাতায়াতৰ বাবে এটা টু-হুইলাৰ ল\'ব বিচাৰে। তেওঁ কমিউটাৰ বাইক (ভাল মাইলেজ) আৰু স্কুটাৰ (অধিক প্ৰেক্টিকেল, পত্নীয়েও চলাব পাৰে) মাজত বিভ্ৰান্ত হৈ গাইডেন্স বিচাৰে। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(212, 18, 8, 'சமீபத்தில் திருமணம் ஆன ஒரு கஸ்டமர் நகரத்துக்கு இடம்பெயர்ந்துள்ளார். அவரிடம் ஏற்கனவே ஒரு சிறிய கார் உள்ளது, தினசரி பயணத்திற்கு ஒரு டூ-வீலர் வாங்க நினைக்கிறார். கம்யூட்டர் பைக் (நல்ல மைலேஜ்) மற்றும் ஸ்கூட்டர் (அதிக பயன்பாடு, மனைவியும் ஓட்டலாம்) இரண்டிற்கும் இடையில் குழப்பத்தில் இருந்து வழிகாட்டல் கேட்கிறார். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(213, 18, 9, 'ఇటీవలే పెళ్లి అయిన ఒక కస్టమర్ నగరానికి మారాడు. అతనికి ఇప్పటికే ఒక చిన్న కారు ఉంది మరియు రోజువారీ ప్రయాణాల కోసం టూ-వీలర్ కొనాలని చూస్తున్నాడు. అతను కమ్యూటర్ బైక్ (మంచి మైలేజ్) మరియు స్కూటర్ (ఎక్కువ ఉపయోగకరం, భార్య కూడా నడపవచ్చు) మధ్య అయోమయంలో ఉండి మార్గదర్శనం కోరుతున్నాడు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(214, 18, 10, 'സമീപകാലത്ത് വിവാഹിതനായ ഒരു കസ്റ്റമർ നഗരത്തിലേക്ക് താമസം മാറിയിട്ടുണ്ട്. അദ്ദേഹത്തിന് ഇതിനകം ഒരു ചെറിയ കാർ ഉണ്ട്, ദിവസേനയുള്ള യാത്രയ്ക്കായി ഒരു ടു-വീലർ വാങ്ങാൻ ആഗ്രഹിക്കുന്നു. കമ്മ്യൂട്ടർ ബൈക്ക് (കൂടുതൽ മൈലേജ്)യും സ്കൂട്ടർ (കൂടുതൽ പ്രായോഗികം, ഭാര്യക്കും ഉപയോഗിക്കാം)യും തമ്മിൽ ആശയക്കുഴപ്പത്തിലാണ്, മാർഗനിർദ്ദേശം തേടുന്നു. ഈ സാഹചര്യത്തെ നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(215, 18, 11, 'ಇತ್ತೀಚೆಗೆ ಮದುವೆಯಾದ ಒಬ್ಬ ಕಸ್ಟಮರ್ ನಗರಕ್ಕೆ ಶಿಫ್ಟ್ ಆಗಿದ್ದಾನೆ. ಅವನಿಗೆ ಈಗಾಗಲೇ ಒಂದು ಸಣ್ಣ ಕಾರು ಇದೆ ಮತ್ತು ದಿನನಿತ್ಯದ ಪ್ರಯಾಣಕ್ಕೆ ಟೂ-ವೀಲರ್ ಖರೀದಿಸಲು ಬಯಸುತ್ತಾನೆ. ಅವನು ಕಮ್ಯೂಟರ್ ಬೈಕ್ (ಉತ್ತಮ ಮೈಲೇಜ್) ಮತ್ತು ಸ್ಕೂಟರ್ (ಹೆಚ್ಚು ಪ್ರಾಯೋಗಿಕ, ಹೆಂಡತিও ಬಳಸಬಹುದು) ನಡುವೆ ಗೊಂದಲದಲ್ಲಿದ್ದು ಮಾರ್ಗದರ್ಶನ ಕೇಳುತ್ತಿದ್ದಾನೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(216, 18, 12, 'ସମ୍ପ୍ରତି ବିବାହିତ ଜଣେ କଷ୍ଟମର ସହରକୁ ସ୍ଥାନାନ୍ତର ହୋଇଛନ୍ତି। ତାଙ୍କ ପାଖରେ ପୂର୍ବରୁ ଏକ ଛୋଟ କାର୍ ଅଛି ଏବଂ ଦୈନିକ ଯାତାୟାତ ପାଇଁ ଏକ ଟୁ-ହ୍ୱିଲର୍ କିଣିବାକୁ ଚାହୁଁଛନ୍ତି। ସେ କମ୍ୟୁଟର୍ ବାଇକ୍ (ଭଲ ମାଇଲେଜ୍) ଓ ସ୍କୁଟର୍ (ଅଧିକ ପ୍ରାୟୋଗିକ, ପତ୍ନୀ ମଧ୍ୟ ବ୍ୟବହାର କରିପାରିବେ) ମଧ୍ୟରେ ଦ୍ୱନ୍ଦ୍ୱରେ ଅଛନ୍ତି ଏବଂ ମାର୍ଗଦର୍ଶନ ଚାହୁଁଛନ୍ତି। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(217, 19, 1, 'A father and son visit the dealership to purchase a motorcycle. The father prefers the Glamour (familiar and simple), while the son wants the Glamour X for its newer design and features at a marginally higher price.\r\n\r\nThe father is not open to change and asks for your suggestion.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(218, 19, 2, 'एक पिता और बेटा बाइक खरीदने के लिए डीलरशिप पर आते हैं। पिता Glamour को पसंद करते हैं क्योंकि वह उन्हें जानी-पहचानी और सिंपल लगती है, जबकि बेटा थोड़ी ज़्यादा कीमत पर नए डिजाइन और फीचर्स वाली Glamour X चाहता है। पिता बदलाव के लिए तैयार नहीं हैं और आपसे सलाह मांगते हैं। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(219, 19, 3, 'ਇੱਕ ਪਿਤਾ ਅਤੇ ਪੁੱਤਰ ਮੋਟਰਸਾਈਕਲ ਖਰੀਦਣ ਲਈ ਡੀਲਰਸ਼ਿਪ ਆਉਂਦੇ ਹਨ। ਪਿਤਾ Glamour ਨੂੰ ਤਰਜੀਹ ਦਿੰਦੇ ਹਨ ਕਿਉਂਕਿ ਉਹ ਉਨ੍ਹਾਂ ਲਈ ਜਾਣੀ-ਪਹਚਾਣੀ ਅਤੇ ਸਧਾਰਣ ਹੈ, ਜਦਕਿ ਪੁੱਤਰ ਥੋੜ੍ਹੀ ਵੱਧ ਕੀਮਤ ’ਤੇ ਨਵੇਂ ਡਿਜ਼ਾਇਨ ਅਤੇ ਫੀਚਰਾਂ ਵਾਲੀ Glamour X ਚਾਹੁੰਦਾ ਹੈ। ਪਿਤਾ ਬਦਲਾਅ ਲਈ ਤਿਆਰ ਨਹੀਂ ਹਨ ਅਤੇ ਤੁਹਾਡੀ ਸਲਾਹ ਮੰਗਦੇ ਹਨ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(220, 19, 4, 'એક પિતા અને પુત્ર મોટરસાયકલ ખરીદવા માટે ડીલરશિપ પર આવે છે. પિતાને Glamour પસંદ છે કારણ કે તે તેમને ઓળખીતી અને સરળ લાગે છે, જ્યારે પુત્ર થોડા વધારે ભાવે નવા ડિઝાઇન અને ફીચર્સવાળી Glamour X ઇચ્છે છે. પિતા બદલાવ માટે તૈયાર નથી અને તમારી સલાહ માંગે છે. આવી સ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(221, 19, 5, 'एक वडील आणि मुलगा मोटरसायकल खरेदीसाठी डीलरशिपवर येतात. वडिलांना Glamour आवडते कारण ती ओळखीची आणि सोपी आहे, तर मुलाला थोड्या जास्त किमतीत नवीन डिझाइन आणि फीचर्स असलेली Glamour X हवी आहे. वडील बदलासाठी तयार नाहीत आणि तुमच्याकडून सल्ला मागतात. अशा परिस्थितीत तुम्ही कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(222, 19, 6, 'একজন বাবা ও ছেলে মোটরসাইকেল কিনতে ডিলারশিপে আসেন। বাবা Glamour পছন্দ করেন কারণ এটি পরিচিত ও সহজ, আর ছেলে সামান্য বেশি দামে নতুন ডিজাইন ও ফিচারসহ Glamour X চায়। বাবা পরিবর্তনে আগ্রহী নন এবং আপনার পরামর্শ চান। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(223, 19, 7, 'এজন পিতৃ আৰু পুত্ৰ মটৰচাইকেল কিনিবলৈ ডীলাৰশ্বিপলৈ আহে। পিতৃয়ে Glamour পছন্দ কৰে কিয়নো ই চিনাকী আৰু সহজ, কিন্তু পুত্ৰই অলপ বেছি মূল্যত নতুন ডিজাইন আৰু ফিচাৰ থকা Glamour X বিচাৰে। পিতৃয়ে পৰিবৰ্তন মানি ল’বলৈ আগ্ৰহী নহয় আৰু আপোনাৰ পৰামৰ্শ বিচাৰে। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(224, 19, 8, 'ஒரு தந்தையும் மகனும் மோட்டார் சைக்கிள் வாங்க டீலர்ஷிப்புக்கு வருகிறார்கள். தந்தைக்கு பரிச்சயமானதும் எளிமையானதுமான Glamour பிடிக்கிறது, ஆனால் மகன் சிறிது கூடுதல் விலையில் புதிய டிசைன் மற்றும் அம்சங்கள் கொண்ட Glamour X-ஐ விரும்புகிறான். தந்தை மாற்றத்திற்கு தயாராக இல்லை மற்றும் உங்கள் ஆலோசனையை கேட்கிறார். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(225, 19, 9, 'ఒక తండ్రి మరియు కుమారుడు మోటార్‌సైకిల్ కొనడానికి డీలర్‌షిప్‌కి వస్తారు. తండ్రికి Glamour పరిచయమైనదిగా, సింపుల్‌గా ఉండటంతో ఇష్టం, కానీ కుమారుడు కొంచెం ఎక్కువ ధరకు కొత్త డిజైన్ మరియు ఫీచర్లు ఉన్న Glamour X కోరుకుంటున్నాడు. తండ్రి మార్పుకు సిద్ధంగా లేక మీ సలహా అడుగుతున్నారు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(226, 19, 10, 'ഒരു അച്ഛനും മകനും മോട്ടോർസൈക്കിൾ വാങ്ങാൻ ഡീലർഷിപ്പിൽ എത്തുന്നു. അച്ഛന് പരിചിതവും ലളിതവുമായ Glamour ഇഷ്ടമാണ്, എന്നാൽ മകൻ കുറച്ച് അധിക വിലക്ക് പുതിയ ഡിസൈനും ഫീച്ചറുകളും ഉള്ള Glamour X ആഗ്രഹിക്കുന്നു. അച്ഛൻ മാറ്റത്തിന് തയ്യാറല്ലാതെ നിങ്ങളുടെ നിർദ്ദേശം ചോദിക്കുന്നു. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(227, 19, 11, 'ಒಬ್ಬ ತಂದೆ ಮತ್ತು ಮಗ ಮೋಟಾರ್‌ಸೈಕಲ್ ಖರೀದಿಸಲು ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಬರುತ್ತಾರೆ. ತಂದೆಗೆ ಪರಿಚಿತ ಮತ್ತು ಸರಳವಾದ Glamour ಇಷ್ಟವಾಗುತ್ತದೆ, ಆದರೆ ಮಗ ಸ್ವಲ್ಪ ಹೆಚ್ಚುವರಿ ಬೆಲೆಗೆ ಹೊಸ ಡಿಸೈನ್ ಮತ್ತು ಫೀಚರ್‌ಗಳಿರುವ Glamour X ಅನ್ನು ಬಯಸುತ್ತಾನೆ. ತಂದೆ ಬದಲಾವಣೆಗೆ ಸಿದ್ಧರಾಗಿಲ್ಲ ಮತ್ತು ನಿಮ್ಮ ಸಲಹೆ ಕೇಳುತ್ತಾರೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(228, 19, 12, 'ଜଣେ ପିତା ଓ ପୁଅ ମୋଟରସାଇକେଲ୍ କିଣିବା ପାଇଁ ଡିଲର୍‌ଶିପ୍‌କୁ ଆସନ୍ତି। ପିତା Glamour କୁ ପସନ୍ଦ କରନ୍ତି କାରଣ ସେଟା ପରିଚିତ ଏବଂ ସରଳ, ଯେତେବେଳେ ପୁଅ ସାନା ଅଧିକ ଦାମରେ ନୂଆ ଡିଜାଇନ୍ ଓ ଫିଚର୍‌ସ୍‌ ଥିବା Glamour X ଚାହୁଁଛନ୍ତି। ପିତା ପରିବର୍ତ୍ତନ ପାଇଁ ପ୍ରସ୍ତୁତ ନୁହେଁ ଏବଂ ଆପଣଙ୍କ ସୁପାରିଶ ଚାହୁଁଛନ୍ତି। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(229, 20, 1, 'A young customer visits the dealership looking for a sporty scooter and shows interest in the Xoom 110.\r\n\r\nBased on his preferences, you see an opportunity to recommend the Xoom 125.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(230, 20, 2, 'एक युवा कस्टमर स्पोर्टी स्कूटर ढूंढते हुए डीलरशिप पर आता है और Xoom 110 में इंटरेस्ट दिखाता है। उसकी पसंद को देखते हुए आपको Xoom 125 रिकमेंड करने का मौका दिखता है। ऐसी स्थिति में आप इसे कैसे हैंडल करेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(231, 20, 3, 'ਇੱਕ ਨੌਜਵਾਨ ਕਸਟਮਰ ਸਪੋਰਟੀ ਸਕੂਟਰ ਦੀ ਖੋਜ ਵਿੱਚ ਡੀਲਰਸ਼ਿਪ ਆਉਂਦਾ ਹੈ ਅਤੇ Xoom 110 ਵਿੱਚ ਦਿਲਚਸਪੀ ਦਿਖਾਉਂਦਾ ਹੈ। ਉਸ ਦੀ ਪਸੰਦ ਦੇ ਆਧਾਰ ’ਤੇ ਤੁਹਾਨੂੰ Xoom 125 ਦੀ ਸਿਫ਼ਾਰਸ਼ ਕਰਨ ਦਾ ਮੌਕਾ ਨਜ਼ਰ ਆਉਂਦਾ ਹੈ। ਇਸ ਸਥਿਤੀ ਨੂੰ ਤੁਸੀਂ ਕਿਵੇਂ ਹੈਂਡਲ ਕਰੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(232, 20, 4, 'એક યુવાન કસ્ટમર સ્પોર્ટી સ્કૂટર શોધતા ડીલરશિપ પર આવે છે અને Xoom 110 માં રસ બતાવે છે. તેની પસંદગીને ધ્યાનમાં લઈ તમને Xoom 125 રિકમેન્ડ કરવાની તક દેખાય છે. આવી સ્થિતિને તમે કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(233, 20, 5, 'एक तरुण कस्टमर स्पोर्टी स्कूटर शोधत डीलरशिपवर येतो आणि Xoom 110 मध्ये इंटरेस्ट दाखवतो. त्याच्या पसंतीनुसार तुम्हाला Xoom 125 सुचवण्याची संधी दिसते. अशा परिस्थितीत तुम्ही कसे हँडल कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(234, 20, 6, 'একজন তরুণ কাস্টমার স্পোর্টি স্কুটার খুঁজতে ডিলারশিপে আসে এবং Xoom 110-এ আগ্রহ দেখায়। তার পছন্দ অনুযায়ী আপনি Xoom 125 রেকমেন্ড করার সুযোগ দেখতে পান। এই পরিস্থিতিটা আপনি কীভাবে হ্যান্ডেল করবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(235, 20, 7, 'এজন যুৱ কাষ্টমাৰ স্পোৰ্টী স্কুটাৰ বিচাৰি ডীলাৰশ্বিপলৈ আহে আৰু Xoom 110-ত আগ্ৰহ দেখুৱায়। তাৰ পছন্দৰ ওপৰত ভিত্তি কৰি আপুনি Xoom 125 ৰ পৰামৰ্শ দিব পৰা সুযোগ দেখে। এই পৰিস্থিতিটো আপুনি কেনেকৈ হেণ্ডেল কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(236, 20, 8, 'ஒரு இளம் கஸ்டமர் ஸ்போர்ட்டி ஸ்கூட்டர் தேடி டீலர்ஷிப்புக்கு வந்து Xoom 110-ல் ஆர்வம் காட்டுகிறார். அவருடைய விருப்பங்களை பார்த்து Xoom 125-ஐ ரெக்கமெண்ட் செய்ய வாய்ப்பு இருப்பதாக நீங்கள் நினைக்கிறீர்கள். இந்த சூழ்நிலையை நீங்கள் எப்படி ஹேண்டில் பண்ணுவீங்க?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(237, 20, 9, 'ఒక యువ కస్టమర్ స్పోర్టీ స్కూటర్ కోసం డీలర్‌షిప్‌కు వచ్చి Xoom 110 పై ఆసక్తి చూపిస్తున్నాడు. అతని అభిరుచులను బట్టి మీరు Xoom 125 ని సిఫారసు చేసే అవకాశం ఉందని చూస్తున్నారు. ఈ పరిస్థితిని మీరు ఎలా హ్యాండిల్ చేస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(238, 20, 10, 'ഒരു യുവ കസ്റ്റമർ സ്പോർട്ടി സ്കൂട്ടർ അന്വേഷിച്ച് ഡീലർഷിപ്പിലെത്തി Xoom 110-ൽ താൽപര്യം കാണിക്കുന്നു. അദ്ദേഹത്തിന്റെ ഇഷ്ടങ്ങൾ പരിഗണിച്ച് Xoom 125 ശുപാർശ ചെയ്യാനുള്ള അവസരം നിങ്ങൾക്ക് കാണാം. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ ഹാൻഡിൽ ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(239, 20, 11, 'ಒಬ್ಬ ಯುವ ಕಸ್ಟಮರ್ ಸ್ಪೋರ್ಟಿ ಸ್ಕೂಟರ್ ಹುಡುಕುತ್ತಾ ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಬಂದು Xoom 110 ಬಗ್ಗೆ ಆಸಕ್ತಿ ತೋರಿಸುತ್ತಾನೆ. ಅವನ ಇಷ್ಟಗಳನ್ನು ಗಮನಿಸಿದರೆ Xoom 125 ಅನ್ನು ಶಿಫಾರಸು ಮಾಡುವ ಅವಕಾಶ ನಿಮಗೆ ಕಾಣುತ್ತದೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ಹ್ಯಾಂಡಲ್ ಮಾಡ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(240, 20, 12, 'ଜଣେ ଯୁବ କଷ୍ଟମର ସ୍ପୋର୍ଟି ସ୍କୁଟର ଖୋଜି ଡିଲର୍‌ଶିପ୍‌କୁ ଆସି Xoom 110 ଉପରେ ଆଗ୍ରହ ଦେଖାଉଛନ୍ତି। ତାଙ୍କ ପସନ୍ଦ ଆଧାରରେ ଆପଣ Xoom 125 ସୁପାରିଶ କରିବାର ସୁଯୋଗ ଦେଖୁଛନ୍ତି। ଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କେମିତି ହାଣ୍ଡଲ୍ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-25 17:54:28', 'Active'),
	(241, 21, 1, 'A college student visits the dealership interested in the Xtreme 160R 4V and asks for an immediate test ride.\r\n\r\nDuring verification, you notice he does not have a valid driving license but insists he regularly rides inside campus. He seems very serious about purchasing the scooter\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(242, 21, 2, 'एक कॉलेज स्टूडेंट शोरूम में आता है और Xtreme 160R 4V में दिलचस्पी दिखाते हुए तुरंत टेस्ट राइड की मांग करता है।\r\n\r\nजांच के दौरान आपको पता चलता है कि उसके पास वैध ड्राइविंग लाइसेंस नहीं है, लेकिन वह कहता है कि वह कैंपस के अंदर नियमित रूप से गाड़ी चलाता है। वह स्कूटर खरीदने को लेकर काफी गंभीर भी लगता है।\r\n\r\nऐसी स्थिति में आपको क्या करना चाहिए?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(243, 21, 3, 'ਇੱਕ ਕਾਲਜ ਦਾ ਵਿਦਿਆਰਥੀ ਡੀਲਰਸ਼ਿਪ ਤੇ ਆਉਂਦਾ ਹੈ ਅਤੇ Xtreme 160R 4V ਵਿੱਚ ਦਿਲਚਸਪੀ ਦਿਖਾਉਂਦਾ ਹੋਇਆ ਤੁਰੰਤ ਟੈਸਟ ਰਾਈਡ ਦੀ ਮੰਗ ਕਰਦਾ ਹੈ।\r\n\r\nਜਾਂਚ ਦੌਰਾਨ ਤੁਹਾਨੂੰ ਪਤਾ ਲੱਗਦਾ ਹੈ ਕਿ ਉਸਦੇ ਕੋਲ ਵੈਧ ਡਰਾਈਵਿੰਗ ਲਾਇਸੈਂਸ ਨਹੀਂ ਹੈ, ਪਰ ਉਹ ਕਹਿੰਦਾ ਹੈ ਕਿ ਉਹ ਕੈਂਪਸ ਅੰਦਰ ਨਿਯਮਿਤ ਤੌਰ ‘ਤੇ ਗੱਡੀ ਚਲਾਉਂਦਾ ਹੈ। ਉਹ ਸਕੂਟਰ ਖਰੀਦਣ ਨੂੰ ਲੈ ਕੇ ਕਾਫ਼ੀ ਗੰਭੀਰ ਲੱਗਦਾ ਹੈ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(244, 21, 4, 'એક કોલેજ વિદ્યાર્થી ડીલરશિપ પર આવે છે અને Xtreme 160R 4V માં રસ બતાવી તરત જ ટેસ્ટ રાઈડ માંગે છે।\r\n\r\nચકાસણી દરમિયાન તમને ખબર પડે છે કે તેના પાસે માન્ય ડ્રાઈવિંગ લાયસન્સ નથી, પરંતુ તે કહે છે કે તે કેમ્પસની અંદર નિયમિત રીતે વાહન ચલાવે છે. તે સ્કૂટર ખરીદવા બાબતે ખૂબ જ ગંભીર લાગે છે।\r\n\r\nઆ પરિસ્થિતિને તમે કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(245, 21, 5, 'एक कॉलेज विद्यार्थी डीलरशिपवर येतो आणि Xtreme 160R 4V मध्ये रस दाखवत लगेच टेस्ट राईडची मागणी करतो.\r\n\r\nतपासणीदरम्यान तुम्हाला लक्षात येते की त्याच्याकडे वैध ड्रायव्हिंग लायसन्स नाही, पण तो सांगतो की तो कॅम्पसमध्ये नियमितपणे वाहन चालवतो. तो स्कूटर खरेदीबाबत खूप गंभीर दिसतो.\r\n\r\nअशा परिस्थितीत तुम्ही काय कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(246, 21, 6, 'একজন কলেজ ছাত্র ডিলারশিপে আসে এবং Xtreme 160R 4V-এ আগ্রহ দেখিয়ে সঙ্গে সঙ্গে টেস্ট রাইড চাইছে।\r\n\r\nযাচাইয়ের সময় আপনি দেখলেন তার বৈধ ড্রাইভিং লাইসেন্স নেই, কিন্তু সে বলছে যে সে নিয়মিত ক্যাম্পাসের ভেতরে চালায়। সে স্কুটারটি কেনার ব্যাপারে খুবই সিরিয়াস।\r\n\r\nএই পরিস্থিতি আপনি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(247, 21, 7, 'এজন কলেজ ছাত্ৰ ডিলাৰশ্বীপলৈ আহে আৰু Xtreme 160R 4V ত আগ্ৰহ দেখুৱাই লগে লগে টেষ্ট ৰাইড বিচাৰে।\r\n\r\nযাচাই কৰাৰ সময়ত আপুনি লক্ষ্য কৰে যে তেওঁৰ বৈধ ড্ৰাইভিং লাইচেন্স নাই, কিন্তু তেওঁ কয় যে তেওঁ নিয়মিতভাৱে কেম্পাছৰ ভিতৰত চলায়। তেওঁ স্কুটাৰখন কিনিবলৈ যথেষ্ট গুৰুত্ব দিয়ে।\r\n\r\nএই পৰিস্থিতিত আপুনি কেনেকৈ ব্যৱস্থা ল\'ব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(248, 21, 8, 'ஒரு கல்லூரி மாணவர் டீலர்ஷிப்பிற்கு வந்து Xtreme 160R 4V மீது ஆர்வம் காட்டி உடனடி டெஸ்ட் ரைடு கேட்கிறார்.\r\n\r\nசரிபார்ப்பின் போது அவரிடம் செல்லுபடியாகும் ஓட்டுநர் உரிமம் இல்லை என்பதை நீங்கள் கவனிக்கிறீர்கள். ஆனால் அவர் காம்பஸிற்குள் নিয়மিতமாக ஓட்டுவதாக கூறுகிறார். ஸ்கூட்டரை வாங்குவதில் அவர் மிகவும் சீரியஸாக இருக்கிறார்.\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(249, 21, 9, 'ఒక కాలేజీ విద్యార్థి డీలర్‌షిప్‌కు వచ్చి Xtreme 160R 4V పై ఆసక్తి చూపుతూ వెంటనే టెస్ట్ రైడ్ కోరుతున్నాడు.\r\n\r\nధృవీకరణ సమయంలో అతనికి చెల్లుబాటు అయ్యే డ్రైవింగ్ లైసెన్స్ లేదని మీరు గమనిస్తారు. కానీ అతను క్యాంపస్ లోపల తరచుగా వాహనం నడుపుతానని అంటున్నాడు. స్కూటర్ కొనుగోలులో అతను చాలా సీరియస్‌గా ఉన్నాడు.\r\n\r\nఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(250, 21, 10, 'ഒരു കോളേജ് വിദ്യാർത്ഥി ഡീലർഷിപ്പിൽ എത്തി Xtreme 160R 4V-യിൽ താൽപര്യം കാണിച്ച് ഉടൻ ടെസ്റ്റ് റൈഡ് ആവശ്യപ്പെടുന്നു.\r\n\r\nപരിശോധനയ്ക്കിടെ അദ്ദേഹത്തിന് സാധുവായ ഡ്രൈവിംഗ് ലൈസൻസ് ഇല്ലെന്ന് നിങ്ങൾ ശ്രദ്ധിക്കുന്നു. എന്നാൽ അദ്ദേഹം ക്യാമ്പസിനുള്ളിൽ സ്ഥിരമായി ഓടിക്കുന്നുവെന്ന് പറയുന്നു. സ്കൂട്ടർ വാങ്ങുന്നതിൽ അദ്ദേഹം വളരെ ഗൗരവമായി തോന്നുന്നു.\r\n\r\nഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(251, 21, 11, 'ಒಬ್ಬ ಕಾಲೇಜು ವಿದ್ಯಾರ್ಥಿ ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಬಂದು Xtreme 160R 4V ಬಗ್ಗೆ ಆಸಕ್ತಿ ತೋರಿಸಿ ತಕ್ಷಣ ಟೆಸ್ಟ್ ರೈಡ್ ಕೇಳುತ್ತಾನೆ.\r\n\r\nಪರಿಶೀಲನೆಯ ವೇಳೆ ಅವನ ಬಳಿ ಮಾನ್ಯ ಚಾಲನಾ ಪರವಾನಗಿ ಇಲ್ಲ ಎಂಬುದು ನಿಮಗೆ ಗೊತ್ತಾಗುತ್ತದೆ. ಆದರೆ ಅವನು ಕ್ಯಾಂಪಸ್ ಒಳಗೆ ನಿಯಮಿತವಾಗಿ ಓಡಿಸುತ್ತೇನೆ ಎಂದು ಹೇಳುತ್ತಾನೆ. ಸ್ಕೂಟರ್ ಖರೀದಿಸಲು ಅವನು ತುಂಬಾ ಗಂಭೀರನಾಗಿ ಕಾಣುತ್ತಾನೆ.\r\n\r\nಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(252, 21, 12, 'ଏକ କଲେଜ୍ ଛାତ୍ର ଡିଲରଶିପ୍‌କୁ ଆସି Xtreme 160R 4V ପ୍ରତି ଆଗ୍ରହ ଦେଖାଇ ସହଜରେ ଟେଷ୍ଟ ରାଇଡ୍ ଚାହୁଁଛି।\r\n\r\nଯାଞ୍ଚ ସମୟରେ ଆପଣ ଦେଖନ୍ତି ଯେ ତାଙ୍କ ପାଖରେ ବୈଧ ଡ୍ରାଇଭିଂ ଲାଇସେନ୍ସ ନାହିଁ, କିନ୍ତୁ ସେ କହୁଛନ୍ତି ଯେ ସେ କ୍ୟାମ୍ପସ୍‌ ଭିତରେ ନିୟମିତ ଭାବେ ଚଲାନ୍ତି। ସ୍କୁଟର କିଣିବାକୁ ସେ ବହୁତ ଗମ୍ଭୀର ଲାଗୁଛନ୍ତି।\r\n\r\nଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କିପରି ହାତଲ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(253, 22, 1, 'A customer booked an Xpulse 210 for his son’s birthday delivery.\r\n\r\nThe chosen colour will arrive three days late, but the same variant is available in other colours today.\r\n\r\nThe customer is upset and insists on delivery on the promised date.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(254, 22, 2, 'एक ग्राहक ने अपने बेटे के जन्मदिन पर डिलीवरी के लिए Xpulse 210 बुक की है।\r\n\r\nलेकिन जिस रंग की गाड़ी उन्होंने चुनी थी, वह तीन दिन देर से आएगी। उसी मॉडल की गाड़ी आज दूसरे रंगों में उपलब्ध है।\r\n\r\nग्राहक नाराज़ हैं और वादा की गई तारीख पर ही डिलीवरी की ज़िद कर रहे हैं।\r\n\r\nऐसी स्थिति में आपको क्या करना चाहिए?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(255, 22, 3, 'ਇੱਕ ਗਾਹਕ ਨੇ ਆਪਣੇ ਪੁੱਤਰ ਦੇ ਜਨਮਦਿਨ ਲਈ ਡਿਲਿਵਰੀ ਵਾਸਤੇ Xpulse 210 ਬੁੱਕ ਕਰਵਾਈ ਹੈ।\r\n\r\nਜੋ ਰੰਗ ਉਸਨੇ ਚੁਣਿਆ ਸੀ, ਉਹ ਤਿੰਨ ਦਿਨ ਦੇਰ ਨਾਲ ਆਏਗਾ, ਪਰ ਉਹੀ ਮਾਡਲ ਅੱਜ ਹੋਰ ਰੰਗਾਂ ਵਿੱਚ ਉਪਲਬਧ ਹੈ।\r\n\r\nਗਾਹਕ ਨਾਰਾਜ਼ ਹੈ ਅਤੇ ਵਾਅਦੇ ਕੀਤੀ ਤਾਰੀਖ ‘ਤੇ ਹੀ ਡਿਲਿਵਰੀ ਦੀ ਜ਼ਿੱਦ ਕਰ ਰਿਹਾ ਹੈ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(256, 22, 4, 'એક ગ્રાહકે પોતાના પુત્રના જન્મદિવસ માટે ડિલિવરી માટે Xpulse 210 બુક કરી છે।\r\n\r\nપસંદ કરેલો રંગ ત્રણ દિવસ મોડો આવશે, પરંતુ એ જ મોડલ આજે બીજા રંગોમાં ઉપલબ્ધ છે।\r\n\r\nગ્રાહક નારાજ છે અને વચન આપેલી તારીખે જ ડિલિવરી માંગે છે।\r\n\r\nઆ પરિસ્થિતિને તમે કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(257, 22, 5, 'एका ग्राहकाने आपल्या मुलाच्या वाढदिवसासाठी Xpulse 210 बुक केली आहे।\r\n\r\nनिवडलेला रंग तीन दिवस उशिरा येणार आहे, पण तोच मॉडेल आज इतर रंगांमध्ये उपलब्ध आहे।\r\n\r\nग्राहक नाराज आहे आणि दिलेल्या तारखेलाच डिलिव्हरीची मागणी करत आहे।\r\n\r\nअशा परिस्थितीत तुम्ही काय कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(258, 22, 6, 'একজন গ্রাহক তার ছেলের জন্মদিনে ডেলিভারির জন্য Xpulse 210 বুক করেছেন।\r\n\r\nনির্বাচিত রং তিন দিন দেরিতে আসবে, তবে একই মডেল আজ অন্য রঙে পাওয়া যাচ্ছে।\r\n\r\nগ্রাহক অসন্তুষ্ট এবং প্রতিশ্রুত তারিখেই ডেলিভারি চান।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(259, 22, 7, 'এজন গ্ৰাহকে তেওঁৰ পুত্ৰৰ জন্মদিনৰ ডেলিভাৰীৰ বাবে Xpulse 210 বুক কৰিছে।\r\n\r\nনির্বাচিত ৰংটো তিনি দিন পিচত আহিব, কিন্তু একে মডেল আজি আন ৰঙত উপলব্ধ আছে।\r\n\r\nগ্ৰাহক অসন্তুষ্ট আৰু প্ৰতিশ্ৰুত তাৰিখতেই ডেলিভাৰী দাবী কৰিছে।\r\n\r\nএই পৰিস্থিতিত আপুনি কেনেকৈ ব্যৱস্থা ল’ব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(260, 22, 8, 'ஒரு வாடிக்கையாளர் தனது மகனின் பிறந்தநாளுக்காக டெலிவரிக்காக Xpulse 210-ஐ முன்பதிவு செய்துள்ளார்।\r\n\r\nதேர்ந்தெடுத்த நிறம் மூன்று நாட்கள் தாமதமாக வரும், ஆனால் அதே மாடல் இன்று மற்ற நிறங்களில் கிடைக்கிறது।\r\n\r\nவாடிக்கையாளர் வருத்தமாக உள்ளார் மற்றும் வாக்குறுதியளிக்கப்பட்ட தேதியிலேயே டெலிவரி வேண்டும் என்று வலியுறுத்துகிறார்।\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(261, 22, 9, 'ఒక కస్టమర్ తన కుమారుడి పుట్టినరోజు డెలివరీ కోసం Xpulse 210 బుక్ చేశాడు।\r\n\r\nఎంచుకున్న రంగు మూడు రోజులు ఆలస్యంగా వస్తుంది, కానీ అదే వేరియంట్ ఈ రోజు ఇతర రంగుల్లో అందుబాటులో ఉంది।\r\n\r\nకస్టమర్ అసంతృప్తిగా ఉన్నాడు మరియు వాగ్దానం చేసిన తేదీకి డెలివరీ ఇవ్వాలని పట్టుబడుతున్నాడు।\r\n\r\nఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(262, 22, 10, 'ഒരു ഉപഭോക്താവ് തന്റെ മകന്റെ ജന്മദിന ഡെലിവറിയ്ക്കായി Xpulse 210 ബുക്ക് ചെയ്തിട്ടുണ്ട്।\r\n\r\nതിരഞ്ഞെടുത്ത നിറം മൂന്ന് ദിവസം വൈകി എത്തും, പക്ഷേ അതേ മോഡൽ ഇന്ന് മറ്റ് നിറങ്ങളിൽ ലഭ്യമാണ്।\r\n\r\nഉപഭോക്താവ് അസന്തുഷ്ടനാണ്, വാഗ്ദാനം ചെയ്ത തീയതിയിലേയ്ക്ക് തന്നെ ഡെലിവറി വേണമെന്ന് ആവശ്യപ്പെടുന്നു।\r\n\r\nഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(263, 22, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕರು ತಮ್ಮ ಮಗನ ಹುಟ್ಟುಹಬ್ಬದ ಡೆಲಿವರಿಗಾಗಿ Xpulse 210 ಬುಕ್ ಮಾಡಿದ್ದಾರೆ।\r\n\r\nಆಯ್ದ ಬಣ್ಣ ಮೂರು ದಿನ ತಡವಾಗಿ ಬರುತ್ತದೆ, ಆದರೆ ಅದೇ ಮಾದರಿ ಇಂದು ಇತರ ಬಣ್ಣಗಳಲ್ಲಿ ಲಭ್ಯವಿದೆ।\r\n\r\nಗ್ರಾಹಕರು ಅಸಮಾಧಾನಗೊಂಡಿದ್ದಾರೆ ಮತ್ತು ಮಾತುಕತೆ ಮಾಡಿದ ದಿನಾಂಕದಲ್ಲೇ ಡೆಲಿವರಿ ಬೇಕೆಂದು ಒತ್ತಾಯಿಸುತ್ತಿದ್ದಾರೆ।\r\n\r\nಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(264, 22, 12, 'ଏକ ଗ୍ରାହକ ତାଙ୍କ ପୁଅଙ୍କ ଜନ୍ମଦିନ ଡେଲିଭେରୀ ପାଇଁ Xpulse 210 ବୁକ୍ କରିଛନ୍ତି।\r\n\r\nଚୟନ କରାଯାଇଥିବା ରଙ୍ଗ ତିନି ଦିନ ପରେ ଆସିବ, କିନ୍ତୁ ସେହି ମଡେଲ୍ ଆଜି ଅନ୍ୟ ରଙ୍ଗରେ ଉପଲବ୍ଧ ଅଛି।\r\n\r\nଗ୍ରାହକ ଅସନ୍ତୁଷ୍ଟ ଅଛନ୍ତି ଏବଂ ପ୍ରତିଶ୍ରୁତ ତାରିଖରେ ହିଁ ଡେଲିଭେରୀ ଚାହୁଁଛନ୍ତି।\r\n\r\nଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(265, 23, 1, 'A customer compares your quotation with another dealership offering a lower on-road price for the same motorcycle.\r\n\r\nHe questions why your dealership price is higher and asks you to match it immediately.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(266, 23, 2, 'एक ग्राहक आपकी दी हुई कीमत की तुलना दूसरे डीलरशिप की कीमत से करता है, जो उसी मोटरसाइकिल पर कम ऑन-रोड प्राइस दे रही है।\r\n\r\nवह पूछता है कि आपकी डीलरशिप की कीमत ज्यादा क्यों है और आपसे तुरंत वही कीमत मैच करने को कहता है।\r\n\r\nऐसी स्थिति में आपको क्या करना चाहिए?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(267, 23, 3, 'ਇੱਕ ਗਾਹਕ ਤੁਹਾਡੇ ਕੋਟੇਸ਼ਨ ਦੀ ਤੁਲਨਾ ਦੂਜੇ ਡੀਲਰਸ਼ਿਪ ਨਾਲ ਕਰਦਾ ਹੈ, ਜੋ ਉਸੇ ਮੋਟਰਸਾਈਕਲ ‘ਤੇ ਘੱਟ ਆਨ-ਰੋਡ ਕੀਮਤ ਦੇ ਰਹੀ ਹੈ।\r\n\r\nਉਹ ਪੁੱਛਦਾ ਹੈ ਕਿ ਤੁਹਾਡੀ ਡੀਲਰਸ਼ਿਪ ਦੀ ਕੀਮਤ ਜ਼ਿਆਦਾ ਕਿਉਂ ਹੈ ਅਤੇ ਤੁਰੰਤ ਕੀਮਤ ਮੇਲ ਕਰਨ ਲਈ ਕਹਿੰਦਾ ਹੈ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(268, 23, 4, 'એક ગ્રાહક તમારી ક્વોટેશનની તુલના બીજી ડીલરશિપ સાથે કરે છે, જે એ જ મોટરસાયકલ પર ઓછી ઓન-રોડ કિંમત આપી રહી છે।\r\n\r\nતે પૂછે છે કે તમારી ડીલરશિપની કિંમત વધુ કેમ છે અને તરત જ કિંમત મેચ કરવાની માંગ કરે છે।\r\n\r\nઆ પરિસ્થિતિને તમે કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(269, 23, 5, 'एक ग्राहक तुमच्या कोटेशनची तुलना दुसऱ्या डीलरशिपशी करतो, जी त्याच मोटरसायकलवर कमी ऑन-रोड किंमत देत आहे।\r\n\r\nतो विचारतो की तुमची किंमत जास्त का आहे आणि लगेच ती किंमत जुळवण्याची मागणी करतो।\r\n\r\nअशा परिस्थितीत तुम्ही काय कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(270, 23, 6, 'একজন গ্রাহক আপনার কোটেশনের সাথে অন্য একটি ডিলারশিপের কোটেশনের তুলনা করছেন, যেখানে একই মোটরসাইকেলে কম অন-রোড মূল্য দেওয়া হচ্ছে।\r\n\r\nতিনি জানতে চান কেন আপনার ডিলারশিপের দাম বেশি এবং সঙ্গে সঙ্গে সেই দাম মিলিয়ে দিতে বলেন।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(271, 23, 7, 'এজন গ্ৰাহকে আপোনাৰ কোটেশ্যনখন আন এটা ডিলাৰশ্বীপৰ সৈতে তুলনা কৰে, যিয়ে একে মটৰচাইকেলত কম অন-ৰোড মূল্য আগবঢ়াইছে।\r\n\r\nতেওঁ সোধে আপোনালোকৰ ডিলাৰশ্বীপৰ দাম বেছি কিয় আৰু তৎক্ষণাৎ সেই দাম মিলাবলৈ কয়।\r\n\r\nএই পৰিস্থিতিত আপুনি কেনেকৈ ব্যৱস্থা ল’ব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(272, 23, 8, 'ஒரு வாடிக்கையாளர் உங்கள் குவோட்டேஷனை அதே மோட்டார் சைக்கிளுக்கு குறைந்த ஆன்-ரோடு விலை வழங்கும் மற்றொரு டீலர்ஷிப்புடன் ஒப்பிடுகிறார்।\r\n\r\nஉங்கள் டீலர்ஷிப் விலை ஏன் அதிகம் என்று கேட்டு, உடனே அதே விலைக்கு பொருத்துமாறு கூறுகிறார்।\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(273, 23, 9, 'ఒక కస్టమర్ మీ కోటేషన్‌ను అదే మోటార్‌సైకిల్‌కు తక్కువ ఆన్-రోడ్ ధర ఇస్తున్న మరో డీలర్‌షిప్‌తో పోలుస్తున్నాడు।\r\n\r\nమీ డీలర్‌షిప్ ధర ఎందుకు ఎక్కువగా ఉందని ప్రశ్నించి, వెంటనే ఆ ధరను మ్యాచ్ చేయాలని అడుగుతున్నాడు।\r\n\r\nఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(274, 23, 10, 'ഒരു ഉപഭോക്താവ് നിങ്ങളുടെ ക്വോട്ടേഷൻ അതേ മോട്ടോർസൈക്കിളിന് കുറവ് ഓൺ-റോഡ് വില നൽകുന്ന മറ്റൊരു ഡീലർഷിപ്പുമായി താരതമ്യം ചെയ്യുന്നു।\r\n\r\nനിങ്ങളുടെ ഡീലർഷിപ്പിന്റെ വില കൂടുതലാണെന്ന് ചോദിച്ച് ഉടൻ തന്നെ അതേ വിലയ്ക്ക് നൽകണമെന്ന് ആവശ്യപ്പെടുന്നു।\r\n\r\nഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(275, 23, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕರು ನಿಮ್ಮ ಕೊಟೇಶನ್ ಅನ್ನು ಅದೇ ಮೋಟಾರ್‌ಸೈಕಲ್‌ಗೆ ಕಡಿಮೆ ಆನ್-ರೋಡ್ ಬೆಲೆ ನೀಡುತ್ತಿರುವ ಇನ್ನೊಂದು ಡೀಲರ್‌ಶಿಪ್ ಜೊತೆ ಹೋಲಿಸುತ್ತಾರೆ।\r\n\r\nನಿಮ್ಮ ಡೀಲರ್‌ಶಿಪ್ ಬೆಲೆ ಏಕೆ ಹೆಚ್ಚು ಎಂದು ಕೇಳಿ, ತಕ್ಷಣ ಅದೇ ಬೆಲೆಯನ್ನು ಹೊಂದಿಸಲು ಕೇಳುತ್ತಾರೆ।\r\n\r\nಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(276, 23, 12, 'ଏକ ଗ୍ରାହକ ଆପଣଙ୍କ କୋଟେସନ୍‌କୁ ଅନ୍ୟ ଏକ ଡିଲରଶିପ୍ ସହିତ ତୁଳନା କରୁଛନ୍ତି, ଯେଉଁଠାରେ ସେହି ମୋଟରସାଇକେଲ୍‌ ପାଇଁ କମ୍ ଅନ-ରୋଡ୍ ଦର ଦିଆଯାଉଛି।\r\n\r\nସେ ପଚାରୁଛନ୍ତି ଯେ ଆପଣଙ୍କ ଡିଲରଶିପ୍‌ର ଦର ଅଧିକ କାହିଁକି ଏବଂ ସତ୍ତ୍ୱରେ ସେହି ଦରକୁ ମେଳ କରିବାକୁ କହୁଛନ୍ତି।\r\n\r\nଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(277, 24, 1, 'A customer serious about buying the Xoom 160 called a week in advance to check if a test ride would be ready.\r\n\r\nHe left early from work to visit the Premia dealer, which is far from his home, but the test ride unit is not available as it is getting serviced.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(278, 24, 2, 'एक ग्राहक जो Xoom 160 खरीदने को लेकर गंभीर है, उसने एक हफ्ता पहले फोन करके पूछा था कि टेस्ट राइड की गाड़ी तैयार रहेगी या नहीं।\r\n\r\nवह ऑफिस से जल्दी निकलकर प्रीमिया डीलर के पास आता है, जो उसके घर से काफी दूर है। लेकिन वहां पहुंचने पर पता चलता है कि टेस्ट राइड की गाड़ी सर्विस में गई हुई है और उपलब्ध नहीं है।\r\n\r\nऐसी स्थिति में आपको क्या करना चाहिए?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(279, 24, 3, 'ਇੱਕ ਗਾਹਕ ਜੋ Xoom 160 ਖਰੀਦਣ ਲਈ ਗੰਭੀਰ ਹੈ, ਉਸਨੇ ਇੱਕ ਹਫ਼ਤਾ ਪਹਿਲਾਂ ਫੋਨ ਕਰਕੇ ਪੁੱਛਿਆ ਸੀ ਕਿ ਟੈਸਟ ਰਾਈਡ ਤਿਆਰ ਹੋਵੇਗੀ ਜਾਂ ਨਹੀਂ।\r\n\r\nਉਹ ਆਪਣੇ ਘਰ ਤੋਂ ਕਾਫ਼ੀ ਦੂਰ ਪ੍ਰੇਮੀਆ ਡੀਲਰ ਕੋਲ ਜਾਣ ਲਈ ਕੰਮ ਤੋਂ ਜਲਦੀ ਨਿਕਲਿਆ, ਪਰ ਟੈਸਟ ਰਾਈਡ ਵਾਲੀ ਗੱਡੀ ਸਰਵਿਸ ਵਿੱਚ ਹੋਣ ਕਰਕੇ ਉਪਲਬਧ ਨਹੀਂ ਹੈ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(280, 24, 4, 'એક ગ્રાહક, જે Xoom 160 ખરીદવા અંગે ગંભીર છે, તેણે એક અઠવાડિયા પહેલાં ફોન કરીને પૂછ્યું હતું કે ટેસ્ટ રાઇડ તૈયાર રહેશે કે નહીં।\r\n\r\nતે પોતાના ઘરથી દૂર આવેલા પ્રીમિયા ડીલર પાસે જવા માટે કામમાંથી વહેલા નીકળી ગયો, પરંતુ ટેસ્ટ રાઇડ યુનિટ સર્વિસમાં હોવાથી ઉપલબ્ધ નથી।\r\n\r\nઆ પરિસ્થિતિને તમે કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(281, 24, 5, 'Xoom 160 खरेदी करण्याबाबत गंभीर असलेल्या एका ग्राहकाने आठवडाभर आधी फोन करून टेस्ट राईड तयार असेल का याची चौकशी केली होती।\r\n\r\nतो घरापासून दूर असलेल्या प्रीमिया डीलरकडे जाण्यासाठी कामावरून लवकर निघाला, पण टेस्ट राईडसाठीची गाडी सर्व्हिसिंगमध्ये असल्यामुळे उपलब्ध नाही।\r\n\r\nअशा परिस्थितीत तुम्ही काय कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(282, 24, 6, 'একজন গ্রাহক, যিনি Xoom 160 কেনার ব্যাপারে সিরিয়াস, এক সপ্তাহ আগে ফোন করে জানতে চেয়েছিলেন টেস্ট রাইড প্রস্তুত থাকবে কি না।\r\n\r\nতিনি বাড়ি থেকে অনেক দূরের প্রিমিয়া ডিলারের কাছে যাওয়ার জন্য অফিস থেকে আগে বেরিয়েছিলেন, কিন্তু টেস্ট রাইড ইউনিট সার্ভিসিংয়ে থাকায় তা উপলব্ধ নয়।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(283, 24, 7, 'Xoom 160 কিনিবলৈ যথেষ্ট গুৰুত্ব দিয়া এজন গ্ৰাহকে এচপ্তাহ আগতে ফোন কৰি টেষ্ট ৰাইড সাজু থাকিব নে নাই সোধিছিল।\r\n\r\nতেওঁ ঘৰ পৰা বহু দূৰত থকা প্ৰিমিয়া ডিলাৰৰ ওচৰলৈ যাবলৈ কামৰ পৰা আগতেই ওলাইছিল, কিন্তু টেষ্ট ৰাইড ইউনিটটো ছাৰ্ভিচিঙত থকাৰ বাবে উপলব্ধ নহয়।\r\n\r\nএই পৰিস্থিতিত আপুনি কেনেকৈ ব্যৱস্থা ল’ব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(284, 24, 8, 'Xoom 160 வாங்குவதில் தீவிரமாக உள்ள ஒரு வாடிக்கையாளர், ஒரு வாரத்திற்கு முன் டெஸ்ட் ரைடு தயாராக இருக்கும் எனக் கேட்டு அழைத்திருந்தார்।\r\n\r\nஅவர் தனது வீட்டிலிருந்து தொலைவில் உள்ள பிரீமியா டீலரிடம் வர வேலை முடிந்து முன்கூட்டியே கிளம்பினார், ஆனால் டெஸ்ட் ரைடு வாகனம் சர்வீசில் இருப்பதால் கிடைக்கவில்லை।\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(285, 24, 9, 'Xoom 160 కొనుగోలు చేయడానికి సీరియస్‌గా ఉన్న ఒక కస్టమర్, ఒక వారం ముందే ఫోన్ చేసి టెస్ట్ రైడ్ సిద్ధంగా ఉంటుందా అని అడిగాడు।\r\n\r\nతన ఇంటికి దూరంగా ఉన్న ప్రీమియా డీలర్‌ను సందర్శించడానికి ఉద్యోగం నుంచి ముందే వచ్చాడు, కానీ టెస్ట్ రైడ్ యూనిట్ సర్వీసింగ్‌లో ఉండటం వల్ల అందుబాటులో లేదు।\r\n\r\nఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(286, 24, 10, 'Xoom 160 വാങ്ങുന്നതിൽ ഗൗരവമുള്ള ഒരു ഉപഭോക്താവ് ഒരു ആഴ്ച മുമ്പ് ടെസ്റ്റ് റൈഡ് തയ്യാറായിരിക്കുമോ എന്ന് ഫോൺ ചെയ്ത് ചോദിച്ചിരുന്നു।\r\n\r\nവീട്ടിൽ നിന്ന് ദൂരെയുള്ള പ്രീമിയ ഡീലറെ കാണാൻ ജോലി മുതൽ നേരത്തെ ഇറങ്ങി വന്നെങ്കിലും ടെസ്റ്റ് റൈഡ് യൂണിറ്റ് സർവീസിൽ ആയതിനാൽ ലഭ്യമല്ല।\r\n\r\nഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(287, 24, 11, 'Xoom 160 ಖರೀದಿಸಲು ಗಂಭೀರವಾಗಿರುವ ಒಬ್ಬ ಗ್ರಾಹಕರು ಒಂದು ವಾರ ಮೊದಲು ಫೋನ್ ಮಾಡಿ ಟೆಸ್ಟ್ ರೈಡ್ ಸಿದ್ಧವಾಗಿರುತ್ತದೆಯೇ ಎಂದು ಕೇಳಿದ್ದರು।\r\n\r\nತಮ್ಮ ಮನೆಗೆ ದೂರದಲ್ಲಿರುವ ಪ್ರೀಮಿಯಾ ಡೀಲರ್ ಭೇಟಿ ಮಾಡಲು ಕೆಲಸದಿಂದ ಬೇಗ ಹೊರಟರು, ಆದರೆ ಟೆಸ್ಟ್ ರೈಡ್ ಯೂನಿಟ್ ಸರ್ವಿಸ್‌ನಲ್ಲಿ ಇರುವುದರಿಂದ ಲಭ್ಯವಿಲ್ಲ।\r\n\r\nಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(288, 24, 12, 'Xoom 160 କିଣିବା ପାଇଁ ଗୁରୁତ୍ୱ ସହ ଭାବୁଥିବା ଜଣେ ଗ୍ରାହକ ଏକ ସପ୍ତାହ ପୂର୍ବରୁ ଫୋନ୍ କରି ଟେଷ୍ଟ ରାଇଡ୍ ପ୍ରସ୍ତୁତ ରହିବ କି ନାହିଁ ପଚାରିଥିଲେ।\r\n\r\nସେ ଘରରୁ ଦୂରରେ ଥିବା ପ୍ରିମିଆ ଡିଲରଙ୍କ ପାଖକୁ ଯିବା ପାଇଁ କାମରୁ ଆଗରୁ ବାହାରିଥିଲେ, କିନ୍ତୁ ଟେଷ୍ଟ ରାଇଡ୍ ୟୁନିଟ୍ ସର୍ଭିସିଂରେ ଥିବାରୁ ଉପଲବ୍ଧ ନାହିଁ।\r\n\r\nଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(289, 25, 1, 'A customer booked a motorcycle and was informed of a two-week waiting period.\r\n\r\nAfter two weeks, he has received no update and visits the dealership upset, threatening to cancel the booking.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(290, 25, 2, 'एक ग्राहक ने मोटरसाइकिल बुक की थी और उसे बताया गया था कि डिलीवरी में दो हफ्ते का इंतज़ार रहेगा।\r\n\r\nदो हफ्ते पूरे हो गए, लेकिन उसे कोई अपडेट नहीं मिला। वह नाराज़ होकर शोरूम आता है और बुकिंग कैंसिल करने की धमकी देता है।\r\n\r\nऐसी स्थिति में आपको क्या करना चाहिए?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(291, 25, 3, 'ਇੱਕ ਗਾਹਕ ਨੇ ਮੋਟਰਸਾਈਕਲ ਬੁੱਕ ਕੀਤੀ ਸੀ ਅਤੇ ਉਸਨੂੰ ਦੋ ਹਫ਼ਤਿਆਂ ਦੀ ਉਡੀਕ ਬਾਰੇ ਦੱਸਿਆ ਗਿਆ ਸੀ।\r\n\r\nਦੋ ਹਫ਼ਤੇ ਬਾਅਦ ਵੀ ਉਸਨੂੰ ਕੋਈ ਅਪਡੇਟ ਨਹੀਂ ਮਿਲੀ। ਉਹ ਨਾਰਾਜ਼ ਹੋ ਕੇ ਡੀਲਰਸ਼ਿਪ ਤੇ ਆਉਂਦਾ ਹੈ ਅਤੇ ਬੁਕਿੰਗ ਰੱਦ ਕਰਨ ਦੀ ਧਮਕੀ ਦਿੰਦਾ ਹੈ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(292, 25, 4, 'એક ગ્રાહકે મોટરસાયકલ બુક કરી હતી અને તેને બે અઠવાડિયાની વેઇટિંગ પિરિયડ વિશે જણાવાયું હતું।\r\n\r\nબે અઠવાડિયા બાદ પણ તેને કોઈ અપડેટ મળ્યો નથી. તે નારાજ થઈને ડીલરશિપ પર આવે છે અને બુકિંગ રદ કરવાની ધમકી આપે છે।\r\n\r\nઆ પરિસ્થિતિને તમે કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(293, 25, 5, 'एका ग्राहकाने मोटरसायकल बुक केली होती आणि त्याला दोन आठवड्यांचा प्रतीक्षा कालावधी सांगितला होता।\r\n\r\nदोन आठवड्यांनंतरही त्याला कोणतीही अपडेट मिळाली नाही. तो नाराज होऊन डीलरशिपवर येतो आणि बुकिंग रद्द करण्याची धमकी देतो।\r\n\r\nअशा परिस्थितीत तुम्ही काय कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(294, 25, 6, 'একজন গ্রাহক একটি মোটরসাইকেল বুক করেছিলেন এবং তাকে দুই সপ্তাহের অপেক্ষার সময় জানানো হয়েছিল।\r\n\r\nদুই সপ্তাহ পরেও তিনি কোনও আপডেট পাননি। তিনি অসন্তুষ্ট হয়ে ডিলারশিপে এসে বুকিং বাতিল করার হুমকি দিচ্ছেন।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(295, 25, 7, 'এজন গ্ৰাহকে এটা মটৰচাইকেল বুক কৰিছিল আৰু তেওঁক দুসপ্তাহ অপেক্ষাৰ সময় জনোৱা হৈছিল।\r\n\r\nদুসপ্তাহ পাছতো তেওঁ কোনো আপডেট পোৱা নাই। তেওঁ অসন্তুষ্ট হৈ ডিলাৰশ্বীপলৈ আহি বুকিং বাতিল কৰাৰ ধমকি দিছে।\r\n\r\nএই পৰিস্থিতিত আপুনি কেনেকৈ ব্যৱস্থা ল’ব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(296, 25, 8, 'ஒரு வாடிக்கையாளர் ஒரு மோட்டார் சைக்கிளை முன்பதிவு செய்தார் மற்றும் அவருக்கு இரண்டு வாரங்கள் காத்திருக்க வேண்டும் என்று தெரிவிக்கப்பட்டது।\r\n\r\nஇரண்டு வாரங்களுக்குப் பிறகும் எந்த தகவலும் கிடைக்கவில்லை. அவர் வருத்தமாக டீலர்ஷிப்பிற்கு வந்து முன்பதிவை ரத்து செய்வதாக கூறுகிறார்।\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(297, 25, 9, 'ఒక కస్టమర్ ఒక మోటార్‌సైకిల్ బుక్ చేసుకున్నాడు మరియు అతనికి రెండు వారాల వెయిటింగ్ పీరియడ్ ఉందని చెప్పారు।\r\n\r\nరెండు వారాల తర్వాత కూడా అతనికి ఎలాంటి అప్డేట్ రాలేదు. అతను అసంతృప్తిగా డీలర్‌షిప్‌కు వచ్చి బుకింగ్ రద్దు చేస్తానని అంటున్నాడు।\r\n\r\nఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(298, 25, 10, 'ഒരു ഉപഭോക്താവ് ഒരു മോട്ടോർസൈക്കിൾ ബുക്ക് ചെയ്തിരുന്നു, രണ്ട് ആഴ്ചയുടെ കാത്തിരിപ്പ് സമയമുണ്ടെന്ന് അറിയിച്ചിരുന്നു।\r\n\r\nരണ്ട് ആഴ്ച കഴിഞ്ഞിട്ടും യാതൊരു അപ്‌ഡേറ്റും ലഭിച്ചില്ല. അദ്ദേഹം അസന്തുഷ്ടനായി ഡീലർഷിപ്പിൽ എത്തി ബുക്കിംഗ് റദ്ദാക്കുമെന്ന് പറയുന്നു।\r\n\r\nഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(299, 25, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕರು ಮೋಟಾರ್‌ಸೈಕಲ್ ಬುಕ್ ಮಾಡಿದ್ದರು ಮತ್ತು ಅವರಿಗೆ ಎರಡು ವಾರಗಳ ನಿರೀಕ್ಷಾ ಅವಧಿ ಇರುವುದಾಗಿ ತಿಳಿಸಲಾಗಿತ್ತು।\r\n\r\nಎರಡು ವಾರಗಳಾದರೂ ಯಾವುದೇ ಅಪ್ಡೇಟ್ ಸಿಗಲಿಲ್ಲ. ಅವರು ಅಸಮಾಧಾನಗೊಂಡು ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಬಂದು ಬುಕ್ಕಿಂಗ್ ರದ್ದು ಮಾಡುವುದಾಗಿ ಹೇಳುತ್ತಿದ್ದಾರೆ।\r\n\r\nಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(300, 25, 12, 'ଏକ ଗ୍ରାହକ ଜଣେ ମୋଟରସାଇକେଲ୍ ବୁକ୍ କରିଥିଲେ ଏବଂ ତାଙ୍କୁ ଦୁଇ ସପ୍ତାହ ଅପେକ୍ଷା ସମୟ ଥିବା କୁହାଯାଇଥିଲା।\r\n\r\nଦୁଇ ସପ୍ତାହ ପରେ ମଧ୍ୟ କୌଣସି ଅପଡେଟ୍ ମିଳିନାହିଁ। ସେ ଅସନ୍ତୁଷ୍ଟ ହୋଇ ଡିଲରଶିପ୍‌କୁ ଆସି ବୁକିଂ ବାତିଲ୍ କରିବେ ବୋଲି କୁହୁଛନ୍ତି।\r\n\r\nଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(301, 26, 1, 'A customer visits the dealership and you approach to assist him.\r\n\r\nHe says he has already researched the bike thoroughly and does not require your assistance.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(302, 26, 2, 'एक ग्राहक शोरूम में आता है और आप उसकी मदद करने के लिए उसके पास जाते हैं।\r\n\r\nवह कहता है कि उसने बाइक के बारे में पहले से पूरी जानकारी ले रखी है और उसे आपकी किसी मदद की ज़रूरत नहीं है।\r\n\r\nऐसी स्थिति में आपको क्या करना चाहिए?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(303, 26, 3, 'ਇੱਕ ਗਾਹਕ ਡੀਲਰਸ਼ਿਪ ਤੇ ਆਉਂਦਾ ਹੈ ਅਤੇ ਤੁਸੀਂ ਉਸਦੀ ਮਦਦ ਲਈ ਅੱਗੇ ਵੱਧਦੇ ਹੋ।\r\n\r\nਉਹ ਕਹਿੰਦਾ ਹੈ ਕਿ ਉਸਨੇ ਬਾਈਕ ਬਾਰੇ ਪਹਿਲਾਂ ਹੀ ਪੂਰੀ ਰਿਸਰਚ ਕਰ ਲਈ ਹੈ ਅਤੇ ਉਸਨੂੰ ਤੁਹਾਡੀ ਮਦਦ ਦੀ ਲੋੜ ਨਹੀਂ ਹੈ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(304, 26, 4, 'એક ગ્રાહક ડીલરશિપ પર આવે છે અને તમે તેની મદદ કરવા આગળ વધો છો।\r\n\r\nતે કહે છે કે તેણે બાઈક વિશે પહેલેથી સંપૂર્ણ માહિતી મેળવી લીધી છે અને તેને તમારી મદદની જરૂર નથી।\r\n\r\nઆ પરિસ્થિતિને તમે કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(305, 26, 5, 'एक ग्राहक डीलरशिपवर येतो आणि तुम्ही त्याला मदत करण्यासाठी पुढे जाता।\r\n\r\nतो सांगतो की त्याने बाईकबद्दल आधीच पूर्ण माहिती घेतली आहे आणि त्याला तुमच्या मदतीची गरज नाही।\r\n\r\nअशा परिस्थितीत तुम्ही काय कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(306, 26, 6, 'একজন গ্রাহক ডিলারশিপে আসেন এবং আপনি তাকে সাহায্য করতে এগিয়ে যান।\r\n\r\nতিনি বলেন যে তিনি বাইক সম্পর্কে আগে থেকেই সম্পূর্ণ গবেষণা করেছেন এবং আপনার সাহায্যের প্রয়োজন নেই।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(307, 26, 7, 'এজন গ্ৰাহক ডিলাৰশ্বীপলৈ আহে আৰু আপুনি তেওঁক সহায় কৰিবলৈ আগবাঢ়ে।\r\n\r\nতেওঁ কয় যে তেওঁ বাইকখনৰ বিষয়ে আগতেই সম্পূৰ্ণ তথ্য সংগ্ৰহ কৰিছে আৰু আপোনাৰ সহায়ৰ প্ৰয়োজন নাই।\r\n\r\nএই পৰিস্থিতিত আপুনি কেনেকৈ ব্যৱস্থা ল’ব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(308, 26, 8, 'ஒரு வாடிக்கையாளர் டீலர்ஷிப்பிற்கு வருகிறார், நீங்கள் அவருக்கு உதவ முன்வருகிறீர்கள்।\r\n\r\nஅவர், பைக்கைப் பற்றி ஏற்கனவே முழுமையாக ஆராய்ச்சி செய்துவிட்டதாகவும், உங்கள் உதவி தேவையில்லை என்றும் கூறுகிறார்।\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(309, 26, 9, 'ఒక కస్టమర్ డీలర్‌షిప్‌కు వస్తాడు, మీరు అతనికి సహాయం చేయడానికి ముందుకు వెళ్తారు।\r\n\r\nఅతను బైక్ గురించి ఇప్పటికే పూర్తిగా తెలుసుకున్నానని, మీ సహాయం అవసరం లేదని అంటున్నాడు।\r\n\r\nఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(310, 26, 10, 'ഒരു ഉപഭോക്താവ് ഡീലർഷിപ്പിൽ എത്തുന്നു, നിങ്ങൾ സഹായിക്കാൻ മുന്നോട്ട് പോകുന്നു।\r\n\r\nഅദ്ദേഹം ബൈക്കിനെ കുറിച്ച് ഇതിനകം മുഴുവൻ പഠിച്ചിട്ടുണ്ടെന്നും നിങ്ങളുടെ സഹായം ആവശ്യമില്ലെന്നും പറയുന്നു।\r\n\r\nഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(311, 26, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕರು ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಬರುತ್ತಾರೆ, ನೀವು ಅವರಿಗೆ ಸಹಾಯ ಮಾಡಲು ಮುಂದೆ ಹೋಗುತ್ತೀರಿ।\r\n\r\nಅವರು ಬೈಕ್ ಬಗ್ಗೆ ಈಗಾಗಲೇ ಸಂಪೂರ್ಣವಾಗಿ ಮಾಹಿತಿ ಪಡೆದುಕೊಂಡಿದ್ದೇನೆ ಮತ್ತು ನಿಮ್ಮ ಸಹಾಯ ಅಗತ್ಯವಿಲ್ಲ ಎಂದು ಹೇಳುತ್ತಾರೆ।\r\n\r\nಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(312, 26, 12, 'ଏକ ଗ୍ରାହକ ଡିଲରଶିପ୍‌କୁ ଆସନ୍ତି ଏବଂ ଆପଣ ସେଠାରେ ସହାୟତା ପାଇଁ ଆଗକୁ ବଢ଼ନ୍ତି।\r\n\r\nସେ କହୁଛନ୍ତି ଯେ ସେ ବାଇକ୍ ବିଷୟରେ ପୂର୍ବରୁ ସମ୍ପୂର୍ଣ୍ଣ ତଥ୍ୟ ଜାଣିଛନ୍ତି ଏବଂ ଆପଣଙ୍କ ସହାୟତାର ଆବଶ୍ୟକତା ନାହିଁ।\r\n\r\nଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(313, 27, 1, 'A customer interested in the Xtreme 160R 4V is unsure about the Ride-By-Wire feature.\r\n\r\nHe says he prefers simple mechanical systems and is concerned about reliability.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(314, 27, 2, 'एक ग्राहक Xtreme 160R 4V में दिलचस्पी रखता है, लेकिन वह Ride-By-Wire फीचर को लेकर थोड़ा असमंजस में है।\r\n\r\nवह कहता है कि उसे साधारण मैकेनिकल सिस्टम ज़्यादा पसंद हैं और उसे इस फीचर की भरोसेमंद होने को लेकर चिंता है।\r\n\r\nऐसी स्थिति में आपको क्या करना चाहिए?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(315, 27, 3, 'ਇੱਕ ਗਾਹਕ ਜੋ Xtreme 160R 4V ਵਿੱਚ ਦਿਲਚਸਪੀ ਰੱਖਦਾ ਹੈ, Ride-By-Wire ਫੀਚਰ ਬਾਰੇ ਨਿਸ਼ਚਿਤ ਨਹੀਂ ਹੈ।\r\n\r\nਉਹ ਕਹਿੰਦਾ ਹੈ ਕਿ ਉਸਨੂੰ ਸਧਾਰਣ ਮਕੈਨਿਕਲ ਸਿਸਟਮ ਪਸੰਦ ਹਨ ਅਤੇ ਉਹ ਇਸਦੀ ਭਰੋਸੇਯੋਗਤਾ ਬਾਰੇ ਚਿੰਤਿਤ ਹੈ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(316, 27, 4, 'એક ગ્રાહક, જે Xtreme 160R 4Vમાં રસ ધરાવે છે, Ride-By-Wire ફીચર અંગે નિશ્ચિત નથી।\r\n\r\nતે કહે છે કે તેને સરળ મિકેનિકલ સિસ્ટમ વધુ ગમે છે અને વિશ્વસનીયતા અંગે ચિંતિત છે।\r\n\r\nઆ પરિસ્થિતિને તમે કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(317, 27, 5, 'Xtreme 160R 4V मध्ये रस असलेला एक ग्राहक Ride-By-Wire फीचरबद्दल संभ्रमात आहे।\r\n\r\nतो सांगतो की त्याला साधी मेकॅनिकल सिस्टीम जास्त आवडते आणि विश्वसनीयतेबद्दल तो चिंतित आहे।\r\n\r\nअशा परिस्थितीत तुम्ही काय कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(318, 27, 6, 'একজন গ্রাহক Xtreme 160R 4V-এ আগ্রহী, কিন্তু Ride-By-Wire ফিচার সম্পর্কে নিশ্চিত নন।\r\n\r\nতিনি বলেন, তিনি সহজ মেকানিক্যাল সিস্টেম পছন্দ করেন এবং নির্ভরযোগ্যতা নিয়ে উদ্বিগ্ন।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(319, 27, 7, 'Xtreme 160R 4V ত আগ্ৰহী এজন গ্ৰাহক Ride-By-Wire ফিচাৰটো লৈ নিশ্চিত নহয়।\r\n\r\nতেওঁ কয় যে তেওঁ সৰল মেকানিকেল ব্যৱস্থা পছন্দ কৰে আৰু নিৰ্ভৰযোগ্যতাৰ বিষয়ে চিন্তিত।\r\n\r\nএই পৰিস্থিতিত আপুনি কেনেকৈ ব্যৱস্থা ল’ব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(320, 27, 8, 'Xtreme 160R 4V மீது ஆர்வம் கொண்ட ஒரு வாடிக்கையாளர் Ride-By-Wire அம்சம் குறித்து உறுதியாக இல்லை।\r\n\r\nஅவர் எளிய மெக்கானிக்கல் அமைப்புகளை விரும்புகிறார் மற்றும் நம்பகத்தன்மை குறித்து கவலைப்படுகிறார்।\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(321, 27, 9, 'Xtreme 160R 4V పై ఆసక్తి ఉన్న ఒక కస్టమర్ Ride-By-Wire ఫీచర్ గురించి సందేహంగా ఉన్నాడు।\r\n\r\nతాను సాదాసీదా మెకానికల్ సిస్టమ్‌లను ఇష్టపడతానని, విశ్వసనీయతపై ఆందోళన ఉందని చెబుతున్నాడు।\r\n\r\nఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(322, 27, 10, 'Xtreme 160R 4V-യിൽ താൽപര്യമുള്ള ഒരു ഉപഭോക്താവ് Ride-By-Wire ഫീച്ചറിനെക്കുറിച്ച് ഉറപ്പില്ല।\r\n\r\nഅദ്ദേഹം ലളിതമായ മെക്കാനിക്കൽ സംവിധാനങ്ങൾ ഇഷ്ടപ്പെടുന്നു, വിശ്വാസ്യതയെക്കുറിച്ച് ആശങ്കപ്പെടുന്നു।\r\n\r\nഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(323, 27, 11, 'Xtreme 160R 4V ಬಗ್ಗೆ ಆಸಕ್ತಿ ಹೊಂದಿರುವ ಒಬ್ಬ ಗ್ರಾಹಕರು Ride-By-Wire ವೈಶಿಷ್ಟ್ಯ ಕುರಿತು ಖಚಿತವಾಗಿಲ್ಲ।\r\n\r\nಅವರಿಗೆ ಸರಳ ಮೆಕಾನಿಕಲ್ ವ್ಯವಸ್ಥೆಗಳು ಇಷ್ಟ ಮತ್ತು ನಂಬಿಕಸ್ತತೆಯ ಬಗ್ಗೆ ಚಿಂತೆಯಿದೆ ಎಂದು ಹೇಳುತ್ತಾರೆ।\r\n\r\nಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(324, 27, 12, 'Xtreme 160R 4V ପ୍ରତି ଆଗ୍ରହ ରଖିଥିବା ଜଣେ ଗ୍ରାହକ Ride-By-Wire ଫିଚର ବିଷୟରେ ନିଶ୍ଚିତ ନୁହେଁ।\r\n\r\nସେ କହୁଛନ୍ତି ଯେ ସେ ସରଳ ମେକାନିକାଲ୍ ସିଷ୍ଟମ୍ ପସନ୍ଦ କରନ୍ତି ଏବଂ ନିର୍ଭରଯୋଗ୍ୟତା ବିଷୟରେ ଚିନ୍ତିତ।\r\n\r\nଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(325, 28, 1, 'A young customer visits the dealership along with his parents to buy his first bike, showing interest in the Xpulse 210.\r\n\r\nHis parents are concerned about safety given Indian road conditions.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(326, 28, 2, 'एक युवा ग्राहक अपने माता-पिता के साथ अपनी पहली बाइक खरीदने के लिए शोरूम आता है। उसे Xpulse 210 पसंद आई है।\r\n\r\nलेकिन उसके माता-पिता भारतीय सड़कों की स्थिति को देखते हुए सुरक्षा को लेकर चिंतित हैं।\r\n\r\nऐसी स्थिति में आपको क्या करना चाहिए?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(327, 28, 3, 'ਇੱਕ ਨੌਜਵਾਨ ਗਾਹਕ ਆਪਣੇ ਮਾਤਾ-ਪਿਤਾ ਨਾਲ ਆਪਣੀ ਪਹਿਲੀ ਬਾਈਕ ਖਰੀਦਣ ਲਈ ਡੀਲਰਸ਼ਿਪ ਤੇ ਆਉਂਦਾ ਹੈ ਅਤੇ Xpulse 210 ਵਿੱਚ ਦਿਲਚਸਪੀ ਦਿਖਾਉਂਦਾ ਹੈ।\r\n\r\nਉਸਦੇ ਮਾਤਾ-ਪਿਤਾ ਭਾਰਤੀ ਸੜਕ ਹਾਲਾਤਾਂ ਨੂੰ ਦੇਖਦੇ ਹੋਏ ਸੁਰੱਖਿਆ ਬਾਰੇ ਚਿੰਤਿਤ ਹਨ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(328, 28, 4, 'એક યુવાન ગ્રાહક પોતાના માતા-પિતા સાથે પોતાની પહેલી બાઈક ખરીદવા ડીલરશિપ પર આવે છે અને Xpulse 210 માં રસ બતાવે છે।\r\n\r\nભારતીય રસ્તાની પરિસ્થિતિને ધ્યાનમાં રાખીને તેના માતા-પિતા સુરક્ષા અંગે ચિંતિત છે।\r\n\r\nઆ પરિસ્થિતિને તમે કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(329, 28, 5, 'एक तरुण ग्राहक आपल्या आई-वडिलांसोबत पहिली बाईक खरेदी करण्यासाठी डीलरशिपवर येतो आणि Xpulse 210 मध्ये रस दाखवतो।\r\n\r\nभारतीय रस्त्यांच्या परिस्थितीचा विचार करून त्याचे आई-वडील सुरक्षेबाबत चिंतित आहेत।\r\n\r\nअशा परिस्थितीत तुम्ही काय कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(330, 28, 6, 'একজন তরুণ গ্রাহক তার বাবা-মায়ের সাথে তার প্রথম বাইক কিনতে ডিলারশিপে আসে এবং Xpulse 210-এ আগ্রহ দেখায়।\r\n\r\nভারতের রাস্তার অবস্থা বিবেচনা করে তার বাবা-মা নিরাপত্তা নিয়ে উদ্বিগ্ন।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(331, 28, 7, 'এজন যুৱ গ্ৰাহক নিজৰ মাক-দেউতাকৰ সৈতে প্ৰথম বাইক কিনিবলৈ ডিলাৰশ্বীপলৈ আহে আৰু Xpulse 210 ত আগ্ৰহ দেখুৱায়।\r\n\r\nভাৰতীয় ৰাস্তাৰ অৱস্থাৰ কথা ভাবি তেওঁৰ মাক-দেউতাক সুৰক্ষাৰ বিষয়ে চিন্তিত।\r\n\r\nএই পৰিস্থিতিত আপুনি কেনেকৈ ব্যৱস্থা ল’ব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(332, 28, 8, 'ஒரு இளைஞர் தனது பெற்றோருடன் தனது முதல் பைக்கை வாங்க டீலர்ஷிப்பிற்கு வந்து Xpulse 210 மீது ஆர்வம் காட்டுகிறார்।\r\n\r\nஇந்திய சாலைகளின் நிலையை கருத்தில் கொண்டு அவரது பெற்றோர் பாதுகாப்பு குறித்து கவலைப்படுகிறார்கள்।\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(333, 28, 9, 'ఒక యువ కస్టమర్ తన తల్లిదండ్రులతో కలిసి తన మొదటి బైక్ కొనడానికి డీలర్‌షిప్‌కు వచ్చి Xpulse 210 పై ఆసక్తి చూపుతున్నాడు।\r\n\r\nభారతీయ రహదారి పరిస్థితులను దృష్టిలో ఉంచుకుని అతని తల్లిదండ్రులు భద్రతపై ఆందోళన చెందుతున్నారు।\r\n\r\nఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(334, 28, 10, 'ഒരു യുവ ഉപഭോക്താവ് തന്റെ മാതാപിതാക്കളുമായി ആദ്യ ബൈക്ക് വാങ്ങാൻ ഡീലർഷിപ്പിൽ എത്തി Xpulse 210-ൽ താൽപര്യം കാണിക്കുന്നു।\r\n\r\nഇന്ത്യൻ റോഡ് സാഹചര്യങ്ങൾ പരിഗണിച്ച് അദ്ദേഹത്തിന്റെ മാതാപിതാക്കൾ സുരക്ഷയെക്കുറിച്ച് ആശങ്കപ്പെടുന്നു।\r\n\r\nഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(335, 28, 11, 'ಒಬ್ಬ ಯುವ ಗ್ರಾಹಕರು ತಮ್ಮ ತಾಯಿ-ತಂದೆಯರೊಂದಿಗೆ ಮೊದಲ ಬೈಕ್ ಖರೀದಿಸಲು ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಬಂದು Xpulse 210 ಬಗ್ಗೆ ಆಸಕ್ತಿ ತೋರಿಸುತ್ತಾರೆ।\r\n\r\nಭಾರತೀಯ ರಸ್ತೆ ಪರಿಸ್ಥಿತಿಯನ್ನು ಗಮನದಲ್ಲಿಟ್ಟುಕೊಂಡು ಅವರ ತಾಯಿ-ತಂದೆಯರು ಸುರಕ್ಷತೆ ಬಗ್ಗೆ ಚಿಂತಿಸುತ್ತಿದ್ದಾರೆ।\r\n\r\nಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(336, 28, 12, 'ଏକ ଯୁବ ଗ୍ରାହକ ତାଙ୍କ ମାତା-ପିତାଙ୍କ ସହ ପ୍ରଥମ ବାଇକ୍ କିଣିବା ପାଇଁ ଡିଲରଶିପ୍‌କୁ ଆସି Xpulse 210 ପ୍ରତି ଆଗ୍ରହ ଦେଖାଉଛନ୍ତି।\r\n\r\nଭାରତୀୟ ରାସ୍ତା ପରିସ୍ଥିତିକୁ ଭାବି ତାଙ୍କ ମାତା-ପିତା ସୁରକ୍ଷା ବିଷୟରେ ଚିନ୍ତିତ ଅଛନ୍ତି।\r\n\r\nଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(337, 29, 1, 'A customer is in the market for a premium 250cc sportbike and mentions that he is also considering models from KTM and Suzuki.\r\n\r\nHe has visited your dealership to experience the Xtreme 250R.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(338, 29, 2, 'एक ग्राहक प्रीमियम 250cc स्पोर्ट्स बाइक खरीदने का सोच रहा है और बताता है कि वह KTM और Suzuki के मॉडल भी देख रहा है।\r\n\r\nवह आपकी डीलरशिप पर Xtreme 250R को देखने और अनुभव करने आया है।\r\n\r\nऐसी स्थिति में आपको क्या करना चाहिए?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(339, 29, 3, 'ਇੱਕ ਗਾਹਕ ਪ੍ਰੀਮਿਅਮ 250cc ਸਪੋਰਟਸ ਬਾਈਕ ਖਰੀਦਣ ਦੀ ਸੋਚ ਰਿਹਾ ਹੈ ਅਤੇ ਕਹਿੰਦਾ ਹੈ ਕਿ ਉਹ KTM ਅਤੇ Suzuki ਦੇ ਮਾਡਲ ਵੀ ਦੇਖ ਰਿਹਾ ਹੈ।\r\n\r\nਉਹ Xtreme 250R ਦਾ ਅਨੁਭਵ ਕਰਨ ਲਈ ਤੁਹਾਡੀ ਡੀਲਰਸ਼ਿਪ ਤੇ ਆਇਆ ਹੈ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(340, 29, 4, 'એક ગ્રાહક પ્રીમિયમ 250cc સ્પોર્ટ્સ બાઈક ખરીદવા ઇચ્છે છે અને કહે છે કે તે KTM અને Suzuki ના મોડેલ્સ પણ વિચારમાં લઈ રહ્યો છે।\r\n\r\nતે Xtreme 250R નો અનુભવ કરવા તમારી ડીલરશિપ પર આવ્યો છે।\r\n\r\nઆ પરિસ્થિતિને તમે કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(341, 29, 5, 'एक ग्राहक प्रीमियम 250cc स्पोर्ट्स बाईक खरेदी करण्याच्या विचारात आहे आणि तो KTM आणि Suzuki चे मॉडेल्सही पाहत असल्याचे सांगतो।\r\n\r\nतो Xtreme 250R चा अनुभव घेण्यासाठी तुमच्या डीलरशिपवर आला आहे।\r\n\r\nअशा परिस्थितीत तुम्ही काय कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(342, 29, 6, 'একজন গ্রাহক প্রিমিয়াম 250cc স্পোর্টস বাইক কেনার কথা ভাবছেন এবং তিনি জানান যে KTM ও Suzuki-এর মডেলও বিবেচনা করছেন।\r\n\r\nতিনি Xtreme 250R অভিজ্ঞতা নিতে আপনার ডিলারশিপে এসেছেন।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(343, 29, 7, 'এজন গ্ৰাহক প্ৰিমিয়াম 250cc স্পৰ্টছ বাইক কিনিবলৈ চিন্তা কৰি আছে আৰু তেওঁ কয় যে KTM আৰু Suzuki ৰ মডেলসমূহো বিবেচনা কৰিছে।\r\n\r\nতেওঁ Xtreme 250R ৰ অভিজ্ঞতা ল\'বলৈ আপোনাৰ ডিলাৰশ্বীপলৈ আহিছে।\r\n\r\nএই পৰিস্থিতিত আপুনি কেনেকৈ ব্যৱস্থা ল’ব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(344, 29, 8, 'ஒரு வாடிக்கையாளர் பிரீமியம் 250cc ஸ்போர்ட்ஸ் பைக் வாங்க விரும்புகிறார் மற்றும் KTM, Suzuki மாடல்களையும் பரிசீலித்து வருவதாக கூறுகிறார்।\r\n\r\nஅவர் Xtreme 250R அனுபவிக்க உங்கள் டீலர்ஷிப்பிற்கு வந்துள்ளார்।\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(345, 29, 9, 'ఒక కస్టమర్ ప్రీమియం 250cc స్పోర్ట్స్ బైక్ కొనాలని ఆలోచిస్తున్నాడు మరియు KTM, Suzuki మోడళ్లను కూడా పరిశీలిస్తున్నానని చెబుతున్నాడు।\r\n\r\nఅతను Xtreme 250R అనుభవించడానికి మీ డీలర్‌షిప్‌కు వచ్చాడు।\r\n\r\nఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(346, 29, 10, 'ഒരു ഉപഭോക്താവ് പ്രീമിയം 250cc സ്പോർട്സ് ബൈക്ക് വാങ്ങാൻ ആലോചിക്കുന്നു, കൂടാതെ KTM, Suzuki മോഡലുകളും പരിഗണിക്കുന്നതായി പറയുന്നു।\r\n\r\nഅദ്ദേഹം Xtreme 250R അനുഭവിക്കാൻ നിങ്ങളുടെ ഡീലർഷിപ്പിൽ എത്തിയിട്ടുണ്ട്।\r\n\r\nഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(347, 29, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕರು ಪ್ರೀಮಿಯಂ 250cc ಸ್ಪೋರ್ಟ್ಸ್ ಬೈಕ್ ಖರೀದಿಸಲು ಯೋಚಿಸುತ್ತಿದ್ದಾರೆ ಮತ್ತು KTM ಹಾಗೂ Suzuki ಮಾದರಿಗಳನ್ನೂ ಪರಿಗಣಿಸುತ್ತಿದ್ದಾರೆ ಎಂದು ಹೇಳುತ್ತಾರೆ।\r\n\r\nಅವರು Xtreme 250R ಅನುಭವಿಸಲು ನಿಮ್ಮ ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಬಂದಿದ್ದಾರೆ।\r\n\r\nಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(348, 29, 12, 'ଏକ ଗ୍ରାହକ ପ୍ରିମିୟମ 250cc ସ୍ପୋର୍ଟସ୍ ବାଇକ୍ କିଣିବାକୁ ଭାବୁଛନ୍ତି ଏବଂ ସେ KTM ଓ Suzuki ମଡେଲ୍‌ଗୁଡ଼ିକୁ ମଧ୍ୟ ବିଚାର କରୁଛନ୍ତି ବୋଲି କହୁଛନ୍ତି।\r\n\r\nସେ Xtreme 250R ର ଅନୁଭବ ପାଇଁ ଆପଣଙ୍କ ଡିଲରଶିପ୍‌କୁ ଆସିଛନ୍ତି।\r\n\r\nଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(349, 30, 1, 'A young customer visits the dealership looking for an adventure motorcycle and shows interest in the Xpulse 200.\r\n\r\nBased on his preferences, you see an opportunity to recommend the Xpulse 210.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(350, 30, 2, 'एक युवा ग्राहक एडवेंचर बाइक लेने के लिए शोरूम आता है और उसे Xpulse 200 पसंद आती है।\r\n\r\nउसकी ज़रूरत और पसंद को देखते हुए आपको लगता है कि आप उसे Xpulse 210 भी सुझा सकते हैं।\r\n\r\nऐसी स्थिति में आपको क्या करना चाहिए?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(351, 30, 3, 'ਇੱਕ ਨੌਜਵਾਨ ਗਾਹਕ ਐਡਵੈਂਚਰ ਮੋਟਰਸਾਈਕਲ ਲੱਭਣ ਲਈ ਡੀਲਰਸ਼ਿਪ ਤੇ ਆਉਂਦਾ ਹੈ ਅਤੇ Xpulse 200 ਵਿੱਚ ਦਿਲਚਸਪੀ ਦਿਖਾਉਂਦਾ ਹੈ।\r\n\r\nਉਸਦੀ ਪਸੰਦ ਨੂੰ ਦੇਖਦੇ ਹੋਏ, ਤੁਹਾਨੂੰ ਲੱਗਦਾ ਹੈ ਕਿ ਤੁਸੀਂ ਉਸਨੂੰ Xpulse 210 ਵੀ ਸਿਫਾਰਸ਼ ਕਰ ਸਕਦੇ ਹੋ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(352, 30, 4, 'એક યુવાન ગ્રાહક એડવેન્ચર મોટરસાયકલ લેવા ડીલરશિપ પર આવે છે અને Xpulse 200 માં રસ બતાવે છે।\r\n\r\nતેની પસંદગીના આધારે તમને લાગે છે કે તમે તેને Xpulse 210 પણ ભલામણ કરી શકો છો।\r\n\r\nઆ પરિસ્થિતિને તમે કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(353, 30, 5, 'एक तरुण ग्राहक अ‍ॅडव्हेंचर मोटरसायकल घेण्यासाठी डीलरशिपवर येतो आणि Xpulse 200 मध्ये रस दाखवतो।\r\n\r\nत्याच्या आवडीनुसार तुम्हाला वाटते की तुम्ही त्याला Xpulse 210 चीही शिफारस करू शकता।\r\n\r\nअशा परिस्थितीत तुम्ही काय कराल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(354, 30, 6, 'একজন তরুণ গ্রাহক অ্যাডভেঞ্চার মোটরসাইকেল খুঁজতে ডিলারশিপে আসেন এবং Xpulse 200-এ আগ্রহ দেখান।\r\n\r\nতার পছন্দ অনুযায়ী আপনি মনে করেন যে Xpulse 210-ও তাকে প্রস্তাব করা যেতে পারে।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(355, 30, 7, 'এজন যুৱ গ্ৰাহক এডভেঞ্চাৰ মটৰচাইকেল বিচাৰি ডিলাৰশ্বীপলৈ আহে আৰু Xpulse 200 ত আগ্ৰহ দেখুৱায়।\r\n\r\nতেওঁৰ পছন্দ অনুসৰি আপুনি ভাবে যে Xpulse 210 টোও সিফাৰিছ কৰিব পাৰে।\r\n\r\nএই পৰিস্থিতিত আপুনি কেনেকৈ ব্যৱস্থা ল’ব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(356, 30, 8, 'ஒரு இளைஞர் அட்வென்சர் மோட்டார் சைக்கிள் வாங்க டீலர்ஷிப்பிற்கு வந்து Xpulse 200 மீது ஆர்வம் காட்டுகிறார்।\r\n\r\nஅவரின் விருப்பங்களை பார்த்து, Xpulse 210-ஐயும் பரிந்துரைக்கலாம் என்று நீங்கள் நினைக்கிறீர்கள்।\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(357, 30, 9, 'ఒక యువ కస్టమర్ అడ్వెంచర్ మోటార్‌సైకిల్ కోసం డీలర్‌షిప్‌కు వచ్చి Xpulse 200 పై ఆసక్తి చూపుతున్నాడు।\r\n\r\nఅతని అభిరుచులను ఆధారంగా మీరు Xpulse 210 ను కూడా సూచించవచ్చని భావిస్తున్నారు।\r\n\r\nఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(358, 30, 10, 'ഒരു യുവ ഉപഭോക്താവ് അഡ്വഞ്ചർ മോട്ടോർസൈക്കിൾ തേടി ഡീലർഷിപ്പിൽ എത്തി Xpulse 200-ൽ താൽപര്യം കാണിക്കുന്നു।\r\n\r\nഅദ്ദേഹത്തിന്റെ അഭിരുചി പരിഗണിച്ച് Xpulse 210-യും ശുപാർശ ചെയ്യാം എന്ന് നിങ്ങൾ കരുതുന്നു।\r\n\r\nഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(359, 30, 11, 'ಒಬ್ಬ ಯುವ ಗ್ರಾಹಕರು ಅಡ್ವೆಂಚರ್ ಮೋಟಾರ್‌ಸೈಕಲ್ ಹುಡುಕಲು ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಬಂದು Xpulse 200 ಬಗ್ಗೆ ಆಸಕ್ತಿ ತೋರಿಸುತ್ತಾರೆ।\r\n\r\nಅವರ ಇಷ್ಟದ ಆಧಾರದ ಮೇಲೆ Xpulse 210 ಅನ್ನು ಕೂಡ ಶಿಫಾರಸು ಮಾಡಬಹುದು ಎಂದು ನೀವು ಭಾವಿಸುತ್ತೀರಿ।\r\n\r\nಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(360, 30, 12, 'ଏକ ଯୁବ ଗ୍ରାହକ ଏଡଭେଞ୍ଚର ମୋଟରସାଇକେଲ୍ ଖୋଜି ଡିଲରଶିପ୍‌କୁ ଆସି Xpulse 200 ପ୍ରତି ଆଗ୍ରହ ଦେଖାଉଛନ୍ତି।\r\n\r\nତାଙ୍କ ପସନ୍ଦ ଆଧାରରେ ଆପଣ Xpulse 210 କୁ ମଧ୍ୟ ସୁପାରିଶ କରିପାରିବେ ବୋଲି ଭାବୁଛନ୍ତି।\r\n\r\nଏହି ପରିସ୍ଥିତିକୁ ଆପଣ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-26 07:03:07', 'Active'),
	(361, 31, 1, 'A customer applied for vehicle finance. During verification, the income declared in the application was found to be incorrect and the loan was rejected.\r\n\r\nThe customer later checked his credit score, found it satisfactory, and returned to the dealership asking why the loan was declined.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(362, 31, 2, 'एक ग्राहक ने वाहन फाइनेंस के लिए आवेदन किया। जांच के दौरान पता चला कि आवेदन में बताई गई आय गलत थी, इसलिए लोन रिजेक्ट हो गया।\r\nबाद में ग्राहक ने अपना क्रेडिट स्कोर चेक किया, जो सही था, और वह डीलरशिप पर वापस आकर पूछने लगा कि लोन क्यों रिजेक्ट हुआ।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(363, 31, 3, 'ਇੱਕ ਗਾਹਕ ਨੇ ਵਾਹਨ ਫਾਇਨੈਂਸ ਲਈ ਅਰਜ਼ੀ ਦਿੱਤੀ। ਜਾਂਚ ਦੌਰਾਨ ਪਤਾ ਲੱਗਿਆ ਕਿ ਅਰਜ਼ੀ ਵਿੱਚ ਦਰਜ ਕੀਤੀ ਆਮਦਨ ਗਲਤ ਸੀ, ਇਸ ਕਰਕੇ ਲੋਨ ਰੱਦ ਹੋ ਗਿਆ।\r\nਬਾਅਦ ਵਿੱਚ ਗਾਹਕ ਨੇ ਆਪਣਾ ਕਰੈਡਿਟ ਸਕੋਰ ਚੈਕ ਕੀਤਾ, ਜੋ ਠੀਕ ਸੀ, ਅਤੇ ਉਹ ਡੀਲਰਸ਼ਿਪ ‘ਤੇ ਵਾਪਸ ਆ ਕੇ ਪੁੱਛਣ ਲੱਗਾ ਕਿ ਲੋਨ ਕਿਉਂ ਰੱਦ ਹੋਇਆ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(364, 31, 4, 'એક ગ્રાહકે વાહન ફાઇનાન્સ માટે અરજી કરી. ચકાસણી દરમિયાન અરજીમાં દર્શાવેલ આવક ખોટી હોવાનું જાણવા મળ્યું અને લોન નામંજૂર થયો.\r\nપછી ગ્રાહકે પોતાનો ક્રેડિટ સ્કોર ચકાસ્યો, જે સંતોષકારક હતો, અને ડીલરશીપ પર આવીને પૂછ્યું કે લોન કેમ નકારાયો.\r\n\r\nતમે આ પરિસ્થિતિને કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(365, 31, 5, 'एका ग्राहकाने वाहन फायनान्ससाठी अर्ज केला. तपासणीदरम्यान अर्जात नमूद केलेले उत्पन्न चुकीचे असल्याचे आढळले आणि कर्ज नाकारले गेले.\r\nनंतर ग्राहकाने आपला क्रेडिट स्कोअर तपासला, जो समाधानकारक होता, आणि तो डीलरशिपवर येऊन विचारू लागला की कर्ज का नाकारले गेले.\r\n\r\nतुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(366, 31, 6, 'একজন গ্রাহক গাড়ির ফাইন্যান্সের জন্য আবেদন করেছিলেন। যাচাইয়ের সময় দেখা গেল যে আবেদনে উল্লেখ করা আয় ভুল ছিল, তাই ঋণ বাতিল করা হয়।\r\nপরে গ্রাহক তার ক্রেডিট স্কোর চেক করে দেখেন যে তা ঠিক আছে, এবং তিনি ডিলারশিপে ফিরে এসে জানতে চান কেন ঋণ বাতিল হয়েছে।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(367, 31, 7, 'এজন গ্ৰাহকে বাহনৰ ফাইনান্সৰ বাবে আবেদন কৰিছিল। যাচাইৰ সময় আবেদনত উল্লেখ কৰা আয় ভুল বুলি ধৰা পৰে আৰু ঋণ নাকচ কৰা হয়।\r\nপিছত গ্ৰাহকে নিজৰ ক্রেডিট স্কোৰ চেক কৰি সন্তোষজনক পায় আৰু ডিলাৰশ্বীপলৈ উভতি আহি সুধে যে ঋণ কিয় নাকচ কৰা হৈছিল।\r\n\r\nআপুনি এই পৰিস্থিতি কেনেকৈ সামলাব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(368, 31, 8, 'ஒரு வாடிக்கையாளர் வாகன நிதிக்கு விண்ணப்பித்தார். சரிபார்ப்பின் போது விண்ணப்பத்தில் குறிப்பிடப்பட்ட வருமானம் தவறாக இருந்தது தெரிய வந்ததால் கடன் நிராகரிக்கப்பட்டது.\r\nபின்னர் வாடிக்கையாளர் தனது கிரெடிட் ஸ்கோரைக் பார்த்தார், அது சரியாக இருந்தது, மற்றும் டீலர்ஷிப்பிற்கு திரும்பி கடன் ஏன் நிராகரிக்கப்பட்டது என்று கேட்டார்.\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(369, 31, 9, 'ఒక కస్టమర్ వాహన ఫైనాన్స్ కోసం దరఖాస్తు చేశాడు. పరిశీలనలో దరఖాస్తులో పేర్కొన్న ఆదాయం తప్పుగా ఉందని తెలిసి లోన్ తిరస్కరించబడింది.\r\nతర్వాత కస్టమర్ తన క్రెడిట్ స్కోర్ చూసి అది సరైనదని తెలుసుకుని, డీలర్‌షిప్‌కు వచ్చి లోన్ ఎందుకు తిరస్కరించబడిందని అడిగాడు.\r\n\r\nమీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(370, 31, 10, 'ഒരു ഉപഭോക്താവ് വാഹന ഫിനാൻസിനായി അപേക്ഷിച്ചു. പരിശോധിക്കുമ്പോൾ അപേക്ഷയിൽ നൽകിയ വരുമാനം തെറ്റാണെന്ന് കണ്ടെത്തി വായ്പ നിരസിക്കപ്പെട്ടു.\r\nശേഷം ഉപഭോക്താവ് തന്റെ ക്രെഡിറ്റ് സ്കോർ പരിശോധിച്ച് അത് ശരിയാണെന്ന് കണ്ടു, പിന്നെ ഡീലർഷിപ്പിലേക്ക് എത്തി വായ്പ എന്തുകൊണ്ട് നിരസിച്ചതെന്ന് ചോദിച്ചു.\r\n\r\nനിങ്ങൾ ഈ സാഹചര്യം എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(371, 31, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕ ವಾಹನ ಹಣಕಾಸಿಗಾಗಿ ಅರ್ಜಿ ಸಲ್ಲಿಸಿದರು. ಪರಿಶೀಲನೆಯ ವೇಳೆ ಅರ್ಜಿಯಲ್ಲಿ ಉಲ್ಲೇಖಿಸಿದ ಆದಾಯ ತಪ್ಪಾಗಿದೆ ಎಂದು ಕಂಡುಬಂದು ಸಾಲು ತಿರಸ್ಕರಿಸಲಾಯಿತು.\r\nನಂತರ ಗ್ರಾಹಕರು ತಮ್ಮ ಕ್ರೆಡಿಟ್ ಸ್ಕೋರ್ ಪರಿಶೀಲಿಸಿ ಅದು ಸರಿಯಾಗಿದೆ ಎಂದು ಕಂಡು, ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಬಂದು ಸಾಲು ಯಾಕೆ ತಿರಸ್ಕರಿಸಲಾಯಿತು ಎಂದು ಕೇಳಿದರು.\r\n\r\nನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(372, 31, 12, 'ଜଣେ ଗ୍ରାହକ ଯାନ ଫାଇନାନ୍ସ ପାଇଁ ଆବେଦନ କରିଥିଲେ। ଯାଞ୍ଚ ସମୟରେ ଆବେଦନରେ ଦିଆଯାଇଥିବା ଆୟ ଭୁଲ ଥିବା ପାଇଁ ଋଣ ରଦ୍ଦ କରାଗଲା।\r\nପରେ ଗ୍ରାହକ ନିଜର କ୍ରେଡିଟ୍ ସ୍କୋର ଯାଞ୍ଚ କରି ସେଥି ଠିକ୍ ଥିବା ଦେଖି ଡିଲରଶିପ୍‌କୁ ଫେରି ଆସି ପଚାରିଲେ ଯେ ଋଣ କାହିଁକି ରଦ୍ଦ ହେଲା।\r\n\r\nଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(373, 32, 1, 'A customer applied for finance to purchase a Hero Glamour XTEC and was informed that approval would be completed within a few hours. \r\n\r\nDue to delays in document verification, the loan was not processed even after three days, and no update was shared. The customer visits the dealership frustrated, concerned about missing an auspicious delivery date.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(374, 32, 2, 'एक ग्राहक ने Hero Glamour XTEC खरीदने के लिए फाइनेंस के लिए आवेदन किया। उसे बताया गया था कि कुछ ही घंटों में लोन मंजूरी मिल जाएगी।\r\n\r\nलेकिन डॉक्यूमेंट वेरिफिकेशन में देरी के कारण तीन दिन बाद भी लोन प्रोसेस नहीं हुआ और कोई अपडेट भी नहीं दिया गया। ग्राहक डीलरशिप पर नाराज़ होकर आया है, क्योंकि उसे शुभ डिलीवरी की तारीख निकल जाने की चिंता है।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(375, 32, 3, 'ਇੱਕ ਗਾਹਕ ਨੇ Hero Glamour XTEC ਖਰੀਦਣ ਲਈ ਫਾਇਨੈਂਸ ਲਈ ਅਰਜ਼ੀ ਦਿੱਤੀ। ਉਸਨੂੰ ਕਿਹਾ ਗਿਆ ਸੀ ਕਿ ਕੁਝ ਘੰਟਿਆਂ ਵਿੱਚ ਮਨਜ਼ੂਰੀ ਮਿਲ ਜਾਵੇਗੀ।\r\n\r\nਪਰ ਦਸਤਾਵੇਜ਼ ਜਾਂਚ ਵਿੱਚ ਦੇਰੀ ਹੋਣ ਕਰਕੇ ਤਿੰਨ ਦਿਨ ਬਾਅਦ ਵੀ ਲੋਨ ਪ੍ਰੋਸੈਸ ਨਹੀਂ ਹੋਇਆ ਅਤੇ ਕੋਈ ਅਪਡੇਟ ਨਹੀਂ ਦਿੱਤਾ ਗਿਆ। ਗਾਹਕ ਨਾਰਾਜ਼ ਹੋ ਕੇ ਡੀਲਰਸ਼ਿਪ ‘ਤੇ ਆਇਆ ਹੈ ਅਤੇ ਉਸਨੂੰ ਸ਼ੁਭ ਡਿਲਿਵਰੀ ਦੀ ਤਾਰੀਖ ਨਿਕਲ ਜਾਣ ਦੀ ਚਿੰਤਾ ਹੈ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(376, 32, 4, 'એક ગ્રાહકે Hero Glamour XTEC ખરીદવા માટે ફાઇનાન્સ માટે અરજી કરી. તેને કહેવામાં આવ્યું હતું કે થોડા કલાકોમાં મંજૂરી મળી જશે.\r\n\r\nપરંતુ દસ્તાવેજ ચકાસણીમાં વિલંબને કારણે ત્રણ દિવસ પછી પણ લોન પ્રોસેસ થયો નથી અને કોઈ અપડેટ આપવામાં આવ્યો નથી. ગ્રાહક નારાજ થઈને ડીલરશીપ પર આવ્યો છે અને શુભ ડિલિવરી તારીખ ચૂકી જવાની ચિંતા કરે છે.\r\n\r\nતમે આ પરિસ્થિતિને કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(377, 32, 5, 'एका ग्राहकाने Hero Glamour XTEC खरेदीसाठी फायनान्ससाठी अर्ज केला. त्याला सांगण्यात आले होते की काही तासांत मंजुरी मिळेल.\r\n\r\nपरंतु कागदपत्र पडताळणीमध्ये विलंब झाल्यामुळे तीन दिवसानंतरही कर्ज प्रक्रिया झाली नाही आणि कोणतीही माहिती देण्यात आली नाही. ग्राहक नाराज होऊन डीलरशिपमध्ये आला आहे आणि शुभ डिलिव्हरीची तारीख चुकण्याची त्याला चिंता आहे.\r\n\r\nतुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(378, 32, 6, 'একজন গ্রাহক Hero Glamour XTEC কেনার জন্য ফাইন্যান্সের আবেদন করেছিলেন। তাকে বলা হয়েছিল কয়েক ঘণ্টার মধ্যে অনুমোদন হয়ে যাবে।\r\n\r\nকিন্তু ডকুমেন্ট যাচাইয়ের দেরির কারণে তিন দিন পরেও ঋণ প্রক্রিয়া হয়নি এবং কোনও আপডেটও দেওয়া হয়নি। গ্রাহক বিরক্ত হয়ে ডিলারশিপে এসেছেন এবং শুভ ডেলিভারির তারিখ মিস হয়ে যাওয়ার চিন্তায় আছেন।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(379, 32, 7, 'এজন গ্ৰাহকে Hero Glamour XTEC কিনিবলৈ ফাইনান্সৰ বাবে আবেদন কৰিছিল। তেওঁক কোৱা হৈছিল যে কেইঘণ্টাৰ ভিতৰতে অনুমোদন সম্পূৰ্ণ হ’ব।\r\n\r\nকিন্তু দস্তাবেজ যাচাইত বিলম্ব হোৱাৰ বাবে তিনিদিন পাছতো ঋণ প্ৰক্ৰিয়া হোৱা নাছিল আৰু কোনো আপডেট দিয়া হোৱা নাছিল। গ্ৰাহক ক্ষুব্ধ হৈ ডিলাৰশ্বীপলৈ আহিছে আৰু শুভ ডেলিভাৰী তাৰিখ মিছ হৈ যোৱাৰ চিন্তাত আছে।\r\n\r\nআপুনি এই পৰিস্থিতি কেনেকৈ সামলাব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(380, 32, 8, 'ஒரு வாடிக்கையாளர் Hero Glamour XTEC வாங்க நிதிக்காக விண்ணப்பித்தார். சில மணி நேரங்களில் அனுமதி கிடைக்கும் என்று கூறப்பட்டது.\r\n\r\nஆனால் ஆவண சரிபார்ப்பில் தாமதம் ஏற்பட்டதால் மூன்று நாட்களுக்குப் பிறகும் கடன் செயல்படுத்தப்படவில்லை, எந்த தகவலும் பகிரப்படவில்லை. வாடிக்கையாளர் கோபமாக டீலர்ஷிப்பிற்கு வந்து, நல்ல நேர டெலிவரி தவறிவிடுமோ என்று கவலைப்படுகிறார்.\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(381, 32, 9, 'ఒక కస్టమర్ Hero Glamour XTEC కొనుగోలు కోసం ఫైనాన్స్‌కు దరఖాస్తు చేశాడు. కొన్ని గంటల్లో ఆమోదం పూర్తవుతుందని చెప్పారు.\r\n\r\nకానీ డాక్యుమెంట్ వెరిఫికేషన్‌లో ఆలస్యం కారణంగా మూడు రోజులైనా లోన్ ప్రాసెస్ కాలేదు మరియు ఎలాంటి అప్డేట్ ఇవ్వలేదు. కస్టమర్ నిరాశతో డీలర్‌షిప్‌కు వచ్చి, శుభ ముహూర్తం డెలివరీ మిస్ అవుతుందేమో అని ఆందోళన చెందుతున్నాడు.\r\n\r\nమీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(382, 32, 10, 'ഒരു ഉപഭോക്താവ് Hero Glamour XTEC വാങ്ങാൻ ഫിനാൻസിന് അപേക്ഷിച്ചു. കുറച്ച് മണിക്കൂറിനുള്ളിൽ അംഗീകാരം ലഭിക്കും എന്ന് അറിയിച്ചിരുന്നു.\r\n\r\nഎന്നാൽ രേഖകളുടെ പരിശോധനയിൽ ഉണ്ടായ വൈകിപ്പിന്റെ കാരണം മൂന്നു ദിവസമായിട്ടും വായ്പ പ്രോസസ് ചെയ്തില്ല, യാതൊരു അപ്‌ഡേറ്റും നൽകിയില്ല. ഉപഭോക്താവ് നിരാശയോടെ ഡീലർഷിപ്പിൽ എത്തി, ശുഭദിനത്തിലെ ഡെലിവറി നഷ്ടപ്പെടുമോ എന്ന ആശങ്കയിലാണ്.\r\n\r\nനിങ്ങൾ ഈ സാഹചര്യം എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(383, 32, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕ Hero Glamour XTEC ಖರೀದಿಸಲು ಹಣಕಾಸಿಗಾಗಿ ಅರ್ಜಿ ಸಲ್ಲಿಸಿದರು. ಕೆಲವು ಗಂಟೆಗಳಲ್ಲಿ ಅನುಮೋದನೆ ಸಿಗುತ್ತದೆ ಎಂದು ತಿಳಿಸಲಾಗಿತ್ತು.\r\n\r\nಆದರೆ ದಾಖಲೆ ಪರಿಶೀಲನೆಯಲ್ಲಿ ವಿಳಂಬವಾದ ಕಾರಣ ಮೂರು ದಿನಗಳಾದರೂ ಸಾಲು ಪ್ರಕ್ರಿಯೆಯಾಗಿಲ್ಲ ಮತ್ತು ಯಾವುದೇ ಅಪ್ಡೇಟ್ ನೀಡಲಾಗಿಲ್ಲ. ಗ್ರಾಹಕರು ಅಸಮಾಧಾನದಿಂದ ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಬಂದು, ಶುಭ ದಿನದ ಡೆಲಿವರಿ ತಪ್ಪಿಹೋಗಬಹುದು ಎಂದು ಚಿಂತಿಸುತ್ತಿದ್ದಾರೆ.\r\n\r\nನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(384, 32, 12, 'ଜଣେ ଗ୍ରାହକ Hero Glamour XTEC କିଣିବା ପାଇଁ ଫାଇନାନ୍ସ ଆବେଦନ କରିଥିଲେ। କିଛି ଘଣ୍ଟା ମଧ୍ୟରେ ମଞ୍ଜୁରି ମିଳିବ ବୋଲି କୁହାଯାଇଥିଲା।\r\n\r\nକିନ୍ତୁ ଡକ୍ୟୁମେଣ୍ଟ ଯାଞ୍ଚରେ ବିଳମ୍ବ ହେବାରୁ ତିନି ଦିନ ପରେ ମଧ୍ୟ ଋଣ ପ୍ରକ୍ରିୟା ହୋଇନି ଏବଂ କୌଣସି ଅପଡେଟ୍ ଦିଆଯାଇନି। ଗ୍ରାହକ ନିରାଶ ହୋଇ ଡିଲରଶିପ୍‌କୁ ଆସିଛନ୍ତି ଏବଂ ଶୁଭ ଡିଲିଭେରୀ ତାରିଖ ମିସ୍ ହେବାର ଚିନ୍ତା କରୁଛନ୍ତି।\r\n\r\nଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(385, 33, 1, 'A customer visits the dealership after seeing a promotional communication mentioning a 0 Down Payment pre-approved finance offer and strong interest in purchasing the vehicle.\r\n\r\nWhile checking the details, you realize the customer is not eligible for the offer. The customer is hopeful and expects to proceed under the same scheme.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(386, 33, 2, 'एक ग्राहक 0 डाउन पेमेंट प्री-अप्रूव्ड फाइनेंस ऑफर का प्रमोशन देखकर डीलरशिप पर आया है और वाहन खरीदने में काफी रुचि दिखा रहा है।\r\n\r\nडिटेल चेक करने पर आपको पता चलता है कि ग्राहक इस ऑफर के लिए पात्र नहीं है। लेकिन ग्राहक उम्मीद कर रहा है कि वही स्कीम के तहत आगे बढ़ेगा।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(387, 33, 3, 'ਇੱਕ ਗਾਹਕ 0 ਡਾਊਨ ਪੇਮੈਂਟ ਪ੍ਰੀ-ਅਪ੍ਰੂਵਡ ਫਾਇਨੈਂਸ ਆਫਰ ਦਾ ਪ੍ਰਮੋਸ਼ਨ ਵੇਖ ਕੇ ਡੀਲਰਸ਼ਿਪ ‘ਤੇ ਆਇਆ ਹੈ ਅਤੇ ਵਾਹਨ ਖਰੀਦਣ ਵਿੱਚ ਦਿਲਚਸਪੀ ਦਿਖਾ ਰਿਹਾ ਹੈ।\r\n\r\nਡਿਟੇਲ ਚੈਕ ਕਰਨ ‘ਤੇ ਤੁਹਾਨੂੰ ਪਤਾ ਲੱਗਦਾ ਹੈ ਕਿ ਗਾਹਕ ਇਸ ਆਫਰ ਲਈ ਯੋਗ ਨਹੀਂ ਹੈ। ਪਰ ਗਾਹਕ ਉਮੀਦ ਕਰ ਰਿਹਾ ਹੈ ਕਿ ਉਹ ਇਸੇ ਸਕੀਮ ਅਧੀਨ ਅੱਗੇ ਵਧੇਗਾ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(388, 33, 4, 'એક ગ્રાહક 0 ડાઉન પેમેન્ટ પ્રી-અપ્રૂવ્ડ ફાઇનાન્સ ઓફરનું પ્રમોશન જોઈને ડીલરશીપ પર આવ્યો છે અને વાહન ખરીદવામાં રસ દાખવી રહ્યો છે.\r\n\r\nવિગતો તપાસતા તમને ખબર પડે છે કે ગ્રાહક આ ઓફર માટે પાત્ર નથી. પરંતુ ગ્રાહક આશાવાદી છે અને એ જ સ્કીમ હેઠળ આગળ વધવા ઇચ્છે છે.\r\n\r\nતમે આ પરિસ્થિતિને કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(389, 33, 5, 'एक ग्राहक 0 डाउन पेमेंट प्री-अप्रूव्ड फायनान्स ऑफरचे प्रमोशन पाहून डीलरशिपमध्ये आला आहे आणि वाहन खरेदीत त्याला रस आहे.\r\n\r\nतपशील तपासल्यावर लक्षात येते की तो या ऑफरसाठी पात्र नाही. पण ग्राहकाला अपेक्षा आहे की त्याच योजनेअंतर्गत प्रक्रिया होईल.\r\n\r\nतुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(390, 33, 6, 'একজন গ্রাহক ০ ডাউন পেমেন্ট প্রি-অ্যাপ্রুভড ফাইন্যান্স অফারের প্রচার দেখে ডিলারশিপে এসেছেন এবং গাড়ি কেনার ব্যাপারে আগ্রহ দেখাচ্ছেন।\r\n\r\nতথ্য যাচাই করে আপনি বুঝতে পারলেন যে তিনি এই অফারের জন্য যোগ্য নন। কিন্তু গ্রাহক আশা করছেন যে একই স্কিমে তিনি এগোতে পারবেন।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(391, 33, 7, 'এজন গ্ৰাহকে 0 ডাউন পেমেন্ট প্ৰি-অপ্ৰুভড ফাইনান্স অফাৰৰ প্ৰচাৰ দেখি ডিলাৰশ্বীপলৈ আহিছে আৰু বাহন কিনিবলৈ আগ্ৰহ দেখুৱাইছে।\r\n\r\nতথ্য যাচাই কৰি আপুনি গম পালে যে তেওঁ এই অফাৰৰ বাবে যোগ্য নহয়। কিন্তু গ্ৰাহকে আশা কৰিছে যে একে স্কীমৰ অধীনতে আগবাঢ়িব।\r\n\r\nআপুনি এই পৰিস্থিতি কেনেকৈ সামলাব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(392, 33, 8, 'ஒரு வாடிக்கையாளர் 0 டவுன் பேமென்ட் பிரி-அப்ப்ரூவ்டு நிதி சலுகை பற்றிய விளம்பரத்தை பார்த்து டீலர்ஷிப்பிற்கு வந்து, வாகனம் வாங்குவதில் ஆர்வம் காட்டுகிறார்.\r\n\r\nவிவரங்களை சரிபார்த்தபோது, அவர் இந்த சலுகைக்கு தகுதி இல்லை என்று தெரிய வருகிறது. ஆனால் வாடிக்கையாளர் அதே திட்டத்தில் முன்னேறுவேன் என்று நம்புகிறார்.\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(393, 33, 9, 'ఒక కస్టమర్ 0 డౌన్ పేమెంట్ ప్రీ-అప్రూవ్డ్ ఫైనాన్స్ ఆఫర్ ప్రకటన చూసి డీలర్‌షిప్‌కు వచ్చి వాహనం కొనుగోలుపై ఆసక్తి చూపుతున్నాడు.\r\n\r\nవివరాలు చెక్ చేయగా అతను ఆ ఆఫర్‌కు అర్హుడు కాదని తెలుస్తోంది. అయితే కస్టమర్ అదే స్కీమ్‌లో ముందుకు వెళ్లాలని ఆశిస్తున్నాడు.\r\n\r\nమీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(394, 33, 10, 'ഒരു ഉപഭോക്താവ് 0 ഡൗൺ പേയ്മെന്റ് പ്രീ-അപ്രൂവ്ഡ് ഫിനാൻസ് ഓഫർ സംബന്ധിച്ച പ്രമോഷൻ കണ്ടു ഡീലർഷിപ്പിൽ എത്തി വാഹനം വാങ്ങാൻ താൽപ്പര്യം പ്രകടിപ്പിക്കുന്നു.\r\n\r\nവിശദാംശങ്ങൾ പരിശോധിക്കുമ്പോൾ, അദ്ദേഹം ഈ ഓഫറിന് അർഹനല്ലെന്ന് മനസ്സിലാകുന്നു. എന്നാൽ ഉപഭോക്താവ് അതേ പദ്ധതിയിൽ മുന്നോട്ട് പോകാമെന്ന് പ്രതീക്ഷിക്കുന്നു.\r\n\r\nനിങ്ങൾ ഈ സാഹചര്യം എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(395, 33, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕ 0 ಡೌನ್ ಪೇಮೆಂಟ್ ಪ್ರೀ-ಅಪ್ರೂವ್ಡ್ ಫೈನಾನ್ಸ್ ಆಫರ್ ಪ್ರಚಾರವನ್ನು ನೋಡಿ ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಬಂದು ವಾಹನ ಖರೀದಿಸಲು ಆಸಕ್ತಿ ತೋರಿದ್ದಾರೆ.\r\n\r\nವಿವರಗಳನ್ನು ಪರಿಶೀಲಿಸಿದಾಗ ಅವರು ಈ ಆಫರ್‌ಗೆ ಅರ್ಹರಾಗಿಲ್ಲ ಎಂಬುದು ತಿಳಿದುಬರುತ್ತದೆ. ಆದರೆ ಗ್ರಾಹಕರು ಅದೇ ಯೋಜನೆಯಡಿ ಮುಂದುವರಿಯುವ ನಿರೀಕ್ಷೆಯಲ್ಲಿ ಇದ್ದಾರೆ.\r\n\r\nನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(396, 33, 12, 'ଜଣେ ଗ୍ରାହକ 0 ଡାଉନ ପେମେଣ୍ଟ ପ୍ରି-ଅପ୍ରୁଭ୍ଡ ଫାଇନାନ୍ସ ଅଫରର ପ୍ରଚାର ଦେଖି ଡିଲରଶିପ୍‌କୁ ଆସିଛନ୍ତି ଏବଂ ଯାନ କିଣିବାରେ ଆଗ୍ରହ ଦେଖାଇଛନ୍ତି।\r\n\r\nବିବରଣୀ ଯାଞ୍ଚ କରିବା ପରେ ଜଣାପଡ଼ିଲା ଯେ ସେ ଏହି ଅଫର ପାଇଁ ଯୋଗ୍ୟ ନୁହେଁ। କିନ୍ତୁ ଗ୍ରାହକ ସେଇ ସ୍କିମ୍‌ରେ ଆଗକୁ ବଢ଼ିବେ ବୋଲି ଆଶା କରୁଛନ୍ତି।\r\n\r\nଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(397, 34, 1, 'A customer reviews the finance quotation shared at the dealership and notices additional charges such as Processing Fee, and Stamp Duty included in the loan amount.\r\n\r\nHe feels these were not explained earlier and questions the dealership’s transparency, asking why these extra charges have been added.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(398, 34, 2, 'एक ग्राहक डीलरशिप में दी गई फाइनेंस कोटेशन देख रहा है। उसे लोन अमाउंट में प्रोसेसिंग फीस और स्टाम्प ड्यूटी जैसे अतिरिक्त चार्ज शामिल दिखते हैं।\r\n\r\nउसे लगता है कि ये बातें पहले नहीं बताई गई थीं, और वह डीलरशिप की पारदर्शिता पर सवाल उठाता है। वह पूछता है कि ये अतिरिक्त चार्ज क्यों जोड़े गए हैं।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(399, 34, 3, 'ਇੱਕ ਗਾਹਕ ਡੀਲਰਸ਼ਿਪ ‘ਤੇ ਦਿੱਤੀ ਗਈ ਫਾਇਨੈਂਸ ਕੋਟੇਸ਼ਨ ਵੇਖਦਾ ਹੈ। ਉਸਨੂੰ ਲੋਨ ਰਕਮ ਵਿੱਚ ਪ੍ਰੋਸੈਸਿੰਗ ਫੀਸ ਅਤੇ ਸਟੈਂਪ ਡਿਊਟੀ ਵਰਗੇ ਵਾਧੂ ਚਾਰਜ ਸ਼ਾਮਲ ਦਿਖਦੇ ਹਨ।\r\n\r\nਉਸਨੂੰ ਲੱਗਦਾ ਹੈ ਕਿ ਇਹ ਪਹਿਲਾਂ ਨਹੀਂ ਸਮਝਾਇਆ ਗਿਆ ਸੀ ਅਤੇ ਉਹ ਡੀਲਰਸ਼ਿਪ ਦੀ ਪਾਰਦਰਸ਼ਤਾ ‘ਤੇ ਸਵਾਲ ਕਰਦਾ ਹੈ। ਉਹ ਪੁੱਛਦਾ ਹੈ ਕਿ ਇਹ ਵਾਧੂ ਚਾਰਜ ਕਿਉਂ ਜੋੜੇ ਗਏ ਹਨ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(400, 34, 4, 'એક ગ્રાહક ડીલરશીપ પર આપવામાં આવેલી ફાઇનાન્સ કોટેશન ચેક કરે છે. તેને લોન રકમમાં પ્રોસેસિંગ ફી અને સ્ટેમ્પ ડ્યૂટી જેવા વધારાના ચાર્જ જોવા મળે છે.\r\n\r\nતેને લાગે છે કે આ પહેલા સમજાવવામાં આવ્યા નહોતા અને તે ડીલરશીપની પારદર્શિતા વિશે પ્રશ્ન કરે છે. તે પૂછે છે કે આ વધારાના ચાર્જ શા માટે ઉમેરવામાં આવ્યા છે.\r\n\r\nતમે આ પરિસ્થિતિને કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(401, 34, 5, 'એક ગ્રાહક ડીલરશીપ પર આપવામાં આવેલી ફાઇનાન્સ કોટેશન ચેક કરે છે. તેને લોન રકમમાં પ્રોસેસિંગ ફી અને સ્ટેમ્પ ડ્યૂટી જેવા વધારાના ચાર્જ જોવા મળે છે.\r\n\r\nતેને લાગે છે કે આ પહેલા સમજાવવામાં આવ્યા નહોતા અને તે ડીલરશીપની પારદર્શિતા વિશે પ્રશ્ન કરે છે. તે પૂછે છે કે આ વધારાના ચાર્જ શા માટે ઉમેરવામાં આવ્યા છે.\r\n\r\nતમે આ પરિસ્થિતિને કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(402, 34, 6, 'একজন গ্রাহক ডিলারশিপে দেওয়া ফাইন্যান্স কোটেশন দেখছেন। তিনি ঋণের পরিমাণের মধ্যে প্রসেসিং ফি এবং স্ট্যাম্প ডিউটির মতো অতিরিক্ত চার্জ দেখতে পান।\r\n\r\nতার মনে হয় এগুলো আগে ব্যাখ্যা করা হয়নি এবং তিনি ডিলারশিপের স্বচ্ছতা নিয়ে প্রশ্ন তোলেন। তিনি জানতে চান কেন এই অতিরিক্ত চার্জ যোগ করা হয়েছে।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(403, 34, 7, 'এজন গ্ৰাহকে ডিলাৰশ্বীপত দিয়া ফাইনান্স কোটেশন চাইছে। তেওঁ ঋণৰ পৰিমাণত প্ৰচেছিং ফী আৰু ষ্টাম্প ডিউটি আদি অতিৰিক্ত চাৰ্জ অন্তৰ্ভুক্ত হোৱা দেখা পাইছে।\r\n\r\nতেওঁৰ মনে হৈছে যে এইবোৰ আগতে বুজোৱা হোৱা নাছিল আৰু তেওঁ ডিলাৰশ্বীপৰ স্বচ্ছতাৰ ওপৰত প্ৰশ্ন উত্থাপন কৰিছে। তেওঁ সুধিছে যে এই অতিৰিক্ত চাৰ্জ কিয় যোগ কৰা হৈছে।\r\n\r\nআপুনি এই পৰিস্থিতি কেনেকৈ সামলাব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(404, 34, 8, 'ஒரு வாடிக்கையாளர் டீலர்ஷிப்பில் வழங்கப்பட்ட நிதி கோட்டேஷனை பார்ப்பார். கடன் தொகையில் செயலாக்க கட்டணம் மற்றும் ஸ்டாம்ப் டியூட்டி போன்ற கூடுதல் கட்டணங்கள் சேர்க்கப்பட்டிருப்பதை கவனிக்கிறார்.\r\n\r\nஇவை முன்பே விளக்கப்படவில்லை என்று அவர் நினைக்கிறார் மற்றும் டீலர்ஷிப்பின் வெளிப்படைத்தன்மையை கேள்வி எழுப்புகிறார். இந்த கூடுதல் கட்டணங்கள் ஏன் சேர்க்கப்பட்டன என்று கேட்கிறார்.\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(405, 34, 9, 'ఒక కస్టమర్ డీలర్‌షిప్‌లో ఇచ్చిన ఫైనాన్స్ కోటేషన్‌ను పరిశీలిస్తున్నాడు. లోన్ మొత్తంలో ప్రాసెసింగ్ ఫీ మరియు స్టాంప్ డ్యూటీ వంటి అదనపు ఛార్జీలు చేర్చబడ్డాయని గమనిస్తున్నాడు.\r\n\r\nఇవి ముందుగా వివరించలేదని భావించి, డీలర్‌షిప్ పారదర్శకతపై ప్రశ్నిస్తున్నాడు. ఈ అదనపు ఛార్జీలు ఎందుకు జోడించబడ్డాయని అడుగుతున్నాడు.\r\n\r\nమీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(406, 34, 10, 'ഒരു ഉപഭോക്താവ് ഡീലർഷിപ്പിൽ നൽകിയ ഫിനാൻസ് ക്വോട്ടേഷൻ പരിശോധിക്കുന്നു. വായ്പയുടെ തുകയിലേക്കു പ്രോസസ്സിംഗ് ഫീസ്, സ്റ്റാമ്പ് ഡ്യൂട്ടി പോലുള്ള അധിക ചാർജുകൾ ഉൾപ്പെടുത്തിയിരിക്കുന്നത് അദ്ദേഹം കാണുന്നു.\r\n\r\nഇത് മുൻകൂട്ടി വിശദീകരിച്ചിട്ടില്ലെന്ന് അദ്ദേഹം കരുതുന്നു, ഡീലർഷിപ്പിന്റെ സുതാര്യതയെ ചോദ്യം ചെയ്യുന്നു. ഈ അധിക ചാർജുകൾ എന്തുകൊണ്ട് ചേർത്തുവെന്ന് ചോദിക്കുന്നു.\r\n\r\nനിങ്ങൾ ഈ സാഹചര്യം എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(407, 34, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕ ಡೀಲರ್‌ಶಿಪ್‌ನಲ್ಲಿ ನೀಡಿದ ಫೈನಾನ್ಸ್ ಕೋಟ್ೇಶನ್ ಪರಿಶೀಲಿಸುತ್ತಿದ್ದಾರೆ. ಸಾಲದ ಮೊತ್ತದಲ್ಲಿ ಪ್ರೊಸೆಸಿಂಗ್ ಫೀ ಮತ್ತು ಸ್ಟಾಂಪ್ ಡ್ಯೂಟಿ ಮೊದಲಾದ ಹೆಚ್ಚುವರಿ ಶುಲ್ಕಗಳನ್ನು ಸೇರಿಸಿರುವುದನ್ನು ಗಮನಿಸುತ್ತಾರೆ.\r\n\r\nಇವುಗಳನ್ನು ಮೊದಲು ವಿವರಿಸಲಾಗಲಿಲ್ಲ ಎಂದು ಅವರು ಭಾವಿಸಿ, ಡೀಲರ್‌ಶಿಪ್‌ನ ಪಾರದರ್ಶಕತೆಯನ್ನು ಪ್ರಶ್ನಿಸುತ್ತಾರೆ. ಈ ಹೆಚ್ಚುವರಿ ಶುಲ್ಕಗಳನ್ನು ಯಾಕೆ ಸೇರಿಸಲಾಗಿದೆ ಎಂದು ಕೇಳುತ್ತಾರೆ.\r\n\r\nನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(408, 34, 12, 'ଜଣେ ଗ୍ରାହକ ଡିଲରଶିପ୍‌ରେ ଦିଆଯାଇଥିବା ଫାଇନାନ୍ସ କୋଟେସନ୍ ଯାଞ୍ଚ କରୁଛନ୍ତି। ସେ ଋଣ ରାଶିରେ ପ୍ରୋସେସିଂ ଫି ଏବଂ ଷ୍ଟାମ୍ପ ଡ୍ୟୁଟି ଭଳି ଅତିରିକ୍ତ ଶୁଳ୍କ ଯୋଡ଼ାଯାଇଥିବା ଦେଖୁଛନ୍ତି।\r\n\r\nସେ ଭାବୁଛନ୍ତି ଯେ ଏହା ପୂର୍ବରୁ ବୁଝାଯାଇନଥିଲା ଏବଂ ଡିଲରଶିପ୍‌ର ପାରଦର୍ଶିତା ଉପରେ ପ୍ରଶ୍ନ କରୁଛନ୍ତି। ସେ ପଚାରୁଛନ୍ତି ଯେ ଏହି ଅତିରିକ୍ତ ଶୁଳ୍କ କାହିଁକି ଯୋଡ଼ାଯାଇଛି।\r\n\r\nଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(409, 35, 1, 'A customer who recently took finance returns to the dealership asking about closing the loan early. \r\n\r\nOn learning about foreclosure charges, he becomes irritated and claims this was never explained during purchase.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(410, 35, 2, 'एक ग्राहक जिसने हाल ही में फाइनेंस लिया था, डीलरशिप पर वापस आता है और लोन को समय से पहले बंद करने के बारे में पूछता है।\r\n\r\nजब उसे फोरक्लोज़र चार्ज के बारे में बताया जाता है, तो वह नाराज़ हो जाता है और कहता है कि खरीदते समय यह बात उसे नहीं बताई गई थी।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(411, 35, 3, 'एक ग्राहक जिसने हाल ही में फाइनेंस लिया था, डीलरशिप पर वापस आता है और लोन को समय से पहले बंद करने के बारे में पूछता है।\r\n\r\nजब उसे फोरक्लोज़र चार्ज के बारे में बताया जाता है, तो वह नाराज़ हो जाता है और कहता है कि खरीदते समय यह बात उसे नहीं बताई गई थी।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(412, 35, 4, 'એક ગ્રાહક જેમણે તાજેતરમાં ફાઇનાન્સ લીધો હતો, ડીલરશીપ પર પાછા આવી લોન વહેલી તકે બંધ કરવાની માહિતી માંગે છે.\r\n\r\nફોરક્લોઝર ચાર્જ વિશે જાણ્યા બાદ તે ચીડાઈ જાય છે અને કહે છે કે ખરીદી વખતે આ બાબત સમજાવવામાં આવી નહોતી.\r\n\r\nતમે આ પરિસ્થિતિને કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(413, 35, 5, 'एका ग्राहकाने अलीकडेच फायनान्स घेतला होता आणि तो डीलरशिपमध्ये परत येऊन कर्ज लवकर फेडण्याबद्दल विचारतो.\r\n\r\nफोरक्लोजर शुल्काबद्दल कळल्यावर तो नाराज होतो आणि सांगतो की खरेदीवेळी ही माहिती दिली नव्हती.\r\n\r\nतुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(414, 35, 6, 'একজন গ্রাহক যিনি সম্প্রতি ফাইন্যান্স নিয়েছেন, তিনি ডিলারশিপে ফিরে এসে ঋণ আগেই বন্ধ করার বিষয়ে জানতে চান।\r\n\r\nফোরক্লোজার চার্জ সম্পর্কে জানার পর তিনি বিরক্ত হয়ে বলেন যে কেনার সময় এটি তাকে জানানো হয়নি।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(415, 35, 7, 'এজন গ্ৰাহকে শেহতীয়া ফাইনান্স লৈছিল আৰু ডিলাৰশ্বীপলৈ উভতি আহি ঋণ আগতেই বন্ধ কৰাৰ বিষয়ে সুধিছে।\r\n\r\nফৰক্ল’জাৰ চাৰ্জৰ কথা জানি তেওঁ ক্ষুব্ধ হৈ কয় যে ক্ৰয়ৰ সময় এই কথা কোৱা হোৱা নাছিল।\r\n\r\nআপুনি এই পৰিস্থিতি কেনেকৈ সামলাব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(416, 35, 8, 'சமீபத்தில் நிதி பெற்ற ஒரு வாடிக்கையாளர் டீலர்ஷிப்பிற்கு திரும்பி கடனை முன்கூட்டியே முடிப்பது குறித்து கேட்கிறார்.\r\n\r\nஃபோர்க்ளோஷர் கட்டணம் இருப்பதை அறிந்ததும் அவர் எரிச்சலடைகிறார் மற்றும் வாங்கும் போது இது சொல்லப்படவில்லை என்று கூறுகிறார்.\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(417, 35, 9, 'ఇటీవల ఫైనాన్స్ తీసుకున్న ఒక కస్టమర్ డీలర్‌షిప్‌కు వచ్చి లోన్‌ను ముందుగానే క్లోజ్ చేయడం గురించి అడుగుతున్నాడు.\r\n\r\nఫోర్‌క్లోజర్ ఛార్జీల గురించి తెలుసుకున్న తర్వాత అతను చిరాకు పడుతూ, కొనుగోలు సమయంలో ఇది చెప్పలేదని అంటున్నాడు.\r\n\r\nమీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(418, 35, 10, 'സമീപകാലത്ത് ഫിനാൻസ് എടുത്ത ഒരു ഉപഭോക്താവ് ഡീലർഷിപ്പിലേക്ക് തിരികെ എത്തി വായ്പ നേരത്തെ അടയ്ക്കുന്നതിനെക്കുറിച്ച് ചോദിക്കുന്നു.\r\n\r\nഫോർക്ലോഷർ ചാർജുകൾ ഉണ്ടെന്ന് അറിഞ്ഞപ്പോൾ അദ്ദേഹം അസ്വസ്ഥനായി, വാങ്ങുമ്പോൾ ഇത് പറഞ്ഞിട്ടില്ലെന്ന് പറയുന്നു.\r\n\r\nനിങ്ങൾ ഈ സാഹചര്യം എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(419, 35, 11, 'ಇತ್ತೀಚೆಗೆ ಫೈನಾನ್ಸ್ ಪಡೆದ ಒಬ್ಬ ಗ್ರಾಹಕರು ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಮರಳಿ ಬಂದು ಸಾಲವನ್ನು ಮುಂಚಿತವಾಗಿ ಮುಚ್ಚುವ ಬಗ್ಗೆ ಕೇಳುತ್ತಾರೆ.\r\n\r\nಫೋರ್‌ಕ್ಲೋಸರ್ ಶುಲ್ಕಗಳ ಬಗ್ಗೆ ತಿಳಿದ ನಂತರ ಅವರು ಅಸಮಾಧಾನಗೊಂಡು, ಖರೀದಿಸುವ ಸಮಯದಲ್ಲಿ ಇದನ್ನು ವಿವರಿಸಲಿಲ್ಲ ಎಂದು ಹೇಳುತ್ತಾರೆ.\r\n\r\nನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(420, 35, 12, 'ସମ୍ପ୍ରତି ଫାଇନାନ୍ସ ନେଇଥିବା ଜଣେ ଗ୍ରାହକ ଡିଲରଶିପ୍‌କୁ ଫେରି ଆସି ଋଣ ପୂର୍ବରୁ ବନ୍ଦ କରିବା ବିଷୟରେ ପଚାରୁଛନ୍ତି।\r\n\r\nଫୋରକ୍ଲୋଜର ଶୁଳ୍କ ବିଷୟରେ ଜାଣିବା ପରେ ସେ ରାଗି ଯାଆନ୍ତି ଏବଂ କହୁଛନ୍ତି ଯେ କିଣିବା ସମୟରେ ଏହା ବୁଝାଯାଇନଥିଲା।\r\n\r\nଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(421, 36, 1, 'A customer has fully repaid his vehicle loan but has not received the NOC (No Objection Certificate) even after several days.\r\n\r\nHe contacts the dealership, sounding worried and frustrated, asking why the document has not been shared yet and whether there is an issue with his loan closure.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(422, 36, 2, 'एक ग्राहक ने अपना वाहन लोन पूरी तरह चुका दिया है, लेकिन कई दिनों बाद भी उसे NOC (नो ऑब्जेक्शन सर्टिफिकेट) नहीं मिला है।\r\n\r\nवह डीलरशिप से संपर्क करता है और चिंतित व नाराज़ लग रहा है। वह पूछता है कि अभी तक डॉक्यूमेंट क्यों नहीं मिला और क्या उसके लोन क्लोजर में कोई समस्या है।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(423, 36, 3, 'ਇੱਕ ਗਾਹਕ ਨੇ ਆਪਣਾ ਵਾਹਨ ਲੋਨ ਪੂਰੀ ਤਰ੍ਹਾਂ ਅਦਾ ਕਰ ਦਿੱਤਾ ਹੈ, ਪਰ ਕਈ ਦਿਨਾਂ ਬਾਅਦ ਵੀ ਉਸਨੂੰ NOC (ਨੋ ਓਬਜੈਕਸ਼ਨ ਸਰਟੀਫਿਕੇਟ) ਨਹੀਂ ਮਿਲਿਆ।\r\n\r\nਉਹ ਡੀਲਰਸ਼ਿਪ ਨਾਲ ਸੰਪਰਕ ਕਰਦਾ ਹੈ ਅਤੇ ਚਿੰਤਿਤ ਤੇ ਨਾਰਾਜ਼ ਲੱਗਦਾ ਹੈ। ਉਹ ਪੁੱਛਦਾ ਹੈ ਕਿ ਦਸਤਾਵੇਜ਼ ਅਜੇ ਤੱਕ ਕਿਉਂ ਨਹੀਂ ਮਿਲਿਆ ਅਤੇ ਕੀ ਲੋਨ ਕਲੋਜ਼ਰ ਵਿੱਚ ਕੋਈ ਸਮੱਸਿਆ ਹੈ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(424, 36, 4, 'એક ગ્રાહકે પોતાનો વાહન લોન સંપૂર્ણ ચૂકવી દીધો છે, પરંતુ ઘણા દિવસો બાદ પણ તેને NOC (નો ઑબ્જેક્શન સર્ટિફિકેટ) મળ્યું નથી.\r\n\r\nતે ડીલરશીપનો સંપર્ક કરે છે અને ચિંતિત તથા નારાજ લાગે છે. તે પૂછે છે કે દસ્તાવેજ હજુ સુધી કેમ મળ્યો નથી અને શું લોન ક્લોઝરમાં કોઈ સમસ્યા છે.\r\n\r\nતમે આ પરિસ્થિતિને કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(425, 36, 5, 'एका ग्राहकाने आपले वाहन कर्ज पूर्णपणे फेडले आहे, पण अनेक दिवस झाले तरी त्याला NOC (नो ऑब्जेक्शन सर्टिफिकेट) मिळालेले नाही.\r\n\r\nतो डीलरशिपशी संपर्क साधतो आणि चिंतित व नाराज दिसतो. तो विचारतो की कागदपत्र अजून का मिळाले नाही आणि कर्ज बंद करण्यात काही अडचण आहे का.\r\n\r\nतुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(426, 36, 6, 'একজন গ্রাহক তার গাড়ির ঋণ পুরোপুরি শোধ করেছেন, কিন্তু কয়েক দিন পরেও তিনি NOC (নো অবজেকশন সার্টিফিকেট) পাননি।\r\n\r\nতিনি ডিলারশিপে যোগাযোগ করেন এবং উদ্বিগ্ন ও বিরক্ত শোনান। তিনি জানতে চান কেন এখনো নথি দেওয়া হয়নি এবং ঋণ বন্ধ করতে কোনও সমস্যা আছে কি না।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(427, 36, 7, 'এজন গ্ৰাহকে নিজৰ বাহনৰ ঋণ সম্পূৰ্ণকৈ পৰিশোধ কৰিছে, কিন্তু কেইবাদিন পিছতো তেওঁ NOC (নো অবজেকশন চাৰ্টিফিকেট) পোৱা নাই।\r\n\r\nতেওঁ ডিলাৰশ্বীপৰ সৈতে যোগাযোগ কৰিছে আৰু চিন্তিত তথা ক্ষুব্ধ শুনা যায়। তেওঁ সুধিছে যে দস্তাবেজ এতিয়াও কিয় দিয়া হোৱা নাই আৰু ঋণ বন্ধ কৰাত কোনো সমস্যা আছে নেকি।\r\n\r\nআপুনি এই পৰিস্থিতি কেনেকৈ সামলাব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(428, 36, 8, 'ஒரு வாடிக்கையாளர் தனது வாகன கடனை முழுமையாக செலுத்தியுள்ளார், ஆனால் பல நாட்களாகியும் NOC (நோ ஒப்ஜெக்ஷன் சர்டிபிகேட்) பெறவில்லை.\r\n\r\nஅவர் டீலர்ஷிப்பை தொடர்புகொண்டு கவலையுடன் மற்றும் ஏமாற்றத்துடன் பேசுகிறார். ஆவணம் இன்னும் ஏன் வழங்கப்படவில்லை மற்றும் கடன் முடிப்பதில் ஏதேனும் பிரச்சனை உள்ளதா என்று கேட்கிறார்.\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(429, 36, 9, 'ఒక కస్టమర్ తన వాహన లోన్‌ను పూర్తిగా చెల్లించాడు, కానీ కొన్ని రోజులైనా NOC (నో అబ్జెక్షన్ సర్టిఫికేట్) పొందలేదు.\r\n\r\nఅతను డీలర్‌షిప్‌ను సంప్రదించి ఆందోళనతో మరియు అసహనంతో మాట్లాడుతున్నాడు. డాక్యుమెంట్ ఇంకా ఎందుకు ఇవ్వలేదని, లోన్ క్లోజర్‌లో ఏమైనా సమస్య ఉందా అని అడుగుతున్నాడు.\r\n\r\nమీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(430, 36, 10, 'ഒരു ഉപഭോക്താവ് തന്റെ വാഹന വായ്പ പൂർണ്ണമായും അടച്ചിട്ടുണ്ട്, എന്നാൽ പല ദിവസങ്ങൾ കഴിഞ്ഞിട്ടും NOC (നോ ഒബ്ജക്ഷൻ സർട്ടിഫിക്കറ്റ്) ലഭിച്ചിട്ടില്ല.\r\n\r\nഅദ്ദേഹം ഡീലർഷിപ്പുമായി ബന്ധപ്പെടുകയും ആശങ്കയോടും അസ്വസ്ഥതയോടും സംസാരിക്കുകയും ചെയ്യുന്നു. രേഖ ഇതുവരെ എന്തുകൊണ്ട് നൽകിയിട്ടില്ലെന്നും വായ്പ അടച്ചതിൽ എന്തെങ്കിലും പ്രശ്നമുണ്ടോയെന്നും ചോദിക്കുന്നു.\r\n\r\nനിങ്ങൾ ഈ സാഹചര്യം എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(431, 36, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕರು ತಮ್ಮ ವಾಹನ ಸಾಲನ್ನು ಸಂಪೂರ್ಣವಾಗಿ ತೀರಿಸಿದ್ದಾರೆ, ಆದರೆ ಹಲವಾರು ದಿನಗಳಾದರೂ NOC (ನೋ ಒಬ್ಜೆಕ್ಷನ್ ಸರ್ಟಿಫಿಕೇಟ್) ಪಡೆಯಿಲ್ಲ.\r\n\r\nಅವರು ಡೀಲರ್‌ಶಿಪ್ ಅನ್ನು ಸಂಪರ್ಕಿಸಿ ಚಿಂತಿತ ಹಾಗೂ ಅಸಮಾಧಾನಗೊಂಡ ಧ್ವನಿಯಲ್ಲಿ ಕೇಳುತ್ತಾರೆ. ದಾಖಲೆ ಇನ್ನೂ ಏಕೆ ನೀಡಲಾಗಿಲ್ಲ ಮತ್ತು ಸಾಲ ಮುಚ್ಚುವಿಕೆಯಲ್ಲಿ ಯಾವುದೇ ಸಮಸ್ಯೆಯಿದೆಯೇ ಎಂದು ಪ್ರಶ್ನಿಸುತ್ತಾರೆ.\r\n\r\nನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(432, 36, 12, 'ଜଣେ ଗ୍ରାହକ ନିଜର ଯାନ ଋଣ ପୂରାପୁରି ଶୋଧ କରିଛନ୍ତି, କିନ୍ତୁ କେତେକ ଦିନ ପରେ ମଧ୍ୟ ସେ NOC (ନୋ ଅବଜେକ୍ସନ ସର୍ଟିଫିକେଟ୍) ପାଇନାହାନ୍ତି।\r\n\r\nସେ ଡିଲରଶିପ୍‌ ସହିତ ସମ୍ପର୍କ କରି ଚିନ୍ତିତ ଓ ନିରାଶ ଭାବରେ ପଚାରୁଛନ୍ତି ଯେ ଡକ୍ୟୁମେଣ୍ଟ ଏପର୍ଯ୍ୟନ୍ତ କାହିଁକି ଦିଆଯାଇନି ଏବଂ ଋଣ ବନ୍ଦ ହେବାରେ କୌଣସି ସମସ୍ୟା ଅଛି କି।\r\n\r\nଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(433, 37, 1, 'During discussion, the customer was told an estimated EMI and loan amount based on a scheme.\r\n\r\nAfter approval, the sanctioned amount differs, resulting in a higher EMI. The customer feels misled and questions the credibility of the dealership.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(434, 37, 2, 'चर्चा के दौरान ग्राहक को एक स्कीम के आधार पर अनुमानित EMI और लोन अमाउंट बताया गया था।\r\n\r\nलेकिन मंजूरी के बाद स्वीकृत लोन राशि अलग निकली, जिससे EMI ज्यादा हो गई। ग्राहक को लगता है कि उसे गुमराह किया गया है और वह डीलरशिप की विश्वसनीयता पर सवाल उठाता है।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(435, 37, 3, 'ਗੱਲਬਾਤ ਦੌਰਾਨ ਗਾਹਕ ਨੂੰ ਇੱਕ ਸਕੀਮ ਦੇ ਅਧਾਰ ‘ਤੇ ਅੰਦਾਜ਼ਨ EMI ਅਤੇ ਲੋਨ ਰਕਮ ਦੱਸੀ ਗਈ ਸੀ।\r\n\r\nਪਰ ਮਨਜ਼ੂਰੀ ਤੋਂ ਬਾਅਦ ਮਨਜ਼ੂਰ ਕੀਤੀ ਗਈ ਰਕਮ ਵੱਖਰੀ ਨਿਕਲੀ, ਜਿਸ ਕਰਕੇ EMI ਵੱਧ ਗਈ। ਗਾਹਕ ਨੂੰ ਲੱਗਦਾ ਹੈ ਕਿ ਉਸਨੂੰ ਗੁੰਮਰਾਹ ਕੀਤਾ ਗਿਆ ਹੈ ਅਤੇ ਉਹ ਡੀਲਰਸ਼ਿਪ ਦੀ ਭਰੋਸੇਯੋਗਤਾ ‘ਤੇ ਸਵਾਲ ਕਰਦਾ ਹੈ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(436, 37, 4, 'ચર્ચા દરમિયાન ગ્રાહકને એક સ્કીમ આધારિત અંદાજિત EMI અને લોન રકમ જણાવવામાં આવી હતી.\r\n\r\nપરંતુ મંજૂરી બાદ સૅન્કશન્ડ રકમ અલગ નીકળી, જેના કારણે EMI વધારે થઈ ગઈ. ગ્રાહકને લાગે છે કે તેને ભ્રમિત કરવામાં આવ્યો છે અને તે ડીલરશીપની વિશ્વસનીયતા પર પ્રશ્ન ઉઠાવે છે.\r\n\r\nતમે આ પરિસ્થિતિને કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(437, 37, 5, 'चर्चेदरम्यान ग्राहकाला एका योजनेनुसार अंदाजे EMI आणि कर्ज रक्कम सांगितली होती.\r\n\r\nमात्र मंजुरीनंतर मंजूर झालेली रक्कम वेगळी निघाली आणि EMI वाढली. ग्राहकाला वाटते की त्याची दिशाभूल झाली आहे आणि तो डीलरशिपच्या विश्वासार्हतेवर प्रश्न विचारतो.\r\n\r\nतुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(438, 37, 6, 'আলোচনার সময় গ্রাহককে একটি স্কিমের ভিত্তিতে আনুমানিক EMI এবং ঋণের পরিমাণ জানানো হয়েছিল।\r\n\r\nকিন্তু অনুমোদনের পর মঞ্জুর হওয়া ঋণের পরিমাণ ভিন্ন হয়, ফলে EMI বেড়ে যায়। গ্রাহক মনে করেন তাকে ভুলভাবে বোঝানো হয়েছে এবং ডিলারশিপের বিশ্বাসযোগ্যতা নিয়ে প্রশ্ন তোলেন।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(439, 37, 7, 'আলোচনাৰ সময় গ্ৰাহকক এটা স্কীমৰ ভিত্তিত অনুমানিক EMI আৰু ঋণৰ পৰিমাণ কোৱা হৈছিল।\r\n\r\nকিন্তু অনুমোদনৰ পিছত মঞ্জুৰ হোৱা ৰাশি বেলেগ ওলাল, যাৰ ফলত EMI বেছি হৈ গ’ল। গ্ৰাহকে ভাবে যে তেওঁক বিভ্ৰান্ত কৰা হৈছে আৰু ডিলাৰশ্বীপৰ বিশ্বাসযোগ্যতাৰ ওপৰত প্ৰশ্ন তোলে।\r\n\r\nআপুনি এই পৰিস্থিতি কেনেকৈ সামলাব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(440, 37, 8, 'விவாதத்தின் போது வாடிக்கையாளருக்கு ஒரு திட்டத்தின் அடிப்படையில் கணிக்கப்பட்ட EMI மற்றும் கடன் தொகை கூறப்பட்டது.\r\n\r\nஆனால் அனுமதிக்குப் பிறகு ஒப்புதல் பெற்ற தொகை மாறுபட்டதால் EMI அதிகரித்தது. வாடிக்கையாளர் தன்னை தவறாக வழிநடத்தப்பட்டதாக உணர்ந்து டீலர்ஷிப்பின் நம்பகத்தன்மையை கேள்வி கேட்கிறார்.\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(441, 37, 9, 'చర్చ సమయంలో కస్టమర్‌కు ఒక స్కీమ్ ఆధారంగా అంచనా EMI మరియు లోన్ మొత్తాన్ని చెప్పారు.\r\n\r\nకానీ ఆమోదం తర్వాత మంజూరైన మొత్తం భిన్నంగా ఉండడంతో EMI పెరిగింది. కస్టమర్ తనను తప్పుదారి పట్టించారని భావించి డీలర్‌షిప్ నమ్మకాన్ని ప్రశ్నిస్తున్నాడు.\r\n\r\nమీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(442, 37, 10, 'ചർച്ചയ്ക്കിടെ ഉപഭോക്താവിന് ഒരു സ്കീമിന്റെ അടിസ്ഥാനത്തിൽ ഏകദേശ EMIയും വായ്പ തുകയും പറഞ്ഞിരുന്നു.\r\n\r\nഎന്നാൽ അംഗീകാരത്തിന് ശേഷം അനുവദിച്ച തുക വ്യത്യസ്തമായതിനാൽ EMI കൂടുകയായിരുന്നു. ഉപഭോക്താവ് തനിക്കു തെറ്റിദ്ധരിപ്പിച്ചതായി കരുതി ഡീലർഷിപ്പിന്റെ വിശ്വാസ്യത ചോദ്യം ചെയ്യുന്നു.\r\n\r\nനിങ്ങൾ ഈ സാഹചര്യം എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(443, 37, 11, 'ಚರ್ಚೆಯ ಸಮಯದಲ್ಲಿ ಗ್ರಾಹಕರಿಗೆ ಒಂದು ಯೋಜನೆಯ ಆಧಾರದ ಮೇಲೆ ಅಂದಾಜು EMI ಮತ್ತು ಸಾಲದ ಮೊತ್ತ ತಿಳಿಸಲಾಯಿತು.\r\n\r\nಆದರೆ ಅನುಮೋದನೆಯ ನಂತರ ಮಂಜೂರಾದ ಮೊತ್ತ ಭಿನ್ನವಾಗಿದ್ದು, EMI ಹೆಚ್ಚಾಗಿದೆ. ಗ್ರಾಹಕರು ತಮ್ಮನ್ನು ತಪ್ಪು ದಾರಿಗೆಳೆಯಲಾಗಿದೆ ಎಂದು ಭಾವಿಸಿ ಡೀಲರ್‌ಶಿಪ್‌ನ ವಿಶ್ವಾಸಾರ್ಹತೆಯನ್ನು ಪ್ರಶ್ನಿಸುತ್ತಾರೆ.\r\n\r\nನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(444, 37, 12, 'ଆଲୋଚନା ସମୟରେ ଗ୍ରାହକଙ୍କୁ ଗୋଟିଏ ସ୍କିମ୍ ଆଧାରରେ ଅନୁମାନିତ EMI ଏବଂ ଋଣ ରାଶି କୁହାଯାଇଥିଲା।\r\n\r\nକିନ୍ତୁ ମଞ୍ଜୁରି ପରେ ଅନୁମୋଦିତ ରାଶି ଭିନ୍ନ ହେବାରୁ EMI ବଢ଼ିଗଲା। ଗ୍ରାହକଙ୍କୁ ଲାଗୁଛି ଯେ ତାଙ୍କୁ ଭ୍ରମିତ କରାଯାଇଛି ଏବଂ ସେ ଡିଲରଶିପ୍‌ର ବିଶ୍ୱସନୀୟତା ଉପରେ ପ୍ରଶ୍ନ କରୁଛନ୍ତି।\r\n\r\nଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(445, 38, 1, 'A customer compares the dealership’s finance quotation with an offer from his own bank branch and finds the dealership option more expensive.\r\n\r\nHe questions why he should proceed through the dealership instead of arranging finance independently.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(446, 38, 2, 'एक ग्राहक डीलरशिप की फाइनेंस कोटेशन की तुलना अपने बैंक ब्रांच के ऑफर से करता है और पाता है कि डीलरशिप का विकल्प महंगा है।\r\n\r\nवह पूछता है कि जब बैंक से सस्ता फाइनेंस मिल रहा है, तो उसे डीलरशिप के जरिए ही क्यों आगे बढ़ना चाहिए।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(447, 38, 3, 'ਇੱਕ ਗਾਹਕ ਡੀਲਰਸ਼ਿਪ ਦੀ ਫਾਇਨੈਂਸ ਕੋਟੇਸ਼ਨ ਦੀ ਤੁਲਨਾ ਆਪਣੇ ਬੈਂਕ ਦੇ ਆਫਰ ਨਾਲ ਕਰਦਾ ਹੈ ਅਤੇ ਵੇਖਦਾ ਹੈ ਕਿ ਡੀਲਰਸ਼ਿਪ ਵਾਲਾ ਵਿਕਲਪ ਮਹਿੰਗਾ ਹੈ।\r\n\r\nਉਹ ਪੁੱਛਦਾ ਹੈ ਕਿ ਜਦੋਂ ਬੈਂਕ ਤੋਂ ਸਸਤਾ ਫਾਇਨੈਂਸ ਮਿਲ ਰਿਹਾ ਹੈ, ਤਾਂ ਉਹ ਡੀਲਰਸ਼ਿਪ ਰਾਹੀਂ ਕਿਉਂ ਕਰੇ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(448, 38, 4, 'એક ગ્રાહક ડીલરશીપની ફાઇનાન્સ કોટેશનની તુલના પોતાની બેંક બ્રાન્ચના ઓફર સાથે કરે છે અને જુએ છે કે ડીલરશીપ વિકલ્પ વધુ મોંઘો છે.\r\n\r\nતે પૂછે છે કે જ્યારે બેંકમાંથી સસ્તુ ફાઇનાન્સ મળી રહ્યું છે, ત્યારે ડીલરશીપ મારફતે જ કેમ આગળ વધવું જોઈએ.\r\n\r\nતમે આ પરિસ્થિતિને કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(449, 38, 5, 'एक ग्राहक डीलरशिपच्या फायनान्स कोटेशनची तुलना आपल्या बँक शाखेच्या ऑफरशी करतो आणि डीलरशिपचा पर्याय महाग असल्याचे त्याला दिसते.\r\n\r\nतो विचारतो की जेव्हा बँकेतून स्वस्त फायनान्स मिळत आहे, तेव्हा डीलरशिपमार्फतच का करावे.\r\n\r\nतुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(450, 38, 6, 'একজন গ্রাহক ডিলারশিপের ফাইন্যান্স কোটেশনের সাথে তার নিজের ব্যাংক শাখার অফারের তুলনা করে দেখেন যে ডিলারশিপের বিকল্পটি বেশি খরচের।\r\n\r\nতিনি প্রশ্ন করেন, যখন ব্যাংক থেকে সস্তায় ফাইন্যান্স পাওয়া যাচ্ছে, তখন কেন ডিলারশিপের মাধ্যমে এগোতে হবে।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(451, 38, 7, 'এজন গ্ৰাহকে ডিলাৰশ্বীপৰ ফাইনান্স কোটেশ্যন নিজৰ বেংকৰ অফাৰৰ সৈতে তুলনা কৰি দেখে যে ডিলাৰশ্বীপৰ বিকল্পটো বেছি খৰচৰ।\r\n\r\nতেওঁ সুধিছে যে যেতিয়া বেংকৰ পৰা সস্তাত ফাইনান্স পোৱা যায়, তেন্তে ডিলাৰশ্বীপৰ জৰিয়তে কিয় আগবাঢ়িব লাগে।\r\n\r\nআপুনি এই পৰিস্থিতি কেনেকৈ সামলাব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(452, 38, 8, 'ஒரு வாடிக்கையாளர் டீலர்ஷிப்பின் நிதி கோட்டேஷனை தனது வங்கி கிளையின் சலுகையுடன் ஒப்பிட்டு பார்க்கிறார் மற்றும் டீலர்ஷிப் விருப்பம் அதிக செலவாக இருப்பதை காண்கிறார்.\r\n\r\nவங்கியில் குறைந்த செலவில் நிதி கிடைக்கும்போது, ஏன் டீலர்ஷிப் மூலம் செல்ல வேண்டும் என்று அவர் கேட்கிறார்.\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(453, 38, 9, 'ఒక కస్టమర్ డీలర్‌షిప్ ఫైనాన్స్ కోటేషన్‌ను తన బ్యాంక్ బ్రాంచ్ ఆఫర్‌తో పోల్చి చూస్తే, డీలర్‌షిప్ ఎంపిక ఖరీదుగా ఉందని తెలుసుకుంటాడు.\r\n\r\nబ్యాంక్ నుండి తక్కువ ఖర్చుతో ఫైనాన్స్ లభిస్తే, డీలర్‌షిప్ ద్వారా ఎందుకు ముందుకు వెళ్లాలి అని అడుగుతున్నాడు.\r\n\r\nమీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(454, 38, 10, 'ഒരു ഉപഭോക്താവ് ഡീലർഷിപ്പിന്റെ ഫിനാൻസ് ക്വോട്ടേഷൻ തന്റെ ബാങ്ക് ശാഖയിലെ ഓഫറുമായി താരതമ്യം ചെയ്ത്, ഡീലർഷിപ്പ് ഓപ്ഷൻ കൂടുതൽ ചെലവാണെന്ന് കാണുന്നു.\r\n\r\nബാങ്കിൽ നിന്ന് കുറഞ്ഞ ചെലവിൽ ഫിനാൻസ് ലഭിക്കുമ്പോൾ, എന്തുകൊണ്ട് ഡീലർഷിപ്പിലൂടെ തന്നെ പോകണം എന്ന് അദ്ദേഹം ചോദിക്കുന്നു.\r\n\r\nനിങ്ങൾ ഈ സാഹചര്യം എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(455, 38, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕರು ಡೀಲರ್‌ಶಿಪ್‌ನ ಫೈನಾನ್ಸ್ ಕೋಟ್ೇಶನ್ ಅನ್ನು ತಮ್ಮ ಬ್ಯಾಂಕ್ ಶಾಖೆಯ ಆಫರ್ ಜೊತೆಗೆ ಹೋಲಿಸಿ ನೋಡುತ್ತಾರೆ ಮತ್ತು ಡೀಲರ್‌ಶಿಪ್ ಆಯ್ಕೆ ಹೆಚ್ಚು ಖರ್ಚಾಗಿದೆ ಎಂದು ಗಮನಿಸುತ್ತಾರೆ.\r\n\r\nಬ್ಯಾಂಕ್‌ನಿಂದ ಕಡಿಮೆ ಖರ್ಚಿನಲ್ಲಿ ಫೈನಾನ್ಸ್ ಸಿಗುತ್ತಿದ್ದರೆ, ಡೀಲರ್‌ಶಿಪ್ ಮೂಲಕವೇ ಯಾಕೆ ಮುಂದುವರಿಯಬೇಕು ಎಂದು ಕೇಳುತ್ತಾರೆ.\r\n\r\nನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(456, 38, 12, 'ଜଣେ ଗ୍ରାହକ ଡିଲରଶିପ୍‌ର ଫାଇନାନ୍ସ କୋଟେସନ୍‌କୁ ନିଜ ବ୍ୟାଙ୍କ ଶାଖାର ଅଫର ସହିତ ତୁଳନା କରି ଦେଖନ୍ତି ଯେ ଡିଲରଶିପ୍‌ର ବିକଳ୍ପ ଅଧିକ ଖର୍ଚ୍ଚାଳୁ।\r\n\r\nସେ ପଚାରୁଛନ୍ତି ଯେ ଯେତେବେଳେ ବ୍ୟାଙ୍କରୁ ସସ୍ତା ଫାଇନାନ୍ସ ମିଳୁଛି, ତେବେ ଡିଲରଶିପ୍‌ ମାଧ୍ୟମରେ କାହିଁକି ଆଗକୁ ବଢ଼ିବା ଉଚିତ?\r\n\r\nଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(457, 39, 1, 'A customer feels the dealership is repeatedly insisting on processing the loan through one specific financer, even after he has shown interest in another option. \r\n\r\nHe suspects biased guidance.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(458, 39, 2, 'एक ग्राहक को लगता है कि डीलरशिप बार-बार एक ही फाइनेंसर के जरिए लोन कराने पर ज़ोर दे रही है, जबकि उसने किसी दूसरे विकल्प में भी रुचि दिखाई है।\r\n\r\nउसे शक हो रहा है कि उसे पक्षपातपूर्ण सलाह दी जा रही है।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(459, 39, 3, 'ਇੱਕ ਗਾਹਕ ਨੂੰ ਲੱਗਦਾ ਹੈ ਕਿ ਡੀਲਰਸ਼ਿਪ ਵਾਰ-ਵਾਰ ਇੱਕ ਹੀ ਫਾਇਨੈਂਸਰ ਰਾਹੀਂ ਲੋਨ ਕਰਨ ‘ਤੇ ਜ਼ੋਰ ਦੇ ਰਹੀ ਹੈ, ਜਦੋਂ ਕਿ ਉਸਨੇ ਕਿਸੇ ਹੋਰ ਵਿਕਲਪ ਵਿੱਚ ਵੀ ਦਿਲਚਸਪੀ ਦਿਖਾਈ ਹੈ।\r\n\r\nਉਸਨੂੰ ਸ਼ੱਕ ਹੈ ਕਿ ਉਸਨੂੰ ਪੱਖਪਾਤ ਵਾਲੀ ਸਲਾਹ ਦਿੱਤੀ ਜਾ ਰਹੀ ਹੈ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(460, 39, 4, 'એક ગ્રાહકને લાગે છે કે ડીલરશીપ વારંવાર એક જ ફાઇનાન્સર મારફતે લોન પ્રોસેસ કરવા દબાણ કરી રહી છે, જ્યારે તેણે બીજા વિકલ્પમાં પણ રસ દર્શાવ્યો છે.\r\n\r\nતેને શંકા થાય છે કે તેને પક્ષપાતપૂર્ણ માર્ગદર્શન આપવામાં આવી રહ્યું છે.\r\n\r\nતમે આ પરિસ્થિતિને કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(461, 39, 5, 'एका ग्राहकाला वाटते की डीलरशिप वारंवार एकाच फायनान्सरमार्फत कर्ज प्रक्रिया करण्यावर आग्रह धरत आहे, जरी त्याने दुसऱ्या पर्यायातही रस दाखवला आहे.\r\n\r\nत्याला संशय येतो की त्याला पक्षपाती मार्गदर्शन दिले जात आहे.\r\n\r\nतुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(462, 39, 6, 'একজন গ্রাহকের মনে হচ্ছে ডিলারশিপ বারবার একটি নির্দিষ্ট ফাইন্যান্সারের মাধ্যমে ঋণ প্রক্রিয়া করতে চাপ দিচ্ছে, যদিও তিনি অন্য একটি বিকল্পেও আগ্রহ দেখিয়েছেন।\r\n\r\nতার সন্দেহ হচ্ছে যে তাকে পক্ষপাতমূলক পরামর্শ দেওয়া হচ্ছে।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(463, 39, 7, 'এজন গ্ৰাহকৰ মনে হৈছে যে ডিলাৰশ্বীপে বাৰে বাৰে এটা নিৰ্দিষ্ট ফাইনান্সাৰৰ জৰিয়তে ঋণ প্ৰক্ৰিয়া কৰিবলৈ জোৰ দিছে, যদিও তেওঁ আন এটা বিকল্পতো আগ্ৰহ দেখুৱাইছে।\r\n\r\nতেওঁ সন্দেহ কৰিছে যে তেওঁক পক্ষপাতমূলক পৰামৰ্শ দিয়া হৈছে।\r\n\r\nআপুনি এই পৰিস্থিতি কেনেকৈ সামলাব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(464, 39, 8, 'ஒரு வாடிக்கையாளருக்கு டீலர்ஷிப் தொடர்ந்து ஒரு குறிப்பிட்ட நிதியாளரின் மூலம் மட்டுமே கடன் செயல்படுத்த வலியுறுத்துகிறது என்று தோன்றுகிறது, যদিও அவர் மற்றொரு விருப்பத்திலும் ஆர்வம் காட்டியுள்ளார்.\r\n\r\nஅவருக்கு পক্ষபாதமான வழிகாட்டுதல் வழங்கப்படுகிறது என்ற சந்தேகம் வருகிறது.\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(465, 39, 9, 'ఒక కస్టమర్‌కు డీలర్‌షిప్ పదేపదే ఒకే ఫైనాన్సర్ ద్వారా లోన్ ప్రాసెస్ చేయాలని ఒత్తిడి చేస్తున్నట్లు అనిపిస్తోంది, అయితే అతను మరో ఆప్షన్‌పైనా ఆసక్తి చూపించాడు.\r\n\r\nఅతనికి పక్షపాత మార్గదర్శనం ఇస్తున్నారనే అనుమానం కలుగుతోంది.\r\n\r\nమీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(466, 39, 10, 'ഒരു ഉപഭോക്താവിന് ഡീലർഷിപ്പ് തുടർച്ചയായി ഒരു നിർദ്ദിഷ്ട ഫിനാൻസറിലൂടെ മാത്രം വായ്പ പ്രോസസ് ചെയ്യാൻ സമ്മർദ്ദം ചെലുത്തുന്നതായി തോന്നുന്നു, എന്നാൽ അദ്ദേഹം മറ്റൊരു ഓപ്ഷനിലും താൽപ്പര്യം പ്രകടിപ്പിച്ചിട്ടുണ്ട്.\r\n\r\nഅദ്ദേഹത്തിന് പക്ഷപാതപരമായ നിർദ്ദേശം നൽകുന്നുവെന്ന സംശയം ഉണ്ട്.\r\n\r\nനിങ്ങൾ ഈ സാഹചര്യം എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(467, 39, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕರಿಗೆ ಡೀಲರ್‌ಶಿಪ್ ಪದೇ ಪದೇ ಒಂದೇ ಫೈನಾನ್ಸರ್ ಮೂಲಕ ಸಾಲು ಪ್ರಕ್ರಿಯೆ ಮಾಡಲು ಒತ್ತಾಯಿಸುತ್ತಿದೆ ಎಂಬ ಭಾವನೆ ಬಂದಿದೆ, ಅವರು ಇನ್ನೊಂದು ಆಯ್ಕೆಯಲ್ಲಿಯೂ ಆಸಕ್ತಿ ತೋರಿದ್ದರೂ.\r\n\r\nಅವರಿಗೆ ಪಕ್ಷಪಾತದ ಮಾರ್ಗದರ್ಶನ ನೀಡಲಾಗುತ್ತಿದೆ ಎಂಬ ಅನುಮಾನ ಉಂಟಾಗಿದೆ.\r\n\r\nನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(468, 39, 12, 'ଜଣେ ଗ୍ରାହକଙ୍କୁ ଲାଗୁଛି ଯେ ଡିଲରଶିପ୍‌ ପୁନଃପୁନି ଗୋଟିଏ ନିର୍ଦ୍ଦିଷ୍ଟ ଫାଇନାନ୍ସର ମାଧ୍ୟମରେ ଲୋନ ପ୍ରକ୍ରିୟା କରିବାକୁ ଜୋର ଦେଉଛି, ଯେତେବେଳେ ସେ ଅନ୍ୟ ଏକ ବିକଳ୍ପରେ ମଧ୍ୟ ଆଗ୍ରହ ଦେଖାଇଛନ୍ତି।\r\n\r\nତାଙ୍କୁ ଲାଗୁଛି ଯେ ପକ୍ଷପାତମୂଳକ ପରାମର୍ଶ ଦିଆଯାଉଛି।\r\n\r\nଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(469, 40, 1, 'A customer wants to purchase a motorcycle using dealer finance through his own bank.\r\n\r\nHowever, the dealership does not support that bank as a financer, making the customer hesitant to proceed.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(470, 40, 2, 'एक ग्राहक अपनी ही बैंक के जरिए डीलर फाइनेंस से मोटरसाइकिल खरीदना चाहता है।\r\n\r\nलेकिन डीलरशिप उस बैंक के साथ फाइनेंसर के रूप में काम नहीं करती, जिससे ग्राहक आगे बढ़ने में हिचकिचा रहा है।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(471, 40, 3, 'ਇੱਕ ਗਾਹਕ ਆਪਣੀ ਹੀ ਬੈਂਕ ਰਾਹੀਂ ਡੀਲਰ ਫਾਇਨੈਂਸ ਨਾਲ ਮੋਟਰਸਾਈਕਲ ਖਰੀਦਣਾ ਚਾਹੁੰਦਾ ਹੈ।\r\n\r\nਪਰ ਡੀਲਰਸ਼ਿਪ ਉਸ ਬੈਂਕ ਨਾਲ ਫਾਇਨੈਂਸਰ ਵਜੋਂ ਕੰਮ ਨਹੀਂ ਕਰਦੀ, ਜਿਸ ਕਾਰਨ ਗਾਹਕ ਅੱਗੇ ਵੱਧਣ ਵਿੱਚ ਹਿਚਕਚਾ ਰਿਹਾ ਹੈ।\r\n\r\nਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(472, 40, 4, 'એક ગ્રાહક પોતાની જ બેંક મારફતે ડીલર ફાઇનાન્સ દ્વારા મોટરસાઇકલ ખરીદવા માંગે છે.\r\n\r\nપરંતુ ડીલરશીપ તે બેંકને ફાઇનાન્સર તરીકે સપોર્ટ કરતી નથી, તેથી ગ્રાહક આગળ વધવા અંગે સંકોચ અનુભવે છે.\r\n\r\nતમે આ પરિસ્થિતિને કેવી રીતે સંભાળશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(473, 40, 5, 'एक ग्राहक आपल्या स्वतःच्या बँकेमार्फत डीलर फायनान्सद्वारे मोटरसायकल खरेदी करू इच्छितो.\r\n\r\nपरंतु डीलरशिप त्या बँकेला फायनान्सर म्हणून सपोर्ट करत नाही, त्यामुळे ग्राहक पुढे जाण्यास संकोच करतो आहे.\r\n\r\nतुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(474, 40, 6, 'একজন গ্রাহক তার নিজের ব্যাংকের মাধ্যমে ডিলার ফাইন্যান্সে মোটরসাইকেল কিনতে চান।\r\n\r\nকিন্তু ডিলারশিপ সেই ব্যাংককে ফাইন্যান্সার হিসেবে সমর্থন করে না, ফলে গ্রাহক এগোতে দ্বিধায় পড়েছেন।\r\n\r\nআপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(475, 40, 7, 'এজন গ্ৰাহকে নিজৰ বেংকৰ জৰিয়তে ডিলাৰ ফাইনান্সত মটৰচাইকেল কিনিব বিচাৰে।\r\n\r\nকিন্তু ডিলাৰশ্বীপে সেই বেংকক ফাইনান্সাৰ হিচাপে সমৰ্থন নকৰে, যাৰ বাবে গ্ৰাহক আগবাঢ়িবলৈ সংকোচ কৰিছে।\r\n\r\nআপুনি এই পৰিস্থিতি কেনেকৈ সামলাব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(476, 40, 8, 'ஒரு வாடிக்கையாளர் தனது சொந்த வங்கியின் மூலம் டீலர் நிதியில் மோட்டார் சைக்கிள் வாங்க விரும்புகிறார்.\r\n\r\nஆனால் டீலர்ஷிப் அந்த வங்கியை நிதியாளராக ஆதரிக்கவில்லை, இதனால் வாடிக்கையாளர் முன்னேற தயங்குகிறார்.\r\n\r\nஇந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(477, 40, 9, 'ఒక కస్టమర్ తన స్వంత బ్యాంక్ ద్వారా డీలర్ ఫైనాన్స్‌లో మోటార్‌సైకిల్ కొనుగోలు చేయాలనుకుంటున్నాడు.\r\n\r\nకానీ డీలర్‌షిప్ ఆ బ్యాంక్‌ను ఫైనాన్సర్‌గా మద్దతు ఇవ్వడం లేదు, అందువల్ల కస్టమర్ ముందుకు సాగడంలో సంకోచిస్తున్నాడు.\r\n\r\nమీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(478, 40, 10, 'ഒരു ഉപഭോക്താവ് തന്റെ സ്വന്തം ബാങ്ക് വഴി ഡീലർ ഫിനാൻസ് ഉപയോഗിച്ച് മോട്ടോർസൈക്കിൾ വാങ്ങാൻ ആഗ്രഹിക്കുന്നു.\r\n\r\nഎന്നാൽ ഡീലർഷിപ്പ് ആ ബാങ്കിനെ ഫിനാൻസറായി പിന്തുണയ്ക്കുന്നില്ല, അതിനാൽ ഉപഭോക്താവ് മുന്നോട്ട് പോകാൻ മടിക്കുന്നു.\r\n\r\nനിങ്ങൾ ഈ സാഹചര്യം എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(479, 40, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕರು ತಮ್ಮ ಸ್ವಂತ ಬ್ಯಾಂಕ್ ಮೂಲಕ ಡೀಲರ್ ಫೈನಾನ್ಸ್ ಬಳಸಿ ಮೋಟಾರ್ ಸೈಕಲ್ ಖರೀದಿಸಲು ಬಯಸುತ್ತಾರೆ.\r\n\r\nಆದರೆ ಡೀಲರ್‌ಶಿಪ್ ಆ ಬ್ಯಾಂಕ್ ಅನ್ನು ಫೈನಾನ್ಸರ್ ಆಗಿ ಬೆಂಬಲಿಸುವುದಿಲ್ಲ, ಇದರಿಂದ ಗ್ರಾಹಕರು ಮುಂದುವರಿಯಲು ಹಿಂಜರಿಯುತ್ತಿದ್ದಾರೆ.\r\n\r\nನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(480, 40, 12, 'ଜଣେ ଗ୍ରାହକ ନିଜ ବ୍ୟାଙ୍କ ମାଧ୍ୟମରେ ଡିଲର ଫାଇନାନ୍ସ ଦ୍ୱାରା ମୋଟରସାଇକେଲ କିଣିବାକୁ ଚାହୁଁଛନ୍ତି।\r\n\r\nକିନ୍ତୁ ଡିଲରଶିପ୍‌ ସେହି ବ୍ୟାଙ୍କକୁ ଫାଇନାନ୍ସର ଭାବେ ସମର୍ଥନ କରୁନାହିଁ, ଯାହାରୁ ଗ୍ରାହକ ଆଗକୁ ବଢ଼ିବାରେ ହିଚକିଚାଉଛନ୍ତି।\r\n\r\nଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 05:40:40', 'Active'),
	(481, 41, 1, 'A customer initiates an exchange enquiry through the Hero Wheels of Trust DIY portal and receives an indicative value of ₹40,000 for his 5-year-old motorcycle.\r\n\r\nUpon visiting the dealership for final inspection, the evaluated value is revised to ₹30,000 due to high mileage and overall vehicle condition. The customer is upset about the difference and insists on receiving ₹40,000 as shown online.\r\n\r\nHow would you address this situation effectively?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(482, 41, 2, 'एक ग्राहक Hero Wheels of Trust DIY पोर्टल के माध्यम से एक्सचेंज पूछताछ करता है और अपनी 5 साल पुरानी मोटरसाइकिल के लिए ₹40,000 का अनुमानित मूल्य देखता है। जब वह अंतिम जांच के लिए डीलरशिप पर आता है, तो अधिक माइलेज और वाहन की स्थिति के कारण मूल्य ₹30,000 कर दिया जाता है। ग्राहक इस अंतर से नाराज़ है और ऑनलाइन दिखाए गए ₹40,000 की मांग करता है। आप इस स्थिति को प्रभावी ढंग से कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(483, 41, 3, 'ਇੱਕ ਗਾਹਕ Hero Wheels of Trust DIY ਪੋਰਟਲ ਰਾਹੀਂ ਐਕਸਚੇਂਜ ਪੁੱਛਗਿੱਛ ਕਰਦਾ ਹੈ ਅਤੇ ਆਪਣੀ 5 ਸਾਲ ਪੁਰਾਣੀ ਮੋਟਰਸਾਈਕਲ ਲਈ ₹40,000 ਦੀ ਅਨੁਮਾਨਿਤ ਕੀਮਤ ਵੇਖਦਾ ਹੈ। ਡੀਲਰਸ਼ਿਪ ‘ਤੇ ਅੰਤਿਮ ਜਾਂਚ ਦੌਰਾਨ ਵੱਧ ਮਾਈਲੇਜ ਅਤੇ ਗੱਡੀ ਦੀ ਹਾਲਤ ਕਰਕੇ ਕੀਮਤ ₹30,000 ਕਰ ਦਿੱਤੀ ਜਾਂਦੀ ਹੈ। ਗਾਹਕ ਇਸ ਫਰਕ ਤੋਂ ਨਾਰਾਜ਼ ਹੈ ਅਤੇ ਆਨਲਾਈਨ ਦਿਖਾਈ ਕੀਮਤ ₹40,000 ਦੀ ਮੰਗ ਕਰਦਾ ਹੈ। ਤੁਸੀਂ ਇਹ ਸਥਿਤੀ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(484, 41, 4, 'એક ગ્રાહક Hero Wheels of Trust DIY પોર્ટલ દ્વારા એક્સચેન્જ પૂછપરછ કરે છે અને તેની 5 વર્ષ જૂની બાઇક માટે ₹40,000 નું અંદાજિત મૂલ્ય જુએ છે. અંતિમ તપાસ દરમિયાન વધુ માઇલેજ અને વાહનની સ્થિતિને કારણે મૂલ્ય ₹30,000 થાય છે. ગ્રાહક આ તફાવતથી નારાજ છે અને ઓનલાઇન બતાવેલ ₹40,000 ની માંગ કરે છે. તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(485, 41, 5, 'एक ग्राहक Hero Wheels of Trust DIY पोर्टलवर एक्सचेंज चौकशी करतो आणि आपल्या 5 वर्ष जुन्या मोटरसायकलसाठी ₹40,000 ची अंदाजित किंमत पाहतो. अंतिम तपासणीत जास्त मायलेज आणि वाहनाच्या स्थितीमुळे किंमत ₹30,000 केली जाते. ग्राहक या फरकामुळे नाराज आहे आणि ऑनलाइन दाखवलेले ₹40,000 मागतो. तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(486, 41, 6, 'একজন গ্রাহক Hero Wheels of Trust DIY পোর্টালের মাধ্যমে এক্সচেঞ্জ অনুসন্ধান করে এবং তার ৫ বছরের পুরোনো মোটরসাইকেলের জন্য ₹40,000 এর আনুমানিক মূল্য পায়। চূড়ান্ত পরিদর্শনে বেশি মাইলেজ ও গাড়ির অবস্থার কারণে মূল্য ₹30,000 করা হয়। গ্রাহক এই পার্থক্যে অসন্তুষ্ট এবং অনলাইনে দেখানো ₹40,000 দাবি করছে। আপনি কীভাবে এই পরিস্থিতি সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(487, 41, 7, 'এজন গ্ৰাহকে Hero Wheels of Trust DIY প’ৰ্টেলৰ জৰিয়তে এক্সচেঞ্জ অনুসন্ধান কৰে আৰু ৫ বছৰ পুৰণি মটৰচাইকেলৰ বাবে ₹40,000 ৰ আনুমানিক মূল্য পায়। চূড়ান্ত পৰীক্ষাত অধিক মাইলেজ আৰু গাড়ীৰ অৱস্থাৰ বাবে মূল্য ₹30,000 কৰা হয়। গ্ৰাহক এই পাৰ্থক্যত অসন্তুষ্ট আৰু ₹40,000 দাবী কৰিছে। আপুনি এই পৰিস্থিতি কেনেকৈ সমাধান কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(488, 41, 8, 'ஒரு வாடிக்கையாளர் Hero Wheels of Trust DIY போர்டல் மூலம் எக்ஸ்சேஞ்ச் செய்து தனது 5 ஆண்டு பழைய பைக்கிற்கு ₹40,000 மதிப்பீடு பெறுகிறார். இறுதி பரிசோதனையில் அதிக மைலேஜ் மற்றும் வாகன நிலை காரணமாக மதிப்பு ₹30,000 ஆக மாற்றப்படுகிறது. வாடிக்கையாளர் இந்த வித்தியாசத்தில் அதிருப்தி அடைந்து ₹40,000 வேண்டும் எனக் கோருகிறார். நீங்கள் இந்த நிலையை எப்படி சமாளிப்பீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(489, 41, 9, 'ఒక కస్టమర్ Hero Wheels of Trust DIY పోర్టల్ ద్వారా ఎక్స్చేంజ్ చేసి తన 5 సంవత్సరాల పాత బైక్‌కు ₹40,000 అంచనా విలువ పొందాడు. తుది పరిశీలనలో ఎక్కువ మైలేజ్ మరియు వాహనం పరిస్థితి కారణంగా విలువ ₹30,000కి తగ్గింది. కస్టమర్ ఈ తేడాతో అసంతృప్తిగా ఉండి ₹40,000నే కోరుతున్నాడు. మీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(490, 41, 10, 'ഒരു ഉപഭോക്താവ് Hero Wheels of Trust DIY പോർട്ടൽ വഴി എക്സ്ചേഞ്ച് ചെയ്ത് തന്റെ 5 വർഷം പഴക്കമുള്ള ബൈക്കിന് ₹40,000 എന്ന ഏകദേശ വില ലഭിച്ചു. അന്തിമ പരിശോധനയിൽ ഉയർന്ന മൈലേജും വാഹനത്തിന്റെ അവസ്ഥയും കാരണം വില ₹30,000 ആയി കുറച്ചു. ഉപഭോക്താവ് ഈ വ്യത്യാസത്തിൽ അസന്തുഷ്ടനാണ്, ₹40,000 ആവശ്യപ്പെടുന്നു. നിങ്ങൾ ഇത് എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(491, 41, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕ Hero Wheels of Trust DIY ಪೋರ್ಟಲ್ ಮೂಲಕ ಎಕ್ಸ್ಚೇಂಜ್ ಮಾಡಿ ತನ್ನ 5 ವರ್ಷದ ಹಳೆಯ ಬೈಕ್‌ಗೆ ₹40,000 ಅಂದಾಜು ಮೌಲ್ಯ ಪಡೆದಿದ್ದಾನೆ. ಅಂತಿಮ ಪರಿಶೀಲನೆಯಲ್ಲಿ ಹೆಚ್ಚಿನ ಮೈಲೇಜ್ ಮತ್ತು ವಾಹನದ ಸ್ಥಿತಿ ಕಾರಣದಿಂದ ಮೌಲ್ಯ ₹30,000ಕ್ಕೆ ಇಳಿಸಲಾಯಿತು. ಗ್ರಾಹಕ ಈ ವ್ಯತ್ಯಾಸದಿಂದ ಅಸಮಾಧಾನಗೊಂಡು ₹40,000 ಬೇಕೆಂದು ಹೇಳುತ್ತಾನೆ. ನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(492, 41, 12, 'ଏକ ଗ୍ରାହକ Hero Wheels of Trust DIY ପୋର୍ଟାଲ ମାଧ୍ୟମରେ ଏକ୍ସଚେଞ୍ଜ କରି 5 ବର୍ଷ ପୁରୁଣା ବାଇକ ପାଇଁ ₹40,000 ର ଅନୁମାନିତ ମୂଲ୍ୟ ପାଉଛନ୍ତି। ଅନ୍ତିମ ପରୀକ୍ଷାରେ ଅଧିକ ମାଇଲେଜ୍ ଓ ଯାନର ଅବସ୍ଥା କାରଣରୁ ମୂଲ୍ୟ ₹30,000 କରାଯାଏ। ଗ୍ରାହକ ଏହି ତଫାତରୁ ଅସନ୍ତୁଷ୍ଟ ହୋଇ ₹40,000 ଦାବି କରୁଛନ୍ତି। ଆପଣ ଏହାକୁ କିପରି ସମାଧାନ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(493, 42, 1, 'A customer initiates an exchange enquiry at the dealership and receives the final tender price after inspection and bidding.\r\n\r\nHe then shows you listings on OLX where similar models are advertised at higher prices and argues that his vehicle should fetch at least the same amount.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(494, 42, 2, 'एक ग्राहक डीलरशिप पर एक्सचेंज पूछताछ करता है और निरीक्षण व बिडिंग के बाद उसे अंतिम टेंडर कीमत बताई जाती है। फिर वह OLX पर समान मॉडल के ऊंचे दाम वाले विज्ञापन दिखाकर कहता है कि उसकी गाड़ी की कीमत भी कम से कम उतनी ही होनी चाहिए। आप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(495, 42, 3, 'ਇੱਕ ਗਾਹਕ ਡੀਲਰਸ਼ਿਪ ‘ਤੇ ਐਕਸਚੇਂਜ ਪੁੱਛਗਿੱਛ ਕਰਦਾ ਹੈ ਅਤੇ ਜਾਂਚ ਤੇ ਬੋਲੀ ਪ੍ਰਕਿਰਿਆ ਤੋਂ ਬਾਅਦ ਉਸਨੂੰ ਆਖਰੀ ਟੈਂਡਰ ਕੀਮਤ ਦੱਸੀ ਜਾਂਦੀ ਹੈ। ਫਿਰ ਉਹ OLX ‘ਤੇ ਮਿਲਦੇ ਜੁਲਦੇ ਮਾਡਲਾਂ ਦੇ ਵੱਧ ਕੀਮਤ ਵਾਲੇ ਵਿਗਿਆਪਨ ਦਿਖਾ ਕੇ ਕਹਿੰਦਾ ਹੈ ਕਿ ਉਸਦੀ ਗੱਡੀ ਨੂੰ ਵੀ ਘੱਟੋ-ਘੱਟ ਉਹਨੀ ਕੀਮਤ ਮਿਲਣੀ ਚਾਹੀਦੀ ਹੈ। ਤੁਸੀਂ ਇਹ ਸਥਿਤੀ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(496, 42, 4, 'એક ગ્રાહક ડીલરશિપ પર એક્સચેન્જ પૂછપરછ કરે છે અને નિરીક્ષણ અને બિડિંગ પછી તેને અંતિમ ટેન્ડર કિંમત જણાવવામાં આવે છે. ત્યારબાદ તે OLX પર સમાન મોડલની ઊંચી કિંમતની જાહેરાતો બતાવીને કહે છે કે તેની ગાડી પણ ઓછામાં ઓછી એટલી કિંમત મેળવવી જોઈએ. તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(497, 42, 5, 'एक ग्राहक डीलरशिपमध्ये एक्सचेंज चौकशी करतो आणि तपासणी व बोली प्रक्रियेनंतर त्याला अंतिम टेंडर किंमत सांगितली जाते. त्यानंतर तो OLX वर समान मॉडेलच्या जास्त किमतीच्या जाहिराती दाखवून म्हणतो की त्याच्या गाडीला किमान तितकीच किंमत मिळायला हवी. तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(498, 42, 6, 'একজন গ্রাহক ডিলারশিপে এক্সচেঞ্জ অনুসন্ধান করেন এবং পরিদর্শন ও বিডিংয়ের পর চূড়ান্ত টেন্ডার মূল্য পান। এরপর তিনি OLX-এ একই ধরনের মডেলের বেশি দামের বিজ্ঞাপন দেখিয়ে বলেন যে তার গাড়িরও অন্তত সেই মূল্য পাওয়া উচিত। আপনি কীভাবে এই পরিস্থিতি সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(499, 42, 7, 'এজন গ্ৰাহকে ডীলাৰশিপত এক্সচেঞ্জ অনুসন্ধান কৰে আৰু পৰীক্ষা আৰু বিডিংৰ পিছত চূড়ান্ত টেণ্ডাৰ মূল্য লাভ কৰে। তাৰ পিছত তেওঁ OLXত একে ধৰণৰ মডেলৰ অধিক মূল্যৰ বিজ্ঞাপন দেখুৱাই কয় যে তেওঁৰ গাড়ীৰো অন্তত সেই মূল্য পোৱা উচিত। আপুনি এই পৰিস্থিতি কেনেকৈ সমাধান কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(500, 42, 8, 'ஒரு வாடிக்கையாளர் டீலர்ஷிப்பில் எக்ஸ்சேஞ்ச் விசாரணை செய்து, ஆய்வு மற்றும் பிடிங் பிறகு இறுதி டெண்டர் விலையை பெறுகிறார். பின்னர் அவர் OLX-ல் அதே மாதிரி மாடல்களுக்கு அதிக விலை காட்டும் விளம்பரங்களை காட்டி, தனது வாகனமும் குறைந்தது அதே விலை பெற வேண்டும் என வாதிடுகிறார். இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(501, 42, 9, 'ఒక కస్టమర్ డీలర్‌షిప్‌లో ఎక్స్చేంజ్ విచారణ చేసి, పరిశీలన మరియు బిడ్డింగ్ తర్వాత తుది టెండర్ ధర పొందాడు. తరువాత అతను OLXలో ఇలాంటి మోడళ్లకు ఎక్కువ ధరల ప్రకటనలు చూపిస్తూ, తన వాహనం కూడా కనీసం అంతే ధర రావాలని అంటున్నాడు. మీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(502, 42, 10, 'ഒരു ഉപഭോക്താവ് ഡീലർഷിപ്പിൽ എക്സ്ചേഞ്ച് അന്വേഷണം നടത്തി, പരിശോധനയും ബിഡിംഗും കഴിഞ്ഞ് അന്തിമ ടെൻഡർ വില ലഭിക്കുന്നു. തുടർന്ന് OLX-ൽ സമാന മോഡലുകൾക്ക് കൂടുതലായ വില കാണിക്കുന്ന പരസ്യങ്ങൾ കാണിച്ച്, തന്റെ വാഹനത്തിനും കുറഞ്ഞത് അതേ വില ലഭിക്കണം എന്ന് പറയുന്നു. നിങ്ങൾ ഈ സാഹചര്യം എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(503, 42, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕ ಡೀಲರ್‌ಶಿಪ್‌ನಲ್ಲಿ ಎಕ್ಸ್ಚೇಂಜ್ ವಿಚಾರಣೆ ಮಾಡಿ, ಪರಿಶೀಲನೆ ಮತ್ತು ಬಿದ್ದಿಂಗ್ ನಂತರ ಅಂತಿಮ ಟೆಂಡರ್ ಬೆಲೆ ಪಡೆಯುತ್ತಾನೆ. ನಂತರ ಅವನು OLXನಲ್ಲಿ ಸಮಾನ ಮಾದರಿಗಳಿಗೆ ಹೆಚ್ಚಿನ ಬೆಲೆಯ ಜಾಹೀರಾತುಗಳನ್ನು ತೋರಿಸಿ, ತನ್ನ ವಾಹನಕ್ಕೂ ಕನಿಷ್ಠ ಅದೇ ಬೆಲೆ ಸಿಗಬೇಕು ಎಂದು ವಾದಿಸುತ್ತಾನೆ. ನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(504, 42, 12, 'ଏକ ଗ୍ରାହକ ଡିଲରଶିପରେ ଏକ୍ସଚେଞ୍ଜ ପଚରାଉଚରି କରି, ପରୀକ୍ଷା ଓ ବିଡିଂ ପରେ ଅନ୍ତିମ ଟେଣ୍ଡର ମୂଲ୍ୟ ପାଇଥାନ୍ତି। ପରେ ସେ OLX ରେ ସମାନ ମଡେଲ ପାଇଁ ଅଧିକ ଦାମର ବିଜ୍ଞାପନ ଦେଖାଇ କହୁଛନ୍ତି ଯେ ତାଙ୍କ ଯାନକୁ ମଧ୍ୟ କମରେ କମ ସେହି ମୂଲ୍ୟ ମିଳିବା ଉଚିତ। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(505, 43, 1, 'A customer initiates an exchange enquiry at the dealership and receives the final tender price after inspection and bidding.\r\n\r\nHe then shows you listings on OLX where similar models are advertised at higher prices and argues that his vehicle should fetch at least the same amount.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(506, 43, 2, 'एक ग्राहक डीलरशिप पर एक्सचेंज पूछताछ करता है और निरीक्षण व बिडिंग के बाद उसे अंतिम टेंडर कीमत बताई जाती है। फिर वह OLX पर समान मॉडल के ऊंचे दाम वाले विज्ञापन दिखाकर कहता है कि उसकी गाड़ी की कीमत भी कम से कम उतनी ही होनी चाहिए। आप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(507, 43, 3, 'ਇੱਕ ਗਾਹਕ ਡੀਲਰਸ਼ਿਪ ‘ਤੇ ਐਕਸਚੇਂਜ ਪੁੱਛਗਿੱਛ ਕਰਦਾ ਹੈ ਅਤੇ ਜਾਂਚ ਤੇ ਬੋਲੀ ਤੋਂ ਬਾਅਦ ਉਸਨੂੰ ਆਖਰੀ ਟੈਂਡਰ ਕੀਮਤ ਦੱਸੀ ਜਾਂਦੀ ਹੈ। ਫਿਰ ਉਹ OLX ‘ਤੇ ਮਿਲਦੇ ਜੁਲਦੇ ਮਾਡਲਾਂ ਦੇ ਵੱਧ ਕੀਮਤ ਵਾਲੇ ਵਿਗਿਆਪਨ ਦਿਖਾ ਕੇ ਕਹਿੰਦਾ ਹੈ ਕਿ ਉਸਦੀ ਗੱਡੀ ਨੂੰ ਵੀ ਘੱਟੋ-ਘੱਟ ਉਹਨੀ ਕੀਮਤ ਮਿਲਣੀ ਚਾਹੀਦੀ ਹੈ। ਤੁਸੀਂ ਇਹ ਸਥਿਤੀ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(508, 43, 4, 'એક ગ્રાહક ડીલરશિપ પર એક્સચેન્જ પૂછપરછ કરે છે અને નિરીક્ષણ અને બિડિંગ પછી તેને અંતિમ ટેન્ડર કિંમત જણાવવામાં આવે છે। ત્યારબાદ તે OLX પર સમાન મોડલની ઊંચી કિંમતની જાહેરાતો બતાવીને કહે છે કે તેની ગાડી પણ ઓછામાં ઓછી એટલી કિંમત મેળવવી જોઈએ। તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(509, 43, 5, 'एक ग्राहक डीलरशिपमध्ये एक्सचेंज चौकशी करतो आणि तपासणी व बोली प्रक्रियेनंतर त्याला अंतिम टेंडर किंमत सांगितली जाते। त्यानंतर तो OLX वर समान मॉडेलच्या जास्त किमतीच्या जाहिराती दाखवून म्हणतो की त्याच्या गाडीला किमान तितकीच किंमत मिळायला हवी। तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(510, 43, 6, 'একজন গ্রাহক ডিলারশিপে এক্সচেঞ্জ অনুসন্ধান করেন এবং পরিদর্শন ও বিডিংয়ের পর চূড়ান্ত টেন্ডার মূল্য পান। এরপর তিনি OLX-এ একই ধরনের মডেলের বেশি দামের বিজ্ঞাপন দেখিয়ে বলেন যে তার গাড়িরও অন্তত সেই মূল্য পাওয়া উচিত। আপনি কীভাবে এই পরিস্থিতি সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(511, 43, 7, 'এজন গ্ৰাহকে ডীলাৰশিপত এক্সচেঞ্জ অনুসন্ধান কৰে আৰু পৰীক্ষা আৰু বিডিংৰ পিছত চূড়ান্ত টেণ্ডাৰ মূল্য লাভ কৰে। তাৰ পিছত তেওঁ OLXত একে ধৰণৰ মডেলৰ অধিক মূল্যৰ বিজ্ঞাপন দেখুৱাই কয় যে তেওঁৰ গাড়ীৰো অন্তত সেই মূল্য পোৱা উচিত। আপুনি এই পৰিস্থিতি কেনেকৈ সমাধান কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(512, 43, 8, 'ஒரு வாடிக்கையாளர் டீலர்ஷிப்பில் எக்ஸ்சேஞ்ச் விசாரணை செய்து, ஆய்வு மற்றும் பிடிங் பிறகு இறுதி டெண்டர் விலையை பெறுகிறார். பின்னர் அவர் OLX-ல் அதே மாதிரி மாடல்களுக்கு அதிக விலை காட்டும் விளம்பரங்களை காட்டி, தனது வாகனமும் குறைந்தது அதே விலை பெற வேண்டும் என வாதிடுகிறார். இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(513, 43, 9, 'ఒక కస్టమర్ డీలర్‌షిప్‌లో ఎక్స్చేంజ్ విచారణ చేసి, పరిశీలన మరియు బిడ్డింగ్ తర్వాత తుది టెండర్ ధర పొందాడు. తరువాత అతను OLXలో ఇలాంటి మోడళ్లకు ఎక్కువ ధరల ప్రకటనలు చూపిస్తూ, తన వాహనం కూడా కనీసం అంతే ధర రావాలని అంటున్నాడు. మీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(514, 43, 10, 'ഒരു ഉപഭോക്താവ് ഡീലർഷിപ്പിൽ എക്സ്ചേഞ്ച് അന്വേഷണം നടത്തി, പരിശോധനയും ബിഡിംഗും കഴിഞ്ഞ് അന്തിമ ടെൻഡർ വില ലഭിക്കുന്നു. തുടർന്ന് OLX-ൽ സമാന മോഡലുകൾക്ക് കൂടുതലായ വില കാണിക്കുന്ന പരസ്യങ്ങൾ കാണിച്ച്, തന്റെ വാഹനത്തിനും കുറഞ്ഞത് അതേ വില ലഭിക്കണം എന്ന് പറയുന്നു. നിങ്ങൾ ഈ സാഹചര്യം എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(515, 43, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕ ಡೀಲರ್‌ಶಿಪ್‌ನಲ್ಲಿ ಎಕ್ಸ್ಚೇಂಜ್ ವಿಚಾರಣೆ ಮಾಡಿ, ಪರಿಶೀಲನೆ ಮತ್ತು ಬಿದ್ದಿಂಗ್ ನಂತರ ಅಂತಿಮ ಟೆಂಡರ್ ಬೆಲೆ ಪಡೆಯುತ್ತಾನೆ. ನಂತರ ಅವನು OLXನಲ್ಲಿ ಸಮಾನ ಮಾದರಿಗಳಿಗೆ ಹೆಚ್ಚಿನ ಬೆಲೆಯ ಜಾಹೀರಾತುಗಳನ್ನು ತೋರಿಸಿ, ತನ್ನ ವಾಹನಕ್ಕೂ ಕನಿಷ್ಠ ಅದೇ ಬೆಲೆ ಸಿಗಬೇಕು ಎಂದು ವಾದಿಸುತ್ತಾನೆ. ನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(516, 43, 12, 'ଏକ ଗ୍ରାହକ ଡିଲରଶିପରେ ଏକ୍ସଚେଞ୍ଜ ପଚରାଉଚରି କରି, ପରୀକ୍ଷା ଓ ବିଡିଂ ପରେ ଅନ୍ତିମ ଟେଣ୍ଡର ମୂଲ୍ୟ ପାଇଥାନ୍ତି। ପରେ ସେ OLX ରେ ସମାନ ମଡେଲ ପାଇଁ ଅଧିକ ଦାମର ବିଜ୍ଞାପନ ଦେଖାଇ କହୁଛନ୍ତି ଯେ ତାଙ୍କ ଯାନକୁ ମଧ୍ୟ କମରେ କମ ସେହି ମୂଲ୍ୟ ମିଳିବା ଉଚିତ। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(517, 44, 1, 'A customer owns a 15-year-old motorcycle and visits the dealership for general service.\r\n\r\nDuring discussion, you suggest the option of scrapping the vehicle and upgrading under applicable benefits. However, the customer states that his bike is still running fine and refuses to consider scrappage.\r\n\r\nHow would you handle this objection?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(518, 44, 2, 'एक ग्राहक अपनी 15 साल पुरानी मोटरसाइकिल की सामान्य सर्विस के लिए डीलरशिप पर आता है। बातचीत के दौरान आप स्क्रैप करके लाभ के साथ नई गाड़ी लेने का सुझाव देते हैं, लेकिन ग्राहक कहता है कि उसकी बाइक अभी ठीक चल रही है और वह स्क्रैप कराने के लिए तैयार नहीं है। आप इस आपत्ति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(519, 44, 3, 'ਇੱਕ ਗਾਹਕ ਆਪਣੀ 15 ਸਾਲ ਪੁਰਾਣੀ ਮੋਟਰਸਾਈਕਲ ਦੀ ਸਰਵਿਸ ਲਈ ਡੀਲਰਸ਼ਿਪ ‘ਤੇ ਆਉਂਦਾ ਹੈ। ਗੱਲਬਾਤ ਦੌਰਾਨ ਤੁਸੀਂ ਸਕ੍ਰੈਪ ਕਰਕੇ ਫਾਇਦੇ ਨਾਲ ਨਵੀਂ ਗੱਡੀ ਲੈਣ ਦੀ ਸਲਾਹ ਦਿੰਦੇ ਹੋ, ਪਰ ਗਾਹਕ ਕਹਿੰਦਾ ਹੈ ਕਿ ਉਸਦੀ ਬਾਈਕ ਅਜੇ ਵੀ ਠੀਕ ਚੱਲ ਰਹੀ ਹੈ ਅਤੇ ਉਹ ਸਕ੍ਰੈਪ ਨਹੀਂ ਕਰਨਾ ਚਾਹੁੰਦਾ। ਤੁਸੀਂ ਇਸ ਐਤਰਾਜ਼ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(520, 44, 4, 'એક ગ્રાહક તેની 15 વર્ષ જૂની મોટરસાઇકલની સર્વિસ માટે ડીલરશિપ પર આવે છે। ચર્ચા દરમિયાન તમે સ્ક્રેપ કરીને લાભ સાથે નવી ગાડી લેવા સૂચન કરો છો, પરંતુ ગ્રાહક કહે છે કે તેની બાઇક હજુ સારી રીતે ચાલે છે અને તે સ્ક્રેપ કરવા તૈયાર નથી। તમે આ આક્ષેપને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(521, 44, 5, 'एक ग्राहक आपल्या 15 वर्ष जुन्या मोटरसायकलची सर्विस करण्यासाठी डीलरशिपमध्ये येतो। चर्चेदरम्यान तुम्ही स्क्रॅप करून फायदे घेऊन नवीन गाडी घेण्याचा सल्ला देता, पण ग्राहक सांगतो की त्याची बाईक अजून व्यवस्थित चालू आहे आणि तो स्क्रॅप करण्यास तयार नाही। तुम्ही ही हरकत कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(522, 44, 6, 'একজন গ্রাহক তার ১৫ বছরের পুরোনো মোটরসাইকেলের সাধারণ সার্ভিসের জন্য ডিলারশিপে আসেন। আলোচনার সময় আপনি স্ক্র্যাপ করে সুবিধা নিয়ে নতুন গাড়ি নেওয়ার পরামর্শ দেন, কিন্তু গ্রাহক বলেন তার বাইক এখনও ভালো চলছে এবং তিনি স্ক্র্যাপ করতে চান না। আপনি কীভাবে এই আপত্তি সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(523, 44, 7, 'এজন গ্ৰাহকে নিজৰ ১৫ বছৰ পুৰণি মটৰচাইকেল সাধাৰণ চাৰ্ভিচৰ বাবে ডীলাৰশিপলৈ আহে। আলোচনাৰ সময়ত আপুনি স্ক্ৰেপ কৰি সুবিধা লৈ নতুন গাড়ী লোৱাৰ পৰামৰ্শ দিয়ে, কিন্তু গ্ৰাহকে কয় যে তেওঁৰ বাইক এতিয়াও ভালদৰে চলি আছে আৰু তেওঁ স্ক্ৰেপ কৰিব নুখোজে। আপুনি এই আপত্তি কেনেকৈ সমাধান কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(524, 44, 8, 'ஒரு வாடிக்கையாளர் தனது 15 ஆண்டு பழைய மோட்டார்சைக்கிளின் சர்வீஸிற்காக டீலர்ஷிப்பிற்கு வருகிறார்। உரையாடலில், ஸ்கிராப் செய்து சலுகைகளுடன் புதிய வாகனம் வாங்கலாம் என்று நீங்கள் பரிந்துரைக்கிறீர்கள். ஆனால் வாடிக்கையாளர் தனது பைக் இன்னும் நன்றாக இயங்குகிறது என்று கூறி ஸ்கிராப் செய்ய மறுக்கிறார். இந்த எதிர்ப்பை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(525, 44, 9, 'ఒక కస్టమర్ తన 15 సంవత్సరాల పాత బైక్ సాధారణ సర్వీస్ కోసం డీలర్‌షిప్‌కు వస్తాడు. చర్చలో మీరు స్క్రాప్ చేసి ప్రయోజనాలతో కొత్త వాహనం తీసుకోవాలని సూచిస్తారు. కానీ కస్టమర్ తన బైక్ ఇంకా బాగానే నడుస్తోందని చెప్పి స్క్రాప్ చేయడానికి నిరాకరిస్తాడు. ఈ అభ్యంతరాన్ని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(526, 44, 10, 'ഒരു ഉപഭോക്താവ് തന്റെ 15 വർഷം പഴക്കമുള്ള ബൈക്കിന്റെ സർവീസിനായി ഡീലർഷിപ്പിൽ എത്തുന്നു. സംസാരത്തിനിടെ സ്ക്രാപ്പ് ചെയ്ത് ആനുകൂല്യങ്ങളോടെ പുതിയ വാഹനം എടുക്കാമെന്ന് നിങ്ങൾ നിർദേശിക്കുന്നു. പക്ഷേ ഉപഭോക്താവ് തന്റെ ബൈക്ക് ഇപ്പോഴും നന്നായി ഓടുന്നു എന്ന് പറഞ്ഞ് സ്ക്രാപ്പ് ചെയ്യാൻ തയ്യാറല്ലെന്ന് പറയുന്നു. ഈ എതിർപ്പിനെ നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(527, 44, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕ ತನ್ನ 15 ವರ್ಷದ ಹಳೆಯ ಬೈಕ್‌ನ ಸಾಮಾನ್ಯ ಸರ್ವೀಸ್‌ಗಾಗಿ ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಬರುತ್ತಾನೆ. ಚರ್ಚೆಯ ಸಮಯದಲ್ಲಿ ನೀವು ಸ್ಕ್ರ್ಯಾಪ್ ಮಾಡಿ ಲಾಭಗಳೊಂದಿಗೆ ಹೊಸ ವಾಹನಕ್ಕೆ ಅಪ್‌ಗ್ರೇಡ್ ಮಾಡಲು ಸಲಹೆ ನೀಡುತ್ತೀರಿ. ಆದರೆ ಗ್ರಾಹಕ ತನ್ನ ಬೈಕ್ ಇನ್ನೂ ಚೆನ್ನಾಗಿ ಓಡುತ್ತಿದೆ ಎಂದು ಹೇಳಿ ಸ್ಕ್ರ್ಯಾಪ್ ಮಾಡಲು ನಿರಾಕರಿಸುತ್ತಾನೆ. ಈ ಆಕ್ಷೇಪವನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(528, 44, 12, 'ଏକ ଗ୍ରାହକ ତାଙ୍କ 15 ବର୍ଷ ପୁରୁଣା ବାଇକର ସାଧାରଣ ସର୍ଭିସ ପାଇଁ ଡିଲରଶିପକୁ ଆସନ୍ତି। ଆଲୋଚନା ସମୟରେ ଆପଣ ସ୍କ୍ରାପ୍ କରି ଲାଭ ସହ ନୂଆ ଯାନ ନେବାକୁ ପରାମର୍ଶ ଦେଉଛନ୍ତି। କିନ୍ତୁ ଗ୍ରାହକ କହୁଛନ୍ତି ଯେ ତାଙ୍କ ବାଇକ ଏଯାବତ୍ ଭଲ ଚାଲୁଛି ଏବଂ ସେ ସ୍କ୍ରାପ୍ କରିବାକୁ ଚାହୁଁନାହାନ୍ତି। ଆପଣ ଏହି ଆପତ୍ତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(529, 45, 1, 'During the CertX inspection, minor scratches and tyre wear are recorded in the system.\r\n\r\nThe customer disagrees with the observations and feels the condition has been marked more negatively than actual, which may reduce the bidding price.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(530, 45, 2, 'CertX निरीक्षण के दौरान सिस्टम में हल्की खरोंच और टायर घिसाव दर्ज किया जाता है। ग्राहक इन टिप्पणियों से असहमत है और उसे लगता है कि गाड़ी की स्थिति को वास्तविक से ज्यादा नकारात्मक दिखाया गया है, जिससे बोली की कीमत कम हो सकती है। आप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(531, 45, 3, 'CertX ਇੰਸਪੈਕਸ਼ਨ ਦੌਰਾਨ ਸਿਸਟਮ ਵਿੱਚ ਛੋਟੀਆਂ ਖਰੋਚਾਂ ਅਤੇ ਟਾਇਰ ਘਿਸਾਈ ਦਰਜ ਕੀਤੀ ਜਾਂਦੀ ਹੈ। ਗਾਹਕ ਇਨ੍ਹਾਂ ਨਿਰੀਖਣਾਂ ਨਾਲ ਅਸਹਿਮਤ ਹੈ ਅਤੇ ਉਸਨੂੰ ਲੱਗਦਾ ਹੈ ਕਿ ਗੱਡੀ ਦੀ ਹਾਲਤ ਅਸਲ ਤੋਂ ਵੱਧ ਖਰਾਬ ਦਰਸਾਈ ਗਈ ਹੈ, ਜਿਸ ਨਾਲ ਬੋਲੀ ਦੀ ਕੀਮਤ ਘੱਟ ਹੋ ਸਕਦੀ ਹੈ। ਤੁਸੀਂ ਇਹ ਸਥਿਤੀ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(532, 45, 4, 'CertX નિરીક્ષણ દરમિયાન સિસ્ટમમાં નાના સ્ક્રેચ અને ટાયર ઘસારો નોંધવામાં આવે છે। ગ્રાહક આ નોંધ સાથે અસહમત છે અને તેને લાગે છે કે વાહનની સ્થિતિ વાસ્તવિક કરતાં વધુ નકારાત્મક દર્શાવવામાં આવી છે, જેના કારણે બિડિંગ કિંમત ઘટી શકે છે। તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(533, 45, 5, 'CertX तपासणीदरम्यान सिस्टममध्ये किरकोळ ओरखडे आणि टायर घासलेले असल्याची नोंद केली जाते। ग्राहक या निरीक्षणांशी असहमत आहे आणि त्याला वाटते की वाहनाची स्थिती प्रत्यक्षापेक्षा अधिक खराब दाखवली आहे, ज्यामुळे बोली किंमत कमी होऊ शकते। तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(534, 45, 6, 'CertX পরিদর্শনের সময় সিস্টেমে সামান্য স্ক্র্যাচ এবং টায়ার ক্ষয় নথিভুক্ত করা হয়। গ্রাহক এই পর্যবেক্ষণের সাথে একমত নন এবং মনে করেন গাড়ির অবস্থা বাস্তবের তুলনায় বেশি খারাপ দেখানো হয়েছে, যা বিডিং মূল্য কমাতে পারে। আপনি কীভাবে এই পরিস্থিতি সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(535, 45, 7, 'CertX পৰীক্ষাৰ সময়ত সিস্টেমত সৰু খোঁচ আৰু টায়াৰ ক্ষয় লিপিবদ্ধ কৰা হয়। গ্ৰাহক এই পর্যবেক্ষণসমূহৰ সৈতে অসম্মত আৰু ভাবিছে যে গাড়ীৰ অৱস্থা বাস্তৱতকৈ বেছি খারাপ দেখুওৱা হৈছে, যাৰ ফলত বিডিং মূল্য কমি যাব পাৰে। আপুনি এই পৰিস্থিতি কেনেকৈ সমাধান কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(536, 45, 8, 'CertX ஆய்வின் போது சிஸ்டத்தில் சிறிய சிராய்ப்புகள் மற்றும் டயர் kulai பதிவு செய்யப்படுகிறது. வாடிக்கையாளர் இந்த குறிப்புகளுடன் ஒப்புக்கொள்ளவில்லை மற்றும் வாகனத்தின் நிலை உண்மையை விட மோசமாக பதிவு செய்யப்பட்டுள்ளது என்று நினைக்கிறார், இது பிடிங் விலையை குறைக்கலாம். இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(537, 45, 9, 'CertX తనిఖీ సమయంలో సిస్టమ్‌లో చిన్న గీతలు మరియు టైర్ kulupu నమోదు చేయబడుతుంది. కస్టమర్ ఈ గమనికలతో ఏకీభవించడు మరియు వాహనం పరిస్థితిని అసలు కంటే ఎక్కువగా చెడుగా నమోదు చేశారని భావిస్తున్నాడు, దీని వల్ల బిడ్డింగ్ ధర తగ్గవచ్చు. మీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(538, 45, 10, 'CertX പരിശോധന സമയത്ത് സിസ്റ്റത്തിൽ ചെറിയ സ്ക്രാച്ചുകളും ടയർ kulaiയും രേഖപ്പെടുത്തുന്നു. ഉപഭോക്താവ് ഈ നിരീക്ഷണങ്ങളോട് യോജിക്കുന്നില്ല, വാഹനത്തിന്റെ നില യാഥാർത്ഥ്യത്തേക്കാൾ കൂടുതൽ മോശമായി രേഖപ്പെടുത്തിയതായി കരുതുന്നു, ഇതു ബിഡിംഗ് വില കുറയ്ക്കാം. നിങ്ങൾ ഈ സാഹചര്യം എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(539, 45, 11, 'CertX ಪರಿಶೀಲನೆಯ ವೇಳೆ ಸಿಸ್ಟಂನಲ್ಲಿ ಸಣ್ಣ ಸ್ಕ್ರಾಚ್‌ಗಳು ಮತ್ತು ಟೈರ್ kulita ದಾಖಲಿಸಲಾಗುತ್ತದೆ. ಗ್ರಾಹಕ ಈ ಗಮನಿಕೆಗಳಿಗೆ ಒಪ್ಪುವುದಿಲ್ಲ ಮತ್ತು ವಾಹನದ ಸ್ಥಿತಿ ನಿಜಕ್ಕಿಂತ ಹೆಚ್ಚು ಕೆಟ್ಟದಾಗಿ ಗುರುತಿಸಲಾಗಿದೆ ಎಂದು ಭಾವಿಸುತ್ತಾನೆ, ಇದರಿಂದ ಬಿಡ್ಡಿಂಗ್ ಬೆಲೆ ಕಡಿಮೆಯಾಗಬಹುದು. ನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(540, 45, 12, 'CertX ପରୀକ୍ଷା ସମୟରେ ସିଷ୍ଟମରେ ସାନା ଖରୋଚ୍ଚ ଓ ଟାୟାର ଘସା ଦର୍ଜ କରାଯାଏ। ଗ୍ରାହକ ଏହି ଅବଲୋକନ ସହ ସହମତ ନୁହେଁ ଏବଂ ଭାବୁଛନ୍ତି ଯେ ଯାନର ଅବସ୍ଥା ବାସ୍ତବ ତୁଳନାରେ ଅଧିକ ଖରାପ ଦେଖାଯାଇଛି, ଯାହା ବିଡିଂ ମୂଲ୍ୟ କମାଇ ପାରେ। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(541, 46, 1, 'After accepting the highest bid and completing the exchange documentation, the customer requests to retain the vehicle for another week until his new vehicle delivery is scheduled.\r\n\r\nHe insists that since the deal is finalized, temporary possession should not be an issue.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(542, 46, 2, 'सबसे ऊंची बोली स्वीकार करने और एक्सचेंज की प्रक्रिया पूरी करने के बाद ग्राहक अनुरोध करता है कि नई गाड़ी की डिलीवरी तक वह अपनी पुरानी गाड़ी एक हफ्ते और अपने पास रखना चाहता है। वह कहता है कि जब सौदा फाइनल हो चुका है, तो अस्थायी रूप से गाड़ी रखना कोई समस्या नहीं होनी चाहिए। आप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(543, 46, 3, 'ਸਭ ਤੋਂ ਉੱਚੀ ਬੋਲੀ ਮਨਜ਼ੂਰ ਕਰਨ ਅਤੇ ਐਕਸਚੇਂਜ ਦੀ ਕਾਰਵਾਈ ਪੂਰੀ ਹੋਣ ਤੋਂ ਬਾਅਦ ਗਾਹਕ ਬੇਨਤੀ ਕਰਦਾ ਹੈ ਕਿ ਨਵੀਂ ਗੱਡੀ ਦੀ ਡਿਲੀਵਰੀ ਤੱਕ ਉਹ ਆਪਣੀ ਪੁਰਾਣੀ ਗੱਡੀ ਇੱਕ ਹਫ਼ਤਾ ਹੋਰ ਆਪਣੇ ਕੋਲ ਰੱਖਣਾ ਚਾਹੁੰਦਾ ਹੈ। ਉਹ ਜ਼ੋਰ ਦੇ ਕੇ ਕਹਿੰਦਾ ਹੈ ਕਿ ਜਦੋਂ ਸੌਦਾ ਫਾਈਨਲ ਹੋ ਗਿਆ ਹੈ, ਤਾਂ ਅਸਥਾਈ ਕਬਜ਼ਾ ਕੋਈ ਸਮੱਸਿਆ ਨਹੀਂ ਹੋਣਾ ਚਾਹੀਦਾ। ਤੁਸੀਂ ਇਹ ਸਥਿਤੀ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(544, 46, 4, 'સૌથી ઊંચી બોલી સ્વીકારી અને એક્સચેન્જ દસ્તાવેજ પ્રક્રિયા પૂર્ણ થયા બાદ ગ્રાહક વિનંતી કરે છે કે નવી ગાડીની ડિલિવરી સુધી તે તેની જૂની ગાડી એક અઠવાડિયા સુધી પોતાના પાસે રાખવા માંગે છે। તે કહે છે કે સોદો પૂર્ણ થઈ ગયો હોવાથી તાત્કાલિક કબજો કોઈ સમસ્યા ન હોવો જોઈએ। તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(545, 46, 5, 'सर्वोच्च बोली स्वीकारून एक्सचेंजची कागदपत्रे पूर्ण केल्यानंतर ग्राहक विनंती करतो की नवीन गाडीची डिलिव्हरी होईपर्यंत त्याला जुनी गाडी एक आठवडा स्वतःकडे ठेवायची आहे। तो म्हणतो की व्यवहार पूर्ण झाला असल्याने तात्पुरता ताबा ठेवण्यात काही अडचण नसावी। तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(546, 46, 6, 'সর্বোচ্চ বিড গ্রহণ করে এক্সচেঞ্জের কাগজপত্র সম্পন্ন করার পর গ্রাহক অনুরোধ করেন যে নতুন গাড়ির ডেলিভারি পর্যন্ত তিনি তার পুরোনো গাড়িটি আরও এক সপ্তাহ নিজের কাছে রাখতে চান। তিনি জোর দিয়ে বলেন যে চুক্তি চূড়ান্ত হয়ে গেছে, তাই অস্থায়ীভাবে গাড়ি রাখা কোনো সমস্যা হওয়া উচিত নয়। আপনি কীভাবে এই পরিস্থিতি সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(547, 46, 7, 'সৰ্বোচ্চ বিড গ্ৰহণ কৰি এক্সচেঞ্জৰ নথিপত্ৰ সম্পূৰ্ণ কৰাৰ পিছত গ্ৰাহকে অনুৰোধ কৰে যে নতুন গাড়ীৰ ডেলিভাৰী হওালৈকে তেওঁ নিজৰ পুৰণি গাড়ীটো আৰু এটা সপ্তাহ নিজৰ ওচৰত ৰাখিব বিচাৰে। তেওঁ কয় যে চুক্তি চূড়ান্ত হৈছে, সেয়েহে সাময়িক দখল কোনো সমস্যা নহ’ব লাগে। আপুনি এই পৰিস্থিতি কেনেকৈ সমাধান কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(548, 46, 8, 'அதிகபட்ச பிட் ஏற்று எக்ஸ்சேஞ்ச் ஆவணங்கள் முடிந்த பிறகு, புதிய வாகன டெலிவரி வரை தனது பழைய வாகனத்தை இன்னும் ஒரு வாரம் வைத்திருக்க அனுமதி கேட்கிறார். ஒப்பந்தம் முடிந்துவிட்டதால் தற்காலிகமாக வைத்திருப்பதில் பிரச்சினை இருக்கக்கூடாது என்று வலியுறுத்துகிறார். இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(549, 46, 9, 'అత్యధిక బిడ్‌ను అంగీకరించి ఎక్స్చేంజ్ పత్రాలు పూర్తి చేసిన తర్వాత, కొత్త వాహనం డెలివరీ వరకు తన పాత వాహనాన్ని మరో వారం తన వద్ద ఉంచుకోవాలని కస్టమర్ కోరుతున్నాడు. ఒప్పందం పూర్తయిందని, తాత్కాలికంగా వాహనం తన వద్ద ఉండటం సమస్య కాదని అంటున్నాడు. మీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(550, 46, 10, 'ഏറ്റവും ഉയർന്ന ബിഡ് അംഗീകരിച്ച് എക്സ്ചേഞ്ച് രേഖകൾ പൂർത്തിയാക്കിയതിന് ശേഷം, പുതിയ വാഹനത്തിന്റെ ഡെലിവറി വരെയും തന്റെ പഴയ വാഹനം ഒരു ആഴ്ച കൂടി സ്വന്തമായി വയ്ക്കാൻ ഉപഭോക്താവ് അഭ്യർത്ഥിക്കുന്നു. ഇടപാട് പൂർത്തിയായതിനാൽ താൽക്കാലിക കൈവശം വയ്ക്കുന്നതിൽ പ്രശ്നമില്ലെന്നാണ് അദ്ദേഹം പറയുന്നത്. നിങ്ങൾ ഈ സാഹചര്യം എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(551, 46, 11, 'ಅತ್ಯಧಿಕ ಬಿಡ್ ಅಂಗೀಕರಿಸಿ ಎಕ್ಸ್ಚೇಂಜ್ ದಾಖಲೆಗಳು ಪೂರ್ಣಗೊಂಡ ನಂತರ, ಹೊಸ ವಾಹನದ ಡೆಲಿವರಿ ಆಗುವವರೆಗೆ ತನ್ನ ಹಳೆಯ ವಾಹನವನ್ನು ಇನ್ನೂ ಒಂದು ವಾರ ತನ್ನ ಬಳಿ ಇಟ್ಟುಕೊಳ್ಳಲು ಗ್ರಾಹಕ ಕೇಳುತ್ತಾನೆ. ವ್ಯವಹಾರ ಅಂತಿಮಗೊಂಡಿರುವುದರಿಂದ ತಾತ್ಕಾಲಿಕವಾಗಿ ತನ್ನ ಬಳಿ ಇರುವುದು ಸಮಸ್ಯೆಯಾಗಬಾರದು ಎಂದು ಅವನು ಹೇಳುತ್ತಾನೆ. ನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(552, 46, 12, 'ସର୍ବାଧିକ ବିଡ୍ ଗ୍ରହଣ କରି ଏକ୍ସଚେଞ୍ଜ ଡକ୍ୟୁମେଣ୍ଟ ପୂର୍ଣ୍ଣ କରିବା ପରେ ଗ୍ରାହକ ଅନୁରୋଧ କରୁଛନ୍ତି ଯେ ନୂତନ ଯାନ ଡେଲିଭରି ହେବା ପର୍ଯ୍ୟନ୍ତ ସେ ପୁରୁଣା ଯାନକୁ ଆଉ ଗୋଟିଏ ସପ୍ତାହ ନିଜ ପାଖରେ ରଖିବେ। ସେ କହୁଛନ୍ତି ଯେ ଚୁକ୍ତି ସମ୍ପୂର୍ଣ୍ଣ ହୋଇଗଲାପରେ ଅସ୍ଥାୟୀ ରଖିବାରେ କୌଣସି ସମସ୍ୟା ହେବା ଉଚିତ୍ ନୁହେଁ। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(553, 47, 1, 'A customer feels the exchange value is slightly below his expectation and threatens to cancel his new vehicle booking if the dealership does not increase the valuation by ₹2,000.\r\n\r\nHe indicates that the exchange decision directly impacts his purchase commitment.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(554, 47, 2, 'एक ग्राहक को लगता है कि एक्सचेंज की कीमत उसकी अपेक्षा से थोड़ी कम है और वह कहता है कि यदि डीलरशिप ₹2,000 नहीं बढ़ाती तो वह नई गाड़ी की बुकिंग रद्द कर देगा। वह बताता है कि एक्सचेंज का फैसला उसकी खरीद पर सीधा असर डालता है। आप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(555, 47, 3, 'ਇੱਕ ਗਾਹਕ ਨੂੰ ਲੱਗਦਾ ਹੈ ਕਿ ਐਕਸਚੇਂਜ ਦੀ ਕੀਮਤ ਉਸਦੀ ਉਮੀਦ ਤੋਂ ਥੋੜ੍ਹੀ ਘੱਟ ਹੈ ਅਤੇ ਉਹ ਕਹਿੰਦਾ ਹੈ ਕਿ ਜੇ ਡੀਲਰਸ਼ਿਪ ₹2,000 ਨਾ ਵਧਾਏ ਤਾਂ ਉਹ ਨਵੀਂ ਗੱਡੀ ਦੀ ਬੁਕਿੰਗ ਰੱਦ ਕਰ ਦੇਵੇਗਾ। ਉਹ ਦੱਸਦਾ ਹੈ ਕਿ ਐਕਸਚੇਂਜ ਦਾ ਫੈਸਲਾ ਉਸਦੀ ਖਰੀਦ ਨਾਲ ਸਿੱਧਾ ਜੁੜਿਆ ਹੈ। ਤੁਸੀਂ ਇਹ ਸਥਿਤੀ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(556, 47, 4, 'એક ગ્રાહકને લાગે છે કે એક્સચેન્જ કિંમત તેની અપેક્ષા કરતાં થોડી ઓછી છે અને તે કહે છે કે જો ડીલરશિપ ₹2,000 નહીં વધારે તો તે નવી ગાડીની બુકિંગ રદ કરી દેશે। તે જણાવે છે કે એક્સચેન્જનો નિર્ણય તેની ખરીદી પર સીધી અસર કરે છે। તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(557, 47, 5, 'एका ग्राहकाला वाटते की एक्सचेंजची किंमत त्याच्या अपेक्षेपेक्षा थोडी कमी आहे आणि तो सांगतो की डीलरशिपने ₹2,000 वाढवले नाही तर तो नवीन गाडीची बुकिंग रद्द करेल। तो स्पष्ट करतो की एक्सचेंजचा निर्णय त्याच्या खरेदीवर थेट परिणाम करतो। तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(558, 47, 6, 'একজন গ্রাহকের মনে হচ্ছে এক্সচেঞ্জ মূল্য তার প্রত্যাশার তুলনায় সামান্য কম এবং তিনি বলেন যে ডিলারশিপ যদি ₹2,000 না বাড়ায় তবে তিনি নতুন গাড়ির বুকিং বাতিল করবেন। তিনি জানান যে এক্সচেঞ্জের সিদ্ধান্ত তার কেনার সিদ্ধান্তের ওপর সরাসরি প্রভাব ফেলে। আপনি কীভাবে এই পরিস্থিতি সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(559, 47, 7, 'এজন গ্ৰাহকে অনুভৱ কৰে যে এক্সচেঞ্জ মূল্য তেওঁৰ আশা অপেক্ষা অলপ কম আৰু কয় যে যদি ডীলাৰশিপে ₹2,000 বৃদ্ধি নকৰে তেন্তে তেওঁ নতুন গাড়ীৰ বুকিং বাতিল কৰিব। তেওঁ উল্লেখ কৰে যে এক্সচেঞ্জ সিদ্ধান্ত তেওঁৰ ক্ৰয় প্ৰতিশ্ৰুতিৰ সৈতে সোজাকৈ জড়িত। আপুনি এই পৰিস্থিতি কেনেকৈ সমাধান কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(560, 47, 8, 'ஒரு வாடிக்கையாளர் எக்ஸ்சேஞ்ச் மதிப்பு தனது எதிர்பார்ப்பை விட சற்றுக் குறைவாக உள்ளது என்று நினைக்கிறார். டீலர்ஷிப் ₹2,000 அதிகரிக்காவிட்டால் புதிய வாகன முன்பதிவை ரத்து செய்வேன் என்று கூறுகிறார். எக்ஸ்சேஞ்ச் முடிவு தனது வாங்கும் உறுதிப்பாட்டை நேரடியாக பாதிக்கிறது என அவர் தெரிவிக்கிறார். இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(561, 47, 9, 'ఒక కస్టమర్‌కు ఎక్స్చేంజ్ విలువ తన అంచనాకు కాస్త తక్కువగా ఉందని అనిపిస్తుంది. డీలర్‌షిప్ ₹2,000 పెంచకపోతే కొత్త వాహనం బుకింగ్ రద్దు చేస్తానని చెబుతున్నాడు. ఎక్స్చేంజ్ నిర్ణయం తన కొనుగోలు నిబద్ధతపై నేరుగా ప్రభావం చూపుతుందని సూచిస్తున్నాడు. మీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(562, 47, 10, 'ഒരു ഉപഭോക്താവിന് എക്സ്ചേഞ്ച് വില തന്റെ പ്രതീക്ഷയേക്കാൾ അല്പം കുറവാണെന്ന് തോന്നുന്നു. ഡീലർഷിപ്പ് ₹2,000 വർധിപ്പിക്കാത്ത പക്ഷം പുതിയ വാഹന ബുക്കിംഗ് റദ്ദാക്കുമെന്ന് പറയുന്നു. എക്സ്ചേഞ്ച് തീരുമാനം തന്റെ വാങ്ങൽ പ്രതിബദ്ധതയെ നേരിട്ട് ബാധിക്കുന്നു എന്നും വ്യക്തമാക്കുന്നു. നിങ്ങൾ ഈ സാഹചര്യം എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(563, 47, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕ ಎಕ್ಸ್ಚೇಂಜ್ ಮೌಲ್ಯ ತನ್ನ ನಿರೀಕ್ಷೆಗೆ ಹೋಲಿಸಿದರೆ ಸ್ವಲ್ಪ ಕಡಿಮೆಯಾಗಿದೆ ಎಂದು ಭಾವಿಸುತ್ತಾನೆ. ಡೀಲರ್‌ಶಿಪ್ ₹2,000 ಹೆಚ್ಚಿಸದಿದ್ದರೆ ಹೊಸ ವಾಹನದ ಬುಕ್ಕಿಂಗ್ ರದ್ದುಪಡಿಸುವುದಾಗಿ ಹೇಳುತ್ತಾನೆ. ಎಕ್ಸ್ಚೇಂಜ್ ನಿರ್ಧಾರ ತನ್ನ ಖರೀದಿ ಬದ್ಧತೆಯನ್ನು ನೇರವಾಗಿ ಪ್ರಭಾವಿಸುತ್ತದೆ ಎಂದು ಸೂಚಿಸುತ್ತಾನೆ. ನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(564, 47, 12, 'ଏକ ଗ୍ରାହକ ଭାବୁଛନ୍ତି ଯେ ଏକ୍ସଚେଞ୍ଜ ମୂଲ୍ୟ ତାଙ୍କ ଆଶା ତୁଳନାରେ ସାନା କମ୍। ଡିଲରଶିପ୍ ₹2,000 ବଢ଼ାଇ ନ ଦେଲେ ସେ ନୂତନ ଯାନ ବୁକିଂ ବାତିଲ କରିବେ ବୋଲି କହୁଛନ୍ତି। ଏକ୍ସଚେଞ୍ଜ ନିଷ୍ପତ୍ତି ତାଙ୍କ କ୍ରୟ ପ୍ରତିବଦ୍ଧତା ଉପରେ ସିଧାସଳଖ ପ୍ରଭାବ ପକାଏ ବୋଲି ସୂଚନା ଦେଉଛନ୍ତି। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(565, 48, 1, 'A customer with a 4-year-old vehicle visits your workshop for routine service.\r\n\r\nDuring interaction, he enquires about the new model or a higher variant of the same vehicle he is currently driving. He appears interested in the latest features but has not clearly expressed an intention to exchange his current vehicle.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(566, 48, 2, 'एक ग्राहक अपनी 4 साल पुरानी गाड़ी की नियमित सर्विस के लिए वर्कशॉप में आता है। बातचीत के दौरान वह उसी गाड़ी के नए मॉडल या उच्च वेरिएंट के बारे में पूछता है। वह नए फीचर्स में रुचि दिखाता है, लेकिन उसने अभी तक अपनी मौजूदा गाड़ी एक्सचेंज करने का स्पष्ट इरादा नहीं जताया है। आप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(567, 48, 3, 'ਇੱਕ ਗਾਹਕ ਆਪਣੀ 4 ਸਾਲ ਪੁਰਾਣੀ ਗੱਡੀ ਦੀ ਰੁਟੀਨ ਸਰਵਿਸ ਲਈ ਵਰਕਸ਼ਾਪ ‘ਤੇ ਆਉਂਦਾ ਹੈ। ਗੱਲਬਾਤ ਦੌਰਾਨ ਉਹ ਉਸੇ ਮਾਡਲ ਦੇ ਨਵੇਂ ਜਾਂ ਉੱਚ ਵੈਰੀਐਂਟ ਬਾਰੇ ਪੁੱਛਦਾ ਹੈ। ਉਹ ਨਵੇਂ ਫੀਚਰਾਂ ਵਿੱਚ ਦਿਲਚਸਪੀ ਦਿਖਾਉਂਦਾ ਹੈ ਪਰ ਆਪਣੀ ਮੌਜੂਦਾ ਗੱਡੀ ਐਕਸਚੇਂਜ ਕਰਨ ਦੀ ਸਪਸ਼ਟ ਇੱਛਾ ਨਹੀਂ ਦੱਸਦਾ। ਤੁਸੀਂ ਇਹ ਸਥਿਤੀ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(568, 48, 4, 'એક ગ્રાહક તેની 4 વર્ષ જૂની ગાડીની નિયમિત સર્વિસ માટે વર્કશોપ પર આવે છે। વાતચીત દરમિયાન તે હાલમાં ચલાવતી ગાડીના નવા મોડેલ અથવા ઉચ્ચ વેરિઅન્ટ વિશે પૂછે છે। તે નવા ફીચર્સમાં રસ દર્શાવે છે પરંતુ તેની હાલની ગાડી એક્સચેન્જ કરવાની સ્પષ્ટ ઇચ્છા વ્યક્ત કરેલ નથી। તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(569, 48, 5, 'एक ग्राहक आपल्या 4 वर्ष जुन्या गाडीच्या नियमित सर्विससाठी वर्कशॉपमध्ये येतो। चर्चेदरम्यान तो सध्या वापरत असलेल्या गाडीच्या नवीन मॉडेल किंवा उच्च व्हेरिएंटबद्दल चौकशी करतो। तो नवीन फीचर्समध्ये रस दाखवतो पण गाडी एक्सचेंज करण्याचा स्पष्ट हेतू व्यक्त करत नाही। तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(570, 48, 6, 'একজন গ্রাহক তার ৪ বছরের পুরোনো গাড়ির নিয়মিত সার্ভিসের জন্য ওয়ার্কশপে আসেন। আলোচনার সময় তিনি বর্তমানে চালানো গাড়ির নতুন মডেল বা উচ্চ ভেরিয়েন্ট সম্পর্কে জানতে চান। তিনি নতুন ফিচারগুলিতে আগ্রহ দেখান, তবে তার বর্তমান গাড়ি এক্সচেঞ্জ করার স্পষ্ট ইচ্ছা প্রকাশ করেননি। আপনি কীভাবে এই পরিস্থিতি সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(571, 48, 7, 'এজন গ্ৰাহকে নিজৰ ৪ বছৰ পুৰণি গাড়ীৰ নিয়মীয়া চাৰ্ভিচৰ বাবে ৱৰ্কশপলৈ আহে। আলোচনাৰ সময়ত তেওঁ বৰ্তমান ব্যৱহাৰ কৰা গাড়ীৰ নতুন মডেল বা উচ্চ ভেৰিয়েণ্ট বিষয়ে সুধে। তেওঁ নতুন ফিচাৰসমূহত আগ্ৰহ দেখুৱায়, কিন্তু গাড়ী এক্সচেঞ্জ কৰাৰ স্পষ্ট ইচ্ছা প্ৰকাশ কৰা নাই। আপুনি এই পৰিস্থিতি কেনেকৈ সমাধান কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(572, 48, 8, 'ஒரு வாடிக்கையாளர் தனது 4 ஆண்டு பழைய வாகனத்தின் வழக்கமான சேவைக்காக பணிமனைக்கு வருகிறார். உரையாடலின் போது, தற்போது பயன்படுத்தும் வாகனத்தின் புதிய மாடல் அல்லது உயர்ந்த வகை குறித்து கேட்கிறார். புதிய அம்சங்களில் ஆர்வம் காட்டுகிறார், ஆனால் தற்போதைய வாகனத்தை மாற்றும் தெளிவான நோக்கம் வெளிப்படுத்தவில்லை. இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(573, 48, 9, 'ఒక కస్టమర్ తన 4 సంవత్సరాల పాత వాహనం సాధారణ సర్వీస్ కోసం వర్క్‌షాప్‌కు వస్తాడు. సంభాషణలో అతను ప్రస్తుతం ఉపయోగిస్తున్న వాహనం యొక్క కొత్త మోడల్ లేదా ఉన్నత వేరియంట్ గురించి అడుగుతున్నాడు. అతను కొత్త ఫీచర్లపై ఆసక్తి చూపుతున్నాడు కానీ తన వాహనాన్ని ఎక్స్చేంజ్ చేయాలనే స్పష్టమైన ఉద్దేశాన్ని వ్యక్తం చేయలేదు. మీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(574, 48, 10, 'ഒരു ഉപഭോക്താവ് തന്റെ 4 വർഷം പഴക്കമുള്ള വാഹനത്തിന്റെ സാധാരണ സർവീസിനായി വർക്ക്‌ഷോപ്പിൽ എത്തുന്നു. സംസാരത്തിനിടെ ഇപ്പോൾ ഉപയോഗിക്കുന്ന വാഹനത്തിന്റെ പുതിയ മോഡൽ അല്ലെങ്കിൽ ഉയർന്ന വേരിയന്റിനെ കുറിച്ച് ചോദിക്കുന്നു. പുതിയ ഫീച്ചറുകളിൽ താൽപര്യം കാണിച്ചെങ്കിലും നിലവിലെ വാഹനം എക്സ്ചേഞ്ച് ചെയ്യാനുള്ള വ്യക്തമായ ഉദ്ദേശം വ്യക്തമാക്കിയിട്ടില്ല. നിങ്ങൾ ഈ സാഹചര്യം എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(575, 48, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕ ತನ್ನ 4 ವರ್ಷದ ಹಳೆಯ ವಾಹನದ ರೂಟಿನ್ ಸರ್ವೀಸ್‌ಗಾಗಿ ವರ್ಕ್‌ಶಾಪ್‌ಗೆ ಬರುತ್ತಾನೆ. ಸಂಭಾಷಣೆಯ ವೇಳೆ, ಅವನು ಪ್ರಸ್ತುತ ಬಳಸುತ್ತಿರುವ ವಾಹನದ ಹೊಸ ಮಾದರಿ ಅಥವಾ ಹೆಚ್ಚಿನ ವೇರಿಯಂಟ್ ಬಗ್ಗೆ ಕೇಳುತ್ತಾನೆ. ಹೊಸ ವೈಶಿಷ್ಟ್ಯಗಳಲ್ಲಿ ಆಸಕ್ತಿ ತೋರಿಸುತ್ತಾನೆ, ಆದರೆ ತನ್ನ ಪ್ರಸ್ತುತ ವಾಹನವನ್ನು ಎಕ್ಸ್ಚೇಂಜ್ ಮಾಡುವ ಸ್ಪಷ್ಟ ಉದ್ದೇಶ ವ್ಯಕ್ತಪಡಿಸಿಲ್ಲ. ನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(576, 48, 12, 'ଏକ ଗ୍ରାହକ ତାଙ୍କ 4 ବର୍ଷ ପୁରୁଣା ଯାନର ସାଧାରଣ ସର୍ଭିସ ପାଇଁ ୱର୍କଶପକୁ ଆସନ୍ତି। ଆଲୋଚନା ସମୟରେ ସେ ବର୍ତ୍ତମାନ ଚଳାଉଥିବା ଯାନର ନୂତନ ମଡେଲ କିମ୍ବା ଉଚ୍ଚ ଭାର୍ସନ ବିଷୟରେ ପଚାରନ୍ତି। ସେ ନୂତନ ବିଶେଷତାରେ ଆଗ୍ରହ ଦେଖାନ୍ତି, କିନ୍ତୁ ନିଜର ବର୍ତ୍ତମାନ ଯାନକୁ ଏକ୍ସଚେଞ୍ଜ କରିବାର ସ୍ପଷ୍ଟ ଇଚ୍ଛା ଦେଖାଇନାହାନ୍ତି। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(577, 49, 1, 'A customer claims his friend received a higher exchange value for the same model at another dealership.\r\n\r\nHe expects you to match that value.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(578, 49, 2, 'एक ग्राहक कहता है कि उसके दोस्त को इसी मॉडल के लिए किसी दूसरे डीलरशिप पर ज्यादा एक्सचेंज कीमत मिली है। वह उम्मीद करता है कि आप भी उतनी ही कीमत दें। आप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(579, 49, 3, 'ਇੱਕ ਗਾਹਕ ਕਹਿੰਦਾ ਹੈ ਕਿ ਉਸਦੇ ਦੋਸਤ ਨੂੰ ਇਸੇ ਮਾਡਲ ਲਈ ਕਿਸੇ ਹੋਰ ਡੀਲਰਸ਼ਿਪ ਤੋਂ ਵੱਧ ਐਕਸਚੇਂਜ ਕੀਮਤ ਮਿਲੀ ਸੀ। ਉਹ ਉਮੀਦ ਕਰਦਾ ਹੈ ਕਿ ਤੁਸੀਂ ਵੀ ਉਹੀ ਕੀਮਤ ਦਿਓ। ਤੁਸੀਂ ਇਹ ਸਥਿਤੀ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(580, 49, 4, 'એક ગ્રાહક કહે છે કે તેના મિત્રને આ જ મોડેલ માટે બીજી ડીલરશિપ પર વધુ એક્સચેન્જ કિંમત મળી હતી। તે અપેક્ષા રાખે છે કે તમે પણ એટલી જ કિંમત આપો। તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(581, 49, 5, 'एक ग्राहक सांगतो की त्याच्या मित्राला याच मॉडेलसाठी दुसऱ्या डीलरशिपमध्ये जास्त एक्सचेंज किंमत मिळाली होती। तो अपेक्षा करतो की तुम्हीही तितकीच किंमत द्यावी। तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(582, 49, 6, 'একজন গ্রাহক বলেন যে তার বন্ধুকে একই মডেলের জন্য অন্য একটি ডিলারশিপে বেশি এক্সচেঞ্জ মূল্য দেওয়া হয়েছিল। তিনি আশা করছেন যে আপনিও একই মূল্য দেবেন। আপনি কীভাবে এই পরিস্থিতি সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(583, 49, 7, 'এজন গ্ৰাহকে কয় যে তেওঁৰ বন্ধুৱে একে মডেলৰ বাবে আন ডীলাৰশিপত অধিক এক্সচেঞ্জ মূল্য পাইছিল। তেওঁ আশা কৰিছে যে আপুনিও সেই একে মূল্য দিব। আপুনি এই পৰিস্থিতি কেনেকৈ সমাধান কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(584, 49, 8, 'ஒரு வாடிக்கையாளர் தனது நண்பருக்கு இதே மாடலுக்கு மற்றொரு டீலர்ஷிப்பில் அதிக எக்ஸ்சேஞ்ச் மதிப்பு கிடைத்ததாக கூறுகிறார். அதே மதிப்பை நீங்கள் வழங்க வேண்டும் என்று எதிர்பார்க்கிறார். இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(585, 49, 9, 'ఒక కస్టమర్ తన స్నేహితుడికి ఇదే మోడల్‌కు మరో డీలర్‌షిప్‌లో ఎక్కువ ఎక్స్చేంజ్ విలువ లభించిందని చెబుతున్నాడు. మీరు కూడా అదే విలువ ఇవ్వాలని ఆశిస్తున్నాడు. మీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(586, 49, 10, 'ഒരു ഉപഭോക്താവ് തന്റെ സുഹൃത്തിന് ഇതേ മോഡലിന് മറ്റൊരു ഡീലർഷിപ്പിൽ കൂടുതൽ എക്സ്ചേഞ്ച് വില ലഭിച്ചതായി പറയുന്നു. നിങ്ങളും അതേ വില നൽകുമെന്ന് പ്രതീക്ഷിക്കുന്നു. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(587, 49, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕ ತನ್ನ ಸ್ನೇಹಿತನಿಗೆ ಇದೇ ಮಾದರಿಗೆ ಮತ್ತೊಂದು ಡೀಲರ್‌ಶಿಪ್‌ನಲ್ಲಿ ಹೆಚ್ಚಿನ ಎಕ್ಸ್ಚೇಂಜ್ ಮೌಲ್ಯ ಸಿಕ್ಕಿತು ಎಂದು ಹೇಳುತ್ತಾನೆ. ನೀವು ಕೂಡ ಅದೇ ಮೌಲ್ಯ ನೀಡಬೇಕು ಎಂದು ನಿರೀಕ್ಷಿಸುತ್ತಾನೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(588, 49, 12, 'ଏକ ଗ୍ରାହକ କହୁଛନ୍ତି ଯେ ତାଙ୍କ ବନ୍ଧୁଙ୍କୁ ଏହି ଏକେ ମଡେଲ ପାଇଁ ଅନ୍ୟ ଡିଲରଶିପରେ ଅଧିକ ଏକ୍ସଚେଞ୍ଜ ମୂଲ୍ୟ ମିଳିଥିଲା। ସେ ଆଶା କରୁଛନ୍ତି ଯେ ଆପଣମାନେ ମଧ୍ୟ ସେହି ମୂଲ୍ୟ ଦେବେ। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(589, 50, 1, 'During final inspection before documentation, your exchange evaluator discovers accidental damage that was not disclosed earlier. \r\n\r\nThe customer insists the previously discussed value should not change.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(590, 50, 2, 'डॉक्यूमेंटेशन से पहले अंतिम निरीक्षण के दौरान एक्सचेंज मूल्यांकनकर्ता को गाड़ी में दुर्घटना से हुआ नुकसान मिलता है, जिसकी पहले जानकारी नहीं दी गई थी। ग्राहक जोर देकर कहता है कि पहले जो कीमत तय हुई थी, वह नहीं बदलनी चाहिए। आप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(591, 50, 3, 'ਡਾਕੂਮੈਂਟੇਸ਼ਨ ਤੋਂ ਪਹਿਲਾਂ ਆਖਰੀ ਜਾਂਚ ਦੌਰਾਨ ਐਕਸਚੇਂਜ ਮੁਲਾਂਕਣ ਕਰਨ ਵਾਲੇ ਨੂੰ ਗੱਡੀ ਵਿੱਚ ਹਾਦਸੇ ਦਾ ਨੁਕਸਾਨ ਮਿਲਦਾ ਹੈ, ਜਿਸਦੀ ਪਹਿਲਾਂ ਜਾਣਕਾਰੀ ਨਹੀਂ ਦਿੱਤੀ ਗਈ ਸੀ। ਗਾਹਕ ਜ਼ੋਰ ਦਿੰਦਾ ਹੈ ਕਿ ਪਹਿਲਾਂ ਤੈਅ ਕੀਤੀ ਕੀਮਤ ਨਹੀਂ ਬਦਲਣੀ ਚਾਹੀਦੀ। ਤੁਸੀਂ ਇਹ ਸਥਿਤੀ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(592, 50, 4, 'ડોક્યુમેન્ટેશન પહેલાં અંતિમ તપાસ દરમિયાન એક્સચેન્જ મૂલ્યાંકનકર્તાને વાહનમાં અકસ્માતથી થયેલ નુકસાન મળે છે, જે પહેલા જાહેર કરવામાં આવ્યું ન હતું। ગ્રાહક આગ્રહ કરે છે કે અગાઉ ચર્ચાયેલી કિંમત બદલવી નહીં જોઈએ। તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(593, 50, 5, 'डॉक्युमेंटेशनपूर्वी अंतिम तपासणीदरम्यान एक्सचेंज मूल्यांकनकर्त्याला गाडीत अपघातामुळे झालेले नुकसान आढळते, ज्याची आधी माहिती दिली नव्हती। ग्राहक ठामपणे सांगतो की आधी ठरलेली किंमत बदलू नये। तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(594, 50, 6, 'ডকুমেন্টেশন করার আগে চূড়ান্ত পরিদর্শনের সময় এক্সচেঞ্জ মূল্যায়নকারী গাড়িতে দুর্ঘটনাজনিত ক্ষতি খুঁজে পান, যা আগে জানানো হয়নি। গ্রাহক জোর দিয়ে বলেন যে আগে আলোচনা করা মূল্য পরিবর্তন করা উচিত নয়। আপনি কীভাবে এই পরিস্থিতি সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(595, 50, 7, 'ডকুমেন্টেশনৰ আগতে চূড়ান্ত পৰীক্ষাৰ সময়ত এক্সচেঞ্জ মূল্যায়নকাৰীয়ে গাড়ীত দুর্ঘটনাজনিত ক্ষতি বিচাৰে, যি আগতে প্ৰকাশ কৰা হোৱা নাছিল। গ্ৰাহকে জোৰ দিয়ে কয় যে পূৰ্বতে আলোচনা কৰা মূল্য সলনি কৰা উচিত নহয়। আপুনি এই পৰিস্থিতি কেনেকৈ সমাধান কৰিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(596, 50, 8, 'டாக்குமெண்டேஷன் முன் இறுதி ஆய்வின் போது எக்ஸ்சேஞ்ச் மதிப்பீட்டாளர் முன்பு தெரிவிக்கப்படாத விபத்து சேதத்தை கண்டுபிடிக்கிறார். முன்பு பேசப்பட்ட மதிப்பு மாற்றப்படக்கூடாது என்று வாடிக்கையாளர் வலியுறுத்துகிறார். இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(597, 50, 9, 'డాక్యుమెంటేషన్‌కు ముందు తుది తనిఖీ సమయంలో ఎక్స్చేంజ్ మూల్యాంకన అధికారి ముందుగా తెలియజేయని ప్రమాద నష్టాన్ని గుర్తిస్తాడు. ముందుగా చర్చించిన విలువ మార్చకూడదని కస్టమర్ అంటున్నాడు. మీరు ఈ పరిస్థితిని ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(598, 50, 10, 'ഡോക്യുമെന്റേഷനു മുൻപ് അന്തിമ പരിശോധനയിൽ എക്സ്ചേഞ്ച് മൂല്യനിർണയ ഉദ്യോഗസ്ഥൻ മുൻപ് അറിയിക്കാത്ത അപകടനഷ്ടം കണ്ടെത്തുന്നു. മുൻപ് പറഞ്ഞ വില മാറ്റരുതെന്ന് ഉപഭോക്താവ് ഉറച്ചുപറയുന്നു. നിങ്ങൾ ഈ സാഹചര്യം എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(599, 50, 11, 'ಡಾಕ್ಯುಮೆಂಟೇಶನ್‌ಗೆ ಮುನ್ನ ಅಂತಿಮ ಪರಿಶೀಲನೆಯ ವೇಳೆ ಎಕ್ಸ್ಚೇಂಜ್ ಮೌಲ್ಯಮಾಪಕನು ಮೊದಲು ತಿಳಿಸದ ಅಪಘಾತ ಹಾನಿಯನ್ನು ಕಂಡುಹಿಡಿಯುತ್ತಾನೆ. ಮೊದಲು ಚರ್ಚಿಸಿದ ಮೌಲ್ಯವನ್ನು ಬದಲಿಸಬಾರದು ಎಂದು ಗ್ರಾಹಕ ಒತ್ತಾಯಿಸುತ್ತಾನೆ. ನೀವು ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(600, 50, 12, 'ଡକ୍ୟୁମେଣ୍ଟେସନ ପୂର୍ବରୁ ଅନ୍ତିମ ପରୀକ୍ଷା ସମୟରେ ଏକ୍ସଚେଞ୍ଜ ମୂଲ୍ୟାୟନକାରୀ ପୂର୍ବରୁ ଜଣାଇନଥିବା ଦୁର୍ଘଟଣା ହାନି ଚିହ୍ନଟ କରନ୍ତି। ପୂର୍ବରୁ ଆଲୋଚିତ ମୂଲ୍ୟ ପରିବର୍ତ୍ତନ ହେବା ଉଚିତ୍ ନୁହେଁ ବୋଲି ଗ୍ରାହକ ଜୋର ଦେଉଛନ୍ତି। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ସମ୍ଭାଳିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:03:51', 'Active'),
	(601, 51, 1, 'A customer purchased a Hero motorcycle two weeks ago and calls the dealership. \r\n\r\nHe was informed that the Registration Certificate (RC) would be delivered within one week, but it has not yet been received.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(602, 51, 2, 'एक ग्राहक ने दो हफ्ते पहले एक हीरो मोटरसाइकिल खरीदी थी और वह डीलरशिप पर कॉल करता है।\r\n\r\nउसे बताया गया था कि रजिस्ट्रेशन सर्टिफिकेट (RC) एक हफ्ते के अंदर मिल जाएगा, लेकिन अभी तक उसे RC प्राप्त नहीं हुआ है।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(603, 51, 3, 'ਇੱਕ ਗਾਹਕ ਨੇ ਦੋ ਹਫ਼ਤੇ ਪਹਿਲਾਂ ਹੀਰੋ ਮੋਟਰਸਾਈਕਲ ਖਰੀਦੀ ਸੀ ਅਤੇ ਡੀਲਰਸ਼ਿਪ ਨੂੰ ਕਾਲ ਕਰਦਾ ਹੈ। ਉਸਨੂੰ ਦੱਸਿਆ ਗਿਆ ਸੀ ਕਿ ਰਜਿਸਟ੍ਰੇਸ਼ਨ ਸਰਟੀਫਿਕੇਟ (RC) ਇੱਕ ਹਫ਼ਤੇ ਵਿੱਚ ਮਿਲ ਜਾਵੇਗਾ, ਪਰ ਅਜੇ ਤੱਕ ਨਹੀਂ ਮਿਲਿਆ। ਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(604, 51, 4, 'એક ગ્રાહકે બે અઠવાડિયા પહેલા હીરો મોટરસાયકલ ખરીદી હતી અને ડીલરશિપ પર કોલ કરે છે. તેમને કહેવામાં આવ્યું હતું કે રજિસ્ટ્રેશન સર્ટિફિકેટ (RC) એક અઠવાડિયામાં મળી જશે, પરંતુ હજુ સુધી મળ્યું નથી. તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(605, 51, 5, 'एका ग्राहकाने दोन आठवड्यांपूर्वी हिरो मोटरसायकल खरेदी केली आणि डीलरशिपला फोन केला. त्याला सांगितले होते की रजिस्ट्रेशन सर्टिफिकेट (RC) एक आठवड्यात मिळेल, पण अजून मिळालेले नाही. तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(606, 51, 6, 'একজন গ্রাহক দুই সপ্তাহ আগে হিরো মোটরসাইকেল কিনেছেন এবং ডিলারশিপে ফোন করেছেন। তাকে বলা হয়েছিল যে রেজিস্ট্রেশন সার্টিফিকেট (RC) এক সপ্তাহের মধ্যে দেওয়া হবে, কিন্তু এখনও পাননি। আপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(607, 51, 7, 'এজন গ্ৰাহকে দুসপ্তাহ আগতে হিৰো মটৰচাইকেল ক্ৰয় কৰিছিল আৰু ডিলাৰশ্বিপলৈ ফোন কৰে। তেওঁক কোৱা হৈছিল যে ৰেজিষ্ট্ৰেচন চাৰ্টিফিকেট (RC) এটা সপ্তাহৰ ভিতৰত পোৱা যাব, কিন্তু এতিয়াও পোৱা হোৱা নাই। আপুনি এই পৰিস্থিতি কেনেকৈ সামাল দিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(608, 51, 8, 'ஒரு வாடிக்கையாளர் இரண்டு வாரங்களுக்கு முன்பு ஹீரோ மோட்டார்சைக்கிள் வாங்கி டீலர்ஷிப்புக்கு அழைக்கிறார். பதிவு சான்றிதழ் (RC) ஒரு வாரத்தில் வழங்கப்படும் என்று கூறப்பட்டது, ஆனால் இன்னும் பெறவில்லை. இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(609, 51, 9, 'ఒక కస్టమర్ రెండు వారాల క్రితం హీరో మోటార్‌సైకిల్ కొనుగోలు చేసి డీలర్‌షిప్‌కు కాల్ చేస్తాడు. రిజిస్ట్రేషన్ సర్టిఫికేట్ (RC) ఒక వారంలో అందిస్తామని చెప్పారు, కానీ ఇంకా అందలేదు. ఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(610, 51, 10, 'ഒരു ഉപഭോക്താവ് രണ്ട് ആഴ്ച മുമ്പ് ഹീറോ മോട്ടോർസൈക്കിൾ വാങ്ങി ഡീലർഷിപ്പിലേക്ക് വിളിക്കുന്നു. റജിസ്ട്രേഷൻ സർട്ടിഫിക്കറ്റ് (RC) ഒരു ആഴ്ചയ്ക്കുള്ളിൽ ലഭിക്കും എന്ന് പറഞ്ഞിരുന്നു, എന്നാൽ ഇതുവരെ ലഭിച്ചിട്ടില്ല. ഈ സാഹചര്യത്തെ നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(611, 51, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕರು ಎರಡು ವಾರಗಳ ಹಿಂದೆ ಹೀರೋ ಮೋಟಾರ್‌ಸೈಕಲ್ ಖರೀದಿಸಿ ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಕರೆ ಮಾಡುತ್ತಾರೆ. ರಿಜಿಸ್ಟ್ರೇಷನ್ ಪ್ರಮಾಣಪತ್ರ (RC) ಒಂದು ವಾರದಲ್ಲಿ ದೊರೆಯುತ್ತದೆ ಎಂದು ತಿಳಿಸಲಾಗಿತ್ತು, ಆದರೆ ಇನ್ನೂ ದೊರೆತಿಲ್ಲ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(612, 51, 12, 'ଏକ ଗ୍ରାହକ ଦୁଇ ସପ୍ତାହ ପୂର୍ବରୁ ହିରୋ ମୋଟରସାଇକେଲ କିଣିଥିଲେ ଏବଂ ଡିଲରଶିପକୁ ଫୋନ କରିଛନ୍ତି। ତାଙ୍କୁ କୁହାଯାଇଥିଲା ଯେ ରେଜିଷ୍ଟ୍ରେସନ ସର୍ଟିଫିକେଟ (RC) ଏକ ସପ୍ତାହ ମଧ୍ୟରେ ମିଳିବ, କିନ୍ତୁ ଏପର୍ଯ୍ୟନ୍ତ ମିଳିନି। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ହ୍ୟାଣ୍ଡଲ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(613, 52, 1, 'A customer who booked a Hero Xtreme 160R 4V two weeks ago calls the dealership. \r\n\r\nHe was informed that the delivery date would be confirmed shortly after booking, but he has not yet received any confirmation.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(614, 52, 2, 'एक ग्राहक ने दो हफ्ते पहले Hero Xtreme 160R 4V बुक की थी और वह डीलरशिप पर कॉल करता है।\r\n\r\nउसे बताया गया था कि बुकिंग के थोड़े समय बाद डिलीवरी की तारीख कन्फर्म कर दी जाएगी, लेकिन अभी तक उसे कोई पुष्टि नहीं मिली है।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(615, 52, 3, 'ਇੱਕ ਗਾਹਕ ਨੇ ਦੋ ਹਫ਼ਤੇ ਪਹਿਲਾਂ Hero Xtreme 160R 4V ਬੁੱਕ ਕੀਤੀ ਸੀ ਅਤੇ ਡੀਲਰਸ਼ਿਪ ਨੂੰ ਕਾਲ ਕਰਦਾ ਹੈ। ਉਸਨੂੰ ਦੱਸਿਆ ਗਿਆ ਸੀ ਕਿ ਬੁੱਕਿੰਗ ਤੋਂ ਥੋੜ੍ਹੇ ਸਮੇਂ ਬਾਅਦ ਡਿਲਿਵਰੀ ਦੀ ਤਾਰੀਖ ਪੱਕੀ ਕਰ ਦਿੱਤੀ ਜਾਵੇਗੀ, ਪਰ ਅਜੇ ਤੱਕ ਕੋਈ ਪੁਸ਼ਟੀ ਨਹੀਂ ਮਿਲੀ। ਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(616, 52, 4, 'એક ગ્રાહકે બે અઠવાડિયા પહેલા Hero Xtreme 160R 4V બુક કરી હતી અને ડીલરશિપ પર કોલ કરે છે. તેમને કહેવામાં આવ્યું હતું કે બુકિંગ પછી ટૂંક સમયમાં ડિલિવરી તારીખ કન્ફર્મ કરવામાં આવશે, પરંતુ હજુ સુધી કોઈ પુષ્ટિ મળી નથી. તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(617, 52, 5, 'एका ग्राहकाने दोन आठवड्यांपूर्वी Hero Xtreme 160R 4V बुक केली आणि डीलरशिपला फोन केला. त्याला सांगितले होते की बुकिंगनंतर लवकरच डिलिव्हरीची तारीख निश्चित केली जाईल, पण अजून कोणतीही पुष्टी मिळालेली नाही. तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(618, 52, 6, 'একজন গ্রাহক দুই সপ্তাহ আগে Hero Xtreme 160R 4V বুক করেছেন এবং ডিলারশিপে ফোন করেছেন। তাকে বলা হয়েছিল যে বুকিংয়ের কিছুদিনের মধ্যেই ডেলিভারির তারিখ নিশ্চিত করা হবে, কিন্তু এখনও কোনো নিশ্চিতকরণ পাননি। আপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(619, 52, 7, 'এজন গ্ৰাহকে দুসপ্তাহ আগতে Hero Xtreme 160R 4V বুক কৰিছিল আৰু ডিলাৰশ্বিপলৈ ফোন কৰে। তেওঁক কোৱা হৈছিল যে বুকিঙৰ পিছতে সোনকালেই ডেলিভাৰী তাৰিখ নিশ্চিত কৰা হ\'ব, কিন্তু এতিয়াও কোনো নিশ্চিতকৰণ পোৱা হোৱা নাই। আপুনি এই পৰিস্থিতি কেনেকৈ সামাল দিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(620, 52, 8, 'ஒரு வாடிக்கையாளர் இரண்டு வாரங்களுக்கு முன்பு Hero Xtreme 160R 4V முன்பதிவு செய்து டீலர்ஷிப்புக்கு அழைக்கிறார். முன்பதிவு செய்த சில நாட்களில் டெலிவரி தேதி உறுதிப்படுத்தப்படும் என்று கூறப்பட்டது, ஆனால் இன்னும் எந்த உறுதிப்படுத்தலும் பெறவில்லை. இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(621, 52, 9, 'ఒక కస్టమర్ రెండు వారాల క్రితం Hero Xtreme 160R 4V బుక్ చేసి డీలర్‌షిప్‌కు కాల్ చేస్తాడు. బుకింగ్ చేసిన కొద్ది కాలంలోనే డెలివరీ తేదీ నిర్ధారిస్తామని చెప్పారు, కానీ ఇంకా ఎలాంటి నిర్ధారణ అందలేదు. ఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(622, 52, 10, 'ഒരു ഉപഭോക്താവ് രണ്ട് ആഴ്ച മുമ്പ് Hero Xtreme 160R 4V ബുക്ക് ചെയ്ത് ഡീലർഷിപ്പിലേക്ക് വിളിക്കുന്നു. ബുക്കിംഗ് കഴിഞ്ഞ ഉടൻ ഡെലിവറി തീയതി സ്ഥിരീകരിക്കും എന്ന് പറഞ്ഞിരുന്നു, എന്നാൽ ഇതുവരെ സ്ഥിരീകരണം ലഭിച്ചിട്ടില്ല. ഈ സാഹചര്യത്തെ നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(623, 52, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕರು ಎರಡು ವಾರಗಳ ಹಿಂದೆ Hero Xtreme 160R 4V ಬುಕ್ ಮಾಡಿ ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಕರೆ ಮಾಡುತ್ತಾರೆ. ಬುಕಿಂಗ್ ನಂತರ ಸ್ವಲ್ಪ ಸಮಯದಲ್ಲೇ ಡೆಲಿವರಿ ದಿನಾಂಕವನ್ನು ದೃಢಪಡಿಸಲಾಗುತ್ತದೆ ಎಂದು ತಿಳಿಸಲಾಗಿತ್ತು, ಆದರೆ ಇನ್ನೂ ಯಾವುದೇ ದೃಢೀಕರಣ ಸಿಕ್ಕಿಲ್ಲ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(624, 52, 12, 'ଏକ ଗ୍ରାହକ ଦୁଇ ସପ୍ତାହ ପୂର୍ବରୁ Hero Xtreme 160R 4V ବୁକ୍ କରିଥିଲେ ଏବଂ ଡିଲରଶିପକୁ ଫୋନ କରିଛନ୍ତି। ତାଙ୍କୁ କୁହାଯାଇଥିଲା ଯେ ବୁକିଂ ପରେ ଶୀଘ୍ର ଡେଲିଭରି ତାରିଖ ନିଶ୍ଚିତ କରାଯିବ, କିନ୍ତୁ ଏପର୍ଯ୍ୟନ୍ତ କୌଣସି ନିଶ୍ଚିତକରଣ ମିଳିନି। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ହ୍ୟାଣ୍ଡଲ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(625, 53, 1, 'A customer calls after receiving a quotation from the dealership for a Hero bike. On comparing with another Hero dealership, he notices the price is higher. \r\n\r\nHe becomes irate and questions the dealership’s pricing practices.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(626, 53, 2, 'एक ग्राहक ने Hero बाइक के लिए डीलरशिप से कोटेशन प्राप्त करने के बाद कॉल किया। जब उसने दूसरी Hero डीलरशिप से तुलना की, तो उसे कीमत ज़्यादा लगी।\r\n\r\nवह नाराज़ हो जाता है और डीलरशिप की प्राइसिंग पॉलिसी पर सवाल उठाता है।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(627, 53, 3, 'ਇੱਕ ਗਾਹਕ ਨੇ Hero ਬਾਈਕ ਲਈ ਡੀਲਰਸ਼ਿਪ ਤੋਂ ਕੋਟੇਸ਼ਨ ਮਿਲਣ ਤੋਂ ਬਾਅਦ ਕਾਲ ਕੀਤੀ। ਜਦੋਂ ਉਸਨੇ ਕਿਸੇ ਹੋਰ Hero ਡੀਲਰਸ਼ਿਪ ਨਾਲ ਤੁਲਨਾ ਕੀਤੀ ਤਾਂ ਉਸਨੂੰ ਕੀਮਤ ਵੱਧ ਲੱਗੀ। ਉਹ ਨਾਰਾਜ਼ ਹੋ ਗਿਆ ਅਤੇ ਡੀਲਰਸ਼ਿਪ ਦੀ ਕੀਮਤ ਨੀਤੀ ‘ਤੇ ਸਵਾਲ ਉਠਾਉਣ ਲੱਗ ਪਿਆ। ਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(628, 53, 4, 'એક ગ્રાહકે Hero બાઈક માટે ડીલરશિપમાંથી ક્વોટેશન મળ્યા પછી કોલ કર્યો. બીજી Hero ડીલરશિપ સાથે તુલના કરતાં તેને ભાવ વધારે લાગ્યો. તે ગુસ્સે થઈ ગયો અને ડીલરશિપની પ્રાઇસિંગ પદ્ધતિ પર સવાલ ઉઠાવ્યો. તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(629, 53, 5, 'एका ग्राहकाने Hero बाईकसाठी डीलरशिपकडून कोटेशन मिळाल्यानंतर फोन केला. दुसऱ्या Hero डीलरशिपशी तुलना करताना त्याला किंमत जास्त वाटली. तो संतापला आणि डीलरशिपच्या किंमत धोरणावर प्रश्न उपस्थित करू लागला. तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(630, 53, 6, 'একজন গ্রাহক Hero বাইকের জন্য ডিলারশিপ থেকে কোটেশন পাওয়ার পর ফোন করেছেন। অন্য একটি Hero ডিলারশিপের সাথে তুলনা করে তিনি দেখলেন দাম বেশি। তিনি রেগে গিয়ে ডিলারশিপের মূল্য নির্ধারণ পদ্ধতি নিয়ে প্রশ্ন তুললেন। আপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(631, 53, 7, 'এজন গ্ৰাহকে Hero বাইকৰ বাবে ডিলাৰশ্বিপৰ পৰা কোটেচন লাভ কৰাৰ পিছত ফোন কৰে। আন এটা Hero ডিলাৰশ্বিপৰ সৈতে তুলনা কৰি তেওঁ মূল্য অধিক বুলি লক্ষ্য কৰে। তেওঁ ক্ষুব্ধ হৈ ডিলাৰশ্বিপৰ মূল্য নিৰ্ধাৰণ পদ্ধতি সন্দৰ্ভত প্ৰশ্ন উত্থাপন কৰে। আপুনি এই পৰিস্থিতি কেনেকৈ সামাল দিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(632, 53, 8, 'ஒரு வாடிக்கையாளர் Hero பைக்கிற்கான quotation பெற்ற பிறகு டீலர்ஷிப்புக்கு அழைக்கிறார். மற்றொரு Hero டீலர்ஷிப்புடன் ஒப்பிடும்போது விலை அதிகமாக இருப்பதை கவனிக்கிறார். அவர் கோபமாகி டீலர்ஷிப்பின் விலை நிர்ணய முறையை கேள்வி எழுப்புகிறார். இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(633, 53, 9, 'ఒక కస్టమర్ Hero బైక్ కోసం డీలర్‌షిప్ నుండి కోటేషన్ అందుకున్న తర్వాత కాల్ చేస్తాడు. ఇంకొక Hero డీలర్‌షిప్‌తో పోల్చితే ధర ఎక్కువగా ఉందని గమనిస్తాడు. అతను కోపంగా మారి డీలర్‌షిప్ ధర విధానంపై ప్రశ్నలు వేస్తాడు. ఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(634, 53, 10, 'ഒരു ഉപഭോക്താവ് Hero ബൈക്കിന് ഡീലർഷിപ്പിൽ നിന്ന് ക്വോട്ടേഷൻ ലഭിച്ചതിന് ശേഷം വിളിക്കുന്നു. മറ്റൊരു Hero ഡീലർഷിപ്പുമായി താരതമ്യം ചെയ്തപ്പോൾ വില കൂടുതലാണെന്ന് ശ്രദ്ധിക്കുന്നു. അദ്ദേഹം അസ്വസ്ഥനായി ഡീലർഷിപ്പിന്റെ വില നിശ്ചയ രീതിയെ ചോദ്യം ചെയ്യുന്നു. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(635, 53, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕರು Hero ಬೈಕ್‌ಗೆ ಡೀಲರ್‌ಶಿಪ್‌ನಿಂದ ಕೊಟೇಶನ್ ಪಡೆದ ನಂತರ ಕರೆ ಮಾಡುತ್ತಾರೆ. ಮತ್ತೊಂದು Hero ಡೀಲರ್‌ಶಿಪ್ ಜೊತೆ ಹೋಲಿಕೆ ಮಾಡಿದಾಗ ಬೆಲೆ ಹೆಚ್ಚು ಎಂದು ಗಮನಿಸುತ್ತಾರೆ. ಅವರು ಕೋಪಗೊಂಡು ಡೀಲರ್‌ಶಿಪ್‌ನ ಬೆಲೆ ನಿಗದಿ ವಿಧಾನವನ್ನು ಪ್ರಶ್ನಿಸುತ್ತಾರೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(636, 53, 12, 'ଏକ ଗ୍ରାହକ Hero ବାଇକ ପାଇଁ ଡିଲରଶିପରୁ କୋଟେସନ ପାଇବା ପରେ ଫୋନ କରିଛନ୍ତି। ଅନ୍ୟ ଏକ Hero ଡିଲରଶିପ ସହିତ ତୁଳନା କରି ସେ ଦାମ ଅଧିକ ଥିବାକୁ ଲକ୍ଷ୍ୟ କରିଛନ୍ତି। ସେ କ୍ରୋଧିତ ହୋଇ ଡିଲରଶିପର ମୂଲ୍ୟ ନିର୍ଧାରଣ ପ୍ରଣାଳୀ ବିଷୟରେ ପ୍ରଶ୍ନ କରୁଛନ୍ତି। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ହ୍ୟାଣ୍ଡଲ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(637, 54, 1, 'A customer purchased a Hero motorcycle last week and has not yet received the High Security Registration Plate (HSRP). \r\n\r\nHe calls the dealership sounding frustrated about the delay.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(638, 54, 2, 'एक ग्राहक ने पिछले हफ्ते Hero मोटरसाइकिल खरीदी थी और उसे अभी तक हाई सिक्योरिटी रजिस्ट्रेशन प्लेट (HSRP) नहीं मिली है।\r\n\r\nवह देरी को लेकर नाराज़गी जताते हुए डीलरशिप पर कॉल करता है।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(639, 54, 3, 'ਇੱਕ ਗਾਹਕ ਨੇ ਪਿਛਲੇ ਹਫ਼ਤੇ Hero ਮੋਟਰਸਾਈਕਲ ਖਰੀਦੀ ਸੀ ਅਤੇ ਉਸਨੂੰ ਹਾਲੇ ਤੱਕ High Security Registration Plate (HSRP) ਨਹੀਂ ਮਿਲੀ। ਉਹ ਦੇਰੀ ਕਾਰਨ ਨਾਰਾਜ਼ਗੀ ਨਾਲ ਡੀਲਰਸ਼ਿਪ ਨੂੰ ਕਾਲ ਕਰਦਾ ਹੈ। ਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(640, 54, 4, 'એક ગ્રાહકે ગયા અઠવાડિયે Hero મોટરસાયકલ ખરીદી હતી અને તેને હજુ સુધી High Security Registration Plate (HSRP) મળી નથી. તે વિલંબને કારણે નારાજગી વ્યક્ત કરતાં ડીલરશિપ પર કોલ કરે છે. તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(641, 54, 5, 'एका ग्राहकाने गेल्या आठवड्यात Hero मोटरसायकल खरेदी केली आहे आणि त्याला अजून High Security Registration Plate (HSRP) मिळालेली नाही. तो उशिरामुळे नाराज होऊन डीलरशिपला फोन करतो. तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(642, 54, 6, 'একজন গ্রাহক গত সপ্তাহে Hero মোটরসাইকেল কিনেছেন এবং এখনও High Security Registration Plate (HSRP) পাননি। বিলম্বের কারণে বিরক্ত হয়ে তিনি ডিলারশিপে ফোন করেন। আপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(643, 54, 7, 'এজন গ্ৰাহকে গতা সপ্তাহত Hero মটৰচাইকেল ক্ৰয় কৰিছিল আৰু এতিয়াও High Security Registration Plate (HSRP) লাভ কৰা নাই। বিলম্বৰ বাবে ক্ষুব্ধ হৈ তেওঁ ডিলাৰশ্বিপলৈ ফোন কৰে। আপুনি এই পৰিস্থিতি কেনেকৈ সামাল দিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(644, 54, 8, 'ஒரு வாடிக்கையாளர் கடந்த வாரம் Hero மோட்டார்சைக்கிள் வாங்கியுள்ளார், ஆனால் இன்னும் High Security Registration Plate (HSRP) பெறவில்லை. தாமதம் காரணமாக வருத்தத்துடன் டீலர்ஷிப்புக்கு அழைக்கிறார். இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(645, 54, 9, 'ఒక కస్టమర్ గత వారం Hero మోటార్‌సైకిల్ కొనుగోలు చేశాడు, కానీ ఇంకా High Security Registration Plate (HSRP) పొందలేదు. ఆలస్యంపై అసహనంతో డీలర్‌షిప్‌కు కాల్ చేస్తాడు. ఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(646, 54, 10, 'ഒരു ഉപഭോക്താവ് കഴിഞ്ഞ ആഴ്ച Hero മോട്ടോർസൈക്കിൾ വാങ്ങി, എന്നാൽ ഇതുവരെ High Security Registration Plate (HSRP) ലഭിച്ചിട്ടില്ല. വിലംബം കാരണം അസ്വസ്ഥനായി ഡീലർഷിപ്പിലേക്ക് വിളിക്കുന്നു. ഈ സാഹചര്യത്തെ നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(647, 54, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕರು ಕಳೆದ ವಾರ Hero ಮೋಟಾರ್‌ಸೈಕಲ್ ಖರೀದಿಸಿದ್ದಾರೆ, ಆದರೆ ಇನ್ನೂ High Security Registration Plate (HSRP) ಪಡೆಯಿಲ್ಲ. ವಿಳಂಬದ ಕಾರಣ ಕೋಪಗೊಂಡು ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಕರೆ ಮಾಡುತ್ತಾರೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(648, 54, 12, 'ଏକ ଗ୍ରାହକ ପଛ ସପ୍ତାହରେ Hero ମୋଟରସାଇକେଲ କିଣିଥିଲେ, କିନ୍ତୁ ଏପର୍ଯ୍ୟନ୍ତ High Security Registration Plate (HSRP) ପାଇନାହାନ୍ତି। ବିଳମ୍ବ ପାଇଁ କ୍ଷୁବ୍ଧ ହୋଇ ସେ ଡିଲରଶିପକୁ ଫୋନ କରିଛନ୍ତି। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ହ୍ୟାଣ୍ଡଲ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(649, 55, 1, 'A customer had requested a quotation for a motorcycle several days ago but has not received it. \r\n\r\nHe calls the dealership sounding impatient and annoyed.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(650, 55, 2, 'एक ग्राहक ने कुछ दिन पहले मोटरसाइकिल के लिए कोटेशन मांगा था, लेकिन उसे अभी तक प्राप्त नहीं हुआ है।\r\n\r\nवह अधीर और नाराज़गी भरे लहजे में डीलरशिप पर कॉल करता है।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(651, 55, 3, 'ਇੱਕ ਗਾਹਕ ਨੇ ਕੁਝ ਦਿਨ ਪਹਿਲਾਂ ਮੋਟਰਸਾਈਕਲ ਲਈ ਕੋਟੇਸ਼ਨ ਮੰਗਿਆ ਸੀ, ਪਰ ਉਸਨੂੰ ਹਾਲੇ ਤੱਕ ਨਹੀਂ ਮਿਲਿਆ। ਉਹ ਬੇਸਬਰ ਅਤੇ ਨਾਰਾਜ਼ ਲਹਿਜ਼ੇ ਨਾਲ ਡੀਲਰਸ਼ਿਪ ਨੂੰ ਕਾਲ ਕਰਦਾ ਹੈ। ਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(652, 55, 4, 'એક ગ્રાહકે થોડા દિવસ પહેલા મોટરસાયકલ માટે ક્વોટેશન માંગ્યું હતું, પરંતુ તેને હજુ સુધી મળ્યું નથી. તે બેચેન અને નારાજ અવાજમાં ડીલરશિપ પર કોલ કરે છે. તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(653, 55, 5, 'एका ग्राहकाने काही दिवसांपूर्वी मोटरसायकलसाठी कोटेशन मागितले होते, पण अजून मिळालेले नाही. तो अधीर आणि नाराज स्वरात डीलरशिपला फोन करतो. तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(654, 55, 6, 'একজন গ্রাহক কয়েক দিন আগে মোটরসাইকেলের জন্য কোটেশন চেয়েছিলেন, কিন্তু এখনও পাননি। তিনি অধৈর্য এবং বিরক্ত স্বরে ডিলারশিপে ফোন করেন। আপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(655, 55, 7, 'এজন গ্ৰাহকে কেইদিনমান আগতে মটৰচাইকেলৰ বাবে কোটেচন বিচাৰিছিল, কিন্তু এতিয়াও পোৱা হোৱা নাই। তেওঁ অধৈৰ্য আৰু অসন্তুষ্ট স্বৰত ডিলাৰশ্বিপলৈ ফোন কৰে। আপুনি এই পৰিস্থিতি কেনেকৈ সামাল দিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(656, 55, 8, 'ஒரு வாடிக்கையாளர் சில நாட்களுக்கு முன்பு மோட்டார்சைக்கிளுக்கான quotation கேட்டிருந்தார், ஆனால் இன்னும் பெறவில்லை. அவர் பொறுமையிழந்து எரிச்சலுடன் டீலர்ஷிப்புக்கு அழைக்கிறார். இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(657, 55, 9, 'ఒక కస్టమర్ కొన్ని రోజుల క్రితం మోటార్‌సైకిల్ కోసం కోటేషన్ కోరాడు, కానీ ఇంకా అందలేదు. అతను అసహనంతో మరియు అసంతృప్తితో డీలర్‌షిప్‌కు కాల్ చేస్తాడు. ఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(658, 55, 10, 'ഒരു ഉപഭോക്താവ് ചില ദിവസങ്ങൾക്ക് മുമ്പ് മോട്ടോർസൈക്കിളിനായി ക്വോട്ടേഷൻ അഭ്യർത്ഥിച്ചിരുന്നു, എന്നാൽ ഇതുവരെ ലഭിച്ചിട്ടില്ല. അദ്ദേഹം അസഹനവും അസന്തോഷവും പ്രകടിപ്പിച്ച് ഡീലർഷിപ്പിലേക്ക് വിളിക്കുന്നു. ഈ സാഹചര്യത്തെ നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(659, 55, 11, 'ಒಬ್ಬ ಗ್ರಾಹಕರು ಕೆಲವು ದಿನಗಳ ಹಿಂದೆ ಮೋಟಾರ್‌ಸೈಕಲ್‌ಗಾಗಿ ಕೊಟೇಶನ್ ಕೇಳಿದ್ದರು, ಆದರೆ ಇನ್ನೂ ಪಡೆಯಲಾಗಿಲ್ಲ. ಅವರು ಅಸಹನೆ ಮತ್ತು ಅಸಮಾಧಾನದಿಂದ ಡೀಲರ್‌ಶಿಪ್‌ಗೆ ಕರೆ ಮಾಡುತ್ತಾರೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(660, 55, 12, 'ଏକ ଗ୍ରାହକ କିଛି ଦିନ ପୂର୍ବରୁ ମୋଟରସାଇକେଲ ପାଇଁ କୋଟେସନ ଅନୁରୋଧ କରିଥିଲେ, କିନ୍ତୁ ଏପର୍ଯ୍ୟନ୍ତ ପାଇନାହାନ୍ତି। ସେ ଅଧୀର ଏବଂ କ୍ଷୁବ୍ଧ ସ୍ୱରରେ ଡିଲରଶିପକୁ ଫୋନ କରିଛନ୍ତି। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ହ୍ୟାଣ୍ଡଲ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(661, 56, 1, 'You call a customer to follow up on an enquiry.\r\n\r\nThe customer is irritated and complains about receiving repeated calls, claiming they consider it spam.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(662, 56, 2, 'आप किसी ग्राहक को उसकी पूछताछ (enquiry) के फॉलो-अप के लिए कॉल करते हैं।\r\n\r\nग्राहक चिढ़ा हुआ है और बार-बार कॉल आने की शिकायत करता है, यह कहते हुए कि उसे यह स्पैम जैसा लग रहा है।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(663, 56, 3, 'ਤੁਸੀਂ ਇੱਕ ਗਾਹਕ ਨੂੰ ਉਸਦੀ ਪੁੱਛਗਿੱਛ ਦੇ ਫਾਲੋ-ਅਪ ਲਈ ਕਾਲ ਕਰਦੇ ਹੋ। ਗਾਹਕ ਚਿੜਿਆ ਹੋਇਆ ਹੈ ਅਤੇ ਬਾਰ-ਬਾਰ ਕਾਲ ਆਉਣ ਦੀ ਸ਼ਿਕਾਇਤ ਕਰਦਾ ਹੈ, ਕਹਿੰਦਾ ਹੈ ਕਿ ਉਸਨੂੰ ਇਹ ਸਪੈਮ ਵਰਗਾ ਲੱਗਦਾ ਹੈ। ਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(664, 56, 4, 'તમે એક ગ્રાહકને તેની પૂછપરછના ફોલો-અપ માટે કોલ કરો છો. ગ્રાહક ચીડાયેલો છે અને વારંવાર કોલ મળવાની ફરિયાદ કરે છે, કહે છે કે તેને આ સ્પામ લાગે છે. તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(665, 56, 5, 'तुम्ही एका ग्राहकाला त्याच्या चौकशीच्या फॉलो-अपसाठी फोन करता. ग्राहक चिडलेला आहे आणि वारंवार फोन येत असल्याची तक्रार करतो, त्याला ते स्पॅम वाटते असे तो सांगतो. तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(666, 56, 6, 'আপনি একজন গ্রাহককে তার অনুসন্ধানের ফলো-আপ করার জন্য ফোন করেন। গ্রাহক বিরক্ত এবং বারবার ফোন পাওয়ার অভিযোগ করেন, তিনি বলেন এটি তার কাছে স্প্যাম মনে হচ্ছে। আপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(667, 56, 7, 'আপুনি এজন গ্ৰাহকলৈ তেওঁৰ অনুসন্ধানৰ ফ’ল’আপৰ বাবে ফোন কৰে। গ্ৰাহক অসন্তুষ্ট আৰু সঘনাই ফোন অহাৰ অভিযোগ কৰে, আৰু কয় যে এইটো স্পেম যেন লাগে। আপুনি এই পৰিস্থিতি কেনেকৈ সামাল দিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(668, 56, 8, 'நீங்கள் ஒரு வாடிக்கையாளரை அவரது விசாரணையின் தொடர்ச்சி அழைப்பிற்காக தொடர்பு கொள்கிறீர்கள். வாடிக்கையாளர் எரிச்சலுடன் பல முறை அழைப்புகள் வருவதாக கூறி, அதை ஸ்பாம் என கருதுகிறார். இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(669, 56, 9, 'మీరు ఒక కస్టమర్‌ను వారి విచారణపై ఫాలో-అప్ చేయడానికి కాల్ చేస్తారు. కస్టమర్ చిరాకు వ్యక్తం చేస్తూ, పదే పదే కాల్స్ వస్తున్నాయని మరియు అవి స్పామ్ లాగా అనిపిస్తున్నాయని చెబుతాడు. ఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(670, 56, 10, 'നിങ്ങൾ ഒരു ഉപഭോക്താവിനെ അവരുടെ അന്വേഷണത്തെ കുറിച്ച് ഫോളോ-അപ്പ് ചെയ്യാൻ വിളിക്കുന്നു. ഉപഭോക്താവ് അസ്വസ്ഥനായി നിരന്തരം കോളുകൾ വരുന്നതായി പരാതി പറയുന്നു, അത് സ്പാം എന്നാണ് കരുതുന്നത്. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(671, 56, 11, 'ನೀವು ಒಬ್ಬ ಗ್ರಾಹಕರನ್ನು ಅವರ ವಿಚಾರಣೆ ಕುರಿತು ಫಾಲೋ-ಅಪ್ ಮಾಡಲು ಕರೆ ಮಾಡುತ್ತೀರಿ. ಗ್ರಾಹಕರು ಬೇಸರಗೊಂಡು ಮರುಮರು ಕರೆ ಬರುತ್ತಿರುವುದಾಗಿ ಹೇಳುತ್ತಾರೆ ಮತ್ತು ಅದನ್ನು ಸ್ಪ್ಯಾಮ್ ಎಂದು ಭಾವಿಸುತ್ತಾರೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(672, 56, 12, 'ଆପଣ ଗ୍ରାହକଙ୍କୁ ତାଙ୍କର ପଚରାଉଚରି ପାଇଁ ଫଲୋ-ଅପ କରିବାକୁ ଫୋନ କରୁଛନ୍ତି। ଗ୍ରାହକ କ୍ଷୁବ୍ଧ ହୋଇ ବାରମ୍ବାର ଫୋନ ଆସୁଥିବାର ଅଭିଯୋଗ କରୁଛନ୍ତି ଏବଂ ଏହାକୁ ସ୍ପାମ୍ ବୋଲି ଭାବୁଛନ୍ତି। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ହ୍ୟାଣ୍ଡଲ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(673, 57, 1, 'You call a lead to follow up on an enquiry. \r\n\r\nThe customer says they have already purchased the same motorcycle from another dealership.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(674, 57, 2, 'आप किसी लीड को उसकी पूछताछ (enquiry) के फॉलो-अप के लिए कॉल करते हैं।\r\n\r\nग्राहक बताता है कि वह वही मोटरसाइकिल किसी दूसरी डीलरशिप से पहले ही खरीद चुका है।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(675, 57, 3, 'ਤੁਸੀਂ ਇੱਕ ਲੀਡ ਨੂੰ ਉਸਦੀ ਪੁੱਛਗਿੱਛ ਦੇ ਫਾਲੋ-ਅਪ ਲਈ ਕਾਲ ਕਰਦੇ ਹੋ। ਗਾਹਕ ਦੱਸਦਾ ਹੈ ਕਿ ਉਹ ਉਹੀ ਮੋਟਰਸਾਈਕਲ ਕਿਸੇ ਹੋਰ ਡੀਲਰਸ਼ਿਪ ਤੋਂ ਪਹਿਲਾਂ ਹੀ ਖਰੀਦ ਚੁੱਕਾ ਹੈ। ਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(676, 57, 4, 'તમે એક લીડને તેની પૂછપરછના ફોલો-અપ માટે કોલ કરો છો. ગ્રાહક કહે છે કે તેણે એ જ મોટરસાયકલ બીજી ડીલરશિપમાંથી પહેલેથી જ ખરીદી લીધી છે. તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(677, 57, 5, 'तुम्ही एका लीडला त्याच्या चौकशीच्या फॉलो-अपसाठी फोन करता. ग्राहक सांगतो की त्याने तीच मोटरसायकल दुसऱ्या डीलरशिपमधून आधीच खरेदी केली आहे. तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(678, 57, 6, 'আপনি একজন লিডকে তার অনুসন্ধানের ফলো-আপ করার জন্য ফোন করেন। গ্রাহক বলেন যে তিনি একই মোটরসাইকেল অন্য একটি ডিলারশিপ থেকে ইতিমধ্যেই কিনেছেন। আপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(679, 57, 7, 'আপুনি এজন লিডলৈ তেওঁৰ অনুসন্ধানৰ ফ’ল’আপৰ বাবে ফোন কৰে। গ্ৰাহকে কয় যে তেওঁ একে মটৰচাইকেল আন এটা ডিলাৰশ্বিপৰ পৰা ইতিমধ্যে ক্ৰয় কৰিছে। আপুনি এই পৰিস্থিতি কেনেকৈ সামাল দিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(680, 57, 8, 'நீங்கள் ஒரு லீடுக்கு அவரது விசாரணையின் தொடர்ச்சி அழைப்பிற்காக தொடர்பு கொள்கிறீர்கள். வாடிக்கையாளர் அதே மோட்டார்சைக்கிளை மற்றொரு டீலர்ஷிப்பில் இருந்து ஏற்கனவே வாங்கியதாக கூறுகிறார். இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(681, 57, 9, 'మీరు ఒక లీడ్‌ను వారి విచారణపై ఫాలో-అప్ చేయడానికి కాల్ చేస్తారు. కస్టమర్ అదే మోటార్‌సైకిల్‌ను మరో డీలర్‌షిప్ నుండి ఇప్పటికే కొనుగోలు చేశామని చెబుతాడు. ఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(682, 57, 10, 'നിങ്ങൾ ഒരു ലീഡിനെ അവരുടെ അന്വേഷണത്തെ കുറിച്ച് ഫോളോ-അപ്പ് ചെയ്യാൻ വിളിക്കുന്നു. ഉപഭോക്താവ് അതേ മോട്ടോർസൈക്കിൾ മറ്റൊരു ഡീലർഷിപ്പിൽ നിന്ന് ഇതിനകം വാങ്ങിയതായി പറയുന്നു. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(683, 57, 11, 'ನೀವು ಒಬ್ಬ ಲೀಡ್‌ಗೆ ಅವರ ವಿಚಾರಣೆ ಕುರಿತು ಫಾಲೋ-ಅಪ್ ಮಾಡಲು ಕರೆ ಮಾಡುತ್ತೀರಿ. ಗ್ರಾಹಕರು ಅದೇ ಮೋಟಾರ್‌ಸೈಕಲ್ ಅನ್ನು ಮತ್ತೊಂದು ಡೀಲರ್‌ಶಿಪ್‌ನಿಂದ ಈಗಾಗಲೇ ಖರೀದಿಸಿದ್ದಾಗಿ ಹೇಳುತ್ತಾರೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(684, 57, 12, 'ଆପଣ ଗ୍ରାହକଙ୍କୁ ତାଙ୍କର ପଚରାଉଚରି ପାଇଁ ଫଲୋ-ଅପ କରିବାକୁ ଫୋନ କରୁଛନ୍ତି। ଗ୍ରାହକ କହୁଛନ୍ତି ଯେ ସେ ସେହି ମୋଟରସାଇକେଲକୁ ଅନ୍ୟ ଏକ ଡିଲରଶିପରୁ ପୂର୍ବରୁ କିଣିଛନ୍ତି। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ହ୍ୟାଣ୍ଡଲ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(685, 58, 1, 'You are tasked with following up on enquiries. \r\n\r\nOne of the customers that you follow up with reveals that he has already purchased the bike, but the lead is still marked as "follow-up pending".\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(686, 58, 2, 'आपको enquiries पर फॉलो-अप करने की ज़िम्मेदारी दी गई है।\r\n\r\nजिन ग्राहकों से आप फॉलो-अप करते हैं, उनमें से एक ग्राहक बताता है कि उसने पहले ही बाइक खरीद ली है, लेकिन लीड अभी भी सिस्टम में “follow-up pending” के रूप में दिखाई दे रही है।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(687, 58, 3, 'ਤੁਹਾਨੂੰ ਪੁੱਛਗਿੱਛਾਂ ਦਾ ਫਾਲੋ-ਅਪ ਕਰਨ ਦੀ ਜ਼ਿੰਮੇਵਾਰੀ ਦਿੱਤੀ ਗਈ ਹੈ। ਜਿਸ ਗਾਹਕ ਨਾਲ ਤੁਸੀਂ ਫਾਲੋ-ਅਪ ਕਰਦੇ ਹੋ, ਉਹ ਦੱਸਦਾ ਹੈ ਕਿ ਉਹ ਪਹਿਲਾਂ ਹੀ ਬਾਈਕ ਖਰੀਦ ਚੁੱਕਾ ਹੈ, ਪਰ ਸਿਸਟਮ ਵਿੱਚ ਲੀਡ ਹਾਲੇ ਵੀ \'follow-up pending\' ਵਜੋਂ ਦਰਜ ਹੈ। ਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(688, 58, 4, 'તમને પૂછપરછ પર ફોલો-અપ કરવાની જવાબદારી સોંપવામાં આવી છે. જેનાં સાથે તમે ફોલો-અપ કરો છો તેમાંથી એક ગ્રાહક કહે છે કે તેણે પહેલેથી જ બાઈક ખરીદી લીધી છે, પણ લીડ હજુ પણ \'follow-up pending\' તરીકે દર્શાવવામાં આવી રહી છે. તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(689, 58, 5, 'तुम्हाला चौकशींचा फॉलो-अप करण्याची जबाबदारी देण्यात आली आहे. ज्या ग्राहकासोबत तुम्ही फॉलो-अप करता, तो सांगतो की त्याने आधीच बाईक खरेदी केली आहे, पण लीड अजूनही \'follow-up pending\' म्हणून दर्शवली जात आहे. तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(690, 58, 6, 'আপনাকে অনুসন্ধানের ফলো-আপ করার দায়িত্ব দেওয়া হয়েছে। যে গ্রাহকের সাথে আপনি ফলো-আপ করেন, তিনি জানান যে তিনি ইতিমধ্যেই বাইক কিনেছেন, কিন্তু লিড এখনও \'follow-up pending\' হিসেবে দেখানো হচ্ছে। আপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(691, 58, 7, 'আপোনাক অনুসন্ধানসমূহৰ ফ’ল’আপ কৰাৰ দায়িত্ব দিয়া হৈছে। আপুনি যি গ্ৰাহকৰ সৈতে ফ’ল’আপ কৰে, তেওঁ কয় যে তেওঁ ইতিমধ্যে বাইক ক্ৰয় কৰিছে, কিন্তু লিড এতিয়াও \'follow-up pending\' হিচাপে দেখুওৱা হৈছে। আপুনি এই পৰিস্থিতি কেনেকৈ সামাল দিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(692, 58, 8, 'உங்களுக்கு விசாரணைகளின் தொடர்ச்சி அழைப்புகளை மேற்கொள்ளும் பொறுப்பு வழங்கப்பட்டுள்ளது. நீங்கள் தொடர்பு கொண்ட வாடிக்கையாளர்களில் ஒருவர் ஏற்கனவே பைக்கை வாங்கியதாக கூறுகிறார், ஆனால் லீடு இன்னும் \'follow-up pending\' எனக் காட்டப்படுகிறது. இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(693, 58, 9, 'మీకు విచారణలపై ఫాలో-అప్ చేసే బాధ్యత అప్పగించబడింది. మీరు ఫాలో-అప్ చేసిన కస్టమర్లలో ఒకరు ఇప్పటికే బైక్ కొనుగోలు చేశారని చెబుతున్నారు, కానీ లీడ్ ఇంకా \'follow-up pending\'గా చూపబడుతోంది. ఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(694, 58, 10, 'നിങ്ങൾക്ക് അന്വേഷണങ്ങളുടെ ഫോളോ-അപ്പ് നടത്താനുള്ള ചുമതല നൽകിയിരിക്കുന്നു. നിങ്ങൾ ഫോളോ-അപ്പ് ചെയ്യുന്ന ഉപഭോക്താക്കളിൽ ഒരാൾ ഇതിനകം ബൈക്ക് വാങ്ങിയതായി പറയുന്നു, എന്നാൽ ലീഡ് ഇപ്പോഴും \'follow-up pending\' ആയി കാണിക്കുന്നു. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(695, 58, 11, 'ನಿಮಗೆ ವಿಚಾರಣೆಗಳ ಫಾಲೋ-ಅಪ್ ಮಾಡುವ ಜವಾಬ್ದಾರಿ ನೀಡಲಾಗಿದೆ. ನೀವು ಫಾಲೋ-ಅಪ್ ಮಾಡಿದ ಗ್ರಾಹಕರಲ್ಲಿ ಒಬ್ಬರು ಈಗಾಗಲೇ ಬೈಕ್ ಖರೀದಿಸಿದ್ದಾಗಿ ಹೇಳುತ್ತಾರೆ, ಆದರೆ ಲೀಡ್ ಇನ್ನೂ \'follow-up pending\' ಎಂದು ತೋರಿಸಲಾಗುತ್ತಿದೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(696, 58, 12, 'ଆପଣଙ୍କୁ ପଚରାଉଚରିର ଫଲୋ-ଅପ କରିବାର ଦାୟିତ୍ୱ ଦିଆଯାଇଛି। ଯେଉଁ ଗ୍ରାହକ ସହ ଆପଣ ଫଲୋ-ଅପ କରୁଛନ୍ତି, ସେ କହୁଛନ୍ତି ଯେ ସେ ପୂର୍ବରୁ ବାଇକ କିଣିଛନ୍ତି, କିନ୍ତୁ ଲିଡ୍ ଏବେ ମଧ୍ୟ \'follow-up pending\' ଭାବେ ଦର୍ଶାଯାଉଛି। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ହ୍ୟାଣ୍ଡଲ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(697, 59, 1, 'During a follow-up call, the customer reveals that he had asked for more information about financing options in an earlier call and was promised a callback.\r\n\r\nThe customer is frustrated that they have not received any update.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(698, 59, 2, 'फॉलो-अप कॉल के दौरान ग्राहक बताता है कि उसने पिछली कॉल में फाइनेंसिंग ऑप्शन्स के बारे में अधिक जानकारी मांगी थी और उसे कॉलबैक का वादा किया गया था।\r\n\r\nग्राहक इस बात से नाराज़ है कि उसे अभी तक कोई अपडेट नहीं मिला है।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(699, 59, 3, 'ਫਾਲੋ-ਅਪ ਕਾਲ ਦੌਰਾਨ ਗਾਹਕ ਦੱਸਦਾ ਹੈ ਕਿ ਉਸਨੇ ਪਹਿਲੀ ਕਾਲ ਵਿੱਚ ਫਾਇਨੈਂਸਿੰਗ ਵਿਕਲਪਾਂ ਬਾਰੇ ਹੋਰ ਜਾਣਕਾਰੀ ਮੰਗੀ ਸੀ ਅਤੇ ਉਸਨੂੰ ਵਾਪਸੀ ਕਾਲ ਦਾ ਵਾਅਦਾ ਕੀਤਾ ਗਿਆ ਸੀ। ਗਾਹਕ ਇਸ ਗੱਲ ਨਾਲ ਨਾਰਾਜ਼ ਹੈ ਕਿ ਉਸਨੂੰ ਅਜੇ ਤੱਕ ਕੋਈ ਅਪਡੇਟ ਨਹੀਂ ਮਿਲੀ। ਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(700, 59, 4, 'ફોલો-અપ કોલ દરમિયાન ગ્રાહક કહે છે કે તેણે અગાઉની કોલમાં ફાઇનાન્સિંગ વિકલ્પો વિશે વધુ માહિતી માંગી હતી અને તેને કોલબેક કરવાનો વચન આપવામાં આવ્યો હતો. ગ્રાહક આ બાબતે નારાજ છે કે તેને હજુ સુધી કોઈ અપડેટ મળ્યો નથી. તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(701, 59, 5, 'फॉलो-अप कॉलदरम्यान ग्राहक सांगतो की त्याने आधीच्या कॉलमध्ये फायनान्सिंग पर्यायांविषयी अधिक माहिती मागितली होती आणि त्याला कॉलबॅकचे आश्वासन देण्यात आले होते. ग्राहक याबद्दल नाराज आहे की त्याला अजून कोणतीही अपडेट मिळालेली नाही. तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(702, 59, 6, 'ফলো-আপ কলের সময় গ্রাহক জানান যে তিনি আগের কলে ফাইন্যান্সিং বিকল্প সম্পর্কে আরও তথ্য চেয়েছিলেন এবং তাকে কলব্যাকের প্রতিশ্রুতি দেওয়া হয়েছিল। তিনি ক্ষুব্ধ যে এখনও কোনো আপডেট পাননি। আপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(703, 59, 7, 'ফ’ল’আপ কলৰ সময় গ্ৰাহকে কয় যে তেওঁ পূৰ্বৰ কলত ফাইনেন্সিং বিকল্পসমূহৰ বিষয়ে অধিক তথ্য বিচাৰিছিল আৰু তেওঁক পুনৰ কল কৰাৰ প্ৰতিশ্ৰুতি দিয়া হৈছিল। তেওঁ এতিয়াও কোনো আপডেট নোপোৱাৰ বাবে ক্ষুব্ধ। আপুনি এই পৰিস্থিতি কেনেকৈ সামাল দিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(704, 59, 8, 'தொடர்ச்சி அழைப்பின் போது வாடிக்கையாளர் முன்பு நிதி வசதிகள் பற்றிய கூடுதல் தகவலை கேட்டதாகவும், அவருக்கு மீண்டும் அழைப்பதாக உறுதி அளிக்கப்பட்டதாகவும் தெரிவிக்கிறார். இன்னும் எந்த தகவலும் கிடைக்காததால் அவர் வருத்தமடைந்துள்ளார். இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(705, 59, 9, 'ఫాలో-అప్ కాల్ సమయంలో కస్టమర్ ముందున్న కాల్‌లో ఫైనాన్సింగ్ ఎంపికల గురించి మరింత సమాచారం అడిగినట్లు మరియు కాల్‌బ్యాక్ వాగ్దానం చేసినట్లు చెబుతాడు. ఇప్పటికీ ఎలాంటి అప్డేట్ రాలేదని అసహనం వ్యక్తం చేస్తున్నాడు. ఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(706, 59, 10, 'ഫോളോ-അപ്പ് കോളിനിടെ ഉപഭോക്താവ് മുമ്പത്തെ കോളിൽ ഫിനാൻസിംഗ് ഓപ്ഷനുകൾ സംബന്ധിച്ച് കൂടുതൽ വിവരങ്ങൾ ആവശ്യപ്പെട്ടതും, തിരികെ വിളിക്കാമെന്ന് വാഗ്ദാനം ചെയ്തതും പറയുന്നു. ഇതുവരെ ഒരു അപ്ഡേറ്റും ലഭിക്കാത്തതിൽ അദ്ദേഹം അസ്വസ്ഥനാണ്. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(707, 59, 11, 'ಫಾಲೋ-ಅಪ್ ಕರೆ ವೇಳೆ ಗ್ರಾಹಕರು ಹಿಂದಿನ ಕರೆದಲ್ಲಿ ಹಣಕಾಸು ಆಯ್ಕೆಗಳ ಕುರಿತು ಹೆಚ್ಚಿನ ಮಾಹಿತಿಯನ್ನು ಕೇಳಿದ್ದರು ಮತ್ತು ಕಾಲ್‌ಬ್ಯಾಕ್ ಮಾಡುವುದಾಗಿ ಭರವಸೆ ನೀಡಲಾಗಿತ್ತು ಎಂದು ಹೇಳುತ್ತಾರೆ. ಇನ್ನೂ ಯಾವುದೇ ಅಪ್ಡೇಟ್ ಸಿಗದಿರುವುದರಿಂದ ಅವರು ಅಸಮಾಧಾನಗೊಂಡಿದ್ದಾರೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(708, 59, 12, 'ଫଲୋ-ଅପ କଲ୍ ସମୟରେ ଗ୍ରାହକ କହୁଛନ୍ତି ଯେ ପୂର୍ବରୁ ଥିବା କଲ୍‌ରେ ସେ ଫାଇନାନ୍ସିଂ ବିକଳ୍ପ ବିଷୟରେ ଅଧିକ ସୂଚନା ଚାହିଁଥିଲେ ଏବଂ ପୁନଃ କଲ୍ କରିବାକୁ ପ୍ରତିଶ୍ରୁତି ଦିଆଯାଇଥିଲା। ଏପର୍ଯ୍ୟନ୍ତ କୌଣସି ଅପଡେଟ୍ ନ ମିଳିବାରୁ ସେ କ୍ଷୁବ୍ଧ ଅଟନ୍ତି। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ହ୍ୟାଣ୍ଡଲ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(709, 60, 1, 'You are tasked with following up on enquiries. \r\n\r\nDuring the call, the customer reveals that they are deferring their purchase decision due to financial constraints.\r\n\r\nHow should you handle the situation?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(710, 60, 2, 'आपको enquiries पर फॉलो-अप करने की ज़िम्मेदारी दी गई है।\r\n\r\nकॉल के दौरान ग्राहक बताता है कि वह आर्थिक कारणों की वजह से अपनी खरीद का निर्णय फिलहाल टाल रहा है।\r\n\r\nआप इस स्थिति को कैसे संभालेंगे?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(711, 60, 3, 'ਤੁਹਾਨੂੰ ਪੁੱਛਗਿੱਛਾਂ ਦਾ ਫਾਲੋ-ਅਪ ਕਰਨ ਦੀ ਜ਼ਿੰਮੇਵਾਰੀ ਦਿੱਤੀ ਗਈ ਹੈ। ਕਾਲ ਦੌਰਾਨ ਗਾਹਕ ਦੱਸਦਾ ਹੈ ਕਿ ਵਿੱਤੀ ਪਾਬੰਦੀਆਂ ਕਾਰਨ ਉਹ ਆਪਣਾ ਖਰੀਦਣ ਦਾ ਫੈਸਲਾ ਟਾਲ ਰਿਹਾ ਹੈ। ਤੁਸੀਂ ਇਸ ਸਥਿਤੀ ਨੂੰ ਕਿਵੇਂ ਸੰਭਾਲੋਗੇ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(712, 60, 4, 'તમને પૂછપરછ પર ફોલો-અપ કરવાની જવાબદારી સોંપવામાં આવી છે. કોલ દરમિયાન ગ્રાહક કહે છે કે નાણાકીય મર્યાદાઓને કારણે તે પોતાની ખરીદીનો નિર્ણય મુલતવી રાખી રહ્યો છે. તમે આ પરિસ્થિતિને કેવી રીતે હેન્ડલ કરશો?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(713, 60, 5, 'तुम्हाला चौकशींचा फॉलो-अप करण्याची जबाबदारी देण्यात आली आहे. कॉलदरम्यान ग्राहक सांगतो की आर्थिक अडचणींमुळे तो खरेदीचा निर्णय पुढे ढकलत आहे. तुम्ही ही परिस्थिती कशी हाताळाल?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(714, 60, 6, 'আপনাকে অনুসন্ধানের ফলো-আপ করার দায়িত্ব দেওয়া হয়েছে। কলের সময় গ্রাহক জানান যে আর্থিক সীমাবদ্ধতার কারণে তিনি তার ক্রয়ের সিদ্ধান্ত স্থগিত রাখছেন। আপনি এই পরিস্থিতি কীভাবে সামলাবেন?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(715, 60, 7, 'আপোনাক অনুসন্ধানসমূহৰ ফ’ল’আপ কৰাৰ দায়িত্ব দিয়া হৈছে। কলৰ সময় গ্ৰাহকে কয় যে আৰ্থিক সীমাবদ্ধতাৰ বাবে তেওঁ ক্ৰয়ৰ সিদ্ধান্ত পিছলৈ ঠেলি দিছে। আপুনি এই পৰিস্থিতি কেনেকৈ সামাল দিব?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(716, 60, 8, 'உங்களுக்கு விசாரணைகளின் தொடர்ச்சி அழைப்புகளை மேற்கொள்ளும் பொறுப்பு வழங்கப்பட்டுள்ளது. அழைப்பின் போது வாடிக்கையாளர் நிதி கட்டுப்பாடுகள் காரணமாக தனது வாங்கும் முடிவை ஒத்திவைத்துள்ளதாக தெரிவிக்கிறார். இந்த நிலையை நீங்கள் எப்படி கையாளுவீர்கள்?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(717, 60, 9, 'మీకు విచారణలపై ఫాలో-అప్ చేసే బాధ్యత అప్పగించబడింది. కాల్ సమయంలో కస్టమర్ ఆర్థిక పరిమితుల కారణంగా తన కొనుగోలు నిర్ణయాన్ని వాయిదా వేస్తున్నట్లు చెబుతున్నాడు. ఈ పరిస్థితిని మీరు ఎలా నిర్వహిస్తారు?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(718, 60, 10, 'നിങ്ങൾക്ക് അന്വേഷണങ്ങളുടെ ഫോളോ-അപ്പ് നടത്താനുള്ള ചുമതല നൽകിയിരിക്കുന്നു. കോളിനിടെ ഉപഭോക്താവ് സാമ്പത്തിക നിയന്ത്രണങ്ങൾ കാരണം തന്റെ വാങ്ങൽ തീരുമാനം മാറ്റിവെച്ചതായി പറയുന്നു. ഈ സാഹചര്യം നിങ്ങൾ എങ്ങനെ കൈകാര്യം ചെയ്യും?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(719, 60, 11, 'ನಿಮಗೆ ವಿಚಾರಣೆಗಳ ಫಾಲೋ-ಅಪ್ ಮಾಡುವ ಜವಾಬ್ದಾರಿ ನೀಡಲಾಗಿದೆ. ಕರೆ ಸಮಯದಲ್ಲಿ ಗ್ರಾಹಕರು ಆರ್ಥಿಕ ನಿರ್ಬಂಧಗಳ ಕಾರಣದಿಂದ ತಮ್ಮ ಖರೀದಿ ನಿರ್ಧಾರವನ್ನು ಮುಂದೂಡುತ್ತಿದ್ದಾರೆ ಎಂದು ಹೇಳುತ್ತಾರೆ. ಈ ಪರಿಸ್ಥಿತಿಯನ್ನು ನೀವು ಹೇಗೆ ನಿರ್ವಹಿಸುತ್ತೀರಿ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active'),
	(720, 60, 12, 'ଆପଣଙ୍କୁ ପଚରାଉଚରିର ଫଲୋ-ଅପ କରିବାର ଦାୟିତ୍ୱ ଦିଆଯାଇଛି। କଲ୍ ସମୟରେ ଗ୍ରାହକ କହୁଛନ୍ତି ଯେ ଆର୍ଥିକ ସୀମାବଦ୍ଧତା କାରଣରୁ ସେ ତାଙ୍କର କ୍ରୟ ନିଷ୍ପତ୍ତିକୁ ପଛକୁ ଟାଣୁଛନ୍ତି। ଆପଣ ଏହି ପରିସ୍ଥିତିକୁ କିପରି ହ୍ୟାଣ୍ଡଲ କରିବେ?', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-27 06:06:08', 'Active');
